import { RefObject, useCallback, useEffect, useRef, useState } from 'react';
import { IApiFailureResponse } from '@core/api';
import { IError } from '@core/error';
import { FieldProps } from '@cb/forms';
import { useToggler } from '@cbhq/cds-common';
import { ListCell } from '@cbhq/cds-mobile/cells/ListCell';
import { Spacer } from '@cbhq/cds-mobile/layout/Spacer';
import { TextBody, TextTitle3 } from '@cbhq/cds-mobile/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { Button } from '@components/interactables/Button';
import { TextInput } from '@components/interactables/TextInput';
import { formatStringToTitleCase } from '@utils/string/stringUtils';
import { KeyboardAvoidingView } from '@app/components/KeyboardAvoidingView';
import { AddPaymentMethodBoundary } from '@app/contexts/AddPaymentMethodBoundary/AddPaymentMethodBoundary';
import { useAddPaymentMethodUtils } from '@app/contexts/AddPaymentMethodBoundary/useAddPaymentMethodUtils';
import { useParams } from '@app/hooks/navigation/useParams';
import { useScreenProtectOnFocus } from '@app/hooks/navigation/useScreenProtect';
import { PlaidSupportedBankTray } from '@app/screens/AddPaymentMethod/components/PlaidSupportedBankTray';
import { client } from '@app/utils/api/client';

import { BankAccountHelpLink } from './BankAccountHelpLink';
import { BankInfo } from './BankInfo';

const i18nKey = 'RoutingNumberForm';
const messages = defineMessages({
  enterYourRouting: {
    id: `${i18nKey}.enterYourRouting`,
    defaultMessage: 'Enter your routing number',
    description: '',
  },
  enterYour9Digit: {
    id: `${i18nKey}.enterYour9Digit`,
    defaultMessage:
      'Enter your 9-digit bank routing number (ABA) so we can connect to your bank. Not sure where to find this? {helpLink}',
    description: '',
  },
  continue: {
    id: `${i18nKey}.continue`,
    defaultMessage: 'Continue',
    description: '',
  },
  bankName: {
    id: `${i18nKey}.bankName`,
    defaultMessage: 'Bank name',
    description: 'Label for bank name',
  },
  bankAddress: {
    id: `${i18nKey}.bankAddress`,
    defaultMessage: 'Bank address',
    description: 'Label for bank address',
  },
  bankLocationHeading: {
    id: `${i18nKey}.bankLocationHeading`,
    defaultMessage: 'Bank location',
    description: 'Label for bank location',
  },
  bankInfoAccessibilityLabel: {
    id: `${i18nKey}.bankInfoAccessibilityLabel`,
    defaultMessage: 'Your bank name and location',
    description: 'Accessibility label for bank info',
  },
  bankInfoAccessibilityHint: {
    id: `${i18nKey}.bankInfoAccessibilityHint`,
    defaultMessage: 'Bank Information',
    description: 'Accessibility hint for bank info',
  },
  plaidSupportedError: {
    id: `${i18nKey}.plaidSupportedError`,
    defaultMessage:
      "This bank account can't be added manually. Try instant verification or use a different bank account.",
    description:
      'Unique error message from the backend that indicates a routing number is associated with a Plaid-supported bank',
  },
});
export type RoutingNumberFormProps = {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  field: FieldProps<string, any>;
  isSubmittable: boolean;
  onPress: () => void;
  infoLoaded?: (info: BankInfo | undefined) => void;
  onError?: (error: IError | undefined) => void;
};

async function fetchRoutingInformation(
  routingNumber: string,
  abortController: RefObject<AbortController>,
) {
  return client.fetch<BankInfo>('v2/routing-number-information/', {
    signal: abortController.current?.signal,
    params: {
      routing_number: routingNumber,
    },
  });
}

function getErrorMessage(error: IApiFailureResponse): string {
  if (
    error.data &&
    'message' in error.data &&
    typeof error.data?.message === 'string' &&
    error.data.message.length > 0
  ) {
    return error.data.message;
  }

  return error.errors[0].message;
}

export function RoutingNumberForm({
  field,
  isSubmittable,
  onPress,
  infoLoaded,
  onError,
}: RoutingNumberFormProps) {
  useScreenProtectOnFocus();
  const { formatMessage } = useIntl();
  const [bank, setBank] = useState<BankInfo>();
  const abortController = useRef(new AbortController());
  const [loading, setLoading] = useState(false);
  const { logAddPaymentEvent } = useAddPaymentMethodUtils();
  const [isVisible, { toggleOff: hideTray }] = useToggler(false);

  const { entryPoint = 'unknown' } = useParams<'AddPaymentMethod'>();

  const infoLoadedIfDefined = useCallback(
    (info: BankInfo | undefined) => {
      if (infoLoaded !== undefined) {
        infoLoaded(info);
      }
    },
    [infoLoaded],
  );

  useEffect(() => {
    setBank(undefined);
    if (field.value === '' || field.errors.length !== 0) {
      return;
    }
    abortController.current.abort();
    abortController.current = new AbortController();
    setLoading(true);
    void fetchRoutingInformation(field.value, abortController).then(
      (response) => {
        if (response.type === 'success') {
          logAddPaymentEvent('fetch_routing_info_success', {
            action: ActionType.process,
            componentType: ComponentType.unknown,
          });
          setBank(response.data);
          infoLoadedIfDefined(response.data);
        } else if (
          (response as IApiFailureResponse).errors.find(
            (e) => e.id === 'invalid_request',
          ) !== undefined
        ) {
          logAddPaymentEvent('fetch_routing_info_error', {
            action: ActionType.process,
            componentType: ComponentType.unknown,
            error: getErrorMessage(response) || null,
          });
          if (onError !== undefined) {
            onError(
              (response as IApiFailureResponse).errors.find(
                (e) => e.id === 'invalid_request',
              ),
            );
          }
          setBank(undefined);
          infoLoadedIfDefined(undefined);
        } else {
          logAddPaymentEvent('fetch_routing_info_error', {
            action: ActionType.process,
            componentType: ComponentType.unknown,
            error: getErrorMessage(response) || null,
          });
          infoLoadedIfDefined(undefined);
          setBank(undefined);
        }
        setLoading(false);
      },
    );
    // Wants me to include field.errors.length but that
    // would cause a loop
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [field.value, onError, setLoading, infoLoadedIfDefined]);

  return (
    <KeyboardAvoidingView>
      <TextTitle3 spacingBottom={1}>
        {formatMessage(messages.enterYourRouting)}
      </TextTitle3>
      <TextBody spacingBottom={3} color="foregroundMuted">
        {formatMessage(messages.enterYour9Digit, {
          helpLink: <BankAccountHelpLink key="helpLink" />,
        })}
      </TextBody>
      <TextInput
        {...field}
        autoFocus
        showErrorsOnChange
        keyboardType="number-pad"
        testID="routing-number"
        accessibilityLabel="Routing Number"
      />
      {bank?.address !== undefined && !loading ? (
        <BankInfoSection bank={bank} />
      ) : null}
      <Spacer />
      <Button disabled={!isSubmittable} loading={loading} onPress={onPress}>
        {formatMessage(messages.continue)}
      </Button>

      <AddPaymentMethodBoundary
        entryPoint="plaid_supported_bank_tray"
        paymentMethodType="ach_bank_account"
      >
        {/* todo: add this tray to the last step of manual flow */}
        <PlaidSupportedBankTray
          isVisible={isVisible}
          onDismiss={hideTray}
          entryPoint={entryPoint}
          bankName={bank ? bank.bankName : 'your bank'}
        />
      </AddPaymentMethodBoundary>
    </KeyboardAvoidingView>
  );
}

type BankInfoSectionProps = { bank: BankInfo };

function BankInfoSection({ bank }: BankInfoSectionProps) {
  const { formatMessage } = useIntl();

  const bankLocation = `${formatStringToTitleCase(bank?.address?.city)}, ${
    bank?.address?.state
  }`;

  return (
    <ListCell
      title={<TextBody>{formatMessage(messages.bankName)}</TextBody>}
      description={bank.bankName}
      detail={formatMessage(messages.bankLocationHeading)}
      subdetail={bankLocation}
      accessibilityHint={formatMessage(messages.bankInfoAccessibilityHint)}
      accessibilityLabel={formatMessage(messages.bankInfoAccessibilityLabel)}
      outerSpacing={{ spacing: 0 }}
    />
  );
}

import { Button } from 'react-native';
