  afterEach(() => {
    jest.clearAllMocks();
  });

  const mockResponse = {
    zepto: {
      depositInformation: [
        {
          key: 'header',
          title: 'Top up your wallet with a PayID or BSB/Account Transfer',
          value: '',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'payid_qr_string',
          title: 'PayID QR Code sring',
          value: 'mockQrCodeString',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'payid_title',
          title: 'PayID',
          value: '',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'payid_step_1',
          title: 'PayID Step 1',
          value: 'PayID Copy Value 1',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'payid_step_2',
          title: 'PayID Step 2',
          value: '',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'payid_step_3',
          title: 'PayID Step 3',
          value: '',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'bsb_title',
          title: 'BSB/Account Transfer',
          value: '',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'bsb_step_1',
          title: 'BSB Step 1',
          value: '',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'bsb_step_1_1',
          title: 'BSB Step 1.1',
          value: 'Copy value 1.1',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'bsb_step_1_2',
          title: 'BSB Step 1.2',
          value: 'Copy value 1.2',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'bsb_step_1_3',
          title: 'BSB Step 1.3',
          value: 'Copy value 1.3',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'bsb_step_2',
          title: 'BSB Step 2',
          value: '',
          description: '',
          isHighlighted: false,
        },
        {
          key: 'bsb_step_3',
          title: 'BSB Step 3',
          value: '',
          description: '',
          isHighlighted: false,
        },
      ],
      name: 'Zepto',
    },
  };

  const mockDepositMethods = [
    {
      type: 'zepto' as AllPaymentMethodType,
      options: [
        {
          type: 'payid',
        },
        {
          type: 'bsb',
        },
      ],
    },
  ];

  beforeEach(() => {
    (TabNavigation as unknown as jest.Mock).mockImplementation(
      ({ tabs, onChange }: { tabs: MockTab[]; onChange: MockTabOnChange }) => (
        <>
