    );
    (useDimensions as jest.Mock).mockReturnValue({ screenWidth: 800 });
  });

  it('should render the instructions for PayID initially', () => {
    // Mock Response
    (useDepositInformationByPaymentMethod as jest.Mock).mockImplementation(
      () => {
