      </MonitoringBoundaryProvider>,
    );

    expect(getByTestId('deposit-information-qr-code')).toBeTruthy();
  });

  it('should not render the QR Code for BSB tab', () => {
    // Mock Response
    (useDepositInformationByPaymentMethod as jest.Mock).mockImplementation(
      () => {
        return mockResponse;
      },
    );

    const { queryByTestId, getByText } = render(
      <MonitoringBoundaryProvider getDefaultErrorLogger={getDefaultErrorLogger}>
        <MockScreenProviders>
          <MockGraphqlProvider>
            <BaseDepositInformationStepsScreen
              accountId="mock-account-id"
              currencies={['AUD']}
              depositMethods={mockDepositMethods}
              onNext={jest.fn()}
              title="Mock Title"
            />
          </MockGraphqlProvider>
        </MockScreenProviders>
      </MonitoringBoundaryProvider>,
    );

    fireEvent.press(getByText('BSB/Account Transfer'));

    expect(queryByTestId('deposit-information-qr-code')).toBeNull();
  });
});

import { memo, useCallback } from 'react';
import { StyleSheet } from 'react-native';
import { AssistOptionType } from '@core/__generated__/enums';
import { useIsFocused, useNavigationState } from '@react-navigation/native';
import { DotCount } from '@cbhq/cds-mobile/dots';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Pressable } from '@cbhq/cds-mobile/system';

import { useCBAssistContext } from '@app/contexts/CBAssist/CBAssistContext';
import { useCBAssistChat } from '@app/hooks/useCBAssistChat/useCBAssistChat';
import {
  SupportModalStack,
  SupportStackScreens,
} from '@app/screens/Support/constants';

const styles = StyleSheet.create({
  bubble: {
    position: 'absolute',
    bottom: 90,
    right: 24,
    zIndex: 100,
  },
});

const IconWrappedWithUnreadMessageCount = memo(
  ({
    messageCount,
    children,
  }: {
    messageCount: number;
    children: React.ReactNode;
  }) =>
    messageCount ? (
      <DotCount pin="top-end" count={messageCount} overlap="circular">
        {children}
      </DotCount>
    ) : (
      <>{children}</>
    ),
);

export const CBAssistChatBubble = memo(() => {
  const navigationState = useNavigationState((state) => state);
  const currentStack =
    navigationState?.routes?.[navigationState.index]?.name || '';
  const currentStackParams =
    navigationState?.routes?.[navigationState.index]?.params || {};

  const isSupportChatScreenActive =
    currentStack === SupportModalStack &&
    'screen' in currentStackParams &&
    currentStackParams.screen === SupportStackScreens.SupportChatScreen;

  const isScreenActive = useIsFocused() && !isSupportChatScreenActive;

  const {
    isCBAssistEnabled,
    isChatStartedViaCBAssist,
    activeCBAssistChatType,
  } = useCBAssistContext();
  const { unreadMessagesCount, conversation, handleCBAssistChat } =
    useCBAssistChat({ isScreenActive });

  const handleBubblePress = useCallback(() => {
    handleCBAssistChat(activeCBAssistChatType as AssistOptionType);
  }, [activeCBAssistChatType, handleCBAssistChat]);

  return !isSupportChatScreenActive &&
    conversation &&
    isCBAssistEnabled &&
    isChatStartedViaCBAssist ? (
    <Pressable
      background="primary"
      borderRadius={32}
      accessibilityRole="button"
      onPress={handleBubblePress}
      style={styles.bubble}
    >
      <IconWrappedWithUnreadMessageCount messageCount={unreadMessagesCount}>
        <Icon spacing={2} size="m" name="chatBubble" color="secondary" />
      </IconWrappedWithUnreadMessageCount>
    </Pressable>
  ) : null;
});

import { memo, useCallback } from 'react';
import { NudgeCard } from '@cbhq/cds-mobile/cards/NudgeCard';
import { Pictogram } from '@cbhq/cds-mobile/illustrations';
import { Box } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextHeadline, TextLabel2 } from '@cbhq/cds-mobile/typography';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { useStackNavigation } from '@app/hooks/navigation/useStackNavigation';

const i18nKey = 'DerivativesUpsellCard';
const messages = defineMessages({
  derivativesCardTitle: {
    id: `${i18nKey}.derivativesCardTitle`,
    defaultMessage: 'Looking for derivatives?',
    description: 'Title for derivatives card',
  },
  derivativesCardDescription: {
    id: `${i18nKey}.derivativesCardDescription`,
    defaultMessage: 'Manage derivatives in Advanced trade',
    description: 'Description for derivatives card',
  },
  derivativesCardCta: {
    id: `${i18nKey}.derivativesCardCta`,
    defaultMessage: 'Go to Advanced',
    description: 'CTA for derivatives card',
  },
});

export const DerivativesUpsellCard = memo(() => {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();

  const handlePressGoToAdvanced = useCallback(() => {
    navigate('TradeStack', {
      screen: 'TradeRedirect',
      params: { tradingPreferenceOverride: 'advanced' },
    });
  }, [navigate]);

  return (
    <Pressable
      accessibilityRole="button"
      background="transparent"
      onPress={handlePressGoToAdvanced}
    >
      <NudgeCard
        title={
          <Box spacingEnd={3}>
            <TextHeadline spacingBottom={0.5}>
              {formatMessage(messages.derivativesCardTitle)}
            </TextHeadline>
            <TextLabel2>
              {formatMessage(messages.derivativesCardDescription)}
            </TextLabel2>
          </Box>
        }
        description={
          <TextHeadline color="primary" onPress={handlePressGoToAdvanced}>
            {formatMessage(messages.derivativesCardCta)}
          </TextHeadline>
        }
        media={
          <Box position="relative" right={16} bottom={6}>
            <Pictogram name="advancedTradingDesktop" dimension="64x64" />
          </Box>
        }
        width="100%"
      />
    </Pressable>
  );
});

import { ComponentProps, memo, useState } from 'react';
import { Button, Text } from 'react-native';
import { mockKillSwitches } from '@support/mocks/mockKillSwitches';
import { fireEvent, render, waitFor } from '@testing-library/react-native';
import { ApiError, NetworkError } from '@cbhq/data-layer';
import { IntlProvider } from '@cbhq/i18n';

import { useOnMount } from '@hooks/useOnMount';
import * as networkInfoModule from '@utils/networkInfo';
import { ErrorStatsProvider } from '@app/contexts/ErrorStatsProvider';
import { signOut } from '@app/utils/api/auth';
import * as resetEnvironmentCacheModule from '@app/utils/data-layer/resetEnvironmentCache';
import { ErrorWithUserErrorCode } from '@app/utils/errors/assignUserErrorCode';
import { useNotifyErrorMetrics } from '@app/utils/errors/useNotifyErrorMetrics';

import { ErrorBoundary, ErrorBoundaryFallbackProps } from './ErrorBoundary';

jest.mock('@cbhq/client-analytics');
jest.mock(
  'react-native-safe-area-context',
  () => jest.requireActual('react-native-safe-area-context/jest/mock').default,
);
jest.mock('@app/utils/errors/useNotifyErrorMetrics', () => ({
  useNotifyErrorMetrics: jest.fn(),
}));

jest.mock('@app/utils/api/auth', () => ({
  ...jest.requireActual('@app/utils/api/auth'),
  signOut: jest.fn(),
}));

function Fallback(props: ErrorBoundaryFallbackProps) {
  return (
    <>
      <Text>Fallback Rendered</Text>
      <Text>Fallback Error Message: {props.error?.message}</Text>
      <Text>User Error Code: {props.userErrorCode}</Text>
      <Button title="Retry" onPress={props.onRetry} />
    </>
  );
}

describe('ErrorBoundary', () => {
  let mockNotifyBoundaryError: jest.Mock;
  let setIsInternetConnected: (newValue: boolean) => void;

  beforeEach(() => {
    setIsInternetConnected = (newValue) => {
      (
        networkInfoModule as Pick<
          typeof networkInfoModule,
          'isInternetReachable'
        >
      ).isInternetReachable = newValue;
    };
    mockNotifyBoundaryError = jest.fn();
    (useNotifyErrorMetrics as jest.Mock).mockReturnValue(
      mockNotifyBoundaryError,
    );
    mockKillSwitches({ kill_app_reset_retry_rn: false });
  });

  afterEach(async () => {
    setIsInternetConnected(true);
  });

  describe('prop types', () => {
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const check = (_props: ComponentProps<typeof ErrorBoundary>) => {};
    const onCatch = () => {};
    const baseProps = {
      // eslint-disable-next-line react/jsx-no-useless-fragment
      children: [<></>],
    } as const;

    it('does not allow willErrorBlockUser when null fallback and no onCatch', () => {
      // @ts-expect-error Cannot supply willErrorBlockUser and null fallback
      check({ ...baseProps, fallback: null, willErrorBlockUser: true });
      check({ ...baseProps, fallback: null });

      expect.pass('type test');
    });

    it('requires willErrorBlockUser when non-null fallback is provided', () => {
      // @ts-expect-error Requires willErrorBlockUser
      check({ ...baseProps, fallback: Fallback });
      check({ ...baseProps, fallback: Fallback, willErrorBlockUser: true });

      expect.pass('type test');
    });

    it('requires willErrorBlockUser when non-null fallback and onCatch is provided', () => {
      // @ts-expect-error Requires willErrorBlockUser
      check({ ...baseProps, fallback: Fallback, onCatch });
      check({
        ...baseProps,
        fallback: Fallback,
        onCatch,
        willErrorBlockUser: true,
      });

      expect.pass('type test');
    });

    it('requires willErrorBlockUser when fallback is null but onCatch is provided', () => {
      // @ts-expect-error Requires willErrorBlockUser
      check({ ...baseProps, fallback: null, onCatch });
      check({
        ...baseProps,
        fallback: null,
        onCatch,
        willErrorBlockUser: true,
      });

      expect.pass('type test');
    });

    it('dangerously allows setting the willErrorBlockUser flag', () => {
      check({
        ...baseProps,
        _dangerouslyAllowErrorDisplayFlag: true,
        fallback: null,
        onCatch,
        willErrorBlockUser: true,
      });

      check({
        ...baseProps,
        _dangerouslyAllowErrorDisplayFlag: true,
        fallback: Fallback,
        willErrorBlockUser: true,
      });

      expect.pass('type test');
    });
  });

  describe('error catching', () => {
    let throwCount: number;
    beforeEach(() => {
      throwCount = 0;
    });

    function Throws({
      error,
      maxThrows,
    }: {
      error: Error;
      maxThrows?: number;
    }) {
      const [throwIt, setThrowIt] = useState(false);

      useOnMount(() => {
        if (throwCount >= (maxThrows ?? Infinity)) return () => {};
        const errorTimeout = setTimeout(() => setThrowIt(true), 1);
        return () => clearTimeout(errorTimeout);
      });
      if (throwIt) {
        throwCount += 1;
        throw error;
      }
      return <Text>Has not thrown yet</Text>;
    }

    it('signs the user out and calls onCatch but does not notify when on 401 errors', async () => {
      const handleCatch = jest.fn();
      const testError = new ApiError(new Response(null, { status: 401 }), {});
      const { findByText } = render(
        <ErrorBoundary
          fallback={Fallback}
          onCatch={handleCatch}
          willErrorBlockUser
        >
          <Throws error={testError} />
        </ErrorBoundary>,
      );
      await findByText('Fallback Rendered');

      expect(handleCatch).toHaveBeenCalledOnce();
      expect(handleCatch).toHaveBeenCalledWith(testError, {
        userWasSignedOut: true,
      });
      expect(mockNotifyBoundaryError).not.toHaveBeenCalledOnce();
      expect(signOut).toHaveBeenCalled();
    });

    it('does not sign the user out when 401 ApiError occurs and reauthentication required flag is explicitly false', async () => {
      // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
      const handleCatch = () => {};
      const testError = new ApiError(
        {
          status: 401,
          headers: new Headers(),
        },
        null,
      );
      testError.reauthenticationRequired = false;
      const { findByText } = render(
        <ErrorBoundary
          fallback={Fallback}
          onCatch={handleCatch}
          willErrorBlockUser
        >
          <Throws error={testError} />
        </ErrorBoundary>,
      );
      await findByText('Fallback Rendered');

      expect(signOut).not.toHaveBeenCalled();
    });

    it('log error when an error is caught', async () => {
      const testError = new Error('Test Error');
      const { findByText } = render(
        <ErrorBoundary fallback={Fallback} willErrorBlockUser>
          <Throws error={testError} />
        </ErrorBoundary>,
      );

      await findByText('Fallback Rendered');

      expect(mockNotifyBoundaryError).toHaveBeenCalledOnce();
      expect(mockNotifyBoundaryError).toHaveBeenCalledWith(testError, {
        errorBlocksUser: true,
        isDuplicateError: false,
      });
    });

    it('log error multiple times for multiple errors but analytics only gets one update', async () => {
      const firstError = new Error('First Error');
      const secondError = new Error('Second Error');

      function ThrowNow({ error }: { error: Error }) {
        return (
          <Text>
            {(() => {
              throw error;
            })()}
          </Text>
        );
      }
      const { findByText } = render(
        <ErrorBoundary fallback={Fallback} willErrorBlockUser>
          {[
            <ThrowNow key="first" error={firstError} />,
            <ThrowNow key="second" error={secondError} />,
          ]}
        </ErrorBoundary>,
      );
      await findByText('Fallback Rendered');

      expect(mockNotifyBoundaryError).toHaveBeenCalledTimes(2);
      expect(mockNotifyBoundaryError).toHaveBeenCalledWith(firstError, {
        errorBlocksUser: true,
        isDuplicateError: false,
      });
      expect(mockNotifyBoundaryError).toHaveBeenCalledWith(secondError, {
        errorBlocksUser: true,
        /**
         * It is *very* important that only one of these logs to analytics
         * Two errors in a single render will result in the user seeing
         * only *one* error screen so we should only count these once
         * in this scenario.
         */
        isDuplicateError: true,
      });
    });

    it('renders children when no error is caught', async () => {
      const { getByText } = render(
        <ErrorBoundary fallback={Fallback} willErrorBlockUser>
          <Text>Child Content</Text>
        </ErrorBoundary>,
      );

      expect(getByText('Child Content')).toBeTruthy();
    });

    it('renders the fallback as a component when caught', async () => {
      const { findByText } = render(
        <ErrorBoundary fallback={Fallback} willErrorBlockUser>
          <Throws error={new Error('Test Error')} />
        </ErrorBoundary>,
      );

      expect(await findByText('Fallback Rendered')).toBeTruthy();
    });

    it('renders the fallback as an exotic (memo) component when caught', async () => {
      const MemoFallback = memo(Fallback);

      const { findByText } = render(
        <ErrorBoundary fallback={MemoFallback} willErrorBlockUser>
          <Throws error={new Error('Test Error')} />
        </ErrorBoundary>,
      );

      expect(await findByText('Fallback Rendered')).toBeTruthy();
    });

    it('passes the thrown error to the fallback component', async () => {
      const { findByText } = render(
        <ErrorBoundary fallback={Fallback} willErrorBlockUser>
          <Throws error={new Error('Test Error')} />
        </ErrorBoundary>,
      );

      expect(
        await findByText('Fallback Error Message: Test Error'),
      ).toBeTruthy();
    });

    it('passes the userErrorCode to the fallback component', async () => {
      const testError: ErrorWithUserErrorCode = new Error('Test Error');
      testError.userErrorCode = 'TEST-CODE';
      const { findByText } = render(
        <ErrorBoundary fallback={Fallback} willErrorBlockUser>
          <Throws error={testError} />
        </ErrorBoundary>,
      );

      expect(await findByText('User Error Code: TEST-CODE')).toBeTruthy();
    });

    it('calls onCatch when an error is caught', async () => {
      const testError = new Error('Test Error');
      const onCatch = jest.fn();
      const { findByText } = render(
        <ErrorBoundary fallback={Fallback} onCatch={onCatch} willErrorBlockUser>
          <Text>Child Content</Text>
          <Throws error={testError} />
        </ErrorBoundary>,
      );

      await findByText('Fallback Rendered');

      expect(onCatch).toHaveBeenCalledOnce();
      expect(onCatch).toHaveBeenCalledWith(testError, {
        userWasSignedOut: false,
      });
    });

    describe('retries', () => {
      beforeEach(() => {
        jest
          .spyOn(resetEnvironmentCacheModule, 'resetEnvironmentCache')
          .mockResolvedValue();
      });
      describe('when kill_app_reset_retry_rn is false', () => {
        it('clears the error when the fallback onRetry callback is called', async () => {
          const { findByText, getByText } = render(
            <ErrorBoundary fallback={Fallback} willErrorBlockUser>
              <Text>Child Content</Text>
              <Throws error={new Error()} />
            </ErrorBoundary>,
          );

          fireEvent.press(await findByText('Retry'));

          expect(getByText('Child Content')).toBeTruthy();

          // To leave the component in a "settled" state
          await findByText('Fallback Rendered');
        });

        it('does not auto-retry when the device is offline', async () => {
          (
            networkInfoModule as Pick<
              typeof networkInfoModule,
              'isInternetReachable'
            >
          ).isInternetReachable = false;

          const { findByText } = render(
            <IntlProvider locale="en">
              <ErrorStatsProvider>
                <ErrorBoundary fallback={Fallback} willErrorBlockUser>
                  <Text>Child Content</Text>
                  <Throws error={new Error('Test Error')} />
                </ErrorBoundary>
              </ErrorStatsProvider>
            </IntlProvider>,
          );

          fireEvent.press(await findByText('Retry'));
          await findByText('Fallback Rendered');

          expect(throwCount).toBe(2);
          expect(
            resetEnvironmentCacheModule.resetEnvironmentCache,
          ).not.toHaveBeenCalled();
        });

        it('does not auto-retry network errors', async () => {
          const networkError = new NetworkError({ message: 'Test Error' });
          const { findByText } = render(
            <ErrorStatsProvider>
              <ErrorBoundary fallback={Fallback} willErrorBlockUser>
                <Text>Child Content</Text>
                <Throws error={networkError} />
              </ErrorBoundary>
            </ErrorStatsProvider>,
          );

          fireEvent.press(await findByText('Retry'));
          await findByText('Child Content');

          await waitFor(() => expect(throwCount).toBe(2));
          expect(
            resetEnvironmentCacheModule.resetEnvironmentCache,
          ).not.toHaveBeenCalled();
        });

        it('resets the GQL/IAH cache when the first retry produces the same error', async () => {
          const { findByText, getByText } = render(
            <ErrorStatsProvider>
              <ErrorBoundary fallback={Fallback} willErrorBlockUser>
                <Text>Child Content</Text>
                <Throws
                  error={new Error('Test Error')}
                  /////////////////////////////////////
                  // Critical that we only throw twice so we don't trigger
                  // an app-restart
                  // 1. initial throw (retried by user)
                  // 2. rethrow after first auto-retry
                  // 3. works!
                  /////////////////////////////////////
                  /////////////////////////////////////
                  maxThrows={2}
                />
              </ErrorBoundary>
            </ErrorStatsProvider>,
          );

          fireEvent.press(await findByText('Retry'));
          await waitFor(() => expect(throwCount).toBe(2));

          expect(getByText('Child Content')).toBeTruthy();
          expect(
            resetEnvironmentCacheModule.resetEnvironmentCache,
          ).toHaveBeenCalled();
        });

        it('prompts to restart the app when the auto-retry fails', async () => {
          const { findByText, getByText } = render(
            <IntlProvider locale="en">
              <ErrorStatsProvider>
                <ErrorBoundary fallback={Fallback} willErrorBlockUser>
                  <Text>Child Content</Text>
                  <Throws error={new Error('Test Error')} />
                </ErrorBoundary>
              </ErrorStatsProvider>
            </IntlProvider>,
          );

          fireEvent.press(await findByText('Retry'));
          await findByText('Fallback Rendered');

          expect(getByText('Go to home')).toBeTruthy();
          expect(throwCount).toBe(3);
        });
      });

      describe('when kill_app_reset_retry_rn is true', () => {
        beforeEach(() => {
          jest
            .spyOn(resetEnvironmentCacheModule, 'resetEnvironmentCache')
            .mockResolvedValue();
          mockKillSwitches({
            kill_app_reset_retry_rn: true,
          });
        });

        it('resets the GQL/IAH cache when the third retry produces the same error', async () => {
          const { findByText, getByText } = render(
            <ErrorStatsProvider>
              <ErrorBoundary fallback={Fallback} willErrorBlockUser>
                <Text>Child Content</Text>
                <Throws
                  error={new Error(`Test Error${throwCount}`)}
                  maxThrows={4}
                />
              </ErrorBoundary>
            </ErrorStatsProvider>,
          );

          fireEvent.press(await findByText('Retry'));
          expect(
            resetEnvironmentCacheModule.resetEnvironmentCache,
          ).not.toHaveBeenCalled();
          fireEvent.press(await findByText('Retry'));
          expect(
            resetEnvironmentCacheModule.resetEnvironmentCache,
          ).not.toHaveBeenCalled();
          fireEvent.press(await findByText('Retry'));

          await waitFor(() => expect(throwCount).toBe(4));

          expect(getByText('Child Content')).toBeTruthy();
          expect(
            resetEnvironmentCacheModule.resetEnvironmentCache,
          ).toHaveBeenCalledTimes(1);
        });

        it('does not prompt to restart the app when the auto-retry fails', async () => {
          const { findByText, queryByText } = render(
            <IntlProvider locale="en">
              <ErrorStatsProvider>
                <ErrorBoundary fallback={Fallback} willErrorBlockUser>
                  <Text>Child Content</Text>
                  <Throws error={new Error('Test Error')} />
                </ErrorBoundary>
              </ErrorStatsProvider>
            </IntlProvider>,
          );

          fireEvent.press(await findByText('Retry'));
          await findByText('Fallback Rendered');

          expect(queryByText('Go to home')).toBeFalsy();
        });
      });

      describe('kill_default_ttl_rn', () => {
        it.each`
          killSwitch | value
          ${false}   | ${false}
          ${true}    | ${true}
        `(
          'calls resetEnvironmentCache with `$value` when killSwitch is `$killSwitch`',
          async ({ killSwitch, value }) => {
            mockKillSwitches({
              kill_default_ttl_rn: killSwitch,
            });
            const { findByText, getByText } = render(
              <ErrorStatsProvider>
                <ErrorBoundary fallback={Fallback} willErrorBlockUser>
                  <Text>Child Content</Text>
                  <Throws error={new Error('Test Error')} maxThrows={2} />
                </ErrorBoundary>
              </ErrorStatsProvider>,
            );

            fireEvent.press(await findByText('Retry'));
            await waitFor(() => expect(throwCount).toBe(2));

            expect(getByText('Child Content')).toBeTruthy();

            expect(
              resetEnvironmentCacheModule.resetEnvironmentCache,
            ).toHaveBeenCalledWith(value);
          },
        );
      });
    });
  });
});

import { useMemo } from 'react';
import { HeroSquare } from '@cbhq/cds-mobile/illustrations';
import { Box, VStack } from '@cbhq/cds-mobile/layout';
import { Modal } from '@cbhq/cds-mobile/overlays';
import { TextBody, TextTitle3 } from '@cbhq/cds-mobile/typography';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { IconButton } from '@components/interactables/IconButton';
import { Link } from '@components/typography/Link';

const i18nKey = 'FullscreenErrorModal';

const messages = defineMessages({
  close: {
    id: `${i18nKey}.close`,
    defaultMessage: 'Close',
    description: 'Close button for the error message',
  },
});

type FullscreenErrorModalProps = {
  onClose?: () => void;
  visible: boolean;
  title: string | JSX.Element;
  subtitle: string | JSX.Element;
  learnMore?: {
    to: string;
    label: string;
  };
};

function noop() {}

export function FullscreenErrorModal({
  onClose,
  visible,
  title,
  subtitle,
  learnMore,
}: FullscreenErrorModalProps) {
  const { formatMessage } = useIntl();

  const learnMoreElement = useMemo(() => {
    if (!learnMore) {
      return null;
    }

    return (
      <TextBody>
        <Link to={learnMore.to}>{learnMore.label}</Link>
      </TextBody>
    );
  }, [learnMore]);

  const closeButton = useMemo(() => {
    if (!onClose) {
      return null;
    }

    return (
      <IconButton
        name="close"
        aria-label={formatMessage(messages.close)}
        transparent
        onPress={onClose}
      />
    );
  }, [formatMessage, onClose]);

  return (
    <Modal visible={visible} onRequestClose={onClose ?? noop}>
      <Box
        width="100%"
        spacing={2}
        spacingHorizontal={4}
        justifyContent="flex-end"
        flexDirection="row"
      >
        {closeButton}
      </Box>
      <VStack height="100%">
        <VStack
          justifyContent="center"
          alignItems="center"
          gap={3}
          flexGrow={1}
          maxHeight="80%"
        >
          <HeroSquare name="error400" />
          <VStack gap={0.5} alignItems="center" spacingHorizontal={5}>
            <TextTitle3 align="center">{title}</TextTitle3>
            <TextBody align="center" color="foregroundMuted">
              {subtitle}
            </TextBody>
            {learnMoreElement}
          </VStack>
        </VStack>
      </VStack>
    </Modal>
  );
}

import { memo, useCallback, useContext, useMemo, useState } from 'react';
