import { getErrorInstance } from '@utils/errors/getErrorInstance';
import { AppIntlContext } from '@app/contexts/AppIntlProvider';
import { AppLocaleContext } from '@app/contexts/AppLocaleProvider';

import { LocalePickerModal } from './LocalePicker';

const messages = defineMessages({
  confirmLanguageTitle: {
    id: 'LocaleSwitchTray.confirmLanguage',
    defaultMessage: 'Confirm account language',
    description: 'Title for the confirm language tray',
  },
  confirmLanguageBody: {
    id: 'LocaleSwitchTray.confirmLanguageBody',
    defaultMessage:
      'This will be used across Coinbase’s products and services.',
    description: 'Text body description for the confirm language tray',
  },
  changeButton: {
    id: 'LocaleSwitchTray.changeButton',
    defaultMessage: 'Change',
    description: 'Change language button for the confirm language tray',
  },
  confirmButton: {
    id: 'LocaleSwitchTray.confirmButton',
    defaultMessage: 'Confirm',
    description: 'Confirm button for the confirm language tray',
  },
  somethingWrong: {
    id: 'LocaleSwitchTray.somethingWrong',
    defaultMessage: 'Something went wrong. Please try again.',
    description: 'Message for the error toast',
  },
});

type LocaleSwitchTrayProps = {
  onClose: () => void;
};

export const LocaleSwitchTray = memo(function LocaleSwitchTray({
  onClose,
}: LocaleSwitchTrayProps) {
  const { formatMessage } = useIntl();
  const { locale } = useContext(AppIntlContext);
  const { updateLocale, isLocaleUpdating } = useContext(AppLocaleContext);
  const [showPicker, setShowPicker] = useState(false);
  const [isLoading, setisLoading] = useState(false);
  const toast = useToast();

  useLogEventOnMount('locale_alert_viewed', {
    componentType: ComponentType.tray,
    action: ActionType.render,
  });

  useOnMount(() => {
    setStoreDataSynchronous(
      'UserPreference',
      'locale_alert_timestamp',
      Date.now(),
    );
  });

  const togglePickerModal = useCallback(
    () => setShowPicker((prev) => !prev),
    [],
  );

  const localeLanguage = useMemo(
    () =>
      supportedLocales.find((item) => item.locale === locale) ?? {
        locale: 'en',
        display_name: 'English', //doesn't need to be translated since this is shown during language selection
      },
    [locale],
  );

  const handleClose = useCallback(() => {
    logEvent('locale_alert_closed', {
      componentType: ComponentType.button,
      action: ActionType.click,
    });
    onClose();
  }, [onClose]);

  const handleSubmit = useCallback(async () => {
    setisLoading(true);
    logEvent('locale_alert_confirmed', {
      componentType: ComponentType.button,
      action: ActionType.click,
      newLocale: localeLanguage.locale,
    });
    try {
      await updateLocale(localeLanguage.locale);
      setisLoading(isLocaleUpdating);
    } catch (e) {
      logEvent('locale_alert_confirm_error', {
        componentType: ComponentType.page,
        action: ActionType.select,
        newLocale: localeLanguage.locale,
        error: getErrorInstance(e).message,
      });
      handleClose();
      toast.show(formatMessage(messages.somethingWrong));
    }
  }, [
    updateLocale,
    toast,
    isLocaleUpdating,
    handleClose,
    formatMessage,
    localeLanguage.locale,
  ]);

  return (
    <Tray
      onCloseComplete={handleClose}
      hideHandleBar
      disableCapturePanGestureToDismiss
      preventDismissGestures
    >
      <VStack
        spacingHorizontal={3}
        spacingTop={1}
        spacingBottom={0}
        justifyContent="center"
        alignItems="center"
        testID="locale-switch-tray"
        gap={2}
      >
        <SpotSquare name="globalTransactions" />
        <TextTitle3>{formatMessage(messages.confirmLanguageTitle)}</TextTitle3>
        <TextBody color="foregroundMuted">
          {formatMessage(messages.confirmLanguageBody)}
        </TextBody>
        <TextInput
          value={localeLanguage.display_name}
          accessibilityRole="text"
          disabled
          end={
            <VStack spacingEnd={2}>
              {/* eslint-disable-next-line jsx-a11y/anchor-is-valid */}
              <Link onPress={togglePickerModal}>
                <TextCaption color="primary">
                  {formatMessage(messages.changeButton)}
                </TextCaption>
              </Link>
            </VStack>
          }
        />
        <Button onPress={handleSubmit} loading={isLoading} block>
          {formatMessage(messages.confirmButton)}
        </Button>
      </VStack>
      <LocalePickerModal
        showPicker={showPicker}
        onClose={togglePickerModal}
        closeParent={handleClose}
      />
    </Tray>
  );
});

