  const { screenWidth } = useDimensions();
  const { hasAssetListPriceContext } = useContext(AssetListPriceContext);

  const asset = useFragment(
    graphql`
      fragment MarketCellFragment on Asset {
        imageUrl
        name
        platformName
        displaySymbol
        marketCapV2(quoteCurrency: $nativeCurrency)
        latestPrice(quoteCurrency: $nativeCurrency) {
          price
          percentChanges {
            day
          }
        }
      }
    `,
    assetRef,
  );

  const { percent, sign, variant } = usePercentChange(
    asset?.platformName,
    asset.latestPrice?.percentChanges?.day,
  );
  const latestPriceFormatter = useNativeCurrencyFormatter({
    minimumFractionDigits: getPriceScale(asset?.latestPrice?.price),
  });

  const formatPriceChange = usePriceChangeFormatter();
  const price = parseFloat(asset.latestPrice?.price ?? '0');
  const priceChange = formatPriceChange(
    price,
    asset?.latestPrice?.percentChanges?.day ?? 0,
    {
      isSensitive: false,
    },
  );

  const marketCap = parseFloat(asset?.marketCapV2 ?? '0');

  // Only show the sparkline when there is enough room
  // in the viewport, and the device font hasnt been scaled up
  const scale = useRootScale();
  const isSmallScale =
    scale === 'xSmall' || scale === 'small' || scale === 'medium';
  const isLargeScale = scale === 'large';
  const showSparkline =
    !!sparkline &&
    screenWidth > breakpoints.small &&
    (isSmallScale || isLargeScale);

  const detail = useMemo(
    () =>
      latestPriceFormatter({
        amount: asset?.latestPrice?.price,
        isSensitive: false,
        minimumFractionDigits: getPriceScale(asset?.latestPrice?.price),
      }),
    [asset?.latestPrice?.price, latestPriceFormatter],
  );

  const subdetail = useMemo(() => `${sign}${percent}`, [percent, sign]);

  const detailWidth = useMemo(() => {
    const largerScale = isLargeScale ? '33%' : '30%';
    const scaleSize = isSmallScale ? '20%' : largerScale;
    return showSparkline ? scaleSize : undefined;
  }, [isLargeScale, isSmallScale, showSparkline]);

  const hasLivePriceTickerV2Experiment = useIsTreatment(
    'dec_2023_rn_watchlist_live_price_ticker_v2',
  );

  const action = useMemo(() => {
    if (hasAssetListPriceContext) {
      return (
        <Box>
          {showLivePriceTicker ? (
            <VStack justifyContent="center" alignItems="flex-end">
              <LiveTicker
                value={detail ?? ''}
                variant="body"
                alignSelf="flex-end"
                color="foreground"
                enableColorChange={!hasLivePriceTickerV2Experiment}
                fallback={<Fallback height={15} width={80} spacingBottom={1} />}
                tabularNumbers={false}
              />
              {hasLivePriceTickerV2Experiment ? (
                <Subdetail
                  percent={percent}
                  price={priceChange}
                  marketCap={marketCap}
                  sign={sign}
                  variant={variant}
                  showLiveTicker
                />
              ) : (
                <LiveTicker
                  value={subdetail}
                  variant="body"
                  alignSelf="flex-end"
                  color={variant}
                  fallback={<Fallback height={15} width={40} spacingTop={1} />}
                  tabularNumbers={false}
                />
              )}
            </VStack>
          ) : (
            <VStack
              alignContent="flex-end"
              alignItems="flex-end"
              justifyContent="center"
            >
              <TextBody
                align="end"
                numberOfLines={1}
                adjustsFontSizeToFit={!!detailWidth}
              >
                {detail}
              </TextBody>
              <Subdetail
                percent={percent}
                price={priceChange}
                marketCap={marketCap}
                sign={sign}
                variant={variant}
              />
            </VStack>
          )}
        </Box>
      );
    }

    return undefined;
  }, [
    hasAssetListPriceContext,
    showLivePriceTicker,
    detail,
    hasLivePriceTickerV2Experiment,
    percent,
    priceChange,
    marketCap,
    sign,
    variant,
    subdetail,
    detailWidth,
  ]);

  const cellMedia = useMemo(
    () => (
      <CellMedia type="asset" source={asset.imageUrl} cache="force-cache" />
    ),
    [asset.imageUrl],
  );

  return (
    <ListCell
      description={listCellProps.description ?? asset.displaySymbol}
      title={asset.name}
      detail={detail}
      subdetail={hideSubdetail ? undefined : subdetail}
      variant={variant}
      // Allow all fields to be overridden
      {...listCellProps}
      intermediary={showSparkline ? sparkline : undefined}
      detailWidth={detailWidth}
      priority={showSparkline ? undefined : 'end'}
      media={cellMedia}
      action={action}
    />
  );
}, isEqual);

type SubdetailProps = {
  percent: string;
  price: string;
  marketCap: number;
  sign: string;
  variant: string;
  showLiveTicker?: boolean;
};

const Subdetail = memo(function Subdetail({
  percent,
  price,
  marketCap: rawMarketCap,
  sign,
  variant,
  showLiveTicker = false,
}: SubdetailProps) {
  const { displayedPrice, toggleAssetPrice } = useContext(
    AssetListPriceContext,
  );
  const { formatMessage } = useIntl();

  useLogEventOnMount('asset_list_prices_view', {
    action: ActionType.view,
    componentType: ComponentType.button,
    displayedPrice,
  });

  const percentChange = `${sign}${percent}`;
  const priceChange = `${sign}${price}`;
  const marketCap = useCompactNumberFormatter({ value: rawMarketCap });

  const priceMap = useMemo(
    () => ({
      percentChange,
      priceChange,
      marketCap,
    }),
    [marketCap, percentChange, priceChange],
  );

  const accessibilityLabel = useMemo(
    () =>
      displayedPrice === 'marketCap'
        ? formatMessage(messages.marketCapLabel, {
            marketCap,
          })
        : formatMessage(messages.performanceLabel, {
            direction:
              variant === 'positive'
                ? formatMessage(messages.upLabel)
                : formatMessage(messages.downLabel),
            change:
              displayedPrice === 'percentChange'
                ? percentChange.slice(1)
                : priceChange.slice(1),
          }),
    [
      displayedPrice,
      formatMessage,
      marketCap,
      percentChange,
      priceChange,
      variant,
    ],
  );

  const variantMap: Record<string, ColorScheme> = useMemo(
    () => ({
      positive: 'green',
      foregroundMuted: 'gray',
      negative: 'red',
    }),
    [],
  );

  const { background } = tagColorMap[TAG_INTENT][variantMap[variant]];
  const backgroundColor = usePaletteValueToRgbaString(background);
  const spacingStyles = useSpacingStyles({
    spacingHorizontal: horizontalSpacing[TAG_INTENT],
  });
  const style = useMemo(
    () => ({ paddingVertical: 2, ...spacingStyles }),
    [spacingStyles],
  );

  if (!percentChange) {
    return null;
  }

  return (
    <PressableOpacity
      onPress={toggleAssetPrice}
      accessibilityLabel={accessibilityLabel}
    >
      {showLiveTicker ? (
        // Unable to use a CDS tag component here as the children passed in are wrapped in a Text
        // component and when the value of the text changes, the tag does not resize. This is due
        // to the align-items stretch default style
        <Box
          style={style}
          dangerouslySetBackground={backgroundColor}
          alignItems="flex-end"
          background="background"
          borderRadius="roundedSmall"
        >
          <LiveTicker
            value={priceMap[displayedPrice]}
            variant="label1"
            alignItems="flex-end"
            color={variant as PaletteForeground}
            fallback={<Fallback height={12} width={50} />}
            tabularNumbers={false}
          />
        </Box>
      ) : (
        <Tag colorScheme={variantMap[variant]} alignSelf="flex-end">
          {priceMap[displayedPrice]}
        </Tag>
      )}
    </PressableOpacity>
  );
});

