import { memo } from 'react';
import { ImageSourcePropType } from 'react-native/types';
import { CellMedia } from '@cbhq/cds-mobile/cells/CellMedia';
import { DotSymbol } from '@cbhq/cds-mobile/dots/DotSymbol';
import { graphql, useFragment } from '@cbhq/data-layer';

import { FiatIcon } from '@app/components/Icons/FiatIcon';
import { errorVitals } from '@app/utils/errors/errorVitals';

import { MarketCellIconFragment$key } from './__generated__/MarketCellIconFragment.graphql';
import { CurrencyIcon } from './CurrencyIcon';

export type MarketCellIconProps = {
  assetOrFiatRef: MarketCellIconFragment$key | null;
  imageUrl?: string;
  dotSymbolUrl?: string | ImageSourcePropType;
  code?: string;
};

export const MarketCellIcon = memo<MarketCellIconProps>(
  ({ assetOrFiatRef, imageUrl, dotSymbolUrl, code }) => {
    const assetOrFiat = useFragment(
      graphql`
        fragment MarketCellIconFragment on AssetOrCurrency {
          ... on ViewerAsset {
            asset {
              ...CurrencyIconAssetFragment
            }
          }
          ... on TiersCurrency {
            code
          }
        }
      `,
      assetOrFiatRef,
    );
    if (assetOrFiat?.asset) {
      return <CurrencyIcon assetRef={assetOrFiat.asset} />;
    }
    if (assetOrFiat?.code) {
      return <FiatIcon currencyCode={assetOrFiat.code} />;
    }
    if (imageUrl || code) {
      if (imageUrl && dotSymbolUrl) {
        return (
          <DotSymbol
            size="s"
            pin="bottom-end"
            source={dotSymbolUrl}
            overlap="circular"
          >
            <CellMedia
              type="asset"
              source={imageUrl}
              accessibilityLabel={code}
            />
          </DotSymbol>
        );
      }

      return imageUrl ? (
        <CellMedia type="asset" source={imageUrl} accessibilityLabel={code} />
      ) : (
        <FiatIcon currencyCode={code ?? ''} />
      );
    }
    errorVitals.logError(
      new Error('MarketCellIcon: invalid asset or fiat currency'),
      {
        severity: 'error',
        context: 'market_cell_icon',
        isHandled: false,
      },
    );
    return null;
  },
);

