} from './SimpleTradePaymentMethodCellSelector';

type SimpleTradeCryptoPaymentMethodCellSelectorProps = Pick<
  CryptoPaymentMethodCellProps,
  'onPress' | 'transferType'
> & {
  viewerAssetRef: SimpleTradeCryptoPaymentMethodCellSelectorFragment$key;
};

export const SimpleTradeCryptoPaymentMethodCellSelector = memo(
  function SimpleTradeCryptoPaymentMethodCellSelector({
    viewerAssetRef,
    onPress,
    transferType,
  }: SimpleTradeCryptoPaymentMethodCellSelectorProps) {
    const formatCurrency = useCurrencyFormatter();
    const { formatMessage } = useIntl();
    const { isActive: privacyModeIsActive } = usePrivacyMode();

    const { asset, accounts, rewardApy } = useFragment(
      graphql`
        fragment SimpleTradeCryptoPaymentMethodCellSelectorFragment on ViewerAsset {
          asset {
            uuid
            name
            displaySymbol
            imageUrl
          }
          rewardApy {
            formattedValue
            statsLabel
          }
          accounts {
            primary
            availableBalanceInNativeCurrency {
              value
              currency
            }
          }
        }
      `,
      viewerAssetRef,
    );
    const account = useMemo(() => {
      return accounts?.find((acc) => acc?.primary) ?? accounts?.[0];
    }, [accounts]);

    const handlePress = useCallback(
      () => onPress?.(asset?.uuid ?? ''),
      [asset?.uuid, onPress],
    );

    const media = useMemo(() => {
      return asset?.imageUrl ? (
        <CellMedia
          type="asset"
          source={asset?.imageUrl}
          accessibilityLabel={asset?.displaySymbol ?? asset?.name ?? ''}
          cache="force-cache"
        />
      ) : undefined;
    }, [asset?.displaySymbol, asset?.imageUrl, asset?.name]);

    const detail = useMemo(
      () =>
        formatCurrency({
          amount: account?.availableBalanceInNativeCurrency?.value ?? '0',
          currency: {
            code: account?.availableBalanceInNativeCurrency?.currency ?? '',
            type: 'fiat',
          },
          isSensitive: privacyModeIsActive,
        }),
      [
        account?.availableBalanceInNativeCurrency?.currency,
        account?.availableBalanceInNativeCurrency?.value,
        formatCurrency,
        privacyModeIsActive,
      ],
    );

    const showUsdcApy =
      transferType === 'sell' &&
      asset?.uuid === USDC_ASSET_ID &&
      !!rewardApy?.formattedValue;

    const isInSellToUsdcTreatment = useIsTreatment(
      'aug_2023_sell_to_usdc_growth',
      { skipTracking: !showUsdcApy },
    );

    const descriptionWithApy = useMemo(() => {
      if (isInSellToUsdcTreatment && showUsdcApy) {
        return (
          <>
            {asset?.name ? (
              <TextBody color="foregroundMuted">
                {asset?.name}
                {' • '}
              </TextBody>
            ) : null}
            <TextBody color="positive">
              {rewardApy?.formattedValue ?? ''} {rewardApy?.statsLabel ?? ''}
            </TextBody>
          </>
        );
      }

      return asset?.name;
    }, [
      isInSellToUsdcTreatment,
      showUsdcApy,
      asset?.name,
      rewardApy?.formattedValue,
      rewardApy?.statsLabel,
    ]);

    const listCellTitle = useMemo(() => {
      return transferType === 'buy'
        ? formatMessage(messages.buyTitle)
        : formatMessage(messages.sellTitleTo);
    }, [formatMessage, transferType]);

    if (
      !asset ||
      // if buy payment method selector and no balance do not show asset as option
      (transferType === 'buy' &&
        !Number(account?.availableBalanceInNativeCurrency?.value ?? 0))
    ) {
      return (
        <SimpleTradeMissingPaymentMethodCell
          onPress={handlePress}
          transferType={transferType}
        />
      );
    }

    return (
      <PressableOpacity onPress={handlePress}>
        <ListCell
          title={listCellTitle}
          description={descriptionWithApy}
          media={media}
          detail={detail}
          subdetail={formatMessage(messages.subdetail)}
          detailWidth="30%"
          accessory="arrow"
          outerSpacing={DEFAULT_CELL_SPACING_CONFIG}
        />
      </PressableOpacity>
    );
  },
);

