import { memo, useContext, useEffect, useMemo } from 'react';
import { Pressable, ViewStyle } from 'react-native';
import { useIndexCounter } from '@cbhq/cds-common/hooks/useIndexCounter';
import { Box, VStack } from '@cbhq/cds-mobile/layout';

import { useDimensions } from '@designSystem/hooks/useDimensions';
import { ProgressCarousel } from '@designSystem/navigation/progress/ProgressCarousel/ProgressCarousel';
import { ProgressCarouselSlide } from '@designSystem/navigation/progress/ProgressCarousel/ProgressCarouselSlide';

import { ShareableContentObjectType } from '@app/components/ShareTray/hooks/useShareableContent';
import { ShareTrayContext } from '@app/components/ShareTray/ShareTrayProvider';
import { useResizeContent } from '@app/hooks/useResizeContent';

import { ShareableContent } from './ShareableContent';

type ShareableContentContainerProps = {
  content: ShareableContentObjectType;
  capturableContent: number;
  shareableContentMaxHeight: number;
  updateActiveIndex: (idx: number) => void;
};

const ShareableContentContainer = memo<ShareableContentContainerProps>(
  function ShareableContentContainer({
    content,
    shareableContentMaxHeight,
    updateActiveIndex,
  }) {
    const { activeIndex, setActiveIndex } = useIndexCounter({
      length: Object.keys(content).length,
    });

    useEffect(() => {
      updateActiveIndex(activeIndex);
    }, [activeIndex, updateActiveIndex]);

    const { windowWidth } = useDimensions();

    // ProgressCarouselSlide includes a bottom gutter that occupies
    // valuable Tray real estate.
    const slideStyle = useMemo(() => ({ paddingBottom: 0 }), []);

    const pressableStyle: ViewStyle = useMemo(
      () => ({
        justifyContent: 'center',
        alignItems: 'center',
        flex: 1,
      }),
      [],
    );

    const { handleResize } = useResizeContent({
      maxHeight: shareableContentMaxHeight,
      maxWidth: windowWidth,
    });

    const { handleTouchStart, handleTouchUpdate } =
      useContext(ShareTrayContext);

    // ProgressCarousel expects at least 2 slides
    if (Object.keys(content).length > 1) {
      return (
        <VStack>
          <ProgressCarousel
            testID="ShareTrayCarousel"
            activeIndex={activeIndex}
            setActiveIndex={setActiveIndex}
          >
            {Object.values(content).map(({ height, width, url }, idx) => {
              const { scaledHeight, scaledWidth } = handleResize(height, width);

              return (
                <ProgressCarouselSlide
                  key={idx} // eslint-disable-line react/no-array-index-key
                  dangerouslySetStyle={slideStyle}
                >
                  <Pressable
                    accessibilityRole="button"
                    style={pressableStyle}
                    onTouchEnd={handleTouchUpdate}
                    onTouchMove={handleTouchUpdate}
                    onTouchStart={handleTouchStart}
                  >
                    <Box
                      justifyContent="center"
                      alignItems="center"
                      spacingTop={4}
                      spacingBottom={6}
                    >
                      <ShareableContent
                        maxHeight={shareableContentMaxHeight}
                        scaledHeight={scaledHeight}
                        scaledWidth={scaledWidth}
                        url={url}
                      />
                    </Box>
                  </Pressable>
                </ProgressCarouselSlide>
              );
            })}
          </ProgressCarousel>
        </VStack>
      );
    }

    const { height, width, url } = content[0];
    const { scaledHeight, scaledWidth } = handleResize(height, width);

    return (
      <Box
        flexGrow={1}
        justifyContent="center"
        alignItems="center"
        spacingTop={2}
        spacingBottom={6}
        background="background"
      >
        <ShareableContent
          maxHeight={shareableContentMaxHeight}
          scaledHeight={scaledHeight}
          scaledWidth={scaledWidth}
          url={url}
        />
      </Box>
    );
  },
);

export { ShareableContentContainer };

