export type AssetSelectorCellProps = Pick<
  ListCellProps,
  'title' | 'description' | 'detail' | 'subdetail'
> &
  Pick<
    AssetSelectorTrayProps,
    | 'selectedAssetId'
    | 'selectedAssetAddress'
    | 'excludeAssetIds'
    | 'recurringTradeExperimentRecurringPeriod'
    | 'tradeSubType'
  > & {
    tradeType?: TradeType;
    assetImageUrl: string;
    onPress?: () => void;
    assetSelectorType: AssetSelectorMode;
    transferSource?: TransferSource;
    readOnly?: boolean;
    openAsModal?: boolean;
  };

export const AssetSelectorCell = memo(function AssetSelectorCell({
  assetImageUrl,
  onPress,
  assetSelectorType,
  selectedAssetId,
  selectedAssetAddress,
  excludeAssetIds,
  transferSource,
  recurringTradeExperimentRecurringPeriod,
  tradeType,
  readOnly,
  tradeSubType,
  detail,
  subdetail,
  openAsModal,
  ...listCellProps
}: AssetSelectorCellProps) {
  const [isTrayVisible, { toggleOn: toggleTrayOn, toggleOff: toggleTrayOff }] =
    useToggler(false);
  const { logSimpleTradeClickEvent } = useSimpleTradeAnalytics(tradeType);
  const isMgxEligible = useHasMgx();

  const eventNameTapAssetSelector = useMemo(() => {
    switch (assetSelectorType) {
      case 'Buy':
        return 'buy_tapped_change_asset';
      case 'Sell':
        return 'sell_tapped_change_asset';
      case 'ConvertFrom':
        return 'convert_tapped_select_source_asset';
      case 'ConvertTo':
        return 'convert_tapped_select_target_asset';
      default:
        return '';
    }
  }, [assetSelectorType]);

  const eventNameChangeAsset = useMemo(() => {
    switch (assetSelectorType) {
      case 'Buy':
        return 'buy_asset_changed';
      case 'Sell':
        return 'sell_asset_changed';
      case 'ConvertFrom':
        return 'convert_tapped_source_asset';
      case 'ConvertTo':
        return 'convert_tapped_target_asset';
      default:
        return '';
    }
  }, [assetSelectorType]);

  const handleOnCellPress = useCallback(() => {
    if (eventNameTapAssetSelector) {
      logSimpleTradeClickEvent(eventNameTapAssetSelector, {});
    }
    if (tradeSubType === 'dex' && !readOnly) {
      markJourneyOnce('navigate_to_dex_asset_selector_tray');
    }

    if (readOnly) {
      // noop to disallow asset change
      return;
    }

    onPress?.();
    toggleTrayOn();
  }, [
    eventNameTapAssetSelector,
    tradeSubType,
    readOnly,
    onPress,
    logSimpleTradeClickEvent,
    toggleTrayOn,
  ]);

  const handleAssetSelect = useCallback(
    (params: AccountSelectorOnSelectProps | AssetSelectorOnSelectProps) => {
      // Close asset selector tray upon selection. This resolves a bug where DeFi
      // gating prompts don't appear due to the tray's continued open state.
      const isDefiAsset =
        'contractAddress' in params && params?.contractAddress;
      const isDexFlow = isDefiAsset;
      const isMgxFlow = isMgxEligible && isDefiAsset;
      if (isDexFlow || isMgxFlow) {
        toggleTrayOff();
      }

      if (eventNameChangeAsset) {
        logSimpleTradeClickEvent?.(eventNameChangeAsset, {
          asset: params?.assetId,
        });
      }
    },
    [
      eventNameChangeAsset,
      isMgxEligible,
      logSimpleTradeClickEvent,
      toggleTrayOff,
    ],
  );

  const media = useMemo(
    () =>
      assetImageUrl ? (
        <CellMedia type="asset" source={assetImageUrl} testID="asset-icon" />
      ) : undefined,
    [assetImageUrl],
  );

  const detailNode = useMemo(
    () => (typeof detail === 'string' ? <TextBody>{detail}</TextBody> : detail),
    [detail],
  );

  const subdetailNode = useMemo(
    () =>
      typeof subdetail === 'string' ? (
        <TextBody color="foregroundMuted">{subdetail}</TextBody>
      ) : (
        subdetail
      ),
    [subdetail],
  );

  const action = useMemo(
    () => (
      <VStack
        alignItems="flex-end"
        offsetEnd={0.5}
        spacingEnd={0.5}
        testID="trade-asset-cell-right-content"
      >
        {detailNode}
        {subdetailNode}
      </VStack>
    ),
    [detailNode, subdetailNode],
  );

  const detailWidth = !readOnly ? '40%' : '25%';

  return (
    <>
      <PressableOpacityOrReadOnly
        readOnly={readOnly}
        onPress={handleOnCellPress}
        testID="asset-selector-cell"
      >
        <ListCell
          {...listCellProps}
          detail={detail}
          subdetail={subdetail}
          testID="trade-asset-cell"
          media={media}
          detailWidth={detailWidth}
          action={action} // action node contains detail and subdetail content. This prop is passed in for certain Android screens which do not render a non-textual node
          outerSpacing={DEFAULT_CELL_SPACING_CONFIG}
          accessory={!readOnly ? 'arrow' : undefined}
        />
      </PressableOpacityOrReadOnly>
      <AssetSelectorTray
        transferSource={transferSource}
        isTrayVisible={isTrayVisible}
        toggleTrayOff={toggleTrayOff}
        onAssetSelect={handleAssetSelect}
        tradeType={assetSelectorType}
        tradeSubType={tradeSubType}
        selectedAssetId={selectedAssetId}
        selectedAssetAddress={selectedAssetAddress}
        excludeAssetIds={excludeAssetIds}
        recurringTradeExperimentRecurringPeriod={
          recurringTradeExperimentRecurringPeriod
        }
        openAsModal={openAsModal}
      />
    </>
  );
});

