export type PromoSuccessCallback = (
  codeValue: string,
  userIncentiveId?: string,
) => void;

export type PromoRowProps = {
  queryRef: PromoRowFragment$key;
  fiatAmount: Amount;
  onSuccess: PromoSuccessCallback;
  defaultInputValue?: string;
};

const PromoRowContent = memo(function PromoRowContent({
  queryRef,
  fiatAmount,
  onSuccess,
  defaultInputValue,
}: PromoRowProps) {
  const { formatMessage } = useIntl();
  const isPromoExperiment = useTradePreviewPromoExperiment();

  const [inputValue, setInputValue] = useState<string | null>(
    defaultInputValue ?? null,
  );
  const [helperText, setHelperText] = useState<string>(
    formatMessage(messages.helperTextPlaceholder),
  );
  const [promoResponse, setPromoResponse] =
    useState<ApplyTradePromoCodeResponse | null>(null);

  const isSuccess = promoResponse?.__typename === 'IncentiveCodeDetails';
  const isError = promoResponse?.__typename === 'IncentiveCodeDetailsError';

  const query = useFragment(
    graphql`
      fragment PromoRowFragment on Query {
        ...useIsTradePromoCodeEligibleFragment
          @arguments(
            skipTradePromoCodeEligibleQuery: $skipTradePromoCodeEligibleQuery
          )
      }
    `,
    queryRef,
  );

  const isEligible = useIsTradePromoCodeEligible(query);

  const [applyTradePromoCodeMutation, isApplyTradePromoCodeLoading] =
    useApplyTradePromoCode();

  const resetState = useCallback(() => {
    setPromoResponse(null);
    setHelperText(formatMessage(messages.helperTextPlaceholder));
    setInputValue('');
  }, [formatMessage]);

  const onChangeText = useCallback(
    (text: string) => {
      const promoCodeNoWhiteSpace = text.replaceAll(' ', '');
      if (!promoCodeNoWhiteSpace) {
        resetState();
      } else {
        setInputValue(promoCodeNoWhiteSpace);
      }
    },
    [resetState],
  );

  const handleSubmitCode = useCallback(() => {
    if (!inputValue || !isLocallyValidTradePromoCode(inputValue)) {
      setHelperText(formatMessage(messages.localValidationFailed));
      logTradePromoCodeApplyError({
        promoCode: inputValue,
        errorCode: null,
        errorMessage: formatMessage(messages.localValidationFailed),
        errorType: 'Apply',
      });
      setPromoResponse(null);
      return;
    }
    applyTradePromoCodeMutation({
      variables: {
        input: {
          codeValue: inputValue,
          allowedCodeTypes: ['FREE_SIMPLE_TRADE_CODE'],
          tradeFiatAmount: fiatAmount.amount,
          tradeFiatCurrencyCode: fiatAmount.currency,
        },
      },
      onCompleted: ({ response }) => {
        matchUnion(response.applyIncentiveCode)
          .when('IncentiveCodeDetails', ({ userIncentive }) => {
            logEvent('free_trade_promo_code_apply_success', {
              componentType: ComponentType.button,
              action: ActionType.click,
              codeValue: inputValue,
            });
            onSuccess(inputValue, userIncentive?.uuid ?? undefined);
          })
          .when('IncentiveCodeDetailsError', ({ code, message }) => {
            setHelperText(message);
            logTradePromoCodeApplyError({
              promoCode: inputValue,
              errorCode: code,
              errorMessage: message,
              errorType: 'Apply',
            });
          })
          .otherwise(() => {
            errorVitals.logError(
              new Error(
                `applyTradePromoCodeMutation did not return an error response nor a successful one. The payload must not be providing the full data needed to render`,
              ),
              {
                severity: 'error',
                context: 'apply_trade_promo',
                isHandled: false,
              },
            );
            setHelperText(formatMessage(messages.fallbackError));
          });

        setPromoResponse(response.applyIncentiveCode);
      },
      onError: ({ alreadyReportedError }) => {
        setHelperText(formatMessage(messages.fallbackError));
        errorVitals.logError(alreadyReportedError, {
          severity: 'error',
          context: 'trade_promo_onerror',
          isHandled: true,
        });
        logTradePromoCodeApplyError({
          promoCode: inputValue,
          errorCode: null,
          errorMessage: formatMessage(messages.fallbackError),
          errorType: 'Apply',
        });
        setPromoResponse(null);
      },
    });
  }, [
    applyTradePromoCodeMutation,
    fiatAmount.amount,
    fiatAmount.currency,
    formatMessage,
    inputValue,
    onSuccess,
  ]);

  const applyButton = useMemo(
    () => (
      <Box spacingEnd={2}>
        {isApplyTradePromoCodeLoading ? (
          <Spinner size="small" />
        ) : (
          // CDS docs use this pattern for some reason
          // eslint-disable-next-line jsx-a11y/anchor-is-valid
          <Link
            variant="caption"
            color={isError ? 'negative' : 'primary'}
            onPress={handleSubmitCode}
          >
            {formatMessage(messages.applyLabel)}
          </Link>
        )}
      </Box>
    ),
    [formatMessage, handleSubmitCode, isApplyTradePromoCodeLoading, isError],
  );

  if (!isEligible || !isPromoExperiment) {
    return null;
  }

  return isSuccess ? (
    <PromoRowSuccessCell
      inputValue={inputValue ?? ''}
      onCancel={resetState}
      successResponse={promoResponse}
    />
  ) : (
    <AccordionRow title={formatMessage(messages.title)} testID="promo-row">
      <Box offsetVertical={2}>
        <TextInput
          accessibilityLabel={formatMessage(messages.textInputFieldA11yLabel)}
          accessibilityHint={formatMessage(messages.textInputFieldA11yLabel)}
          spellCheck={false}
          autoCorrect={false}
          placeholder={formatMessage(messages.placeholder)}
          helperText={helperText}
          variant={isError ? 'negative' : undefined}
          onChangeText={onChangeText}
          autoCapitalize="characters"
          rejectResponderTermination
          onFocus={logTradePromoCodeInputFieldFocused}
          end={applyButton}
        />
      </Box>
    </AccordionRow>
  );
});

