  media,
  ...switchProps
}: ToggleRowProps) {
  const cellDescription = useMemo(
    () =>
      description ? (
        <HStack gap={0.5} alignItems="center" spacingVertical={0.5}>
          <TextLabel2 color="foregroundMuted">{description}</TextLabel2>
          {!!infoTrayState && (
            <InfoIcon onPress={onInfoPress} trayState={infoTrayState} />
          )}
        </HStack>
      ) : undefined,
    [description, infoTrayState, onInfoPress],
  );

  const accessibilityState = useMemo(
    () => ({
      checked: switchProps.checked,
    }),
    [switchProps.checked],
  );

  return (
    <ActionableRow
      title={title}
      description={cellDescription}
      action={
        <Switch
          {...switchProps}
          accessibilityLabel={accessibility}
          accessibilityHint={accessibility}
          accessibilityState={accessibilityState}
          testID={testID ?? 'toggle-row-switch'}
          disabled={disabled}
        />
      }
      media={media}
    />
  );
});

type ToggleRowFallbackProps = Pick<ToggleRowProps, 'title' | 'description'>;

export const ToggleRowFallback = memo(function ToggleRowFallback({
  title,
  description,
}: ToggleRowFallbackProps) {
  const cellDescription = useMemo(
    () =>
      description ? (
        <TextLabel2 color="foregroundMuted">{description}</TextLabel2>
      ) : null,
    [description],
  );

  return (
    <ActionableRow
      title={title}
      description={cellDescription}
      action={<Switch disabled />}
    />
  );
});

import { ComponentProps } from 'react';
import { Button, Text, View } from 'react-native';
import { fireEvent, render } from '@testing-library/react-native';

import { TabViewV2 } from './TabViewV2';

describe('TabViewV2', () => {
  const mockRoutes = [
    { key: 'tab1', title: 'Tab 1' },
    { key: 'tab2', title: 'Tab 2' },
  ];

  const renderHeader = () => (
    <View>
      <Text>Header Content</Text>
    </View>
  );

  const renderScene = ({
    route,
  }: {
    route: { key: string; title?: string };
  }) => (
    <View testID={`scene-${route.key}`}>
      <Text>render scene {route?.title}</Text>
    </View>
  );

  const renderTabBar = ({
    onPress,
    navigationState,
  }: Parameters<ComponentProps<typeof TabViewV2>['renderTabBar']>[0]) => (
    <View>
      {navigationState.routes.map((route, index) => (
        <Button
          title={route.title ?? ''}
          key={route.key}
          onPress={() => onPress(index)}
        />
      ))}
    </View>
  );

  const mockOnIndexChange = jest.fn();

  it('renders tabs and handles index changes', () => {
    const { getByText } = render(
      <TabViewV2
        index={0}
        renderHeader={renderHeader}
        renderTabBar={renderTabBar}
        renderScene={renderScene}
        onIndexChange={mockOnIndexChange}
        routes={mockRoutes}
      />,
    );

    expect(getByText('Header Content')).toBeTruthy();
    expect(getByText('render scene Tab 1')).toBeTruthy();

    fireEvent.press(getByText('Tab 2'));
    expect(mockOnIndexChange).toHaveBeenCalledWith(1);
    expect(getByText('render scene Tab 2')).toBeTruthy();
  });

  it('renders tabs and handles index changes without header', () => {
    const { getByText, queryByText } = render(
      <TabViewV2
        index={0}
        renderTabBar={renderTabBar}
        renderScene={renderScene}
        onIndexChange={mockOnIndexChange}
        routes={mockRoutes}
      />,
    );

    expect(queryByText('Header Content')).toBeFalsy();
    expect(getByText('render scene Tab 1')).toBeTruthy();

    fireEvent.press(getByText('Tab 2'));
    expect(mockOnIndexChange).toHaveBeenCalledWith(1);
    expect(getByText('render scene Tab 2')).toBeTruthy();
  });
});

