type CurrencyConversionSelectorProps = {
  sourceAssetRef: CurrencyConversionSelectorSourceFragment$key | null;
  targetAssetRef: CurrencyConversionSelectorTargetFragment$key | null;
  onPressCellLeft?: () => void;
  onPressCellRight?: () => void;
  onPressSwap?: IconButtonProps['onPress'];
  hideSwapButton?: boolean;
  disableSwap?: boolean;
  accessibilityLabel?: string;
};

function onPressSwapDefault() {
  return true;
}

export function CurrencyConversionSelector({
  onPressCellLeft = noop,
  onPressCellRight = noop,
  onPressSwap = onPressSwapDefault,
  disableSwap = false,
  hideSwapButton = false,
  sourceAssetRef,
  targetAssetRef,
  accessibilityLabel,
}: CurrencyConversionSelectorProps) {
  const { formatMessage } = useIntl();

  const sourceAsset = useFragment(
    graphql`
      fragment CurrencyConversionSelectorSourceFragment on Asset {
        ...SelectorCurrencyCellLeftFragment
      }
    `,
    sourceAssetRef,
  );

  const targetAsset = useFragment(
    graphql`
      fragment CurrencyConversionSelectorTargetFragment on Asset {
        ...SelectorCurrencyCellRightFragment
      }
    `,
    targetAssetRef,
  );

  return (
    <Card elevation={0} spacingVertical={0.5} overflow="hidden">
      <HStack justifyContent="space-evenly" offsetVertical={0.5}>
        <SelectorCurrencyCellLeft
          label={formatMessage(messages.from)}
          onPress={onPressCellLeft}
          hideSwapButton={hideSwapButton}
          assetRef={sourceAsset}
        />
        {!!hideSwapButton && <Divider direction="vertical" />}
        <SelectorCurrencyCellRight
          label={formatMessage(messages.to)}
          onPress={onPressCellRight}
          hideSwapButton={hideSwapButton}
          assetRef={targetAsset}
        />
        {!hideSwapButton && (
          <VStack spacing={0} justifyContent="center" style={swapPositioning}>
            <SwapCurrenciesButton
              testID="SwapCurrenciesButton"
              disabled={disableSwap}
              onPress={onPressSwap}
              horizontal
              accessibilityLabel={accessibilityLabel}
            />
          </VStack>
        )}
      </HStack>
    </Card>
  );
}

