type TrayMessageProps = {
  promoCode: string;
  message: string;
};

const TrayMessage = memo(({ promoCode, message }: TrayMessageProps) => {
  return (
    <TextBody spacingBottom={2}>
      <TextHeadline>{promoCode}</TextHeadline>
      {` `}
      {message}
    </TextBody>
