type AppliedTradePromoCodeCellProps = {
  promoCode: string;
  subdetail: string;
  subtitle: string;
  onPressCancel: () => void;
  trayContent: TradePromoCodeTrayResponse | null;
};

const priority = ['middle' as const, 'end' as const];
const outerSpacing = { spacingHorizontal: 0 } as const;

export const AppliedTradePromoCodeCell = memo(
  function AppliedTradePromoCodeCell({
    promoCode,
    subdetail,
    subtitle,
    onPressCancel,
    trayContent,
  }: AppliedTradePromoCodeCellProps) {
    const { formatMessage } = useIntl();

    const [
      tradePromoCodeInfoTrayVisible,
      {
        toggleOn: toggleTradePromoCodeInfoTrayOn,
        toggleOff: toggleTradePromoCodeInfoTrayOff,
      },
    ] = useToggler(false);

    const showTradePromoCodeInfoTray = useCallback(() => {
      logTradePromoCodeInfoButtonClicked(promoCode);
      toggleTradePromoCodeInfoTrayOn();
    }, [promoCode, toggleTradePromoCodeInfoTrayOn]);

    const content = useMemo<TrayContent | undefined>(() => {
      if (
        !trayContent?.trayMsg ||
        !trayContent?.termsText ||
        !trayContent?.termsUrl ||
        !trayContent?.trayTitle
      ) {
        return undefined;
      }
      return {
        title: trayContent.trayTitle,
        message: (
          <TrayMessage promoCode={promoCode} message={trayContent.trayMsg} />
        ),
        cta: {
          type: 'link',
          urlOrAction: trayContent.termsUrl,
          text: trayContent.termsText,
        },
        dismiss: {
          text: formatMessage(
            appliedTradePromoCodeCellMessages.gotItButtonTitle,
          ),
        },
      };
    }, [trayContent, promoCode, formatMessage]);

    return (
      <>
        <Cell
          testID="AppliedTradePromoCodeCell"
          priority={priority}
          outerSpacing={outerSpacing}
          detail={<CellDetail subdetail={subdetail} variant="positive" />}
          media={
            <Pressable
              accessibilityRole="button"
              onPress={onPressCancel}
              background="transparent"
              hitSlop={15}
            >
              <Icon
                testID="AppliedTradePromoCodeCellCancelButton"
                color="foreground"
                name="close"
                size="s"
              />
            </Pressable>
          }
        >
          <VStack>
            <Box flexShrink={1}>
              <TextHeadline numberOfLines={1} ellipsize="tail">
                {promoCode}
              </TextHeadline>
            </Box>
            <HStack flexShrink={1} gap={1} alignItems="center">
              <TextBody numberOfLines={1}>{subtitle}</TextBody>
              <Pressable
                accessibilityRole="button"
                onPress={showTradePromoCodeInfoTray}
                background="transparent"
                hitSlop={15}
              >
                <Icon
                  testID="AppliedTradePromoCodeCellInfoButton"
                  name="info"
                  color="foregroundMuted"
                  size="s"
                />
              </Pressable>
            </HStack>
          </VStack>
        </Cell>
        <TooltipTray
          hideTray={toggleTradePromoCodeInfoTrayOff}
          isVisible={tradePromoCodeInfoTrayVisible}
          content={content}
        />
      </>
    );
  },
);

import { memo } from 'react';
import { CellMedia } from '@cbhq/cds-mobile/cells/CellMedia';
