import { graphql, useLazyLoadQuery } from '@cbhq/data-layer';

import { DarkThemeProvider } from '@components/ThemeProvider';
import { FiatIcon } from '@app/components/Icons/FiatIcon';
import { DAppAssetIcon } from '@app/screens/Defi/components/DAppAssetIcon';
import { createMonitoringBoundary } from '@app/utils/errors/boundary';
import { errorVitals } from '@app/utils/errors/errorVitals';

import { TransactionHistoryCellMediaQuery } from './__generated__/TransactionHistoryCellMediaQuery.graphql';
import { NetworkBoundary } from './NetworkBoundary';

const CELL_MEDIA_WIDTH = 32;
const CELL_MEDIA_HEIGHT = 32;

type TransactionHistoryCellMediaProps = {
  symbol: string;
  isFiat: boolean;
  category: string;
  isDexTx?: boolean;
};

const TransactionHistoryCellMediaContent = memo(
  ({
    symbol,
    isFiat,
    category,
    isDexTx = false,
  }: TransactionHistoryCellMediaProps) => {
    const { viewer } = useLazyLoadQuery<TransactionHistoryCellMediaQuery>(
      graphql`
        query TransactionHistoryCellMediaQuery(
          $symbol: String!
          $isFiat: Boolean!
        ) {
          viewer @skip(if: $isFiat) {
            assetBySymbol(symbol: $symbol) {
              asset {
                displaySymbol
                imageUrl
                name
              }
            }
          }
        }
      `,
      { isFiat, symbol },
    );

    // If there is no asset info and it is not fiat
    if (!isFiat && !viewer?.assetBySymbol?.asset) {
      errorVitals.logError(
        new Error('No asset metadata found for transaction'),
        {
          severity: 'warning',
          context: 'transaction_history_cell_media',
          isHandled: true,
          symbol,
          category,
        },
      );
    }

    // Return the fiat icon or cash symbol if it is a fiat transaction
    if (isFiat) {
      return (
        <DarkThemeProvider>
          <Box
            width={CELL_MEDIA_WIDTH}
            height={CELL_MEDIA_HEIGHT}
            borderRadius="roundedFull"
            background="primary"
            alignItems="center"
            justifyContent="center"
          >
            {symbol ? (
              <FiatIcon currencyCode={symbol} />
            ) : (
              <Icon name="cash" size="s" color="foreground" />
            )}
          </Box>
        </DarkThemeProvider>
      );
    }

    // TODO: Remove when BE posts correct data for MGX Account Entries
    // https://jira.coinbase-corp.com/browse/DAPP-6011
    if (isDexTx) {
      return <DAppAssetIcon />;
    }

    return (
      <CellMedia
        type="asset"
        source={viewer?.assetBySymbol?.asset?.imageUrl ?? ''}
        accessibilityLabel={
          viewer?.assetBySymbol?.asset?.displaySymbol ??
          viewer?.assetBySymbol?.asset?.name ??
          ''
        }
        cache="force-cache"
      />
    );
  },
);

const { MonitoringBoundary: TransactionHistoryCellMediaBoundary } =
  createMonitoringBoundary({
    boundaryName: 'transaction-history-cell-media',
    boundaryOwner: 'feed-and-home',
  });

export const TransactionHistoryCellMedia =
  memo<TransactionHistoryCellMediaProps>(function TransactionHistoryCellMedia({
    ...props
  }) {
    return (
      <NetworkBoundary
        errorFallback={null}
        suspenseFallback={
          <Fallback
            width={CELL_MEDIA_WIDTH}
            height={CELL_MEDIA_HEIGHT}
            shape="circle"
          />
        }
        monitoringBoundary={TransactionHistoryCellMediaBoundary}
        instrumentationId="FinPromFooter"
        disableInstrumentation
      >
        <TransactionHistoryCellMediaContent {...props} />
      </NetworkBoundary>
    );
  });

import { memo, useCallback, useMemo } from 'react';
