import { SellCryptoPaymentMethodCellFragment$key } from './__generated__/SellCryptoPaymentMethodCellFragment.graphql';
import {
  CryptoPaymentMethodCellFallback,
  OnCryptoPaymentMethodCellPress,
} from './CryptoPaymentMethodCell';

type SellCryptoPaymentMethodCellProps = {
  viewerAssetRef: SellCryptoPaymentMethodCellFragment$key;
  onPress?: OnCryptoPaymentMethodCellPress;
  selectedPaymentMethodId?: string;
};

const SellCryptoPaymentMethodCellContent = memo(
  function SellCryptoPaymentMethodCellContent({
    viewerAssetRef,
    onPress,
    selectedPaymentMethodId,
  }: SellCryptoPaymentMethodCellProps) {
    const viewerAsset = useFragment(
      graphql`
        fragment SellCryptoPaymentMethodCellFragment on ViewerAsset {
          asset @required(action: THROW) {
            uuid
            imageUrl
            name
            platformName
            latestPrice(quoteCurrency: $nativeCurrency) {
              price
              percentChanges {
                day
              }
            }
          }
        }
      `,
      viewerAssetRef,
    );

    const asset = viewerAsset?.asset;
    const { percent, sign, variant } = usePercentChange(
      asset?.platformName,
      asset?.latestPrice?.percentChanges?.day,
    );

    const subdetail = `${sign}${percent}`;

    const cellMedia = useMemo(
      () => (
        <CellMedia
          type="asset"
          source={asset.imageUrl}
          accessibilityLabel={asset.name || ''}
          cache="force-cache"
          testID={`AssetIcon-${asset.name}`}
        />
      ),
      [asset.imageUrl, asset.name],
    );

    const latestPriceFormatter = useNativeCurrencyFormatter({
      minimumFractionDigits: getPriceScale(asset?.latestPrice?.price),
    });

    const detail = useMemo(
      () =>
        latestPriceFormatter({
          amount: asset.latestPrice?.price,
          isSensitive: false,
        }),
      [asset.latestPrice?.price, latestPriceFormatter],
    );

    const handlePress = useCallback(
      () => onPress?.(asset.uuid),
      [asset.uuid, onPress],
    );

    return (
      <SimpleTradeSourceTargetTrayCellWrapper
        isSelected={selectedPaymentMethodId === asset.uuid}
        onPress={handlePress}
      >
        <Box offsetHorizontal={0.5}>
          <ListCell
            title={asset.name}
            description={asset.platformName}
            subdetail={subdetail}
            media={cellMedia}
            variant={variant}
            detail={detail}
            compact
          />
        </Box>
      </SimpleTradeSourceTargetTrayCellWrapper>
    );
  },
);

