  function SellCryptoPaymentMethodCell(
    props: SellCryptoPaymentMethodCellProps,
  ) {
    return (
      <NetworkBoundary
        errorFallback={null}
        suspenseFallback={CryptoPaymentMethodCellFallback}
      >
        <SellCryptoPaymentMethodCellContent {...props} />
      </NetworkBoundary>
    );
  },
);

import { memo, useCallback, useEffect, useMemo } from 'react';
import { Card } from '@cbhq/cds-mobile/cards/Card';
import { CellMedia } from '@cbhq/cds-mobile/cells';
import { Box, Fallback, HStack } from '@cbhq/cds-mobile/layout';
import {
  TextHeadline,
  TextLabel1,
  TextLabel2,
  useLineHeightMap,
} from '@cbhq/cds-mobile/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';
import { graphql, useFragment } from '@cbhq/data-layer';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { NetworkBoundary } from '@app/components/NetworkBoundary';
import { useEvaluateScreenLayout } from '@app/components/Transfer/hooks/useEvaluateScreenLayout';
import { usePercentChangeFormatter } from '@app/hooks/formatters/usePercentChangeFormatter';
import { useNavigateToAsset } from '@app/hooks/useNavigateToAsset';
import { FiatTransferType, TransferType } from '@app/types/Transfer';
import { Analytics } from '@app/utils/analytics/Analytics';
import { PAGE_KEYS } from '@app/utils/analytics/pagekeys';

import { AssetRecsUpsellCardFragment$key } from './__generated__/AssetRecsUpsellCardFragment.graphql';
import { AssetRecsUpsellFragment$key } from './__generated__/AssetRecsUpsellFragment.graphql';

const i18nKey = 'AssetRecsOrderConfirm';

const messages = defineMessages({
  header: {
    id: `${i18nKey}.headerHeuristic`,
    defaultMessage: 'You might also like',
    description: 'Header for asset recommendations',
  },
});

const assetPosition = ['Left', 'Middle', 'Right'];

type AssetRecsUpsellTypes = {
  viewerRef: AssetRecsUpsellFragment$key;
  tradeType: FiatTransferType | TransferType | 'convert';
};

const AssetRecsUpsellContent = memo(
  ({ viewerRef, tradeType }: AssetRecsUpsellTypes) => {
    const { formatMessage } = useIntl();
    const { isCompact } = useEvaluateScreenLayout();
    const spacing = isCompact ? 2 : 3;

    const data = useFragment(
      graphql`
        # eslint-disable-next-line @cbhq/cdl-graphql-no-fragments-on-viewer
        fragment AssetRecsUpsellFragment on Viewer {
          personalizedAssetRecs(surface: "PostTrade")
            @required(action: NONE)
            @skip(if: $skipAssetRecsUpsell) {
            assets @required(action: NONE) {
              uuid
              name
              ...AssetRecsUpsellCardFragment
            }
          }
        }
      `,
      viewerRef,
    );

    const assetData = useMemo(
      () =>
        data?.personalizedAssetRecs?.assets.map((asset) => {
          return asset?.name;
        }) ?? ['No assets returned'],
      [data?.personalizedAssetRecs?.assets],
    );

    useEffect(() => {
      Analytics.track('asset_recs_upsell_on_order_confirm', {
        action: ActionType.render,
        componentType: ComponentType.page,
        assets: assetData.join(', '),
        tradeType,
      });
    }, [assetData, tradeType]);

    const assetRecs = data?.personalizedAssetRecs?.assets;

    if (!data || !assetRecs || assetRecs?.length === 0) {
      return null;
    }

    return (
      <Box spacingVertical={spacing} spacingBottom={2} testID="assetRecsUpsell">
        <TextHeadline spacingBottom={2} align="center">
          {formatMessage(messages.header)}
        </TextHeadline>
        <HStack
          justifyContent={
            assetRecs.length < 3 ? 'space-evenly' : 'space-between'
          }
        >
          {assetRecs?.map((rec, index) => {
            if (!rec) {
              return null;
            }

            return (
              <AssetRecCard
                key={rec?.uuid}
                assetRef={rec}
                assetNames={assetData}
                assetPosition={assetPosition[index]}
              />
            );
          })}
        </HStack>
      </Box>
    );
  },
);

type AssetRecCardTypes = {
  assetRef: AssetRecsUpsellCardFragment$key;
  assetNames: (string | undefined)[];
  assetPosition: string;
};

const AssetRecCard = memo(({ assetRef, assetNames }: AssetRecCardTypes) => {
  const asset = useFragment(
    graphql`
      fragment AssetRecsUpsellCardFragment on Asset {
        uuid
        imageUrl
        name
        displaySymbol
        latestPrice(quoteCurrency: $nativeCurrency) {
          percentChanges {
            day
          }
        }
      }
    `,
    assetRef,
  );

  const navigateToAsset = useNavigateToAsset();
  const pageName = PAGE_KEYS.SimpleTradeScreen;
  const componentName = 'asset_recs_upsell';

  const handleCardPress = useCallback(() => {
    const nonClickedAssets = assetNames
      .filter((assetName) => assetName !== asset.name)
      .join(', ');

    Analytics.track('asset_recs_upsell_on_order_confirm', {
      action: ActionType.click,
      componentType: ComponentType.card,
      assetId: asset.uuid,
      assetName: asset.name,
      assetPosition,
      nonClickedAssets,
    });
    navigateToAsset(
      asset.uuid,
      pageName, // TODO: Get better pageName
      componentName,
    );
  }, [asset.name, asset.uuid, assetNames, navigateToAsset, pageName]);

  const formatPercentChange = usePercentChangeFormatter();
  const { variant, sign, percent } = formatPercentChange({
    value: asset.latestPrice?.percentChanges?.day ?? 0,
  });

  return (
    <Card
      elevation={0}
      minWidth={100}
      spacing={1}
      onPress={handleCardPress}
      alignItems="center"
      testID="assetRecsUpsell-card"
      bordered
      borderRadius="rounded"
    >
      <CellMedia
        type="asset"
        accessibilityLabel={asset.displaySymbol ?? ''}
        source={asset.imageUrl}
      />
      <TextLabel1 spacingTop={1}>{asset.displaySymbol}</TextLabel1>
      {variant && sign && percent && (
        <TextLabel2 color={variant}>{sign + percent}</TextLabel2>
      )}
    </Card>
  );
});

const CardFallback = memo(() => {
  const lineHeight = useLineHeightMap();

  return (
    <Card elevation={0} minWidth={100} spacing={2} alignItems="center">
