import { useCallback, useState } from 'react';
import { HStack } from '@cbhq/cds-mobile/layout';
import { ThemeProvider } from '@cbhq/cds-mobile/system';

import { useDimensions } from '@designSystem/hooks/useDimensions';
import { ProgressBar } from '@designSystem/navigation/progress/ProgressBar';

import { IconButton } from '@components/interactables/IconButton';
import { useTimer } from '@hooks/useTimer';
import { useStackNavigation } from '@app/hooks/navigation/useStackNavigation';

const COUNTDOWN_INTERVAL = 100;

type Props = {
  value: number;
  total: number;
  delay: number;
};

export function ProgressBarHeader({ value, total, delay }: Props) {
  const { pop } = useStackNavigation();
  const { top } = useDimensions();

  const handleClose = useCallback(() => {
    pop();
  }, [pop]);

  return (
    <ThemeProvider spectrum="light" name="progress-bar-header">
      <HStack
        gap={0.5}
        spacing={3}
        alignItems="center"
        background="background"
        style={{ zIndex: 20, position: 'absolute', top }}
      >
        {[...Array(total).keys()].map((index) =>
          value === index ? (
            <AnimatedProgressBar key={index} delay={delay} />
          ) : (
            <ProgressBar
              key={index}
              width={40}
              percent={value > index ? 1 : 0}
              color={value > index ? 'primary' : 'foreground'}
              steps={1}
            />
          ),
        )}

        <IconButton name="close" transparent onPress={handleClose} />
      </HStack>
    </ThemeProvider>
  );
}

type AnimatedProgressBarProps = { delay: number };

function AnimatedProgressBar({ delay = 0 }: AnimatedProgressBarProps) {
  const [progress, setProgress] = useState(0);

  const handleOnStep = useCallback(
    (timeDiff: number) => {
      const percent = 1 - timeDiff / delay;
      setProgress(percent);
    },
    [delay],
  );

  useTimer({
    duration: delay,
    step: COUNTDOWN_INTERVAL,
    onStep: handleOnStep,
    shouldCheckForStep: () => true,
  });

  return (
    <ProgressBar percent={progress} width={40} color="primary" steps={1} />
  );
}

import {
