type BottomTabNavigatorProps = {
  children: ReactNode;
  initialRouteName?: string; // if not specified, the first route in the navigator is used
} & TabRouterOptions;

type BottomTabNavigationOptionsWithCDSTabBarIcon =
  BottomTabNavigationOptions & {
    tabBarIcon: (props: Omit<NavigationIconProps, 'name'>) => ReactNode;
    showUpsellDot?: boolean;
  };

type BottomNavPressableItemProps = {
  route: { name: string; key: string };
  options: BottomTabNavigationOptionsWithCDSTabBarIcon;
  isFocused: boolean;
  label: BottomTabNavigationOptions['tabBarLabel'];
  currentRouteName: string;
  navigation: BottomTabBarProps['navigation'];
};

const Tab = createBottomTabNavigator();
const BottomTabScreen = Tab.Screen;

const screenOptions = {
  headerShown: false, // to freeze inactive screens from re-rendering.
  // https://reactnavigation.org/docs/bottom-tab-navigator/#freezeonblur
  freezeOnBlur: true,
};

function BottomTabNavigator({
  children,
  initialRouteName,
  backBehavior,
}: BottomTabNavigatorProps) {
  const isKeyboardVisible = useKeyboardVisibility();
  const { isBottomTabBarVisible } = useIsBottomTabVisible();
  const { isScreenResizingEnabled } = useContext(ScreenResizeContext);

  // Currently, we need to hide the TabBar on Android when:
  // 1. The keyboard is visible AND
  // 2. A screen is resized based on the keyboard being visible
  // These 2 properties together will cause the TabBar to position
  // itself above the keyboard when the keyboard is up, which is undesirable.
  // To circumvent this, we render null for the TabBar in these cases.
  // An example of where we would want to hide the TabBar is on the Native Currency
  // selector screen.
  // See https://github.cbhq.net/consumer/react-native/pull/1385#discussion_r300544
  const hideTabBar = useMemo(
    () =>
      !isBottomTabBarVisible ||
      (isKeyboardVisible && isScreenResizingEnabled && device.isAndroid),
    [isBottomTabBarVisible, isKeyboardVisible, isScreenResizingEnabled],
  );
  const tabBar = useCallback(
    (props: BottomTabBarProps) =>
      hideTabBar ? null : (
        <TabBar
          routes={props.state.routes}
          index={props.state.index}
          descriptors={props.descriptors}
          navigation={props.navigation}
        />
      ),
    [hideTabBar],
  );
  return (
    <Tab.Navigator
      initialRouteName={initialRouteName}
      backBehavior={backBehavior}
      tabBar={tabBar}
      screenOptions={screenOptions}
    >
      {children}
    </Tab.Navigator>
  );
}

const accessibilitySelectedState: AccessibilityState = { selected: true };

const BottomNavPressableItem = memo(
  forwardRef<MutableRefObject<View | null>, BottomNavPressableItemProps>(
    function BottomNavPressableItem(
      { isFocused, label, currentRouteName, navigation, route, options },
      ref,
    ) {
      const { showGlobalTrade, preloadTradeOptions } = useGlobalTrade();

      const tradingMethod = useSelectedTradingMethod();

      const trackTapEvent = useGlobalNavEvent('global_button');

      const [startLoadTradeScreenPerfMark] = usePerfMark(
        'simple_trade',
        'navigate_to_explore_screen',
      );
      const [startLoadAssetsPerfMark] = usePerfMark(
        'simple_trade',
        'load_assets',
      );
      const [startLoadAssetsScreenPerfMark] = usePerfMark(
        'simple_trade',
        'navigate_to_assets_screen',
      );

      const [startLoadAssetsScreenTopAssetHoldingsPerfMark] = usePerfMark(
        'simple_trade',
        'navigate_to_assets_screen_top_asset_holdings',
      );

      const [startLoadHomePerfMark] = usePerfMark(
        'simple_trade',
        'navigate_to_home_screen',
      );

      const { setEntryComponent } = useSetTradeAnalyticsContext();
      const trackHomepageAnalytics = useHomepageAnalytics();

      const onPress = useCallback(() => {
        const event = navigation.emit({
          type: 'tabPress',
          target: route.key,
          canPreventDefault: true,
        });

        if (route.name === 'GlobalTrade' || route.name === 'TradeStack') {
          startLoadTradeScreenPerfMark();
          markJourneyOnce('navigate_to_explore_screen');
          startLoadAssetsPerfMark();
        } else if (route.name === 'Earn') {
          markJourneyOnce('navigate_to_yield_center_screen');
        } else if (route.name === 'HomeFeedTab') {
          startLoadHomePerfMark();
        } else if (route.name === 'Assets') {
          startLoadAssetsScreenPerfMark();
          // The current metric for navigate_to_assets_screen is wrong as it gets measured
          // when only cryptoBalance is available. In order to proeceed to next CUJ step,
          // Tracking this separately with different end step (loaded_assets_screen_top_asset_holdings)
          // to not disturb the existing metric.
          startLoadAssetsScreenTopAssetHoldingsPerfMark();
          markJourneyOnce('navigate_to_assets_screen');
          setEntryComponent('asset_portfolio_l1'); // user enters assets page via navbar instead of from "Your Balance" at HomeFeed
        }

        if (route.name === 'GlobalTrade') {
          preloadTradeOptions();
          trackTapEvent({
            componentName: 'global_action',
            surfaceName: currentRouteName.toLowerCase() as GlobalNavSurfaceName,
          });
          return showGlobalTrade();
        }

        if (route.name === 'TradeStack' && isFocused) {
          navigation.navigate(route.name, {
            screen:
              tradingMethod === 'advanced'
                ? tradeStackInitialRouteNames.advanced
                : tradeStackInitialRouteNames.simple,
            params: {},
          });

          trackTapEvent({
            componentName: route.name.toLowerCase() as GlobalNavComponentName,
            surfaceName: currentRouteName.toLowerCase() as GlobalNavSurfaceName,
          });

          return undefined;
        }

        if (!isFocused && !event.defaultPrevented) {
          if (route.name === 'BrowserStack') {
            markJourney('navigate_to_dapp_web3_screen');
            navigation.navigate(route.name, {
              screen: 'Browser',
              params: { disableGatekeeper: false, nuxContentSlug: 'web3_nux' },
            });
          } else {
            navigation.navigate(route.name);
          }

          trackTapEvent({
            componentName: route.name.toLowerCase() as GlobalNavComponentName,
            surfaceName: currentRouteName.toLowerCase() as GlobalNavSurfaceName,
          });
          trackHomepageAnalytics(
            ActionType.click,
            ComponentType.button,
            'app_tab',
            route.name,
          );
        }

        return undefined;
      }, [
        navigation,
        route.key,
        route.name,
        isFocused,
        startLoadTradeScreenPerfMark,
        startLoadAssetsPerfMark,
        startLoadHomePerfMark,
        startLoadAssetsScreenPerfMark,
        startLoadAssetsScreenTopAssetHoldingsPerfMark,
        setEntryComponent,
        preloadTradeOptions,
        trackTapEvent,
        currentRouteName,
        showGlobalTrade,
        tradingMethod,
        trackHomepageAnalytics,
      ]);

      const onLongPress = useCallback(() => {
        navigation.emit({
          type: 'tabLongPress',
          target: route.key,
        });
      }, [navigation, route]);

      const hasRAV4BottomTabExperiment = useHasRAV4BottomTabExperiment();

      useEffect(() => {
        trackHomepageAnalytics(
          ActionType.render,
          ComponentType.button,
          'app_tab',
          route.name,
        );
      }, [route.name, trackHomepageAnalytics]);

      return (
        <Box flexGrow={hasRAV4BottomTabExperiment ? 1 : undefined}>
          <PressableOpacity
            testID={options.tabBarTestID}
            accessibilityLabel={options.tabBarAccessibilityLabel}
            accessibilityRole="button"
            accessibilityState={
              isFocused ? accessibilitySelectedState : undefined
            }
            feedback={route.name === 'GlobalTrade' ? 'heavy' : 'none'}
            onPress={onPress}
            onLongPress={onLongPress}
            block
          >
            <BottomNavItem
              active={isFocused}
              icon={options.tabBarIcon}
              // @ts-expect-error Label should be a string
              label={label}
              ref={ref}
              showUpsellDot={options.showUpsellDot}
            />
          </PressableOpacity>
        </Box>
      );
    },
  ),
);

type TabBarProps = {
  routes: BottomTabBarProps['state']['routes'];
  index: BottomTabBarProps['state']['index'];
  descriptors: BottomTabBarProps['descriptors'];
  navigation: BottomTabBarProps['navigation'];
};

const TabBar = memo(function TabBar({
  routes,
  index: routeIndex,
  descriptors,
  navigation,
}: TabBarProps) {
  const web3TabRef = useRef(null);

  return (
    <BottomNav currentRoute={routeIndex}>
      {routes.map((route: NavigationState['routes'][number], index: number) => {
        const { options } = descriptors[route.key];
        const isFocused = routeIndex === index;
        const label = options.tabBarLabel;
        const currentRouteName = routes[routeIndex].name;

        return (
          <BottomNavPressableItem
            key={`bottomNavItem-${route.key}`}
            options={options as BottomTabNavigationOptionsWithCDSTabBarIcon}
            isFocused={isFocused}
            label={label}
            currentRouteName={currentRouteName}
            route={route}
            navigation={navigation}
            ref={label === 'Web3' ? web3TabRef : null}
          />
        );
      })}
    </BottomNav>
  );
});

