export type SubscriptionChangePlanFlowTrayProps = {
  onClose: () => void;
  onChangePlanSuccess: () => void;
};

function SubscriptionChangePlanFlowTrayInner({
  onClose,
  onChangePlanSuccess,
}: SubscriptionChangePlanFlowTrayProps) {
  useLogManagementEventOnMount({
    componentType: ComponentType.tray,
    feature: 'change_plan_tray',
  });

  const query = useLazyLoadQuery<SubscriptionChangePlanFlowTrayQuery>(
    graphql`
      query SubscriptionChangePlanFlowTrayQuery($productKey: String!) {
        ...usePaymentMethodSelectorControlsFragment
        # eslint-disable-next-line relay/must-colocate-fragment-spreads
        ...cryptoBackupUtils_getOptInStatusFragment
        ...SubscriptionPaymentMethodsModalFragment
        ...useHasActiveFreeTrialFragment
        viewer @required(action: THROW) {
          ...usePremiumTierPlanFragment
          coinbaseSubscription(productKey: $productKey) {
            id
            subscriptionUuid
            nextBillingDate
          }
        }
      }
    `,
    {
      productKey: PRODUCT_KEY,
    },
  );

  const { premiumTierPlan } = usePremiumTierPlan(query.viewer);
  const { isInFreeTrial } = useHasActiveFreeTrial({
    queryRef: query,
  });

  const { formatMessage, formatDate } = useIntl();
  const formatCurrency = useCurrencyFormatter();
  const toast = useToast();

  const handleChangeSubscriptionPlanSuccess = useCallback(() => {
    onClose();
    onChangePlanSuccess();
    toast.show(formatMessage(messages.successToast), {
      bottomOffset: 125,
    });
  }, [formatMessage, onChangePlanSuccess, onClose, toast]);

  const [isError, setIsError] = useState(false);
  const handleChangeSubscriptionPlanError = useCallback((error: Error) => {
    logSubscriptionError({
      error,
      isHandled: true,
      componentName: 'SubscriptionChangePlanFlowTray',
    });
    setIsError(true);
  }, []);

  const {
    changeSubscriptionPlan,
    isInFlight: isChangeSubscriptionPlanInFlight,
  } = useChangeSubscriptionPlan({
    subscriptionRelayId: query.viewer.coinbaseSubscription?.id || '',
    onSuccess: handleChangeSubscriptionPlanSuccess,
    onError: handleChangeSubscriptionPlanError,
    // TODO: refactor useChangeSubscriptionPlan to get these UUIDs from the callback it returns, changeSubscriptionPlan, instead of within the hook call
    subscriptionUuid: query.viewer.coinbaseSubscription?.subscriptionUuid ?? '',
    newPlanUuid: premiumTierPlan?.subscriptionPlanUuid ?? '',
  });

  const onUpgradePress = useCallback(() => {
    if (isChangeSubscriptionPlanInFlight) {
      return;
    }

    logManagementEvent({
      action: ActionType.click,
      componentType: ComponentType.button,
      feature: 'change_plan_tray',
      additionalData: {
        componentName: 'upgrade_button',
      },
    });

    changeSubscriptionPlan();
  }, [changeSubscriptionPlan, isChangeSubscriptionPlanInFlight]);

  // User needs to be eligible for premium tier plan to see this tray
  useEffect(() => {
    if (!premiumTierPlan) {
      logSubscriptionError({
        error: new Error('Premium tier plan not available'),
        isHandled: true,
        componentName: 'SubscriptionChangePlanFlowTray',
      });
      onClose();
    }
  }, [onClose, premiumTierPlan]);
  const {
    selectedPaymentMethod,
    isPaymentMethodModalVisible,
    showPaymentMethodModal,
    hidePaymentMethodModal,
    handlePaymentMethodSelect,
  } = usePaymentMethodSelectorControls({
    queryRef: query,
  });

  const optedIntoCryptoBackups = cryptoBackupUtils.getOptInStatus(query);
  const legalText = useMemo(() => {
    const today = new Date();
    const nextBillingDate = isInFreeTrial
      ? new Date(today.getFullYear(), today.getMonth() + 1, today.getDate())
      : query.viewer.coinbaseSubscription?.nextBillingDate;

    return formatMessage(
      optedIntoCryptoBackups
        ? messages.textLegalOptedIntoCryptoBackups
        : messages.textLegal,
      {
        buttonLabel: formatMessage(messages.upgradeToUnlimited),
        premiumPrice: formatCurrency({
          isFiat: true,
          amount: premiumTierPlan?.price,
        }),
        nextBillingDate: formatDate(nextBillingDate, {
          month: 'short',
          day: 'numeric',
        }),
      },
    );
  }, [
    formatCurrency,
    formatDate,
    formatMessage,
    isInFreeTrial,
    optedIntoCryptoBackups,
    premiumTierPlan?.price,
    query.viewer.coinbaseSubscription?.nextBillingDate,
  ]);

  if (!premiumTierPlan) {
    return null;
  }

  if (isError) {
    return <ErrorContent onTryAgain={onClose} />;
  }

  return (
    <>
      <VStack maxHeight="100%">
        <ScrollView
          bounces={false}
          style={{
            borderTopLeftRadius: borderRadius.roundedLarge,
            borderTopRightRadius: borderRadius.roundedLarge,
          }}
        >
          <Pressable
            accessibilityRole="button"
            background="background"
            noScaleOnPress
          >
            <ValuePropContent
              planPrice={premiumTierPlan.price}
              proratedPrice={
                premiumTierPlan.metadata?.migrationMetadata?.proratedPrice
              }
              creditRefund={
                premiumTierPlan.metadata?.migrationMetadata?.creditRefund
              }
              isInFreeTrial={isInFreeTrial}
            />
          </Pressable>
        </ScrollView>
      </VStack>
      <Divider />
      <VStack
        spacingHorizontal={3}
        spacingTop={selectedPaymentMethod ? 0 : 2}
        background="background"
      >
        {selectedPaymentMethod && (
          <SelectedPaymentMethod
            testID="subscription_change_plan_flow_payment_method_selector"
            paymentMethod={selectedPaymentMethod}
            onPress={showPaymentMethodModal}
            outerSpacing={{ spacingHorizontal: 0 }}
          />
        )}
        <VStack gap={1} spacingBottom={2}>
          <TextLabel2>{formatMessage(messages.spreadStillApplies)}</TextLabel2>
          <TextLabel2 testID="upgrade-tray-terms">{legalText}</TextLabel2>
        </VStack>
        <Button
          spacingBottom={0}
          onPress={onUpgradePress}
          loading={isChangeSubscriptionPlanInFlight}
          testID="subscription_change_plan_flow_tray_action_button"
        >
          {formatMessage(messages.upgradeToUnlimited)}
        </Button>
      </VStack>
      <SubscriptionPaymentMethodsModal
        selectedPaymentMethod={selectedPaymentMethod}
        visible={isPaymentMethodModalVisible}
        onRequestClose={hidePaymentMethodModal}
        onSelect={handlePaymentMethodSelect}
        queryRef={query}
        showAddPaymentButton={false}
      />
    </>
  );
}

