  props: SubscriptionChangePlanFlowTrayProps,
) {
  const trayRef = useRef<DrawerRefBaseProps | null>(null);
  const getHandleClose = useCallback(
    (close: () => void) => () => {
      logManagementEvent({
        action: ActionType.click,
        componentType: ComponentType.button,
        feature: 'change_plan_tray',
        additionalData: {
          componentName: 'close',
        },
      });
      close();
    },
    [],
  );

  return (
    <Tray
      onCloseComplete={props.onClose}
      ref={trayRef}
      disableCapturePanGestureToDismiss
      verticalDrawerPercentageOfView={90}
    >
      {({ handleClose: close }) => (
        <InstrumentedSuspense
          instrumentationId="SubscriptionChangePlanFlowTray"
          fallback={<SubscriptionChangePlanFlowTrayFallback />}
        >
          <SubscriptionChangePlanFlowTrayInner
            {...props}
            onClose={getHandleClose(close)}
          />
        </InstrumentedSuspense>
      )}
    </Tray>
  );
}

import { useCallback, useContext, useMemo } from 'react';
