import { PlanSelectionListQuery } from './__generated__/PlanSelectionListQuery.graphql';

const i18nKey = 'PlanSelectionList';
const messages = defineMessages({
  chooseAPlan: {
    id: `${i18nKey}.chooseAPlan`,
    defaultMessage: 'Choose a plan',
    description: 'Title for the plan selection list',
  },
  monthlyPrice: {
    id: `${i18nKey}.monthlyPrice`,
    defaultMessage: '{monthlyPrice}/month',
    description: 'Label for the monthly price',
  },
  monthlyPriceWithBilledDetails: {
    id: `${i18nKey}.monthlyPriceWithBilledDetails`,
    defaultMessage: '{monthlyPrice}/month (billed {yearlyPrice}/year)',
    description:
      'Label for the monthly price for an annual plan, noting that it is billed annually',
  },
  monthly: {
    id: `${i18nKey}.monthly`,
    defaultMessage: 'Monthly',
    description:
      'Label for a subscription plan that has a monthly billing cadence',
  },
  annual: {
    id: `${i18nKey}.annual`,
    defaultMessage: 'Annual',
    description:
      'Label for a subscription plan that has an annual billing cadence',
  },
  saveTag: {
    id: `${i18nKey}.saveTag`,
    defaultMessage: 'Save {savings}',
    description: 'Label for a tag on a cell that shows potential savings',
  },
});

type PlanSelectionListItemProps = {
  plan: SubscriptionPlan;
  handleClose: () => void;
  annualSavings: number;
  selected?: boolean;
  onPress?: () => void;
};

export function PlanSelectionListItem({
  plan,
  handleClose,
  annualSavings,
  selected,
  onPress,
}: PlanSelectionListItemProps) {
  const { selectedPaidPlan, setSelectedPaidPlan } = useContext(
    SubscriptionSignupContext,
  );

  const handlePress = useCallback(() => {
    setSelectedPaidPlan(plan);
    onPress?.();
    handleClose();
  }, [handleClose, plan, setSelectedPaidPlan, onPress]);

  const { formatMessage, formatNumber } = useIntl();

  const title = useMemo(() => {
    const titleMessage =
      plan.planBillingFrequency.numberOfUnits === 12 &&
      plan.planBillingFrequency.unit === 'MONTH'
        ? messages.annual
        : messages.monthly;

    if (annualSavings > 0) {
      return (
        <HStack alignItems="center">
          <TextHeadline>{formatMessage(titleMessage)}</TextHeadline>
          <Spacer horizontal={1} />
          <Tag intent="promotional" colorScheme="blue">
            {formatMessage(messages.saveTag, {
              savings: formatNumber(annualSavings, {
                style: 'currency',
                currency: plan.price.currency,
              }),
            })}
          </Tag>
        </HStack>
      );
    }

    return <TextHeadline>{formatMessage(titleMessage)}</TextHeadline>;
  }, [
    annualSavings,
    formatMessage,
    formatNumber,
    plan.planBillingFrequency.numberOfUnits,
    plan.planBillingFrequency.unit,
    plan.price.currency,
  ]);

  const description = useMemo(() => {
    const { value, currency } = plan.price;

    if (
      (plan?.planBillingFrequency.numberOfUnits === 12 &&
        plan?.planBillingFrequency.unit === 'MONTH') ||
      (plan?.planBillingFrequency.numberOfUnits === 1 &&
        plan?.planBillingFrequency.unit === 'YEAR')
    ) {
      return formatMessage(messages.monthlyPriceWithBilledDetails, {
        monthlyPrice: formatNumber(Number(value) / 12, {
          style: 'currency',
          currency,
        }),
        yearlyPrice: formatNumber(Number(value), {
          style: 'currency',
          currency,
        }),
      });
    }

    return formatMessage(messages.monthlyPrice, {
      monthlyPrice: formatNumber(Number(value), {
        style: 'currency',
        currency,
      }),
    });
  }, [
    formatMessage,
    formatNumber,
    plan?.planBillingFrequency.numberOfUnits,
    plan?.planBillingFrequency.unit,
    plan.price,
  ]);

  return (
    <ListCell
      testID={`plan-selection-list-item-${plan.subscriptionPlanUuid}`}
      title={title}
      description={<TextBody color="foreground">{description}</TextBody>}
      onPress={handlePress}
      outerSpacing={{
        spacingHorizontal: 0,
        spacingVertical: 0.5,
      }}
      selected={
        selected ||
        selectedPaidPlan?.subscriptionPlanUuid === plan.subscriptionPlanUuid
      }
    />
  );
}

type PlanSelectionListProps = {
  handleClose: () => void;
};

export function PlanSelectionList({ handleClose }: PlanSelectionListProps) {
  const query = useLazyLoadQuery<PlanSelectionListQuery>(
    graphql`
      query PlanSelectionListQuery {
        ...useSubscriptionPlansFragment
      }
    `,
    {},
  );

  const { paidPlans, originalMonthlyPlan } = useSubscriptionPlans(query);

  const { formatMessage } = useIntl();

  const filteredPaidPlans = useMemo(() => {
    return paidPlans
      .filter((plan: SubscriptionPlan) => {
        return plan.tier === 'BASIC';
      })
      .sort((a: SubscriptionPlan, b: SubscriptionPlan) => {
        // Sort by price ascending
        return Number(a.price.value) - Number(b.price.value);
      });
  }, [paidPlans]);

  const getAnnualSavings = useCallback(
    (plan: SubscriptionPlan) => {
      const planPriceAnnualized =
        plan.planBillingFrequency.numberOfUnits === 12 &&
        plan.planBillingFrequency.unit === 'MONTH'
          ? Number(plan.price.value)
          : Number(plan.price.value) * 12;
      return (
        Number(originalMonthlyPlan?.price.value) * 12 - planPriceAnnualized
      );
    },
    [originalMonthlyPlan],
  );

  return (
    <VStack testID="plan-selection-list">
      <HStack spacingHorizontal={2}>
        <IconButton
          name="backArrow"
          transparent
          compact
          onPress={handleClose}
        />
      </HStack>

      <Spacer vertical={1} />

      <VStack spacingHorizontal={3}>
        <TextTitle3>{formatMessage(messages.chooseAPlan)}</TextTitle3>

        <Spacer vertical={2} />

        {filteredPaidPlans.map((plan: SubscriptionPlan) => (
          <PlanSelectionListItem
            key={plan.subscriptionPlanUuid}
            plan={plan}
            handleClose={handleClose}
            annualSavings={getAnnualSavings(plan)}
          />
        ))}
      </VStack>
    </VStack>
  );
}

