const i18nKey = `SubscriptionSignupFlowTray`;
const messages = defineMessages({
  freeTrial: {
    id: `${i18nKey}.freeTrial`,
    defaultMessage: 'Claim free trial',
    description:
      'Button label for primary button that signs a user up for a free trial',
  },
  tryForFree: {
    id: `${i18nKey}.tryForFree`,
    defaultMessage: 'Try for free',
    description:
      'Alternate Button label for primary button that signs a user up for a free trial',
  },
  signup: {
    id: `${i18nKey}.signup`,
    defaultMessage: 'Sign up',
    description:
      'Button label prompting users to sign up now for a Coinbase One subscription',
  },
  successToast: {
    id: `${i18nKey}.successToast`,
    defaultMessage: 'Welcome to {productName}!',
    description:
      'Toast message that shows to users welcoming them to our subscription product after a successful signup',
  },
});

export type SubscriptionSignupFlowTrayVariant = 'trade' | 'premium';
export type SubscriptionSignupFlowTrayProps = {
  onClose: () => void;
  onSignupSuccess: () => void;
  variant: SubscriptionSignupFlowTrayVariant;
  tradeVolume?: V3Amount;
  promoCode?: string;
};

// Contains props for internal controls that shouldn't be exposed to parent components
type SubscriptionSignupFlowTrayInnerProps = SubscriptionSignupFlowTrayProps & {
  handlePlanSelectorPress?: () => void;
};

function SubscriptionSignupFlowTrayInner({
  onClose,
  onSignupSuccess,
  variant,
  promoCode,
  tradeVolume,
  handlePlanSelectorPress,
}: SubscriptionSignupFlowTrayInnerProps) {
  const REFERRER = `signup_tray_${variant}`;

  const query = useLazyLoadQuery<SubscriptionSignupFlowTrayQuery>(
    graphql`
      query SubscriptionSignupFlowTrayQuery(
        $first: Int!
        $productKey: String!
      ) {
        ...SignupLegalTermsFragment
        ...ValuePropContentFragment
        ...useSignupFeaturesFragment
        ...useBenefitsListFragment
        ...useSupportedSubscriptionPaymentMethodsFragment
        ...SubscriptionPaymentMethodsModalFragment
        viewer @required(action: THROW) {
          ...usePremiumTierPlanFragment
        }
      }
    `,
    {
      productKey: PRODUCT_KEY,
      first: INVOICE_PAGINATION_LIMIT,
    },
  );

  useJourneyMarkOnMount('loaded_cb1_signup_overlay');

  const formatMessage = useFormatSubscriptionTextWithParams({});
  const toast = useToast();

  const {
    selectedPaymentMethod,
    showPaymentMethodModal,
    hidePaymentMethodModal,
    selectPaymentMethod,
    isPaymentMethodModalOpen,
    isEligibleForFreeTrial,
    paidPlan: originalMonthlyPlan,
    freeTrialPlan,
  } = useSignupFeatures(query);
  const { premiumTierPlan } = usePremiumTierPlan(query.viewer);

  const {
    promo: validatedPromo,
    promoApplied,
    selectedPaidPlan,
    setSelectedPaidPlan,
    setSelectedPaymentMethod,
  } = useContext(SubscriptionSignupContext);

  // payment methods
  const [firstSupportedPaymentMethod = null] =
    useSupportedSubscriptionPaymentMethods(query);

  const initialPaymentMethodSet = useRef(false);
  useEffect(() => {
    if (!initialPaymentMethodSet.current) {
      setSelectedPaymentMethod(firstSupportedPaymentMethod);
      initialPaymentMethodSet.current = true;
    }
  }, [setSelectedPaymentMethod, firstSupportedPaymentMethod]);

  useEffect(() => {
    if (selectedPaidPlan === null && originalMonthlyPlan) {
      setSelectedPaidPlan(originalMonthlyPlan);
    }
  }, [originalMonthlyPlan, selectedPaidPlan, setSelectedPaidPlan]);

  const inUpsellToPaidExperiment = useInPreTradeUpsellToPaidExperiment({
    isEligibleForFreeTrial,
    tradeVolumeValue: tradeVolume?.value ?? '',
    isIneligibleForUpsell: variant !== 'trade',
  });

  // What the user will sign up for immediately
  const subscriptionPlan = useMemo(() => {
    if (variant === 'premium' && premiumTierPlan) {
      return premiumTierPlan;
    }

    if (
      isEligibleForFreeTrial &&
      freeTrialPlan !== undefined &&
      !inUpsellToPaidExperiment
    ) {
      return freeTrialPlan;
    }
    return selectedPaidPlan ?? originalMonthlyPlan;
  }, [
    freeTrialPlan,
    inUpsellToPaidExperiment,
    isEligibleForFreeTrial,
    originalMonthlyPlan,
    premiumTierPlan,
    selectedPaidPlan,
    variant,
  ]);

  useLogSignupEventOnMount({
    componentType: ComponentType.tray,
    feature: 'signup_home',
    trackingData: {
      referrer: REFERRER,
      isFreeTrial: isEligibleForFreeTrial,
    },
  });

  if (!subscriptionPlan) {
    throw new Error('Subscription plans failed to load');
  }

  // Hardcoded to false for now - will use in the future once some prerequisite experiments resolve
  const showPlanSelector = false;
  const { showPreTradeUpsellTrayCopy, showPreTradeUpsellTraySelectorButton } =
    usePreTradeUpsellTrayPaymentSelectorTreatment({ isEligibleForFreeTrial });

  const { validateSubscriptionCode } = useValidateSignupPromoCode({
    onError: ({ error }) => {
      logSubscriptionError({
        error,
        isHandled: true,
        componentName: 'SubscriptionSignupFlowTray',
        additionalMetadata: {
          promoCode,
        },
      });
    },
  });

  const promoCodeValidationAttempted = useRef(false);
  useEffect(() => {
    if (promoCode && !promoCodeValidationAttempted.current) {
      validateSubscriptionCode(promoCode);
      promoCodeValidationAttempted.current = true;
    }
  }, [promoCode, validateSubscriptionCode]);

  const { benefitTerms } = useBenefitsList({
    queryRef: query,
    variant,
  });

  const [isError, setIsError] = useState(false);
  const handleSignupError = useCallback(
    (error: Error) => {
      logSubscriptionError({
        error,
        isHandled: true,
        componentName: 'SubscriptionSignupFlowTray',
        additionalMetadata: {
          promoCode,
        },
      });
      setIsError(true);
    },
    [promoCode],
  );

  const handleSignupSuccess = useCallback(() => {
    markJourney('shown_cb1_signup_success');
    toast.show(
      formatMessage(messages.successToast, {
        productName: PRODUCT_NAME,
      }) as string,
      {
        bottomOffset: 125,
      },
    );
    onClose();
    onSignupSuccess();
  }, [onClose, onSignupSuccess, toast, formatMessage]);

  const { createSubscription, isInFlight: isCreateSubscriptionInFlight } =
    useSubscriptionCreator({
      onGenericError: handleSignupError,
      onInsufficientFundsError: handleSignupError,
      onSuccess: handleSignupSuccess,
    });

  const handleSignupButtonPress = useCallback(() => {
    if (isCreateSubscriptionInFlight) {
      return;
    }

    markJourney('press_cb1_signup_button');
    logSignupEvent({
      action: ActionType.click,
      componentType: ComponentType.button,
      feature: 'signup_tray',
      additionalData: {
        componentName: 'signup_button',
        variant,
        isFreeTrial: isEligibleForFreeTrial,
      },
    });

    logSignupEvent({
      action: ActionType.click,
      componentType: ComponentType.tray,
      feature: 'enrollment',
      trackingData: {
        referrer: REFERRER,
        isFreeTrial: isEligibleForFreeTrial,
      },
      additionalData: {
        stage: 'submitting',
        variant,
      },
    });

    if (!selectedPaymentMethod) {
      showPaymentMethodModal();
      return;
    }

    if (selectedPaymentMethod) {
      createSubscription({
        // What plan the user will immediately sign up for (could be free trial or a paid plan)
        planId: subscriptionPlan.subscriptionPlanUuid,
        // Only applicable if user is signing up for free trial: what plan will they be billed for after the free trial ends
        targetPlanId: isEligibleForFreeTrial
          ? selectedPaidPlan?.subscriptionPlanUuid
          : null,
        accountId: selectedPaymentMethod.getAccountUuid(),
        paymentMethodId: selectedPaymentMethod.getPaymentMethodUuid(),
        paymentMethodType: selectedPaymentMethod.getType(),
        signUpCode: validatedPromo ? validatedPromo.code : '',
        attributionSource: REFERRER,
        preferences: {
          payments: {
            cryptoPaymentPreferences: {
              cryptoBackupPaymentOptIn: false,
            },
          },
        },
      });
    }
  }, [
    isCreateSubscriptionInFlight,
    variant,
    isEligibleForFreeTrial,
    REFERRER,
    selectedPaymentMethod,
    showPaymentMethodModal,
    createSubscription,
    subscriptionPlan.subscriptionPlanUuid,
    selectedPaidPlan?.subscriptionPlanUuid,
    validatedPromo,
  ]);

  const ctaButtonText = useMemo(() => {
    if (showPreTradeUpsellTrayCopy) {
      return formatMessage(messages.tryForFree) as string;
    }

    if (isEligibleForFreeTrial && !inUpsellToPaidExperiment) {
      return formatMessage(messages.freeTrial) as string;
    }

    return formatMessage(messages.signup) as string;
  }, [
    formatMessage,
    inUpsellToPaidExperiment,
    isEligibleForFreeTrial,
    showPreTradeUpsellTrayCopy,
  ]);

  if (isError) {
    return <ErrorContent onTryAgain={onClose} />;
  }

  const PaymentComponent = showPreTradeUpsellTraySelectorButton ? (
    <>
      <Spacer vertical={2} />
      <VStack gap={1} spacingBottom={2}>
        <TextLegal testID="signup-tray-terms">{benefitTerms}</TextLegal>
        <SignupLegalTerms
          queryRef={query}
          ctaButtonText={ctaButtonText}
          promo={validatedPromo}
          promoApplied={promoApplied}
          isSigningUpForPremium={variant === 'premium' && !!premiumTierPlan}
          cryptoBackupsDisabled
          disableFreeTrial={inUpsellToPaidExperiment}
        />
      </VStack>
      <HStack alignItems="center" justifyContent="space-between">
        {selectedPaymentMethod ? (
          <PaymentMethodSelectorButton
            testID="subscription_signup_payment_method_select"
            paymentMethod={selectedPaymentMethod}
            onPress={showPaymentMethodModal}
          />
        ) : null}
        <HStack width="55%">
          <Button
            onPress={handleSignupButtonPress}
            variant="primary"
            testID="subscription_signup_flow_tray_signup_button"
            block
          >
            {ctaButtonText}
          </Button>
        </HStack>
      </HStack>
    </>
  ) : (
    <>
      {selectedPaymentMethod ? (
        <SelectedPaymentMethod
          testID="subscription_signup_payment_method_selector"
          paymentMethod={selectedPaymentMethod}
          onPress={showPaymentMethodModal}
          outerSpacing={
            {
              spacingHorizontal: 0,
              spacingTop: showPlanSelector ? 0 : 2,
            } as const
          }
          useLegacyLayout
        />
      ) : null}
      <VStack gap={1} spacingBottom={2}>
        <TextLegal testID="signup-tray-terms">{benefitTerms}</TextLegal>
        <SignupLegalTerms
          queryRef={query}
          ctaButtonText={ctaButtonText}
          promo={validatedPromo}
          promoApplied={promoApplied}
          isSigningUpForPremium={variant === 'premium' && !!premiumTierPlan}
          cryptoBackupsDisabled
          disableFreeTrial={inUpsellToPaidExperiment}
        />
      </VStack>
      <Button
        spacingBottom={0}
        onPress={handleSignupButtonPress}
        loading={isCreateSubscriptionInFlight}
        testID="subscription_signup_flow_tray_signup_button"
      >
        {ctaButtonText}
      </Button>
    </>
  );

  return (
    <>
      <VStack maxHeight="100%">
        <ScrollView bounces={false}>
          <Pressable
            accessibilityRole="button"
            background="background"
            noScaleOnPress
          >
            <ValuePropContent
              queryRef={query}
              variant={variant}
              validatedPromo={promoApplied ? validatedPromo : null}
              disableFreeTrial={inUpsellToPaidExperiment}
            />
          </Pressable>
        </ScrollView>
        <Divider />
        <VStack
          spacingHorizontal={3}
          spacingTop={selectedPaymentMethod ? 0 : 2}
          background="background"
        >
          {showPlanSelector ? (
            <PlanSelectorCell
              outerSpacing={
                {
                  spacingHorizontal: 0,
                  spacingBottom: 0,
                } as const
              }
              onPress={handlePlanSelectorPress}
            />
          ) : null}
          {/*
          this scenario is unlikely:
          in the trade flow (preview screen) we do not show this tray unless the user has a supported payment method
         */}
          {PaymentComponent}
        </VStack>
      </VStack>
      <SubscriptionPaymentMethodsModal
        selectedPaymentMethod={selectedPaymentMethod}
        visible={isPaymentMethodModalOpen}
        onRequestClose={hidePaymentMethodModal}
        onSelect={selectPaymentMethod}
        queryRef={query}
        showAddPaymentButton={false}
      />
    </>
  );
}

function SubscriptionSignupFlowTrayFallback() {
  return (
    <VStack spacing={4}>
      <Spinner size="large" />
    </VStack>
  );
}

export function SubscriptionSignupFlowTray({
  onClose,
  ...props
}: SubscriptionSignupFlowTrayProps) {
  // State to handle the visibility of sub-steps within this signup flow
  const [
    isMainStepVisible,
    { toggleOff: hideMainStep, toggleOn: showMainStep },
  ] = useToggler(true);
  const [
    isPlanSelectionStepVisible,
    { toggleOff: hidePlanSelectionStep, toggleOn: showPlanSelectionStep },
  ] = useToggler(false);

  // Ref used to control what action to take when the main tray exits. Needs to be a ref due to some React state lifecycle wonkiness w.r.t how CDS Tray propagates close events
  const closeActionRef = useRef<'EXIT' | 'PLAN_SELECT'>('EXIT');

  const handleMainTrayClose = useCallback(() => {
    if (closeActionRef.current === 'EXIT') {
      logSignupEvent({
        action: ActionType.click,
        componentType: ComponentType.button,
        feature: 'signup_tray',
        additionalData: {
          componentName: 'close',
        },
      });

      onClose();
    }
    if (closeActionRef.current === 'PLAN_SELECT') {
      hideMainStep();
      showPlanSelectionStep();
    }
  }, [hideMainStep, onClose, showPlanSelectionStep]);

  const handlePlanSelectionTrayClose = useCallback(() => {
    closeActionRef.current = 'EXIT';
    hidePlanSelectionStep();
    showMainStep();
  }, [hidePlanSelectionStep, showMainStep]);

  //Fires exposures
  useHasPaypalExperiment({});

  return (
    <SubscriptionSignupProvider>
      {isMainStepVisible && (
        <Tray
          testID="subscription-signup-flow-tray"
          onCloseComplete={handleMainTrayClose}
          disableCapturePanGestureToDismiss
          verticalDrawerPercentageOfView={0.96}
        >
          {({ handleClose: close }) => (
            <NetworkBoundary
              instrumentationId="SubscriptionSignupFlowTray"
              suspenseFallback={<SubscriptionSignupFlowTrayFallback />}
              errorFallback={null}
            >
              <SubscriptionSignupFlowTrayInner
                {...props}
                onClose={close}
                // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                handlePlanSelectorPress={() => {
                  closeActionRef.current = 'PLAN_SELECT';
                  close();
                }}
              />
            </NetworkBoundary>
          )}
        </Tray>
      )}
      {isPlanSelectionStepVisible && (
        <Tray onCloseComplete={handlePlanSelectionTrayClose}>
          {({ handleClose }) => <PlanSelectionList handleClose={handleClose} />}
        </Tray>
      )}
    </SubscriptionSignupProvider>
  );
}

import { PropsWithChildren, useCallback, useContext } from 'react';
import { Button, Text } from 'react-native';
import { SafeAreaProvider } from 'react-native-safe-area-context';
import { fireEvent, render, screen } from '@testing-library/react-native';
import { IntlProvider } from '@cbhq/i18n';

import {
  LogToErrorMetricsFunc,
  useNotifyErrorMetrics,
} from '@app/utils/errors/useNotifyErrorMetrics';

import {
  ErrorTrayContext,
  ErrorTrayProvider,
  ShowErrorTrayOptions,
} from './ErrorTrayContext';

jest.mock('@app/utils/errors/useNotifyErrorMetrics', () => ({
  useNotifyErrorMetrics: jest.fn(),
}));

function TestTrayComponent(options: Partial<ShowErrorTrayOptions>) {
  const { showErrorTray } = useContext(ErrorTrayContext);
  const handlePress = useCallback(
    () => showErrorTray({ error: new Error('My Test Error'), ...options }),
    [showErrorTray, options],
  );

  return <Button title="Show the tray" onPress={handlePress} />;
}

function Wrapper({ children }: PropsWithChildren<Record<string, never>>) {
  return (
    <SafeAreaProvider
      initialSafeAreaInsets={{ top: 0, left: 0, right: 0, bottom: 0 }}
    >
      <IntlProvider locale="en">{children}</IntlProvider>
    </SafeAreaProvider>
  );
}

describe('ErrorTrayContext', () => {
  let notifyErrorMetrics: LogToErrorMetricsFunc;
  beforeEach(() => {
    notifyErrorMetrics = jest.fn();
    (useNotifyErrorMetrics as jest.Mock).mockReturnValue(notifyErrorMetrics);
  });
  it('Renders children', () => {
    render(
      <ErrorTrayProvider>
        <Text>My Content</Text>
      </ErrorTrayProvider>,
      { wrapper: Wrapper },
    );

    expect(screen.getByText('My Content')).toBeTruthy();
  });

  it('displays a modal when showErrorModal is called', () => {
    render(
      <ErrorTrayProvider>
        <TestTrayComponent />
      </ErrorTrayProvider>,
      { wrapper: Wrapper },
    );

    fireEvent.press(screen.getByText('Show the tray'));

    expect(screen.getByText('My Test Error')).toBeTruthy();
  });

  it('reports to our error screen metrics as a blocking error', () => {
    render(
      <ErrorTrayProvider>
        <TestTrayComponent />
      </ErrorTrayProvider>,
      { wrapper: Wrapper },
    );

    fireEvent.press(screen.getByText('Show the tray'));

    expect(screen.getByText('My Test Error')).toBeTruthy();
    expect(notifyErrorMetrics).toHaveBeenCalledWith(
      new Error('My Test Error'),
      expect.objectContaining({
        // This flag is set to true when an error blocks the user from performing their
        // intended task and the error does not represent basic form/account validations
        // like account balance validation, empty form fields, etc.
        errorBlocksUser: true,

        metadata: expect.objectContaining({
          errorDisplayType: 'tray',
        }),
      }),
    );
  });

  it('skips reporting to our error screen metrics when omitFromErrorMetrics is true', () => {
    render(
      <ErrorTrayProvider>
        <TestTrayComponent omitFromErrorScreenMetric />
      </ErrorTrayProvider>,
      { wrapper: Wrapper },
    );

    fireEvent.press(screen.getByText('Show the tray'));

    expect(screen.getByText('My Test Error')).toBeTruthy();
    expect(notifyErrorMetrics).not.toHaveBeenCalled();
  });

  it('hides the error tray when dismiss is pressed', () => {
    render(
      <ErrorTrayProvider>
        <TestTrayComponent />
      </ErrorTrayProvider>,
      { wrapper: Wrapper },
    );

    fireEvent.press(screen.getByText('Show the tray'));
    fireEvent.press(screen.getByText('Dismiss'));

    expect(screen.queryByText('My Test Error')).toBeFalsy();
  });
});

