} from './PageLevelErrorStateContext';

function MockFallbackBanner() {
  const { incrementFallback, decrementFallback, displayBanner } =
    usePageLevelErrorState();

  useEffect(() => {
    incrementFallback('TestComponent');
    return () => decrementFallback();
  }, [decrementFallback, incrementFallback]);

  return (
    <Box testID="mock-banner">
      <TextLabel1>{`should display banner: ${displayBanner}`}</TextLabel1>
      {/* need to simulate using a button because when the component actually unmounts, 
      there's no way to query by anything anymore to verify that it works */}
      <Button onPress={() => decrementFallback()} title="testButton" />
    </Box>
  );
}

describe('PageLevelErrorStateContext', () => {
  it('should return displayBanner:true when a fallback banner mounts', async () => {
    const { getByTestId, getByText } = await renderAsync(
      <PageLevelErrorStateProvider>
        <MockFallbackBanner />
      </PageLevelErrorStateProvider>,
    );

    expect(getByTestId('mock-banner')).toBeTruthy();
    expect(getByText('should display banner: true')).toBeTruthy();
  });

  it('should return displayBanner:false when a fallback banner unmounts', async () => {
    const { getByText } = await renderAsync(
      <PageLevelErrorStateProvider>
        <MockFallbackBanner />
      </PageLevelErrorStateProvider>,
    );

    expect(getByText('should display banner: true')).toBeTruthy();

    const button = getByText('testButton');
    fireEvent.press(button);

    await waitFor(() => {
      expect(getByText('should display banner: false')).toBeTruthy();
    });
  });
});

