import { memo, useCallback, useMemo } from 'react';
import { Box } from '@cbhq/cds-mobile/layout/Box';
import { markJourney } from '@cbhq/core-vitals-mobile';
import { graphql, useFragment } from '@cbhq/data-layer';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { IconButton } from '@components/interactables/IconButton';
import { NetworkBoundary } from '@app/components/NetworkBoundary';
import { useModal } from '@app/hooks/navigation/useModal';
import { tapTracker } from '@app/screens/Receive/hooks/analytics';
import { useHasReceiveRedesignSupport } from '@app/screens/Receive/hooks/useHasReceiveRedesignSupport';
import { usePerfMark } from '@app/utils/performance/hooks/usePerfMark';

import { ReceiveButtonFragment$key } from './__generated__/ReceiveButtonFragment.graphql';

type ReceiveButtonProps = {
  queryRef: ReceiveButtonFragment$key;
  transparent?: boolean;
};

const i18nKey = 'AccountReceiveButton';
const messages = defineMessages({
  receive: {
    id: `${i18nKey}.receive`,
    defaultMessage: 'Receive',
    description: 'Accessibility label for receive button for account',
  },
});

const ReceiveButtonContent = memo(function ReceiveButtonContent({
  queryRef,
  transparent,
}: ReceiveButtonProps) {
  const { formatMessage } = useIntl();
  const receiveModal = useModal('ReceiveModalStack');
  const [startReceiveFlow] = usePerfMark('p2p', 'navigate_to_receive');
  const hasReceiveRedesign = useHasReceiveRedesignSupport();

  const { viewer } = useFragment(
    graphql`
      fragment ReceiveButtonFragment on Query {
        viewer {
          accountByUuidV2(uuid: $uuid) {
            uuid
            type
            allowDeposits
            assetOrFiatCurrency {
              __typename
              ... on ViewerAsset {
                asset {
                  platformName
                }
              }
              ... on TiersCurrency {
                code @required(action: THROW)
              }
            }
          }
        }
      }
    `,
    queryRef,
  );

  const account = viewer?.accountByUuidV2 || null;
  const currency = account?.assetOrFiatCurrency;
  const isViewerAsset = currency?.__typename === 'ViewerAsset';

  const currencyCode =
    useMemo(() => {
      if (isViewerAsset) {
        return currency?.asset?.platformName;
      }
      if (currency?.__typename === 'TiersCurrency') {
        return currency?.code;
      }

      return '';
    }, [currency, isViewerAsset]) ?? '';

  const trackTap = useCallback(() => {
    // Native Android fires both, keeping as it is for consistency
    tapTracker({
      name: 'receive_icon_tapped',
      context: 'account',
      currencyCode,
    });
    tapTracker({
      name: 'account_tapped_receive',
      context: 'account',
      currencyCode,
    });
  }, [currencyCode]);

  const handleOnPress = useCallback(() => {
    // Cannot change account because it was presented from a specific account
    startReceiveFlow();
    if (hasReceiveRedesign) {
      markJourney('navigate_to_receive_account_selector');
      receiveModal.present('ReceiveAccountSelector', {
        accountId: account?.uuid ?? '',
      });
    } else {
      markJourney('navigate_to_receive');
      receiveModal.present('Receive', {
        accountId: account?.uuid ?? '',
        canChangeAccount: false,
        entryPoint: 'account',
      });
    }

    trackTap();
  }, [
    account?.uuid,
    hasReceiveRedesign,
    receiveModal,
    startReceiveFlow,
    trackTap,
  ]);

  const isReceiveEnabled =
    ['VAULT', 'MULTISIG_VAULT', 'MULTISIG', 'WALLET'].includes(
      account?.type ?? '',
    ) && account?.allowDeposits;

  if (!isReceiveEnabled) {
    return null;
  }

  return (
    <IconButton
      accessibilityLabel={formatMessage(messages.receive)}
      accessibilityHint={formatMessage(messages.receive)}
      name="qrCode"
      transparent={transparent}
      onPress={handleOnPress}
    />
  );
});

export const ReceiveButton = memo(function ReceiveButton(
  props: ReceiveButtonProps,
) {
  return (
    <Box spacingStart={1}>
      <NetworkBoundary
        errorFallback={null}
        suspenseFallback={<IconButton name="qrCode" transparent disabled />}
      >
        <ReceiveButtonContent {...props} />
      </NetworkBoundary>
    </Box>
  );
});

