type TransactionListProps = {
  queryRef: TransactionListFragment$key;
  info?: TrayProps['children'];
  infoButtonText?: string;
  outerSpacing?: SpacingProps;
  historySectionTitle?: string;
  showDivider?: boolean;
  TypographyComponent?: FC<TextProps>;
  incompleteListInformationalBanner?: ReactNode;
};

export const transactionListQuery = graphql`
  query TransactionListQuery(
    $accountId: Uuid!
    $first: Int!
    $after: String
    $shouldIncludeMgx: Boolean!
    $txHistoryRefreshEnabled: Boolean!
  ) {
    viewer @required(action: THROW) {
      accountByUuidV2(uuid: $accountId) @required(action: THROW) {
        ...TransactionListTransactionListFragment
          @arguments(
            first: $first
            after: $after
            shouldIncludeMgx: $shouldIncludeMgx
            txHistoryRefreshEnabled: $txHistoryRefreshEnabled
          )
      }
    }
  }
`;

type IncompleteLimitOrderListProps = {
  viewerRef: TransactionListIncompleteLimitOrdersFragment$key | null;
};

const IncompleteLimitOrderList = memo(
  ({ viewerRef }: IncompleteLimitOrderListProps) => {
    const viewer = useFragment(
      graphql`
        # eslint-disable-next-line @cbhq/cdl-graphql-no-fragments-on-viewer
        fragment TransactionListIncompleteLimitOrdersFragment on Viewer
        @argumentDefinitions(limitOrderProductId: { type: "String!" }) {
          incompleteOrders: limitOrders(
            filter: {
              productId: $limitOrderProductId
              orderStatus: [CANCELLED, EXPIRED, FAILED]
            }
            first: 20
          ) {
            edges {
              node {
                orderConfiguration {
                  __typename
                  ... on BrokerageLimitOrderConfiguration {
                    limitPrice {
                      currency
                    }
                  }
                }
                status
                uuid
                side
                createdTime
                asset {
                  asset {
                    displaySymbol
                    imageUrl
                    name
                  }
                }
              }
            }
          }
        }
      `,
      viewerRef,
    );
    const { formatMessage, formatNumber, formatDate } = useIntl();
    const { navigate } = useStackNavigation();
    const txHistoryRefreshEnabled = useTxHistoryStylingExperiment();

    return (
      <>
        {useMemo(
          () =>
            viewer?.incompleteOrders?.edges.map(({ node }) => {
              if (!node) {
                return null;
              }

              let formattedDate = '';

              if (node?.createdTime) {
                formattedDate = formatDate(node?.createdTime, {
                  month: 'short',
                  day: 'numeric',
                  year: 'numeric',
                });
              }

              let cellMedia = (
                <DarkThemeProvider>
                  <Box
                    width={32}
                    height={32}
                    borderRadius="roundedFull"
                    background="primary"
                    alignItems="center"
                    justifyContent="center"
                  >
                    <Icon name="cash" size="s" color="foreground" />
                  </Box>
                </DarkThemeProvider>
              );

              if (node?.asset?.asset?.imageUrl) {
                cellMedia = (
                  <CellMedia
                    type="asset"
                    source={node?.asset?.asset?.imageUrl ?? ''}
                    accessibilityLabel={
                      node?.asset?.asset?.displaySymbol ??
                      node?.asset?.asset?.name ??
                      ''
                    }
                    cache="force-cache"
                  />
                );
              }

              const isBuy = node.side === 'BUY';
              const symbol = node?.asset?.asset?.displaySymbol ?? 'BTC';
              let currency = 'USD';
              if (
                node?.orderConfiguration &&
                node?.orderConfiguration?.__typename ===
                  'BrokerageLimitOrderConfiguration'
              ) {
                currency =
                  node?.orderConfiguration?.limitPrice?.currency ?? 'USD';
              }
              const clientOrderId = node.uuid ?? '';
              const onPress = () =>
                navigate('LimitOrderDetails', { clientOrderId });

              if (txHistoryRefreshEnabled) {
                return (
                  <ListCell
                    key={node.uuid}
                    title={formatMessage(
                      isBuy ? messages.bought : messages.sold,
                      {
                        symbol,
                      },
                    )}
                    description={
                      formattedDate ?? formatMessage(messages.usingUsdc)
                    }
                    detail={formatMessage(messages.amountOfCrypto, {
                      symbol,
                      amount: 0,
                    })}
                    subdetail={formatNumber(Number(0), {
                      currency,
                      style: 'currency',
                    })}
                    media={cellMedia}
                    onPress={onPress}
                    priority="end"
                  />
                );
              }

              return (
                <DSTransactionCell
                  key={node.uuid}
                  onPress={onPress}
                  title={formatMessage(
                    isBuy ? messages.bought : messages.sold,
                    {
                      symbol,
                    },
                  )}
                  description={formatMessage(messages.usingUsdc)}
                  detail={formatMessage(messages.amountOfCrypto, {
                    symbol,
                    amount: 0,
                  })}
                  subdetail={formatNumber(Number(0), {
                    currency,
                    style: 'currency',
                  })}
                />
              );
            }),
          [
            viewer?.incompleteOrders?.edges,
            txHistoryRefreshEnabled,
            formatMessage,
            formatNumber,
            formatDate,
            navigate,
          ],
        )}
      </>
    );
  },
);

type HistoryTransactionListProps = {
  historyTransactions: NonNullable<
    NonNullable<
      TransactionListTransactionListFragment$data['accountHistoryEntries']
    >['edges'][0]['node']
  >[];
  viewer: TransactionListDeferredTransactionCellAccountFragment$key | null;
  hasNext: boolean;
  onViewAllPress: () => void;
  outerSpacing?: SpacingProps;
  isFiat?: boolean;
};

function HistoryTransactionList({
  historyTransactions,
  viewer,
  hasNext,
  onViewAllPress,
  outerSpacing,
  isFiat,
}: HistoryTransactionListProps) {
  const { formatMessage } = useIntl();
  const txHistoryRefreshEnabled = useTxHistoryStylingExperiment();

  const list = useMemo(
    () =>
      historyTransactions?.map((transaction, index) =>
        txHistoryRefreshEnabled ? (
          <DeferredTransactionHistoryCell
            key={transaction.uuid}
            transactionRef={transaction}
            index={index}
            isFiat={isFiat}
          />
        ) : (
          <DeferredTransactionCell
            key={transaction.uuid}
            transactionRef={transaction}
            viewerRef={viewer}
            index={index}
            outerSpacing={outerSpacing}
          />
        ),
      ),

    [
      historyTransactions,
      isFiat,
      outerSpacing,
      txHistoryRefreshEnabled,
      viewer,
    ],
  );

  return (
    <>
      {list}
      {!!hasNext && (
        <DeferredViewAllButton
          variant="secondary"
          spacingTop={1}
          spacingBottom={0}
          spacingHorizontal={3}
          onPress={onViewAllPress}
        >
          {formatMessage(messages.viewAllTransactions)}
        </DeferredViewAllButton>
      )}
    </>
  );
}

function TransactionList({
  queryRef,
  info,
  outerSpacing,
  historySectionTitle,
  showDivider = true,
  TypographyComponent,
  infoButtonText,
  incompleteListInformationalBanner,
}: TransactionListProps) {
  const { formatMessage } = useIntl();
  const { push } = useStackNavigation();
  const query = useFragment(
    // andrei.calazans skip flag here is only used in unit tests.

    graphql`
      fragment TransactionListFragment on Query
      @refetchable(queryName: "TransactionListPaginationQuery")
      @argumentDefinitions(
        accountId: { type: "Uuid!" }
        limitOrderProductId: { type: "String!" }
        skipIncompleteList: { type: "Boolean!" }
        skipTransactionList: { type: "Boolean", defaultValue: false }
      ) {
        ...TransactionListEmptyFragment
          @arguments(
            accountId: $accountId
            skipTransactionList: $skipTransactionList
          )
        viewer @skip(if: $skipTransactionList) {
          ...TransactionListDeferredTransactionCellAccountFragment
            @arguments(accountId: $accountId)
          ...TransactionListIncompleteLimitOrdersFragment
            @arguments(limitOrderProductId: $limitOrderProductId)
            @skip(if: $skipIncompleteList)
          accountByUuidV2(uuid: $accountId) @required(action: THROW) {
            uuid
          }
        }
      }
    `,
    queryRef,
  );

  const { viewer } = query;

  const account = viewer?.accountByUuidV2;

  if (account === undefined) {
    throw new GraphQLMissingDataError();
  }

  const shouldIncludeMgx = useHasMgx();
  const txHistoryRefreshEnabled = useTxHistoryStylingExperiment();

  const transactionListQueryResponse = useLazyLoadQuery<TransactionListQuery>(
    transactionListQuery,
    {
      accountId: account.uuid,
      first: PAGE_LIMIT,
      shouldIncludeMgx,
      txHistoryRefreshEnabled,
    },
    { fetchPolicy: 'store-and-network' },
  );

  const accountByUuid = transactionListQueryResponse.viewer.accountByUuidV2;

  const { data, hasNext } = usePaginationFragment<
    TransactionListTransactionListFragmentQuery,
    TransactionListTransactionListFragment$key
  >(
    graphql`
      fragment TransactionListTransactionListFragment on Account
      @argumentDefinitions(
        first: { type: "Int!" }
        after: { type: "String" }
        shouldIncludeMgx: { type: "Boolean", defaultValue: false }
        txHistoryRefreshEnabled: { type: "Boolean!" }
      )
      @refetchable(queryName: "TransactionListTransactionListFragmentQuery") {
        accountHistoryEntries(first: $first, after: $after)
          @required(action: THROW)
          @connection(key: "TransactionList_viewer_accountHistoryEntries") {
          edges {
            node {
              uuid
              status
              details {
                __typename
                ... on UserSendDetails {
                  offchainStatus
                }
              }
              ...TransactionListDeferredTransactionCellFragment
                @skip(if: $txHistoryRefreshEnabled)
              ...TransactionListDeferredTransactionHistoryCellFragment
                @arguments(shouldIncludeMgx: $shouldIncludeMgx)
                @include(if: $txHistoryRefreshEnabled)
            }
          }
          pageInfo {
            hasNextPage
          }
        }
        type
        assetOrFiatCurrency {
          __typename
          ... on ViewerAsset {
            asset {
              isStablecoin
            }
            ...useAssetHasRewardsOrStakingFragment
          }
        }
      }
    `,
    accountByUuid,
  );

  const viewerAsset =
    data.assetOrFiatCurrency?.__typename === 'ViewerAsset'
      ? data.assetOrFiatCurrency
      : null;

  const hasRewardsOrStaking = useAssetHasRewardsOrStaking(viewerAsset);

  const { refresh } = useRefreshQuery<TransactionListQuery>(
    transactionListQuery,
    {
      accountId: account.uuid,
      first: PAGE_LIMIT,
      shouldIncludeMgx,
      txHistoryRefreshEnabled,
    },
  );

  if (data.id === null) {
    throw new GraphQLMissingDataError();
  }

  useSubscribeToInvalidationState([data.id], refresh);

  let hasTransactions = false;
  const transactions = useMemo(() => {
    return data.accountHistoryEntries?.edges ?? [];
  }, [data.accountHistoryEntries?.edges]);

  if (data) {
    hasTransactions = !!transactions.length;
  }
  const nonNullableTransactions = useMemo(() => {
    return removeFalsyValues(
      transactions.map((transaction) => transaction.node),
    );
  }, [transactions]);

  const pendingTransactions = nonNullableTransactions.filter(
    (transaction) =>
      transaction.status === 'PENDING' ||
      (transaction?.details?.__typename === 'UserSendDetails' &&
        transaction?.details?.offchainStatus === 'PENDING'),
  );
  const historyTransactions = nonNullableTransactions.filter(
    (transaction) =>
      (transaction.status !== 'PENDING' &&
        transaction?.details?.__typename !== 'UserSendDetails') ||
      (transaction?.details?.__typename === 'UserSendDetails' &&
        transaction?.details?.offchainStatus !== 'PENDING'),
  );

  const onViewAllPress = useCallback(
    () => account.uuid && push('Transactions', { accountId: account.uuid }),
    [push, account.uuid],
  );

  const isStableCoin = viewerAsset?.asset?.isStablecoin ?? false;
  const hasLimitOrderExperiment = useIsSimpleTradeLimitOrder(
    isStableCoin,
    'kill_simple_trade_limit_order_access',
  );
  const [tabIndex, setTabIndex] = useState(0);
  const tabs = useMemo(
    () => [
      { key: 'complete', title: formatMessage(messages.completeTab) },
      { key: 'incomplete', title: formatMessage(messages.incompleteTab) },
    ],
    [formatMessage],
  );

  const list = useMemo(
    () => (
      <HistoryTransactionList
        historyTransactions={historyTransactions}
        viewer={viewer ?? null}
        hasNext={hasNext}
        onViewAllPress={onViewAllPress}
        outerSpacing={outerSpacing}
        isFiat={data?.type === 'FIAT'}
      />
    ),
    [
      historyTransactions,
      viewer,
      hasNext,
      onViewAllPress,
      outerSpacing,
      data?.type,
    ],
  );

  const renderScene = useCallback<TabViewProps['renderScene']>(
    ({ route }) => {
      switch (route.key) {
        case 'complete':
          return list;
        case 'incomplete':
          return (
            <>
              {incompleteListInformationalBanner && (
                <Box spacingHorizontal={2}>
                  {incompleteListInformationalBanner}
                </Box>
              )}
              <IncompleteLimitOrderList viewerRef={viewer ?? null} />
            </>
          );
        default:
          return null;
      }
    },
    [list, viewer, incompleteListInformationalBanner],
  );

  const renderTabBar: RenderTabBar = useCallback(
    (p) => <TabBar TypographyComponent={TypographyComponent} {...p} />,
    [TypographyComponent],
  );

  if (!hasTransactions && hasRewardsOrStaking) {
    // If the account supports rewards or staking and we are in the NUX empty
    // transactions experiment, hide this component
    return null;
  }

  return (
    <AccountScreenSection showDivider={showDivider}>
      {!hasTransactions ? (
        <TransactionListEmpty queryRef={query} />
      ) : (
        <>
          {!!pendingTransactions?.length && (
            <Section title={formatMessage(messages.pending)} offsetContent>
              {pendingTransactions.map((transaction, index) => {
                return txHistoryRefreshEnabled ? (
                  <DeferredTransactionHistoryCell
                    key={transaction.uuid}
                    transactionRef={transaction}
                    index={index}
                    isFiat={data?.type === 'FIAT'}
                  />
                ) : (
                  <DeferredTransactionCell
                    key={transaction.uuid}
                    transactionRef={transaction}
                    viewerRef={viewer ?? null}
                    index={index}
                  />
                );
              })}
            </Section>
          )}
          <Section
            title={historySectionTitle ?? formatMessage(messages.history)}
            offsetContent
            info={info}
            iconSize="m"
            infoIcon="info"
            infoButtonText={infoButtonText ?? formatMessage(messages.close)}
            showInfoButton={!!info}
          >
            {hasLimitOrderExperiment ? (
              <TabView
                lazy
                index={tabIndex}
                onIndexChange={setTabIndex}
                routes={tabs}
                renderTabBar={renderTabBar}
                renderScene={renderScene}
              />
            ) : (
              list
            )}
          </Section>
        </>
      )}
    </AccountScreenSection>
  );
}

type TransactionListByAssetSymbolProps = {
  queryRef: TransactionListByAssetSymbolFragment$key;
  incompleteListInformationalBanner?: ReactNode;
  showDivider?: boolean;
  outerSpacing?: SpacingProps;
  TypographyComponent?: FC<TextProps>;
  historySectionTitle?: string;
  infoButtonText?: string;
  info?: TrayProps['children'];
};

// Similar to TransactionList but shows all transactions for all portfolios for provided asset/fiat symbol
export function TransactionListByAssetSymbol({
  queryRef,
  incompleteListInformationalBanner,
  showDivider = true,
  outerSpacing,
  TypographyComponent,
  historySectionTitle,
  infoButtonText,
  info,
}: TransactionListByAssetSymbolProps) {
  const { formatMessage } = useIntl();
  const { push } = useStackNavigation();
  const txHistoryRefreshEnabled = useTxHistoryStylingExperiment();

  const [tabIndex, setTabIndex] = useState(0);
  const tabs = useMemo(
    () => [
      { key: 'complete', title: formatMessage(messages.completeTab) },
      { key: 'incomplete', title: formatMessage(messages.incompleteTab) },
    ],
    [formatMessage],
  );

  const { data, hasNext } = usePaginationFragment<
    TransactionListByAssetSymbolRefetchQuery,
    TransactionListByAssetSymbolFragment$key
  >(
    graphql`
      fragment TransactionListByAssetSymbolFragment on Query
      @refetchable(queryName: "TransactionListByAssetSymbolRefetchQuery")
      @argumentDefinitions(
        cursor: { type: "String", defaultValue: null }
        count: { type: "Int", defaultValue: 10 }
        skipTransactionByAssetSymbolList: {
          type: "Boolean"
          defaultValue: true
        }
        shouldIncludeMgx: { type: "Boolean", defaultValue: false }
      ) {
        ...TransactionListEmptyFragment
          @arguments(
            accountId: $accountUuid
            skipTransactionList: $skipTransactionByAssetSymbolList
          )
        viewer {
          ...TransactionListDeferredTransactionCellAccountFragment
            @arguments(accountId: $accountUuid)
          ...TransactionListIncompleteLimitOrdersFragment
            @arguments(limitOrderProductId: $limitOrderProductId)
            @skip(if: $skipLimitOrder)
          accountByUuidV2(uuid: $accountUuid) @required(action: THROW) {
            uuid
            type
            assetOrFiatCurrency {
              __typename
              ... on ViewerAsset {
                asset {
                  platformName
                  isStablecoin
                }
                ...useAssetHasRewardsOrStakingFragment
              }
              ... on TiersCurrency {
                code
              }
            }
          }

          accountHistory @skip(if: $skipMultiPortfolio) {
            allEntries(
              first: $count
              after: $cursor
              assetSymbols: [$assetSymbol]
              singleSided: false
              transactionsCombined: false
              categories: $categories
            )
              @connection(
                key: "TransactionListByAssetSymbolFragment_allEntries"
              ) {
              pageInfo {
                hasNextPage
              }
              edges {
                node {
                  uuid
                  status
                  details {
                    __typename
                    ... on UserSendDetails {
                      offchainStatus
                    }
                  }

                  ...TransactionListDeferredTransactionCellFragment
                    @skip(if: $txHistoryRefreshEnabled)
                  ...TransactionListDeferredTransactionHistoryCellFragment
                    @arguments(shouldIncludeMgx: $shouldIncludeMgx)
                    @include(if: $txHistoryRefreshEnabled)
                }
              }
            }
          }
        }
      }
    `,
    queryRef,
  );

  const { viewer } = data;

  const account = viewer?.accountByUuidV2;

  if (account === undefined) {
    throw new GraphQLMissingDataError();
  }

  let hasTransactions = false;
  const transactions = useMemo(() => {
    return viewer?.accountHistory?.allEntries?.edges ?? [];
  }, [viewer?.accountHistory?.allEntries?.edges]);

  const isFiat = data.viewer?.accountByUuidV2?.type === 'FIAT';
  const viewerAsset =
    data.viewer?.accountByUuidV2?.assetOrFiatCurrency?.__typename ===
    'ViewerAsset'
      ? data.viewer.accountByUuidV2.assetOrFiatCurrency
      : null;
  const isStableCoin = viewerAsset?.asset?.isStablecoin ?? false;
  const hasLimitOrderExperiment = useIsSimpleTradeLimitOrder(
    isStableCoin,
    'kill_simple_trade_limit_order_access',
  );

  if (data) {
    hasTransactions = !!transactions.length;
  }

  const nonNullableTransactions = useMemo(() => {
    return removeFalsyValues(
      transactions.map((transaction) => transaction?.node),
    );
  }, [transactions]);

  const pendingTransactions = nonNullableTransactions.filter(
    (transaction) =>
      transaction.status === 'PENDING' ||
      (transaction?.details?.__typename === 'UserSendDetails' &&
        transaction?.details?.offchainStatus === 'PENDING'),
  );

  const historyTransactions = nonNullableTransactions.filter(
    (transaction) =>
      (transaction.status !== 'PENDING' &&
        transaction?.details?.__typename !== 'UserSendDetails') ||
      (transaction?.details?.__typename === 'UserSendDetails' &&
        transaction?.details?.offchainStatus !== 'PENDING'),
  );

  const onViewAllPress = useCallback(() => {
    if (account.uuid) {
      let assetSymbol;
      if (account?.assetOrFiatCurrency) {
        if (account.assetOrFiatCurrency.__typename === 'ViewerAsset') {
          assetSymbol =
            account.assetOrFiatCurrency.asset?.platformName || undefined;
        } else if (account.assetOrFiatCurrency.__typename === 'TiersCurrency') {
          assetSymbol = account.assetOrFiatCurrency.code;
        }
      }

      push('Transactions', {
        accountId: account.uuid,
        assetSymbol,
      });
    }
  }, [push, account.uuid, account.assetOrFiatCurrency]);

  const list = useMemo(
    () => (
      <HistoryTransactionList
        historyTransactions={historyTransactions}
        viewer={viewer ?? null}
        hasNext={hasNext}
        onViewAllPress={onViewAllPress}
        outerSpacing={outerSpacing}
        isFiat={isFiat}
      />
    ),
    [
      hasNext,
      historyTransactions,
      isFiat,
      onViewAllPress,
      outerSpacing,
      viewer,
    ],
  );

  const renderScene = useCallback<TabViewProps['renderScene']>(
    ({ route }) => {
      switch (route.key) {
        case 'complete':
          return list;
        case 'incomplete':
          return (
            <>
              {incompleteListInformationalBanner && (
                <Box spacingHorizontal={2}>
                  {incompleteListInformationalBanner}
                </Box>
              )}
              <IncompleteLimitOrderList viewerRef={viewer ?? null} />
            </>
          );
        default:
          return null;
      }
    },
    [list, viewer, incompleteListInformationalBanner],
  );

  const renderTabBar: RenderTabBar = useCallback(
    (p) => <TabBar TypographyComponent={TypographyComponent} {...p} />,
    [TypographyComponent],
  );

  const hasRewardsOrStaking = useAssetHasRewardsOrStaking(viewerAsset);
  if (!hasTransactions && hasRewardsOrStaking) {
    // If the account supports rewards or staking and we are in the NUX empty
    // transactions experiment, hide this component
    return null;
  }

  return (
    <AccountScreenSection showDivider={showDivider}>
      {!hasTransactions ? (
        <TransactionListEmpty queryRef={data} />
      ) : (
        <>
          {!!pendingTransactions?.length && (
            <Section title={formatMessage(messages.pending)} offsetContent>
              {pendingTransactions.map((transaction, index) => {
                return txHistoryRefreshEnabled ? (
                  <DeferredTransactionHistoryCell
                    key={transaction.uuid}
                    transactionRef={transaction}
                    index={index}
                    isFiat={isFiat}
                  />
                ) : (
                  <DeferredTransactionCell
                    key={transaction.uuid}
                    transactionRef={transaction}
                    viewerRef={viewer ?? null}
                    index={index}
                  />
                );
              })}
            </Section>
          )}
          <Section
            title={historySectionTitle ?? formatMessage(messages.history)}
            offsetContent
            info={info}
            iconSize="m"
            infoIcon="info"
            infoButtonText={infoButtonText ?? formatMessage(messages.close)}
            showInfoButton={!!info}
          >
            {hasLimitOrderExperiment ? (
              <TabView
                lazy
                index={tabIndex}
                onIndexChange={setTabIndex}
                routes={tabs}
                renderTabBar={renderTabBar}
                renderScene={renderScene}
              />
            ) : (
              list
            )}
          </Section>
        </>
      )}
    </AccountScreenSection>
  );
}

