type IncentiveDescriptionProps = {
  superText: string;
  onPress?: () => void;
  icon?: ReactElement;
  highlight?: boolean;
};

export const ChecklistSummarySuperText = memo(
  ({ onPress, ...props }: IncentiveDescriptionProps) => {
    return (
      <HStack spacingBottom={2}>
        {onPress ? (
          <Pressable
            accessibilityRole="button"
            background="transparent"
            onPress={onPress}
          >
            <SuperText {...props} />
          </Pressable>
        ) : (
          <SuperText {...props} />
        )}
        <Spacer />
      </HStack>
    );
  },
);

function SuperText({
  superText,
  onPress,
  icon,
  highlight = false,
}: IncentiveDescriptionProps) {
  return (
    <HStack
      testID="checklist-summary-incentive-line"
      flexGrow={1}
      justifyContent="flex-start"
      alignItems="center"
    >
      {!!icon && (
        <VStack height={24} width={24}>
          {icon}
        </VStack>
      )}
      <TextLabel1
        color={highlight ? 'primary' : 'foreground'}
        spacingStart={icon ? 1 : undefined}
        spacingEnd={1}
      >
        {superText}
      </TextLabel1>
      {!!onPress && (
        <Icon
          style={{ transform: [{ scaleX: -1 }] }}
          testID="checklist-incentive-arrow"
          size="s"
          name="backArrow"
        />
      )}
    </HStack>
  );
}

