export type UpdateInformationProps = {
  isHealthCheck?: boolean;
  email?: string | null;
  phone?: string;
  isUSUser: boolean;
  viewerRef: UpdateInformationFragment$key;
  factor?: SecurityPromptViewFactor | null;
};

const styles = StyleSheet.create({
  scrollViewContainer: {
    flexGrow: 1,
  },
});

const shouldUpdateInfo = true;

export const UpdateInformation = memo(
  ({
    isHealthCheck,
    email,
    phone,
    isUSUser,
    viewerRef,
    factor,
  }: UpdateInformationProps) => {
    const { viewer } = useFragment(
      graphql`
        fragment UpdateInformationFragment on Query {
          viewer @skip(if: $skip) {
            userProperties {
              secondFactor {
                twoFactorMethod
              }
            }
          }
        }
      `,
      viewerRef,
    );

    const { userProperties } = viewer || {};
    const { formatMessage } = useIntl();

    const [visible, { toggleOn, toggleOff }] = useToggler(true);
    const alert = useAlert();

    const openAuthorizedUrl = useAuthorizedBrowserOpener();
    const openWebBrowser = useWebBrowserOpener();
    const [keyName, setKeyName] = useState<string>('');

    const [updateInformation] = useMutation<UpdateInformationMutation>(graphql`
      mutation UpdateInformationMutation(
        $input: UpdateSecurityPromptLastDismissedAtDateInput!
      ) {
        updateSecurityPromptLastDismissedAtDate(input: $input) {
          __typename
          ... on UpdateSecurityPromptLastDismissedAtDateSuccess {
            viewer {
              securityPrompt {
                type
              }
            }
          }
          ... on UpdateSecurityPromptLastDismissedAtDateError {
            error {
              message
            }
          }
        }
      }
    `);

    const getFirstSecurityKeyName = useCallback(async () => {
      try {
        const { devices } = (await client.get(
          'v2/user/second-factors/fido/devices',
        )) as unknown as { devices: { name: string }[] };
        setKeyName(devices?.[0]?.name || formatMessage(messages.securityKey));
      } catch (e) {
        setKeyName(formatMessage(messages.securityKey));
      }
    }, [formatMessage]);

    useLogEventOnMount('ar2_0_update_security_setting_render', {
      action: ActionType.view,
      componentType: ComponentType.modal,
      content: isHealthCheck ? 'security_health' : 'update_2fa',
    });

    useEffect(() => {
      if (userProperties?.secondFactor?.twoFactorMethod === 'u2f') {
        void getFirstSecurityKeyName();
      }
    }, [getFirstSecurityKeyName, userProperties?.secondFactor]);

    const legacySettingsURL = `${host}/settings/security_settings`;
    const profileURL = `${accHost}/profile`;
    const helpPage = `https://help.coinbase.com/${locale}/coinbase/getting-started/getting-started-with-coinbase/2-factor-authentication-2fa-faq`;

    const handleUpdateInformation = useCallback(() => {
      toggleOff();
      alert.close();
      updateInformation({
        variables: {
          input: { value: shouldUpdateInfo },
        },
        onCompleted: () => {
          logEvent('ar2_0_update_security_confirm', {
            action: ActionType.click,
            componentType: ComponentType.link,
            content: isHealthCheck ? 'security_health' : 'update_2fa',
          });
        },
        onError: () => {},
      });
    }, [toggleOff, alert, updateInformation, isHealthCheck]);

    const confirmationTitleMessage = useMemo(() => {
      const messageConfirmation = {
        SMS: messages.confirmationTitleSMS,
        EMAIL: messages.confirmationEmail,
        TOTP: messages.confirmationTOTP,
        UNSPECIFIED: messages.confirmationTitleUnspecified,
      };
      return (
        messageConfirmation[factor as 'SMS'] ?? messageConfirmation.UNSPECIFIED
      );
    }, [factor]);

    const confirmationSubtitleMessage = useMemo(() => {
      const messageConfirmation = {
        SMS: messages.confirmationSubtitleSMS,
        EMAIL: messages.confirmationEmail,
        TOTP: messages.confirmationTOTP,
        UNSPECIFIED: messages.confirmationSubtitleUnspecified,
      };
      return (
        messageConfirmation[factor as 'SMS'] ?? messageConfirmation.UNSPECIFIED
      );
    }, [factor]);

    const confirmationIcon = useMemo(() => {
      const icons = {
        SMS: 'phone' as IllustrationPictogramNames,
        EMAIL: 'email',
        TOTP: 'phone',
        UNSPECIFIED: 'contactInfo',
      };
      return icons[factor as 'SMS'] ?? icons.UNSPECIFIED;
    }, [factor]);

    const handleAlertRequestClose = useCallback(() => {
      toggleOn();
      alert.close();
    }, [alert, toggleOn]);

    const handleDismissSecurityPrompt = useCallback(async () => {
      if (isHealthCheck) {
        handleUpdateInformation();
      } else {
        toggleOff();
        alert.open(
          <Alert
            title={formatMessage(messages.confirmationAlertTitle, {
              method: formatMessage(confirmationTitleMessage),
            })}
            body={formatMessage(messages.confirmationAlertSubtitle, {
              method: formatMessage(confirmationSubtitleMessage),
            })}
            pictogram={confirmationIcon}
            visible
            onRequestClose={handleAlertRequestClose}
            preferredActionLabel={formatMessage(
              messages.confirmationAlertConfirm,
            )}
            onPreferredActionPress={handleUpdateInformation}
            dismissActionLabel={formatMessage(
              messages.confirmationAlertDecline,
            )}
          />,
        );
      }
    }, [
      isHealthCheck,
      handleUpdateInformation,
      toggleOff,
      alert,
      formatMessage,
      confirmationTitleMessage,
      confirmationSubtitleMessage,
      confirmationIcon,
      handleAlertRequestClose,
    ]);

    const openUrl = useCallback(
      async (url: string) => {
        await openAuthorizedUrl({
          url,
          omitRedirectUri: true,
          allowManualSignIn: true,
          forceOpenOutsideApp: false,
        });
      },
      [openAuthorizedUrl],
    );

    const handleRedirectLegacySettings = useCallback(
      async (context: string) => {
        try {
          updateInformation({
            variables: {
              input: { value: shouldUpdateInfo },
            },
            onCompleted: () => {
              handleUpdateLogEvent(context);
              void openUrl(legacySettingsURL);
              toggleOff();
            },
            onError: () => {
              void openUrl(legacySettingsURL);
              toggleOff();
            },
          });
        } catch (error) {
          errorVitals.logError(getErrorInstance(error), {
            context: 'account_recover_update_information',
            severity: 'error',
            isHandled: false,
          });
        }
      },
      [openUrl, legacySettingsURL, toggleOff, updateInformation],
    );

    const handleRedirectProfile = useCallback(async () => {
      try {
        updateInformation({
          variables: {
            input: { value: shouldUpdateInfo },
          },
          onCompleted: () => {
            handleUpdateLogEvent('email');
            void openUrl(profileURL);
            toggleOff();
          },
          onError: () => {
            void openUrl(profileURL);
            toggleOff();
          },
        });
      } catch (error) {
        errorVitals.logError(getErrorInstance(error), {
          context: 'account_recover_update_information',
          severity: 'error',
          isHandled: false,
        });
      }
    }, [updateInformation, openUrl, profileURL, toggleOff]);

    const handleRedirectHelpPage = useCallback(() => {
      void openWebBrowser(helpPage);
    }, [openWebBrowser, helpPage]);

    const handleUpdateLogEvent = (context: string) => {
      logEvent('ar2_0_update_security_setting_button', {
        action: ActionType.click,
        componentType: ComponentType.link,
        context,
      });
    };

    const getWarningBox = useCallback(
      (method: TwoFactorMethod | null) => {
        const boxes = {
          sms: (
            <TextBody
              testID="help-page"
              color="primary"
              onPress={handleRedirectHelpPage}
            >
              {formatMessage(messages.help)}
            </TextBody>
          ),
          totp: (
            <Box
              flexDirection="column"
              spacing={3}
              borderRadius="rounded"
              background="primaryWash"
            >
              <TextHeadline color="primary" spacingBottom={1}>
                {formatMessage(messages.twoFactorTOTPWarningTitle)}
              </TextHeadline>
              <TextLabel2 color="primary">
                {formatMessage(messages.twoFactorTOTPWarningSubtitle)}
              </TextLabel2>
            </Box>
          ),
          u2f: (
            <Box
              flexDirection="column"
              spacing={3}
              borderRadius="rounded"
              background="primaryWash"
            >
              <TextHeadline color="primary" spacingBottom={1}>
                {formatMessage(messages.twoFactorKeyWarningTitle)}
              </TextHeadline>
              <TextLabel2 color="primary">
                {formatMessage(messages.twoFactorKeyWarningSubtitle)}
              </TextLabel2>
            </Box>
          ),
        };

        return boxes[method as 'sms'] ?? boxes.sms;
      },
      [formatMessage, handleRedirectHelpPage],
    );

    const handle2FARedirect = useCallback(() => {
      void handleRedirectLegacySettings('second_factor_method');
    }, [handleRedirectLegacySettings]);

    const handlePhoneRedirect = useCallback(() => {
      void handleRedirectLegacySettings('phone');
    }, [handleRedirectLegacySettings]);

    const handleEmailRedirect = useCallback(() => {
      if (isUSUser) {
        void handleRedirectProfile();
      } else {
        void handleRedirectLegacySettings('email');
      }
    }, [handleRedirectLegacySettings, handleRedirectProfile, isUSUser]);

    const handleClose = useCallback(() => {
      void handleDismissSecurityPrompt();
    }, [handleDismissSecurityPrompt]);

    const totpLabel = useMemo(() => {
      if (factor === 'TOTP') {
        return (
          <TextLabel2 color="negative">
            {formatMessage(messages.required)}
          </TextLabel2>
        );
      }
      if (userProperties?.secondFactor?.twoFactorMethod !== 'totp') {
        return <TextLabel2>{formatMessage(messages.totpRegister)}</TextLabel2>;
      }
      return undefined;
    }, [factor, formatMessage, userProperties?.secondFactor?.twoFactorMethod]);

    const getTwoFactorOption = useCallback(
      (method: TwoFactorMethod | null) => {
        if (method === 'u2f') {
          return (
            <ProfileInfoCell
              option={keyName}
              description={formatMessage(messages.twoFactorOptionDescription)}
              onClick={handle2FARedirect}
              id="u2f"
            />
          );
        }
        return (
          <ProfileInfoCell
            option={formatMessage(messages.twoFactorTOTPOption)}
            description={formatMessage(messages.twoFactorOptionDescription)}
            onClick={handle2FARedirect}
            id="totp"
            label={totpLabel}
          />
        );
      },
      [formatMessage, handle2FARedirect, keyName, totpLabel],
    );

    const shouldDisplayModal = useMemo(
      () =>
        visible &&
        (userProperties?.secondFactor?.twoFactorMethod !== 'u2f' ||
          !isEmpty(keyName)),
      [keyName, userProperties?.secondFactor, visible],
    );

    const UpdateInformationModal = useCallback(
      () => (
        <Modal
          visible={shouldDisplayModal}
          onRequestClose={handleClose}
          testID="update-information"
        >
          <ScrollView contentContainerStyle={styles.scrollViewContainer}>
            <VStack
              testID={isHealthCheck ? 'security-health-check' : 'update-2fa'}
              justifyContent="space-between"
              height="100%"
            >
              <VStack spacingHorizontal={3} spacingBottom={2}>
                <HStack justifyContent="flex-end" spacingTop={2}>
                  <Pressable
                    accessibilityRole="button"
                    testID="close-modal"
                    background="transparent"
                    onPress={handleClose}
                  >
                    <Icon name="close" size="s" color="foregroundMuted" />
                  </Pressable>
                </HStack>
                <VStack spacingVertical={2}>
                  <TextTitle1 spacingBottom={2}>
                    {formatMessage(
                      isHealthCheck
                        ? messages.securityHealthTitle
                        : messages.update2FATitle,
                    )}
                  </TextTitle1>
                  <TextBody color="foregroundMuted">
                    {isHealthCheck
                      ? formatMessage(messages.securityHealthSubtitle)
                      : formatMessage(messages.update2FASubtitle, {
                          time: (
                            <TextHeadline color="primary">
                              {formatMessage(messages.twentyFourHourAccess)}
                            </TextHeadline>
                          ),
                        })}
                  </TextBody>
                </VStack>
                <ProfileInfoCell
                  option={phone ?? ''}
                  description={formatMessage(
                    messages.phoneNumberOptionDescription,
                  )}
                  onClick={handlePhoneRedirect}
                  id="phone"
                  label={
                    factor === 'SMS' && (
                      <TextLabel2 color="negative">
                        {formatMessage(messages.required)}
                      </TextLabel2>
                    )
                  }
                />
                <ProfileInfoCell
                  option={email ?? ''}
                  description={formatMessage(messages.emailOptionDescription)}
                  onClick={handleEmailRedirect}
                  id="email"
                  label={
                    factor === 'EMAIL' && (
                      <TextLabel2 color="negative">
                        {formatMessage(messages.required)}
                      </TextLabel2>
                    )
                  }
                />
                {getTwoFactorOption(
                  userProperties?.secondFactor?.twoFactorMethod ?? null,
                )}
                {getWarningBox(
                  userProperties?.secondFactor?.twoFactorMethod ?? null,
                )}
              </VStack>
              {isHealthCheck && (
                <Box borderedTop>
                  <Button
                    variant="secondary"
                    testID="confirm-button"
                    spacingVertical={2}
                    spacingHorizontal={3}
                    onPress={handleClose}
                    block
                  >
                    {formatMessage(messages.confirm)}
                  </Button>
                </Box>
              )}
            </VStack>
          </ScrollView>
        </Modal>
      ),
      [
        email,
        factor,
        formatMessage,
        getTwoFactorOption,
        getWarningBox,
        handleClose,
        handleEmailRedirect,
        handlePhoneRedirect,
        isHealthCheck,
        phone,
        shouldDisplayModal,
        userProperties?.secondFactor?.twoFactorMethod,
      ],
    );

    return shouldDisplayModal ? <UpdateInformationModal /> : null;
  },
);

import { memo, useCallback, useState } from 'react';
import { GestureResponderEvent } from 'react-native';
import { SpacingScale } from '@cbhq/cds-common';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system/Pressable';
import {
  TextBody,
  TextHeadline,
  TextLabel2,
} from '@cbhq/cds-mobile/typography';
import { ActionType, ComponentType, logEvent } from '@cbhq/client-analytics';
import { useIntl } from '@cbhq/i18n';

import { PaymentMethodTypeIcon } from '@app/components/PaymentMethod/PaymentMethodIcon';
import { useCurrencyFormatter } from '@app/hooks/formatters/useCurrencyFormatter';
import { PaymentMethodDetailsTray } from '@app/screens/AddPaymentMethod/components/PaymentMethodDetails/PaymentMethodDetailsTray';

import { AvailablePaymentMethodCellContentProps } from '../../AvailablePaymentMethodCellContent';

import { messages } from './messages';

export const TransactionSpeed = memo(
  ({
    buyTime,
    offsetTop = 0,
  }: {
    buyTime?: string;
    offsetTop?: SpacingScale;
  }) => {
    const isInstant = buyTime?.toLowerCase().includes('instant');
    const { formatMessage } = useIntl();
    return isInstant ? (
      <HStack alignItems="center" offsetTop={offsetTop}>
        <Icon size="xs" name="lightningBolt" color="positive" />
        <TextBody color="positive" spacingStart={1}>
          {formatMessage(messages.instant)}
        </TextBody>
      </HStack>
    ) : (
      <HStack alignItems="center" offsetTop={offsetTop}>
        <TextBody color="foregroundMuted">{buyTime}</TextBody>
      </HStack>
    );
  },
);

export const AvailablePaymentMethodCellContentV2 = memo(
  ({
    title,
    description,
    paymentMethodType,
    buyTime,
    transactionLimits,
    supports,
    transactionFees,
    transferType = 'buys',
  }: AvailablePaymentMethodCellContentProps) => {
    const { formatMessage } = useIntl();

    const fees = transactionFees || formatMessage(messages.feeApply);
    let paymentMethodLimit = formatMessage(messages.highLimits);
    const formatCurrency = useCurrencyFormatter();
    const [showDetailsTray, setShowDetailsTray] = useState<boolean>(false);

    const getLimitUnit = useCallback(
      (periodInDays?: string) => {
        if (!periodInDays) return '';

        switch (periodInDays) {
          case '0':
            return formatMessage(messages.transaction);
          case '1':
            return formatMessage(messages.day);
          case '7':
            return formatMessage(messages.week);
          case '365':
            return formatMessage(messages.year);
          default:
            return `${periodInDays} ${formatMessage(messages.year)}`;
        }
      },
      [formatMessage],
    );

    const getLimitLabelForTransferType = useCallback(() => {
      switch (transferType) {
        case 'buys':
          return formatMessage(messages.buy);
        case 'deposits':
          return formatMessage(messages.deposit);
        case 'withdrawals':
          return formatMessage(messages.withdrawal);
        case 'sells':
          return formatMessage(messages.sell);
        default:
          return '';
      }
    }, [formatMessage, transferType]);

    if (transactionLimits) {
      const limitUnit = getLimitUnit(transactionLimits?.periodInDays);
      const formattedCurrency = formatCurrency({
        amount: transactionLimits?.totalAvailableLimit.value,
        currency: {
          code: transactionLimits?.totalAvailableLimit.currency,
          type: 'fiat',
        },
        minimumFractionDigits: 0,
        isSensitive: false,
      });

      paymentMethodLimit = `${getLimitLabelForTransferType()} ${formattedCurrency}/${limitUnit}`;
    }

    const infoIconClickHandler = useCallback(
      (e: GestureResponderEvent) => {
        e?.preventDefault();
        e?.stopPropagation();
        logEvent('payment_method_info_icon_click', {
          componentType: ComponentType.icon,
          action: ActionType.click,
          paymentMethodType: paymentMethodType ?? '',
        });
        setShowDetailsTray(true);
