import { FuturesAvailableBalanceRowFragment$key } from './__generated__/FuturesAvailableBalanceRowFragment.graphql';

const i18nKey = 'FuturesAvailableBalanceRow';

const messages = defineMessages({
  available: {
    id: `${i18nKey}.available`,
    defaultMessage: 'AVAILABLE',
    description: 'Available label for resource info',
  },
  position: {
    id: `${i18nKey}.position`,
