    id: `${i18nKey}.accessibilityHint`,
    defaultMessage: 'Opens a tray with additional information',
    description: 'Accessibility hint for available balance',
  },
});

type FuturesAvailableBalanceRowProps = {
  queryRef: FuturesAvailableBalanceRowFragment$key;
  productId: string;
};

function FuturesAvailableBalanceRowContent({
  queryRef,
  productId,
}: FuturesAvailableBalanceRowProps) {
  const balanceSummaryStream = useStreamBalanceSummary({});
  const formatCurrency = useCurrencyFormatter();
  const nativeCurrency = useNativeCurrency();
  const { formatMessage } = useIntl();
  const { showBalanceSummaryEntryPoint, onPressBalanceSummaryEntryPoint } =
    useBalanceSummaryEntryPoint({
      entryPoint: 'futures_available_margin',
    });

  const [
    isBalanceErrorTrayVisible,
    {
      toggleOn: toggleBalanceErrorTrayOn,
      toggleOff: toggleBalanceErrorTrayOff,
    },
  ] = useToggler();
  const query = useFragment(
    graphql`
      fragment FuturesAvailableBalanceRowFragment on Query {
        ...useFuturesPositionsFragment
      }
    `,
    queryRef,
  );

  const positions = useFuturesPositions(query);

  const availableFuturesBalance = useMemo(() => {
    if (!balanceSummaryStream?.data?.futuresBuyingPower) return '--';
    return formatCurrency({
      currency: {
        type: 'fiat',
        code: nativeCurrency,
        exponent: 2,
      },
      amount: balanceSummaryStream.data.futuresBuyingPower,
      isSensitive: true,
    });
  }, [balanceSummaryStream, formatCurrency, nativeCurrency]);

  const handleBalanceQuestionMarkPress = useCallback(() => {
    if (showBalanceSummaryEntryPoint) {
      onPressBalanceSummaryEntryPoint();
    }
  }, [onPressBalanceSummaryEntryPoint, showBalanceSummaryEntryPoint]);

  const contracts = useMemo(() => {
    const position = positions.find((p) => p?.productId === productId);

    if (!position) return '';

    if (!position.amount) return '--';

    const contractAmount = position.amount || 0;

    const formattedContract = formatMessage(messages.contracts, {
      num: contractAmount,
    });

    return position.side === 'SHORT'
      ? `${formatMessage(messages.short)} ${formattedContract}`
      : `${formatMessage(messages.long)} ${formattedContract}`;
  }, [formatMessage, positions, productId]);

  const hasAccountError =
    availableFuturesBalance === '--' || contracts === '--';

  return (
    <HStack justifyContent="center" flexWrap="wrap">
      <AvailableResourceInfo
        title={formatMessage(messages.available)}
        value={availableFuturesBalance}
        valueTestId="available-futures-balance"
        startElement={
          hasAccountError ? (
            <PressableOpacity
              testID="balance-row-warning-icon-button"
              accessibilityRole="button"
              accessibilityLabel={formatMessage(messages.accessibilityLabel)}
              accessibilityHint={formatMessage(messages.accessibilityHint)}
              hitSlop={16}
              onPress={toggleBalanceErrorTrayOn}
            >
              <Icon
                testID="balance-row-warning-icon"
                color="warning"
                name="warning"
                size="m"
              />
            </PressableOpacity>
          ) : null
        }
        endElement={
          <Pressable
            accessibilityRole="button"
            onPress={handleBalanceQuestionMarkPress}
            background="transparent"
            noScaleOnPress
          >
            <Icon name="questionMark" size="s" color="foreground" />
          </Pressable>
        }
      />
      {contracts && (
        <AvailableResourceInfo
          title={formatMessage(messages.position)}
          value={contracts}
          valueTestId="futures-contracts"
        />
      )}

      {isBalanceErrorTrayVisible && (
        <BalanceErrorTray onDismiss={toggleBalanceErrorTrayOff} />
      )}
    </HStack>
  );
}

