  },
});

type PerpetualsPositionProps = {
  position: PerpetualsPositionData;
  onPress?: () => void;
};

export function PerpetualsPosition({
  position,
  onPress,
}: PerpetualsPositionProps) {
  const {
    uuid,
    imageUrl,
    name,
    totalBalance,
    marginType,
    aggregatedPnlFiat,
    leverage,
    side,
  } = position;
  const { formatMessage } = useIntl();

  const title = useMemo(() => {
    return (
      <HStack gap={0.5} spacingTop={0.5} alignItems="center">
