import { memo, useCallback, useEffect, useState } from 'react';
import { Collapsible } from '@cbhq/cds-mobile/collapsible/Collapsible';
import { Spacer } from '@cbhq/cds-mobile/layout';
import { HStack } from '@cbhq/cds-mobile/layout/HStack';
import { VStack } from '@cbhq/cds-mobile/layout/VStack';
import { TextTitle3 } from '@cbhq/cds-mobile/typography';

import { IconButton } from '@components/interactables/IconButton';

import { ADV_PORTFOLIO_GUTTER } from '../utils/constants';

type Props = {
  testID?: string;
  label: string;
  /**
   * custom header component besides label
   */
  header?: React.ReactNode;
  /**
   * components on the left of collapsible icon
   */
  accessory?: React.ReactNode;
  borderedTop?: boolean;
};

type CollapsibleSectionProps = Props & {
  children: React.ReactNode;
  defaultCollapsed?: boolean;
  /**
   * if defined, this component will replace accessory when section is collapsed
   */
  collapsedAccessory?: React.ReactNode;
  onToggle?: (collapsed: boolean) => void;
};

export default memo(
  ({
    testID = 'collapsible-section',
    label,
    header,
    children,
    defaultCollapsed = false,
    accessory,
    collapsedAccessory,
    onToggle,
    borderedTop = true,
  }: CollapsibleSectionProps) => {
    const [collapsed, setCollapsed] = useState(defaultCollapsed);

    // NOTE(serra.park) This useEffect triggers the component to re-render if the defaultCollapsed prop has changed, resulting in the correct behavior
    useEffect(() => {
      setCollapsed(defaultCollapsed);
    }, [defaultCollapsed]);

    const handleToggle = useCallback(() => {
      onToggle?.(collapsed);
      setCollapsed(!collapsed);
    }, [collapsed, onToggle]);

    return (
      <VStack testID={testID} borderedTop={borderedTop}>
        <HStack
          alignItems="center"
          justifyContent="space-between"
          spacingHorizontal={ADV_PORTFOLIO_GUTTER}
          spacingVertical={1.5}
        >
          <HStack alignItems="center" gap={1}>
            <TextTitle3 color="foregroundMuted">{label}</TextTitle3>
            {header}
          </HStack>
          <HStack alignItems="center" gap={1}>
            {collapsed && !!collapsedAccessory ? collapsedAccessory : accessory}
            <IconButton
              testID="collapsible-toggle"
              name={collapsed ? 'caretDown' : 'caretUp'}
              onPress={handleToggle}
              compact
            />
          </HStack>
        </HStack>
        <Collapsible collapsed={collapsed}>
          <VStack minHeight="fit-content">
            {children}
            <Spacer vertical={1.5} />
          </VStack>
        </Collapsible>
      </VStack>
    );
  },
);

