const i18nKey = 'AdvPortfolioCryptoTable';
const messages = defineMessages({
  header: {
    id: `${i18nKey}.header`,
    defaultMessage: 'Crypto',
    description: 'section header for user crypto table',
  },
  noTradeCardTitle: {
    id: `${i18nKey}.noTradeCardTitle`,
    defaultMessage: 'Get started with crypto',
    description:
      'title of feature entry card when user does not have any crypto',
  },
  emptyCardTitle: {
