      'description of feature entry card when user does not have any crypto',
  },
  featureEntryButtonLable: {
    id: `${i18nKey}.featureEntryButtonLable`,
    defaultMessage: 'Start trading',
    description:
      'CTA button label of feature entry card when user does not have any crypto',
  },
});

const { MonitoringBoundary } = createMonitoringBoundary({
  boundaryName: 'portfolio-user-crypto-table',
  boundaryOwner: 'advanced-trade',
});

type Props = {
  queryRef: UserCryptoTableFragment$key;
};

function UserCryptoTableContent({ queryRef }: Props) {
  const { formatMessage } = useIntl();
  const formatter = useCurrencyFormatter();

  const hasMultiPortfolioReadOnlyExperiment =
    useHasMultiPortfolioReadOnlyExperiment();

  const query = useFragment(
    graphql`
      fragment UserCryptoTableFragment on Query {
        ...useUserCryptoTableDataFragment
        ...useUserCryptoTableDataV2Fragment
        ...useUserPortfolioCryptoBalanceFragment
        viewer @required(action: THROW) {
          ...useUserDefiTotalBalanceFragment
          ...useUserNonCashEquivalentBalanceFragment
          balanceData {
            cryptoBalanceInFiat(quoteCurrency: $nativeCurrency) {
              value
              currency
            }
          }
          accountHistory {
            allEntries(
              first: 1
              categories: [SELL, BUY, CONVERT, ADVANCED_TRADE]
            ) {
              edges {
                __typename
              }
            }
          }
        }
      }
    `,
    queryRef,
  );
  const { viewer } = query;
  const { balanceInFiat: defiTotalBalance } = useUserDefiTotalBalance({
    viewerRef: viewer,
  });

  // trade history include simple trade buy/sell/convert and advanced trade
  const hasTradeHistory =
    (viewer.accountHistory?.allEntries?.edges ?? []).length > 0;

  const cryptoBalanceInFiat = viewer.balanceData?.cryptoBalanceInFiat;

  const isInUK = useCachedCountryCode() === 'GB';

  const showAdvPortfolioErrorBanner = useShowAdvPortfolioErrorBanner();

  //TODO we could manually add USDC balance to nonCashEquivalentBalance for UK users, so that we can support live balance
  const {
    formattedBalanceInFiat: nonCashEquivalentBalance,
    hasBalanceError: hasNonCashEqBalanceError,
  } = useUserNonCashEquivalentBalance({
    viewerRef: viewer,
    supportPartialBalance: !showAdvPortfolioErrorBanner,
  });

  const {
    formattedCryptoBalance: portfolioCryptoBalance,
    hasBalanceError: hasPortfolioCryptoBalanceError,
  } = useUserPortfolioCryptoBalance({
    queryRef: query,
  });

  const data = useUserCryptoTableData(query);
  const dataV2 = useUserCryptoTableDataV2(query);
  const tableData = hasMultiPortfolioReadOnlyExperiment ? dataV2 : data;

  const hasBalanceError = useMemo(() => {
    if (isInUK) {
      return cryptoBalanceInFiat === null || cryptoBalanceInFiat === undefined;
    }
    return hasMultiPortfolioReadOnlyExperiment
      ? hasPortfolioCryptoBalanceError
      : hasNonCashEqBalanceError;
  }, [
    cryptoBalanceInFiat,
    hasMultiPortfolioReadOnlyExperiment,
    hasNonCashEqBalanceError,
    hasPortfolioCryptoBalanceError,
    isInUK,
  ]);

  const showBalanceBanner =
    (hasBalanceError || tableData === null) && showAdvPortfolioErrorBanner;

  const header = useMemo(() => {
    // for UK users only, crypto include USDC balance
    const formattedCryptoBalance = cryptoBalanceInFiat?.value
      ? formatter({
          isSensitive: true,
          amount:
            parseFloat(cryptoBalanceInFiat?.value ?? '0') +
            (defiTotalBalance ?? 0),
          currency: {
            type: 'fiat',
            code: cryptoBalanceInFiat?.currency ?? 'GBP',
          },
        })
      : DEFAULT_FORMATTED_FALLBACK;

    let displayBalance;

    if (isInUK) {
      displayBalance = formattedCryptoBalance;
    } else {
      displayBalance = hasMultiPortfolioReadOnlyExperiment
        ? portfolioCryptoBalance
        : nonCashEquivalentBalance;
    }
    return <TextTitle4>{displayBalance}</TextTitle4>;
  }, [
    cryptoBalanceInFiat?.value,
    cryptoBalanceInFiat?.currency,
    formatter,
    defiTotalBalance,
    isInUK,
    hasMultiPortfolioReadOnlyExperiment,
    portfolioCryptoBalance,
    nonCashEquivalentBalance,
  ]);

  const content = useMemo(() => {
    if (tableData?.length === 0 && hasTradeHistory) {
      return <RATFeatureEntryCard testID="user-crypto-table" type="empty" />;
    }
    if (tableData?.length === 0 && !hasTradeHistory) {
      return <RATFeatureEntryCard testID="user-crypto-table" type="no-trade" />;
    }
    return (
      <>
        {tableData?.map((node) => (
          <CryptoListCell key={node.uuid} data={node} />
        ))}
        <FinPromPerformanceDisclaimer />
      </>
    );
  }, [tableData, hasTradeHistory]);

  useEffect(() => {
    logAdvPortfolioTableViewedEvent({
      tableType: 'crypto',
    });
  }, []);

  const handleCollapse = useCallback((collapsed: boolean) => {
    logAdvPortfolioTableCollapseButtonClickedEvent({
      tableType: 'crypto',
      prevCollapsedState: collapsed,
    });
  }, []);

  return (
    <PortfolioTable
      testID="user-crypto-table"
      label={formatMessage(messages.header)}
      header={header}
      defaultCollapsed={!showBalanceBanner && tableData?.length === 0}
      handleCollapse={handleCollapse}
      showErrorState={showBalanceBanner}
      errorType="balance"
      component="CryptoTable"
    >
      {content}
    </PortfolioTable>
  );
}

