import { memo, useCallback, useEffect, useMemo } from 'react';
import PortfolioTable from '@advancedTrade/Portfolio/components/PortfolioTable/PortfolioTable';
import TableFallback from '@advancedTrade/Portfolio/components/TableFallback';
import useShowAdvPortfolioErrorBanner from '@advancedTrade/Portfolio/hooks/useShowAdvPortfolioErrorBanner';
import {
  logAdvPortfolioTableCollapseButtonClickedEvent,
  logAdvPortfolioTableViewedEvent,
  logAdvPortfolioUSDCConvertButtonClickedEvent,
} from '@advancedTrade/Portfolio/utils/logAdvancedPortfolioAnalytics';
import { TextTitle4 } from '@cbhq/cds-mobile/typography';
import { graphql, useFragment } from '@cbhq/data-layer';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { IconButton } from '@components/interactables/IconButton';
import { DEFAULT_FORMATTED_FALLBACK } from '@hooks/useCurrencyFormatter';
import { NetworkBoundary } from '@app/components/NetworkBoundary';
import { useDappWallet } from '@app/contexts/Defi/DefiProvider';
import { useAssetTotalBalance } from '@app/hooks/balance/useAssetTotalBalance/useAssetTotalBalance';
import usePortfolioCefiCashBalance from '@app/hooks/balance/usePortfolioCefiCashBalance/usePortfolioCefiCashBalance';
import { useUserCashEquivalentBalance } from '@app/hooks/balance/useUserCashEquivalentBalance/useUserCashEquivalentBalance';
import { useCurrencyFormatter } from '@app/hooks/formatters/useCurrencyFormatter';
import { useCachedCountryCode } from '@app/hooks/useCachedCountryCode';
import { useHasMultiPortfolioReadOnlyExperiment } from '@app/hooks/useHasMultiPortfolioReadOnlyExperiment/useHasMultiPortfolioReadOnlyExperiment';
import { useNativeCurrency } from '@app/hooks/useNativeCurrency';
import { useDappBalances } from '@app/screens/Defi/hooks/useDappBalances';
import { getTotalFiatAmount } from '@app/screens/Defi/utils';
import { useHasUsdcCashTransferExperiment } from '@app/screens/SimpleTrade/hooks/useHasUsdcCashTransferExperiment';
import { isUsdcAsset, USDC_ASSET_ID } from '@app/screens/Stablecoin/constants';
import { useRouteToCashConvert } from '@app/screens/Stablecoin/hooks/useRouteToCashConvert';
import { createMonitoringBoundary } from '@app/utils/errors/boundary';

