import { useDefaultCashTableData } from '../hooks/useDefaultCashTableData';
import { useDefaultCashTableDataV2 } from '../hooks/useDefaultCashTableDataV2';

import { DefaultCashTableFragment$key } from './__generated__/DefaultCashTableFragment.graphql';

const i18nKey = 'AdvPortfolioDefaultCashTable';
const messages = defineMessages({
  header: {
    id: `${i18nKey}.header`,
    defaultMessage: 'Cash',
    description: 'section header for default cash table',
  },
});

const { MonitoringBoundary } = createMonitoringBoundary({
  boundaryName: 'portfolio-default-cash-table',
  boundaryOwner: 'advanced-trade',
});

type Props = {
  queryRef: DefaultCashTableFragment$key;
};

function DefaultCashTableContent({ queryRef }: Props) {
  const { formatMessage } = useIntl();
  const hasUsdcCashTransferExperiment = useHasUsdcCashTransferExperiment();
  const hasMultiPortfolioReadOnlyExperiment =
    useHasMultiPortfolioReadOnlyExperiment();
  const nativeCurrency = useNativeCurrency();

  const query = useFragment(
    graphql`
      fragment DefaultCashTableFragment on Query {
        ...useDefaultCashTableDataFragment
        ...useDefaultCashTableDataV2Fragment
        ...useUserCashEquivalentBalanceFragment @arguments(platform: $platform)
        viewer {
          ...useDappBalancesFragment
          ...useAssetTotalBalanceFragment
            @arguments(assetId: $usdcAssetId, platform: $platform)
          portfolioByUuid(uuid: $portfolioUuid) {
            ...usePortfolioCefiCashBalanceFragment
          }
        }
      }
    `,
    queryRef,
  );

  const isInUK = useCachedCountryCode() === 'GB';
  const formatter = useCurrencyFormatter();

  const showAdvPortfolioErrorBanner = useShowAdvPortfolioErrorBanner();

  const {
    formattedBalanceInFiat: cashEquivalentBalance,
    balanceInFiat: cashEquivalentBalanceNum,
    hasBalanceError: hasCashEqBalanceError,
  } = useUserCashEquivalentBalance({
    queryRef: query,
    supportPartialBalance: !showAdvPortfolioErrorBanner,
  });

  const {
    rawCashBalance: portfolioCashBalance,
    hasBalanceError: hasPortfolioBalanceError,
  } = usePortfolioCefiCashBalance({
    portfolioRef: query.viewer?.portfolioByUuid,
  });

  const { walletAddress, walletAddressHasNetworkError } = useDappWallet();

  // Get dapp usdc balance
  const [dappBalances, defiErrors] = useDappBalances(query.viewer ?? null);
  const dappUSDCBalances = dappBalances?.filter((asset) =>
    isUsdcAsset(asset?.asset?.viewerAsset?.retailAsset?.uuid),
  );
  const hasDefiError =
    (!!walletAddress || walletAddressHasNetworkError) &&
    (defiErrors.length > 0 || dappBalances === undefined);
  const dappUSDCTotalBalance =
    dappUSDCBalances && getTotalFiatAmount(dappUSDCBalances);

  let totalPortfolioCashBalance =
    hasPortfolioBalanceError || hasDefiError ? undefined : portfolioCashBalance;

  if (!isInUK && totalPortfolioCashBalance && dappUSDCTotalBalance) {
    totalPortfolioCashBalance += Number(dappUSDCTotalBalance); // Include dapp USDC as cash for non-UK users
  }

  const {
    totalBalanceInFiat: usdcTotalBalanceNum,
    hasBalanceError: hasUsdcBalanceError,
  } = useAssetTotalBalance({ viewerRef: query.viewer });

  const fiatBalance =
    cashEquivalentBalanceNum === undefined || usdcTotalBalanceNum === undefined
      ? DEFAULT_FORMATTED_FALLBACK
      : formatter({
          isSensitive: true,
          amount: cashEquivalentBalanceNum - usdcTotalBalanceNum,
          currency: { type: 'fiat', code: nativeCurrency },
        });

  const balance = useMemo(() => {
    if (hasMultiPortfolioReadOnlyExperiment) {
      return totalPortfolioCashBalance === undefined
        ? DEFAULT_FORMATTED_FALLBACK
        : formatter({
            isSensitive: true,
            amount: totalPortfolioCashBalance,
            currency: { type: 'fiat', code: nativeCurrency },
          });
    }
    return isInUK ? fiatBalance : cashEquivalentBalance;
  }, [
    cashEquivalentBalance,
    fiatBalance,
    formatter,
    hasMultiPortfolioReadOnlyExperiment,
    isInUK,
    nativeCurrency,
    totalPortfolioCashBalance,
  ]);

  const data = useDefaultCashTableData(query);
  const dataV2 = useDefaultCashTableDataV2(query);
  const cashTableData = hasMultiPortfolioReadOnlyExperiment ? dataV2 : data;

  const hasBalanceError = useMemo(() => {
    if (hasMultiPortfolioReadOnlyExperiment) {
      return hasPortfolioBalanceError || hasDefiError;
    }
    return isInUK
      ? hasCashEqBalanceError || hasUsdcBalanceError
      : hasCashEqBalanceError;
  }, [
    hasCashEqBalanceError,
    hasDefiError,
    hasMultiPortfolioReadOnlyExperiment,
    hasPortfolioBalanceError,
    hasUsdcBalanceError,
    isInUK,
  ]);
  const showBalanceBanner =
    (hasBalanceError || !cashTableData) && showAdvPortfolioErrorBanner;

  const routeToCashConvert = useRouteToCashConvert({
    paymentMethodCurrency: 'USD', // only supporting USD for now
    sourceAssetId: USDC_ASSET_ID,
    tradeType: 'buy',
  });
  const handleUSDCConvert = useCallback(() => {
    routeToCashConvert();
    logAdvPortfolioUSDCConvertButtonClickedEvent();
  }, [routeToCashConvert]);

  const header = useMemo(() => {
    return <TextTitle4>{balance}</TextTitle4>;
  }, [balance]);

  const USDCConvertButton = useMemo(() => {
    if (!hasUsdcCashTransferExperiment) return null;
    return (
      <IconButton
        testID="usdc-convert-button"
        aria-label="usdc-convert-button"
        onPress={handleUSDCConvert}
        name="convert"
        variant="secondary"
      />
    );
  }, [handleUSDCConvert, hasUsdcCashTransferExperiment]);

  useEffect(() => {
    logAdvPortfolioTableViewedEvent({
      tableType: 'cash',
    });
  }, []);

  const handleCollapse = useCallback((collapsed: boolean) => {
    logAdvPortfolioTableCollapseButtonClickedEvent({
      tableType: 'cash',
      prevCollapsedState: collapsed,
    });
  }, []);

  return (
    <PortfolioTable
      showErrorState={showBalanceBanner}
      testID="default-cash-table"
      label={formatMessage(messages.header)}
      header={header}
      accessory={USDCConvertButton}
      defaultCollapsed={!showBalanceBanner && cashTableData?.length === 0}
      handleCollapse={handleCollapse}
      errorType="balance"
      component="CashTable"
    >
      {cashTableData?.map((node) => (
        <CashTableListCell key={node.uuid} node={node} />
      ))}
    </PortfolioTable>
  );
}
export default memo(function DefaultCashTable(props: Props) {
