type Props = {
  queryRef: PortfolioSelectorOrderFormFragment$key;
  selectedPortfolioUuid: string;
  handleUpdatePortfolioUuid: (portfolioUuid: string) => void;
} & Pick<
  PortfolioSelectorCellProps,
  'quoteCurrencyId' | 'baseCurrencyId' | 'productId'
>;

const i18nKey = 'PortfolioSelector';
const messages = defineMessages({
  done: {
    id: `${i18nKey}.done`,
    defaultMessage: 'Done',
    description: 'Button text for closing the drawer',
  },
  selectAPortfolio: {
    id: `${i18nKey}.selectAPortfolio`,
    defaultMessage: 'Select a portfolio',
    description: 'Drawer header title for selecting a portfolio',
  },
});

function PortfolioSelectorContent({
  queryRef,
  selectedPortfolioUuid: selectedPortfolioUuidFromProps,
  handleUpdatePortfolioUuid,
  ...rest
}: Props) {
  const { formatMessage } = useIntl();

  const [visible, { toggleOn, toggleOff }] = useToggler(false);
  const [selectedPortfolioUuid, setSelectedPortfolioUuid] = useState(
    selectedPortfolioUuidFromProps,
  );
  const onSelectPortfolio = useCallback((uuid: string | undefined) => {
    if (uuid) {
      setSelectedPortfolioUuid(uuid);
    }
  }, []);

  const query = useFragment(
    graphql`
      fragment PortfolioSelectorOrderFormFragment on Query {
        viewer @skip(if: $skipMultiPortfolio) {
          portfolioByUuid(uuid: $portfolioUuid) {
            name
          }
          portfolios {
            uuid
            ...PortfolioSelectorCellOrderFormFragment
          }
          defaultPortfolio {
            name
          }
        }
      }
    `,
    queryRef,
  );

  const portfolios = query?.viewer?.portfolios;
  const hasPortfolios = (portfolios?.length ?? 0) > 0;

  const handleDrawerClose = useCallback(() => {
    toggleOff();
    handleUpdatePortfolioUuid(selectedPortfolioUuid);
  }, [handleUpdatePortfolioUuid, selectedPortfolioUuid, toggleOff]);

  if (!portfolios) {
    // TODO(spark): error degradation
    return null;
  }

  const portfolioName =
    query?.viewer?.portfolioByUuid?.name ??
    query?.viewer?.defaultPortfolio?.name;

  return (
    <>
      <Pressable
        accessibilityRole="button"
        onPress={hasPortfolios ? toggleOn : undefined}
        background="secondary"
        borderRadius="roundedSmall"
        style={{
          paddingHorizontal: 16,
          paddingTop: 8,
        }}
        testID="portfolio-selector-pressable"
        noScaleOnPress={!hasPortfolios}
      >
        <ListCell
          title={<TextBody>{portfolioName}</TextBody>}
          media={
            <CircleIcon iconName="chartPieCircle" iconSize="s" spacing={0.5} />
          }
          priority="end"
          disableMultilineTitle
          accessory={hasPortfolios ? 'arrow' : undefined}
          compact
        />
      </Pressable>
      {visible && (
        <Drawer
          pin="bottom"
          onCloseComplete={handleDrawerClose}
          disableCapturePanGestureToDismiss
          testID="portfolio-selector-drawer"
        >
          {({ handleClose }) => (
            <VStack>
              <Box spacing={3}>
                <TextTitle3>
                  {formatMessage(messages.selectAPortfolio)}
                </TextTitle3>
              </Box>
              <VStack maxHeight={500}>
                <ScrollView>
                  <VStack>
                    {removeFalsyValues(portfolios ?? []).map((portfolio) => {
                      const selected = selectedPortfolioUuid === portfolio.uuid;
                      return (
                        <PortfolioSelectorCell
                          selected={selected}
                          onPress={() =>
                            onSelectPortfolio(portfolio.uuid ?? undefined)
                          }
                          portfolioRef={portfolio}
                          key={`portfolio-selector-cell-${portfolio.uuid}`}
                          {...rest}
                        />
                      );
                    })}
