                    testID="portfolio-selector-done-button"
                  >
                    {formatMessage(messages.done)}
                  </Button>
                </StickyFooter>
              </TrayStickyFooter>
            </VStack>
          )}
        </Drawer>
      )}
    </>
  );
}

