type PortfolioSelectorCellProps = {
  selected: boolean;
  onPress: () => void;
  portfolioRef: PortfolioSelectorCellOrderFormFragment$key;
  quoteCurrencyId: string;
  baseCurrencyId: string;
  productId: string;
};

function PortfolioSelectorCell({
  selected,
  onPress,
  portfolioRef,
  quoteCurrencyId,
  baseCurrencyId,
  productId,
}: PortfolioSelectorCellProps) {
  const { hasUSDCAlias } = useUSDCAlias(productId);
  const formatAmount = useCurrencyFormatter();

  const [portfolio, getError] = useFragmentWithError(
    graphql`
      fragment PortfolioSelectorCellOrderFormFragment on Portfolio {
        name
        uuid
        quotePosition: spotPositions(assetSymbol: $quoteCurrencyId, first: 1) {
          edges {
            node {
              availableToTradeCrypto {
                amount
                currency
              }
              asset {
                __typename
                ... on ViewerAsset {
                  asset {
                    exponent
                  }
                }
              }
            }
          }
        }
        usdcPosition: spotPositions(assetSymbol: "USDC", first: 1)
          @skip(if: $skipUsdc) {
          edges {
            node {
              availableToTradeCrypto {
                amount
                currency
              }
              asset {
                __typename
                ... on ViewerAsset {
                  asset {
                    exponent
                  }
                }
              }
            }
          }
        }
        basePosition: spotPositions(assetSymbol: $baseCurrencyId, first: 1) {
          edges {
            node {
              availableToTradeCrypto {
                amount
                currency
              }
              asset {
                __typename
                ... on ViewerAsset {
                  asset {
                    exponent
                  }
                }
              }
            }
          }
        }
      }
    `,
    portfolioRef,
  );

  const quotePosition = useMemo(() => {
    const node = portfolio?.quotePosition?.edges?.[0]?.node;
    let quoteAvailableToTrade = node?.availableToTradeCrypto;

    if (!quoteAvailableToTrade) {
      const quoteError = getError(
        'quotePosition.edges.node.availableToTradeCrypto',
      );
      if (quoteError?.code !== 'UNAVAILABLE') {
        quoteAvailableToTrade = {
          amount: '0',
          currency: quoteCurrencyId,
        };
      } else {
        quoteAvailableToTrade = {
          amount: null,
          currency: quoteCurrencyId,
        };
      }
    }

    const exponent =
      node?.asset?.__typename === 'ViewerAsset'
        ? node?.asset?.asset?.exponent
        : 2;

    return {
      amount: formatAmount({
        amount: {
          amount: quoteAvailableToTrade?.amount ?? '',
          currency: quoteAvailableToTrade?.currency ?? '',
        },
        isFiat: node?.asset?.__typename !== 'ViewerAsset',
        exponent,
        withCurrency: false,
      }),
      amountWithSymbol: formatAmount({
        amount: {
          amount: quoteAvailableToTrade?.amount ?? '',
          currency: quoteAvailableToTrade?.currency ?? '',
        },
        isFiat: node?.asset?.__typename !== 'ViewerAsset',
        exponent,
        withCurrency: true,
      }),
      currency: quoteAvailableToTrade?.currency,
    };
  }, [
    formatAmount,
    getError,
    portfolio?.quotePosition?.edges,
    quoteCurrencyId,
  ]);

  const positions = useMemo(() => {
    const usdcNode = portfolio?.usdcPosition?.edges?.[0]?.node;
    const baseNode = portfolio?.basePosition?.edges?.[0]?.node;
    let usdcAvailableToTrade = usdcNode?.availableToTradeCrypto;
    let baseAvailableToTrade = baseNode?.availableToTradeCrypto;

    if (!usdcAvailableToTrade) {
      const usdcError = getError(
        'usdcPosition.edges.node.availableToTradeCrypto',
      );
      if (usdcError?.code !== 'UNAVAILABLE' && hasUSDCAlias) {
        usdcAvailableToTrade = {
          amount: '0',
          currency: 'USDC',
        };
      } else if (usdcError?.code === 'UNAVAILABLE' && hasUSDCAlias) {
        usdcAvailableToTrade = {
          amount: null,
          currency: 'USDC',
        };
      }
    }

    const usdcPosition = usdcAvailableToTrade
      ? {
          key: 'usdcPosition',
          amount: formatAmount({
            amount: {
              amount: usdcAvailableToTrade?.amount ?? '',
              currency: usdcAvailableToTrade?.currency ?? '',
            },
            isFiat: false,
            exponent:
              usdcNode?.asset?.__typename === 'ViewerAsset'
                ? usdcNode?.asset?.asset?.exponent
                : 6,
            withCurrency: false,
          }),
          currency: usdcAvailableToTrade?.currency,
        }
      : null;

    if (!baseAvailableToTrade) {
      const baseError = getError(
        'basePosition.edges.node.availableToTradeCrypto',
      );
      if (baseError?.code !== 'UNAVAILABLE') {
        baseAvailableToTrade = {
          amount: '0',
          currency: baseCurrencyId,
        };
      } else {
        baseAvailableToTrade = {
          amount: null,
          currency: baseCurrencyId,
        };
      }
    }

    const basePosition = {
      key: 'basePosition',
      amount: formatAmount({
        amount: {
          amount: baseAvailableToTrade?.amount ?? '',
          currency: baseAvailableToTrade?.currency ?? '',
        },
        isFiat: baseNode?.asset?.__typename !== 'ViewerAsset',
        exponent:
          baseNode?.asset?.__typename === 'ViewerAsset'
            ? baseNode?.asset?.asset?.exponent
            : 6,
        withCurrency: false,
      }),
      currency: baseAvailableToTrade?.currency,
    };

    return removeFalsyValues([
      {
        key: 'quotePosition',
        amount: quotePosition.amount,
        currency: quotePosition.currency,
      },
      usdcPosition,
      basePosition,
    ]);
  }, [
    baseCurrencyId,
    formatAmount,
    getError,
    hasUSDCAlias,
    portfolio?.basePosition?.edges,
    portfolio?.usdcPosition?.edges,
    quotePosition,
  ]);

  const handlePress = useCallback(() => {
    onPress();
  }, [onPress]);

  return (
    <VStack>
      <ListCell
        title={portfolio.name ?? ''}
        description={
          <TextLabel1 color="foregroundMuted" tabularNumbers>
            {quotePosition.amountWithSymbol}
          </TextLabel1>
        }
        media={
          <AnimatedCaret color="foreground" rotate={selected ? 180 : 90} />
        }
        selected={selected}
        onPress={handlePress}
        priority="end"
        disableMultilineTitle
        testID={`portfolio-selector-cell-${portfolio.uuid}`}
      />
      {/* NOTE(spark): PressableOpacity enables user to scroll on these components */}
      <PressableOpacity noScaleOnPress transparentWhilePressed>
        <Collapsible
          collapsed={!selected}
          testID={`portfolio-selector-cell-collapsible-${portfolio.uuid}`}
        >
          <VStack spacingStart={9} spacingEnd={3} gap={1}>
            {positions.map((position) => {
              return (
                <HStack justifyContent="space-between" key={position.key}>
                  <TextLabel1 color="foregroundMuted">
                    {position.currency}
                  </TextLabel1>
                  <TextLabel1 color="foregroundMuted" tabularNumbers>
                    {position.amount}
                  </TextLabel1>
                </HStack>
              );
            })}
          </VStack>
        </Collapsible>
      </PressableOpacity>
    </VStack>
  );
}

