type USDCPaymentMethodSelectorProps = {
  paymentMethod: string;
  product: CoinbasePublicApiAuthedRetailBrokerageApiProduct;
  queryRef: USDCPaymentMethodSelectorFragment$key;
  orderSide: `${CoinbasePublicApiAuthedRetailBrokerageApiOrderSide}`;
} & Pick<SelectInputProps, 'onInputPress' | 'onChange'>;

export function USDCPaymentMethodSelector({
  product,
  queryRef,
  paymentMethod,
  orderSide,
  onChange,
  onInputPress,
}: USDCPaymentMethodSelectorProps) {
  const query = useFragment(
    graphql`
      fragment USDCPaymentMethodSelectorFragment on Query
      @argumentDefinitions(
        quoteAccountId: { type: "Uuid!" }
        skipUSDCFeature: { type: "Boolean!" }
      ) {
        ...useAvailableBalancePositionsFragment
          @arguments(skipUSDCFeature: $skipUSDCFeature)
        viewer @required(action: THROW) {
          usdAccount: accountByUuidV3(uuid: $quoteAccountId) {
            account {
              availableBalance {
                value
                currency
              }
            }
            status
          }
          usdcAccount: accountByUuidV3(uuid: "USDC")
            @skip(if: $skipUSDCFeature) {
            account {
              availableBalance {
                value
                currency
              }
            }
            status
          }
          usdcAsset: assetBySymbol(symbol: "USDC") @skip(if: $skipUSDCFeature) {
            asset {
              imageUrl
            }
          }
        }
      }
    `,
    queryRef,
  );
  const {
    usdAccount: actualUsdAccount,
    usdcAccount: actualUsdcAccount,
    usdcAsset,
  } = query.viewer || {};

  const hasMultiPortfolioTradeExperiment =
    useHasMultiPortfolioTradeExperiment();

  const { formatMessage } = useIntl();
  const priceFormatter = useFormatPrice();
  const { quotePrecision, baseCurrencyId, quoteCurrencyId } =
    useSpotProductInfo(product);

  const {
    quotePosition,
    usdcPosition,
    hasQuoteBalanceError,
    hasUSDCBalanceError,
    hasNoQuoteAccount,
  } = useAvailableBalancePositions({
    queryRef: query,
    baseCurrencyId,
    quoteCurrencyId,
  });

  const hasPrimaryCashExperiment = useSingleCashBalanceExperiment();

  const [
    isUsdcDefaultInfoTrayVisible,
    { toggleOn: handleOpenInfoTray, toggleOff: handleCloseInfoTray },
  ] = useToggler(false);

  const usdAccount = useSafeAccount({
    actualAccount: actualUsdAccount,
    currencyId: 'USD',
  });

  const hasAccountError = useMemo(() => {
    if (hasMultiPortfolioTradeExperiment) {
      return hasQuoteBalanceError || hasUSDCBalanceError;
    }
    if (!actualUsdAccount || !actualUsdcAccount) {
      return true;
    }

    return [actualUsdAccount?.status, actualUsdcAccount?.status].some(
      (status) => status === 'ERROR',
    );
  }, [
    actualUsdAccount,
    actualUsdcAccount,
    hasMultiPortfolioTradeExperiment,
    hasQuoteBalanceError,
    hasUSDCBalanceError,
  ]);

  const usdcAccount = useSafeAccount({
    actualAccount: actualUsdcAccount,
    currencyId: actualUsdAccount?.account?.availableBalance.currency || 'USDC',
  });

  const labelMessage = isBuySide(orderSide)
    ? messages.payWith
    : messages.addCashTo;

  const usdBalance = useMemo(
    () =>
      priceFormatter({
        value: hasMultiPortfolioTradeExperiment
          ? quotePosition?.availableBalance.value
          : usdAccount?.availableBalance.value,
        precision: quotePrecision,
        currency: 'USD',
      }),
    [
      hasMultiPortfolioTradeExperiment,
      priceFormatter,
      quotePosition?.availableBalance.value,
      quotePrecision,
      usdAccount?.availableBalance.value,
    ],
  );

  const usdcBalance = useMemo(
    () =>
      priceFormatter({
        value: hasMultiPortfolioTradeExperiment
          ? usdcPosition?.availableBalance.value
          : usdcAccount?.availableBalance.value,
        precision: quotePrecision,
        currency: 'USDC',
      }),
    [
      hasMultiPortfolioTradeExperiment,
      priceFormatter,
      quotePrecision,
      usdcAccount?.availableBalance.value,
      usdcPosition?.availableBalance.value,
    ],
  );

  const usdcIconUrl = usdcAsset?.asset?.imageUrl;

  const label = formatMessage(labelMessage);

  const hasUsdAccount = hasMultiPortfolioTradeExperiment
    ? !hasNoQuoteAccount
    : actualUsdAccount?.account;

  const options = useMemo<SelectInputProps['options']>(() => {
    const items = [
      {
        label: 'USDC',
        value: 'USDC',
        intermediary: (
          <TextBody color="foregroundMuted">{usdcBalance}</TextBody>
        ),
        media: usdcIconUrl ? (
          <CurrencyIconFromUrl size={ICON_SIZE} imageUrl={usdcIconUrl} />
        ) : (
          <USDCIconFallback />
        ),
      },
    ];

    // only adds USD option if user has a USD account
    if (hasUsdAccount) {
      items.unshift({
        label: `${formatMessage(messages.cash)} (USD)`,
        value: 'USD',
        intermediary: <TextBody color="foregroundMuted">{usdBalance}</TextBody>,
        media: <Icon size="m" name="cashUSD" color="primary" />,
      });
    }

    return items;
  }, [formatMessage, hasUsdAccount, usdBalance, usdcBalance, usdcIconUrl]);

  const labelTooltip = useMemo(
    () => (
      <>
        <Pressable
          accessibilityRole="button"
          background="transparent"
          feedback="normal"
          testID="ViewInterestEarnedDisclaimer"
          onPress={handleOpenInfoTray}
        >
          <Icon name="info" size="s" color="foregroundMuted" />
        </Pressable>
        <UsdcDefaultInfoTray
          isVisible={isUsdcDefaultInfoTrayVisible}
          onDismiss={handleCloseInfoTray}
        />
      </>
    ),
    [handleCloseInfoTray, handleOpenInfoTray, isUsdcDefaultInfoTrayVisible],
  );

  return (
    <SelectInput
      label={label}
      labelTooltip={hasPrimaryCashExperiment ? labelTooltip : undefined}
      value={paymentMethod}
      options={options}
      disabled={!hasUsdAccount}
      onChange={onChange}
      testID="paymentMethodSelector"
      onInputPress={onInputPress}
      trayBanner={
        hasAccountError ? <UsdcPaymentMethodErrorBanner /> : undefined
      }
    />
  );
}

type USDCPaymentMethodSelectorOrderFormV3Props = {
  productId: string;
  queryRef: USDCPaymentMethodSelectorOrderFormV3Fragment$key;
  baseCurrencyId: string;
  quoteCurrencyId: string;
};

// TODO: when removing this we need to lift the default payment method logic into the order form framework
function USDCPaymentMethodSelectorOrderFormV3({
  productId,
  queryRef,
  baseCurrencyId,
  quoteCurrencyId,
}: USDCPaymentMethodSelectorOrderFormV3Props) {
  const query = useFragment(
    graphql`
      fragment USDCPaymentMethodSelectorOrderFormV3Fragment on Query
      @argumentDefinitions(
        quoteAccountId: { type: "Uuid!" }
        skipUSDCFeature: { type: "Boolean!" }
      ) {
        ...USDCPaymentMethodSelectorFragment
          @arguments(
            quoteAccountId: $quoteAccountId
            skipUSDCFeature: $skipUSDCFeature
          )
        ...useAvailableBalancePositionsFragment
          @arguments(skipUSDCFeature: $skipUSDCFeature)
        viewer @required(action: THROW) {
          usdAccount: accountByUuidV3(uuid: $quoteAccountId) {
            account {
              availableBalance {
                value
              }
            }
            status
          }
          usdcAccount: accountByUuidV3(uuid: "USDC")
            @skip(if: $skipUSDCFeature) {
            account {
              availableBalance {
                value
              }
            }
            status
          }
        }
      }
    `,
    queryRef,
  );

  const { usdAccount: actualUsdAccount, usdcAccount: actualUsdcAccount } =
    query.viewer;

  const { getProduct } = useGetProducts();
  const product = getProduct(productId);
  const orderSide = useOrderSide();
  const paymentMethod = usePaymentMethod();
  const { state, setOrderForms } = useAdvancedTradeOrderFormsValues();
  const { orderType } = state;
  const hasPrimaryCashExperiment = useSingleCashBalanceExperiment();

  const hasMultiPortfolioTradeExperiment =
    useHasMultiPortfolioTradeExperiment();

  const { quotePosition, usdcPosition, hasNoQuoteAccount } =
    useAvailableBalancePositions({
      queryRef: query,
      baseCurrencyId,
      quoteCurrencyId,
    });

  const handleSelectorPress = useCallback(() => {
    trackPaymentMethodSelectorPressed(orderType, orderSide);
  }, [orderSide, orderType]);

  const handleOnChange = useCallback(
    (value: string) => {
      if (value === 'USD' || value === 'USDC') {
        setOrderForms(orderFormsStateActions.setPaymentMethod(value));

        // save method in local storage
        setStoreDataSynchronous(
          LOCAL_STORAGE_NAME,
          LOCAL_STORAGE_KEYS.USDC_PAYMENT_METHOD_SELECTOR_STATE_KEY,
          value,
        );

        // analytics
        trackPaymentMethodSelected(orderType, orderSide, value);
      }
    },
    [orderSide, orderType, setOrderForms],
  );

  const preferredPmWhenInPrimaryCashExperiment = useMemo(() => {
    // does not use memoized account to avoid the value being
    // '--' if an account is not available as this just does a
    // higher balance comparison
    const usdAccount = hasMultiPortfolioTradeExperiment
      ? quotePosition
      : actualUsdAccount?.account;
    const usdcAccount = hasMultiPortfolioTradeExperiment
      ? usdcPosition
      : actualUsdcAccount?.account;
    const higherBalanceAccount =
      parseFloat(usdAccount?.availableBalance.value || '0') >
      parseFloat(usdcAccount?.availableBalance.value || '0')
        ? 'USD'
        : 'USDC';

    return orderSide === 'SELL' ? 'USDC' : higherBalanceAccount;
  }, [
    actualUsdAccount?.account,
    actualUsdcAccount?.account,
    hasMultiPortfolioTradeExperiment,
    orderSide,
    quotePosition,
    usdcPosition,
  ]);

  useEffect(() => {
    if (!paymentMethod) {
      const hasUSDAccount = hasMultiPortfolioTradeExperiment
        ? !hasNoQuoteAccount
        : actualUsdAccount?.account?.availableBalance.value;
      // if user doesn't have a USD account, force them to use USDC
      const savedPaymentMethod = hasUSDAccount
        ? getStoreDataSynchronous(
            LOCAL_STORAGE_NAME,
            LOCAL_STORAGE_KEYS.USDC_PAYMENT_METHOD_SELECTOR_STATE_KEY,
            hasPrimaryCashExperiment
              ? preferredPmWhenInPrimaryCashExperiment
              : 'USD',
          )
        : 'USDC';

      setOrderForms(
        orderFormsStateActions.setPaymentMethod(savedPaymentMethod),
      );
    }

    // only run this on first load
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!product) {
    return null;
  }

  return (
    <USDCPaymentMethodSelector
      product={product}
      queryRef={query}
      orderSide={orderSide}
      paymentMethod={paymentMethod}
      onChange={handleOnChange}
      onInputPress={handleSelectorPress}
    />
  );
}

