describe('OrdersWithErrorHandling', () => {
  const showErrorTrayMock = jest.fn();

  beforeEach(() => {
    showErrorTrayMock.mockClear();

    (useShowErrorTray as jest.Mock).mockImplementation(() => showErrorTrayMock);
  });

  it('shows an error for a single order error', () => {
    const { getByText } = render(<OrdersWithErrorHandlingTestComponent />);

    fireEvent.press(getByText('set cancel failure mode: single'));

    const errorMessage =
      'Your order could not be canceled at this time. Please try again later.';

    expect(showErrorTrayMock).toHaveBeenCalledWith({
      displayMessage: errorMessage,
      error: new Error(errorMessage),
      title: 'Something went wrong',
    });
  });

  it('shows an error for multiple order errors', () => {
    const { getByText } = render(<OrdersWithErrorHandlingTestComponent />);

    fireEvent.press(getByText('set cancel failure mode: multiple'));

    const errorMessage =
      'Some of your orders could not be canceled. Please try again later.';

    expect(showErrorTrayMock).toHaveBeenCalledWith({
      displayMessage: errorMessage,
      error: new Error(errorMessage),
      title: 'Something went wrong',
    });
  });

  it('tracks cancel all orders pressed', () => {
    const { getByText } = render(<OrdersWithErrorHandlingTestComponent />);

    fireEvent.press(getByText('cancel all'));

    expect(Analytics.tapTracker).toHaveBeenCalledTimes(2);
    expect(Analytics.tapTracker).toHaveBeenNthCalledWith(
      1,
      'cancel_all_orders',
      {
        action: 'click',
        componentType: 'button',
        productType: 'SPOT',
      },
    );
    expect(Analytics.tapTracker).toHaveBeenNthCalledWith(2, 'cancel_orders', {
      action: 'click',
      componentType: 'button',
      ordersCancel: 'cancel_all',
      page: 'advanced_orders',
    });
  });

  it('tracks cancel success', () => {
    const { getByText } = render(<OrdersWithErrorHandlingTestComponent />);

    fireEvent.press(getByText('cancel all success'));

    expect(Analytics.logEvent).toHaveBeenCalledTimes(1);
    expect(Analytics.logEvent).toHaveBeenCalledWith(
      'cancel_all_orders_success',
      {
        action: 'render',
        componentType: 'page',
        productType: 'SPOT',
      },
    );
  });

  it('tracks cancel failure', () => {
    const { getByText } = render(<OrdersWithErrorHandlingTestComponent />);

    fireEvent.press(getByText('cancel all failure'));

    expect(Analytics.logEvent).toHaveBeenCalledTimes(1);
    expect(Analytics.logEvent).toHaveBeenCalledWith('cancel_all_orders_error', {
      action: 'render',
      componentType: 'page',
      productType: 'SPOT',
      orderIds: mockOrderIds,
    });
  });
});

