export const AdvocacyHomeTakeOver = memo(function AdvocacyHomeTakeOver({
  upsell,
  isVisible,
  onDismiss,
}: AdvocacyHomeTakeOverProps) {
  const { formatMessage } = useIntl();
  const { top } = useSafeAreaInsets();
  const [isMinimized, setIsMinimized] = useState(false);
  const isDismissed = useRef(false);

  const hasBeenShown = getStoreDataSynchronous(
    ADVOCACY_STORE,
    SEEN_SWC_HOME_TAKEOVER,
    undefined,
  );

  const [isClosing, setIsClosing] = useState(false);

  const colors = usePalette();
  const navigateToDeepLink = useDeepLinking();
  const spectrum = useSpectrum();

  const { onPrimaryClick, onCloseClick } = useUpsellFrameworkInteract(
    upsell,
    ComponentType.tray,
    isVisible,
  );

  const window = Dimensions.get('window');
  const screenWidth = window.width;

  const bannerHeight =
    screenWidth < SMALL_SCREEN_CUTOFF ? SHORT_UPSELL_HEIGHT : UPSELL_HEIGHT;

  const bannerAnimationRef = useSharedValue(top);
  const expandedBannerOpacityRef = useSharedValue(1);
  const expandedBannerOpacity = useAnimatedStyle(() => ({
    opacity: withTiming(expandedBannerOpacityRef.value, timingConfig),
  }));

  const miniBannerOpacityRef = useSharedValue(0);

  const miniBannerOpacity = useAnimatedStyle(() => ({
    opacity: withTiming(miniBannerOpacityRef.value, timingConfig),
  }));

  const animatedHeight = useAnimatedStyle(() => ({
    height: withTiming(bannerAnimationRef.value, timingConfig),
  }));

  const setHeight = useCallback(
    (newHeight: number) => {
      bannerAnimationRef.value = newHeight;
    },
    [bannerAnimationRef],
  );

  const slug = useWSCMessageExperiment();

  useOnMount(() => {
    logEvent('advocacy', {
      action: ActionType.view,
      componentType: ComponentType.tray,
      slug,
    });

    const subscription = DeviceEventEmitter.addListener(
      HOME_FEED_SCROLL_START_EVENT,
      handleMinimizeOnScroll,
    );

    const delay = setTimeout(() => {
      setHeight(bannerHeight);

      DeviceEventEmitter.emit(HOME_FEED_SCROLL_LOCK_EVENT, {
        homeCanScroll: false,
      });
    }, UPSELL_SHOWING_DELAY);

    return () => {
      clearTimeout(delay);
      subscription.remove();
    };
  });

  const fadeExpandedBanner = useCallback(() => {
    expandedBannerOpacityRef.value = 0;
  }, [expandedBannerOpacityRef]);

  const easeInExpandedBanner = useCallback(() => {
    expandedBannerOpacityRef.value = 1;
  }, [expandedBannerOpacityRef]);

  const fadeMinimizedBanner = useCallback(() => {
    miniBannerOpacityRef.value = 0;
  }, [miniBannerOpacityRef]);

  const easeInMinimizedBanner = useCallback(() => {
    miniBannerOpacityRef.value = 1;
  }, [miniBannerOpacityRef]);

  const handleMinimizeOnScroll = useCallback(() => {
    setIsMinimized(true);
    easeInMinimizedBanner();
    bannerAnimationRef.value = MINIMIZED_UPSELL_HEIGHT + top;
    fadeExpandedBanner();
    DeviceEventEmitter.emit(HOME_FEED_SCROLL_LOCK_EVENT, {
      homeCanScroll: true,
    });
  }, [bannerAnimationRef, easeInMinimizedBanner, fadeExpandedBanner, top]);

  const data = useContentfulFields<AdvocacyTakeActionFields>(
    {
      queryParams: {
        content_type: 'advocacySignUps',
        'fields.slug': slug,
      },
    },
    true,
  );

  const normalizedData = useMemo(() => {
    if (!data) {
      return null;
    }

    const fieldData = data.items[0].fields;
    const { ctaLink, buttonText, header, content, disclaimer, campaignId } =
      fieldData;
    const description = String(content?.content[0].content[0].value ?? '');
    const legalDisclaimer =
      disclaimer?.content[0].content[0].value ?? undefined;

    return {
      ctaLink,
      buttonText,
      campaignId,
      header,
      description,
      legalDisclaimer,
    };
  }, [data]);

  const handleClose = useCallback(
    (animationDuration: number = durations.slow4) => {
      logEvent('advocacy', {
        action: ActionType.click,
        componentType: ComponentType.button,
        ctaClicked: false,
        slug,
      });

      setHeight(0);
      setIsClosing(true);
      setTimeout(() => {
        onDismiss();
      }, animationDuration);
    },
    [onDismiss, setHeight, slug],
  );

  const handleDismiss = useCallback(() => {
    setStoreDataSynchronous(
      ADVOCACY_STORE,
      SEEN_SWC_HOME_TAKEOVER,
      'dismissed',
    );
    if (!isDismissed.current) {
      isDismissed.current = true;
      onCloseClick();
      handleClose();
    }
  }, [handleClose, onCloseClick]);

  const handleMiniBannerClick = useCallback(() => {
    bannerAnimationRef.value = bannerHeight;
    fadeMinimizedBanner();
    setIsMinimized(false);
    easeInExpandedBanner();

    DeviceEventEmitter.emit(HOME_FEED_SCROLL_LOCK_EVENT, {
      homeCanScroll: false,
    });
  }, [
    bannerAnimationRef,
    bannerHeight,
    easeInExpandedBanner,
    fadeMinimizedBanner,
  ]);

  const handleClick = useCallback(() => {
    logEvent('advocacy', {
      action: ActionType.click,
      componentType: ComponentType.button,
      ctaClicked: true,
      slug,
    });
    setStoreDataSynchronous(ADVOCACY_STORE, SEEN_SWC_HOME_TAKEOVER, 'clicked');
    onPrimaryClick();

    navigateToDeepLink({
      url: normalizedData?.ctaLink ?? SWC_CTA_FALLBACK,
      fallbackOnInvalidDeepLink: true,
    });
  }, [navigateToDeepLink, normalizedData?.ctaLink, onPrimaryClick, slug]);

  const containerStyles = useMemo(
    () => [styles.container, animatedHeight],
    [animatedHeight],
  );

  const wrapperStyles: ViewStyle = useMemo(
    () => ({
      backgroundColor: COINBASE_BLUE,
      marginTop: isClosing ? 0 : -top,
    }),
    [top, isClosing],
  );

  const bannerStyle = useMemo(
    () => ({
      paddingTop: top,
    }),
    [top],
  );

  const edgeStyles: ViewStyle = useMemo(
    () => ({
      width: '100%',
      height: 0,
      borderTopLeftRadius: EDGE_RADIUS,
      borderTopRightRadius: EDGE_RADIUS,
      borderWidth: EDGE_RADIUS,
      borderColor: colors.background,
      backgroundColor: COINBASE_BLUE,
    }),
    [colors.background],
  );

  const textColor = useMemo(
    () => (spectrum === 'dark' ? 'foreground' : 'secondary'),
    [spectrum],
  );

  const iconColor = useMemo(
    () => (spectrum === 'dark' ? 'foregroundMuted' : 'primary'),
    [spectrum],
  );

  const expandedBanner = (
    <Reanimated.View style={containerStyles}>
      <VStack
        dangerouslySetBackground={COINBASE_BLUE}
        spacingTop={2}
        spacingHorizontal={3}
        spacingBottom={2}
        style={bannerStyle}
        testID="swc-take-action-home-take-over"
      >
        <VStack offsetStart={2} spacingTop={1}>
          <IconButton
            name="close"
            variant={iconColor}
            transparent={spectrum === 'dark'}
            onPress={handleDismiss}
            testID="swc-upsell-close-btn"
          />
        </VStack>
        <Reanimated.View style={expandedBannerOpacity}>
          <TextTitle1 color={textColor} align="center" spacingTop={1}>
            {normalizedData?.header ?? formatMessage(messages.title)}
          </TextTitle1>
          <TextBody color={textColor} align="center" spacingVertical={3}>
            {normalizedData?.description ?? formatMessage(messages.content)}
          </TextBody>
        </Reanimated.View>
        <PressableOpacity onPress={handleClick}>
          <VStack
            style={buttonStyle}
            justifyContent="center"
            alignItems="center"
          >
            <TextHeadline align="center" dangerouslySetColor="rgb(0, 0, 0)">
              {normalizedData?.buttonText ?? formatMessage(messages.cta)}
            </TextHeadline>
          </VStack>
        </PressableOpacity>
        <VStack offsetTop={0.5}>
          <TextLegal dangerouslySetColor="rgb(176,202,255)" align="center">
            {normalizedData?.legalDisclaimer ??
              formatMessage(messages.disclaimer, {
                link: (
                  <Link
                    key="link"
                    underline
                    variant="body"
                    to={SWC_PRIVACY_POLICY}
                  >
                    <TextLegal dangerouslySetColor="rgb(176,202,255)">
                      {formatMessage(messages.privacyPolicy)}
                    </TextLegal>
                  </Link>
                ),
              })}
          </TextLegal>
        </VStack>
      </VStack>

      <VStack
        justifyContent="center"
        height={0}
        bottom={0}
        left={0}
        right={0}
        position="absolute"
        dangerouslySetBackground={COINBASE_BLUE}
      >
        <VStack background="primary" style={edgeStyles} />
      </VStack>
    </Reanimated.View>
  );

  const minimizedBanner = (
    <>
      <Reanimated.View style={containerStyles}>
        <PressableOpacity onPress={handleMiniBannerClick}>
          <HStack
            dangerouslySetBackground={COINBASE_BLUE}
            spacingTop={2}
            spacingStart={1}
            spacingEnd={2}
            spacingBottom={2}
            style={bannerStyle}
            testID="swc-take-action-home-take-over-minimized"
            maxWidth="100%"
          >
            <VStack offsetEnd={2} alignItems="flex-start" spacingTop={1}>
              <IconButton
                name="close"
                variant={iconColor}
                transparent={spectrum === 'dark'}
                onPress={handleDismiss}
                testID="swc-upsell-close-btn"
              />
            </VStack>
            <Reanimated.View style={miniBannerOpacity}>
              <HStack spacing={2}>
                <TextHeadline color={textColor} numberOfLines={2}>
                  {normalizedData?.header ?? formatMessage(messages.title)}
                </TextHeadline>
              </HStack>
            </Reanimated.View>
          </HStack>
          <Spacer vertical={2} />
        </PressableOpacity>
      </Reanimated.View>
      <VStack
        justifyContent="center"
        height={0}
        bottom={0}
        left={0}
        right={0}
        position="absolute"
        dangerouslySetBackground={COINBASE_BLUE}
      >
        <VStack background="primary" style={edgeStyles} />
      </VStack>
    </>
  );

  return (
    isVisible &&
    !hasBeenShown && (
      <VStack style={wrapperStyles}>
        {isMinimized ? minimizedBanner : expandedBanner}
      </VStack>
    )
  );
});

