  no = 'no',
}

const i18nKey = 'AdvocacySurveyQuestionResponse';

const messages = defineMessages({
  yes: {
    id: `${i18nKey}.yes`,
    defaultMessage: 'Yes',
    description: 'Response yes',
  },
  no: {
    id: `${i18nKey}.no`,
    defaultMessage: 'No',
    description: 'response no',
  },
  groupAccessibilityLabel: {
    id: `${i18nKey}.groupAccessibilityLabel`,
    defaultMessage: 'Button group for responding yes or no',
    description: 'Response button group',
  },
  buttonAccessibilityLabel: {
    id: `${i18nKey}.buttonAccessibilityLabel`,
    defaultMessage: 'Respond {response}',
    description: 'Button to respond {response}',
  },
  success: {
    id: `${i18nKey}.success`,
    defaultMessage: 'Thank you for your response!',
