type Props = {
  question: string;
  isFooterSurvey?: boolean;
};

export const AdvocacyYesNoQuestion = memo(function AdvocacyYesNoQuestion({
  question,
  isFooterSurvey = false,
}: Props) {
  const { advocacyNewsId } = useParams<'AdvocacyContentModal'>();
  const [removeFooter, setRemoveFooter] = useState(false);
  const [responseStatus, setResponseStatus] = useState<
    LottieStatusAnimationType | undefined
  >();
  const { formatMessage } = useIntl();
  const isReduceMotionEnabled = useIsReduceMotionEnabled();
  const handleResponse = useCallback(
    (response: SurveyResponse) => () => {
      setResponseStatus('success');
      logEvent('advocacy', {
        action: ActionType.click,
        componentType: ComponentType.button,
        advocacy_news_id: advocacyNewsId,
        question,
        response,
      });

      if (isFooterSurvey) {
        setTimeout(() => {
          setRemoveFooter(true);
        }, 6000);
      }
    },
    [advocacyNewsId, question, isFooterSurvey],
  );

  const ConfirmationIcon = useMemo(
    () =>
      isReduceMotionEnabled ? (
        <Box spacingVertical={3}>
          <Pictogram name="checkmark" />
        </Box>
      ) : (
        <LottieStatusAnimation height={96} status="success" />
      ),
    [isReduceMotionEnabled],
  );

  if (removeFooter) {
    return null;
  }

  return (
    <Box
      borderedTop={isFooterSurvey}
      background={isFooterSurvey ? 'backgroundAlternate' : undefined}
      justifyContent="space-between"
      alignItems="center"
      spacing={2}
    >
      {responseStatus ? (
        <>
          <Box spacingVertical={3}>
            <TextTitle3>{formatMessage(messages.success)}</TextTitle3>
          </Box>
          {ConfirmationIcon}
        </>
      ) : (
        <>
          <Box spacingVertical={3}>
            <TextTitle3>{question}</TextTitle3>
          </Box>
          <ButtonGroup
            block
            accessibilityLabel={formatMessage(messages.groupAccessibilityLabel)}
          >
            {[SurveyResponse.yes, SurveyResponse.no].map((response) => (
              <Button
                spacingVertical={3}
                key={response}
                onPress={handleResponse(response)}
                accessibilityLabel={formatMessage(
                  messages.buttonAccessibilityLabel,
                  {
                    response,
                  },
                )}
              >
                {formatMessage(messages[response])}
              </Button>
            ))}
          </ButtonGroup>
        </>
      )}
    </Box>
  );
});

