import { memo, useCallback, useMemo } from 'react';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { ThemeProvider } from '@cbhq/cds-mobile/system';
import { Pressable } from '@cbhq/cds-mobile/system/Pressable';

export type StepperProps = {
  totalSteps: number;
  currentStep: number;
  inverted?: boolean;
  onPress?: (index: number) => void;
};
const Stepper = memo(function Stepper({
  totalSteps,
  currentStep,
  inverted,
  onPress,
}: StepperProps) {
  const [active, inactive] = useMemo(() => {
    if (inverted) return ['background', 'backgroundAlternate'] as const;
    return ['primary', 'primaryWash'] as const;
  }, [inverted]);

  if (totalSteps < 1) return null;

  return (
    <ThemeProvider
      palette={{
        primary: 'blue60',
        primaryWash: 'blue5',
        background: 'gray0',
        backgroundAlternate: 'gray30',
      }}
      name="stepper"
    >
      <HStack
        gap={1}
        width="30%"
        height="100%"
        alignItems="center"
        justifyContent="center"
      >
        {Array.from({ length: totalSteps }, (_, index) => (
          <Step
            index={index}
            key={index}
            currentStep={currentStep}
            active={active}
            inactive={inactive}
            onPress={onPress}
          />
        ))}
      </HStack>
    </ThemeProvider>
  );
});

export { Stepper };

type StepOptions = {
  index: number;
  currentStep: number;
  active: 'background' | 'primary';
  inactive: 'backgroundAlternate' | 'primaryWash';
  onPress?: (index: number) => void;
};

const Step = memo(function Step({
  index,
  currentStep,
  active,
  inactive,
  onPress,
}: StepOptions) {
  const handlePress = useCallback(() => {
    onPress?.(index);
  }, [onPress, index]);

  const isActive = useMemo(() => index <= currentStep, [currentStep, index]);

  return (
    <Pressable
      style={{
        flexGrow: 1,
        height: '100%',
        justifyContent: 'center',
        alignItems: 'center',
      }}
      testID={isActive ? 'step-active' : 'step-inactive'}
      accessibilityRole="button"
      onPress={handlePress}
      background={isActive ? active : inactive}
    >
      <Box
        borderRadius="rounded"
        aspectRatio={22 / 3}
        height={3}
        background={isActive ? active : inactive}
      />
    </Pressable>
  );
});

