function StableAssetCarouselContent({
  queryRef,
  carouselType,
  ...props
}: StableAssetCarouselProps) {
  const { formatMessage } = useIntl();
  const carousel = useCarousel();

  const query = useFragment(
    graphql`
      fragment StableAssetCarouselContentFragment on Query {
        ...useStableAssetCarouselContentfulInfoFragment
      }
    `,
    queryRef,
  );

  const entryId = useMemo(() => {
    switch (carouselType) {
      case 'top':
        return TOP_CARDS_ENTRY_ID;
      case 'nextUp':
        return NEXT_UP_CARDS_ENTRY_ID;
      case 'learn':
        return LEARN_CARDS_ENTRY_ID;
      default:
        return '';
    }
  }, [carouselType]);

  const cards = useStableAssetCarouselContentfulInfo({
    entryId,
    queryRef: query,
  }) as ContentfulActionCard[];

  const [activeCards, setActiveCards] = useState<ContentfulActionCard[]>(() => {
    return cards.filter((card) => {
      const isHidden = getStoreDataSynchronous(
        LOCAL_STORAGE_NAME,
        card.cardId,
        false,
      );
      return !isHidden;
    });
  });

  const onDismiss = useCallback(
    (dismissedCardId: string) => {
      const updatedActiveCards = activeCards.filter(
        (card) => card.cardId !== dismissedCardId,
      );
      setActiveCards(updatedActiveCards);
      setStoreDataSynchronous(LOCAL_STORAGE_NAME, dismissedCardId, true);
    },
    [activeCards],
  );

  const cardItems = useMemo(() => {
    if (activeCards && activeCards.length > 0) {
      return activeCards.map((card) => {
        return (
          <StableAssetCarouselCard
            key={card.title}
            card={card}
            cardType={carouselType}
            onDismiss={carouselType === 'top' ? onDismiss : undefined}
            {...props}
          />
        );
      });
    }
    return null;
  }, [activeCards, carouselType, onDismiss, props]);

  const hasCards = cardItems && cardItems.length > 0;

  if (!hasCards) {
    return null;
  }

  return carouselType === 'top' ? (
    <Carousel carouselRef={carousel} gap={1} items={cardItems} />
  ) : (
    <>
      <Divider
        offsetHorizontal={gutter}
        direction="horizontal"
        spacingTop={1}
        spacingBottom={1}
      />
      <Section
        spacingBottom={3}
        titleSpacingBottom={3}
        title={
          carouselType === 'learn'
            ? formatMessage(messages.learnSectionTitle)
            : formatMessage(messages.nextUpTitle)
        }
      >
        <Carousel
          carouselRef={carousel}
          gap={carouselType === 'learn' ? 2 : 1}
          items={cardItems}
        />
      </Section>
    </>
  );
}

