type StableAssetQuickActionsProps = {
  queryRef: StableAssetQuickActionsFragment$key;
  showAddUsdcUpsell?: boolean;
  onPressingAddCash?: () => void;
};

const StableAssetQuickActionsContent = memo<StableAssetQuickActionsProps>(
  ({ queryRef, showAddUsdcUpsell, onPressingAddCash }) => {
    const quickActionsFragmentRef = useFragment(
      graphql`
        fragment StableAssetQuickActionsFragment on Query
        @argumentDefinitions(
          assetId: { type: "Uuid!" }
          chainId: { type: "Int!" }
          address: { type: "String!" }
          skip: { type: "Boolean!" }
        ) {
          ...useStableAssetQuickActionsFragment
            @arguments(
              assetId: $assetId
              chainId: $chainId
              address: $address
              skip: $skip
            )
          viewer {
            assetByUuid(uuid: $assetId) {
              asset {
                uuid
                ...StableAssetConvertTrayFragment
              }
            }
          }
        }
      `,
      queryRef,
    );

    const quickActions = useStableAssetQuickActions({
      queryRef: quickActionsFragmentRef,
      showAddUsdcUpsell,
      onPressingAddCash,
    });

    const boxWidth = useMemo(() => {
      if (quickActions.length === 3) {
        return '33%';
      }
      if (quickActions.length === 4) {
        return '25%';
      }
      return '20%';
    }, [quickActions]);

    const hasUsdcCashTransferExperiment = useHasUsdcCashTransferExperiment();

    const [
      isConvertTrayVisible,
      { toggleOn: showConvertTray, toggleOff: hideConvertTray },
    ] = useToggler(false);
    const handleConvertCrypto = useMemo(() => {
      const btn = quickActions.find(({ name }) => name === 'convert');
      return (btn?.onPress as () => void) ?? (() => {});
    }, [quickActions]);

    const asset = quickActionsFragmentRef?.viewer?.assetByUuid?.asset;
    const isUsdc = isUsdcAsset(asset?.uuid ?? '');

    return (
      <>
        <HStack
          spacingVertical={gutter}
          gap={gutter}
          justifyContent="space-evenly"
        >
          {quickActions.map((button) => {
            const shouldShowConvertTray =
              button.name === 'convert' &&
              isUsdc &&
              hasUsdcCashTransferExperiment;
            const onIconPress = shouldShowConvertTray
              ? showConvertTray
              : button.onPress;

            return (
              <Box key={button.title} width={boxWidth}>
                <VStack alignItems="center">
                  <HStack spacingBottom={1}>
                    <IconButton
                      name={button.iconName}
                      variant="primary"
                      onPress={onIconPress}
                      accessibilityLabel={button.title}
                      disabled={button.disabled}
                    />
                  </HStack>
                  <TextLegal accessible={false}>{button.title}</TextLegal>
                </VStack>
              </Box>
            );
          })}
        </HStack>

        {isConvertTrayVisible ? (
          <StableAssetConvertTray
            onConvertCrypto={handleConvertCrypto}
            assetRef={asset ?? null}
            toggleTrayOff={hideConvertTray}
          />
        ) : null}
