    description: '',
  },
  acknowledgement: {
    id: `${i18nKey}.acknowledgement`,
    defaultMessage: 'Thanks for your response!',
    description: '',
  },
  positiveFeedbackLabel: {
    id: `${i18nKey}.positiveFeedbackLabel`,
