  },
});

type Props = {
  surveyParams: Record<string, unknown>;
};

export function SentimentSurveyCard({ surveyParams }: Props) {
  const [isSubmitted, setSubmitted] = useState(false);

  const markSubmitted = useCallback(() => {
    setSubmitted(true);
  }, [setSubmitted]);

  const feedbackSelected = useCallback(
    (type: 'POSITIVE' | 'NEGATIVE') => {
      Analytics.track('sentiment_survey_response', {
        action: ActionType.click,
        componentType: ComponentType.banner,
        surveyParams,
        type,
      } as AnalyticsEventData);

      markSubmitted();
    },
    [surveyParams, markSubmitted],
  );

  return (
    <Card elevation={0} spacing={2}>
      {!isSubmitted ? (
        <Question feedbackSelected={feedbackSelected} />
      ) : (
        <ResponseAcknowledgement />
      )}
    </Card>
  );
}

type QuestionProps = {
  feedbackSelected: (option: 'POSITIVE' | 'NEGATIVE') => void;
};

function Question({ feedbackSelected }: QuestionProps) {
  const fadeAnimation = useAnimatedValueRef(1).current;
  const { formatMessage } = useIntl();

  const onFeedbackSelected = useCallback(
    (option: 'POSITIVE' | 'NEGATIVE') => {
      Animated.timing(fadeAnimation, {
        toValue: 0,
        duration: durations.moderate1,
        useNativeDriver: true,
      }).start(() => feedbackSelected(option));
    },
    [fadeAnimation, feedbackSelected],
  );

  return (
    <HStack
      alignItems="center"
      justifyContent="space-between"
      minHeight={40}
      animated
      style={{
        opacity: fadeAnimation,
      }}
    >
      <Box spacingEnd={2} maxWidth="60%">
        <TextLabel2>{formatMessage(messages.helpfulQuestion)}</TextLabel2>
      </Box>
      <HStack alignItems="flex-end">
        <Box>
          <IconButton
            name="circleCheckmark"
            onPress={() => onFeedbackSelected('POSITIVE')}
            accessibilityLabel={formatMessage(messages.positiveFeedbackLabel)}
          />
        </Box>

        <Box spacingStart={2}>
          <IconButton
            name="circleCross"
            onPress={() => onFeedbackSelected('NEGATIVE')}
            accessibilityLabel={formatMessage(messages.negativeFeedbackLabel)}
          />
        </Box>
      </HStack>
    </HStack>
  );
}

function ResponseAcknowledgement() {
  const { formatMessage } = useIntl();
  const fadeAnimation = useRef(
    useMemo(() => new Animated.Value(0), []),
  ).current;

  useEffect(() => {
    Animated.timing(fadeAnimation, {
      toValue: 1,
      duration: durations.moderate1,
      useNativeDriver: true,
    }).start();
  }, [fadeAnimation]);

  return (
    <HStack
      alignItems="center"
      justifyContent="center"
      minHeight={40}
      animated
      style={{
        opacity: fadeAnimation,
      }}
    >
      <TextLabel1 color="primary">
        {formatMessage(messages.acknowledgement)}
      </TextLabel1>
    </HStack>
  );
}

