type QuickBuyButtonProps = {
  assetType: 'fiat' | 'crypto' | 'CURRENCY_TYPE_CURRENCY_FIAT';
  tradable?: boolean;
  tradableOnDEX?: boolean;
  allowDeposits?: boolean;
  type: AccountType;
  isDefiAccount?: boolean;
} & QuickBuyReceivableCryptoButtonProps &
  QuickBuyTradableCryptoButtonProps &
  QuickBuyFiatButtonProps;

export const QuickBuyButton = memo(
  ({
    assetType,
    tradable,
    allowDeposits,
    type,
    tradableOnDEX,
    isDefiAccount,
    ...restProps
  }: QuickBuyButtonProps) => {
    const hasMgxDiscoveryQuickBuysExperiment =
      useMgxDiscoveryQuickBuysExperiment();

    // handle fiat
    if (['fiat', 'CURRENCY_TYPE_CURRENCY_FIAT'].includes(assetType)) {
      return allowDeposits ? (
        <InstrumentedSuspense
          instrumentationId="QuickBuyButton-Fiat"
          fallback={<Fallback width={32} height={32} shape="circle" />}
        >
          <QuickBuyFiatButton {...restProps} />
        </InstrumentedSuspense>
      ) : (
        <QuickBuyButtonContent disabled />
      );
    }

    // handle defi
    if (isDefiAccount) {
      const { assetId, code } = restProps;
      if (assetId && tradableOnDEX) {
        // handle defi tradable on dex
        return (
          <InstrumentedSuspense
            instrumentationId="QuickBuyButton-Dex"
            fallback={<Fallback width={32} height={32} shape="circle" />}
          >
            <QuickBuyDEXCryptoButton assetId={assetId} code={code} />
          </InstrumentedSuspense>
        );
      }
      // handle defi not tradable on dex
      return <QuickBuyDefiCryptoButton code={code} />;
    }

    // handle cefi crypto
    // handle tradable on coinbase, e.g. BTC
    if (tradable) {
      return <QuickBuyTradableCryptoButton {...restProps} />;
    }
    // handle not tradable on coinbase
    const isReceiveEnabled =
      ['VAULT', 'MULTISIG_VAULT', 'MULTISIG', 'WALLET'].includes(
        type.toUpperCase(),
      ) && allowDeposits;

    if (isReceiveEnabled) {
      return <QuickBuyReceivableCryptoButton {...restProps} />;
    }

    const isDexOnlyAsset = tradableOnDEX && !tradable;
    if (hasMgxDiscoveryQuickBuysExperiment && isDexOnlyAsset) {
      return (
        <InstrumentedSuspense
          instrumentationId="QuickBuyButton-Mgx"
          fallback={<Fallback width={32} height={32} shape="circle" />}
        >
          <QuickBuyMGXCryptoButton
            assetId={restProps.assetId}
            code={restProps.code}
          />
        </InstrumentedSuspense>
      );
    }

    return <QuickBuyButtonContent disabled />;
  },
);

type QuickBuyTradableCryptoButtonProps = {
  code: string;
  accountId: string;
  assetId: string;
};
const QuickBuyTradableCryptoButton = memo(
  ({ accountId, assetId, code }: QuickBuyTradableCryptoButtonProps) => {
    const trackQuickBuyClick = useAssetQuickBuyClickEvent();
    const { setEntryComponent, setTradeEntryPage } =
      useSetTradeAnalyticsContext();
    const isUsdc = isUsdcAsset(assetId);
    const routeName = useRouteName();
    const navigateToBuyInput = useNavigateToBuyInput();
    const advancedModeMarket = useAdvancedModeMarket(code);
    const { navigateToAdvancedTradeOrderForm } =
      useNavigateToAdvancedTradeOrderForm();

    const handleQuickButtonPressed = useCallback(() => {
      trackQuickBuyClick(code);
      const { newEntryComponent, newTradeEntryPage } =
        // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
        tradeEventDataMap[routeName] ?? tradeEventDataMap.Assets!;
      setTradeEntryPage(newTradeEntryPage);
      setEntryComponent(newEntryComponent);
      if (advancedModeMarket) {
        navigateToAdvancedTradeOrderForm({
          orderSide: CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.BUY,
          entryPoint: 'portfolio_tab',
          productId: advancedModeMarket,
        });
      } else {
        navigateToBuyInput({
          assetId,
          accountId,
          transferSource: 'assetsPortfolioList',
          cashOperation: isUsdc ? 'cash_in' : undefined,
          assetSymbolOrSlug: code,
        });
      }
    }, [
      trackQuickBuyClick,
      code,
      routeName,
      setTradeEntryPage,
      setEntryComponent,
      advancedModeMarket,
      navigateToAdvancedTradeOrderForm,
      navigateToBuyInput,
      assetId,
      accountId,
      isUsdc,
    ]);
    return <QuickBuyButtonContent onPress={handleQuickButtonPressed} />;
  },
);

