type QuickBuyDEXCryptoButtonProps = {
  code: string;
  assetId: string;
};

const QuickBuyDEXCryptoButton = memo(
  ({ code, assetId }: QuickBuyDEXCryptoButtonProps) => {
    const { navigate } = useStackNavigation();
    const trackQuickBuyClick = useAssetQuickBuyClickEvent();

    const query = useLazyLoadQuery<QuickBuyButtonDefiCryptoQuery>(
      graphql`
        query QuickBuyButtonDefiCryptoQuery($assetId: Uuid!) {
          viewer @required(action: THROW) {
            assetByUuid(uuid: $assetId) {
              asset {
                contractAddress
              }
            }
          }
          ...useDappWalletChecksFragment
        }
      `,
      { assetId },
    );

    const asset = query.viewer?.assetByUuid?.asset;

    const [checkRequirements, refreshRequirements] = useDappWalletChecks(
      query,
      {
        returnTo,
      },
    );
    const gatedBlockingCall = useDappWalletBlockingCallEffect({
      checkRequirements,
      refreshRequirements,
    });

    const navigateToDexDisclaimer = useCallback(
      () =>
        navigate('DappWalletDexDisclaimer', {
          assetSpecificDisclaimer: true,
          onContinueTo: [
            'SimpleTradeStack',
            {
              screen: 'SimpleTradeInput',
              params: {
                tradeSubType: 'dex',
                tradeType: 'swap',
                targetAssetAddress: asset?.contractAddress,
                transferSource: 'assets',
              },
            },
          ],
        }),
      [asset?.contractAddress, navigate],
    );

    const handleQuickButtonPressed = useCallback(() => {
      trackQuickBuyClick(code);
      void gatedBlockingCall({
        nuxContentSlug: 'web3_nux_dex',
        entryPoint: 'dex',
        onNext: navigateToDexDisclaimer,
      });
    }, [code, gatedBlockingCall, navigateToDexDisclaimer, trackQuickBuyClick]);

    return <QuickBuyButtonContent onPress={handleQuickButtonPressed} />;
  },
);

