// eslint-disable-next-line @cbhq/ts-no-enum
export enum HeaderOptionKey {
  BALANCE = 'balance',
  PRICE = 'price',
  CURRENT_PRICE = 'current_price',
  PERFORMANCE = 'performance',
  PERFORMANCE_ONE_DAY = 'performance_one_day',
  PERCENTAGE_OF_PORTFOLIO = 'percentage_of_portfolio',
}

// option without dapp wallet experiment
const defaultOptions: HeaderOption[] = [
  {
    key: HeaderOptionKey.BALANCE,
    title: messages.showMyBalanceTitle,
    description: messages.showMyBalanceDescription,
  },
  {
    key: HeaderOptionKey.PRICE,
    title: messages.showAssetPriceTitle,
    description: messages.showAssetPriceDescription,
  },
];

const defaultOptionsWithPerformance: HeaderOption[] = [
  {
    key: HeaderOptionKey.PERFORMANCE,
    title: messages.showAssetPerformanceTitle,
    description: messages.showAssetPerformanceDescription,
  },
  ...defaultOptions,
];

const defaultOptionsWithPerformanceTimeRange: HeaderOption[] = [
  {
    key: HeaderOptionKey.PERFORMANCE,
    title: messages.showAssetPerformanceTitleAllTime,
    description: messages.showAssetPerformanceDescription,
  },
  {
    key: HeaderOptionKey.PERFORMANCE_ONE_DAY,
    title: messages.showAssetPerformanceTitleOneDay,
    description: messages.showAssetPerformanceDescriptionOneDay,
  },
  ...defaultOptions,
];

// option with dapp wallet experiment
export const defaultOptionsCrypto: HeaderOption[] = [
  {
    key: HeaderOptionKey.BALANCE,
    title: cryptoMessages.balanceTitle,
    description: cryptoMessages.balanceDescription,
  },
  {
    key: HeaderOptionKey.PRICE,
    title: cryptoMessages.priceTitle,
    description: cryptoMessages.priceDescription,
  },
];

const defaultOptionsCryptoWithPerformance: HeaderOption[] = [
  {
    key: HeaderOptionKey.PERFORMANCE,
    title: cryptoMessages.performanceTitle,
    description: cryptoMessages.performanceDescription,
  },
  ...defaultOptionsCrypto,
];

// option with dapp wallet experiment & performance time range experiment
const defaultOptionsCryptoWithPerformanceTimeRange: HeaderOption[] = [
  {
    key: HeaderOptionKey.PERFORMANCE,
    title: cryptoMessages.performanceTitleAllTime,
    description: cryptoMessages.performanceDescriptionAllTime,
  },
  {
    key: HeaderOptionKey.PERFORMANCE_ONE_DAY,
    title: cryptoMessages.performanceTitleOneDay,
    description: cryptoMessages.performanceDescriptionOneDay,
  },
  ...defaultOptionsCrypto,
];

type HeaderOption = {
  key: HeaderOptionKey;
  title: MessageDescriptor;
  description: MessageDescriptor;
};

type AssetsPortfolioListHeaderProps = {
  queryRef: AssetsPortfolioListHeaderFragment$key;
  surface: 'assets' | 'portfolio' | 'primaryWallet' | 'dappWallet';
  selected: HeaderOptionKey;
  onOptionSelected: (key: HeaderOptionKey) => () => void;
  hasPerformance?: boolean;
  hasPerDayPerformance?: boolean;
  nonCashEquivalentBalance?: string;
  hasUkDisclaimer?: boolean;
  customCopies?: Partial<
    Record<
      HeaderOptionKey,
      { title?: MessageDescriptor; description?: MessageDescriptor }
    >
  >;
};

//* new assets portfolio list header with three options in dropdown: BALANCE, PRICE, PERFORMANCE
//* new header is used in TopAssetHoldingsSection and Portfolio Screen with gain_loss_v1 experiment
//* Primary wallet and dex wallet is still using old header with two options
//* two dropdowns don't share the selected option in local storage.
export const AssetsPortfolioListHeader = memo(
  function AssetsPortfolioListHeader({
    selected,
    onOptionSelected,
    surface,
    customCopies,
    queryRef,
    hasPerformance = false,
    hasPerDayPerformance = false,
    nonCashEquivalentBalance,
    hasUkDisclaimer = false,
  }: AssetsPortfolioListHeaderProps) {
    const query = useFragment(
      graphql`
        fragment AssetsPortfolioListHeaderFragment on Query {
          ...useStableAssetsEligibleFragment
        }
      `,
      queryRef,
    );
    const { userLeapManualNavigationEventTrack } = useUserLeap();
    const [showTray, { toggleOff: toggleTrayOff, toggleOn: toggleTrayOn }] =
      useToggler(false);
    const [
      showDisclaimer,
      { toggleOff: toggleDisclaimerOff, toggleOn: toggleDisclaimerOn },
    ] = useToggler(false);
    const { formatMessage } = useIntl();
    const hasDappWallet = useDappWalletExperiment();
    const { eligible: isStableAssetsEligible } = useStableAssetsEligible(query);
    const hasPerfTimeRangeExp = useAssetPerfTimeRangeExperiment();

    const { title, options } = useMemo(() => {
      // determine which set of HeaderOptions should be displayed
      let optionsToShow = defaultOptions;
      if (hasDappWallet) {
        optionsToShow = defaultOptionsCrypto;
        if (hasPerformance) {
          optionsToShow = defaultOptionsCryptoWithPerformance;
          if (hasPerfTimeRangeExp && hasPerDayPerformance) {
            optionsToShow = defaultOptionsCryptoWithPerformanceTimeRange;
          }
        }
      } else if (hasPerformance) {
        optionsToShow = defaultOptionsWithPerformance;
        if (hasPerfTimeRangeExp && hasPerDayPerformance) {
          optionsToShow = defaultOptionsWithPerformanceTimeRange;
        }
      }

      return {
        title:
          hasDappWallet && isStableAssetsEligible
            ? cryptoMessages.myCrypto
            : messages.yourAssets,
        options: optionsToShow,
      };
    }, [
      hasDappWallet,
      hasPerformance,
      hasPerfTimeRangeExp,
      hasPerDayPerformance,
      isStableAssetsEligible,
    ]);

    const selectedOptionLabel = useMemo(() => {
      return options.find((option) => option.key === selected)?.title;
    }, [options, selected]);

    const dropdownClickHandler = useCallback(() => {
      toggleTrayOn();
      Analytics.track('performance_asset_drawer', {
        action: ActionType.click,
        componentType: ComponentType.dropdown,
        component_name: 'your assets',
        surface,
      });
    }, [toggleTrayOn, surface]);

    return (
      <>
        <HStack
          spacingStart={gutter}
          spacingEnd={3}
          alignItems="center"
          justifyContent="space-between"
        >
          <HStack alignItems="center">
            <Box flexShrink={1} flexWrap="nowrap">
              {isStableAssetsEligible && !!nonCashEquivalentBalance && (
                <>
                  <TextHeadline color="foregroundMuted">
                    {formatMessage(messages.myCrypto)}
                  </TextHeadline>
                  <TextTitle3>{nonCashEquivalentBalance}</TextTitle3>
                </>
              )}
              {(!isStableAssetsEligible ||
                (isStableAssetsEligible && !nonCashEquivalentBalance)) && (
                <TextTitle3 ellipsize="tail">{formatMessage(title)}</TextTitle3>
              )}
            </Box>
            {hasUkDisclaimer && (
              <PressableOpacity onPress={toggleDisclaimerOn}>
                <Icon
                  spacingStart={1}
                  size="xs"
                  name="info"
                  color="foregroundMuted"
                />
              </PressableOpacity>
            )}
          </HStack>
          {options.length > 0 && (
            <MultiFilterPill
              testID="AssetsTabToggle"
              isTrayShowing={showTray}
              label={formatMessage(selectedOptionLabel ?? options[0].title)}
              accessibilityLabel={`${formatMessage(
                messages.sortBy,
              )} ${formatMessage(selectedOptionLabel ?? options[0].title)}`}
              isActive={false}
              onPress={dropdownClickHandler}
            />
          )}
        </HStack>
        <Spacer vertical={1} />
        {!!showTray && (
          <Tray onCloseComplete={toggleTrayOff} testID="dropdown">
            {({ handleClose }) => {
              return (
                <Box spacingHorizontal={1}>
                  {options.map((option) => (
                    <ListCell
                      key={`Tray-${option.key}`}
                      testID={`Tray-${option.key}`}
                      title={formatMessage(
                        customCopies?.[option.key]?.title ?? option.title,
                      )}
                      description={formatMessage(
                        customCopies?.[option.key]?.description ??
                          option.description,
                      )}
                      selected={option.key === selected}
                      onPress={() => {
                        userLeapManualNavigationEventTrack(
                          'PerAssetPerformanceDrawer',
                        );
                        handleClose();
                        onOptionSelected(option.key);
                        Analytics.track('performance_asset_drawer', {
                          action: ActionType.click,
                          componentType: ComponentType.button,
                          component_name: 'your assets',
                          option: option.key,
                          surface,
                        });
                      }}
                    />
                  ))}
                </Box>
              );
            }}
          </Tray>
        )}
        {showDisclaimer && hasUkDisclaimer && (
          <Tray onCloseComplete={toggleDisclaimerOff}>
            {({ handleClose }) => (
              <Box spacingHorizontal={3} spacingTop={1}>
                <VStack spacingBottom={3}>
                  <TextTitle3>
                    {formatMessage(messages.totalBalanceAndPrice)}
                  </TextTitle3>
                  <HStack alignItems="flex-start" spacingTop={0.5}>
                    <TextBody spacingEnd={1}>{'\u2022'}</TextBody>
                    <TextBody>
                      {formatMessage(messages.totalBalanceDisclaimer)}
                    </TextBody>
                  </HStack>
                  <HStack alignItems="flex-start" spacingTop={0.5}>
                    <TextBody spacingEnd={1}>{'\u2022'}</TextBody>
                    <TextBody>
                      {formatMessage(messages.percentChangeDisclaimer)}
                    </TextBody>
                  </HStack>
                </VStack>
                <ApyCalculationDisclaimerTray />
                <Button
                  onPress={handleClose}
                  variant="secondary"
                  spacingTop={2}
                >
                  {formatMessage(messages.balanceExplainerCtaText)}
                </Button>
              </Box>
            )}
          </Tray>
        )}
      </>
    );
  },
);

