                value
              }
              totalBalanceFiat {
                value
              }
            }
            asset {
              displaySymbol
              name
              uuid
            }
          }
        }
      }
    `,
    assetRef,
  );

  const title = useMemo(() => {
    const assetTitle = node?.asset?.name || node?.name || '';

    if (walletType === 'VAULT') {
      return formatMessage(messages.vaultTitle, {
        assetTitle,
      });
    }

    return assetTitle;
  }, [walletType, node, formatMessage]);

  const accountId = useMemo(() => {
    const accountTypes = convertWalletTypeToAccountTypes(walletType);

    const account = node?.accounts?.find((acc) =>
      acc ? accountTypes.includes(acc.type) : null,
    );

    return account?.uuid ?? '';
  }, [node, walletType]);

  const assetId = useMemo(() => {
    return node?.asset?.uuid ?? '';
  }, [node]);

  const assetDisplaySymbol = useMemo(() => {
    return node?.asset?.displaySymbol ?? '';
  }, [node]);

  const advancedModeMarket = useAdvancedModeMarket(assetDisplaySymbol);

  const assetCurrentBalance =
    node?.assetCurrentBalance ?? node?.assetCurrentBalanceV2;

  const assetBalanceInFiat = useMemo(
    () =>
      formatAmount({
        amount: assetCurrentBalance?.totalBalanceFiat?.value ?? '',
        isSensitive: true,
      }),
    [assetCurrentBalance?.totalBalanceFiat?.value, formatAmount],
  );

  const currency = useAssetOrCurrencyGraphQL(node);

  if (!currency) {
    const error = new Error(
      `WalletAssetCell: invalid currency for ${walletType} asset ${title}`,
    );
    errorVitals.logError(error, {
      severity: 'error',
      context: 'wallet_asset_cell',
      isHandled: false,
    });

    throw error;
  }

  const assetBalance = useMemo(
    () =>
      formatCurrency({
        amount: assetCurrentBalance?.totalBalance?.value ?? '',
        isSensitive: privacyModeIsActive,
        maximumFractionDigits: MAX_FRACTION_DIGITS,
        minimumFractionDigits: MIN_FRACTION_DIGITS,
        currency,
      }),
    [
      formatCurrency,
      assetCurrentBalance?.totalBalance?.value,
      privacyModeIsActive,
      currency,
    ],
  );

  const media = useMemo(
    () =>
      currency.type === 'crypto' ? (
        <CellMedia
          type="asset"
          source={currency.image.url}
          accessibilityLabel={currency.code}
        />
      ) : (
        <FiatIcon currencyCode={currency.code} />
      ),
    [currency],
  );

  const shouldNavigateToAssetScreen = useMemo(() => {
    return (
      walletType === 'PRIMARY' &&
      !!node?.accounts?.find((acc) => acc?.type === 'STAKED_FUNDS')
    );
  }, [walletType, node]);

  const handlePress = useCallback(() => {
    trackClickEvent(currency.code);

    if (advancedModeMarket) {
      navigateToAdvancedTradeDetails(advancedModeMarket);
      return;
    }

    if (shouldNavigateToAssetScreen) {
      navigate('Asset', { assetId });
    } else {
      navigate('Account', {
        accountId,
        accountType: walletType,
        assetSymbolOrSlug: assetDisplaySymbol,
      });
    }
  }, [
    trackClickEvent,
    currency.code,
    advancedModeMarket,
    shouldNavigateToAssetScreen,
    navigateToAdvancedTradeDetails,
    navigate,
    assetId,
    accountId,
    walletType,
    assetDisplaySymbol,
  ]);

  return (
    <ListCell
      title={title}
      testID={`WalletAssetCell-${title}`}
      detail={assetBalanceInFiat}
      subdetail={assetBalance}
      priority="end"
      media={media}
      onPress={handlePress}
      disableMultilineTitle
    />
  );
}

function onCatchWalletAssetCellError(error: Error) {
  errorVitals.logError(error, {
    severity: 'error',
