  icon: ReactElement;
};

const WalletBalanceHeaderContent = memo<WalletBalanceHeaderProps>(
  ({ queryRef, walletType, walletTitle, icon }) => {
    const { formatMessage } = useIntl();
    const { toggleIsActive: togglePrivacyMode } = usePrivacyMode();
    const formatAmount = useNativeCurrencyFormatter();

    const { viewer } = useFragment(
      graphql`
        fragment WalletBalanceHeaderFragment on Query {
          viewer @required(action: THROW) {
            ...useUserTotalBalanceByWalletFragment
          }
        }
      `,
      queryRef,
    );

    const { formattedBalanceInFiat, errors } = useUserTotalBalanceByWallet({
      viewerRef: viewer,
      walletType,
    });

    const showAssetsErrorBanner = useShowAssetsErrorBanner();

    const showBalanceUnavailableBanner = useMemo(
      () => showAssetsErrorBanner && !!errors.length,
      [showAssetsErrorBanner, errors],
    );

    const handleOnLongPress = useCallback(() => {
      void togglePrivacyMode();
      Analytics.tapTracker('privacy_portfolio_balance', {
        componentType: ComponentType.button,
      });
