    const headerDefaults = useMemo(() => {
      return {
        defaultLabel: walletTitle,
        defaultTitle: formattedBalanceInFiat,
        defaultAccessibilityLabel: chartHeaderAccessibilityLabel,
        formatAmount,
      };
