          <TextLabel1 color="foregroundMuted" spacingBottom={1}>
            {walletTitle}
          </TextLabel1>
          <BalanceErrorBanner variant="slim" component="WalletBalanceHeader" />
        </Box>
      );
    }

    return (
      <Pressable
        accessibilityRole="button"
        borderRadius="rounded"
        background="transparent"
        onLongPress={handleOnLongPress}
        feedback="normal"
        noScaleOnPress
      >
        <Box spacingHorizontal={gutter} spacingBottom={2} spacingTop={1}>
          <ChartHeader
            testID="WalletBalanceHeader"
            ref={chartHeaderRef}
            trailing={trailingIcon}
            {...headerDefaults}
          />
        </Box>
      </Pressable>
