import { useMemo } from 'react';
import { CellMedia } from '@cbhq/cds-mobile/cells';
import { graphql, readInlineData } from '@cbhq/data-layer';

import { HeaderVariant } from '@designSystem/types';

import { formatPercentage } from '@utils/number/percentageUtils';
import { FiatIcon } from '@app/components/Icons/FiatIcon';
import { app } from '@app/config/app';
import { useCurrencyFormatter } from '@app/hooks/formatters/useCurrencyFormatter';
import { useGainLossAmountFormatter } from '@app/hooks/formatters/useGainLossAmountFormatter';
import { useNativeCurrencyFormatter } from '@app/hooks/formatters/useNativeCurrencyFormatter';
import { useNativeCurrency } from '@app/hooks/useNativeCurrency';
import { PortfolioData } from '@app/hooks/usePortfolio';
import { useIsAugmentedPortfolioPerformance } from '@app/screens/Asset/hooks/useIsAugmentedPortfolioPerformance';
import { HeaderOptionKey } from '@app/screens/AssetsTab/components/AssetsPortfolioListHeader/AssetsPortfolioListHeader';
import { useAssetsRAV4 } from '@app/screens/AssetsTab/hooks/useAssetsRAV4';
import { useIsWeb3WalletEligible } from '@app/screens/Defi/hooks/gating/useIsWeb3WalletEligible';

import { usePortfolioCellInfoInlineFragment$key } from './__generated__/usePortfolioCellInfoInlineFragment.graphql';

export function usePortfolioCellInfo(
  asset: PortfolioData,
  subDetailType?: HeaderOptionKey,
) {
  let detail: string;
  let subdetail: string | undefined;
  let variant: HeaderVariant | undefined;

  const hasAssetsRAV4 = useAssetsRAV4();
  const nativeCurrency = useNativeCurrency();

  const showPrice = subDetailType === HeaderOptionKey.PRICE;

  const assetByUuid = useMemo(() => {
    if (asset?.assetRef) {
      return readInlineData<usePortfolioCellInfoInlineFragment$key>(
        graphql`
          fragment usePortfolioCellInfoInlineFragment on Asset @inline {
            unitPriceScaleV2(quoteCurrency: $nativeCurrency)
            latestPrice(quoteCurrency: $nativeCurrency) {
              price
            }
            platformName
            contractAddress
          }
        `,
        asset.assetRef,
      );
    }
    return null;
  }, [asset]);

  const formatCurrency = useCurrencyFormatter();
  const formatAmount = useNativeCurrencyFormatter({
    minimumFractionDigits: showPrice
      ? assetByUuid?.unitPriceScaleV2 ?? undefined
      : undefined,
  });
  const formatGainLoss = useGainLossAmountFormatter();

  const [hasDappWallet] = useIsWeb3WalletEligible();

  const isAugmentedPortfolioPerformance = useIsAugmentedPortfolioPerformance({
    hasDappWallet,
  });

  switch (subDetailType) {
    case HeaderOptionKey.PERFORMANCE: {
      detail = formatAmount({
        amount: asset.convertedBalance.amount,
        isSensitive: true,
      });
      const gainLossAllTime = isAugmentedPortfolioPerformance
        ? asset.gainLossUnrealized
        : asset.gainLoss;
      if (gainLossAllTime) {
        const { amount, currency } = gainLossAllTime;
        const {
          valueWithArrow,
          variant: color,
          valueWithPercentChange,
        } = formatGainLoss(
          amount,
          currency,
          undefined,
          undefined,
          true,
          isAugmentedPortfolioPerformance
            ? asset.gainLossUnrealizedPercentageChange
            : asset.gainLossPercentageChange,
        );
        variant = color;
        subdetail = hasAssetsRAV4 ? valueWithPercentChange : valueWithArrow;
      } else {
        subdetail = '--';
      }
      break;
    }
    case HeaderOptionKey.PERFORMANCE_ONE_DAY: {
      detail = formatAmount({
        amount: asset.convertedBalance.amount,
        isSensitive: true,
      });
      const gainLossOneDay = isAugmentedPortfolioPerformance
        ? asset?.gainLossOneDayUnrealized
        : asset?.gainLossOneDay;
      if (gainLossOneDay) {
        const { amount, currency } = gainLossOneDay;
        const {
          valueWithArrow,
          variant: color,
          valueWithPercentChange,
        } = formatGainLoss(
          amount,
          currency,
          undefined,
          undefined,
          true,
          isAugmentedPortfolioPerformance
            ? asset?.gainLossOneDayUnrealizedPercentageChange
            : asset?.gainLossOneDayPercentageChange,
        );
        variant = color;
        subdetail = hasAssetsRAV4 ? valueWithPercentChange : valueWithArrow;
      } else {
        subdetail = '--';
      }
      break;
    }
    case HeaderOptionKey.PERCENTAGE_OF_PORTFOLIO: {
      detail = formatAmount({
        amount: asset.convertedBalance.amount,
        isSensitive: true,
      });

      let percentOfPortfolio = '--';
      if (asset.percentOfPortfolio) {
        const value = parseFloat(asset.percentOfPortfolio) / 100;
        percentOfPortfolio = formatPercentage({
          value,
          locale: app.locale,
          scale: 2,
          signDisplay: 'never',
        });
        subdetail = percentOfPortfolio;
      } else {
        subdetail = '--';
      }
      break;
    }
    case HeaderOptionKey.CURRENT_PRICE: {
      detail = formatAmount({
        amount: asset.convertedBalance.amount,
        isSensitive: true,
      });

      const roundupDigits =
        parseFloat(assetByUuid?.latestPrice?.price ?? '0') > 1 ? 2 : 6;

      subdetail = assetByUuid?.latestPrice
        ? formatCurrency({
            amount: assetByUuid.latestPrice.price,
            currency: {
              code: nativeCurrency,
              type: 'fiat',
            },
            isSensitive: true,
            minimumFractionDigits: Math.min(
              asset.currency.exponent,
              roundupDigits,
            ),
            trimTrailingZeros: roundupDigits === 6,
          })
        : undefined;
      break;
    }

    case HeaderOptionKey.BALANCE:
    default: {
      detail = formatAmount({
        amount: asset.convertedBalance.amount,
        isSensitive: true,
      });

      const roundupDigits =
        parseFloat(asset.balance?.amount ?? '0') > 1 ? 2 : 6;

      subdetail = asset.balance
        ? formatCurrency({
            amount: asset.balance.amount,
            currency: asset.currency,
            isSensitive: true,
            maximumFractionDigits: roundupDigits,
            minimumFractionDigits: Math.min(
              asset.currency.exponent,
              roundupDigits,
            ),
            trimTrailingZeros: roundupDigits === 6,
          })
        : undefined;
      // no variant color when show balance
      variant = undefined;
      break;
    }
  }

  const media = useMemo(
    () =>
      asset.currency.type === 'crypto' ? (
        <CellMedia
          type="asset"
          source={asset.currency.image.url}
          accessibilityLabel={asset.currency.code || asset.currency.name || ''}
        />
      ) : (
        <FiatIcon currencyCode={asset.currency.code} />
      ),
    [
      asset.currency.code,
      asset.currency.image.url,
      asset.currency.name,
      asset.currency.type,
    ],
  );

  return useMemo(
    () => ({
      detail,
      subdetail,
      variant,
      media,
      platformName: assetByUuid?.platformName,
      contractAddress: assetByUuid?.contractAddress ?? '',
    }),
    [
      detail,
      subdetail,
      variant,
      media,
      assetByUuid?.platformName,
      assetByUuid?.contractAddress,
    ],
  );
}

