  value: '--',
  valueWithArrow: '--',
  sign: '',
  variant: 'foregroundMuted',
};

export type BalanceSummaryHeroRowType = {
  label: MessageDescriptor;
  amount?: {
    value: string | null;
    currency: string | null;
  } | null;
  isGainLoss?: boolean;
  description?: MessageDescriptor;
  currencyName?: string;
  // Balance summary experiment props
  subTitleAmount?: {
    value: string | null;
    currency: string | null;
  } | null;
  exponent?: number;
};

export type BalanceSummaryHeroRowProps = {
  linkLabel?: MessageDescriptor;
  onLinkPress?: () => void;
  isDetail: boolean;
  currencyCode?: string;
  spacingTop?: SpacingScale;
  spacingBottom?: SpacingScale;
  canShowBalanceSummaryInCryptoDenomination?: boolean;
  balanceText?: FC<TextProps>;
  labelText?: FC<TextProps>;
  labelColor?: PaletteForeground;
} & BalanceSummaryHeroRowType;

export const BalanceSummaryHeroRow = memo(
  ({
    label,
    amount,
    subTitleAmount,
    description,
    linkLabel,
    onLinkPress,
    isDetail,
    isGainLoss = false,
    currencyCode,
    currencyName,
    spacingTop = 3,
    spacingBottom = 6,
    canShowBalanceSummaryInCryptoDenomination,
    exponent,
    balanceText: BalanceText = TextTitle1,
    labelText: LabelText = TextLabel1,
    labelColor = 'foregroundMuted',
  }: BalanceSummaryHeroRowProps) => {
    const { formatMessage } = useIntl();
    const formatGainLoss = useGainLossAmountFormatter();
    const { toggleIsActive: togglePrivacyMode } = usePrivacyMode();
    const hasBalanceHoldTimesExperiment = useHasBalanceHoldTimesExperiment();

    const onLongPress = useCallback(async () => {
      await togglePrivacyMode();
    }, [togglePrivacyMode]);

    const { variant: gainLossColor, valueWithArrow } = formatGainLoss(
      amount?.value ?? '',
      amount?.currency ?? null,
      GAIN_LOSS_FORMATTER_FALLBACK,
    );

    const formatAmount = useCurrencyFormatter();
    const formattedValue = formatAmount({
      isSensitive: true,
      amount: amount?.value ?? '',
      currency: {
        type: 'fiat',
        code: amount?.currency ?? null,
      },
    });

    // Subtitle will always be crypto
    const formattedSubtitleValue = formatAmount({
      isSensitive: true,
      amount: subTitleAmount?.value ?? '',
      currency: {
        type: 'crypto',
        code: subTitleAmount?.currency ?? null,
        exponent,
      },
    });

    const descriptionColor =
      isDetail && !hasBalanceHoldTimesExperiment
        ? 'foreground'
        : 'foregroundMuted';
    const balanceColor = isGainLoss ? gainLossColor : 'foreground';

    const content = useMemo(
      () => (
        <VStack spacingTop={spacingTop} spacingBottom={spacingBottom}>
          <LabelText color={labelColor}>
            {formatMessage(label, { assetCode: currencyCode })}
          </LabelText>

          <BalanceText color={balanceColor} onLongPress={onLongPress}>
            {isGainLoss ? valueWithArrow : formattedValue}
          </BalanceText>
          {!!canShowBalanceSummaryInCryptoDenomination && (
            <TextBody color="foregroundMuted">
              {formattedSubtitleValue}
            </TextBody>
          )}
          <Spacer vertical={isDetail ? 2 : 1} />
          {!!description && (
            <TextBody color={descriptionColor}>
              {formatMessage(description, { assetName: currencyName })}
            </TextBody>
          )}
          {!!linkLabel && (
            <VStack>
              <Spacer vertical={hasBalanceHoldTimesExperiment ? 0 : 2} />
              <TextBody
                color="primary"
                underline={hasBalanceHoldTimesExperiment}
              >
                {formatMessage(linkLabel)}
              </TextBody>
            </VStack>
          )}
        </VStack>
      ),
      [
        spacingTop,
        spacingBottom,
        LabelText,
        labelColor,
        formatMessage,
        label,
        currencyCode,
        BalanceText,
        balanceColor,
        onLongPress,
        isGainLoss,
        valueWithArrow,
        formattedValue,
        canShowBalanceSummaryInCryptoDenomination,
        formattedSubtitleValue,
        isDetail,
        description,
        descriptionColor,
        currencyName,
        linkLabel,
        hasBalanceHoldTimesExperiment,
      ],
    );

    return onLinkPress ? (
      <PressableOpacity onPress={onLinkPress}>{content}</PressableOpacity>
    ) : (
      content
    );
  },
);

