  showDivider?: boolean;
  description?: MessageDescriptor;
  currencyType?: CurrencyType;
  exponent?: number;
};

export const DataRow = memo(
  ({
    label,
    amount,
    headline,
    spacingTop = 1,
    info,
    showColorAndArrow = false,
    negative = false,
    hideRowWhenZero = false,
    isUnavailable = false,
    handleOpenTooltip,
    currencyCode,
    currencyName,
    showDivider = false,
    description,
    currencyType,
    exponent,
  }: DataRowProps) => {
    const { formatMessage } = useIntl();
    const formatGainLoss = useGainLossAmountFormatter();
    const { isActive: privacyModeIsActive } = usePrivacyMode();
    const [informationTrayVisible, { toggleOn, toggleOff }] = useToggler(false);

    const handleOpenTooltipPress = useCallback(() => {
      if (handleOpenTooltip) {
        handleOpenTooltip();
      }
      toggleOn();
    }, [handleOpenTooltip, toggleOn]);

    const { variant: gainLossColor, valueWithArrow } = formatGainLoss(
      amount?.value ?? '',
      amount?.currency ?? null,
      GAIN_LOSS_FORMATTER_FALLBACK,
    );

    const formatAmount = useCurrencyFormatter();
    const formattedValue = formatAmount({
      isSensitive: true,
      amount: amount?.value ?? '',
      currency: {
        type: currencyType ?? 'fiat',
        code: amount?.currency ?? null,
        exponent: currencyType === 'crypto' ? exponent : undefined,
      },
    });

    const labelColor: PaletteForeground = headline
      ? 'foreground'
      : 'foregroundMuted';

    const TextElement = headline ? TextHeadline : TextBody;

    const numberPrefix =
      negative && (isUnavailable || parseFloat(amount?.value ?? '0') > 0)
        ? '-'
        : undefined;

    // NOTE(spark): this allows the correct color to be shown for headline rows when the balance is 0
    const balanceColor =
      gainLossColor === 'foregroundMuted' ? labelColor : gainLossColor;

    const rowContent = useMemo(
      () => (
        <HStack justifyContent="space-between">
          <HStack
            flexGrow={1}
            flexBasis={0}
            alignItems="center"
            // NOTE(spark): this is a hack to prevent the info icon from overlapping the following text.
            // The icon is not being calculated for the width when the text is ellipsized.
            spacingEnd={info ? 1 : undefined}
          >
            <TextElement color={labelColor} ellipsize="tail" spacingEnd={1}>
              {formatMessage(label, { assetCode: currencyCode })}
            </TextElement>
            {!!info && (
              <>
                <Pressable
                  background="transparent"
                  accessibilityRole="button"
                  onPress={handleOpenTooltipPress}
                >
                  <Icon
                    name="info"
                    size="xs"
                    color="foregroundMuted"
                    testID="data-row-info-icon"
                  />
                </Pressable>
                <InformationTray
                  visible={informationTrayVisible}
                  onCloseTray={toggleOff}
                  title={formatMessage(label, { assetCode: currencyCode })}
                  content={formatMessage(info, { assetName: currencyName })}
                />
              </>
            )}
          </HStack>
          <TextElement color={showColorAndArrow ? balanceColor : labelColor}>
            {!privacyModeIsActive && numberPrefix ? numberPrefix : null}
            {showColorAndArrow ? valueWithArrow : formattedValue}
          </TextElement>
        </HStack>
      ),
      [
        TextElement,
        labelColor,
        formatMessage,
        label,
        currencyCode,
        info,
        currencyName,
        showColorAndArrow,
        balanceColor,
        privacyModeIsActive,
        numberPrefix,
        valueWithArrow,
        formattedValue,
        informationTrayVisible,
        handleOpenTooltipPress,
        toggleOff,
      ],
    );

    // NOTE(spark): if hideRowWhenZero is false, show row even if amount is null/undefined
    if (hideRowWhenZero && (!amount?.value || parseFloat(amount.value) === 0)) {
      return null;
    }

    return (
      <VStack spacingTop={spacingTop}>
        {showDivider && (
          <VStack>
            <Spacer vertical={4} />
            <Divider />
            <Spacer vertical={4} />
          </VStack>
        )}
        {rowContent}
        {!!description && (
          <VStack>
            <Spacer vertical={1} />
            <TextLabel2 color="foregroundMuted">
              {formatMessage(description)}
            </TextLabel2>
          </VStack>
        )}
      </VStack>
    );
  },
);

export type SignRowProps = {
  iconName: IconName;
};

const SignRow = memo(({ iconName }: SignRowProps) => {
  // NOTE(spark): using 'pause' icon with 90 degree rotation in place of an equal sign
  const iconStyle =
    iconName === 'pause'
      ? {
          transform: [{ rotate: '90deg' }],
        }
      : {};

  return (
    <HStack width="100%" justifyContent="flex-end" alignItems="center">
      <Icon name={iconName} size="xs" color="foreground" style={iconStyle} />
    </HStack>
  );
});

// eslint-disable-next-line @cbhq/ts-no-enum
export enum FormulaBreakdownRowType {
  data = 'data',
  sign = 'sign',
}

export type FormulaBreakdownDataType =
  | { rowType: 'data'; data: DataRowProps }
  | { rowType: 'sign'; data: SignRowProps };

export const FormulaBreakdownRow = memo(
  ({ rowType, data }: FormulaBreakdownDataType) => {
    // NOTE(spark): need to check for data / sign props because
    // TS throws error for missing fields for union types
    // so data / sign props are separate and optional
    if (rowType === 'data') {
      return <DataRow spacingTop={0} {...data} />;
    }
    return <SignRow key={`${data.iconName}-sign-row`} {...data} />;
  },
);

export type PendingTransactionRowProps = {
