      <ListCell
        outerSpacing={{ spacing: 0 }}
        key={`pending-transaction-${currencyCode}`}
        title={formatMessage(title, {
          assetCode: currencyCode,
        })}
        description={formatMessage(messages.availableIn, {
          availableIn,
        })}
        detail={detail}
      />
    );
