                description
                marketData {
                  floorPrice {
                    value
                    asset {
                      symbol
                    }
                  }
                  numberOfOwners
                  numberOfTokens
                }
                contract {
                  type
                }
                cachedImage(size: LARGE) {
                  url
                }
              }
            }
          }
        }
      }
    `,
    { collectionId, mintProvider },
  );

  const imageSize = height * 0.4;

  const returnTo: NavigateArgs = useMemo(
    () => [
      'ExploreStack',
      {
        screen: 'MintDetails',
        params: { collectionId, mintProvider },
      },
    ],
    [collectionId, mintProvider],
  );

  const [checkRequirements, refreshRequirements] = useDappWalletChecks(query, {
    returnTo,
  });

  const gatedBlockingCall = useDappWalletBlockingCallEffect({
    checkRequirements,
    refreshRequirements,
  });

  const { createMintTx, isFetching: isFetchingTxData } = useCreateMintTx();

  const getMintTxAndNavigateToPreview = useCallback(async () => {
    const mintQuantity =
      selectedAmount === -1 ? Number(debouncedInput) : selectedAmount;

    let mintTxData: DefiGenerateMintTransactionResponse = null;

    try {
      mintTxData = await createMintTx({
        collectionId,
        tokenCount: mintQuantity,
        provider: mintProvider,
        takerAddress: walletAddress ?? '',
      });
    } catch (error) {
      // Ignore error when user does not have a web3 wallet, code below creates new wallet for them
      if (walletAddress !== null) {
        errorVitals.logError(getErrorInstance(error), {
          severity: 'error',
          isHandled: true,
          context: 'cb_nft_mint_details_screen',
          collectionId,
          mintProvider,
          mintQuantity,
        });
      }
    }

    void gatedBlockingCall({
      entryPoint: 'nft',
      onNext: () => {
        navigate('CbNftBuyStack', {
          screen: 'MintPreview',
          params: {
            txData: mintTxData,
            mintQuantity,
            collectionId,
            mintProvider,
          },
        });
      },
      nuxContentSlug: 'web3_nux_nft_transaction',
    });
  }, [
    selectedAmount,
    debouncedInput,
    createMintTx,
    collectionId,
    mintProvider,
    walletAddress,
    gatedBlockingCall,
    navigate,
  ]);

  const handleMintPress = useCallback(() => {
    trackCbNftClick({
      flow: 'cb_nft_mint',
      step: '0_entry_point',
      otherParams: {
        mint_quantity: selectedAmount,
        cb_nft_surface: 'mint_details',
      },
    });
    void getMintTxAndNavigateToPreview();
  }, [getMintTxAndNavigateToPreview, selectedAmount]);

  const mintDetails = query.viewer?.defiV2?.nft?.collectionByUuid;
  const mintPrice = query?.defiMintPrices?.[0]?.price;

  const handleSelectAmount = useCallback((amount: number) => {
    return () => setSelectedAmount(amount);
  }, []);

  const priceFormatter = useCurrencyFormatter();

  const isFreeMint = Number(mintPrice) === 0;

  const priceOfMint = priceFormatter({
    amount: mintPrice,
    currency: {
      type: 'crypto',
      code: mintDetails?.marketData?.floorPrice?.asset?.symbol,
    },
    isSensitive: false,
    minimumFractionDigits: 0,
    maximumFractionDigits: 5,
  });

  const handleOnChangeText = useCallback(
    (amountInput: string) => {
      debouncedSetInput(amountInput);
    },
    [debouncedSetInput],
  );

  const contractName = getContractType(mintDetails?.contract?.type ?? null);

  return (
    <Screen noSpacing>
      <VStack spacingHorizontal={gutter}>
        <VStack justifyContent="center" alignItems="center" spacingBottom={3}>
          <NftImage
            imageUrl={mintDetails?.cachedImage?.url ?? ''}
            imageSize={imageSize}
            style={imageStyle}
          />
        </VStack>

        <Tag alignSelf="flex-start" colorScheme="green">
          {formatMessage(messages.mintingNow)}
        </Tag>

        <VStack gap={3}>
          <TextTitle1>
            {formatMessage(messages.mintTitle, {
              mintTitle: mintDetails?.name,
            })}
          </TextTitle1>
          <ReadMoreText
            textBodyProps={{
              color: paletteForegrounds[1],
            }}
            content={mintDetails?.description ?? ''}
          />
          <HStack justifyContent="space-between">
            {MINT_AMOUNTS.map((amount) => {
              return (
                <Button
                  testID="mint-amount-button"
                  variant={selectedAmount === amount ? 'primary' : 'secondary'}
                  key={amount}
                  compact
                  onPress={handleSelectAmount(amount)}
                >
                  {amount}
                </Button>
              );
            })}

            <Button
              testID="mint-amount-custom"
              compact
              variant={selectedAmount === -1 ? 'primary' : 'secondary'}
              onPress={handleSelectAmount(-1)}
            >
              {formatMessage(messages.custom)}
            </Button>
          </HStack>
        </VStack>
        {selectedAmount === -1 && (
          <Box spacingBottom={1}>
            <TextInput
              testID="mint-amount-input"
              accessibilityRole="keyboardkey"
              keyboardType="number-pad"
              placeholder="1"
              onChangeText={handleOnChangeText}
              end={
                <TextLabel1 spacingEnd={1} color="foregroundMuted">
                  {formatMessage(messages.nfts)}
                </TextLabel1>
              }
            />
          </Box>
        )}
        <Button
          testID="confirm-mint-button"
          block
          loading={isFetchingTxData}
          onPress={handleMintPress}
          disabled={selectedAmount === -1 && debouncedInput === ''} // custom amount with no value
        >
          {isFreeMint
            ? formatMessage(messages.mintFree)
            : formatMessage(messages.mintPricing, { priceOfMint })}
        </Button>
      </VStack>

      <VStack spacingTop={2}>
        <MintDetailsMetadataCell
          field="Minted"
          value={mintDetails?.marketData?.numberOfTokens ?? '--'}
        />
        <MintDetailsMetadataCell field="Schedule" value="Public sale" />
        <MintDetailsMetadataCell
          field="Owners"
          value={mintDetails?.marketData?.numberOfOwners ?? '--'}
        />
        <MintDetailsMetadataCell
          field="Contract details"
          value={contractName}
          borderedBottom
        />
      </VStack>
    </Screen>
  );
});

