const i18nKey = 'OwnedNftSection';
const messages = defineMessages({
  // TODO: Follow up with "Owned since {date}" once the data is available from the BE
  yours: {
    id: `${i18nKey}.yours`,
    defaultMessage: "It's yours!",
    description: `#Component: Body
    #CharLimit: none
    #Context: Date since you've owned the nft`,
  },
  refresh: {
