    #Context: Link out copy for opening the NFT in the block scan site`,
  },
  refreshDataToast: {
    id: `${i18nKey}.refreshDataToast`,
    defaultMessage:
      'Data will refresh soon. This may take several minutes to complete.',
    description: `#Component: Body
    #CharLimit: none
    #Context: Successful refresh metadata message displayed to the user`,
  },
  refreshDataErrorToast: {
    id: `${i18nKey}.refreshDataErrorToast`,
    defaultMessage: 'Refresh data failed. Try again later.',
    description: `#Component: Body
    #CharLimit: none
    #Context: Message displayed to the user when refresh metadata api failed`,
  },
});

type OwnedNftSectionProps = {
  refresh: () => Promise<void>;
  defiNFTRef: NonNullable<
    NonNullable<
      NonNullable<CbNftDetailsScreenQuery['response']['viewer']>['defiV2']
    >['nft']
  >['nftByUuid'];
};

export const OwnedNftSection = memo(function OwnedNftSection({
  refresh,
  defiNFTRef,
}: OwnedNftSectionProps) {
  const { formatMessage } = useIntl();
  const { navigateToWeb3Browser } = useWeb3BrowserTabs();
  const [isRefreshing, setIsRefreshing] = useState(false);
  const toast = useToast();

  const details = useFragment<OwnedNftSectionFragment$key>(
    graphql`
      fragment OwnedNftSectionFragment on DefiNFT {
        uuid
      }
    `,
    defiNFTRef,
  );

  const onRefreshPress = useCallback(async () => {
    if (isRefreshing) {
      return;
    }

    toast.clearQueue();
    setIsRefreshing(true);

    try {
      await refresh();
    } catch (e) {
      toast.show(formatMessage(messages.refreshDataErrorToast));
    } finally {
      setIsRefreshing(false);
    }

    toast.show(formatMessage(messages.refreshDataToast));
  }, [formatMessage, isRefreshing, refresh, toast]);

  const linkoutUrl = buildBlockScanUrl(details?.uuid as string);

  const onLinkOutPress = useCallback(() => {
    navigateToWeb3Browser({
      url: linkoutUrl,
    });
  }, [navigateToWeb3Browser, linkoutUrl]);

  return (
    <VStack spacingTop={3} gap={3}>
      <HStack
        background="primaryWash"
        borderRadius="roundedLarge"
        spacing={2}
        alignItems="center"
      >
        <Icon size="s" name="checkmark" color="primary" spacingEnd={2} />
        <TextBody color="primary">{formatMessage(messages.yours)}</TextBody>
      </HStack>
      <HStack justifyContent="space-around">
        <VStack alignItems="center" gap={1} width="50%">
          <IconButton
            name="refresh"
            onPress={onRefreshPress}
            testID="owned-nft-section-refresh"
            aria-labelledby="owned-nft-section-refresh-label"
          />
          <TextLegal id="owned-nft-section-refresh-label">
            {formatMessage(messages.refresh)}
          </TextLegal>
        </VStack>
        <VStack alignItems="center" gap={1} width="50%">
          <IconButton
            name="externalLink"
            onPress={onLinkOutPress}
            testID="owned-nft-section-view-transaction"
            aria-labelledby="owned-nft-section-transaction-label"
          />
          <TextLegal id="owned-nft-section-transaction-label">
            {formatMessage(messages.viewTransaction)}
          </TextLegal>
        </VStack>
      </HStack>
    </VStack>
  );
});

