const SpendUSDOrCryptoContent = memo(() => {
  const query = useLazyLoadQuery<SpendFiatOrCryptoScreenQuery>(
    graphql`
      query SpendFiatOrCryptoScreenQuery {
        viewer @required(action: THROW) {
          userProperties {
            zeroLiquidationFeesEnabled: isFeatureFlagEnabled(
              flag: "2022.mar.card_zero_liquidation_fees"
            )
          }
        }
        ...useAfterSelectAssetNavigationFragment
        ...useFiatAccountForCardProgramFragment
      }
    `,
    {},
  );

  const fiatAsset = useFiatAccountForCardProgram(query);

  const zeroLiquidationFeesDisabled =
    !query.viewer.userProperties.zeroLiquidationFeesEnabled;

  useEffect(() => logCardSpendUSDorCryptoView(), []);

  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const { navigateToNextScreen } = useAfterSelectAssetNavigation(query);

  const onSetAssetSuccess = useCallback(() => {
    if (!fiatAsset.currency) {
      return null;
    }

    const fiatBalance = fiatAsset.fiatBalanceAvailable?.value;
    void navigateToNextScreen(fiatAsset.currency, fiatBalance ?? '0');

    return null;
  }, [
    fiatAsset.currency,
    fiatAsset.fiatBalanceAvailable?.value,
    navigateToNextScreen,
  ]);

  const { updateSpendableAsset, isUpdating } = useSetSpendableAsset();

  const submitSpendableAsset = useCallback(
    (symbol: string) => {
      updateSpendableAsset({
        variables: {
          input: {
            assetSymbol: symbol,
          },
        },
        onCompleted: () => {
          onSetAssetSuccess();
        },
        onError: ({ alreadyReportedError }) => {
          errorVitals.logError(alreadyReportedError, {
            context: 'coinbase_card',
            severity: 'error',
            isHandled: false,
          });
        },
      });
    },
    [onSetAssetSuccess, updateSpendableAsset],
  );

  const handleSpendFiatPressed = useCallback(async () => {
    logCardSelectUSD();
    if (fiatAsset.currency?.symbol !== undefined) {
      submitSpendableAsset(fiatAsset.currency?.symbol);
    } else {
      errorVitals.logError(new Error('Could not find fiat asset in issuance'), {
        context: 'coinbase_card',
        severity: 'error',
        isHandled: false,
      });
    }
  }, [fiatAsset.currency?.symbol, submitSpendableAsset]);

  const handleSpendCryptoPressed = useCallback(() => {
    logCardSelectCrypto();
    if (zeroLiquidationFeesDisabled) {
      navigate('CardIssuanceSpendableAsset', {});
    } else {
      navigate('ZeroSpendingFeesScreen', {
        isIssuance: true,
        currentAssetUuid: undefined,
      });
    }
  }, [zeroLiquidationFeesDisabled, navigate]);

  const currencyStrings = useTranslatedFiatStrings(
    fiatAsset.currency?.symbol ?? 'fiat',
  );

  return (
    <VStack flexGrow={1} alignItems="center" spacingHorizontal={gutter}>
      <Spacer flexGrow={1} />
      <HeroSquare name="bitcoinAndOtherCrypto" />
      <TextTitle3 align="center" spacingTop={3} spacingBottom={2}>
        {formatMessage(messages.title, { fiat: currencyStrings?.pluralName })}
      </TextTitle3>
      <TextBody align="center" color="foregroundMuted">
        {formatMessage(
          zeroLiquidationFeesDisabled
            ? messages.subtitle
            : messages.subtitleNoLiquidationFees,
          { fiat: currencyStrings?.pluralName },
        )}
      </TextBody>
      <Spacer flexGrow={2} />
      <Button
        block
        variant="primary"
        spacingTop={1}
        onPress={handleSpendFiatPressed}
        disabled={isUpdating}
        loading={isUpdating}
        testID="spend-fiat-cta"
      >
        {formatMessage(messages.spendFiatCta, {
          fiat: currencyStrings?.pluralName,
        })}
      </Button>
      <Button
        block
        variant="secondary"
        accessibilityLabel={formatMessage(
          messages.secondaryButtonCtaAccessibilityLabel,
        )}
        onPress={handleSpendCryptoPressed}
        disabled={isUpdating}
      >
        {formatMessage(messages.secondaryButtonCta)}
      </Button>
    </VStack>
  );
});

export const SpendFiatOrCryptoScreen = memo(() => {
  return (
