import { IssuerRewardInfoContentFragment$key } from './__generated__/IssuerRewardInfoContentFragment.graphql';

const i18nKey = 'IssuerRewardInfoContent';
const messages = defineMessages({
  pastYear: {
    id: `${i18nKey}.pastYear`,
    defaultMessage: 'Past year',
    description: 'Price change in the past year',
  },
  currencyIconLabel: {
    id: `${i18nKey}.currencyIconLabel`,
    defaultMessage: 'Currency image icon',
    description: 'Currency image icon label',
  },
  expirationLabel: {
    id: `${i18nKey}.expirationLabel`,
    defaultMessage: 'Ends {date}',
    description: 'Expiration date text',
  },
  rewardEarningTitle: {
    id: `${i18nKey}.rewardEarningTitle`,
    defaultMessage: '{percent}% back in {asset}',
    description: 'Title showing percentage being earned in rewards',
  },
});

type IssuerRewardInfoContentProps = {
  rewardProgramId: string;
  ctaText: string;
  onCtaPress: () => void;
  queryRef: IssuerRewardInfoContentFragment$key;
};

export const IssuerRewardInfoContent = memo<IssuerRewardInfoContentProps>(
  ({
    ctaText,
    onCtaPress,
    queryRef,
    rewardProgramId,
  }: IssuerRewardInfoContentProps) => {
    const { viewer } = useFragment(
      graphql`
        fragment IssuerRewardInfoContentFragment on Query
        @argumentDefinitions(assetId: { type: "Uuid!" }) {
          viewer @required(action: THROW) {
            card @required(action: THROW) {
              rewardPrograms @required(action: THROW) {
                rewardPrograms {
                  uuid
                  percentEarned
                  isCB1BoostActive
                  boostedPercentEarned
                  assetEarned {
                    # eslint-disable-next-line @graphql-eslint/no-deprecated
                    description
                    imageUrl
                    platformName
                    name
                  }
                  expirationDate
                }
              }
            }
            assetByUuid(uuid: $assetId) {
              asset {
                uuid
                latestPrice(quoteCurrency: $nativeCurrency) {
                  percentChanges {
                    year
                  }
                }
              }
            }
          }
        }
      `,
      queryRef,
    );

    const asset = viewer.assetByUuid?.asset;
    const { rewardPrograms } = viewer.card.rewardPrograms;

    const rewardProgram = useMemo(() => {
      return rewardPrograms.find((r) => r.uuid === rewardProgramId);
    }, [rewardProgramId, rewardPrograms]);
    const expirationDate = rewardProgram?.expirationDate;

    const killedRewardsPricePercentChange = useKillSwitch(
      'kill_rewards_price_percentage_change',
    );

    const { formatMessage, formatNumber } = useIntl();
    const formatPercentChange = usePercentChangeFormatter();
    const formattedPricePercentChange = useMemo(() => {
      const { variant, sign, percent } = formatPercentChange({
        value: asset?.latestPrice?.percentChanges?.year ?? 0,
      });
      return <TextHeadline color={variant}>{sign + percent}</TextHeadline>;
    }, [asset?.latestPrice?.percentChanges?.year, formatPercentChange]);

    const formatRewardExpirationDate = useRewardExpirationDateFormatter();
    const expirationDateFormatted = useMemo(() => {
      if (expirationDate) {
        return formatMessage(messages.expirationLabel, {
          date: formatRewardExpirationDate(expirationDate),
        });
      }
      return null;
    }, [expirationDate, formatMessage, formatRewardExpirationDate]);

    const rewardProgramPercent = useMemo(
      () =>
        rewardProgram?.isCB1BoostActive && rewardProgram?.boostedPercentEarned
          ? formatNumber(Number(rewardProgram?.boostedPercentEarned), {
              maximumFractionDigits: 2,
            })
          : rewardProgram?.percentEarned,
      [
        formatNumber,
        rewardProgram?.boostedPercentEarned,
        rewardProgram?.isCB1BoostActive,
        rewardProgram?.percentEarned,
      ],
    );

    return (
      <VStack gap={1}>
        <CurrencyIconFromUrl
          imageUrl={rewardProgram?.assetEarned.imageUrl ?? ''}
          size="button"
          accessibilityLabel={formatMessage(messages.currencyIconLabel)}
        />
        <TextTitle3 spacingTop={1}>
          {formatMessage(messages.rewardEarningTitle, {
            percent: rewardProgramPercent,
            asset: rewardProgram?.assetEarned.name,
          })}
        </TextTitle3>
        <HStack gap={0.5}>
          {killedRewardsPricePercentChange || !asset ? null : (
            <>
              <Icon
                size="s"
                color="foregroundMuted"
                name="chartLine"
                spacingVertical={0.5}
                spacingEnd={2}
              />
              <HStack gap={0.5}>
                {formattedPricePercentChange}
                <TextHeadline color="foregroundMuted">
                  {formatMessage(messages.pastYear)}
                </TextHeadline>
              </HStack>
            </>
          )}
        </HStack>
        {!!expirationDateFormatted && (
          <HStack gap={0.5}>
            <Icon
              size="s"
              color="foregroundMuted"
              name="clockOutline"
              spacingVertical={0.5}
              spacingEnd={2}
            />
            <TextBody color="foregroundMuted">
              {expirationDateFormatted}
            </TextBody>
          </HStack>
        )}

        <TextBody color="foregroundMuted" spacingTop={1}>
          {rewardProgram?.assetEarned.description}
        </TextBody>
        <Button spacingTop={3} spacingBottom={0} onPress={onCtaPress}>
          {ctaText}
        </Button>
      </VStack>
    );
  },
);

