type SpendableAssets = NonNullable<
  NonNullable<
    CardSpendableAssetContentFragment$data['viewer']['card']
  >['spendableAssets']
>;

export type SpendableAssetType = ExtractFromArray<SpendableAssets['assets']>;

export type CardSpendableAssetsListSpendableAsset = {
  spendableAsset: SpendableAssetType;
  convertedSpendableAsset: CardCurrency | undefined;
};

export type CardSpendableAssetContentProps = {
  queryRef: CardSpendableAssetContentFragment$key;
  onCompleted: ({
    convertedSpendableAsset,
    spendableAsset,
  }: CardSpendableAssetsListSpendableAsset) => void;
  onError: ({ alreadyReportedError }: { alreadyReportedError: Error }) => void;
  onDisclaimer: ({
    convertedSpendableAsset,
    spendableAsset,
  }: CardSpendableAssetsListSpendableAsset) => void;
  currentAssetUuid: string | undefined;
  isInIssuanceFlow?: boolean;
};

const CardSpendableAssetContainer = memo<CardSpendableAssetContentProps>(
  ({
    queryRef,
    onCompleted,
    onError,
    onDisclaimer,
    currentAssetUuid,
    isInIssuanceFlow,
  }) => {
    const [selectedAssetUuid, setSelectedAssetUuid] = useState<
      string | undefined
    >(currentAssetUuid);
    const { formatMessage } = useIntl();
    const { updateSpendableAsset, isUpdating } = useSetSpendableAsset();
    const { setIsSearching, isSearching } = useSearchBar();
    const [searchText, setSearchText] = useState('');
    const searchTextTrimmed = searchText.trim();
    const query = useFragment(
      graphql`
        fragment CardSpendableAssetContentFragment on Query {
          viewer @required(action: THROW) {
            card @required(action: THROW) {
              spendableAssets @required(action: THROW) {
                assets {
                  ...CardSpendableAssetListCellFragment
                  assetOrFiatCurrency {
                    ...useAssetOrCardFiatFragment
                  }
                  fiatBalanceAvailable {
                    value
                  }
                  supplementaryInfo {
                    title
                  }
                }
              }
            }
            userProperties {
              zeroLiquidationFeesEnabled: isFeatureFlagEnabled(
                flag: "2022.mar.card_zero_liquidation_fees"
              )
            }
          }
        }
      `,
      queryRef,
    );
    const { navigate } = useStackNavigation();
    const zeroLiquidationFeesDisabled =
      !query.viewer.userProperties.zeroLiquidationFeesEnabled;

    const rawSpendableAssets = query.viewer.card.spendableAssets.assets;

    const convertedSpendableAssets = useMemo<
      CardSpendableAssetsListSpendableAsset[]
    >(() => {
      const excludeSymbols = isInIssuanceFlow ? ['USD'] : [];
      const newSpendableAssets = rawSpendableAssets.map((spendableAsset) => ({
        spendableAsset,
        convertedSpendableAsset: convertSpendableAsset(
          spendableAsset.assetOrFiatCurrency,
        ),
      }));

      return excludeSymbols
        ? newSpendableAssets.filter(({ convertedSpendableAsset }) => {
            return !excludeSymbols.includes(
              convertedSpendableAsset?.symbol ?? '',
            );
          })
        : newSpendableAssets;
    }, [rawSpendableAssets, isInIssuanceFlow]);

    const filteredAssets = useMemo<
      CardSpendableAssetsListSpendableAsset[]
    >(() => {
      const filter = searchTextTrimmed.toLowerCase();
      return convertedSpendableAssets.filter(({ convertedSpendableAsset }) => {
        if (!convertedSpendableAsset) {
          return false;
        }

        return (
          convertedSpendableAsset.symbol.toLowerCase().includes(filter) ||
          convertedSpendableAsset.name.toLowerCase().includes(filter)
        );
      });
    }, [searchTextTrimmed, convertedSpendableAssets]);

    const handleSpendableAssetSelect = useCallback(
      (assetUuid: string) => {
        if (!isUpdating) {
          setSelectedAssetUuid(assetUuid);
        }
      },
      [isUpdating],
    );

    const currentSelectedAsset = useMemo(
      () =>
        convertedSpendableAssets.find(
          ({ convertedSpendableAsset }) =>
            convertedSpendableAsset?.uuid === selectedAssetUuid,
        ),
      [convertedSpendableAssets, selectedAssetUuid],
    );

    const currentSelectedAssetSymbol =
      currentSelectedAsset?.convertedSpendableAsset?.symbol;
    const currentSelectedAssetUuid =
      currentSelectedAsset?.convertedSpendableAsset?.uuid;
    const hasCurrentSelectedAssetSupplementaryInfo =
      currentSelectedAsset?.spendableAsset?.supplementaryInfo?.title;

    const onSubmitSelectedAsset = useCallback(() => {
      if (!currentSelectedAssetSymbol) {
        return;
      }

      if (
        zeroLiquidationFeesDisabled &&
        hasCurrentSelectedAssetSupplementaryInfo &&
        currentSelectedAssetUuid
      ) {
        onDisclaimer(currentSelectedAsset);
        return;
      }

      const config: spendableMutationProps = {
        variables: {
          input: {
            assetSymbol: currentSelectedAssetSymbol,
          },
        },
        onCompleted: () => {
          onCompleted(currentSelectedAsset);
          navigate('AssetSelectionSuccess', {});
        },
        onError,
      };
      updateSpendableAsset(config);
    }, [
      currentSelectedAsset,
      currentSelectedAssetSymbol,
      currentSelectedAssetUuid,
      hasCurrentSelectedAssetSupplementaryInfo,
      zeroLiquidationFeesDisabled,
      navigate,
      onCompleted,
      onDisclaimer,
      onError,
      updateSpendableAsset,
    ]);
    const searchPlaceHolder = formatMessage(messages.searchPlaceHolderText);
    return (
      <>
        {!isSearching && (
          <TextBody
            spacingHorizontal={gutter}
            spacingTop={0}
            spacingBottom={3}
            color="foregroundMuted"
          >
            {formatMessage(messages.description)}
          </TextBody>
        )}
        <Box spacingHorizontal={2}>
          <SearchInput
            testID="SearchBar-TextInput"
            value={searchText}
            onChangeText={setSearchText}
            onSearch={() => setIsSearching(!isSearching)}
            placeholder={searchPlaceHolder}
          />
        </Box>

        <ScrollView
          scrollEnabled={filteredAssets.length > 0}
          testID="CardSpendableAssetScreenAssetsList"
          removeClippedSubviews={device.isAndroid}
        >
          <VStack spacingHorizontal={0} spacingVertical={1}>
            {filteredAssets.length > 0 ? (
              filteredAssets.map(
                ({ spendableAsset, convertedSpendableAsset }, index) => {
                  const currencyUuid = convertedSpendableAsset?.uuid || '';
                  return (
                    <CardSpendableAssetListCell
                      // eslint-disable-next-line react/no-array-index-key
                      key={`${currencyUuid}_${index}`}
                      spendableAssetRef={spendableAsset}
                      selected={currencyUuid === selectedAssetUuid}
                      onPress={handleSpendableAssetSelect}
                    />
                  );
                },
              )
            ) : (
              <TextBody>
                {formatMessage(messages.noResults, {
                  query: searchTextTrimmed,
                })}
              </TextBody>
            )}
          </VStack>
        </ScrollView>
        <Divider />
        <Button
          accessibilityLabel={formatMessage(messages.ctaAcessibilityLabel)}
          disabled={selectedAssetUuid === undefined}
          loading={isUpdating}
          spacingVertical={2}
          spacingHorizontal={gutter}
          onPress={onSubmitSelectedAsset}
        >
          {isInIssuanceFlow && currentSelectedAssetSymbol
            ? formatMessage(messages.ctaText, {
                assetSymbol: currentSelectedAssetSymbol,
              })
            : formatMessage(messages.button)}
        </Button>
      </>
    );
  },
);

export const CardSpendableAssetContent = memo<CardSpendableAssetContentProps>(
  (props) => {
    return (
      <SearchForm.Provider onSubmit={noop}>
        <CardSpendableAssetContainer {...props} />
      </SearchForm.Provider>
    );
  },
);

