function CalculateLocalDate(date: Date): Date {
  return new Date(date.getTime() - date.getTimezoneOffset() * 60 * 1000);
}

type DateRangeOption = {
  start: Date;
  end: Date;
  optionText: string;
};

type TransactionStatusOption = {
  option: CardTransactionStatus;
  optionText: string;
};

type CardTransactionFiltersProps = {
  prevTransactionStatuses?: CardTransactionStatus[];
  prevDateOption?: string;
  prevStartDate?: string;
  prevEndDate?: string;
};

function CardTransactionFilters({
  prevTransactionStatuses = [],
  prevDateOption = '',
  prevStartDate,
  prevEndDate,
}: CardTransactionFiltersProps) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const [startDate, setStartDate] = useState(
    prevStartDate ? new Date(prevStartDate) : new Date(0),
  );
  const [endDate, setEndDate] = useState(
    prevEndDate ? new Date(prevEndDate) : new Date(),
  );
  // true if checkbox appears checked to user
  const [isAllStatusesBoxChecked, { toggle: setIsAllStatusesBoxChecked }] =
    useToggler(true);

  // Note: months are zero-indexed but days are not
  const dateRange: DateRangeOption[] = useMemo(() => {
    const today = new Date();
    const allTransactionsOption: DateRangeOption = {
      start: new Date(0),
      end: today,
      optionText: formatMessage(messages.allTransactionsOption),
    };
    const past30DaysOption: DateRangeOption = {
      start: CalculateLocalDate(
        new Date(new Date().setDate(new Date().getDate() - 30)),
      ),
      end: today,
      optionText: formatMessage(messages.past30DaysOption),
    };
    const past90DaysOption: DateRangeOption = {
      start: CalculateLocalDate(
        new Date(new Date().setDate(new Date().getDate() - 90)),
      ),
      end: today,
      optionText: formatMessage(messages.past90DaysOption),
    };
    const yearToDateOption: DateRangeOption = {
      start: new Date(new Date().getFullYear(), 0, 1),
      end: today,
      optionText: formatMessage(messages.yearToDateOption),
    };
    const previousYearOption: DateRangeOption = {
      start: new Date(new Date().getFullYear() - 1, 0, 1),
      end: new Date(new Date().getFullYear() - 1, 11, 31),
      optionText: formatMessage(messages.previousYearOption, {
        year: String(new Date().getFullYear() - 1),
      }),
    };
    return [
      allTransactionsOption,
      past30DaysOption,
      past90DaysOption,
      yearToDateOption,
      previousYearOption,
    ];
  }, [formatMessage]);

  const [dateRangeOption, setDateRangeOption] = useState(
    Object.keys(prevDateOption).length === 0
      ? Object.keys(dateRange)[0]
      : prevDateOption.toString(),
  );

  const transactionStatusOptions: TransactionStatusOption[] = useMemo(() => {
    const completed: TransactionStatusOption = {
      option: 'COMPLETED',
      optionText: formatMessage(messages.completedOption),
    };
    const declined: TransactionStatusOption = {
      option: 'DECLINED',
      optionText: formatMessage(messages.declinedOption),
    };
    const pending: TransactionStatusOption = {
      option: 'PENDING',
      optionText: formatMessage(messages.pendingOption),
    };
    const canceled: TransactionStatusOption = {
      option: 'CANCELED',
      optionText: formatMessage(messages.canceledOption),
    };
    const disputed: TransactionStatusOption = {
      option: 'DISPUTED',
      optionText: formatMessage(messages.disputedOption),
    };
    return [completed, declined, pending, canceled, disputed];
  }, [formatMessage]);

  const statusOptions = useMemo(() => {
    return Object.values(transactionStatusOptions).map((item) => item.option);
  }, [transactionStatusOptions]);

  const [selectedTransactionStatuses, { toggle }] = useCheckboxGroupState(
    // set of all options
    statusOptions,
    // options checked by default upon entering page
    prevTransactionStatuses.length === 0
      ? statusOptions
      : Array.from(prevTransactionStatuses),
  );

  // when one of the other checkboxes is toggled, we need to determine if
  // 'All status types' needs to be automatically toggled to reflect update
  useEffect(() => {
    // if it is already checked
    if (isAllStatusesBoxChecked) {
      if (selectedTransactionStatuses.size !== 5) {
        // uncheck it
        setIsAllStatusesBoxChecked();
      }
      // if it is not checked
    } else if (selectedTransactionStatuses.size === 5) {
      // check it
      setIsAllStatusesBoxChecked();
    }
  }, [
    isAllStatusesBoxChecked,
    selectedTransactionStatuses,
    setIsAllStatusesBoxChecked,
  ]);

  // we need to either select all, or unselect all, based on value of isAllStatusesBoxChecked
  const handleSelectAll = useCallback(() => {
    setIsAllStatusesBoxChecked();
    if (isAllStatusesBoxChecked) {
      for (const status of statusOptions) {
        if (selectedTransactionStatuses.has(status)) {
          toggle(status);
        }
      }
    } else {
      for (const status of statusOptions) {
        if (!selectedTransactionStatuses.has(status)) {
          toggle(status);
        }
      }
    }
  }, [
    isAllStatusesBoxChecked,
    selectedTransactionStatuses,
    setIsAllStatusesBoxChecked,
    statusOptions,
    toggle,
  ]);

  const handleReset = useCallback(() => {
    setDateRangeOption(Object.keys(dateRange)[0]);
    for (const status of statusOptions) {
      if (!selectedTransactionStatuses.has(status)) {
        toggle(status);
      }
    }
    setStartDate(new Date(0));
    setEndDate(new Date());
  }, [dateRange, selectedTransactionStatuses, statusOptions, toggle]);

  const handleApply = useCallback(() => {
    navigate('CoinbaseCardTransactions', {
      selectedTransactionStatuses: Array.from(selectedTransactionStatuses),
      startDate: startDate.toDateString(),
      endDate: endDate.toDateString(),
      selectedDateOption: dateRangeOption,
    });
  }, [
    navigate,
    selectedTransactionStatuses,
    startDate,
    endDate,
    dateRangeOption,
  ]);

  const handleSelectDateRange = useCallback(
    (selectedOption: string, start: Date, end: Date) => {
      setDateRangeOption(selectedOption);
      setStartDate(start);
      setEndDate(end);
    },
    [setDateRangeOption, setStartDate, setEndDate],
  );

  const navHeader = useMemo(() => {
    return {
      action: 'back' as const,
      bordered: false,
      title: formatMessage(messages.title),
      trailing: (
        <TextHeadline color="primary" onPress={handleReset} spacing={0}>
          {formatMessage(messages.reset)}
        </TextHeadline>
      ),
      animate: false,
    } as const;
  }, [formatMessage, handleReset]);

  return (
    <Screen
      navHeader={navHeader}
      scrollable={false}
      spacingStart={0}
      spacingEnd={0}
    >
      <ScrollView>
        <VStack gap={2} flexBasis={1} flexGrow={1} spacingStart={3}>
          <TextTitle3>{formatMessage(messages.dateFiltersHeading)}</TextTitle3>
          {Object.entries(dateRange).map(([key, value]) => (
            <VStack key={value.optionText}>
              <RadioGroup
                options={{ [key]: value.optionText }}
                value={dateRangeOption}
                onChange={() =>
                  handleSelectDateRange(key, value.start, value.end)
                }
              />
            </VStack>
          ))}
          <TextTitle3 spacingTop={2}>
            {formatMessage(messages.statusFiltersHeading)}
          </TextTitle3>
          <Box spacingBottom={1}>
            <Checkbox
              onChange={handleSelectAll}
              checked={isAllStatusesBoxChecked}
            >
              {formatMessage(messages.allStatusesOption)}
            </Checkbox>
          </Box>
          <CheckboxGroup
            accessibilityLabel={formatMessage(messages.statusFiltersHeading)}
            selectedValues={selectedTransactionStatuses}
            onChange={toggle}
          >
            {Object.entries(transactionStatusOptions).map(([key, value]) => (
              <Checkbox key={key} value={value.option}>
                {
                  // eslint-disable-next-line react-native/no-raw-text
                  `${value.optionText}\n`
                }
              </Checkbox>
            ))}
          </CheckboxGroup>
        </VStack>
      </ScrollView>
      <Divider />
      <Button
        spacingVertical={2}
        spacingHorizontal={gutter}
        onPress={handleApply}
        disabled={selectedTransactionStatuses.size === 0}
      >
        {formatMessage(messages.applyFiltersButton)}
      </Button>
    </Screen>
  );
}

export const CardTransactionsFiltersScreen = memo(() => {
  const {
    selectedTransactionStatuses,
