  );
});

import { memo, useCallback, useEffect, useMemo, useRef } from 'react';
import { GestureResponderEvent, ScrollView } from 'react-native';
import { PaletteValue, useSpectrum } from '@cbhq/cds-common';
import { gutter } from '@cbhq/cds-common/tokens/sizing';
import { CellMedia, ListCell } from '@cbhq/cds-mobile/cells';
import { VStack } from '@cbhq/cds-mobile/layout';
import {
  TextBody,
  TextHeadline,
  TextTitle2,
} from '@cbhq/cds-mobile/typography';
import { paletteValueToHex } from '@cbhq/cds-mobile/utils/palette';
import { graphql, useFragment, useRelayEnvironment } from '@cbhq/data-layer';
import { useIntl } from '@cbhq/i18n';

import { HeaderVariant } from '@designSystem/types';

import { Button } from '@components/interactables/Button';
import { getPriceScale } from '@utils/number/priceUtils';
import { VisibilityTracker } from '@app/components/Analytics/VisibilityTracker';
import { fetchAssetIdBySymbolOrSlug } from '@app/components/navigation/DeepLinking/fetchAssetIdBySymbolOrSlug/fetchAssetIdBySymbolOrSlug';
import { NetworkBoundary } from '@app/components/NetworkBoundary';
import { useSetTradeAnalyticsContext } from '@app/contexts/TradeAnalyticsContext';
import { useNativeCurrencyFormatter } from '@app/hooks/formatters/useNativeCurrencyFormatter';
import { usePercentChangeFormatter } from '@app/hooks/formatters/usePercentChangeFormatter';
import { useDeepLinking } from '@app/hooks/navigation/useDeepLinking';
import { useStackNavigation } from '@app/hooks/navigation/useStackNavigation';
import { messages } from '@app/screens/CryptoRundown/messages';
import { UIComponentAnalyticsProps } from '@app/screens/HomeTab/analytics';
import { imageUrlParser } from '@app/screens/HomeTab/homeFeedCard/imageUrlParser';
import { PAGE_KEYS } from '@app/utils/analytics/pagekeys';
import { errorVitals } from '@app/utils/errors/errorVitals';

import {
  useCryptoRundownCardViewTracker,
  useCryptoRundownCTATracking,
  useCryptoRundownEntityTracking,
} from '../../Analytics';
import { CRDTouchSurface } from '../../CryptoRundownScreen';
import { useIsValidHexColor } from '../../hooks/useIsValidHexColor';

import {
  CryptoRundownCardFragment$key,
  UIComponentEntityType,
} from './__generated__/CryptoRundownCardFragment.graphql';
import { CryptoRundownCardBoundary } from './CryptoRundownCardBoundary';
import { CryptoRundownCardErrorFallback } from './CryptoRundownCardErrorFallback';
import { CryptoRundownCardFallback } from './CryptoRundownCardFallback';
import { CryptoRundownCardImage, ShapeTypeMap } from './CryptoRundownCardImage';

const EntityDataType: Record<string, UIComponentEntityType> = {
  ASSET: 'ENTITY_TYPE_ASSET',
  CUSTOM: 'ENTITY_TYPE_CUSTOM',
};

type EntityData = {
  title?: string;
  description?: string;
  iconUrl?: string;
  detail?: string;
  subDetail?: string;
  action?: {
    text: string;
    url: string;
  };
  variant?: HeaderVariant;
  slug?: string;
};

type CryptoRundownCardParams = {
  cardRef: CryptoRundownCardFragment$key;
  OnPrev: (surface: CRDTouchSurface) => void;
  OnNext: (surface: CRDTouchSurface) => void;
  cardId?: string;
  onTouchEnd: (
    e: GestureResponderEvent,
    position: 'start' | 'end' | 'story',
  ) => void;
  uicomponent: UIComponentAnalyticsProps;
};

const CryptoRundownCardContent = memo<CryptoRundownCardParams>(
  function CryptoRundownCardContent({
    cardRef,
    cardId,
    onTouchEnd,
    uicomponent,
  }) {
    const cardData = useFragment(
      graphql`
        fragment CryptoRundownCardFragment on CryptoRundownComponent {
          title {
            text
            color
          }
          subtitle {
            text
            color
          }
          description {
            text
            color
          }
          takeaway {
            text
            color
          }
          image {
            url
            description
            shape
          }
          primaryCta {
            text @required(action: LOG)
            url @required(action: LOG)
            isExternalLink
          }
          secondaryCta {
            text @required(action: LOG)
            url @required(action: LOG)
            isExternalLink
          }
          backgroundColor
          relevantEntities {
            entityType
            entity {
              __typename
              ... on UIComponentCustomEntity {
                __typename
                title
                description
                detail
                subDetail
                iconUrl
                action {
                  text @required(action: LOG)
                  url @required(action: LOG)
                }
              }

              ... on RelevantAssetsData {
                __typename
                name @required(action: LOG)
                symbol @required(action: LOG)
                slug @required(action: LOG)
                assetIconUrl: iconUrl @required(action: LOG)
                assetStats {
                  dayPricePercentChange
                  price
                }
              }
            }
          }
        }
      `,
      cardRef,
    );

    const title = cardData?.title;
    const description = cardData?.description;
    const subtitle = cardData?.subtitle;
    const takeaway = cardData?.takeaway;
    const image = cardData?.image;
    const primaryCta = cardData?.primaryCta;
    const secondaryCta = cardData?.secondaryCta;
    const backgroundColor = cardData?.backgroundColor;

    const entityType = cardData?.relevantEntities?.[0]?.entityType;
    const entity = cardData?.relevantEntities?.[0]?.entity;

    const relayEnvironment = useRelayEnvironment();
    const { formatMessage } = useIntl();
    const formatPercentChange = usePercentChangeFormatter();
    const formatNativeCurrency = useNativeCurrencyFormatter();
    const isValidHexColor = useIsValidHexColor();
    const spectrum = useSpectrum();

    const entityData: EntityData | undefined = useMemo(() => {
      if (
        entityType === EntityDataType.ASSET &&
        entity?.__typename === 'RelevantAssetsData'
      ) {
        const assetStats = entity?.assetStats;

        const assetPrice = formatNativeCurrency({
          isSensitive: false,
          amount: assetStats?.price ?? '',
          minimumFractionDigits: getPriceScale(assetStats?.price ?? '0'),
        });
        const formattedPercentChange = formatPercentChange({
          value: assetStats?.dayPricePercentChange ?? '',
        });
        return {
          title: entity?.name ?? '',
          description: entity?.symbol ?? '',
          iconUrl: imageUrlParser(entity?.assetIconUrl ?? ''),
          detail: assetPrice,
          subDetail: `${formattedPercentChange.sign}${formattedPercentChange.percent}`,
          variant: formattedPercentChange.variant,
          slug: entity?.slug ?? '',
        };
      }

      if (
        entityType === EntityDataType.CUSTOM &&
        entity?.__typename === 'UIComponentCustomEntity'
      ) {
        return {
          title: entity?.title ?? '',
          description: entity?.description ?? '',
          iconUrl: imageUrlParser(entity?.iconUrl ?? ''),
          detail: entity?.detail ?? '',
          subDetail: entity.subDetail ?? '',
          action: entity.action
            ? {
                text: entity.action.text ?? '',
                url: entity.action.url ?? '',
              }
            : undefined,
        };
      }

      return undefined;
    }, [entity, entityType, formatNativeCurrency, formatPercentChange]);

    const navigateToDeepLink = useDeepLinking();
    const scrollViewRef = useRef<ScrollView>(null);
    const { setEntryComponent, setAssetEntryPage } =
      useSetTradeAnalyticsContext();

    const {
      ctaViewEventData: primaryCtaViewEventData,
      trackCTAClick: trackPrimaryCTAClick,
    } = useCryptoRundownCTATracking({
      ctaType: 'PRIMARY',
      text: primaryCta?.text ?? '',
      url: primaryCta?.url ?? '',
      storyId: cardId,
      uicomponent,
    });

    const {
      ctaViewEventData: secondaryCtaViewEventData,
      trackCTAClick: trackSecondaryCTAClick,
    } = useCryptoRundownCTATracking({
      ctaType: 'SECONDARY',
      text: secondaryCta?.text ?? '',
      url: secondaryCta?.url ?? '',
      storyId: cardId,
      uicomponent,
    });

    const handlePrimaryCTAPress = useCallback(() => {
      if (!primaryCta?.url) {
        return;
      }

      const url: string = primaryCta?.url;

      trackPrimaryCTAClick();

      navigateToDeepLink({
        url,
        fallbackOnInvalidDeepLink: true,
      });
    }, [navigateToDeepLink, primaryCta?.url, trackPrimaryCTAClick]);

    const handleSecondaryCTAPress = useCallback(() => {
      if (!secondaryCta?.url) {
        return;
      }

      const url: string = secondaryCta?.url;

      trackSecondaryCTAClick();

      navigateToDeepLink({
        url,
        fallbackOnInvalidDeepLink: true,
      });
    }, [navigateToDeepLink, secondaryCta?.url, trackSecondaryCTAClick]);

    const { navigate } = useStackNavigation();

    const { entityViewEventData, trackEntityClick } =
      useCryptoRundownEntityTracking({
        title: entityData?.title ?? '',
        entityType: entityType ?? undefined,
        storyId: cardId,
        uicomponent,
      });

    const handleListCellPress = useCallback(
      (e: GestureResponderEvent) => {
        e?.preventDefault();
        e?.stopPropagation();

        if (entityType === EntityDataType.ASSET) {
          if (!entityData?.slug) {
            return;
          }

          setAssetEntryPage(PAGE_KEYS.CryptoRundown);
          setEntryComponent(`crypto-rundown-card-${cardId}`);

          trackEntityClick();
          // todo: remove this query by exposing uuid on RelevantAssetsData
          fetchAssetIdBySymbolOrSlug(entityData?.slug, relayEnvironment).then(
            (assetId) => {
              if (assetId) {
                navigate('Asset', {
                  assetId,
                });
              } else {
                navigate('UniversalSearch', {
                  initialSearchQuery: entityData?.slug,
                });
              }
            },
          );
          return;
        }

        if (entityData?.action) {
          navigateToDeepLink({
            url: entityData?.action?.url ?? '',
            fallbackOnInvalidDeepLink: true,
          });
        }
      },
      [
        cardId,
        entityData?.action,
        entityData?.slug,
        entityType,
        navigate,
        navigateToDeepLink,
        relayEnvironment,
        setAssetEntryPage,
        setEntryComponent,
        trackEntityClick,
      ],
    );

    const trackview = useCryptoRundownCardViewTracker({
      componentName: 'story',
      uicomponent,
      storyId: cardId,
    });

    useEffect(() => {
      trackview();
    }, [trackview, cardId]);

    useEffect(() => {
      scrollViewRef.current?.scrollTo({ y: 0, x: 0, animated: false });
    }, [cardId]);

    const handleTouchEnd = useCallback(
      (e: GestureResponderEvent) => {
        onTouchEnd(e, 'story');
      },
      [onTouchEnd],
    );

    const entityListCell = useMemo(() => {
      const listAction = entityData?.action ? (
        <Button
          onPress={handleListCellPress}
          compact
          spacingBottom={0}
          noScaleOnPress
          variant="primary"
        >
          {entityData?.action.text}
        </Button>
      ) : undefined;

      const listMedia = entityData?.iconUrl ? (
        <CellMedia
          type="asset"
          source={entityData?.iconUrl ?? ''}
          accessibilityLabel={entityData?.title}
        />
      ) : undefined;

      return (
        <>
          {!!entityData && (
            <VisibilityTracker
              eventName={entityViewEventData.name}
              eventData={entityViewEventData.data}
            >
              <ListCell
                testID="crypto-rundown-listcell"
                title={entityData?.title}
                description={entityData?.description}
                subdetail={entityData?.subDetail}
                variant={entityData?.variant}
                detail={entityData?.detail}
                media={listMedia}
                action={listAction}
                outerSpacing={{
                  spacingHorizontal: 0,
                  spacingTop: 2,
                  spacingBottom: 2,
                }}
                onPress={entityData?.action ? undefined : handleListCellPress}
              />
            </VisibilityTracker>
          )}
        </>
      );
    }, [
      entityData,
      entityViewEventData.data,
      entityViewEventData.name,
      handleListCellPress,
    ]);

    const primaryCTAComponent = useMemo(() => {
      const endIcon = primaryCta?.isExternalLink ? 'externalLink' : undefined;

      return (
        <>
          {!!primaryCta?.text && (
            <VisibilityTracker
              eventName={primaryCtaViewEventData.name}
              eventData={primaryCtaViewEventData.data}
            >
              <Button
                spacingTop={3}
                block
                variant="primary"
                endIcon={endIcon}
                onPress={handlePrimaryCTAPress}
                compact
              >
                {primaryCta?.text?.trim()}
              </Button>
            </VisibilityTracker>
          )}
        </>
      );
    }, [
      primaryCta?.isExternalLink,
      primaryCta?.text,
      primaryCtaViewEventData.name,
      primaryCtaViewEventData.data,
      handlePrimaryCTAPress,
    ]);

    const secondaryCTAComponent = useMemo(() => {
      const endIcon = secondaryCta?.isExternalLink ? 'externalLink' : undefined;

      return (
        <>
          {!!secondaryCta?.text && (
            <VisibilityTracker
              eventName={secondaryCtaViewEventData.name}
              eventData={secondaryCtaViewEventData.data}
            >
              <Button
                spacingTop={primaryCta?.text ? 0 : 3}
                block
                variant="secondary"
                endIcon={endIcon}
                onPress={handleSecondaryCTAPress}
                compact
              >
                {secondaryCta?.text?.trim()}
              </Button>
            </VisibilityTracker>
          )}
        </>
      );
    }, [
      secondaryCta?.isExternalLink,
      secondaryCta?.text,
      secondaryCtaViewEventData.name,
      secondaryCtaViewEventData.data,
      primaryCta?.text,
      handleSecondaryCTAPress,
    ]);

    const finalBackgroundColor = useMemo(() => {
      return backgroundColor
        ? paletteValueToHex(backgroundColor as PaletteValue, spectrum)
        : undefined;
    }, [backgroundColor, spectrum]);

    if (!cardData) {
      return <CryptoRundownCardErrorFallback />;
    }

    return (
      <ScrollView
        key="crypto-rundown-card"
        testID="crypto-rundown-card"
        ref={scrollViewRef}
        onTouchEnd={handleTouchEnd}
      >
        <VStack
          dangerouslySetBackground={finalBackgroundColor}
          spacingHorizontal={gutter}
          flexGrow={1}
          spacingBottom={5}
        >
          <CryptoRundownCardImage
            imageDescription={image?.description ?? ''}
            imageUrl={image?.url ?? ''}
            shape={ShapeTypeMap[image?.shape ?? 'IMAGE_SHAPE_RECTANGLE']}
          />
          <TextTitle2
            dangerouslySetColor={
              title?.color && isValidHexColor(title?.color ?? '')
                ? title?.color
                : undefined
            }
            spacingBottom={1}
          >
            {title?.text?.trim()}
          </TextTitle2>
          <TextBody
            color={
              subtitle?.color && isValidHexColor(subtitle?.color ?? '')
                ? undefined
                : 'foregroundMuted'
            }
            dangerouslySetColor={
              subtitle?.color && isValidHexColor(subtitle?.color ?? '')
                ? subtitle?.color
                : undefined
            }
            spacingBottom={1}
          >
            {subtitle?.text?.trim()}
          </TextBody>
          <TextBody
            dangerouslySetColor={
              description?.color && isValidHexColor(description?.color ?? '')
                ? description?.color
                : undefined
            }
            spacingBottom={takeaway?.text ? 2 : 1}
          >
            {description?.text?.trim()}
          </TextBody>

          {entityListCell}

          {!!takeaway?.text && (
            <TextBody
              dangerouslySetColor={
                takeaway?.color && isValidHexColor(takeaway?.color ?? '')
                  ? takeaway?.color
                  : undefined
              }
              spacingBottom={1}
            >
              <TextHeadline
                dangerouslySetColor={
                  takeaway?.color && isValidHexColor(takeaway?.color ?? '')
                    ? takeaway?.color
                    : undefined
                }
              >{`${formatMessage(messages.takeaway)}: `}</TextHeadline>
              {takeaway?.text?.trim()}
            </TextBody>
          )}

          {primaryCTAComponent}
          {secondaryCTAComponent}
        </VStack>
      </ScrollView>
    );
  },
);

function onCatchCryptoRundownCardError() {
  errorVitals.logError(new Error('Could not render crypto rundown card'), {
    severity: 'error',
    context: 'on_catch_crypto_rundown_card_error',
    card_type: 'story',
    isHandled: true,
  });
}

export const CryptoRundownCard = memo<CryptoRundownCardParams>(
  function CryptoRundownCard({ ...props }) {
    return (
      <NetworkBoundary
        willErrorBlockUser
        suspenseFallback={<CryptoRundownCardFallback />}
        errorFallback={CryptoRundownCardErrorFallback}
        monitoringBoundary={CryptoRundownCardBoundary}
        onCatch={onCatchCryptoRundownCardError}
      >
        <CryptoRundownCardContent {...props} />
      </NetworkBoundary>
    );
  },
);

import { memo, useMemo } from 'react';
import { StatusBar, View, ViewStyle } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { PaletteValue, useSpectrum } from '@cbhq/cds-mobile';
import { HStack } from '@cbhq/cds-mobile/layout';
import { paletteValueToHex } from '@cbhq/cds-mobile/utils/palette';

import { IconButton } from '@components/interactables/IconButton';

type PaginatedTopBarParams = {
  isCoverCard?: boolean;
  currentIndex: number;
  maxCount: number;
  onClose: () => void;
  backgroundColor: PaletteValue;
};

export const PaginatedTopBar = memo<PaginatedTopBarParams>(
  function PaginatedTopBar({
    isCoverCard = false,
    currentIndex,
    maxCount,
    onClose,
    backgroundColor,
  }) {
    const finalBackgroundColor = paletteValueToHex(backgroundColor, 'light');

    const navStyles: ViewStyle = {
      backgroundColor: finalBackgroundColor,
    };

    const paginationBars: JSX.Element[] = useMemo(() => {
      const barList = [];
      for (let index = 0; index < maxCount; index += 1) {
        const isActive = index <= currentIndex;
        barList.push(
          <PaginationBar
            key={`pagination-bar-${index}`}
            isActive={isActive}
            isCoverCard={isCoverCard}
          />,
        );
      }

      return barList;
    }, [currentIndex, isCoverCard, maxCount]);

    return (
      <SafeAreaView edges={['top', 'left', 'right']} style={navStyles}>
        <StatusBar
          barStyle={isCoverCard ? 'light-content' : 'dark-content'}
          backgroundColor={navStyles.backgroundColor}
        />

        <HStack
          background={isCoverCard ? 'primary' : 'background'}
          dangerouslySetBackground={finalBackgroundColor}
          alignItems="center"
          width="100%"
          height={56}
          spacingHorizontal={1}
        >
          <IconButton
            name="close"
            transparentButtonColor={
              isCoverCard ? 'primaryForeground' : 'foreground'
            }
            transparent
            onPress={onClose}
          />
          <HStack
            spacingHorizontal={2}
            height={40}
            width="80%"
            justifyContent="center"
            alignItems="center"
            overflow="hidden"
          >
            {paginationBars}
          </HStack>
        </HStack>
      </SafeAreaView>
    );
  },
);

type PaginationBarParams = {
  isActive: boolean;
  isCoverCard: boolean;
};

const PaginationBar = memo<PaginationBarParams>(function PaginationBar({
  isActive,
  isCoverCard,
}) {
  const spectrum = useSpectrum();

  const backgroundColor = useMemo(() => {
    const activeBar = isCoverCard
      ? paletteValueToHex('gray0', 'light')
      : paletteValueToHex('blue60', spectrum);
    const disabledBar = isCoverCard
      ? paletteValueToHex(['gray80', 0.33], 'light')
      : paletteValueToHex('blue5', spectrum);

    return isActive ? activeBar : disabledBar;
  }, [isActive, isCoverCard, spectrum]);

  return (
    <View
      style={{
        width: 14,
        backgroundColor,
        marginHorizontal: 4,
        height: 3,
        overflow: 'hidden',
        borderRadius: 100,
      }}
    />
  );
});

