import { memo, useCallback, useEffect, useState } from 'react';
import { HStack, Spacer, VStack } from '@cbhq/cds-mobile/layout';
import { TextHeadline, TextLabel1 } from '@cbhq/cds-mobile/typography';

import { Button } from '@components/interactables/Button';
import { TextInput } from '@components/interactables/TextInput';
import { Screen } from '@app/components/Screen';
import {
  deleteSecureData,
  getSecureData,
  setSecureData,
} from '@app/libs/secureStorage/SecureStorage';

const keys = [
  'account_access_token',
  'account_refresh_token',
  'account_auth_code',
  'expires_at',
  'test_secure',
];

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const formattedKeys: any = {
  account_access_token: 'Access Token',
  account_refresh_token: 'Refresh Token',
  account_auth_code: 'Auth Code',
  expires_at: 'Expires At',
  test_secure: 'Text Value',
};

type Setter = Record<string, boolean>;

export const DebugAndroidKeyStoreScreen = memo(() => {
  const [isEnc, setIsEnc] = useState<Setter>({});
  const [encVal, setEncVal] = useState('');
  const [decVal, setDecVal] = useState('');

  const fetchSecureValues = useCallback(() => {
    return keys.map(async (k) => {
      const enc = await isEncrypted(k);
      if (enc) {
        setIsEnc((prev) => ({ ...prev, [k]: !!enc }));
      }
    });
  }, []);

  useEffect(() => {
    fetchSecureValues();
  }, [fetchSecureValues]);

  const isEncrypted = async (key: string) => {
    const enc = await getSecureData(`enc_${key}`);
    return enc;
  };

  return (
    <Screen
      navHeader={{
        action: 'back',
        title: 'Security',
      }}
    >
      {keys.map((k) => (
        <VStack spacingVertical={1} justifyContent="space-between" key={k}>
          <TextHeadline spacing={0}>{formattedKeys[k]}</TextHeadline>
          <HStack justifyContent="space-between" spacing={0}>
            <TextLabel1 spacingBottom={0.5}>Is encrypted: </TextLabel1>
            <TextLabel1 spacingBottom={0.5}>
              {isEnc[k] ? '✅' : '🛑'}
            </TextLabel1>
          </HStack>
        </VStack>
      ))}

      <Spacer />

      <TextInput
        accessibilityLabel="Text input field"
        value={encVal}
        onChange={setEncVal}
        name="enc"
        errors={[]}
        onErrors={() => {}}
        isDirty
      />

      <HStack spacing={0} justifyContent="space-between">
        <Button
          flexBasis="48%"
          onPress={() => {
            void setSecureData('enc_test_secure', encVal);
            fetchSecureValues();
          }}
        >
          Encrypt
        </Button>
        <Button
          flexBasis="48%"
          onPress={async () => {
            const result = await getSecureData('enc_test_secure');
            if (result) {
              setDecVal(result);
            }
          }}
        >
          Decrypt
        </Button>
      </HStack>
      <TextLabel1
        spacingBottom={0.5}
      >{`Decrypted Value: ${decVal}`}</TextLabel1>
      <Button
        onPress={async () => {
          void deleteSecureData('enc_test_secure');
          fetchSecureValues();
          setEncVal('');
          setDecVal('');
        }}
      >
        Clear
      </Button>
    </Screen>
  );
});

