import { SEARCH_RESULT_ICON_SIZE } from '@app/screens/Defi/components/CellIconPlaceholder';
import { DAppIcon } from '@app/screens/Defi/components/DAppIcon';
import { ethereumMainnet } from '@app/screens/Defi/constants';
import { NavigateArgs } from '@app/screens/Defi/requirementScreens/utils/injectNavParams';
import { groupSessions } from '@app/screens/Defi/utils/groupSessions';
import { DappConnectionIcon } from '@app/screens/Settings/DappConnectionListCell';
import { useJoinWalletLinkSession } from '@app/system/walletlink/hooks/useJoinWalletLinkSession';
import {
  HostRequest,
  WalletLinkPendingSession,
  WalletLinkSession,
} from '@app/system/walletlink/types';
import { WalletLinkManager } from '@app/system/walletlink/WalletLinkManager';

import { DebugConnectDappWalletScreenQuery } from './__generated__/DebugConnectDappWalletScreenQuery.graphql';

const navHeader = {
  action: 'back' as const,
  bordered: false,
};

const i18nKey = 'DebugConnectDappWallet';
const messages = defineMessages({
  connectDappTitle: {
    id: `${i18nKey}.connectDappTitle`,
    defaultMessage: 'Connect web3 wallet',
    description: 'Title of connect dapp wallet screen',
  },
  joinSessionTitle: {
    id: `${i18nKey}.joinSessionTitle`,
    defaultMessage: 'Session to join',
    description: 'Title of session to join section',
  },
  scanQR: {
    id: `${i18nKey}.scanQR`,
    defaultMessage: 'Scan QR Code',
    description: 'Scan QR code prompt',
  },
  urlTitle: {
    id: `${i18nKey}.urlTitle`,
    defaultMessage: 'Url',
    description: 'Title of url section',
  },
  requestsTitle: {
    id: `${i18nKey}.requestsTitle`,
    defaultMessage: 'Requests',
    description: 'Title of requests section',
  },
  placeholderURL: {
    id: `${i18nKey}.placeholderURL`,
    defaultMessage: 'WalletLink URL',
    description: 'Placeholder text for TextInput box',
  },
  sessionsTitle: {
    id: `${i18nKey}.sessionsTitle`,
    defaultMessage: 'Sessions',
    description: 'Title of sessions section',
  },
  reconnectWebSocket: {
    id: `${i18nKey}.reconnectWebSocket`,
    defaultMessage: 'Reconnect WebSocket',
    description: 'Reconnect WebSocket button',
  },
});

const statusToColor = {
  Connected: 'positive' as const,
  Connecting: 'primary' as const,
  'Not connected': 'negative' as const,
};

const noHorizontalSpacing = { spacingHorizontal: 0 as const };

// This screen is for the debug menu only.
const DebugConnectDappWallet = memo(function DebugConnectDappWallet() {
  const query = useLazyLoadQuery<DebugConnectDappWalletScreenQuery>(
    graphql`
      query DebugConnectDappWalletScreenQuery {
        ...useJoinWalletLinkSessionFragment
      }
    `,
    {},
  );

  const ethereumWalletPrimaryAddress = useDappWallet().walletAddress ?? '';

  const { formatMessage } = useIntl();

  const walletLinkManager = useMemo(() => WalletLinkManager.getInstance(), []);

  const [
    isCameraVisible,
    { toggleOn: showQRScanner, toggleOff: closeQRScanner },
  ] = useToggler(false);
  const [url, setUrl] = useState<string>('');
  const [sessionToJoin, setSessionToJoin] = useState<
    WalletLinkPendingSession | undefined
  >();
  const [refresh, setRefresh] = useState<boolean>(false);
  const [joinedSessions, setJoinedSessions] = useState<WalletLinkSession[]>(
    Object.values(walletLinkManager.sessions),
  );
  const [requests, setRequests] = useState<HostRequest[]>(
    walletLinkManager.requests,
  );

  const sessionsByDapps: Record<string, WalletLinkSession[]> = useMemo(() => {
    return groupSessions(joinedSessions);
  }, [joinedSessions]);

  const sessionList: WalletLinkSession[] = useMemo(() => {
    const sessions = Object.values(sessionsByDapps).map(
      (walletLinkSessions: WalletLinkSession[]) => walletLinkSessions[0],
    );
    return sessions;
  }, [sessionsByDapps]);

  const returnTo: NavigateArgs = [
    'SettingsModalStack',
    { screen: 'DebugConnectDappWalletScreen', params: {} },
  ];
  const [iteration, setIteration] = useState(0);
  const { joinSession } = useJoinWalletLinkSession({
    returnTo,
    fragmentRef: query,
    onSuccess: () => {
      closeQRScanner();
    },
    onError: () => {
      setIteration((prev) => prev + 1);
      Alert.alert('Failed to join session');
    },
  });

  const reconnectWebSocket = useCallback(async () => {
    const ws = await walletLinkManager.ws;
    if (ws) {
      ws.close();
    }
  }, [walletLinkManager.ws]);

  const [wsStatus, setWsStatus] = useState<keyof typeof statusToColor>(
    walletLinkManager.ws === undefined ? 'Not connected' : 'Connecting',
  );

  useOnMount(() => {
    void (async () => {
      const ws = await walletLinkManager.ws;
      if (ws) {
        setWsStatus('Connected');
      }
    })();
  });

  const handleConnect = useCallback(() => {
    setWsStatus('Connected');
  }, []);
  useEventListener<WalletLinkManager, 'socketOpen'>({
    context: walletLinkManager,
    eventName: 'socketOpen',
    handler: handleConnect,
  });

  const handleDisconnect = useCallback(() => {
    setWsStatus('Not connected');
    setJoinedSessions(Object.values(walletLinkManager.sessions));
  }, [walletLinkManager]);
  useEventListener<WalletLinkManager, 'socketClosed'>({
    context: walletLinkManager,
    eventName: 'socketClosed',
    handler: handleDisconnect,
  });

  const handleConnecting = useCallback(() => {
    setWsStatus('Connecting');
  }, []);
  useEventListener<WalletLinkManager, 'connectSocket'>({
    context: walletLinkManager,
    eventName: 'connectSocket',
    handler: handleConnecting,
  });

  const handleSessionsUpdate = useCallback(
    // @ts-expect-error - this is a valid event handler
    ({ detail: { sessions } }) => {
      setSessionToJoin(undefined);
      setUrl('');

      setJoinedSessions(sessions);
      setRefresh(!refresh);
    },

    [refresh],
  );
  useEventListener<WalletLinkManager, 'joinedSessions'>({
    context: walletLinkManager,
    eventName: 'joinedSessions',
    // @ts-expect-error - this is a valid event handler
    handler: handleSessionsUpdate,
  });
  useEventListener<WalletLinkManager, 'unlinkedSessions'>({
    context: walletLinkManager,
    eventName: 'unlinkedSessions',
    // @ts-expect-error - this is a valid event handler
    handler: handleSessionsUpdate,
  });
  useEventListener<WalletLinkManager, 'destroyedSession'>({
    context: walletLinkManager,
    eventName: 'destroyedSession',
    // @ts-expect-error - this is a valid event handler
    handler: handleSessionsUpdate,
  });

  const handleRequestQueueUpdate = useCallback(() => {
    setRequests(walletLinkManager.requests);
    setJoinedSessions(Object.values(walletLinkManager.sessions));
    setRefresh(!refresh);
  }, [refresh, walletLinkManager]);

  useEventListener<WalletLinkManager, 'receivedRequest'>({
    context: walletLinkManager,
    eventName: 'receivedRequest',
    handler: handleRequestQueueUpdate,
  });

  useEventListener<WalletLinkManager, 'deletedRequest'>({
    context: walletLinkManager,
    eventName: 'deletedRequest',
    handler: handleRequestQueueUpdate,
  });

  const handleDisconnectDapp = useCallback(
    (dappName: string) => {
      void walletLinkManager.unlinkSessions(sessionsByDapps[dappName]);
    },
    [sessionsByDapps, walletLinkManager],
  );

  const connectDapp = useCallback(() => {
    try {
      const parsedQRCode = parseWalletLinkQRCodeText(url);
      if (!(parsedQRCode instanceof URL)) {
        const session = sessionToJoin ?? {
          ...parsedQRCode,
          network: ethereumMainnet,
        };
        setSessionToJoin(session);
        if (session) {
          void walletLinkManager.joinNewSession(
            session,
            ethereumWalletPrimaryAddress,
          );
        }
      }
    } catch (error) {
      Alert.alert(
        error instanceof Error ? error.constructor.name : 'Error',
        'Failed to parse url',
        [{ text: 'Dismiss' }],
      );
    }
  }, [ethereumWalletPrimaryAddress, sessionToJoin, url, walletLinkManager]);

  const wsStatusNode = (
    <TextBody>
      {wsStatus} {wsStatus === 'Connected' && `(${joinedSessions.length})`}
    </TextBody>
  );

  const onScan = useCallback(
    (parsedValue: ParsedWalletLinkResult | URL) => {
      if (!(parsedValue instanceof URL)) {
        joinSession(parsedValue);
      }
    },
    [joinSession],
  );

  return (
    <Screen
      noSpacing
      navHeader={{
        ...navHeader,
        title: formatMessage(messages.connectDappTitle),
      }}
    >
      <VStack spacingHorizontal={gutter} gap={1}>
        <ListCell
          title="WebSocket status"
          action={
            <HStack alignItems="center" gap={1}>
              <DotStatusColor size="xs" variant={statusToColor[wsStatus]} />
              {wsStatusNode}
            </HStack>
          }
          outerSpacing={noHorizontalSpacing}
        />
        <Button
          onPress={reconnectWebSocket}
          variant="negative"
          compact
          spacingBottom={0}
        >
          {formatMessage(messages.reconnectWebSocket)}
        </Button>
        <Button onPress={showQRScanner} compact>
          {formatMessage(messages.scanQR)}
        </Button>
        <Modal
          statusBarTranslucent
          animationType="slide"
          visible={isCameraVisible}
          onRequestClose={closeQRScanner}
        >
          <ConnectDappWalletQRCodeScanner
            onClose={closeQRScanner}
            onScan={onScan}
            iteration={iteration}
          />
        </Modal>

        <HStack alignItems="center" gap={1} width="100%" flexShrink={1}>
          <HStack flexGrow={0} flexShrink={1}>
            <TextInput
              accessibilityLabel="Text input field"
              value={url}
              onChangeText={setUrl}
              placeholder={formatMessage(messages.placeholderURL)}
            />
          </HStack>
          <IconButton
            onPress={connectDapp}
            name="forwardArrow"
            variant="primary"
            accessibilityLabel="Connect"
          />
        </HStack>

        {Boolean(url) && (
          <>
            <TextHeadline>{formatMessage(messages.urlTitle)}</TextHeadline>
            <TextBody selectable="text">{url}</TextBody>
          </>
        )}

        {Boolean(sessionToJoin) && (
          <>
            <TextHeadline>
              {formatMessage(messages.joinSessionTitle)}
            </TextHeadline>
            <TextBody>{JSON.stringify(sessionToJoin, null, 4)}</TextBody>
          </>
        )}
        <>
          <TextHeadline>{formatMessage(messages.sessionsTitle)}</TextHeadline>
          {sessionList.map((item) => {
            return (
              <ListCell
                key={item.id}
                media={<DappConnectionIcon dappConnectionDetails={item} />}
                title={
                  <HStack gap={1} alignItems="center">
                    <TextHeadline>{item.dappName || item.dappUrl}</TextHeadline>
                    {item.isApproved && (
                      <Icon name="checkmark" color="positive" size="s" />
                    )}
                  </HStack>
                }
                description={
                  <HStack gap={1}>
                    <TextBody>
                      {formatMessage(messages.sessionsTitle)}:{' '}
                      {item.dappName
                        ? sessionsByDapps[item.dappName].length
                        : '0'}
                    </TextBody>
                    <TextBody>•</TextBody>
                    <TextBody>{item.network.name}</TextBody>
                  </HStack>
                }
                action={
                  <PressableOpacity
                    onPress={() => {
                      handleDisconnectDapp(item.dappName ?? '');
                    }}
                  >
                    <Icon name="close" color="negative" size="s" />
                  </PressableOpacity>
                }
                priority="end"
                outerSpacing={noHorizontalSpacing}
              />
            );
          })}
        </>
        <>
          <TextHeadline>{formatMessage(messages.requestsTitle)}</TextHeadline>
          {requests.map((item) => {
            return (
              <ListCell
                key={`${item.id} + ${item.method}`}
                media={
                  <DAppIcon
                    iconImageUrl={item.dappIconUrl || ''}
                    borderRadius="roundedFull"
                    size={SEARCH_RESULT_ICON_SIZE}
                  />
                }
                title={item.dappName || item.dappUrl}
                description={item.method}
                outerSpacing={noHorizontalSpacing}
              />
            );
          })}
        </>
      </VStack>
    </Screen>
  );
});

