import { ScreenBoundary } from '@app/components/ScreenBoundary/ScreenBoundary';
import { useNativeCurrency } from '@app/hooks/useNativeCurrency';
import { COINBASE_NFT_KILL_SWITCH } from '@app/screens/CbNft/constants';
import { TrendingNftCollections } from '@app/screens/Defi/DAppBrowser/DappMarketplace/TrendingNftCollections';

import { DebugDappsNFTWebViewScreenQuery } from './__generated__/DebugDappsNFTWebViewScreenQuery.graphql';

const INITIAL_WEBVIEW_URL = `https://nft.coinbase.com?webview=1&platform=${Platform.OS}`;
const NFT_API_URL = 'https://maui-web3-pre-prod.cbhq.net/api/graphql';

const SAMPLE_PAYLOAD = {
  query:
    'query {\n  nftByIdentifiers(input:{standardNftId:"17/35/0xba30e5f9bb24caa003e9f2f0497ad287fdf95623/9406/0"}) {\n      ... on Nft {      id      title      description }\n  }\n}',
};

const navHeader: NavHeaderConfig = {
  title: 'NFT WebView',
};

export const DebugDappsNFTWebViewScreen = memo(() => {
  return (
    <ScreenBoundary instrumentationId="DebugDappsNFTWebViewScreen">
      <Screen navHeader={navHeader} noSpacing>
        <NFTWebView />
      </Screen>
    </ScreenBoundary>
  );
});

const NFTWebView = memo(() => {
  const nativeCurrency = useNativeCurrency();
  const killTrendingNftCollection = useKillSwitch(COINBASE_NFT_KILL_SWITCH);

  const query = useLazyLoadQuery<DebugDappsNFTWebViewScreenQuery>(
    graphql`
      query DebugDappsNFTWebViewScreenQuery(
        $nativeCurrency: TickerSymbol!
        $skipTrendingNftCollection: Boolean!
      ) {
        viewer @required(action: THROW) {
          ...TrendingNftCollectionsFragment
            @arguments(skipTrendingNftCollection: $skipTrendingNftCollection)
        }
      }
    `,
    {
      nativeCurrency,
      skipTrendingNftCollection: killTrendingNftCollection,
    },
  );

  const webViewRef = useRef<WebView>(null);
  const [webViewKey, setWebViewKey] = useState<number>(1);
  const [responseData, setResponseData] = useState<string>();
  const [responseError, setResponseError] = useState<string>();
  const [isApiResponseOpen, setIsApiResponseOpen] = useState<boolean>(false);

  const handleHome = useCallback(() => {
    setWebViewKey(webViewKey + 1);
  }, [webViewKey]);

  const handleReload = useCallback(() => {
    webViewRef?.current?.reload();
  }, []);

  const handleBack = useCallback(() => {
    webViewRef?.current?.goBack();
  }, []);

  const handleForward = useCallback(() => {
    webViewRef?.current?.goForward();
  }, []);

  const handleCollapse = useCallback(() => {
    setIsApiResponseOpen(false);
  }, []);

  const handleApiRequest = useCallback(() => {
    setResponseData('');
    setResponseError('');

    fetch(NFT_API_URL, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
      },
      body: JSON.stringify(SAMPLE_PAYLOAD),
    })
      .then(async (response) => {
        return response.json();
      })
      .then((data) => {
        setResponseData(JSON.stringify(data, null, 2));
        setIsApiResponseOpen(true);
      })
      .catch((err) => {
        setResponseError(JSON.stringify(err, null, 2));
        setIsApiResponseOpen(true);
      });
  }, []);

  const { height } = useWindowDimensions();

  return (
    <>
      <TextTitle2 spacingStart={2}>NFT WebView</TextTitle2>
      <HStack spacing={1} spacingBottom={2}>
        <ButtonGroup>
          <IconButton name="home" onPress={handleHome} />
          <IconButton name="caretLeft" onPress={handleBack} />
          <IconButton name="caretRight" onPress={handleForward} />
          <IconButton name="refresh" onPress={handleReload} />
          <IconButton name="api" onPress={handleApiRequest} />
        </ButtonGroup>
      </HStack>

      <Collapsible collapsed={!isApiResponseOpen} spacing={3} maxHeight={300}>
        <IconButton name="caretDown" onPress={handleCollapse} />
        <TextBody selectable="all">{responseData ?? responseError}</TextBody>
      </Collapsible>

      <VStack
        flexGrow={1}
        spacingBottom={3}
        minHeight={height * 0.75}
        spacingHorizontal={1}
      >
        <WebView
          key={`nft_webview_${webViewKey}`}
          ref={webViewRef}
          originWhitelist={[
            // This is already the default
            'https://*',
            'http://*',
            // This is added. Fixes issue with "Can't open URL about:srcdoc"
            // This is needed, to allow sandboxed NFTs to load
            // https://github.com/react-native-webview/react-native-webview/issues/2567#issuecomment-1171373082
            'about:*',
          ]}
          source={{
            uri: INITIAL_WEBVIEW_URL,
          }}
        />
      </VStack>
      <TextTitle2 spacingStart={2}>Trending NFT Carousels</TextTitle2>
      <ScrollView>
        <HStack spacing={1} spacingBottom={2}>
          <TrendingNftCollections viewerRef={query.viewer} compact />
        </HStack>
        <HStack spacing={1} spacingBottom={2}>
          <TrendingNftCollections viewerRef={query.viewer} />
        </HStack>

        <Collapsible collapsed={!isApiResponseOpen} spacing={3} maxHeight={300}>
          <IconButton name="caretDown" onPress={handleCollapse} />
          <TextBody selectable="all">{responseData ?? responseError}</TextBody>
        </Collapsible>
      </ScrollView>
    </>
  );
});

