import { memo, useCallback, useEffect, useMemo, useState } from 'react';
import { SpacingProps, useToggler } from '@cbhq/cds-common';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { ListCell } from '@cbhq/cds-mobile/cells';
import { Collapsible } from '@cbhq/cds-mobile/collapsible';
import { Icon } from '@cbhq/cds-mobile/icons';
import { HStack } from '@cbhq/cds-mobile/layout';
import { PressableOpacity } from '@cbhq/cds-mobile/system';
import { TextBody, TextHeadline } from '@cbhq/cds-mobile/typography';
import {
  graphql,
  useLazyLoadQuery,
  useRelayEnvironment,
} from '@cbhq/data-layer';
import MpcSdk from '@cbhq/react-native-mpc-sdk';

import { Button } from '@components/interactables/Button';
import { NavHeaderConfig, Screen } from '@app/components/Screen';
import { ScreenBoundary } from '@app/components/ScreenBoundary/ScreenBoundary';
import { useDappWallet } from '@app/contexts/Defi/DefiProvider';
import {
  DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE,
  DefiMPCClient,
} from '@app/screens/Defi/clients/DefiMPCClient';
import { DefiSigningClient } from '@app/screens/Defi/clients/DefiSigningClient';
import { useCohortId } from '@app/screens/Defi/hooks/useCohortId';

import { DebugMPCScreenQuery } from './__generated__/DebugMPCScreenQuery.graphql';

const navHeader: NavHeaderConfig = {
  title: 'Debug MPC',
};

const listSpacing: SpacingProps = { spacingHorizontal: 0 };

const DebugMPC = memo(function DebugMPC() {
  const query = useLazyLoadQuery<DebugMPCScreenQuery>(
    graphql`
      query DebugMPCScreenQuery {
        ...useCohortIdFragment
      }
    `,
    {},
  );

  const cohortId = useCohortId(query);
  const { walletState } = useDappWallet();

  const defiMPCClient = useMemo(() => {
    return DefiMPCClient.getInstance({
      cohortId,
      isMpcWalletEnabled: true,
    });
  }, [cohortId]);

  const environment = useRelayEnvironment();
  const signingClient = useMemo(
    () =>
      DefiSigningClient.getInstance({
        environment,
        cohortId,
        isMpcWalletEnabled: true,
        isSigningSubscriptionsKilled: false,
      }),
    [cohortId, environment],
  );

  const [isCosignerConnected, setIsCosignerConnected] = useState<
    boolean | undefined
  >();
  const refreshCosignerState = useCallback(() => {
    MpcSdk.isCosignerClientConnected((isConnected: boolean) => {
      setIsCosignerConnected(isConnected);
    });
  }, []);

  useEffect(() => {
    refreshCosignerState();

    return () => signingClient.disconnectCosigner();
  }, [refreshCosignerState, signingClient]);

  const [authKeyCollapsed, { toggle: toggleAuthKey }] = useToggler(true);
  const [encKeyCollapsed, { toggle: toggleEncKey }] = useToggler(true);
  const [isCohortJsonCollapsed, { toggle: toggleCohortJson }] =
    useToggler(true);
  const [isAllCohortRevisionsCollapsed, { toggle: toggleAllCohortRevisions }] =
    useToggler(true);

  const allCohortRevisions = useMemo(() => {
    try {
      return JSON.stringify(
        JSON.parse(DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.allCohortRevisions),
        null,
        4,
      );
    } catch (_) {
      return `Malformatted JSON\n${DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.allCohortRevisions}`;
    }
  }, []);

  const cohortJson = useMemo(() => {
    try {
      return JSON.stringify(
        JSON.parse(DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.cohortJson),
        null,
        4,
      );
    } catch (_) {
      return `Malformatted JSON\n${DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.cohortJson}`;
    }
  }, []);

  return (
    <Screen navHeader={navHeader}>
      <ListCell
        title="Dapp wallet state"
        detail={walletState}
        outerSpacing={listSpacing}
      />
      <ListCell
        title="Cosigner connected?"
        description={String(isCosignerConnected)}
        outerSpacing={listSpacing}
        onPress={refreshCosignerState}
        action={<TextBody color="primary">Refresh</TextBody>}
      />
      <ButtonGroup accessibilityLabel="connect or disconnect cosigner" block>
        <Button
          variant="secondary"
          compact
          // eslint-disable-next-line react/jsx-handler-names
          onPress={signingClient.connectCosigner}
        >
          Connect
        </Button>
        <Button
          variant="secondary"
          compact
          onPress={() => signingClient.disconnectCosigner()}
        >
          Disconnect
        </Button>
      </ButtonGroup>

      <TitleCollapsibleToggle
        title="Device auth key"
        collapsed={authKeyCollapsed}
        toggle={toggleAuthKey}
      />
      <Collapsible collapsed={authKeyCollapsed}>
        <TextBody selectable="all">{defiMPCClient.deviceAuthKey}</TextBody>
      </Collapsible>

      <TitleCollapsibleToggle
        title="Device enc key"
        collapsed={encKeyCollapsed}
        toggle={toggleEncKey}
      />
      <Collapsible collapsed={encKeyCollapsed}>
        <TextBody selectable="all">{defiMPCClient.deviceEncKey}</TextBody>
      </Collapsible>

      <TitleCollapsibleToggle
        title="All Cohort Revisions"
        collapsed={
          DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.allCohortRevisions
            ? isAllCohortRevisionsCollapsed
            : undefined
        }
        toggle={
          DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.allCohortRevisions
            ? toggleAllCohortRevisions
            : undefined
        }
      />
      {DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.allCohortRevisions ? (
        <Collapsible collapsed={isAllCohortRevisionsCollapsed}>
          <TextBody selectable="all">{allCohortRevisions}</TextBody>
        </Collapsible>
      ) : (
        <TextBody>undefined</TextBody>
      )}

      <TitleCollapsibleToggle
        title="Cohort JSON"
        collapsed={
          DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.cohortJson
            ? isCohortJsonCollapsed
            : undefined
        }
        toggle={
          DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.cohortJson
            ? toggleCohortJson
            : undefined
        }
      />
      {DEBUG_DEFI_MPC_CLIENT_DO_NOT_USE.cohortJson ? (
        <Collapsible collapsed={isCohortJsonCollapsed}>
          <TextBody selectable="all">{cohortJson}</TextBody>
        </Collapsible>
      ) : (
        <TextBody>undefined</TextBody>
      )}
    </Screen>
  );
});

export function DebugMPCScreen() {
  return (
    <ScreenBoundary instrumentationId="DebugMPCScreen">
      <DebugMPC />
    </ScreenBoundary>
  );
}

type TitleCollapsibleToggleProps = {
  title: string;
  collapsed?: boolean;
  toggle?: () => void;
};

function TitleCollapsibleToggle({
  title,
  collapsed,
  toggle,
}: TitleCollapsibleToggleProps) {
  return (
    <PressableOpacity onPress={toggle}>
      <HStack alignItems="center" gap={1} spacingVertical={3}>
        <TextHeadline>{title}</TextHeadline>
        {collapsed !== undefined && (
          <Icon
            name={collapsed ? 'caretDown' : 'caretUp'}
            size="s"
            color="foreground"
          />
        )}
      </HStack>
    </PressableOpacity>
  );
}

