import { memo, useCallback, useEffect, useState } from 'react';
import { Platform } from 'react-native';
import notifee, { Notification } from '@notifee/react-native';
import messaging from '@react-native-firebase/messaging';
import noop from 'lodash/noop';
import { Divider } from '@cbhq/cds-mobile/layout';
import { HStack } from '@cbhq/cds-mobile/layout/HStack';
import { TextBody, TextLegal } from '@cbhq/cds-mobile/typography';

import { Button } from '@components/interactables/Button';
import { TextInput } from '@components/interactables/TextInput';
import { CopyableField } from '@components/UI/CopyableField';
import { log } from '@utils/log';
import { Screen } from '@app/components/Screen';
import { useDeviceTokenDeregistration } from '@app/hooks/notifications/useDeviceTokenDeregistration';
import { useDeviceTokenRegistration } from '@app/hooks/notifications/useDeviceTokenRegistration';
import { displayNotification } from '@app/utils/notifications/adapter';
import { priceAlertsChannel } from '@app/utils/notifications/channels';

function handleTextAlertPush(url?: string) {
  const payload: Notification = {
    title: 'Test Alert!',
    body: 'Coinbase App Debug Notification',
  };
  if (url) {
    payload.data = {
      url,
    };
  }

  if (Platform.OS === 'android') {
    payload.android = {
      channelId: priceAlertsChannel.channelId,
      smallIcon: 'ic_notification',
    };
  }

  void displayNotification(payload);
}

// An instance of PowerManagerInfo will be returned with an activity property,
// this will be the name of the Android settings screen the user will be navigated
// to via openPowerManagerSettings().
async function getPowerManagerInfo(): Promise<string> {
  const powerManagerInfo = await notifee.getPowerManagerInfo();
  return JSON.stringify(powerManagerInfo);
}

async function getPushToken(): Promise<string> {
  const token =
    Platform.OS === 'android'
      ? await messaging().getToken()
      : await messaging().getAPNSToken();
  return token ?? '';
}

// The authorizationStatus attributes will returns DENIED if user has denied the permission,
// and AUTHORIZED if it's granted.
async function getNotificationSettings(): Promise<string> {
  const settings = await notifee.getNotificationSettings();
  return JSON.stringify(settings);
}

async function getNotificationChannels(): Promise<string> {
  const channels = await notifee.getChannels();
  return JSON.stringify(channels);
}

async function getNotificationCategories(): Promise<string> {
  const categories = await notifee.getNotificationCategories();
  return JSON.stringify(categories);
}

async function getDisplayedNotifications(): Promise<string> {
  const notifications = await notifee.getDisplayedNotifications();
  return JSON.stringify(notifications);
}

function DebugPushNotifications() {
  const [displayedNotifications, setDisplayedNotifications] = useState('');
  const [notificationCategories, setNotificationCategories] = useState('');
  const [notificationChannels, setNotificationChannels] = useState('');
  const [notificationPermissions, setNotificationPermissions] = useState('');
  const [notificationPowerInfo, setNotificationPowerInfo] = useState('');
  const [notificationPushToken, setNotificationPushToken] = useState('');
  const [customDeepLinkUrl, setCustomDeepLinkUrl] = useState('');
  const deregisterDeviceToken = useDeviceTokenDeregistration();
  const deregister = useCallback(() => {
    void deregisterDeviceToken();
  }, [deregisterDeviceToken]);

  const registerDeviceToken = useDeviceTokenRegistration();
  useEffect(() => {
    async function fetchAsyncData() {
      setDisplayedNotifications(await getDisplayedNotifications());
      setNotificationCategories(await getNotificationCategories());
      setNotificationChannels(await getNotificationChannels());
      setNotificationPermissions(await getNotificationSettings());
      setNotificationPowerInfo(await getPowerManagerInfo());
      setNotificationPushToken(await getPushToken());
    }
    void fetchAsyncData();
    log(notificationPushToken);
  }, [notificationPushToken]);

  return (
    <Screen navHeader={{ title: 'Push Notifications' }}>
      <Button onPress={() => handleTextAlertPush()}>Text Alert</Button>
      <TextInput
        accessibilityLabel="Text input field"
        name="url"
        placeholder="/price/btc"
        value={customDeepLinkUrl}
        onChange={setCustomDeepLinkUrl}
        isDirty={false}
        errors={[]}
        onErrors={noop}
      />
      <Button
        onPress={() =>
          handleTextAlertPush(`https://coinbase.com/${customDeepLinkUrl}`)
        }
      >
        Deep Link URL
      </Button>
      <Divider />
      <CopyableField title="Push Token">{notificationPushToken}</CopyableField>
      <HStack gap={6}>
        <Button variant="positive" onPress={async () => registerDeviceToken()}>
          Register
        </Button>

        <Button variant="negative" onPress={deregister}>
          Deregister
        </Button>
      </HStack>
      <TextLegal color="foregroundMuted" spacingBottom={2}>
        Makes request to GNS to configure the device token for remote messages
      </TextLegal>
      <Divider />
      <CopyableField title="Permissions">
        {notificationPermissions}
      </CopyableField>
      <CopyableField title="Power Info">{notificationPowerInfo}</CopyableField>
      <CopyableField title="Channels">{notificationChannels}</CopyableField>
      <CopyableField title="Categories">{notificationCategories}</CopyableField>
      <CopyableField title="Displayed Notifications">
        {displayedNotifications}
