// This function checks if the app is using bundled or runtime-translated messages.
// It compares the latest messages received from useRuntimeTranslationFetcher with a dummy fallback message.
// If they are identical, it means the app is using bundled messages; otherwise, it's using runtime-translated messages.
function getTranslationsVersion(latestMessages?: MessageMap) {
  return !latestMessages ||
    Object.keys(latestMessages).length === 0 ||
    JSON.stringify(latestMessages) === JSON.stringify(dummyFallbackMessage)
    ? 'Bundled Messages'
    : `Runtime Translations (Version: ${getVersion()})`;
}

function getError(...msg: unknown[]) {
  // 2024-06-03 jatin-aggarwal: This Page Component is intended for use only in development builds.
  // It allows developers to catch and resolve errors that may occur during runtime.
  // eslint-disable-next-line no-console
  console.error(...msg);
}

/**
 * Splits a very long string into smaller chunks of a specified size.
 * This is necessary because rendering the entire string at once can be impractical.
 * Each chunk will be rendered individually on the screen.
 */
function splitText(text: string, chunkSize = 10000): string[] {
  const chunks = [];
  for (let i = 0; i < text.length; i += chunkSize) {
    chunks.push(text.slice(i, i + chunkSize));
  }
  return chunks;
}

