const RuntimeTranslationStoredFilesSection = memo(
  ({ locale }: RuntimeTranslationStoredFilesSectionProps) => {
    const targetFiles = useMemo(
      () => [`${locale}.json`, 'etags.json'],
      [locale],
    );

    const [runtimeTranslationsFilesList, setRuntimeTranslationsFilesList] =
      useState<string[]>([]);
    const [runtimeTranslationsFilesdata, setRuntimeTranslationsFilesdata] =
      useState<string[][]>([]);
    const [loadingState, setLoadingState] = useState({
      listLoading: true,
      dataLoading: true,
    });

    const isLoading = useMemo(
      () => loadingState.listLoading || loadingState.dataLoading,
      [loadingState],
    );

    const targetFilesList = useMemo(
      () =>
        runtimeTranslationsFilesList?.filter((file) =>
          targetFiles.includes(file),
        ) || [],
      [runtimeTranslationsFilesList, targetFiles],
    );

    const otherFilesList = useMemo(
      () =>
        runtimeTranslationsFilesList?.filter(
          (file) => !targetFiles.includes(file),
        ) || [],
      [runtimeTranslationsFilesList, targetFiles],
    );

    const fetchAndUpdateRuntimeTranslationFilesList = useCallback(async () => {
      try {
        setLoadingState((prevState) => ({ ...prevState, listLoading: true }));
        const data = await getRuntimeTranslationFilesList(getVersion());

        if (!isEqual(data, runtimeTranslationsFilesList)) {
          setRuntimeTranslationsFilesList(data);
        }
      } catch (error) {
        getError('Error fetching runtime translation files list: ', error);
      } finally {
        setLoadingState((prevState) => ({ ...prevState, listLoading: false }));
      }
    }, [runtimeTranslationsFilesList]);

    const fetchFileData = useCallback(async () => {
      try {
        setLoadingState((prevState) => ({ ...prevState, dataLoading: true }));
        const dataPromises = runtimeTranslationsFilesList
          .filter((file) => targetFiles.includes(file))
          .map((file: string) =>
            getFileContent({
              version: getVersion(),
              fileName: file.split('.')[0],
            }),
          );

        const data = await Promise.all(dataPromises);
        const chunksData = data.map((fileData?: string) =>
          fileData ? splitText(fileData) : [],
        );

        setRuntimeTranslationsFilesdata(chunksData);
      } catch (error) {
        getError('Error fetching file content: ', error);
      } finally {
        setLoadingState((prevState) => ({
          ...prevState,
          dataLoading: false,
        }));
      }
    }, [runtimeTranslationsFilesList, targetFiles]);

    const handleRefresh = useCallback(() => {
      fetchAndUpdateRuntimeTranslationFilesList();
    }, [fetchAndUpdateRuntimeTranslationFilesList]);

    useOnMount(() => {
      fetchAndUpdateRuntimeTranslationFilesList();
    });

    useEffect(() => {
      if (runtimeTranslationsFilesList) {
        fetchFileData();
      }
    }, [runtimeTranslationsFilesList, fetchFileData]);

    return (
      <>
        <HStack justifyContent="space-between" alignItems="center">
          <TextTitle3>Runtime Translation Stored Files</TextTitle3>
          <IconButton
            name="refresh"
            transparent
            aria-label="refresh"
            disabled={isLoading}
            onPress={handleRefresh}
          />
        </HStack>
        {isLoading && <TextBody spacingVertical={3}>Loading...</TextBody>}
        {!isLoading && runtimeTranslationsFilesList.length === 0 && (
          <TextBody spacingVertical={3}>
            No Runtime Translation Files stored in Your Device
          </TextBody>
        )}
        {!isLoading && runtimeTranslationsFilesList.length > 0 && (
          <Accordion>
            <RenderTargetFiles
              files={targetFilesList}
              data={runtimeTranslationsFilesdata}
            />
            <RenderOtherFiles files={otherFilesList} />
          </Accordion>
        )}
      </>
    );
  },
);

