type DataTimingProps = {
  dataTiming: Timing;
  relativeTiming: BranchTiming;
  isWaterfall: boolean;
  scale: number;
};
function DataTiming({
  relativeTiming,
  dataTiming,
  isWaterfall,
  scale,
}: DataTimingProps) {
  const spectrum = useSpectrum();
  const { navigate } = useStackNavigation();

  const backgroundColor = useMemo(() => {
    if (dataTiming.type === 'suspenseFallback') {
      return 'orange15';
    }
    if (dataTiming.didSuspend) {
      return isWaterfall ? 'red15' : 'yellow20';
    }
    if (dataTiming.type === 'fragment') {
      return 'gray10';
    }
    return 'blue5';
  }, [dataTiming, isWaterfall]);

  const textLabel = useMemo(() => {
    let label =
      dataTiming.type === 'suspenseFallback'
        ? dataTiming.identifier
        : dataTiming.name || dataTiming.identifier;

    if (dataTiming.suspenseBoundaryName) {
      label += ` ∈ ${dataTiming.suspenseBoundaryName}`;
    }
    return label;
  }, [
    dataTiming.identifier,
    dataTiming.name,
    dataTiming.suspenseBoundaryName,
    dataTiming.type,
  ]);

  const onPress = useCallback(() => {
    navigate('DebugSuspenseDataTiming', {
      relativeTiming,
      dataTiming,
    });
  }, [dataTiming, navigate, relativeTiming]);

  return (
    <TouchableOpacity
      accessibilityRole="button"
      key={dataTiming.name + dataTiming.identifier}
      onPress={onPress}
      style={timelineStyles.timelineRow}
    >
      <View
        style={[
          timelineStyles.timingBar,
          {
            backgroundColor: paletteValueToHex(backgroundColor, spectrum),
            left: (dataTiming.firstRenderAt ?? 0) * scale,
            width: Math.max(
              ((dataTiming.resolvedAt ?? dataTiming.firstRenderAt ?? 0) -
                (dataTiming.firstRenderAt ?? 0)) *
                scale,
              10,
            ),
          },
        ]}
      />
      <View
        style={[
          timelineStyles.timingLabel,
          { left: (dataTiming.firstRenderAt ?? 0) * scale },
        ]}
      >
        <TextLabel2>{textLabel}</TextLabel2>
      </View>
    </TouchableOpacity>
  );
}

type TimelineViewProps = {
  relativeTiming: BranchTiming;
};

const TimelineView = memo(function TimelineView({
  relativeTiming,
}: TimelineViewProps) {
  const spectrum = useSpectrum();

  const [suspendedTimingsOnly, { toggle: toggleSuspendedOnly }] = useToggler();

  const sortedDataTimings = Object.values(relativeTiming.dataTimings).sort(
    (a, b) =>
      (a.firstRenderAt ?? Number.MAX_SAFE_INTEGER) -
      (b.firstRenderAt ?? Number.MAX_SAFE_INTEGER),
  );

  const filteredDataTimings = sortedDataTimings.filter((dt) =>
    suspendedTimingsOnly
      ? dt.didSuspend === true || dt.type === 'suspenseFallback'
      : true,
  );

  const hasBoundaryRelationships = useRef(false);
  // build suspense boundary relationship between data timings
  const [suspenseBoundaryList, boundarylessOperations] = useMemo(() => {
    const suspenseBoundaryMap: Record<string, BranchTimingWithSuspense> = {};
    // there's some data timings that are not instrumented, we'll put them in a separate list
    // e.g., fetch, streaming, etc.
    const nonInstrumentedList: Timing[] = [];
    // we will try out best to guess
    const unguessableList: Timing[] = [];
    for (const timingKey in relativeTiming?.dataTimings) {
      if (
        Object.prototype.hasOwnProperty.call(
          relativeTiming?.dataTimings,
          timingKey,
        )
      ) {
        const timing = relativeTiming.dataTimings[timingKey];
        if (timing.type === 'suspenseFallback') {
          suspenseBoundaryMap[timing.identifier] = { ...timing };
        }
      }
    }

    for (const timing of filteredDataTimings) {
      if (
        timing.suspenseBoundaryName &&
        suspenseBoundaryMap[timing.suspenseBoundaryName]
      ) {
        const suspenseBoundary =
          suspenseBoundaryMap[timing.suspenseBoundaryName];
        if (!suspenseBoundary?.dataTimings) {
          suspenseBoundary.dataTimings = [];
        }
        if (timing.type !== 'suspenseFallback') {
          if (!hasBoundaryRelationships.current) {
            hasBoundaryRelationships.current = true;
          }
          suspenseBoundary.dataTimings.push(timing);
        }
      } else if (!timing.suspenseBoundaryName) {
        nonInstrumentedList.push(timing);
      }
    }
    // incomplete data here, we need to "guess" where the uninstrumented operations happened
    for (const timing of nonInstrumentedList) {
      const firstRenderAt = timing.firstRenderAt ?? 0;
      const resolvedAt = timing.resolvedAt ?? 0;
      let guessed = false;
      for (const key of Object.keys(suspenseBoundaryMap)) {
        const suspenseBoundary = suspenseBoundaryMap[key];
        // If an operation is missing suspenseBoundary info, we will use firstRenderAt and resolvedAt
        // to estimate where it might have occurred.
        if (
          suspenseBoundary.firstRenderAt !== undefined &&
          suspenseBoundary.resolvedAt !== undefined &&
          suspenseBoundary.firstRenderAt <= firstRenderAt &&
          suspenseBoundary.resolvedAt >= resolvedAt
        ) {
          if (!suspenseBoundary.dataTimings) {
            suspenseBoundary.dataTimings = [];
          }
          suspenseBoundary.dataTimings.push(timing);
          guessed = true;
          break;
        }
      }
      if (!guessed) {
        // we can't guess where this operation happened, put it under unguessable list
        unguessableList.push(timing);
      }
    }

    // need to sort each dataTimings by firstRenderAt
    for (const key of Object.keys(suspenseBoundaryMap)) {
      const suspenseBoundary = suspenseBoundaryMap[key];
      suspenseBoundary.dataTimings?.sort(
        (a, b) => (a?.firstRenderAt ?? 0) - (b?.firstRenderAt ?? 0),
      );
    }

    return [
      Object.values(suspenseBoundaryMap).sort(
        (a, b) => (a?.firstRenderAt ?? 0) - (b?.firstRenderAt ?? 0),
      ),
      unguessableList,
    ];
  }, [filteredDataTimings, relativeTiming?.dataTimings]);

  const timelineEnd = Math.max(
    0,
    ...filteredDataTimings.map((it) => it.resolvedAt ?? 0),
  );

  const renderedTimelineEnd = Math.max(
    0,
    ...filteredDataTimings.map((it) => Math.max(0, ...it.mountedAt) ?? 0),
  );

  const sortedByResolvedAt = useMemo(
    () =>
      [...sortedDataTimings].sort(
        (a, b) =>
          (a.resolvedAt ?? Number.MAX_SAFE_INTEGER) -
          (b.resolvedAt ?? Number.MAX_SAFE_INTEGER),
      ),
    [sortedDataTimings],
  );
  // find potential waterfall
  const [waterfallCount, waterfallList] = useMemo(() => {
    const suspendedOnly = sortedByResolvedAt.filter((it) => it.didSuspend);
    const waterfallSet = new Set();
    // count the number of operations that has firstRenderAt value after an operation resolved
    let count = 0;
    for (let i = 0; i < suspendedOnly.length; i += 1) {
      const { resolvedAt } = suspendedOnly[i];
      for (let j = i + 1; j < suspendedOnly.length; j += 1) {
        if (
          !waterfallSet.has(suspendedOnly[j].identifier) &&
          resolvedAt &&
          (suspendedOnly[j]?.firstRenderAt ?? 0) > resolvedAt
        ) {
          count += 1;
          waterfallSet.add(suspendedOnly[j].identifier);
          break;
        }
      }
    }
    return [count, waterfallSet];
  }, [sortedByResolvedAt]);

  const slowest = useMemo(() => {
    return sortedByResolvedAt[sortedByResolvedAt.length - 1];
  }, [sortedByResolvedAt]);

  const screenWidth = Dimensions.get('window').width;

  const [scale, setScale] = useState(() =>
    Math.min((screenWidth - 100) / timelineEnd, 1),
  );

  const NUM_MARKERS_ON_SCREEN = 2;
  const timeMarkerPxWidth = screenWidth / (NUM_MARKERS_ON_SCREEN + 1);
  const timeMarkerTimespanWidth = timeMarkerPxWidth / scale;
  const numTimeMarkers = Math.max(
    Math.ceil(timelineEnd / timeMarkerTimespanWidth) + 1,
    NUM_MARKERS_ON_SCREEN,
  );

  const timelinePxWidth = (timelineEnd + screenWidth / scale) * scale;

  const dataTimings = useMemo(() => {
    return (
      <>
        {hasBoundaryRelationships.current
          ? suspenseBoundaryList.map((suspenseBoundaryDataTiming) => {
              return (
                <>
                  <DataTiming
                    dataTiming={suspenseBoundaryDataTiming}
                    relativeTiming={relativeTiming}
                    isWaterfall={waterfallList.has(
                      suspenseBoundaryDataTiming.identifier,
                    )}
                    scale={scale}
                  />
                  {suspenseBoundaryDataTiming?.dataTimings?.map(
                    (dataTiming) => {
                      return (
                        <DataTiming
                          relativeTiming={relativeTiming}
                          dataTiming={dataTiming}
                          isWaterfall={waterfallList.has(dataTiming.identifier)}
                          scale={scale}
                        />
                      );
                    },
                  )}
                </>
              );
            })
          : filteredDataTimings.map((dataTiming) => {
              // adding this backward compatability just in case if we need to rollback the datalayer
              // pacakge that doesn't support suspenseBoundary <-> operation relationship.
              return (
                <DataTiming
                  dataTiming={dataTiming}
                  relativeTiming={relativeTiming}
                  isWaterfall={waterfallList.has(dataTiming.identifier)}
                  scale={scale}
                />
              );
            })}
        {boundarylessOperations.map((dataTiming) => {
          // this is for operations that are not instrumented and unguessable
          return (
            <DataTiming
              dataTiming={dataTiming}
              relativeTiming={relativeTiming}
              isWaterfall={waterfallList.has(dataTiming.identifier)}
              scale={scale}
            />
          );
        })}
      </>
    );
  }, [
    boundarylessOperations,
    filteredDataTimings,
    relativeTiming,
    scale,
    suspenseBoundaryList,
    waterfallList,
  ]);

  return (
    <>
      <TextHeadline spacingBottom={1}>Time until all resolved</TextHeadline>
      <TextBody spacingBottom={2}>{`${timelineEnd}ms`}</TextBody>
      <TextHeadline spacingBottom={1}>Time until all rendered</TextHeadline>
      <TextBody spacingBottom={2}>{`${renderedTimelineEnd}ms`}</TextBody>

      <HStack gap={1} spacingBottom={1}>
        <TextHeadline>Waterfall count</TextHeadline>
        <Tooltip content="Possible waterfall count detected during the rendering cycle. This method may not be 100% accurate, as it compares the resolvedAt time with the firstRenderedAt time for each operation. If one operation begins rendering after another operation has resolved, there's a high likelihood that a network waterfall occurred during that specific rendering cycle.">
          <Icon name="info" size="m" />
        </Tooltip>
      </HStack>

      <TextBody spacingBottom={2}>{`${waterfallCount}`}</TextBody>
      <HStack gap={1} spacingBottom={1}>
        <TextHeadline>Slowest</TextHeadline>
        <Tooltip
          content="This operation took the longest to resolve. You should begin your investigation with this operation if you are aiming to improve the rendering performance"
          placement="top"
        >
          <Icon name="info" size="m" />
        </Tooltip>
      </HStack>

      <TextBody
        spacingBottom={2}
      >{`${slowest.name}-${slowest.identifier}`}</TextBody>
      <HStack spacingBottom={1} alignContent="center">
        <TextHeadline spacingBottom={1}>Data timings</TextHeadline>
        <Spacer />
        <ButtonGroup accessibilityLabel="Group">
          <IconButton name="add" onPress={() => setScale((s) => s * 2)} />
          <IconButton name="minus" onPress={() => setScale((s) => s / 2)} />
        </ButtonGroup>
      </HStack>
      <VStack gap={1}>
        <Tag intent="promotional" background="red15" color="gray100">
          Potential Network waterfall
        </Tag>
        <Tag intent="promotional" background="orange15" color="gray100">
          Suspense Fallback
        </Tag>
        <Tag intent="promotional" background="yellow20" color="gray100">
          Suspended operations
        </Tag>
        <Tag intent="promotional" background="blue5" color="gray100">
          Unsuspended operations
        </Tag>
        <Tag intent="promotional" background="gray10" color="gray100">
          Fragment
        </Tag>
      </VStack>
      <Checkbox
        value="suspendedOnly"
        onChange={toggleSuspendedOnly}
        checked={suspendedTimingsOnly}
      >
        Only show operations that suspended
      </Checkbox>
      <ScrollView
        style={timelineStyles.scrollContainer}
        persistentScrollbar
        horizontal
      >
        <View style={[timelineStyles.container, { width: timelinePxWidth }]}>
          {numTimeMarkers > 0 &&
            new Array(numTimeMarkers).fill(0).map((_, i) => (
              <View
                style={[
                  timelineStyles.timeMarker,
                  {
                    left: i * timeMarkerTimespanWidth * scale,
                    borderLeftColor: paletteValueToHex('gray60', spectrum),
                  },
                ]}
                // eslint-disable-next-line react/no-array-index-key
                key={i}
              >
                <TextLegal>
                  {Math.round(i * timeMarkerTimespanWidth)} ms
                </TextLegal>
              </View>
            ))}
          {dataTimings}
        </View>
      </ScrollView>
    </>
  );
});

