export type ConfirmPaymentProps =
  ConfirmationDialogProps<SignEthereumTransactionMessage>;

type ConfirmPaymentContentProps = {
  viewerRef: ConfirmPaymentContentFragment$key;
} & ConfirmPaymentProps;

function ConfirmPaymentContent({
  data,
  onDismiss,
  dappHostName,
  dappName,
  dappIconUrl,
  onConfirm,
  onBlock,
  returnTo,
  metadata,
  setDismissible,
  viewerRef,
  onSubmit,
  wallet,
}: ConfirmPaymentContentProps) {
  const { formatMessage } = useIntl();
  const formatNativeCurrency = useNativeCurrencyFormatter();
  const formatCurrency = useCurrencyFormatter();

  const [networkFee, setNetworkFee] = useState<NetworkFee | undefined>(
    undefined,
  );
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCopied, setIsCopied] = useState(false);
  const [isAdjustingGas, setIsAdjustingGas] = useState(false);

  const [selectedGasTier, setSelectedGasTier] = useState<GasTier>('MEDIUM');
  const copyTimeoutRef = useRef<NodeJS.Timeout>();

  const { height } = useWindowDimensions();

  const { addPendingTx } = useSetWeb3TxStatus();
  const {
    request: {
      params: { weiValue, fromAddress, toAddress, data: txData, chainId },
    },
  } = data;
  const isDefiTxPreviewKilled = useKillSwitch(
    'kill_retail_dapps_browser_tx_preview_rn',
  );
  const hasDefiTxPreviewExperiment = useIsTreatment(
    'aug_2023_defi_tx_preview',
    // Use skip tracking to avoid sending exposures if the feature is killed
    { skipTracking: isDefiTxPreviewKilled },
  );
  const fragment = useFragment(
    graphql`
      fragment ConfirmPaymentContentFragment on Query
      @argumentDefinitions(chainId: { type: "Int!" }) {
        ...useDefiSigningClientFragment
        viewer {
          ...useDeFiBalanceForAssetIdFragment
            @arguments(chainId: $chainId, address: $address)
          defiV2 {
            network(chainId: $chainId) {
              ...useFeeAssetFragment
            }
            ...useDappDefiNetworksFragment
          }
        }
      }
    `,
    viewerRef,
  );

  const handleBlock = useCallback(
    (failedRequirement: Web3WalletCondition) => {
      setIsSubmitting(false);
      onBlock?.(failedRequirement);
    },
    [onBlock],
  );

  const { sendTransaction } = useDefiSigningClient({
    fragmentRef: fragment,
    entryPoint:
      metadata.source === 'walletlink-desktop-browser' ? 'walletLink' : 'dapp',
    onBlock: handleBlock,
    returnTo,
  });

  const { viewer } = fragment;

  const feeAsset = useFeeAsset(viewer?.defiV2?.network ?? null);
  if (!feeAsset?.uuid) {
    throw new Error(
      'Do not have fee asset uuid to find dapp wallet balance in ConfirmPaymentContent',
    );
  }

  // If can't find fee asset balance object, default to 0.
  // This can happen if the user never held the asset before.

  const feeAssetBalance = useDeFiBalanceForAssetId(viewer, feeAsset.uuid) || {
    value: '0',
  };

  const { fetchNetworkFees, isFetching } = useFetchNetworkFees(chainId);

  const { getTxErrorMessage } = useTransactionErrorCode();

  useEffect(() => {
    void (async () => {
      const [selectedNetworkFee] = await fetchNetworkFees(
        {
          fromAddress,
          // TODO: Remove forced typing once API is ready
          // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
          toAddress: toAddress!,
          value: weiValue,
          data: txData,
        },
        selectedGasTier,
      );
      setNetworkFee(selectedNetworkFee);
    })();
  }, [
    fetchNetworkFees,
    fromAddress,
    selectedGasTier,
    toAddress,
    txData,
    weiValue,
  ]);

  const { supportedNetworks } = useDappDefiNetworks({
    fragmentRef: fragment.viewer?.defiV2 ?? null,
  });
  const selectedNetwork = supportedNetworks.find(
    (network) => network?.chainId === chainId,
  );

  useEffect(() => {
    markJourney('loaded_dapp_sign_transaction_confirmation_dialog');

    const timeout = copyTimeoutRef.current;
    return () => clearTimeout(timeout);
  }, []);

  const { estFeeFiatAmount, estFeeCryptoAmount } = useMemo(() => {
    const averageNetworkFee = networkFee?.average || '0';

    const estFeeFiatValue = parseDefiBalanceToFiat({
      value: averageNetworkFee,
      exponent: feeAsset.exponent,
      price: feeAsset.quotePrice,
    });

    const estFeeCryptoValue = baseToDecimal({
      value: averageNetworkFee,
      exponent: feeAsset.exponent,
    });

    return {
      estFeeFiatAmount: estFeeFiatValue,
      estFeeCryptoAmount: estFeeCryptoValue,
    };
  }, [feeAsset.exponent, feeAsset.quotePrice, networkFee?.average]);

  const total = useMemo(() => {
    const amountFiatValue = cryptoToFiat({
      value: baseToDecimal({ value: weiValue, exponent: feeAsset.exponent }),
      quotePrice: feeAsset.quotePrice,
    });

    return {
      fiatAmount:
        amountFiatValue && estFeeFiatAmount
          ? Big(amountFiatValue).plus(estFeeFiatAmount).toString()
          : undefined,
      cryptoAmount:
        weiValue && estFeeCryptoAmount
          ? Big(
              baseToDecimal({
                value: weiValue,
                exponent: feeAsset.exponent,
              }),
            )
              .plus(estFeeCryptoAmount)
              .toString()
          : undefined,
    };
  }, [
    estFeeCryptoAmount,
    estFeeFiatAmount,
    feeAsset.exponent,
    feeAsset.quotePrice,
    weiValue,
  ]);

  const fiatCost = useMemo(
    () =>
      parseDefiBalanceToFiat({
        value: weiValue,
        exponent: feeAsset.exponent,
        price: feeAsset.quotePrice,
      }),
    [weiValue, feeAsset.exponent, feeAsset.quotePrice],
  );

  const formatFiatAndCrypto = useCallback(
    (value: number | string) => {
      const formattedNativeAmount = formatNativeCurrency({
        amount: parseDefiBalanceToFiat({
          value,
          exponent: feeAsset.exponent,
          price: feeAsset.quotePrice,
        }),
        isSensitive: false,
      });
      const formattedCryptoAmount = formatCurrency({
        amount: baseToDecimal({
          value,
          exponent: feeAsset.exponent,
        }),
        currency: {
          type: 'crypto',
          code: feeAsset.symbol,
        },
        isSensitive: false,
      });

      return `${formattedNativeAmount} • ${formattedCryptoAmount}`;
    },
    [
      formatNativeCurrency,
      formatCurrency,
      feeAsset.quotePrice,
      feeAsset.exponent,
      feeAsset.symbol,
    ],
  );

  const formattedNetworkFeeAmount = useMemo(() => {
    return formatMessage(messages.eip1559Estimated, {
      fiatAmount: formatNativeCurrency({
        amount: estFeeFiatAmount,
        isSensitive: false,
      }),
      cryptoAmount: formatCurrency({
        amount: estFeeCryptoAmount,
        currency: {
          type: 'crypto',
          code: feeAsset.symbol,
        },
        isSensitive: false,
        compactNotation: true,
      }),
    });
  }, [
    formatMessage,
    formatNativeCurrency,
    estFeeFiatAmount,
    formatCurrency,
    estFeeCryptoAmount,
    feeAsset.symbol,
  ]);

  const { formattedCost, formattedNetworkFee, formattedTotal } = useMemo(() => {
    return {
      formattedCost: formatFiatAndCrypto(weiValue),
      formattedNetworkFee: formattedNetworkFeeAmount,
      formattedTotal: formatMessage(messages.eip1559Estimated, {
        fiatAmount: formatNativeCurrency({
          amount: total?.fiatAmount ?? '0',
          isSensitive: false,
        }),
        cryptoAmount: formatCurrency({
          amount: total.cryptoAmount,
          currency: {
            type: 'crypto',
            code: feeAsset.symbol,
          },
          isSensitive: false,
          compactNotation: true,
        }),
      }),
    };
  }, [
    formatFiatAndCrypto,
    weiValue,
    formattedNetworkFeeAmount,
    formatMessage,
    formatNativeCurrency,
    total?.fiatAmount,
    total.cryptoAmount,
    formatCurrency,
    feeAsset.symbol,
  ]);

  const errors = useDappTxErrorFormatter({
    amount: weiValue,
    estimatedRemainingBalance: networkFee?.estimatedRemainingBalance,
    assetBalance: feeAssetBalance.value,
    feeAssetBalance: feeAssetBalance.value,
    isNativeAssetTx: true,
    assetSymbol: feeAsset.symbol,
    feeAssetSymbol: feeAsset.symbol,
    feeAssetExponent: feeAsset.exponent,
    feeAssetPrice: feeAsset.quotePrice,
  });

  // errors can not be fully calculated without network fee
  const hasMountedWithNetworkFee = useRef(false);
  useEffect(() => {
    // TEMPORARY logging.
    // Only log error when the component mounts. If there's initial error with the transaction
    // value, we want to measure how many users are seeing this.
    // If the user changes the transaction speed and then the error occurs, we are
    // not interested in tracking this case for now.
    if (hasMountedWithNetworkFee.current) {
      return;
    }
    if (networkFee) {
      hasMountedWithNetworkFee.current = true;
    }
    if (errors.insufficientNonNativeAsset || errors.insufficientNativeAsset) {
      logEvent('dapp_wallet_insufficient_balance', {
        action: ActionType.process,
        componentType: ComponentType.text,
        flow: 'dapp-transaction',
        step: 'confirmation-dialog',
        amount: weiValue,
        feeAssetBalance: feeAssetBalance.value,
        ...(networkFee && { networkFee }),
      });
    }
  }, [
    errors,
    errors.insufficientNonNativeAsset,
    errors.insufficientNativeAsset,
    feeAssetBalance.value,
    networkFee,
    weiValue,
  ]);

  const isSubmittable = useMemo(
    () =>
      errors.insufficientNativeAsset === undefined &&
      !isSubmitting &&
      networkFee,
    [errors.insufficientNativeAsset, isSubmitting, networkFee],
  );

  const signEthereumTransaction = useCallback(
    (web3CallParams: SignEthereumTransactionMessage) => {
      const web3Call = { ...web3CallParams };
      setDismissible(false);
      setIsSubmitting(true);

      if (!web3Call.request.params.shouldSubmit) {
        // Our backend service automatically broadcasts a transaction after signing
        onConfirm({
          id: web3Call.id,
          errorMessage: 'Signing without submitting is not supported',
        });
      }

      if (networkFee?.reference) {
        web3Call.request.params.priceTierReference = networkFee.reference;
      }

      addPendingTx();

      sendTransaction({
        message: web3Call.request.params,
        metadata: metadata ? JSON.stringify(metadata) : '',
        onSuccess: ({ txHash, txUuid }) => {
          addPendingTx({
            uuid: txUuid,
            chainId,
          });

          setDismissible(true);
          markJourney('loaded_dapp_transaction_sucess');
          setIsSubmitting(false);

          onConfirm({ id: web3Call.id, result: txHash, txUuid });
        },
        onError: (errorMessage) => {
          setDismissible(true);
          setIsSubmitting(false);

          onConfirm({
            id: web3Call.id,
            errorMessage: getTxErrorMessage(errorMessage ?? 'unknown'),
          });
        },
      });
    },
    [
      setDismissible,
      networkFee?.reference,
      metadata,
      sendTransaction,
      onConfirm,
      addPendingTx,
      chainId,
      getTxErrorMessage,
    ],
  );

  const handleConfirm = useCallback(() => {
    markJourney('navigate_to_dapp_transaction_sucess');
    trackDefiClick({
      flow: 'transaction',
      step: '4_dapp_sign',
      otherParams: {
        dapp: dappName,
        transaction_amount_usd: fiatCost,
        network_fee: formattedNetworkFee,
        asset: feeAsset.symbol,
        amount: baseToDecimal({ value: weiValue, exponent: feeAsset.exponent }),
        signing_type: 'transaction',
        chain_id: chainId,
      },
    });
    onSubmit?.();
    signEthereumTransaction(data);
  }, [
    dappName,
    fiatCost,
    formattedNetworkFee,
    feeAsset.symbol,
    feeAsset.exponent,
    weiValue,
    chainId,
    onSubmit,
    signEthereumTransaction,
    data,
  ]);

  const handleConfirmAdjustGas = useCallback(
    (selectedTier: GasTier) => {
      setSelectedGasTier(selectedTier);
      setIsAdjustingGas(false);
      setDismissible(true);
    },
    [setDismissible],
  );

  const handleOpenAdjustGas = useCallback(() => {
    setIsAdjustingGas(true);
    setDismissible(false);
  }, [setDismissible]);

  const handleCopy = useCallback(() => {
    if (toAddress) {
      setStringAsync(toAddress).then(() => {
        setIsCopied(true);
        copyTimeoutRef.current = setTimeout(() => setIsCopied(false), 1500);
      });
    }
  }, [toAddress]);

  const addressCopyAction = useMemo(() => {
    if (toAddress === null) {
      return undefined;
    }

    return isCopied ? (
      <Icon size="s" name="checkmark" />
    ) : (
      <Icon size="s" name="copy" color="foreground" />
    );
  }, [isCopied, toAddress]);

  useTrackDefiTrayOnMount({
    flow: 'transaction',
    step: '3_dapp_allow',
    otherParams: {
      dapp: dappName,
      chain_id: chainId,
    },
  });

  const paymentDetails = useMemo(() => {
    return (
      <>
        <ListCell
          title={formatMessage(messages.destination)}
          description={
            toAddress ?? formatMessage(messages.noDestinationAddress)
          }
          action={addressCopyAction}
          multiline
          onPress={handleCopy}
        />
        <ListCell
          title={formatMessage(messages.cost)}
          description={formattedCost}
        />
        {!!selectedNetwork && (
          <ListCell
            action={
              <DAppIcon
                iconImageUrl={selectedNetwork?.imageUrl ?? ''}
                size={sizing.icons.header}
              />
            }
            title={formatMessage(messages.network)}
            description={selectedNetwork.name}
            multiline
          />
        )}
        {!isFetching && networkFee ? (
          <ListCell
            testID="confirmation-dialog-fees"
            title={formatMessage(messages.fee)}
            description={formattedNetworkFee}
            action={
              networkFee?.isRange && (
                <Icon size="s" name="gear" color="foreground" />
              )
            }
            onPress={networkFee?.isRange ? handleOpenAdjustGas : undefined}
          />
        ) : (
          <ListCellFallback title description detail subdetail />
        )}
        <ListCell
          title={formatMessage(messages.total)}
          description={formattedTotal}
        />
      </>
    );
  }, [
    addressCopyAction,
    formatMessage,
    formattedCost,
    formattedNetworkFee,
    formattedTotal,
    handleCopy,
    handleOpenAdjustGas,
    isFetching,
    networkFee,
    selectedNetwork,
    toAddress,
  ]);

  const contentHeight = height * 0.45;

  return !isAdjustingGas ? (
    <>
      <VStack offsetHorizontal={gutter} testID="confirmation-dialog">
        <ListCell
          media={
            dappIconUrl ? (
              <CellMedia source={dappIconUrl} type="avatar" />
            ) : (
              <DAppIcon iconImageUrl={dappIconUrl} size={40} />
            )
          }
          title={dappName}
          description={dappHostName}
          multiline
        />
        {!isDefiTxPreviewKilled && hasDefiTxPreviewExperiment ? (
          <Box
            maxHeight={contentHeight}
            overflow="hidden"
            borderRadius="rounded"
            testID="tx-preview-enabled"
          >
            <ScrollView>
              <PressableOpacity
                // Here to help the ScrollView
                // pick up gesture events.
                noScaleOnPress
                transparentWhilePressed
              >
                <TxPreview
                  data={data}
                  address={wallet.address}
                  networkFee={networkFee}
                />
                {paymentDetails}
              </PressableOpacity>
            </ScrollView>
          </Box>
        ) : (
          paymentDetails
        )}
        {Boolean(errors.insufficientNativeAsset) && (
          <Box spacingHorizontal={gutter}>
            <TextLegal color="negative" testID="confirmation-dialog-error">
              {errors.insufficientNativeAsset}
            </TextLegal>
          </Box>
        )}
      </VStack>
      <VStack spacingTop={2} spacingBottom={4} gap={1}>
        <TextLegal color="foregroundMuted">
          {formatMessage(messages.disclaimerTotal)}
        </TextLegal>
        <TextLegal color="foregroundMuted">
          {formatMessage(messages.disclaimerSending)}
        </TextLegal>
      </VStack>
      <Spacer />
      <ButtonGroup block accessibilityLabel={formatMessage(messages.ctaGroup)}>
        <Button variant="secondary" onPress={onDismiss} disabled={isSubmitting}>
          {formatMessage(messages.cancel)}
        </Button>
        <Button
          variant="primary"
          loading={isSubmitting || isFetching}
          disabled={!isSubmittable}
          onPress={handleConfirm}
          testID="payment-confirm-btn"
        >
          {formatMessage(messages.confirm)}
        </Button>
      </ButtonGroup>
    </>
  ) : (
    <DAppGasSelector
      selectedGasTier={selectedGasTier}
      fromAddress={fromAddress}
      // TODO: Remove forced typing once API is ready
      // https://jira.coinbase-corp.com/browse/DAPP-1046
      // eslint-disable-next-line @typescript-eslint/no-non-null-assertion, @typescript-eslint/no-non-null-assertion
      toAddress={toAddress!}
      weiValue={weiValue}
      data={txData}
      onConfirm={handleConfirmAdjustGas}
      feeAsset={feeAsset}
      chainId={chainId}
    />
  );
}

function ConfirmPaymentContentContainer(props: ConfirmPaymentProps) {
  const { wallet } = props;
  const nativeCurrency = useNativeCurrency();

  const query = useLazyLoadQuery<ConfirmPaymentQuery>(
    graphql`
      query ConfirmPaymentQuery(
        $address: String!
        $chainId: Int!
        $nativeCurrency: TickerSymbol!
        $includeTestNetworks: Boolean!
        $includeUnsupportedNetworks: Boolean!
      ) {
        ...ConfirmPaymentContentFragment @arguments(chainId: $chainId)
      }
    `,
    {
      address: wallet.address,
      chainId: wallet.network.chainId,
      nativeCurrency,
      includeTestNetworks: getIsTestnetsEnabled(),
      includeUnsupportedNetworks: getIsUnsupportedNetworksEnabled(),
