export const ConfirmPayment = memo(function ConfirmPayment(
  props: ConfirmPaymentProps,
) {
  if (props?.wallet?.error) {
    return (
      <WalletStateError
        onDismiss={props.onDismiss}
        error={props.wallet.error}
      />
    );
  }
  if (props?.isInvalidWalletState) {
    return <InvalidWalletStateMessage {...props} />;
  }

  return (
    <NetworkBoundary
      suspenseFallback={<ConfirmPaymentLoadingState />}
      errorFallback={CustomErrorFallback}
      willErrorBlockUser
    >
      <ConfirmPaymentContentContainer {...props} />
    </NetworkBoundary>
  );
});

function CustomErrorFallback() {
  return (
    <Box offsetHorizontal={gutter}>
      <ErrorFallback />
