import { Spacer } from '@cbhq/cds-mobile/layout/Spacer';
import { VStack } from '@cbhq/cds-mobile/layout/VStack';
import { PressableOpacity } from '@cbhq/cds-mobile/system';
import {
  TextHeadline,
  TextLabel2,
  TextLegal,
} from '@cbhq/cds-mobile/typography';
import { graphql, useLazyLoadQuery } from '@cbhq/data-layer';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { useDimensions } from '@designSystem/hooks/useDimensions';

import { Button } from '@components/interactables/Button';
import { NetworkBoundary } from '@app/components/NetworkBoundary';
import { Spinner } from '@app/components/Spinner';
import { trackDefiClick } from '@app/screens/Defi/analytics/events';
import { SEARCH_RESULT_ICON_SIZE } from '@app/screens/Defi/components/CellIconPlaceholder';
import { DAppIcon } from '@app/screens/Defi/components/DAppIcon';
import { InvalidWalletStateMessage } from '@app/screens/Defi/DAppBrowser/ConfirmationDialog/InvalidWalletStateMessage';
import { useDefiSigningClient } from '@app/screens/Defi/hooks/useDefiSigningClient';
import { useTransactionErrorCode } from '@app/screens/Defi/hooks/useTransactionErrorCode';
import { Web3WalletCondition } from '@app/screens/Defi/requirementScreens/types';
import { getUrlFavicon } from '@app/screens/Defi/utils';
import { hexToUtf8 } from '@app/screens/Defi/utils/encodingUtils';

import { WalletStateError } from '../WalletStateError';

import { SignMessageQuery } from './__generated__/SignMessageQuery.graphql';
import { SignMessageProps } from './types';
import { UnsupportedSignMessage } from './UnsupportedSignMessage';
import { isUnsupportedSignMessage } from './utils';

const i18nKey = 'DAppBrowserSignMessageDialog';
const messages = defineMessages({
  title: {
    id: `${i18nKey}.title`,
    defaultMessage: 'Sign message from dapp',
    description:
      'Title text on the screen where you can confirm sign message request from dapp browser',
  },
  caption: {
    id: `${i18nKey}.caption`,
    defaultMessage:
      'Signatures can be used to prove you own this wallet account, to allow asset transfers, or for other purposes. Only sign messages from apps you trust.',
    description:
      'Help text on dapp signing screen that provides user more information about the benefits of signatures and warning text about only signing messages from trusted application',
  },
  ctaGroup: {
    id: `${i18nKey}.ctaGroup`,
    defaultMessage: 'confirm or cancel message signing request from dapp',
    description:
      'Text for accessibility label on buttons allowing a user to cancel or confirm signing request from dapp',
  },
  cancel: {
    id: `${i18nKey}.cancel`,
    defaultMessage: 'Cancel',
    description:
      'Text on button that allows user to cancel signing request from dapp',
  },
  sign: {
    id: `${i18nKey}.sign`,
    defaultMessage: 'Sign',
    description:
      'Text on button that allows use to sign the signing request from dapp',
  },
});

const SignMessageContent = memo(
  ({
    data,
    onDismiss,
    onConfirm,
    onBlock,
    returnTo,
    wallet,
    dappHostName,
    dappName,
    dappIconUrl,
    chainId,
    metadata,
  }: SignMessageProps) => {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const { formatMessage } = useIntl();
    const { screenHeight } = useDimensions();

    const dataParams = data.request.params;

    const query = useLazyLoadQuery<SignMessageQuery>(
      graphql`
        query SignMessageQuery {
          ...useDefiSigningClientFragment
        }
      `,
      {},
    );

    const handleBlock = useCallback(
      (failedRequirement: Web3WalletCondition) => {
        setIsSubmitting(false);
        onBlock?.(failedRequirement);
      },
      [onBlock],
    );

    const handleDismiss = useCallback(() => {
      onDismiss();
    }, [onDismiss]);

    const { signMessage } = useDefiSigningClient({
      fragmentRef: query,
      entryPoint:
        metadata.source === 'walletlink-desktop-browser'
          ? 'walletLink'
          : 'dapp',
      onBlock: handleBlock,
      returnTo,
    });

    const { getTxErrorMessage } = useTransactionErrorCode();

    const readableMessage = useMemo(() => {
      return hexToUtf8(dataParams.message) || dataParams.message;
    }, [dataParams.message]);

    const signEthereumMessage = useCallback(async () => {
      setIsSubmitting(true);
      trackDefiClick({
        flow: 'transaction',
        step: '4_dapp_sign',
        otherParams: {
          dapp: dappName,
          signing_type: 'message',
          chain_id: chainId,
        },
      });
      const { address } = data.request.params;

      if (address.toLowerCase() !== wallet.address.toLowerCase()) {
        onConfirm({
          id: data.id,
          errorMessage: 'Wallet address does not match.',
        });
        return;
      }

      signMessage({
        message: data.request.params,
        metadata: metadata ? JSON.stringify(metadata) : undefined,
        onSuccess: ({ signature }) => {
          setIsSubmitting(false);
          onConfirm({ id: data.id, result: signature });
        },
        onError: (errorMessage) => {
          setIsSubmitting(false);
          onConfirm({
            id: data.id,
            errorMessage: getTxErrorMessage(errorMessage ?? 'unknown'),
          });
        },
      });
    }, [
      dappName,
      chainId,
      data.request.params,
      data.id,
      wallet.address,
      signMessage,
      metadata,
      onConfirm,
      getTxErrorMessage,
    ]);

    const heightStyle = useMemo(
      () => ({
        maxHeight: screenHeight * 0.35,
      }),
      [screenHeight],
    );

    return (
      <VStack height="100%" justifyContent="space-between" flexGrow={1}>
        <VStack>
          <Box
            alignSelf="stretch"
            offsetHorizontal={gutter}
            testID="sign-message-dialog"
          >
            <ListCell
              media={
                <DAppIcon
                  iconImageUrl={dappIconUrl ?? getUrlFavicon(dappHostName)}
                  size={SEARCH_RESULT_ICON_SIZE}
                />
              }
              title={dappName}
              description={dappHostName}
              multiline
            />
          </Box>
          <VStack
            background="backgroundAlternate"
            borderRadius="rounded"
            spacing={2}
            gap={1}
          >
            <TextHeadline>{formatMessage(messages.title)}</TextHeadline>
            <ScrollView style={heightStyle} nestedScrollEnabled>
              <PressableOpacity noScaleOnPress transparentWhilePressed>
                <VStack background="backgroundAlternate">
                  <TextLabel2>
                    {dataParams.typedDataJson
                      ? dataParams.typedDataJson
                      : readableMessage}
                  </TextLabel2>
                </VStack>
              </PressableOpacity>
            </ScrollView>
          </VStack>
          <Spacer vertical={2} />
          <TextLegal color="foregroundMuted">
            {formatMessage(messages.caption)}
          </TextLegal>
          <Spacer vertical={4} />
        </VStack>
        <ButtonGroup
          block
          accessibilityLabel={formatMessage(messages.ctaGroup)}
        >
          <Button variant="secondary" onPress={handleDismiss}>
            {formatMessage(messages.cancel)}
          </Button>
          <Button
            variant="primary"
            onPress={signEthereumMessage}
            loading={isSubmitting}
          >
            {formatMessage(messages.sign)}
          </Button>
        </ButtonGroup>
      </VStack>
    );
  },
);

export const SignMessage = memo(function SignMessage(props: SignMessageProps) {
  // UnsupportedSignMessage doesn't make network calls so it can live
  // outside of the NetworkBoundary
  const isUnsupported = useMemo(
    () => isUnsupportedSignMessage(props.data),
    [props.data],
  );
  if (isUnsupported) {
    return <UnsupportedSignMessage {...props} />;
  }

  if (props?.wallet?.error) {
    return (
      <WalletStateError
        onDismiss={props.onDismiss}
        error={props?.wallet?.error}
      />
    );
  }

  if (props?.isInvalidWalletState) {
    return <InvalidWalletStateMessage {...props} />;
  }

  return (
    <NetworkBoundary
      errorFallback={null}
      suspenseFallback={
        <Box justifyContent="center" height={300}>
          <Spinner />
        </Box>
      }
    >
      <SignMessageContent {...props} />
    </NetworkBoundary>
  );
});

