type RecentDappItemProps = {
  item: RecentDapp;
  onSelect: (url: string, dappImageUrl?: string | null) => void;
  updateLocalRecentDapps?: (recentDapps: RecentDapp[]) => void;
  isV2Variant?: boolean;
};

export const RecentDappItem = memo(
  ({
    item,
    onSelect,
    updateLocalRecentDapps,
    isV2Variant = false,
  }: RecentDappItemProps) => {
    const { chainIdForDapp } = useDappChainId();
    const recentDapps = getRecentDapps();

    const handleDappSelect = useCallback(() => {
      const chainId = chainIdForDapp(item.url);
      trackDefiClick({
        flow: 'transaction',
        step: '2_dapp_browser',
        otherParams: {
          dapp: item.name,
          chain_id: chainId,
        },
      });
      onSelect(item.url, item.iconImageUrl);
    }, [chainIdForDapp, item.name, item.url, item.iconImageUrl, onSelect]);

    const dappHostname = safeParseUrl(item.url).hostname;

    const handleRemoveRecentDapp = useCallback(() => {
      const filteredRecentDapps = recentDapps?.filter(
        (dapp) => dapp.id !== item.id,
      );
      updateLocalRecentDapps?.(filteredRecentDapps);
      setRecentDapps(filteredRecentDapps);
    }, [recentDapps, updateLocalRecentDapps, item]);

    return (
      <ListCell
        testID="RecentlyVisitedDappCell"
        media={
          <DAppIcon
            iconImageUrl={item.iconImageUrl ?? getUrlFavicon(item?.url || '')}
            size={SEARCH_RESULT_ICON_SIZE}
            borderRadius="roundedNone"
          />
        }
        title={
          <TextHeadline numberOfLines={1} ellipsize="tail">
            {item.name}
          </TextHeadline>
        }
        description={isV2Variant ? dappHostname : item.tagline}
        onPress={handleDappSelect}
        action={
          <IconButton
            name="close"
            compact
            transparent
            onPress={handleRemoveRecentDapp}
            variant="foregroundMuted"
          />
        }
      />
    );
  },
);

type DappBrowserRecentDappsProps = {
  onSelect: (url: string, dappImageUrl?: string | null) => void;
  isV2Variant?: boolean;
};

function keyExtractor(item: RecentDapp, index: number) {
  return item.id ?? index;
}

const contentInset = { bottom: BOTTOM_INSET };

export const DappBrowserRecentDapps = memo(
  ({ onSelect, isV2Variant = false }: DappBrowserRecentDappsProps) => {
    const { formatMessage } = useIntl();
    const recentDapps = useRecentDappsOnFocus();

    const renderItem = useCallback(
      ({ item }: ListRenderItemInfo<RecentDapp>) => (
        <RecentDappItem
          item={item}
          onSelect={onSelect}
          isV2Variant={isV2Variant}
        />
      ),
      [onSelect, isV2Variant],
    );

    // show loading state while getting recentDapps. i.e. - recentDapps = null
    if (!recentDapps) {
      return <RecentDappsLoadingFallback />;
    }

    // show nothing if there's no recentDapps, i.e. - recentDapps = []
    if (recentDapps?.length === 0) {
      return null;
    }
    return (
      <VStack flexGrow={1} height="100%" background>
        <TextBody color="foregroundMuted">
          {formatMessage(
            isV2Variant ? messages.recentDappsV2 : messages.recentDapps,
          )}
        </TextBody>
        <FlatList
          testID="DefiRecentDappsList"
          data={recentDapps}
          keyExtractor={keyExtractor}
          renderItem={renderItem}
          contentInset={contentInset}
          scrollEnabled={!isV2Variant}
        />
      </VStack>
    );
  },
);

import { memo, useCallback, useMemo } from 'react';
import { Pressable, StyleSheet, useWindowDimensions } from 'react-native';
import { IconName } from '@cbhq/cds-common';
