type AnnouncementCardBaseProps = {
  title: string;
  description: string;
  onPress: () => void;
  lightModeUrl: string;
  darkModeUrl: string;
  onDismiss: () => void;
  cardName: string;
  cardType: string;
  uuid: string;
};

const WEB3_ANNOUNCEMENT_CARD_HEIGHT = 130;
const IMAGE_SIZE = 80;
const ICON_SIZE = 24;

const ITEM_WIDTH_PER_SCREEN = 0.87;

function getSource(uri: string) {
  if (uri.endsWith('.svg')) {
    return { uri: `https:${uri}`, headers: { format: 'svg' } };
  }

  return { uri: `https:${uri}` };
}

export const Web3GeneralAnnouncementCard = memo(
  ({
    title,
    description,
    onPress,
    lightModeUrl,
    darkModeUrl,
    cardName,
    cardType,
    uuid,
  }: AnnouncementCardBaseProps) => {
    const uri = useSpectrumConditional({
      light: lightModeUrl,
      dark: darkModeUrl,
    });

    const cardViewData = getDefiCardViewData({
      flow: 'home_cards',
      step: '0_home',
      otherParams: {
        card_surface: 'home_announcements',
        card_name: cardName,
        card_id: uuid,
        card_type: cardType,
      },
    });

    return (
      <VisibilityTracker
        trackOnce
        eventName="dapp_marketplace_card"
        eventData={cardViewData}
      >
        <Box>
          <AnnouncementCard
            title={title}
            description={description}
            onPress={onPress}
            image={`https:${uri}`}
          />
        </Box>
      </VisibilityTracker>
    );
  },
);

export const Web3DappAnnouncementCard = memo(
  ({
    title,
    description,
    onPress,
    isAd,
    cdsIconName,
    lightModeUrl,
    darkModeUrl,
    onDismiss,
    cardName,
    cardType,
    uuid,
  }: AnnouncementCardBaseProps & {
    isAd?: boolean;
    cdsIconName: IconName;
  }) => {
    const { formatMessage } = useIntl();
    const uri = useSpectrumConditional({
      light: lightModeUrl,
      dark: darkModeUrl,
    });
    const { dismiss } = useCarouselItem();
    const { width } = useWindowDimensions();
    const handleDismissPress = useCallback(() => {
      dismiss(onDismiss);
    }, [dismiss, onDismiss]);

    const cardViewData = getDefiCardViewData({
      flow: 'home_cards',
      step: '0_home',
      otherParams: {
        card_surface: 'home_announcements',
        card_name: cardName,
        card_id: uuid,
        card_type: cardType,
      },
    });

    const source = useMemo(() => {
      return getSource(uri);
    }, [uri]);

    return (
      <VisibilityTracker
        trackOnce
        eventName="dapp_marketplace_card"
        eventData={cardViewData}
      >
        <Pressable accessibilityRole="button" onPress={onPress}>
          <VStack
            spacingBottom={2}
            alignContent="flex-start"
            height={WEB3_ANNOUNCEMENT_CARD_HEIGHT}
            width={width * ITEM_WIDTH_PER_SCREEN}
          >
            <HStack
              bordered
              borderRadius="rounded"
              height="100%"
              spacingStart={2}
            >
              {uri ? (
                <RemoteImage
                  width={IMAGE_SIZE}
                  height={IMAGE_SIZE}
                  resizeMode="contain"
                  source={source}
                  style={{ alignSelf: 'center' }}
                />
              ) : (
                <Fallback
                  width={IMAGE_SIZE}
                  height={IMAGE_SIZE}
                  shape="squircle"
                  style={{ alignSelf: 'center' }}
                />
              )}
              <VStack
                justifyContent="center"
                flexShrink={1}
                spacingHorizontal={2}
              >
                <TextHeadline>{title}</TextHeadline>
                <HStack alignItems="center">
                  {!isAd && <Icon size="s" name={cdsIconName} spacingEnd={1} />}
                  <TextLabel2 lineBreakMode="tail" spacingEnd={1}>
                    {description}
                  </TextLabel2>
                  {isAd && (
                    <Box
                      background="backgroundAlternate"
                      borderRadius="rounded"
                      alignSelf="flex-start"
                      spacingHorizontal={1}
                      spacingVertical={0.5}
                    >
                      <TextLegal>{formatMessage(messages.ad)}</TextLegal>
                    </Box>
                  )}
                </HStack>
              </VStack>
              <Spacer horizontal={1} />
              <IconButton
                name="close"
                transparent
                onPress={handleDismissPress}
              />
            </HStack>
          </VStack>
        </Pressable>
      </VisibilityTracker>
    );
  },
);

