type RecentDappItemProps = {
  item: RecentDapp;
  onSelect: (url: string, dappImageUrl?: string | null) => void;
  bookmarkHostname: string;
  // eslint-disable-next-line @cbhq/cdl-no-optional-relay-fragment-refs
