const RecentDappItem = memo(
  ({
    bookmarViewerRef,
    item,
    onSelect,
    bookmarkHostname,
    bookmarkToggleRef,
  }: RecentDappItemProps) => {
    const { isBookmarked, toggleBookmark } = useDappBrowserBookmarkToggler({
      name: item.name,
      url: item.url,
      bookmarkRef: bookmarkToggleRef || null,
      bookmarkViewerRef: bookmarViewerRef || null,
    });

    const handleDappSelect = useCallback(() => {
      onSelect(item.url, item.iconImageUrl);
    }, [item.url, item.iconImageUrl, onSelect]);

    return (
      <ListCell
        testID="RecentlyVisitedDappCell"
        media={
          <DAppIcon
            iconImageUrl={item.iconImageUrl ?? getUrlFavicon(item?.url || '')}
            size={SEARCH_RESULT_ICON_SIZE}
          />
        }
        action={
          <Pressable
            accessibilityRole="button"
            onPress={() => toggleBookmark()}
          >
            <CellMedia
              type="icon"
              name={isBookmarked ? 'bookmarkActive' : 'bookmarkInactive'}
              color={isBookmarked ? 'primary' : 'foreground'}
            />
          </Pressable>
        }
        title={
          <TextHeadline numberOfLines={1} ellipsize="tail">
            {item.name}
          </TextHeadline>
        }
        description={bookmarkHostname}
        onPress={handleDappSelect}
      />
    );
  },
);

type DappBrowserRecentDappsProps = {
  onSelect: (url: string, dappImageUrl?: string | null) => void;
  bookmarkRef: DappMarketplaceV2RecentDappsFragment$key;
};

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function keyExtractor(item: any, index: any) {
  return item.id ?? index;
}
const contentInset = { bottom: BOTTOM_INSET };

export const DappMarketplaceV2RecentDapps = memo(
  ({ onSelect, bookmarkRef }: DappBrowserRecentDappsProps) => {
    const { formatMessage } = useIntl();
    const recentDapps = useRecentDappsOnFocus();

    const query: DappMarketplaceV2RecentDappsFragment$data = useFragment(
      graphql`
        fragment DappMarketplaceV2RecentDappsFragment on Query
        @argumentDefinitions(skipMyDapps: { type: "Boolean!" }) {
          ...useDappBrowserBookmarkTogglerFragmentViewer
            @arguments(skipMyDapps: $skipMyDapps)
          viewer @skip(if: $skipMyDapps) {
            defiV2 {
              browser {
                bookmarks {
                  edges {
                    node {
                      url
                      ...useDappBrowserBookmarkTogglerFragment
                    }
                  }
                }
              }
            }
          }
        }
      `,
      bookmarkRef,
    );

    const renderItem = useCallback(
      ({ item }: ListRenderItemInfo<RecentDapp>) => {
        const recentDappHostname = safeParseUrl(item.url).hostname;

        const bookmarkToggleRef =
          query?.viewer?.defiV2?.browser?.bookmarks?.edges.find((bookmark) => {
            const bookmarkHostname = safeParseUrl(bookmark?.node?.url).hostname;

            return recentDappHostname === bookmarkHostname;
          });

        return (
          <RecentDappItem
            item={item}
            onSelect={onSelect}
            bookmarkToggleRef={bookmarkToggleRef?.node}
            bookmarViewerRef={query}
            bookmarkHostname={recentDappHostname}
          />
        );
      },
      [onSelect, query],
    );

    // show loading state while getting recentDapps. i.e. - recentDapps = null
    if (!recentDapps) {
      return <RecentDappsLoadingFallback />;
    }

    // show nothing if there's no recentDapps, i.e. - recentDapps = []
    if (recentDapps?.length === 0) {
      return null;
    }

    return (
      <VStack spacingHorizontal={gutter}>
        <TextTitle3 spacingBottom={1}>
          {formatMessage(messages.recentDapps)}
        </TextTitle3>
        <FlatList
          testID="DefiRecentDappsList"
          data={recentDapps}
          keyExtractor={keyExtractor}
          renderItem={renderItem}
          contentInset={contentInset}
          scrollEnabled={false}
        />
      </VStack>
    );
  },
);

