      nativeCurrency,
      skip: !walletAddress || hasWeb3BalanceExperiment,
      skipWeb3BalanceExperiment: !walletAddress || !hasWeb3BalanceExperiment,
      skipDefiPositions:
        !shouldFetchDefiPositions ||
        !walletAddress ||
        !hasWeb3WalletBalanceLocal,
      includeTestNetworks: getIsTestnetsEnabled(),
      includeUnsupportedNetworks: getIsUnsupportedNetworksEnabled(),
      first: CRYPTO_TAB_PAGE_LIMIT,
      skipBalancesQuery: !walletAddress,
      order: web3WalletBalancesSortOrder,
      deFiBalanceFilter: {
        includeTestNetworks: getIsTestnetsEnabled(),
        includeUnsupportedNetworks: getIsUnsupportedNetworksEnabled(),
      },
      skipWeb3TotalBalance: !hasWeb3WalletBalanceDataComponentExperiment,
      shouldIncludeWeb3WalletBalance:
        !!walletAddress || walletAddressHasNetworkError,
    }),
    [
      selectedChainId,
      chainId,
      walletAddress,
      nativeCurrency,
      hasWeb3BalanceExperiment,
      shouldFetchDefiPositions,
      hasWeb3WalletBalanceLocal,
      hasWeb3WalletBalanceDataComponentExperiment,
      walletAddressHasNetworkError,
    ],
  );

  const query = useLazyLoadQuery<DAppWalletScreenQuery>(
    dappWalletScreenQuery,
    queryParams,
    { fetchPolicy: 'store-and-network' },
  );

  const hasWeb3WalletBalance = useHasWeb3WalletBalance(query);

  useEffect(() => {
    setHasWeb3WalletBalanceLocal(hasWeb3WalletBalance);
  }, [hasWeb3WalletBalance]);

  const { refresh: refreshDappWalletScreen } =
    useRefreshQuery<DAppWalletScreenQuery>(dappWalletScreenQuery, queryParams);

  const shouldOffboard = query?.viewer?.userProperties?.userFlags?.some(
    (flag) => flag === CBKE_OFFBOARDING_FLAG,
  );

  const returnTo: NavigateArgs = useMemo(() => {
    return ['Assets', { screen: 'DAppWallet', params: routeParams }];
  }, [routeParams]);

  const onBlock = useCallback(
    (failedRequirement: Web3WalletCondition) => {
      if (failedRequirement === 'nux') {
        navigate('Assets', {});
      }
    },
    [navigate],
  );

  // Disable gating when DeFi network is down, this allows screen to render
  // degraded UI and prevents error tray from prompting immediately.
  const disableGatekeeper =
    isDefiEligibleNetworkError ?? disableGatekeeperParam;

  useSubscribeToInvalidationState([query?.viewer.id], refreshDappWalletScreen);
  useDappWalletScreenTrackingEvents(activeTab);
  useWeb3WalletGateOnFocus({
    queryRef: query,
    returnTo,
    entryPoint,
    subEntryPoint,
    onBlock,
    disableGatekeeper,
    promptFundingForChainId: ETH_MAINNET_CHAIN_ID,
  });

  const navHeader = useMemo(
    () => ({
      animate: false,
      trailing: (
        <IconButton
          name="info"
          onPress={showExplainerTray}
          feedback="light"
          transparent
          compact
        />
      ),
    }),
    [showExplainerTray],
  );

  const refreshControl = useMemo(
    () => <RefreshControl onRefresh={refreshDappWalletScreen} />,
    [refreshDappWalletScreen],
  );

  const { tabNavigation, tabView, isDefiTabActive } = useDappWalletTabs({
    handleTabChange: setActiveTab,
    activeTab,
    queryRef: query,
    selectedChainId,
  });

  useEffect(() => {
    // should only intentionally fetch fragment once when defi tab is active
    // and wallet has a positive balance. This is for minimizing calls to
    // an expensive endpoint.
    if (!shouldFetchDefiPositions && isDefiTabActive && hasWeb3WalletBalance) {
      setShouldFetchDefiPositions(true);
    }
  }, [isDefiTabActive, hasWeb3WalletBalance, shouldFetchDefiPositions]);

  const dappWalletHeader = useMemo(() => {
    if (hasWeb3WalletBalanceDataComponentExperiment) {
      return (
        <Web3WalletBalanceHeaderDataComponent
          queryRef={query?.viewer}
          label={formatMessage(messages.title)}
          trailingIcon={<Web3WalletBrowserButton />}
        />
      );
    }
    if (hasWeb3BalanceExperiment) {
      return (
        <Web3WalletBalanceHeader
          queryRef={query?.viewer}
          label={formatMessage(messages.title)}
          trailingIcon={<Web3WalletBrowserButton />}
        />
      );
    }

    return (
      <DappWalletBalanceHeader
        queryRef={query?.viewer}
        label={formatMessage(messages.title)}
        trailingIcon={<Web3WalletBrowserButton />}
      />
    );
  }, [
    hasWeb3WalletBalanceDataComponentExperiment,
    hasWeb3BalanceExperiment,
    query?.viewer,
    formatMessage,
  ]);

  const dappWalletQuickActions = useMemo(() => {
    return (
      <VStack>
        {!!(shouldOffboard && !dismissOffboardingMessage) && (
          <TempCBKEOffBoarding
            dismissBanner={toggleDismissOffboardingMessage}
            showOffBoardingModal={toggleShowOffBoardingModal}
          />
        )}
      </VStack>
    );
  }, [
    dismissOffboardingMessage,
    shouldOffboard,
    toggleDismissOffboardingMessage,
    toggleShowOffBoardingModal,
  ]);

  const dappTabNavigation = useMemo(() => {
    return (
      <VStack spacingStart={gutter} background>
        {tabNavigation}
      </VStack>
    );
  }, [tabNavigation]);

  const arBanner = useMemo(() => {
    if (isWeb3WalletInRecovery(walletState)) {
      return <AccountRecoveryBanner />;
    }

    return null;
  }, [walletState]);

  const renderItem = useCallback(
    ({ item }: { item: (typeof flatListData)[number] }) => {
      if (item.id === 'arBanner') return arBanner;
      if (item.id === 'header') return dappWalletHeader;
      if (item.id === 'quickActions') return dappWalletQuickActions;
      if (item.id === 'tabNavigation') return dappTabNavigation;
      if (item.id === 'tabContent') return tabView;
      return null;
    },
    [
      arBanner,
      dappWalletHeader,
      dappWalletQuickActions,
      dappTabNavigation,
      tabView,
    ],
  );

  const dappWalletTrayText = useDappWalletTrayData(formatMessage);

  return (
    <Screen
      testID="DAppWallet"
      scrollable={false}
      scrollRefOverride={scrollRef}
      scrollableChild={scrollableChildRef.current}
      navHeader={navHeader}
      noSpacing
    >
      <VStack spacingHorizontal={gutter} height="100%" flexGrow={1}>
        <AnimatedFlatList
          ref={flatlistRef}
          data={flatListData}
          keyExtractor={keyExtractor}
          refreshControl={refreshControl}
          renderItem={renderItem}
          onScroll={customOnScroll}
          stickyHeaderIndices={[STICKY_HEADER_INDEX]}
          contentContainerStyle={styles.contentContainer}
        />
      </VStack>

      <GlobalActionsContainer animatedStyle={animatedStyleBackground}>
        <DappWalletQuickActions
          animatedStyleLeft={animatedStyleFirst}
          animatedStyleRight={animatedStyleSecond}
          queryRef={query}
        />
      </GlobalActionsContainer>

      <WalletExplainerTray
        onDismiss={hideExplainerTray}
        isVisible={explainerTrayVisible}
        data={dappWalletTrayText}
      />

      {showOffBoardingModal && (
        <TempCBKEOffBoardingModal
          toggleShowOffBoardingModal={toggleShowOffBoardingModal}
        />
      )}
    </Screen>
  );
});

const DappWalletScreenEligibilityCheck = memo(
  function DappWalletScreenEligibilityCheck() {
    const [isEligible, networkError] = useIsWeb3WalletEligible();

    if (!isEligible && !networkError) {
      return (
        <Screen testID="DAppWallet">
          <Web3IneligibleErrorContent contextType="web3Wallet" />
        </Screen>
      );
    }

    return <DAppWalletScreenContent />;
  },
);

export const DAppWalletScreen = memo(function DAppWalletScreen() {
  return (
    <ScreenBoundary
      instrumentationId="DAppWalletScreen"
      fallback={<DappWalletScreenLoadingFallback />}
      errorFallback={DAppWalletErrorFallback}
      willErrorBlockUser
    >
      <DappWalletScreenEligibilityCheck />
    </ScreenBoundary>
  );
});

const DAppWalletErrorFallback = memo(function DAppWalletErrorFallback({
  onRetry,
}: ErrorBoundaryFallbackProps) {
  const refetchFailed = useRefetchFailed();

  const clearError = useCallback(() => {
    refetchFailed();
    onRetry?.();
  }, [onRetry, refetchFailed]);

  return (
    <Screen testID="DAppWalletErrorFallback">
      <DappMarketplaceV2ErrorComponent
        tab="web3Wallet"
        illustration="web3ActivityError"
        align="center"
        onClearError={clearError}
        spacingHorizontal={0}
      />
    </Screen>
  );
});

