function useContentfulWeb3ActionComplete(slug: string) {
  const content = useContentfulFields<ContentfulWeb3ActionCompleteFields>(
    {
      queryParams: {
        content_type: 'web3ActionComplete',
        'fields.slug': slug,
        include: '1',
      },
    },
    true,
  );

  return useMemo(() => {
    if (!content) {
      return null;
    }

    const fieldData = content.items[0].fields;
    return flattenContentfulResponse<ContentfulWeb3ActionCompleteFields>(
      fieldData,
      content.includes as Includes,
    );
  }, [content]);
}

