  const content = useContentfulWeb3ActionComplete(contentSlug);

  if (!content) {
    throw new Error('Failed to fetch content for Web3 action complete.');
  }

  const { title, description, secondaryCta, nextScreen, web3BadgeCampaign } =
    content;

  const { formatMessage } = useIntl();
  const navigation = useStackNavigation();
  const { navigate, pop } = navigation;
  const spectrum = useSpectrum();
  const { bottom } = useDimensions();
  const layoutStyle = useMemo(() => ({ paddingBottom: bottom }), [bottom]);

  const handleSecondaryAction = useCallback(() => {
    if (secondaryCta?.action) {
      navigation[secondaryCta.action.type]?.(...secondaryCta.action.to);
    }
  }, [navigation, secondaryCta?.action]);

  const dismiss = useCallback(() => {
    if (nextScreen) {
      navigate(...(nextScreen as NavigateArgs));
    } else {
      pop();
    }
  }, [navigate, nextScreen, pop]);

  const navHeader = useMemo(
    () => ({ action: 'close' as const, backHandler: dismiss }),
    [dismiss],
  );

  const heroImage =
    spectrum === 'light'
      ? content.heroImageLightMode?.file
      : content.heroImageDarkMode?.file;

  useTrackDefiScreenOnMount({
    flow: 'web3_action',
    step: 'action_complete',
    otherParams: {
      content_slug: contentSlug,
      web3_badge_campaigns: web3BadgeCampaign ? [web3BadgeCampaign] : undefined,
    },
  });

  const [setWeb3UserFlag] = useMutation<Web3ActionCompleteUserFlagMutation>(
    graphql`
      mutation Web3ActionCompleteUserFlagMutation(
        $input: DefiSetUserFlagInput!
      ) {
        defiSetUserFlag(input: $input) {
          __typename
        }
      }
    `,
  );

  useOnMount(() => {
    if (
      web3BadgeCampaign &&
      legacyCampaignsNotUsingManagementTool.includes(web3BadgeCampaign)
    ) {
      const flag = `${web3BadgeCampaign.toUpperCase()}_PENDING` as DefiUserFlag;
      setWeb3UserFlag({
        variables: {
          input: {
            flag,
            value: true,
          },
        },
        onCompleted: ({ response }) => {
          matchUnion(response.defiSetUserFlag).when(
            'DefiSetUserFlagSuccess',
            () => {
              log(`Set user flag ${flag} successfully`);
            },
          );
        },
        onError: () => {
          // It is tolerable that this fails. The user just won't see the NFT arrival
          // announcement but they will still get the NFT.
        },
      });
    }
  });

  return (
    <Screen navHeader={navHeader}>
      {!!heroImage && (
        <HeroImage>
          <RemoteImage
            source={heroImage.url && `https:${heroImage.url}`}
            width={heroImage.details.image.width}
            height={heroImage.details.image.height}
            resizeMode="contain"
          />
        </HeroImage>
      )}
      <VStack gap={2} flexGrow={1} spacingTop={2} style={layoutStyle}>
        <TextTitle3 align="center">{title}</TextTitle3>
        <RichText align="center" contents={description} />

        <Spacer />

        <ButtonGroup
          block
          accessibilityLabel={formatMessage(messages.buttonGroup)}
          direction="vertical"
        >
          <Button variant="primary" spacingBottom={0} onPress={dismiss}>
            {formatMessage(messages.done)}
          </Button>
          {!!secondaryCta && (
            <Button
              variant="secondary"
              spacingBottom={0}
              onPress={handleSecondaryAction}
            >
              {secondaryCta.label}
            </Button>
          )}
        </ButtonGroup>
      </VStack>
    </Screen>
  );
}

// If the screen fails to render, we just pop the screen off the stack and avoid showing an error
// to the user.
function ErrorFallback() {
  const { pop } = useStackNavigation();
  useOnMount(() => {
    pop();
  });

  // eslint-disable-next-line react/jsx-no-useless-fragment
  return <></>;
}

export function Web3ActionCompleteScreen() {
  return (
    <ScreenBoundary
      instrumentationId="Web3ActionCompleteScreen"
      errorFallback={ErrorFallback}
      willErrorBlockUser={false}
    >
      <Web3ActionComplete />
    </ScreenBoundary>
  );
}

