const i18nKey = 'SeeAllAssetsScreen';
const messages = defineMessages({
  searchAllAssetsLabel: {
    id: `${i18nKey}.searchAllAssetsLabel`,
    defaultMessage: 'Seach all assets',
    description: 'Accessibility label to display asset search bar',
  },
});

const seeAllAssetsScreenWrapperQuery = graphql`
  query SeeAllAssetsScreenQuery(
    $nativeCurrency: TickerSymbol!
    $filter: AssetSearchFilter!
    $sort: AssetSearchSort
    $order: SortOrder
    $query: String
    $first: Int!
    $after: String
    $resolution: SearchResolution
    $skipWallet: Boolean!
    $skipDex: Boolean!
    $hideSparkline: Boolean!
    $skipSwipeActions: Boolean!
    $userCountryCode: CountryCode!
  ) {
    ...SeeAllAssetsScreenFragment
      @arguments(
        filter: $filter
        sort: $sort
        order: $order
        query: $query
        first: $first
        after: $after
        resolution: $resolution
        skipWallet: $skipWallet
        skipDex: $skipDex
      )
  }
`;

type AssetListProps = {
  // Callback for when the user begins scrolling on the list
  onScroll: ComponentProps<typeof FlatList>['onScroll'];
  // Arguments to send up to searchAssets endpoint
  assetSearchArgs: {
    sortKey: AssetSearchSort;
    isAscending: boolean;
    filterKey: AssetSearchFilter;
    pageSize: number;
  };
  // Set this if you want to apply an additional filter on top of the API filters
  additionalFilter?: FilterFunction;
  // Set this if you want to override the sort order from the API.
  // This is not recommended but has been added as a workaround
  // to account for sorting issues with the searchAssets API.
  // See [INSERT JIRA HERE]
  sortOverrideFunction?: SortFunction;
  // Callback when an asset is tapped
  onAssetTapped?: (index: number, symbol: string) => void;
  pageName?: PageKey;
  shouldNavigateToAssetOnPress?: boolean;
};

const AssetList = memo(
  forwardRef<FlatList, AssetListProps>(
    (
      {
        onScroll,
        assetSearchArgs: { sortKey, isAscending, filterKey, pageSize },
        additionalFilter,
        sortOverrideFunction,
        onAssetTapped,
        pageName,
        shouldNavigateToAssetOnPress,
      }: AssetListProps,
      forwardedRef,
    ) => {
      const nativeCurrency = useNativeCurrency();
      const hideSparkline = useKillSwitch('kill_sparkline_data_rn');
      const swipeActionsVariant = useIsSwipeActionsExperiment();
      const isSwipeActionsKilled = swipeActionsVariant === 'control';
      const countryCode = useCachedCountryCode() ?? '';
      // Reverse the sort order for rank since rank is opposite of market cap
      // and we actually want to sort by market cap
      const isSortOrderAscending = useMemo(
        () => (sortKey === 'RANK' ? !isAscending : isAscending),
        [isAscending, sortKey],
      );

      const queryParams = useMemo((): SeeAllAssetsScreenQuery$variables => {
        return {
          filter: filterKey,
          nativeCurrency,
          first: pageSize,
          sort: sortKey,
          order: isSortOrderAscending ? 'ASC' : 'DESC',
          resolution: 'DAY',
          // Do not include Dex and Wallet for New on Coinbase
          skipWallet: filterKey === 'RECENTLY_LISTED',
          skipDex: filterKey === 'RECENTLY_LISTED',
          hideSparkline,
          skipSwipeActions: isSwipeActionsKilled,
          userCountryCode: countryCode,
        };
      }, [
        countryCode,
        filterKey,
        hideSparkline,
        isSortOrderAscending,
        isSwipeActionsKilled,
        nativeCurrency,
        pageSize,
        sortKey,
      ]);

      const queryData = useLazyLoadQuery<SeeAllAssetsScreenQuery>(
        seeAllAssetsScreenWrapperQuery,
        queryParams,
      );

      const { refresh } = useRefreshQuery<SeeAllAssetsScreenQuery>(
        seeAllAssetsScreenWrapperQuery,
        queryParams,
      );

      const { data, loadNext, hasNext, isLoadingNext } = usePaginationFragment<
        SeeAllAssetsScreenQuery,
        SeeAllAssetsScreenFragment$key
      >(
        graphql`
          fragment SeeAllAssetsScreenFragment on Query
          @argumentDefinitions(
            first: { type: "Int!" }
            after: { type: "String" }
            filter: { type: "AssetSearchFilter!" }
            order: { type: "SortOrder" }
            query: { type: "String" }
            sort: { type: "AssetSearchSort" }
            resolution: { type: "SearchResolution" }
            skipWallet: { type: "Boolean!" }
            skipDex: { type: "Boolean!" }
          )
          @refetchable(queryName: "SeeAllAssetsPaginationQuery") {
            # eslint-disable-next-line relay/must-colocate-fragment-spreads
            ...SwipeableRowFragment
            viewer @required(action: THROW) {
              searchAssets(
                filter: $filter
                sort: $sort
                order: $order
                query: $query
                first: $first
                after: $after
                resolution: $resolution
              ) @connection(key: "SeeAllAssetsScreenFragment_searchAssets") {
                edges {
                  ...SeeAllAssetsListFragment
                  node {
                    asset {
                      platformName
                    }
                    ...useSortedAssetsSortFunctionFragment
                    ...useFilteredAssetsFilterFunctionFragment
                      @arguments(skipWallet: $skipWallet, skipDex: $skipDex)
                  }
                }
              }
            }
          }
        `,
        queryData,
      );
      const fetchNextPage = useCallback(() => {
        if (hasNext) {
          loadNext(pageSize);
        }
      }, [hasNext, loadNext, pageSize]);

      const isClientSortKillSwitchActive = useKillSwitch(
        'kill_rn_explore_tab_client_sorting',
      );

      const assetEdges = useMemo(() => {
        const nonNullAssets = filterNulls(
          data.viewer.searchAssets?.edges,
        ).filter((it) => !!it.node);

        const filteredAssets = additionalFilter
          ? nonNullAssets.filter(
              (edge) => edge.node && additionalFilter(edge.node),
            )
          : nonNullAssets;

        if (sortOverrideFunction && !isClientSortKillSwitchActive) {
          filteredAssets.sort((a, b) =>
            a.node && b.node ? sortOverrideFunction(a.node, b.node) : 0,
          );
        }

        return filteredAssets;
      }, [
        additionalFilter,
        data.viewer.searchAssets?.edges,
        isClientSortKillSwitchActive,
        sortOverrideFunction,
      ]);

      const onPress = useCallback(
        (index: number) => {
          const symbol = assetEdges[index]?.node?.asset?.platformName;
          if (symbol) {
            onAssetTapped?.(index, symbol);
          }
        },
        [assetEdges, onAssetTapped],
      );
      return (
        <SeeAllAssetsList
          onScroll={onScroll}
          ref={forwardedRef}
          viewerAssetEdgesRef={assetEdges}
          isLoadingNext={isLoadingNext}
          handleEndReached={fetchNextPage}
          onPress={onPress}
          refresh={refresh}
          pageName={pageName}
          swipeQueryRef={data}
          shouldNavigateToAssetOnPress={shouldNavigateToAssetOnPress}
        />
      );
    },
  ),
);

const AssetListWrapper = memo(
  forwardRef<FlatList, AssetListProps>((props, forwardedRef) => {
    return (
      <NetworkBoundary
        errorFallback={null}
        suspenseFallback={<SeeAllAssetsFallback />}
      >
        <AssetList {...props} ref={forwardedRef} />
      </NetworkBoundary>
    );
  }),
);

export const SeeAllAssetsScreen = memo(() => {
  const { assetListType, onAssetTapped, pageName, source } =
    useParams<'ExploreTabSeeAllAssets'>();
  const config = assetListToConfig[assetListType];
  const { formatMessage } = useIntl();
  const isExploreRAV4 = useIsExploreRAV4();

  useEffect(() => {
    if (source === 'explore') {
      logEvent('homepage_analytics', {
        action: ActionType.render,
        componentType: ComponentType.page,
        type: 'explore_all_assets',
      });
    }
  }, [source]);

  const { scrollRef, onScroll } = useNavHeaderScrolling();

  const { trackSearchQuery, trackSearchResultTapped } = useTrackSearch(
    config.analyticsEventData.componentName,
    source,
  );

  const onSearchResultTapped = useCallback(
    (query: string, index: number, assetSymbol: string, assetId: string) =>
      trackSearchResultTapped(query, index + 1, assetSymbol, assetId),
    [trackSearchResultTapped],
  );

  const [searchInput, setSearchInput] = useState('');
  const { isSearching, setIsSearching, debouncedInput, setSearchBarTextInput } =
    useSearchBar({
      lowerCaseSearch: true,
      debounce: TRADETAB_SEARCH_DEBOUNCE,
    });

  const onSearchResults = useCallback(
    (query: string, numResults: number) => {
      if (isSearching) {
        trackSearchQuery(query, numResults);
      }
    },
    [isSearching, trackSearchQuery],
  );

  const assetListRef = useRef<FlatList>(null);

  const {
    sortOptions,
    currentSortSelection,
    setSortSelection,
    isSortActive,
    isSortingTrayShowing,
    showSortingTray,
    hideSortingTray,
    sortFunction,
  } = useSortedAssets({ assetListType });

  const {
    filterOptions,
    activeFilter,
    setActiveFilter,
    isFilterActive,
    filterFunction,
    isFilterTrayShowing,
    showFilterTray,
    hideFilterTray,
  } = useFilteredAssets({ assetListType });

  const scrollToTop = useCallback(
    () => assetListRef.current?.scrollToOffset({ offset: 0, animated: true }),
    [],
  );

  const onFilterSelected = useCallback(
    (selectedFilter: FilterType) => {
      scrollToTop();
      setActiveFilter(selectedFilter);
    },
    [scrollToTop, setActiveFilter],
  );

  const onSortSelected = useCallback(
    (key: SortType, isAscending: boolean) => {
      scrollToTop();
      setSortSelection({ key, isAscending });
    },
    [scrollToTop, setSortSelection],
  );

  const searchInputRef = useRef<TextInput>(null);

  const [startSearchAssetPerfMark] = usePerfMark(
    'simple_trade',
    'search_asset_explore_tab',
  );

  const setSearchQuery = useCallback(
    (query: string) => {
      setSearchInput(query);
      setSearchBarTextInput(query);
      startSearchAssetPerfMark();
      markJourney('search_asset_explore_screen');
    },
    [setSearchBarTextInput, startSearchAssetPerfMark],
  );

  const searchToggle = useMemo(
    () =>
      isSearching ? (
        <Box background="background" width="100%">
          <SearchInput
            ref={searchInputRef}
            compact
            value={searchInput}
            onBack={() => {
              setSearchQuery('');
              setIsSearching(false);
            }}
            onChangeText={(input: string) => {
              setSearchQuery(input);
            }}
          />
        </Box>
      ) : (
        <IconButton
          accessibilityLabel={formatMessage(messages.searchAllAssetsLabel)}
          name="search"
          onPress={() => setIsSearching(true)}
        />
      ),
    [isSearching, searchInput, setIsSearching, formatMessage, setSearchQuery],
  );

  const sortFilterToggles = useMemo(() => {
    return (
      <HStack spacingVertical={1} spacingHorizontal={3}>
        {sortOptions.length > 0 && (
          <SortingPill
            isActive={isSortActive}
            label={currentSortSelection.label}
            isAscending={currentSortSelection.isAscending}
            onPress={showSortingTray}
          />
        )}
        <Spacer horizontal={0.5} />
        {filterOptions.length > 0 && assetListType !== 'TRADABLE_ONLY' && (
          <MultiFilterPill
            label={activeFilter.label}
            isActive={isFilterActive}
            onPress={showFilterTray}
            isTrayShowing={isFilterTrayShowing}
            testID="MultiFilterPill"
          />
        )}
      </HStack>
    );
  }, [
    activeFilter.label,
    assetListType,
    currentSortSelection.isAscending,
    currentSortSelection.label,
    filterOptions.length,
    isFilterActive,
    isFilterTrayShowing,
    isSortActive,
    showFilterTray,
    showSortingTray,
    sortOptions.length,
  ]);

  const trackAssetTapped = useTrackAssetTapped(
    config.analyticsEventData.componentName,
    source,
    currentSortSelection.apiKey,
    currentSortSelection.isAscending,
    activeFilter.key,
    'DAY',
  );

  const handleAssetTapped = useCallback(
    (index: number, symbol: string) => {
      onAssetTapped?.(index, symbol);
      trackAssetTapped(index + 1, symbol);
    },
    [onAssetTapped, trackAssetTapped],
  );

  useDisableResizingWithKeyboard();

  useEffect(() => {
    if (isSearching) {
      searchInputRef.current?.focus();
    }
  }, [isSearching]);

  return (
    <ScreenBoundary instrumentationId="SeeAllAssetsScreen">
      <Screen
        scrollRefOverride={scrollRef}
        navHeader={{
          title: formatMessage(
            isExploreRAV4 ? seeAllAssetsMessages.prices : config.title,
          ),
          bordered: false,
          trailing: () => {
            return searchToggle;
          },
        }}
        noSpacing
        scrollable={false}
      >
        <AssetListPriceProvider>
          <VStack>
            {sortFilterToggles}
            {!!scrollRef && (
              <NavBarBorderBottom scrollRef={scrollRef} bordered />
            )}
          </VStack>
          <AssetListWrapper
            onScroll={onScroll}
            ref={assetListRef}
            onAssetTapped={handleAssetTapped}
            shouldNavigateToAssetOnPress={!onAssetTapped}
            pageName={pageName}
            assetSearchArgs={{
              sortKey: currentSortSelection.apiKey,
              filterKey: config.filter,
              isAscending: currentSortSelection.isAscending,
              pageSize: config.pageSize,
            }}
            additionalFilter={filterFunction}
            sortOverrideFunction={sortFunction}
          />
          {isFilterTrayShowing && (
            <FilterTray
              isTrayVisible={isFilterTrayShowing}
              filterOptions={filterOptions}
              activeFilterKey={activeFilter.key}
              onDismiss={hideFilterTray}
              onFilterSelected={onFilterSelected}
            />
          )}
          {isSortingTrayShowing && (
            <SortingTray
              sortOptions={sortOptions}
              isTrayVisible={isSortingTrayShowing}
              onDismiss={hideSortingTray}
              onSortOptionSelected={onSortSelected}
              activeSortOption={currentSortSelection}
            />
          )}
          <AssetSearchResults
            searchQuery={debouncedInput}
            isSearching={isSearching}
            filter={config.filter}
            onSearchResults={onSearchResults}
            onSearchResultTapped={onSearchResultTapped}
            pullToRefreshEnabled
            source={source}
          />
        </AssetListPriceProvider>
      </Screen>
    </ScreenBoundary>
  );
});

