const i18nKey = 'InteracWithdrawConfirmationScreen';
const messages = defineMessages({
  withdrawEmail: {
    id: `${i18nKey}.withdrawEmail`,
    defaultMessage: 'We sent an email to {email}. ',
    description:
      'Message to inform user that email to initiate transfer has been sent',
  },
  withdrawInfo: {
    id: `${i18nKey}.depsoitInfo`,
    defaultMessage:
      'Your funds may be automatically deposited in your account. If prompted, the answer to the security question is this reference number:',
    description: 'Message about the deposit details',
  },
  openEmail: {
    id: `${i18nKey}.email`,
    defaultMessage: 'Open email',
    description: 'Button text for opening email client',
  },
  done: {
    id: `${i18nKey}.done`,
    defaultMessage: 'Done',
    description: 'Done button text for user to navigate back to app home',
  },
});
const navHeader = {
  action: 'none',
} as const;

const InteracWithdrawConfirmationContent = memo(() => {
  const { accountId, transferId, amount, userReference } =
    useParams<'InteracWithdrawConfirmation'>();
  const { formatMessage } = useIntl();
  const { replace } = useStackNavigation();
  const formatCurrency = useCurrencyFormatter();
  const requestReview = useRequestReview();

  const openEmailClient = useCallback(() => {
    void openInbox({});
  }, []);

  const onDonePress = useCallback(() => {
    logEvent('interac_withdraw_done_clicked', {
      action: ActionType.click,
      componentType: ComponentType.button,
    });
    replace(SIGNED_IN_APP_STACK_NAME, {});
  }, [replace]);

  useLogEventOnMount('interac_withdraw_confirmation', {
    componentType: ComponentType.page,
    action: ActionType.view,
    category: 'withdraw',
    context: 'withdraw_status',
  });
  type ViewerProp = {
    viewer: InteracWithdrawConfirmationScreenQuery$data['viewer'];
  };

  const { viewer }: ViewerProp =
    useLazyLoadQuery<InteracWithdrawConfirmationScreenQuery>(
      graphql`
        query InteracWithdrawConfirmationScreenQuery {
          viewer @required(action: THROW) {
            userProperties {
              email
            }
          }
        }
      `,
      {},
      {
        fetchPolicy: 'network-only',
      },
    );

  const email = viewer.userProperties?.email ?? '';
  const withdrawCurrency = amount?.currency ?? 'CAD';
  const withdrawAmount = amount?.value ?? '';

  const { status: transferStatus } = useTransactionStatus({
    accountId,
    transferId,
    transferType: 'withdrawal',
  });

  const copyCode = useCallback(() => {
    logEvent('interac_withdraw_reference_code_copied', {
      componentType: ComponentType.button,
      action: ActionType.click,
    });
    void setStringAsync(userReference || '');
  }, [userReference]);

  const status = useMemo(() => {
    return transferStatus === 'pending' ? 'success' : transferStatus;
  }, [transferStatus]);

  const isSuccess = status === 'success';
  useEffect(() => {
    if (isSuccess) {
      markJourney('load_withdraw_confirmation_screen');
    }
    return () => {
      if (isSuccess) void requestReview();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isSuccess]);

  let transferStatusComponent: ReactNode;
  switch (status) {
    case 'loading':
      transferStatusComponent = (
        <LottieStatusAnimation width="auto" height="auto" status="loading" />
      );
      break;
    case 'success':
    default:
      transferStatusComponent = (
        <HeroScreenLayout
          image={
            <SpotSquare
              name="confirmEmail"
              dimension="96x96"
              scaleMultiplier={1.5}
            />
          }
          top={
            <Box offsetTop={5}>
              <TextTitle1 spacingBottom={1} align="center" color="primary">
                {formatCurrency({
                  amount: withdrawAmount,
                  currency: { code: withdrawCurrency, type: 'fiat' },
                  isSensitive: false,
                  minimumFractionDigits: 2,
                })}
              </TextTitle1>
              <TextHeadline align="center">
                {formatMessage(messages.withdrawEmail, { email })}
              </TextHeadline>
            </Box>
          }
          bottom={
            <Box top={20}>
              <TextBody color="foregroundMuted" align="center">
                {formatMessage(messages.withdrawInfo)}
              </TextBody>
              <HStack alignItems="center" justifyContent="center">
                <TextTitle3 color="foreground">{userReference}</TextTitle3>
                <IconButton transparent name="copy" onPress={copyCode} />
              </HStack>
            </Box>
          }
          button={
            <>
              <Button block variant="secondary" onPress={onDonePress}>
                {formatMessage(messages.done)}
              </Button>
              <Button block onPress={openEmailClient}>
                {formatMessage(messages.openEmail)}
              </Button>
            </>
          }
        />
      );
      break;
  }
  return <Screen navHeader={navHeader}>{transferStatusComponent}</Screen>;
});

export const InteracWithdrawConfirmationScreen = memo(() => (
  <ScreenBoundary instrumentationId="InteracWithdrawConfirmationScreen">
    <InteracWithdrawConfirmationContent />
  </ScreenBoundary>
));

