const supportUrl = getFeeLink(locale);

export type PreviewTransferBuy = {
  type: 'buy';
  data: TransferBuyResponse;
};

export type PreviewTransferSell = {
  type: 'sell';
  data: TransferSellResponse;
};

export type TradePreviewContentProps = {
  queryRef: TradePreviewContentFragment$key;
  transfer: PreviewTransferBuy | PreviewTransferSell;
  paymentMethod: PaymentMethodInterface;
  userWarnings: UserWarningsSellResponse | UserWarningsBuyResponse;
  inputCurrency: CurrencyStub; // TODO: [DL-313] used in the `recurringPayment` logic below
  bottomDetails?: ReactNode[];
  transferSource?: TransferSource;
  highlightRowMap?: HighlightRowMap;
  livePricesEnabled?: boolean;
  isSignificantPriceChange?: boolean;
  triggerConvertTradeToRecurring?: (recurringPeriod?: RecurringPeriod) => void;
  showConvertTradeToRecurring?: boolean;
  isRefreshingBuyQuote?: boolean;
  showSubscriptionSignupCell?: boolean;
  onSubscriptionSignupSuccess?: () => void;
  isSuccessfulSubscriptionSignup?: boolean;
  shouldBuyAndStake?: boolean;
  onShouldBuyAndStakeChange?: (checked: boolean) => void;
  applyTradePromoCode?: (
    promoCode: string | null,
    tradeFiatAmount: string | null,
    tradeFiatCurrencyCode: string | null,
  ) => void;
  applyTradePromoCodeData?:
    | ApplyTradePromoCodeData
    | ApplyTradePromoCodeError
    | null;
  resetTradePromoCode?: () => void;
  showTradePromoCode?: boolean;
  cashOperation?: CashOperation;
};

export const TradePreviewContent = memo<TradePreviewContentProps>(
  ({
    queryRef,
    transfer,
    paymentMethod,
    userWarnings,
    inputCurrency,
    bottomDetails = [],
    transferSource,
    highlightRowMap,
    livePricesEnabled,
    isSignificantPriceChange,
    triggerConvertTradeToRecurring,
    showConvertTradeToRecurring,
    isRefreshingBuyQuote,
    showSubscriptionSignupCell,
    onSubscriptionSignupSuccess,
    isSuccessfulSubscriptionSignup,
    shouldBuyAndStake,
    onShouldBuyAndStakeChange,
    applyTradePromoCode,
    applyTradePromoCodeData,
    resetTradePromoCode,
    showTradePromoCode,
    cashOperation,
  }) => {
    const query = useFragment(
      graphql`
        fragment TradePreviewContentFragment on Query
        @argumentDefinitions(
          accountId: { type: "Uuid!" }
          productKey: { type: "String!" }
          includeAutoStakingCheck: { type: "Boolean!", defaultValue: false }
        ) {
          # eslint-disable-next-line relay/must-colocate-fragment-spreads
          ...useTradeBenefitDataFragment @arguments(skip: false)
          viewer {
            accountByUuidV2(uuid: $accountId) {
              assetOrFiatCurrency {
                ...useAssetOrCurrencyGraphQLFragment
                ...useAccountRewardApyFragment
                ... on ViewerAsset {
                  ...useBuyAndStakeEligibleFragment
                  ...BuyAndStakeSwitchFragment
                    @arguments(
                      includeAutoStakingCheck: $includeAutoStakingCheck
                    )
                  ...useBuyAndStakeUserWarningsFragment
                }
              }
            }
            coinbaseSubscription(productKey: $productKey) {
              status
              subscriptionPlan {
                type
              }
            }
            # eslint-disable-next-line relay/must-colocate-fragment-spreads: "warn"
            ...useFirstYieldIncentiveEligibleFragment
            userProperties {
              regionFeatures {
                isInSingapore
              }
            }
          }
        }
      `,
      queryRef,
    );
    const { viewer } = query;

    const accountGraphQL = viewer?.accountByUuidV2;
    const isInSingapore = Boolean(
      viewer?.userProperties?.regionFeatures?.isInSingapore,
    );
    const subscriptionStatus =
      viewer?.coinbaseSubscription?.status ?? 'NOT_SUBSCRIBED';
    const hasSubscription =
      viewer?.coinbaseSubscription?.subscriptionPlan?.type !== 'PAUSE_PLAN' &&
      isSubscribed(subscriptionStatus);

    if (!accountGraphQL) {
      const error = new Error('TradePreviewContent: invalid account');
      errorVitals.logError(error, {
        severity: 'error',
        context: 'trade_preview_content',
        isHandled: true,
      });

      throw error;
    }

    const isFirstYieldEligible = useFirstYieldIncentiveEligible(viewer);
    const currency = useAssetOrCurrencyGraphQL(
      accountGraphQL?.assetOrFiatCurrency,
    );

    const displaySymbol = currency?.displayCode;

    if (!currency) {
      const error = new Error('TradePreviewContent: invalid currency');
      errorVitals.logError(error, {
        severity: 'error',
        context: 'trade_preview_content',
        isHandled: true,
      });

      throw error;
    }

    const { formatMessage } = useIntl();
    const formatCurrency = useCurrencyFormatter();

    const hasRetailAdvancedTrade = useIsAdvancedTradeAvailable();

    const amount = transfer.data?.amount;
    const subtotal = transfer.data?.subtotal;
    const fee = transfer.data?.fee;
    const transferFeeValue = fee?.value;
    const transferFeeValueAsNumber =
      transferFeeValue && !Number.isNaN(parseFloat(transferFeeValue))
        ? parseFloat(transferFeeValue)
        : null;
    const unitPrice = transfer.data?.unitPrice;
    const total = transfer.data?.total;

    const subscriptionFeeBenefit = transfer?.data
      ? parseSimpleTradeBenefitFromQuote(transfer?.data, transfer.type)
      : undefined;

    const taxTitleMessage: Record<string, string> = useMemo(
      () => ({
        INDIA_WITHHOLDING: formatMessage(messages.tds),

        AUSTRALIA_GST: formatMessage(messages.gst),
        SINGAPORE_GST: formatMessage(messages.gst),
      }),
      [formatMessage],
    );

    const display = useMemo(() => {
      return {
        currencyCode: currency.code,
        subtotalAmount: subtotal?.value,
        subtotalCurrency: subtotal?.currency,
        fiatAmount: unitPrice?.amount.value,
        fiatCurrency: unitPrice?.amount.currency,
        unitPriceCurrency: unitPrice?.amount.currency,
        totalValue: total?.value,
        totalValueCurrency: total?.currency,
        amountValue: amount?.value,
        currency,
      };
    }, [
      amount?.value,
      currency,
      subtotal?.currency,
      subtotal?.value,
      total?.currency,
      total?.value,
      unitPrice?.amount.currency,
      unitPrice?.amount.value,
    ]);

    const { tapTracker } = useTransferTracker({
      context: 'confirmation',
      currencyCode: display.currencyCode,
      transferType: transfer.type,
    });
    const feeTappedEventString =
      transfer.type === 'buy'
        ? 'tapped_buy_fee_explanation_button'
        : 'tapped_sell_fee_explanation_button';
    const isRecurring = Boolean(
      transfer.type === 'buy' && transfer?.data?.recurringPayment,
    );

    const isBuyAndStakeEligible = useBuyAndStakeEligible({
      viewerAssetRef: accountGraphQL?.assetOrFiatCurrency,
    });
    const buyAndStakeUserWarnings = useBuyAndStakeUserWarnings(
      accountGraphQL?.assetOrFiatCurrency,
    );

    const allUserWarnings = useMemo(() => {
      if (shouldBuyAndStake && userWarnings) {
        return [...buyAndStakeUserWarnings, ...userWarnings];
      }
      return userWarnings;
    }, [shouldBuyAndStake, buyAndStakeUserWarnings, userWarnings]);

    const [isToggled, { toggleOn, toggleOff }] = useToggler(false);
    const [tooltipTrayContent, setTooltipTrayContent] = useState<
      TrayContent | undefined
    >();
    const isUSDCTrade = transfer?.data?.amount.currency === 'USDC';
    const [isShowingPriceChangeTray, setIsShowingPriceChangeTray] =
      useState(false);
    const [isShowingLivePricesTray, setIsShowingLivePricesTray] =
      useState(false);
    const { pop } = useStackNavigation();

    useEffect(() => {
      setIsShowingPriceChangeTray(isSignificantPriceChange ?? false);
    }, [isSignificantPriceChange]);

    // CB1
    const tradeBenefitData = useTradeBenefitData(query);
    // will only show this banner for the capped version of the ZTF benefit
    // may need to adjust design if we ever decide to resume supporting uncapped fee free trading
    const showSubscriptionBanner =
      (hasSubscription || isSuccessfulSubscriptionSignup) &&
      tradeBenefitData !== null &&
      isCappedBenefitData(tradeBenefitData);
    const [
      subscriptionSignupFlowTrayVisible,
      {
        toggleOn: toggleSubscriptionSignupFlowTrayOn,
        toggleOff: toggleSubscriptionSignupFlowTrayOff,
      },
    ] = useToggler(false);

    const tooltipTitle = useMemo(() => {
      if (isRecurring) {
        return formatMessage(messages.feeTrayTitleRecurring);
      }
      return transfer.type === 'buy'
        ? formatMessage(messages.feeTrayTitleBuy)
        : formatMessage(messages.feeTrayTitleSell);
    }, [formatMessage, isRecurring, transfer.type]);

    const tooltipContent = useMemo(() => {
      let formattedMessage;

      if (isRecurring) {
        if (isUSDCTrade) {
          formattedMessage = formatMessage(
            messages.feeTrayContentRecurringUSDCNoCommission,
          );
        } else {
          formattedMessage = hasRetailAdvancedTrade
            ? formatMessage(messages.feeTrayContentRecurringAdvancedTrade)
            : formatMessage(messages.feeTrayContentRecurring);
        }
      } else if (isUSDCTrade) {
        formattedMessage = formatMessage(
          messages.feeTrayContentUSDCNoCommission,
        );
      } else {
        formattedMessage = formatMessage(messages.feeTrayContentUpdated, {
          link: TradingFeesLink,
        });
      }
      return formattedMessage;
    }, [formatMessage, hasRetailAdvancedTrade, isRecurring, isUSDCTrade]);

    const handleFeeInfoPress = useCallback(() => {
      tapTracker(feeTappedEventString);
      setTooltipTrayContent({
        title: tooltipTitle,
        message: tooltipContent,
        cta: {
          type: 'link',
          urlOrAction: supportUrl,
          text: formatMessage(messages.learnMore),
        },
        postMessageContent:
          showSubscriptionBanner && tradeBenefitData ? (
            <SubscriptionTradingBanner tradeBenefitData={tradeBenefitData} />
          ) : null,
        dismiss: {
          text: formatMessage(messages.ok),
        },
      });
      toggleOn();
    }, [
      showSubscriptionBanner,
      tapTracker,
      feeTappedEventString,
      tooltipTitle,
      tooltipContent,
      formatMessage,
      toggleOn,
      tradeBenefitData,
    ]);

    const handleUnstakingInfoPress = useCallback(
      (info: InfoTrayType) => {
        if (info) {
          setTooltipTrayContent({
            title: info.title,
            message: info.description,
            cta: info.link
              ? {
                  type: 'link',
                  urlOrAction: info.link.url,
                  text: info.link.text,
                }
              : undefined,
            dismiss: {
              text: info.cta,
            },
          });
          toggleOn();
        }
      },
      [toggleOn],
    );

    const handleOneTimeBonusInfoPress = useCallback(() => {
      setTooltipTrayContent({
        title: formatMessage(messages.oneTimeBonusTrayTitle),
        message: formatMessage(messages.oneTimeBonusTrayDetail, {
          asset: displaySymbol,
        }),
        cta: {
          type: 'link',
          urlOrAction:
            'https://help.coinbase.com/en/coinbase/getting-started/getting-started-with-coinbase/first-yield-incentive',
          text: formatMessage(messages.termsApply),
        },
        dismiss: {
          text: formatMessage(messages.gotIt),
        },
      });
      toggleOn();
    }, [displaySymbol, formatMessage, toggleOn]);

    const taxInfo = useCallback(
      (taxType: string) => {
        switch (taxType) {
          case 'INDIA_WITHHOLDING':
            return {
              title: formatMessage(messages.tdsTrayTitle),
              content: formatMessage(messages.tdsTrayContent),
            };
          case 'AUSTRALIA_GST':
            return {
              title: formatMessage(messages.gstTrayTitle),
              content: formatMessage(messages.auGstTrayContent),
            };
          case 'SINGAPORE_GST':
            return {
              title: formatMessage(messages.gstTrayTitle),
              content: formatMessage(messages.sgGstTrayContent),
            };
          default:
            return null;
        }
      },
      [formatMessage],
    );

    const handleTaxInfoPress = useCallback(
      (taxType: string) => {
        const taxTrayInfo = taxInfo(taxType);
        if (taxTrayInfo?.title && taxTrayInfo?.content) {
          setTooltipTrayContent({
            title: taxTrayInfo.title,
            message: taxTrayInfo.content,
            cta: {
              type: 'link',

              urlOrAction: getTaxLink(taxType),

              text: formatMessage(messages.learnMore),
            },
            dismiss: {
              text: formatMessage(messages.done),
            },
          });
          toggleOn();
        }
      },
      [formatMessage, taxInfo, toggleOn],
    );

    const transactionRecurringBuyCellAmount = useMemo(() => {
      if (inputCurrency.type === 'crypto') {
        if (amount?.value) {
          return amount.value;
        }
        return null;
      }
      if (total?.value) {
        return total.value;
      }
      return null;
    }, [amount?.value, inputCurrency.type, total?.value]);

    let confirmationRows: ReactNode[] = [];
    const transactionRecurringBuyCell = transfer.type === 'buy' &&
      !!transfer?.data?.recurringPayment && (
        <TransactionRecurringBuyCell
          key="transactionRecurringBuyCell"
          title={formatMessage(messages.recurring)}
          titleAmount={formatMessage(messages.amount)}
          period={transfer.data.recurringPayment}
          amount={transactionRecurringBuyCellAmount}
          currency={inputCurrency}
          highlightRowMap={highlightRowMap}
        />
      );

    const subscriptionSignupSwitchCell = useMemo(() => {
      return (
        showSubscriptionSignupCell &&
        !!fee &&
        transferFeeValueAsNumber &&
        transferFeeValueAsNumber > 0 &&
        !!transfer.data && (
          <Fragment key="subscriptionTradeUpsellCell">
            <Spacer vertical={1} />
            <SubscriptionTradeUpsellCell
              fee={fee}
              onPress={toggleSubscriptionSignupFlowTrayOn}
              isEligibleForFreeTrial={false}
              tradeVolume={transfer.data.total}
            />
            <Spacer vertical={1} />
          </Fragment>
        )
      );
    }, [
      showSubscriptionSignupCell,
      fee,
      transferFeeValueAsNumber,
      transfer.data,
      toggleSubscriptionSignupFlowTrayOn,
    ]);

    const transactionConvertTradeToRecurringCell = useMemo(
      () =>
        transfer.type === 'buy' &&
        showConvertTradeToRecurring &&
        triggerConvertTradeToRecurring ? (
          <TransactionConvertTradeToRecurringCell
            key="convertTradeToRecurringCell"
            recurringPayment={transfer?.data?.recurringPayment ?? null}
            triggerConvertTradeToRecurring={triggerConvertTradeToRecurring}
            isRefreshingBuyQuote={isRefreshingBuyQuote}
          />
        ) : null,
      [
        transfer,
        showConvertTradeToRecurring,
        isRefreshingBuyQuote,
        triggerConvertTradeToRecurring,
      ],
    );

    const subtotalCellBuyTitle = useMemo(() => {
      if (transfer.type === 'sell') {
        return formatMessage(messages.sale);
      }
      if (cashOperation === 'cash_in') {
        return formatMessage(messages.amount);
      }
      return formatMessage(messages.purchase);
    }, [cashOperation, formatMessage, transfer.type]);

    const subtotalCell = (
      <TransactionFiatAmountCell
        key="subtotal"
        title={subtotalCellBuyTitle}
        amount={display.subtotalAmount ?? null}
        currency={display.subtotalCurrency ?? null}
      />
    );

    const isTaxDetails = transfer.data?.taxDetails?.length;
    const transactionSingaporeFeeCell = !!fee && (
      <TransactionSingaporeFeeCell
        key="coinbaseFeeSingapore"
        fee={{
          amount: fee.value,
          currency: fee.currency,
        }}
        hideSubtitle={Boolean(isTaxDetails)}
        onInfoPress={handleFeeInfoPress}
      />
    );
    const transactionSubscriptionFeeCell = !!subscriptionFeeBenefit && (
      <TransactionSubscriptionFeeCell
        key="coinbaseFeeSubscription"
        onInfoPress={handleFeeInfoPress}
        title={formatMessage(messages.coinbaseFee)}
        subscriptionFeeBenefit={subscriptionFeeBenefit}
        testID="TradePreviewContent_coinbaseFeeSubscription"
      />
    );

    const { originalFee, newFeeMinusOriginalFee } =
      useTradePreviewFeesWithPromoCodeApplied({ transfer });

    const transactionFeeCell = useMemo(
      () =>
        fee ? (
          <TransactionFeeCell
            key="coinbaseFee"
            infoIconAccessibilityLabel={formatMessage(
              messages.coinbaseFeeAccessibilityLabel,
            )}
            onInfoPress={handleFeeInfoPress}
            title={formatMessage(messages.coinbaseFee)}
            detailVariant={cashOperation ? 'positive' : undefined}
            fee={
              cashOperation
                ? formatMessage(messages.free)
                : formatCurrency({
                    amount: newFeeMinusOriginalFee?.value || fee.value,
                    currency: {
                      code: newFeeMinusOriginalFee?.currency || fee.currency,
                      type: 'fiat',
                    },
                    isSensitive: false,
                  })
            }
            testID="fee"
          />
        ) : null,
      [
        fee,

        formatCurrency,
        formatMessage,
        handleFeeInfoPress,
        newFeeMinusOriginalFee?.currency,
        newFeeMinusOriginalFee?.value,
        cashOperation,
      ],
    );

    const fiatAmountCell = useMemo(
      () => (
        <TransactionFiatAmountCell
          key="amount"
          title={formatMessage(messages.currencyPrice, {
            currency: displaySymbol,
          })}
          amount={display.fiatAmount ?? null}
          currency={display.fiatCurrency ?? null}
          scale={unitPrice?.scale}
          infoIconName={livePricesEnabled ? 'lightningBolt' : undefined}
          infoIconAccessibilityLabel={formatMessage(
            messages.currencyPriceAccessibilityLabel,
            {
              currency: displaySymbol,
            },
          )}
          info={livePricesEnabled ? ' ' : undefined} // Requires a non empty string
          onInfoPress={
            livePricesEnabled
              ? () => {
                  setIsShowingLivePricesTray(true);
                }
              : undefined
          }
          testID={livePricesEnabled ? 'live-price' : undefined}
        />
      ),
      [
        display.fiatAmount,
        display.fiatCurrency,
        displaySymbol,
        formatMessage,
        livePricesEnabled,
        unitPrice?.scale,
      ],
    );

    const totalAmountCell = (
      <TransactionFiatAmountCell
        key="total"
        variant="bold"
        title={formatMessage(messages.total)}
        amount={display.totalValue ?? null}
        currency={display.totalValueCurrency ?? null}
      />
    );

    if (!cashOperation) {
      confirmationRows.push(fiatAmountCell);
    }

    if (transfer.type === 'buy' && transferSource === 'fundedSend') {
      confirmationRows.push(
        <TransactionDetailCell
          key="tradeOnCoinbaseCell"
          title={formatMessage(messages.tradeOnCoinbase)}
          detail={formatMessage(messages.instantly)}
        />,
      );
      confirmationRows.push(
        <TransactionDetailCell
          key="withdrawFromCoinbaseCell"
          title={formatMessage(withdrawMessages.cashOutFromCoinbase)}
          detail={formatMessage(messages.instantly)}
        />,
      );
    }

    confirmationRows.push(transactionRecurringBuyCell);
    const depositToTitle = formatMessage(depositMessages.depositToTradePreview);

    confirmationRows.push(
      <TransactionPaymentMethodCell
        key="paymentMethod"
        title={
          transfer.type === 'buy'
            ? formatMessage(messages.paymentMethod)
            : depositToTitle
        }
        paymentMethod={paymentMethod}
      />,
    );

    if (fee) {
      confirmationRows.push(subtotalCell);
      if (isInSingapore) {
        confirmationRows.push(transactionSingaporeFeeCell);
      } else if (hasSubscription || isSuccessfulSubscriptionSignup) {
        confirmationRows.push(transactionSubscriptionFeeCell);
      } else {
        confirmationRows.push(transactionFeeCell);

        if (
          showTradePromoCode &&
          applyTradePromoCode &&
          resetTradePromoCode &&
          (transfer.type === 'sell' || transfer.type === 'buy')
        ) {
          confirmationRows.push(
            <TradePromoCodeCell
              applyOnPress={applyTradePromoCode}
              applyTradePromoCodeData={applyTradePromoCodeData || null}
              resetTradePromoCode={resetTradePromoCode}
              tradePromoCodeAmountWaived={originalFee}
              userEnteredTradeFiatAmount={
                transfer.type === 'buy'
                  ? transfer?.data?.total
                  : transfer.data?.subtotal
              }
              key="TradePromoCodeCell"
            />,
          );
        }
      }
    }

    if (transfer.type === 'sell' || transfer.type === 'buy') {
      const taxDetails = transfer?.data?.taxDetails;
      const transactionTaxCell = (
        <Fragment key="transactionTaxCells">
          {taxDetails?.map((tax, index) => {
            if (!tax) {
              return null;
            }

            return (
              <TransactionTaxCell
                key={tax.name}
                index={index}
                isInfo
                onInfoPress={handleTaxInfoPress}
                title={taxTitleMessage[tax.name]}
                taxName={tax.name}
                tax={formatCurrency({
                  amount: tax.amount.value,
                  currency: { code: tax.amount.currency, type: 'fiat' },
                  isSensitive: false,
                })}
                testID="tax"
              />
            );
          })}
        </Fragment>
      );
      confirmationRows.push(transactionTaxCell);
    }

    const livePricesTray = useMemo(
      () => (
        <Tray
          onDismiss={() => setIsShowingLivePricesTray(false)}
          isVisible={isShowingLivePricesTray}
        >
          <TextTitle3 spacingBottom={1}>
            {formatMessage(messages.priceIsLiveTitle, {
              asset: displaySymbol,
            })}
          </TextTitle3>
          <TextBody spacingBottom={3}>
            {formatMessage(messages.priceIsLiveDescFiatUpdated, {
              link: TradingFeesLink,
            })}
          </TextBody>
          <Button
            variant="secondary"
            onPress={() => setIsShowingLivePricesTray(false)}
          >
            {formatMessage(messages.close)}
          </Button>
        </Tray>
      ),
      [displaySymbol, formatMessage, isShowingLivePricesTray],
    );

    const significantPriceChangeTray = useMemo(
      () => (
        <Tray
          onDismiss={() => setIsShowingPriceChangeTray(false)}
          isVisible={isShowingPriceChangeTray}
        >
          <TextTitle3 spacingBottom={1}>
            {formatMessage(messages.priceHasChangedTitle, {
              asset: displaySymbol,
            })}
          </TextTitle3>
          <TextBody spacingBottom={3}>
            {formatMessage(messages.priceHasChangedDesc, {
              asset: displaySymbol,
              displayInputCurrency: inputCurrency.code,
            })}
          </TextBody>
          <ButtonGroup
            block
            accessibilityLabel={formatMessage(messages.buttonGroup)}
          >
            <Button variant="secondary" onPress={() => pop()}>
              {formatMessage(messages.goBack)}
            </Button>
            <Button
              variant="primary"
              onPress={() => setIsShowingPriceChangeTray(false)}
            >
              {formatMessage(messages.placeOrder)}
            </Button>
          </ButtonGroup>
        </Tray>
      ),
      [
        displaySymbol,
        formatMessage,
        inputCurrency.code,
        isShowingPriceChangeTray,
        pop,
      ],
    );

    const subscriptionSignupFlowTrayIfVisible = useMemo(() => {
      return subscriptionSignupFlowTrayVisible ? (
        <SubscriptionSignupFlowTray
          onClose={toggleSubscriptionSignupFlowTrayOff}
          onSignupSuccess={() => {
            onSubscriptionSignupSuccess?.();
          }}
          variant="trade"
        />
      ) : null;
    }, [
      subscriptionSignupFlowTrayVisible,
      onSubscriptionSignupSuccess,
      toggleSubscriptionSignupFlowTrayOff,
    ]);

    const oneTimeBonusCell = useMemo(
      () => (
        <TransactionBonusCell
          key="bonus"
          title={formatMessage(messages.oneTimeBonus)}
          info="One Time Bonus"
          onInfoPress={handleOneTimeBonusInfoPress}
          amount={`${
            Number(display.totalValue) * 0.1 > 30
              ? 30
              : Number(display.totalValue) * 0.1
          }`}
          currency={display.totalValueCurrency ?? null}
          asset={displaySymbol || ''}
        />
      ),

      [
        display.totalValue,
        display.totalValueCurrency,
        displaySymbol,
        formatMessage,
        handleOneTimeBonusInfoPress,
      ],
    );

    if (
      Number(display.totalValue) >= 100 &&
      isFirstYieldEligible &&
      transfer.type === 'buy' &&
      (transferSource === 'firstYieldIncentive' ||
        transferSource === 'ycFirstYieldIncentive')
    ) {
      confirmationRows.push(oneTimeBonusCell);
    }

    confirmationRows.push(totalAmountCell);

    confirmationRows.push(subscriptionSignupSwitchCell);

    confirmationRows.push(transactionConvertTradeToRecurringCell);

    confirmationRows.push(bottomDetails);

    confirmationRows = confirmationRows.filter((row) => row);

    const rewardApy = useAccountRewardApy(
      accountGraphQL?.assetOrFiatCurrency || null,
    );

    const rewardsLabel = useMemo(() => {
      return rewardApy?.label
        ? formatMessage(messages.eligibleToEarn, {
            label: rewardApy?.label,
          })
        : '';
    }, [formatMessage, rewardApy?.label]);

    const stakingDetails = !!rewardsLabel && transfer.type === 'buy' && (
      <PillLabel variant="positive" alignSelf="center">
        {rewardsLabel}
      </PillLabel>
    );
    const [, endPreviewButtonNavigationPerfMark] = usePerfMark(
      'simple_trade',
      'load_order_preview',
    );

    const showOBRedirectionBanner = useMemo(() => {
      return (
        paymentMethod?.type === 'uk_bank_account' && transfer.type === 'buy'
      );
    }, [paymentMethod, transfer.type]);

    const showBuyAndStakeSwitch = useMemo(() => {
      return transfer.type === 'buy' && isBuyAndStakeEligible && !isRecurring;
    }, [transfer.type, isBuyAndStakeEligible, isRecurring]);

    useEffect(() => {
      endPreviewButtonNavigationPerfMark({
        logMetric: true,
        tags: {
          tradeType: transfer.type,
        },
      });
      if (transfer.type === 'buy') {
        markJourney('loaded_buy_order_preview_screen');
      } else if (transfer.type === 'sell') {
        markJourney('loaded_sell_order_preview_screen');
      }
    }, [transfer.type, endPreviewButtonNavigationPerfMark]);

    return (
      <VStack spacing={0} flexGrow={1}>
        <TransactionAmountHeader
          amount={formatCurrency({
            amount: display.amountValue,
            currency: display.currency,
            trimTrailingZeros: false,
            isSensitive: false,
            minimumFractionDigits: cashOperation === 'cash_in' ? 2 : undefined,
            maximumFractionDigits: cashOperation === 'cash_in' ? 2 : undefined,
          })}
          useLiveTicker={livePricesEnabled}
          variant="preview"
        >
          {stakingDetails}
        </TransactionAmountHeader>
        {confirmationRows}
        {showOBRedirectionBanner ? (
          <>
            <Spacer vertical={2} />
            <Box
              borderRadius="rounded"
              borderColor="line"
              bordered
              spacingVertical={2}
              spacingStart={2}
              spacingEnd={1}
            >
              <BuyRedirectBannerDeprecated paymentMethod={paymentMethod} />
            </Box>
          </>
        ) : null}

        {showBuyAndStakeSwitch && (
          <>
            <Spacer vertical={1} />
            <BuyAndStakeSwitch
              onChange={onShouldBuyAndStakeChange}
              checked={shouldBuyAndStake}
              viewerAssetRef={accountGraphQL?.assetOrFiatCurrency}
              transferSource={transferSource}
              handleUnstakingEstimatePress={handleUnstakingInfoPress}
            />
          </>
        )}

        <Spacer vertical={1} />
        {Boolean(
          allUserWarnings?.length &&
            transferSource !== 'fundedSend' &&
            !cashOperation,
        ) && (
          <UserWarningCell
            key="userWarnings"
            userWarnings={allUserWarnings}
            spacingTop={1}
          />
        )}
        <TooltipTray
          hideTray={toggleOff}
          isVisible={isToggled}
          content={tooltipTrayContent}
        />
        {livePricesEnabled && livePricesTray}
        {livePricesEnabled && significantPriceChangeTray}
        {subscriptionSignupFlowTrayIfVisible}
      </VStack>
    );
  },
);

import { useMemo } from 'react';
import { HeroSquare } from '@cbhq/cds-mobile/illustrations';
import { Box, Spacer, VStack } from '@cbhq/cds-mobile/layout';
import { TextBody, TextTitle2 } from '@cbhq/cds-mobile/typography';
import { useIntl } from '@cbhq/i18n';

import { Button } from '@components/interactables/Button';
import { IconButton } from '@components/interactables/IconButton';
import { Link } from '@components/typography/Link';

import { messages } from './messages';
import { SpinTheWheelContentState } from './useSpinTheWheelGameState';

const TERMS_LINK =
  'https://help.coinbase.com/en/coinbase/getting-started/getting-started-with-coinbase/new-customer-incentive';
type SpinTheWheelGameContentProps = {
  state: SpinTheWheelContentState;
  onCompletePress: () => void;
  onStartPress: () => void;
  onSkipPress: () => void;
  amount: string;
  isLoading: boolean;
  hasGamificationUsdIncentive: boolean;
};

export function useSpinTheWheelGameContent({
  state,
  onCompletePress,
  onStartPress,
  onSkipPress,
  amount,
  isLoading,
  hasGamificationUsdIncentive,
}: SpinTheWheelGameContentProps) {
  const { formatMessage } = useIntl();

  const title = useMemo(() => {
    switch (state) {
      case 'finishing':
        return (
          <VStack>
            <TextTitle2 align="center">
              {formatMessage(messages.spinTheWheelCompletedTitle)}
            </TextTitle2>
            <TextTitle2 align="center">
              {formatMessage(messages.spinTheWheelCompletedAmountAsset, {
                amount,
                asset: hasGamificationUsdIncentive ? 'USD' : 'BTC',
              })}
            </TextTitle2>
          </VStack>
        );
      case 'error':
        return (
          <TextTitle2 align="center">
            {formatMessage(messages.spinTheWheelErrorTitle)}
          </TextTitle2>
        );
      default:
        return (
          <Box width="80%" spacingBottom={1}>
            <TextTitle2 align="start" color="primaryForeground">
              {formatMessage(
                hasGamificationUsdIncentive
                  ? messages.spinTheWheelTitleUsd
                  : messages.spinTheWheelTitle,
              )}
            </TextTitle2>
          </Box>
        );
    }
  }, [amount, formatMessage, hasGamificationUsdIncentive, state]);

  const message = useMemo(() => {
    switch (state) {
      case 'finishing':
        return (
          <TextBody align="center" spacingBottom={3}>
            {formatMessage(messages.spinTheWheelCompletedMessage)}
          </TextBody>
        );
      case 'error':
        return (
          <TextBody align="center" spacingBottom={3}>
            {formatMessage(messages.spinTheWheelErrorMessage, {
              link: (
                <Link to={TERMS_LINK} variant="body">
                  {formatMessage(messages.learnMore)}
                </Link>
              ),
            })}
          </TextBody>
        );
      default:
        return (
          <TextBody align="start" spacingBottom={3} color="primaryForeground">
            {formatMessage(messages.spinTheWheelMessage)}
          </TextBody>
        );
    }
  }, [formatMessage, state]);

  const button = useMemo(() => {
    switch (state) {
      case 'finishing':
      case 'error':
        return (
          <Button variant="primary" onPress={onCompletePress}>
            {formatMessage(messages.spinTheWheelCompletedButtonTitle)}
          </Button>
        );
      case 'ready':
        return (
          <Box width={200} height={60}>
            <Button
              variant="secondary"
              onPress={onStartPress}
              disabled={state !== 'ready'}
              loading={isLoading}
            >
              {formatMessage(messages.spinTheWheelButtonTitle)}
            </Button>
          </Box>
        );
      default:
        return <Box height={60} />;
    }
  }, [formatMessage, isLoading, onCompletePress, onStartPress, state]);

  const heroImage = useMemo(() => {
    switch (state) {
      case 'finishing':
        return (
          <Box alignSelf="center" spacingTop={10}>
            <HeroSquare name="cryptoAndMore" dimension="200x200" />
          </Box>
        );
      case 'error':
        return (
          <Box alignSelf="center" spacingTop={10}>
            <HeroSquare name="docError" dimension="200x200" />
          </Box>
        );
      default:
        return null;
    }
  }, [state]);

  const skipButton = useMemo(() => {
    switch (state) {
      case 'initiating':
      case 'starting':
        return (
          <Button
            compact
            variant="primary"
            onPress={onSkipPress}
            spacingTop={1}
          >
            {formatMessage(messages.skipButtonTitle)}
          </Button>
        );
      default:
        return <Spacer vertical={5} />;
    }
  }, [formatMessage, onSkipPress, state]);

  const closeButton = useMemo(
    () =>
      state === 'ready' ? (
        <IconButton name="close" onPress={onCompletePress} variant="primary" />
      ) : null,
    [onCompletePress, state],
  );

  return {
    heroImage,
    title,
    message,
    button,
    skipButton,
    closeButton,
  };
}

import { memo, useCallback, useMemo } from 'react';
import { CellMedia, ListCell } from '@cbhq/cds-mobile/cells';
import { TextBody } from '@cbhq/cds-mobile/typography';
import { ComponentType } from '@cbhq/client-analytics';
import { markJourneyOnce } from '@cbhq/core-vitals-mobile';
import { graphql, useFragment } from '@cbhq/data-layer';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { getPriceScale } from '@utils/number/priceUtils';
import LiveTickerCellDetail from '@app/components/LiveTickerCellDetail/LiveTickerCellDetail';
import { AssetSelectorMode } from '@app/components/navigation/stacks/TradeParams';
import { SimpleTradeSourceTargetTrayCellWrapper } from '@app/components/SimpleTrade/BaseInput/components/SimpleTradeSourceTargetSelector/SimpleTradeSourceTargetTrayCellWrapper';
import { TransferSource } from '@app/components/Transfer/TransferSource';
import { useDappChainId } from '@app/contexts/Defi/DappChainIdProvider';
import { useNativeCurrencyFormatter } from '@app/hooks/formatters/useNativeCurrencyFormatter';
import { usePercentChange } from '@app/hooks/resource/usePercentChange';
import { AssetPriceSubscription } from '@app/screens/Asset/components/AssetPriceSubscription';
import { useDappWalletBlockingCallEffect } from '@app/screens/Defi/hooks/gating/useDappWalletBlockingCallEffect';
import { NATIVE_ASSET_ADDRESS_POLYGON } from '@app/screens/Dex/constants';
import { useHasMgx } from '@app/screens/Dex/MGX/hooks/useHasMgx';
import { useTrackL1SearchResultTapped } from '@app/screens/UniversalSearch/hooks/Analytics';
import { usePerfMark } from '@app/utils/performance/hooks/usePerfMark';

import { AssetSelectorCellItemFragment$key } from './__generated__/AssetSelectorCellItemFragment.graphql';

const messages = defineMessages({
  apyFormat: {
    id: `AssetSelectorCell.apyFormat`,
    defaultMessage: '{percent} {apy}',
    description: 'amount interest/yield on an asset',
  },
});

export type AssetSelectorOnSelectProps = {
  contractAddress: string | null;
  assetId: string;
  isAssetExperimental?: boolean;
  assetSymbolOrSlug?: string;
  assetName?: string;
  isDexOnlyAsset?: boolean | null;
  dexGatedBlockingCall?: ReturnType<typeof useDappWalletBlockingCallEffect>;
  isStableCoin?: boolean;
  entryPoint?: string;
};

type AssetSelectorCellProps = {
  tradeType: AssetSelectorMode;
  transferSource?: TransferSource;
  viewerAssetRef: AssetSelectorCellItemFragment$key;
  rewardApy?: { formattedRate: string | undefined; label: string | undefined };
  isDex?: boolean;
  onSelect: ({
    contractAddress,
    assetId,
    isAssetExperimental,
    assetName,
    dexGatedBlockingCall,
    isStableCoin,
  }: AssetSelectorOnSelectProps) => void;
  selected?: boolean;
  dexGatedBlockingCall?: ReturnType<typeof useDappWalletBlockingCallEffect>;
  index: number;
  searchQueryForMLTrackEvent?: string;
  nullStateRank: number;
  searchSessionId: string;
  hasLivePricesExperiment?: boolean;
};

export const AssetSelectorCell = memo(function AssetSelectorCell({
  tradeType,
  transferSource,
  viewerAssetRef,
  onSelect,
  rewardApy,
  selected = false,
  dexGatedBlockingCall,
  isDex,
  index,
  searchQueryForMLTrackEvent,
  nullStateRank,
  searchSessionId,
  hasLivePricesExperiment,
}: AssetSelectorCellProps) {
  const viewerAsset = useFragment(
    graphql`
      fragment AssetSelectorCellItemFragment on ViewerAsset {
        asset @required(action: THROW) {
          imageUrl
          uuid
          name
          platformName
          isStablecoin
          displaySymbol
          contractAddress
          experimental
          networks @include(if: $isDexAPI) {
            chainId
            contractAddress
          }
          latestPrice(quoteCurrency: $nativeCurrency) {
            price
            percentChanges {
              day
            }
          }
        }
        supportedContextsV2 @skip(if: $skipSupportedContextsV2) {
          isDex(chainId: $chainId)
          isTradable
        }
      }
    `,
    viewerAssetRef,
  );

  const { dexChainId } = useDappChainId();
  const isMgxEligible = useHasMgx();
  const [startPerfMark] = usePerfMark('simple_trade', 'load_numpad');
  const isDexOnlyAsset =
    Boolean(viewerAsset.supportedContextsV2?.isDex) &&
    !viewerAsset.supportedContextsV2?.isTradable;
  const showLivePrices =
    hasLivePricesExperiment && tradeType.toLowerCase() === 'buy';

  const trackAssetSelectorCellTapped = useTrackL1SearchResultTapped();
  const { formatMessage } = useIntl();

  const { asset } = viewerAsset;

  const handleOnPress = useCallback(() => {
    startPerfMark();
    markJourneyOnce('navigate_to_numpad_screen');
    trackAssetSelectorCellTapped({
      searchTerm: searchQueryForMLTrackEvent ?? '',
      asset: asset.name,
      assetRank: index + 1,
      sourcePage: transferSource ?? '',
      assetId: asset.uuid,
      componentType: ComponentType.unknown,
      componentName: tradeType,
      rowIndex: index,
      inSectionRank: index + 1,
      sectionIndex: 0,
      sectionType: 'searchResults',
      nullStateRank: nullStateRank + 1,
      searchSessionId,
      entityType: 'asset',
    });
    // If in DEX mode, then use asset's contract address corresponding to selected DEX network
    const selectedDexNetwork = asset.networks?.find(
      (network) => network?.chainId === dexChainId,
    );
    const assetContractAddress =
      selectedDexNetwork?.contractAddress !== undefined
        ? selectedDexNetwork?.contractAddress
        : '';
    // we need to pass null to targetAssetAddress if matic is chosen as targetAsset on polygon network
    // because 0x0000000000000000000000000000000000001010 would be passed as address and with the way BE is wired now it would error out
    const dexAssetContractAddress =
      assetContractAddress === NATIVE_ASSET_ADDRESS_POLYGON
        ? null
        : assetContractAddress;

    onSelect({
      contractAddress: isDex ? dexAssetContractAddress : asset.contractAddress,
      assetId: asset.uuid,
      isAssetExperimental: asset.experimental,
      assetSymbolOrSlug: asset.platformName ?? '',
      assetName: asset.name,
      isDexOnlyAsset: isMgxEligible ? !!isDexOnlyAsset : undefined,
      dexGatedBlockingCall,
      isStableCoin: Boolean(asset.isStablecoin),
    });
  }, [
    trackAssetSelectorCellTapped,
    searchQueryForMLTrackEvent,
    asset.name,
    asset.uuid,
    asset.networks,
    asset.contractAddress,
    asset.experimental,
    asset.platformName,
    asset.isStablecoin,
    index,
    transferSource,
    tradeType,
    nullStateRank,
    searchSessionId,
    onSelect,
    isDex,
    isMgxEligible,
    isDexOnlyAsset,
    dexGatedBlockingCall,
    startPerfMark,
    dexChainId,
  ]);

  const { percent, sign, variant } = usePercentChange(
    asset?.platformName,
    asset.latestPrice?.percentChanges?.day,
  );
  const subdetail = `${sign}${percent}`;
  const latestPriceFormatter = useNativeCurrencyFormatter({
    minimumFractionDigits: getPriceScale(asset?.latestPrice?.price),
  });
  const detail = useMemo(
    () =>
      latestPriceFormatter({
        amount: asset.latestPrice?.price,
        isSensitive: false,
      }),
    [asset?.latestPrice?.price, latestPriceFormatter],
  );

  const cellMedia = useMemo(
    () => (
      <CellMedia
        testID={`AssetIcon-${viewerAsset.asset.name}`}
        type="asset"
        source={asset.imageUrl}
        accessibilityLabel={asset.displaySymbol || asset.name || ''}
        cache="force-cache"
      />
    ),
    [asset.displaySymbol, asset.imageUrl, asset.name, viewerAsset.asset.name],
  );

  const description = useMemo(() => {
    return rewardApy ? (
      <>
        <TextBody color="foregroundMuted">{`${asset.displaySymbol} • `}</TextBody>
        <TextBody color="positive">
          {formatMessage(messages.apyFormat, {
            percent: rewardApy.formattedRate,
            apy: rewardApy.label,
          })}
        </TextBody>
      </>
    ) : (
      asset.displaySymbol
    );
  }, [asset.displaySymbol, rewardApy, formatMessage]);

  const action = useMemo(
    () =>
      showLivePrices ? (
        <>
          <LiveTickerCellDetail
            detail={detail}
            subdetail={subdetail}
            variant={variant}
            showLiveSubdetail
          />
          <AssetPriceSubscription assetUuid={asset.uuid} />
        </>
      ) : null,
    [asset.uuid, detail, showLivePrices, subdetail, variant],
  );

  const simpleTradeAssetListCell = useMemo(
    () => (
      <SimpleTradeSourceTargetTrayCellWrapper
        isSelected={selected}
        onPress={handleOnPress}
      >
        <ListCell
          testID={`AssetSelectorCell-${viewerAsset.asset.name}`}
          title={asset.name}
          subdetail={subdetail}
          variant={variant}
          description={description}
          detail={detail}
          media={cellMedia}
          action={action}
          innerSpacing={{ spacingHorizontal: 1 }}
        />
      </SimpleTradeSourceTargetTrayCellWrapper>
    ),
    [
      selected,
      handleOnPress,
      viewerAsset.asset.name,
      asset.name,
      subdetail,
      variant,
      description,
      detail,
      cellMedia,
      action,
    ],
  );
  return simpleTradeAssetListCell;
});

import { memo, useCallback, useEffect, useMemo, useRef, useState } from 'react';
// 2024-04-23 weslie-zhang: set accessibility requires a react tag returned from findNodeHandle
// eslint-disable-next-line @cbhq/react-native-no-fabric-incompatible-apis
import {
  AccessibilityInfo,
  findNodeHandle,
  ScrollView,
  useWindowDimensions,
  View,
} from 'react-native';
import { useToggler } from '@cbhq/cds-common';
import { MAX_OVER_DRAG } from '@cbhq/cds-common/animation/drawer';
import { useInteractableHeight } from '@cbhq/cds-common/hooks/useInteractableHeight';
import { verticalDrawerPercentageOfView } from '@cbhq/cds-common/tokens/drawer';
import { ListCell } from '@cbhq/cds-mobile/cells';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { Tray } from '@cbhq/cds-mobile/overlays/Tray/Tray';
