import { TextLabel1 } from '@cbhq/cds-mobile/typography';
import { ComponentType } from '@cbhq/client-analytics';
import { useIntl } from '@cbhq/i18n';

import { useMultipleWatchlistsTreatment } from '@app/hooks/useMultipleWatchlistsTreatment';
import {
  logWatchlistTabEvent,
  TabOptionType,
} from '@app/hooks/useWatchlistTabs/useWatchlistTabs';
import { MultiFilterPill } from '@app/screens/ExploreTab/components/MultiFilterPill';
import CreateWatchlistButton from '@app/screens/Home/components/WatchList/CreateWatchlist/CreateWatchlistButton';
import {
  UIComponentAnalyticsProps,
  useWatchlistUIComponentEventTracker,
} from '@app/screens/HomeTab/analytics';
import { messages } from '@app/screens/HomeTab/messages';

type WatchlistTabsProps = {
  onChange: (key: string) => void;
  tabOptions: TabOptionType[];
  value: TabOptionType;
  horizontal?: boolean;
  uicomponent?: UIComponentAnalyticsProps;
};

const WatchlistTabs = memo(
  ({
    horizontal,
    tabOptions,
    onChange,
    value,
    uicomponent,
  }: WatchlistTabsProps) => {
    const { formatMessage } = useIntl();
    const { trackWatchlistClickEvent } = useWatchlistUIComponentEventTracker();
    const hasMultipleWatchlists = useMultipleWatchlistsTreatment();
    const { height } = useWindowDimensions();
    const buttonHeight = useInteractableHeight();
    const listTrayMaxHeight = useMemo(
      () =>
        height * verticalDrawerPercentageOfView - MAX_OVER_DRAG - buttonHeight,
      [buttonHeight, height],
    );

    const [activeList, setActiveList] = useState(value);
    const [showTabsTray, { toggleOff: toggleTrayOff, toggleOn: toggleTrayOn }] =
      useToggler(false);

    useEffect(() => {
      if (value.key !== activeList.key) {
        setActiveList(value);
      }
    }, [activeList.key, value]);

    const handleToggleTrayOn = useCallback(() => {
      logWatchlistTabEvent({
        context: 'dropdown_open',
        componentType: ComponentType.dropdown,
      });

      if (uicomponent) {
        trackWatchlistClickEvent({
          triggerPointEventName: 'watchlist_tab_event',
          componentName: 'dropdown_open',
          componentType: ComponentType.button,
          uicomponent,
          activeTab: activeList.key,
        });
      }
      toggleTrayOn();
    }, [activeList.key, toggleTrayOn, trackWatchlistClickEvent, uicomponent]);

    const buttonRef = useRef<View>(null);
    const handleToggleTrayOff = useCallback(() => {
      toggleTrayOff();
      const reactTag = findNodeHandle(buttonRef.current as React.Component);
      if (reactTag) {
        AccessibilityInfo.setAccessibilityFocus(reactTag);
      }
    }, [toggleTrayOff]);

    if (horizontal) {
      return (
        <HStack justifyContent="space-evenly" spacingBottom={2}>
          {tabOptions.map((option) => (
            <TabOptionButton
              key={option.key}
              isActive={activeList.key === option.key}
              option={option}
              setActiveList={setActiveList}
              onChange={onChange}
            />
          ))}
        </HStack>
      );
    }

    return (
      <>
        <Box ref={buttonRef}>
          <MultiFilterPill
            label={activeList.title ?? tabOptions[0].title}
            isActive={false}
            onPress={handleToggleTrayOn}
            isTrayShowing={showTabsTray}
            testID="watchlist-tray-button"
            accessibilityLabel={formatMessage(messages.viewList, {
              listName: activeList.title,
            })}
          />
        </Box>
        {!!showTabsTray && (
          <Tray
            title={formatMessage(messages.trayTitle)}
            onCloseComplete={handleToggleTrayOff}
            disableCapturePanGestureToDismiss
          >
            {({ handleClose }) => {
              return (
                <Box spacingHorizontal={1} maxHeight={listTrayMaxHeight}>
                  <ScrollView>
                    {tabOptions.map((option) => (
                      <ListOption
                        key={`Tray-${option.key}`}
                        option={option}
                        onChange={onChange}
                        handleClose={handleClose}
                        setActiveList={setActiveList}
                        isSelected={option.key === activeList.key}
                      />
                    ))}
                  </ScrollView>
                  {hasMultipleWatchlists && (
                    <CreateWatchlistButton onPress={toggleTrayOff} />
                  )}
                </Box>
              );
            }}
          </Tray>
        )}
      </>
    );
  },
);

type TabOptionButtonProps = {
  option: TabOptionType;
  isActive: boolean;
  setActiveList: (option: TabOptionType) => void;
  onChange: (key: string) => void;
};

function TabOptionButton({
  option,
  isActive,
  setActiveList,
  onChange,
}: TabOptionButtonProps) {
  const handlePress = useCallback(() => {
    setActiveList(option);
    onChange(option.key);
  }, [setActiveList, option, onChange]);

  return (
    <Pressable
      accessibilityRole="button"
      key={option.key}
      onPress={handlePress}
      background={isActive ? 'secondary' : 'transparent'}
      borderRadius="roundedLarge"
    >
      <Box
        spacingVertical={1}
        spacingHorizontal={2}
        bordered={false}
        borderRadius="roundedLarge"
      >
        <TextLabel1>{option.title}</TextLabel1>
      </Box>
    </Pressable>
  );
}

type ListOptionProps = {
  option: TabOptionType;
  onChange: (key: string) => void;
  isSelected: boolean;
  setActiveList: (option: TabOptionType) => void;
  handleClose: () => void;
};

function ListOption({
  option,
  onChange,
  isSelected,
  setActiveList,
  handleClose,
}: ListOptionProps) {
  const handlePress = useCallback(() => {
    logWatchlistTabEvent({ context: option.key });
    handleClose();
    setActiveList(option);
    onChange(option.key);
  }, [handleClose, onChange, option, setActiveList]);

  const selectedLabel = useMemo(() => {
    return `${option.title} list view. ${isSelected ? 'Selected' : 'Not selected'}`;
  }, [isSelected, option.title]);

  return (
    <ListCell
      testID={`Tray-${option.key}`}
      title={option.title}
      description={option.description ?? ''}
      accessibilityLabel={selectedLabel}
      accessibilityHint={option.description}
      selected={isSelected}
      onPress={handlePress}
    />
  );
}

export default WatchlistTabs;

