type HeaderImageType = {
  imageUrl?: string | null;
};

const HeaderImage = memo<HeaderImageType>(function HeaderImage({ imageUrl }) {
  const parsedImageUrl = useMemo(() => {
    return imageUrlParser(imageUrl, {
      fm: 'webp',
      height: 64,
      width: 64,
      resizeStrategy: 'fill',
    });
  }, [imageUrl]);

  const [isLoading, setIsLoading] = useState(true);
  const [isErrored, setIsErrored] = useState(false);

  const handleLoadStart = useCallback(() => {
    setIsLoading(true);
    setIsErrored(false);
  }, []);

  const handleLoadEnd = useCallback(() => {
    setIsLoading(false);
  }, []);

  const handleError = useCallback(() => {
    setIsLoading(false);
    setIsErrored(true);
  }, []);

  if (!parsedImageUrl) return null;

  return (
    <Box
      alignItems="center"
      alignSelf="center"
      width={isErrored ? 0 : undefined}
    >
      <RemoteImage
        source={parsedImageUrl}
        onLoadStart={handleLoadStart}
        onLoadEnd={handleLoadEnd}
        onError={handleError}
        size="l"
        shape="circle"
      />
      {isLoading && (
        <Fallback
          justifyContent="center"
          alignItems="center"
          alignSelf="center"
          position="absolute"
          shape="circle"
          height={32}
          width={32}
        />
      )}
    </Box>
  );
});

type DynamicFeedCardHeaderProps = {
  header:
    | DynamicFeedCardFragment$data['header']
    | SocialPollCardFragment$data['header'];
  onShowMorePress: () => void;
  uiComponentId?: string;
};

// ts-prune-ignore-next
export const DynamicFeedCardHeader = memo(
  ({ onShowMorePress, header }: DynamicFeedCardHeaderProps) => {
    const spectrum = useSpectrum();

    const [isActionIconChecked, { toggle: toggleActionIcon }] = useToggler(
      header?.actionIcon?.isSelected ?? false,
    );

    const currActionIcon = useMemo(() => {
      return (
        isActionIconChecked
          ? header?.actionIcon?.active?.icon
          : header?.actionIcon?.inactive?.icon
      ) as UiIconName;
    }, [
      header?.actionIcon?.active?.icon,
      header?.actionIcon?.inactive?.icon,
      isActionIconChecked,
    ]);

    const handleActionButtonPress = useCallback(() => {
      toggleActionIcon();
    }, [toggleActionIcon]);

    const promoTag = useMemo(() => {
      if (!header?.tag?.text) {
        return undefined;
      }

      return (
        <Box
          dangerouslySetBackground={parseContentPlatformColor({
            color: header?.tag?.backgroundColor,
            fallbackColor: 'blue60',
            spectrum,
          })}
          borderRadius="roundedFull"
          spacingHorizontal={1}
        >
          <TextLabel1
            dangerouslySetColor={parseContentPlatformColor({
              color: header?.tag?.color,
              fallbackColor: 'gray0',
              spectrum,
            })}
          >
            {header.tag.text.toUpperCase()}
          </TextLabel1>
        </Box>
      );
    }, [
      header?.tag?.backgroundColor,
      header?.tag?.color,
      header?.tag?.text,
      spectrum,
    ]);

    const { formatDate, formatMessage } = useIntl();

    const timeStamp = useMemo(() => {
      const time = new Date(header?.timeStamp?.text ?? '');
      const isValidDate = !Number.isNaN(time.getTime());

      if (!isValidDate) return undefined;

      const date = formatDate(time, {
        month: 'short',
        day: 'numeric',
      });

      const justNow = formatMessage(messages.justNow);

      return formatTimeStamp(time.toISOString(), date, justNow);
    }, [formatDate, formatMessage, header?.timeStamp?.text]);

    const subtitleText = useMemo(() => {
      const subtitle = header?.subtitle?.text;

      if (subtitle && timeStamp) {
        return subtitle.concat('・', timeStamp);
      }

      return subtitle ?? timeStamp;
    }, [header?.subtitle?.text, timeStamp]);

    return (
      <HStack
        alignItems="center"
        spacingStart={3}
        spacingVertical={2}
        style={{
          paddingRight: 12,
        }}
      >
        <HeaderImage imageUrl={header?.image?.url} />
        <VStack spacingHorizontal={2}>
          <TextLabel1
            color="foreground"
            dangerouslySetColor={parseContentPlatformColor({
              color: header?.title?.color,
              fallbackColor: 'gray100',
              spectrum,
            })}
          >
            {header?.title?.text}
          </TextLabel1>
          <TextLegal
            color="foregroundMuted"
            dangerouslySetColor={parseContentPlatformColor({
              color: header?.subtitle?.color,
              fallbackColor: 'gray60',
              spectrum,
            })}
            style={{
              fontSize: 12,
            }}
          >
            {subtitleText}
          </TextLegal>
        </VStack>
        <Spacer />
        {currActionIcon ? (
          <Box spacingEnd={0}>
            <IconButton
              compact
              transparent
              feedback="normal"
              onPress={handleActionButtonPress}
              name={currActionIcon}
            />
          </Box>
        ) : null}

        {promoTag}
        <ShowMoreButton
          title={header?.title?.text}
          onShowMorePress={onShowMorePress}
        />
      </HStack>
    );
  },
);

import { memo, useCallback, useEffect, useMemo, useRef } from 'react';
import { Animated } from 'react-native';
import { useSparklineArea } from '@cbhq/cds-common/visualizations/useSparklineArea';
