import { useHomepageAnalytics } from '../../analytics';

import { HomePortfolioChartButtonFragment$key } from './__generated__/HomePortfolioChartButtonFragment.graphql';

const i18nKey = 'HomePortfolioChartButton';
const messages = defineMessages({
  expandChart: {
    id: `${i18nKey}.expandChart`,
    defaultMessage: 'Expand portfolio chart',
    description: 'Accessibility label for mini portfolio chart button.',
  },
  collapseChart: {
    id: `${i18nKey}.collapseChart`,
    defaultMessage: 'Collapse portfolio chart',
    description:
      'Accessibility label for button to collapse the expanded portfolio chart.',
  },
});

const minimizedChartSize = { width: 75, height: 30 };

type HomePortfolioChartMinimizedProps = {
  activePeriod: ChartPeriod;
  queryRef: HomePortfolioChartButtonFragment$key;
};

const HomePortfolioChartMinimizedContent =
  memo<HomePortfolioChartMinimizedProps>(
    function HomePortfolioChartButtonProps({ activePeriod, queryRef }) {
      const palette = usePalette();

      const { viewer } = useFragment(
        graphql`
          fragment HomePortfolioChartButtonFragment on Query
          @argumentDefinitions(nativeCurrency: { type: "TickerSymbol!" }) {
            viewer @skip(if: $hideRAV4Sparkline) {
              userBalanceChart(currency: $nativeCurrency) {
                balanceChart {
                  ...usePortfolioChartDataFragment
                }
              }
            }
          }
        `,
        queryRef,
      );

      const data = usePortfolioChartData(
        viewer?.userBalanceChart?.balanceChart ?? null,
      );

      const dataForPeriod = useMemo(() => {
        return (data[activePeriod] ?? []).map((dataPoint) => dataPoint.value);
      }, [data, activePeriod]);

      const sparklinePath = useSparklinePath({
        data: dataForPeriod,
        ...minimizedChartSize,
      });

      const sparklineArea = useSparklineArea({
        data: dataForPeriod,
        ...minimizedChartSize,
      });

      return (
        <Sparkline
          testID="HomeChartHeaderSparkline"
          path={sparklinePath}
          color={palette.primary}
          {...minimizedChartSize}
        >
          <SparklineArea area={sparklineArea} />
        </Sparkline>
      );
    },
  );

const HomePortfolioChartMinimized = memo<HomePortfolioChartMinimizedProps>(
  function HomePortfolioChartMinimized({ ...props }) {
    return (
      <PersistedCacheGuardrailSuspenseBoundary
        instrumentationSuspenseId="HomePortfolioChartMinimized"
        fallback={null}
      >
        <HomePortfolioChartMinimizedContent {...props} />
      </PersistedCacheGuardrailSuspenseBoundary>
    );
  },
);

type HomePortfolioChartButtonProps = {
  minimized: boolean;
  setMinimized: (minimized: boolean) => void;
  chartButtonDisabled?: boolean;
} & HomePortfolioChartMinimizedProps;

export const HomePortfolioChartButton = memo<HomePortfolioChartButtonProps>(
  function HomePortfolioChartButton({
    minimized,
    setMinimized,
    chartButtonDisabled,
    ...props
  }) {
    const { formatMessage } = useIntl();
    const trackHomepageAnalytics = useHomepageAnalytics();
    const collapseButtonOpacity = useRef(new Animated.Value(1)).current;
    const miniChartOpacity = useRef(new Animated.Value(1)).current;

    const animateExpandChart = useCallback(() => {
      Animated.timing(
        miniChartOpacity,
        convertMotionConfig({
          fromValue: 1,
          toValue: 0,
          duration: 'quick',
          easing: 'linear',
        }),
      ).start(() => {
        setMinimized(false);
      });
      Animated.timing(
        collapseButtonOpacity,
        convertMotionConfig({
          fromValue: 0,
          toValue: 1,
          delay: 33,
          duration: 'quick',
          easing: 'linear',
        }),
      ).start();
    }, [collapseButtonOpacity, miniChartOpacity, setMinimized]);

    const handleExpandChart = useCallback(() => {
      animateExpandChart();

      trackHomepageAnalytics(
        ActionType.click,
        ComponentType.button,
        'home_chart',
        'expand',
      );
    }, [animateExpandChart, trackHomepageAnalytics]);

    const animateCollapseChart = useCallback(() => {
      Animated.timing(
        collapseButtonOpacity,
        convertMotionConfig({
          fromValue: 1,
          toValue: 0,
          duration: 'quick',
          easing: 'linear',
        }),
      ).start(() => {
        setMinimized(true);
      });
      Animated.timing(
        miniChartOpacity,
        convertMotionConfig({
          fromValue: 0,
          toValue: 1,
          delay: 33,
          duration: 'quick',
          easing: 'linear',
        }),
      ).start();
    }, [collapseButtonOpacity, miniChartOpacity, setMinimized]);

    const handleCollapseChart = useCallback(() => {
      animateCollapseChart();
      trackHomepageAnalytics(
        ActionType.click,
        ComponentType.button,
        'home_chart',
        'collapse',
      );
    }, [animateCollapseChart, trackHomepageAnalytics]);

    const accessibilityState = useMemo(
      () => ({
        disabled: chartButtonDisabled,
      }),
      [chartButtonDisabled],
    );

    useEffect(() => {
      if (minimized && chartButtonDisabled) {
        animateCollapseChart(); // to avoid analytics event on error craft
      }
    }, [animateCollapseChart, chartButtonDisabled, minimized]);

    return (
      <Box>
        {minimized ? (
          <Box
            animated
            opacity={miniChartOpacity}
            testID="HomePortfolioChartMinimized"
          >
            <PressableOpacity
              accessibilityRole="button"
              onPress={handleExpandChart}
              accessibilityState={accessibilityState}
              accessibilityLabel={formatMessage(messages.expandChart)}
              disabled={chartButtonDisabled}
            >
              <HomePortfolioChartMinimized {...props} />
            </PressableOpacity>
          </Box>
        ) : (
          <Box
            animated
            opacity={collapseButtonOpacity}
            testID="ChartCollapseButton"
          >
            <IconButton
              name="caretUp"
              variant="secondary"
              onPress={handleCollapseChart}
              accessibilityState={accessibilityState}
              accessibilityLabel={formatMessage(messages.collapseChart)}
              disabled={chartButtonDisabled}
            />
          </Box>
        )}
      </Box>
    );
  },
);

