  description?: string;
  url?: string;
  surface?: string;
  uicomponent?: UIComponentAnalyticsProps;
} & Omit<IconButtonProps, 'name'>;

export function TopOfFeedButton({
  title,
  iconName,
  onPress,
  name,
  buttonPlacement,
  order,
  url,
  description,
  surface,
  uicomponent,
  ...props
}: TopOfFeedButtonProps) {
  const quickActionEvent = useMemo(
    () => ({
      surface,
      componentPlacement: buttonPlacement,
      order,
      // Action Response
      componentName: name,
      title,
      description,
      url,
      iconName,
    }),
    [surface, buttonPlacement, order, name, title, description, url, iconName],
  );

  const viewEventData = useTopOfFeedViewEventData({
    uicomponent,
    ...quickActionEvent,
  });

  const buttonEventAnalyticsConfig = useMemo(
    () =>
      createEventConfig(TopOfFeedEventName, [ActionType.click], {
        ...uicomponent,
        ...quickActionEvent,
        component_placement: quickActionEvent.componentPlacement,
        legacy_component_name: quickActionEvent.componentName,
        icon_name: quickActionEvent.iconName,
      }),
    [quickActionEvent, uicomponent],
  );

  // This is to capture deposit rendering on the home screen to create data table in amplitude
  useEffect(() => {
    if (name === 'cash_in') {
      logEvent('add_cash_btn_rendered_on_home_page', {
        action: ActionType.render,
        componentType: ComponentType.button,
      });
    }
  }, [name]);

  return (
    <VisibilityTracker eventName={TopOfFeedEventName} eventData={viewEventData}>
      <VStack alignItems="center" testID={`top_of_feed_${title}`}>
        <HStack spacingBottom={1}>
          <IconButton
            name={iconName}
            variant="primary"
            onPress={onPress}
            eventConfig={buttonEventAnalyticsConfig}
            accessibilityLabel={title}
            {...props}
          />
        </HStack>
        <TextLegal align="center" accessible={false}>
          {title}
        </TextLegal>
      </VStack>
    </VisibilityTracker>
  );
}

