type DenseFeedCardFooterProps = {
  feedCardRef: DenseHomeFeedCardFooterFragment$key;
  ctaButtonText: string;
  onCTAPress: () => void;
  onSharePress: () => void;
  onLikeButtonPress: (isLikeClicked: boolean) => void;
  showLikeButton?: boolean;
};

export const DenseHomeFeedCardFooter = memo(
  ({
    feedCardRef,
    ctaButtonText,
    onCTAPress,
    onSharePress,
    onLikeButtonPress,
    showLikeButton = true,
  }: DenseFeedCardFooterProps) => {
    const feedCardFooterRef = useFragment(
      graphql`
        fragment DenseHomeFeedCardFooterFragment on FeedCard {
          relevantAssetsData {
            assetStats {
              dayPricePercentChange
            }
            symbol
          }
          ...LikeButtonFragment
        }
      `,
      feedCardRef,
    );

    const { formatMessage } = useIntl();
    const assetData = feedCardFooterRef?.relevantAssetsData?.[0];
    const formatPercentChange = usePercentChangeFormatter();
    const formattedPercentChange = formatPercentChange({
      value: assetData?.assetStats?.dayPricePercentChange,
    });

    const likeButton = useMemo(
      () => (
        <HStack alignSelf="center">
          <LikeButton
            onPress={onLikeButtonPress}
            denseFeed
            feedCardRef={feedCardFooterRef}
          />
        </HStack>
      ),
      [feedCardFooterRef, onLikeButtonPress],
    );

    const shareButton = useMemo(
      () => (
        <HStack alignSelf="center" spacingStart={showLikeButton ? 2 : 0}>
          <PressableOpacity
            testID="share_button"
            onPress={onSharePress}
            accessibilityLabel={formatMessage(messages.share)}
          >
            <Icon color="foreground" name="share" size="s" />
          </PressableOpacity>
        </HStack>
      ),
      [formatMessage, onSharePress, showLikeButton],
    );

    const showDynamicCTA = !!(
      formattedPercentChange.percent !== '' && assetData?.symbol
    );

    const ctaButton = useMemo(
      () =>
        !!ctaButtonText && (
          <Box maxWidth={200} spacingStart={1} alignSelf="center">
            {showDynamicCTA ? (
              <DenseCtaButton onPress={onCTAPress} testID="dynamic_cta_button">
                <TextCaption>{assetData?.symbol}</TextCaption>
                <TextCaption color={formattedPercentChange.variant}>
                  {`${formattedPercentChange.sign}${formattedPercentChange.percent}`}
                </TextCaption>
              </DenseCtaButton>
            ) : (
              <DenseCtaButton
                onPress={onCTAPress}
                testID="dense_non_dynamic_cta_button"
              >
                <TextCaption numberOfLines={1}>{ctaButtonText}</TextCaption>
              </DenseCtaButton>
            )}
          </Box>
        ),

      [
        onCTAPress,
        ctaButtonText,
        showDynamicCTA,
        assetData?.symbol,
        formattedPercentChange.sign,
        formattedPercentChange.variant,
        formattedPercentChange.percent,
      ],
    );

    // to prevent layout shifts and consistent card height
    // between the cta and non-cta cards,
    // adding in minHeight as 68
    return (
      <HStack
        testID="denseFeedCardFooter"
        minHeight={68}
        alignItems="center"
        spacingVertical={2}
      >
        {!!showLikeButton && likeButton}
        {!!showLikeButton && shareButton}
        <Spacer />
        {ctaButton}
      </HStack>
    );
  },
);

