function TradingInsightChartContentFallback() {
  return <Fallback width="100%" height={180} shape="squircle" />;
}

type TradingInsightChartProps = {
  feedCardRef: TradingInsightChartFragment$key;
  onError?: (error: Error) => void;
};

type TradingInsightChartContentProps = Omit<
  TradingInsightChartProps,
  'onError'
>;

const TradingInsightChartContent = memo<TradingInsightChartContentProps>(
  ({ feedCardRef }) => {
    const data = useFragment<TradingInsightChartFragment$key>(
      graphql`
        fragment TradingInsightChartFragment on FeedCard {
          imageUrl @required(action: LOG)
          relevantAssetsData {
            color @required(action: LOG)
            symbol @required(action: LOG)
            name @required(action: LOG)
            assetStats {
              priceHistory {
                pricePoint {
                  openPrice @required(action: LOG)
                }
              }
            }
          }
        }
      `,
      feedCardRef,
    );

    const imageUrl = data?.imageUrl;
    const relevantAssetsData = data?.relevantAssetsData;

    const asset = relevantAssetsData?.[0];
    const pricePoints = asset?.assetStats?.priceHistory?.pricePoint ?? [];
    const prices = pricePoints.map((pricePoint) => pricePoint?.openPrice ?? '');

    const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

    const path = useSparklinePath({
      ...dimensions,
      data: prices,
    });
    const area = useSparklineArea({
      ...dimensions,
      data: prices,
    });

    const onLayout = useCallback((event: LayoutChangeEvent) => {
      const { width, height } = event.nativeEvent.layout;
      setDimensions({ width, height });
    }, []);

    const assetColor = asset?.color ?? '';

    const defaultBackgroundColor = usePaletteValueToRgbaString('gray5');
    const backgroundColor = assetColor
      ? hexToRGBA(assetColor, 0.06)
      : defaultBackgroundColor;

    const assetIcon = useMemo(
      () => (
        <Box style={styles.floatingAssetIcon}>
          <CellMedia
            testID={`AssetIcon-${asset?.name}`}
            type="asset"
            source={imageUrl ?? ''}
            accessibilityLabel={asset?.symbol || asset?.name || ''}
            cache="force-cache"
          />
        </Box>
      ),
      [asset?.name, asset?.symbol, imageUrl],
    );

    return (
      <VStack
        testID="TradingInsightChart"
        width="100%"
        onLayout={onLayout}
        aspectRatio={326 / 180}
        alignItems="center"
        justifyContent="center"
        borderRadius="roundedLarge"
        overflow="hidden"
        style={{
          backgroundColor,
        }}
      >
        <Sparkline {...dimensions} path={path} color={assetColor}>
          <SparklineArea area={area} />
        </Sparkline>
        {assetIcon}
      </VStack>
    );
  },
);

const styles = StyleSheet.create({
  floatingAssetIcon: {
    position: 'absolute',
    top: 16,
    left: 16,
    zIndex: 2,
  },
});

export const TradingInsightChart = memo<TradingInsightChartProps>(
  ({ onError, ...props }) => (
    <NetworkBoundary
      onCatch={onError}
      // eslint-disable-next-line react/jsx-no-useless-fragment, react/no-unstable-nested-components
      errorFallback={() => <></>}
      suspenseFallback={<TradingInsightChartContentFallback />}
      monitoringBoundary={HomeFeedCardBoundary}
      willErrorBlockUser={false}
    >
      <TradingInsightChartContent {...props} />
    </NetworkBoundary>
  ),
);

function hexToRGBA(hex: string, alpha = 1) {
  const parsedRGB = hex.match(/\w\w/g)?.map((x) => parseInt(x, 16));
  if (!parsedRGB || parsedRGB.length !== 3) {
    throw new Error('Unexpected HEX value provided');
  }
  const [r, g, b] = parsedRGB;
  return `rgba(${r},${g},${b},${alpha})`;
}

