const IPHONE_SE_2ND_GEN_HEIGHT = 667;

export const MultichainNuxModal = memo(
  ({ onDismiss, mode, entryPoint, flow }: MultichainNuxModalProps) => {
    const { formatMessage } = useIntl();
    const { logGenericSendReceiveFlowEvent } = useSendReceiveLoggers();
    const { screenWidth } = useDimensions();
    const { navigateToReceive } = useReceiveAssetSelectorNavigation();

    useFocusEffectAfterInteractions(() => {
      logGenericSendReceiveFlowEvent(
        flow ? `${flow}_modal` : 'l2_landing_modal',
        {
          componentType: ComponentType.modal,
          flow: flow ? `${flow}_network_selection` : 'l2_multichain',
          action: ActionType.render,
          entryPoint: mode,
          step: 'onboarding',
        },
      );
    });

    const trackButtonClick = useCallback(
      (componentName: ComponentNames) =>
        logGenericSendReceiveFlowEvent(
          flow ? `${flow}_modal_button` : 'l2_landing_modal_button',
          {
            componentType: ComponentType.button,
            action: ActionType.click,
            entryPoint: mode,
            flow: flow ? `${flow}_network_selection` : 'l2_multichain',
            componentName,
            step: 'onboarding',
          },
        ),
      [flow, logGenericSendReceiveFlowEvent, mode],
    );

    const navigateToSendFlow = useNavigateToSendFlow(null);
    const handleOnPressSend = useCallback(() => {
      trackButtonClick('send');
      markJourney('navigate_to_send_account_selector');
      navigateToSendFlow(undefined, entryPoint);
    }, [entryPoint, navigateToSendFlow, trackButtonClick]);

    const handleOnPressReceive = useCallback(() => {
      trackButtonClick('receive');
      navigateToReceive({
        canChangeAccount: true,
        entryPoint,
        headerAction: 'back',
      });
    }, [entryPoint, navigateToReceive, trackButtonClick]);

    const handleOnPressGotIt = useCallback(() => {
      trackButtonClick('got_it');
      onDismiss(false);
    }, [onDismiss, trackButtonClick]);

    const handleLearnMoreTracking = useCallback(
      () => trackButtonClick('learn_more'),
      [trackButtonClick],
    );

    const handleOnClose = useCallback(() => {
      trackButtonClick('close');
      onDismiss(true);
    }, [onDismiss, trackButtonClick]);

    return mode === 'nux' ? (
      <Box justifyContent="space-between" flexGrow={1}>
        <Box offsetHorizontal={3} justifyContent="center">
          <MultichainNuxModalContent
            handleLearnMoreTracking={handleLearnMoreTracking}
            mode={mode}
          />
        </Box>
        <Box
          position="absolute"
          bottom="1%"
          width={screenWidth}
          alignSelf="center"
          background="background"
          spacingHorizontal={2}
          offsetBottom={1}
        >
          <ButtonGroup block accessibilityLabel="Group">
            <Button
              variant="secondary"
              onPress={handleOnPressReceive}
              testID="receiveButton"
            >
              {formatMessage(messages.receive)}
            </Button>
            <Button
              variant="primary"
              onPress={handleOnPressSend}
              testID="sendButton"
            >
              {formatMessage(messages.send)}
            </Button>
          </ButtonGroup>
        </Box>
      </Box>
    ) : (
      <Modal
        onRequestClose={handleOnClose}
        visible
        hideDividers
        testID="closeButton"
        hideCloseButton={false}
      >
        <ModalHeader />
        <ModalBody>
          <MultichainNuxModalContent
            handleLearnMoreTracking={handleLearnMoreTracking}
            mode={mode}
          />
        </ModalBody>
        <ModalFooter
          primaryAction={
            <Button
              variant="primary"
              onPress={handleOnPressGotIt}
              block
              testID="gotItButton"
            >
              {formatMessage(messages.gotIt)}
            </Button>
          }
        />
      </Modal>
    );
  },
);
