export const LoyaltyMixedCampaignDetailScreenContent = memo(
  function LoyaltyMixedCampaignDetailScreenContent({
    viewer,
  }: LoyaltyMixedCampaignDetailScreenContentProps) {
    const { assetSlug, cardName, entryPoint } =
      useParams<'LoyaltyMixedCampaignDetail'>();

    // WALL-30523 TODO: fetch card from single campaign endpoint when available
    const edge = viewer?.loyaltyCards?.edges.find(
      ({ node }) => node?.cardName === cardName,
    );
    const earnCard = edge?.node;

    if (!earnCard) {
      const error = new Error(
        `LoyaltyMixedCampaignDetailScreen: loyaltyCard for ${cardName} not found, user ineligible`,
      );
      errorVitals.logError(error, {
        context: 'loyalty_mixed_campaign_detail_screen',
        severity: 'warning',
        isHandled: true,
      });
      // show IneligibleCampaignError
      throw error;
    }

    const {
      duration: defaultDuration,
      imageUrl: defaultImageUrl,
      iconUrl: defaultIconUrl,
      title,
      header: defaultHeader,
      tasks = [],
      body,
      extendedBody,
      reward,
    } = earnCard;
    const noReward = reward === 'None';

    const { iconUrl, imageUrl, header, duration } = useLegacyLoyaltyCardDetails(
      {
        iconUrl: defaultIconUrl || '',
        imageUrl: defaultImageUrl,
        fallbackImageUrl: tasks?.[0]?.imageUrl ?? '',
        header: defaultHeader || '',
        title,
        duration: defaultDuration || '',
      },
    );

    const { formatMessage } = useIntl();
    const { goBack, canGoBack, replace } = useStackNavigation();
    const earnModal = useModal('EarnModalStack');
    const { navigateWithUrl } = useEarnCardNavigation({
      entryPoint: entryPoint ?? entryPointFallback,
      earnCardRef: null,
    });
    const spacing = useSpacingScale();
    const { top: paddingTop, bottom: paddingBottom } = useDimensions();

    // TODO: we will eventually want to pass in a real `assetSlug` so we can retrieve
    // the exact `assetName` and `assetColor` rather than an approximation
    // https://jira.coinbase-corp.com/browse/EARN-3539
    const assetName = assetSlug.split('-').join(' ');
    const assetColor = '#ffffff';

    const isCompleteCampaign = useMemo(() => {
      return tasks?.every(getIsTaskComplete);
    }, [tasks]);

    const isLessonsOnly = useMemo(() => {
      return tasks?.every((task) => task.type === 'LESSON' || !task.type);
    }, [tasks]);

    const nextTask = useMemo(() => {
      return tasks?.find((task) => !getIsTaskComplete(task) && !task.isLocked);
    }, [tasks]);

    const ctaLabel = useMemo(() => {
      if (isCompleteCampaign) {
        return messages.completed;
      }
      const isPartiallyCompleted = tasks?.some(getIsTaskComplete);
      if (isPartiallyCompleted) {
        return messages.continue;
      }
      return messages.start;
    }, [isCompleteCampaign, tasks]);

    const handleGoBack = useCallback(() => {
      if (canGoBack()) {
        goBack();
      } else {
        replace('LoyaltySurface', {});
      }
