                  resizeMode="cover"
                  aspectRatio={SHARED_IMAGE_SECTION_RATIO}
                  style={styles.borderRadius}
                />
                <Box
                  position="absolute"
                  top={paddingTop + spacing[1]}
                  left={spacing[1]}
                >
                  <IconButton name="backArrow" onPress={handleGoBack} />
                </Box>
              </Box>
              <VStack gap={2}>
                <VStack gap={1} spacingTop={2}>
                  {!noReward && (
                    <HStack gap={1} alignItems="center">
                      <AssetIcon
                        uri={iconUrl}
                        size="s"
                        name={assetName}
                        color={assetColor}
                      />
                      <TextLabel1
                        transform={
                          assetName === 'usdc' ? 'uppercase' : 'capitalize'
                        }
                      >
                        {assetName}
                      </TextLabel1>
                    </HStack>
                  )}

                  <TextTitle1>{header}</TextTitle1>
                  <TextBody>{extendedBody || body}</TextBody>
                </VStack>
                <VStack gap={4} offsetTop={0.5}>
                  <HStack gap={3}>
                    {!!duration && (
                      <HStack alignItems="center" gap={1}>
                        <Icon
                          name="clockOutline"
                          size="s"
                          color="foregroundMuted"
                        />
                        <TextLabel2 color="foregroundMuted">
                          {duration}
                        </TextLabel2>
                      </HStack>
                    )}
                    <HStack alignItems="center" gap={1}>
                      <Icon
                        name="newsletter"
                        size="s"
                        color="foregroundMuted"
                      />
                      <TextLabel2 color="foregroundMuted">
                        {isLessonsOnly
                          ? formatMessage(messages.lessonsLabel, {
                              taskCount: tasks?.length,
                            })
                          : formatMessage(messages.tasksLabel, {
                              taskCount: tasks?.length,
                            })}
                      </TextLabel2>
