            </VStack>
          </ScrollableView>
          <HStack
            alignItems="center"
            background="background"
            borderedTop
            gap={3}
            spacingTop={2}
            bottom={paddingBottom}
            spacingStart={3}
            spacingEnd={noReward ? 3 : 2}
          >
            {!noReward && (
              <HStack alignItems="center" gap={1}>
                <AssetIcon
                  uri={iconUrl}
                  size="s"
                  name={assetName}
                  color={assetColor}
