    const noReward = reward === 'None';

    const { iconUrl, imageUrl, header } = useLegacyLoyaltyCardDetails({
      iconUrl: defaultIconUrl || '',
      imageUrl: defaultImageUrl,
      fallbackImageUrl: tasks?.[0]?.imageUrl ?? '',
      header: defaultHeader || '',
      title,
      duration: '',
    });

    const { formatMessage } = useIntl();
    const isInBoostedRewardsExperiment = useIsInBoostedRewardsExperiment();
    const { presentUpsell } = useBoostedRewardUpsellContext();
    const { goBack, canGoBack, replace } = useStackNavigation();
