    const spacing = useSpacingScale();
    const { top: paddingTop, bottom: paddingBottom } = useDimensions();

    const assetName = assetSlug.split('-').join(' ');
    const assetColor = '#ffffff';

    const isCompleteCampaign = useMemo(() => {
      return tasks?.every(getIsTaskComplete);
    }, [tasks]);

    const isLessonsOnly = useMemo(() => {
      return tasks?.every((task) => task.type === 'LESSON' || !task.type);
    }, [tasks]);

    const sortedTasks = useMemo(() => {
      const tempTasks = tasks ? tasks.slice() : [];
      return tempTasks.sort((a, b) => {
        if (a.isComplete && !b.isComplete) {
          return 1;
        }
        if (!a.isComplete && b.isComplete) {
          return -1;
        }
        return 0;
      });
    }, [tasks]);

    const nextTask = useMemo(() => {
      return sortedTasks?.find((task) => !task.isComplete && !task.isLocked);
    }, [sortedTasks]);

    const ctaLabel = useMemo(() => {
      if (isCompleteCampaign) {
        return messages.completed;
      }
      const isPartiallyCompleted = tasks?.some(getIsTaskComplete);
      if (isPartiallyCompleted) {
        return messages.continue;
      }
      return messages.start;
    }, [isCompleteCampaign, tasks]);

    const handleGoBack = useCallback(() => {
      if (canGoBack()) {
        goBack();
      } else {
        replace('LoyaltySurface', {});
      }
    }, [canGoBack, goBack, replace]);

    const handlePresentUpsell = useCallback(() => {
      if (upsell?.upsellId) {
        presentUpsell(upsell?.upsellId);
      }
