    const handleCTAPress = useCallback(() => {
      if (nextTask) {
        if (nextTask.type === 'QUEST') {
          const questParsedUrl = parseUrl(nextTask.url);
          const [, , questLessonIndex] = questParsedUrl.pathname
            .split('/')
            .slice(2);
          const { campaign: questCampaignSlug } = questParsedUrl.params;
          earnModal.present('QuestInstructions', {
            campaignSlug: questCampaignSlug ?? '',
            assetSlug,
            lessonIndex: questLessonIndex,
          });
        } else {
          navigateWithUrl(nextTask.url);
        }
      }
    }, [assetSlug, earnModal, navigateWithUrl, nextTask]);

    const [animatedNavBarStyle, handleScroll] = useAnimatedNavBarStyle();

    const isBoosted = upsell?.isBoosted && isInBoostedRewardsExperiment;

    return (
      <>
        <Animated.View style={animatedNavBarStyle}>
          <NavHeader
            title={formatMessage(loyaltyMessages.title)}
            action="back"
            backHandler={handleGoBack}
            animate={false}
          />
        </Animated.View>
        <VStack height="100%">
          <ScrollableView
            bounces={false}
            onScroll={handleScroll}
            scrollEventThrottle={16}
            scrollIndicatorInsets={{ right: 1 }}
          >
            <VStack spacingBottom={4}>
              <Box offsetHorizontal={gutter}>
                <RemoteImage
                  width="100%"
                  source={{
                    uri: imageUrl,
                  }}
                  resizeMode="cover"
                  aspectRatio={SHARED_IMAGE_SECTION_RATIO}
                  style={styles.borderRadius}
                />
                <Box
                  position="absolute"
                  top={paddingTop + spacing[1]}
                  left={spacing[1]}
                >
                  <IconButton name="backArrow" onPress={handleGoBack} />
                </Box>
              </Box>
              <VStack gap={2}>
                <VStack gap={1} spacingTop={2}>
                  {!noReward && (
                    <HStack gap={1} alignItems="center">
                      <AssetIcon
                        uri={iconUrl}
                        size="m"
                        name={assetName}
                        color={assetColor}
                      />
                      <TextLabel1
                        transform={
                          assetName === 'usdc' ? 'uppercase' : 'capitalize'
                        }
                      >
                        {assetName}
                      </TextLabel1>
                    </HStack>
                  )}

                  <TextTitle1>{header}</TextTitle1>
                  <TextBody color="foregroundMuted">
                    {extendedBody || body}
                  </TextBody>
                </VStack>
                <VStack gap={4} offsetTop={0.5}>
                  <HStack gap={3}>
                    <HStack alignItems="center" gap={1}>
                      <Icon
                        name="newsletter"
                        size="s"
                        color="foregroundMuted"
