                          : formatMessage(messages.tasksLabel, {
                              taskCount: tasks?.length,
                            })}
                      </TextLabel2>
                    </HStack>
                  </HStack>
                  {isBoosted && (
                    <BoostedRewardCampaignBanner
                      rewardModifier={upsell?.boostAmount}
                      onPress={handlePresentUpsell}
                    />
                  )}
                  {sortedTasks?.map((task) => {
                    return (
                      <TaskCard
                        key={task.title + task.description}
                        entryPoint={entryPoint ?? entryPointFallback}
                        taskRef={task}
                        nextTaskTitle={nextTask?.title}
                      />
                    );
                  })}
                </VStack>
              </VStack>
            </VStack>
          </ScrollableView>
          <HStack
            alignItems="center"
            background="background"
            borderedTop
            gap={3}
            spacingTop={2}
            bottom={paddingBottom}
            spacingStart={3}
            spacingEnd={noReward ? 3 : 2}
          >
            {!noReward && (
              <HStack alignItems="center" gap={1}>
                <AssetIcon
                  uri={iconUrl}
                  size="m"
                  name={assetName}
                  color={assetColor}
                />
                <VStack alignItems="flex-start">
                  <TextCaption transform="uppercase" color="foregroundMuted">
                    {formatMessage(messages.reward)}
                  </TextCaption>
                  <TextHeadline color={isBoosted ? 'primary' : 'foreground'}>
                    {reward}
                  </TextHeadline>
                </VStack>
              </HStack>
            )}
            <Box flexGrow={1}>
              <Button
                testID="campaignDetailScreen_cta"
                block
                spacingBottom={0}
                disabled={isCompleteCampaign || !nextTask}
                onPress={handleCTAPress}
              >
                {formatMessage(ctaLabel)}
              </Button>
            </Box>
          </HStack>
        </VStack>
      </>
    );
  },
);

export const QuestInstructionScreen = memo(() => {
  const isRedesignEnabled = useLearningRewardsRedesign();
  const query = useLazyLoadQuery<LoyaltyMixedCampaignDetailScreenQuery>(
    graphql`
      query LoyaltyMixedCampaignDetailScreenQuery(
        $location: LoyaltyCardLocation
        $inAppIdv: Boolean
        $fullWidthSummary: Boolean
      ) {
        ...BoostedRewardUpsellProviderFragment
        viewer @required(action: THROW) {
          loyaltyCards(
            location: $location
            inAppIdv: $inAppIdv
            fullWidthSummary: $fullWidthSummary
          ) {
            edges {
              node {
                title
                header
                cardName
                imageUrl
                iconUrl
                body
                extendedBody
                duration
                reward
                tasks {
                  ...TaskCardFragment
                  title
                  description
                  imageUrl
                  url
                  reward
                  isComplete
                  isLocked
                  type
                }
                upsell {
                  upsellId
                  isBoosted
                  boostAmount
                }
              }
            }
          }
        }
      }
    `,
    {
      location: 'LOYALTY_SURFACE',
      inAppIdv: true,
      fullWidthSummary: true,
    },
  );

  const { viewer } = query;

  return isRedesignEnabled ? (
    <BoostedRewardUpsellProvider queryRef={query} source="campaignDetailScreen">
      <LoyaltyMixedCampaignDetailScreenContentRedesign viewer={viewer} />
    </BoostedRewardUpsellProvider>
  ) : (
    <LoyaltyMixedCampaignDetailScreenContent viewer={viewer} />
  );
});

const QuestInstructionScreenWithBoundary = memo(() => {
  return (
    <ScreenBoundary
      instrumentationId="LoyaltyMixedCampaignDetailScreen"
      errorFallback={IneligibleCampaignError}
      willErrorBlockUser={false}
    >
      <QuestInstructionScreen />
    </ScreenBoundary>
  );
});

function getIsTaskComplete(task: {
  isComplete: boolean | null;
  description: string | null;
}) {
  // Legacy campaigns don't necessarily use the `isComplete` boolean but instead
  // have "earned" or "complete" in the description
  return /earned|complete/i.test(task.description ?? '') || task.isComplete;
}

