const i18nKey = 'LoyaltyStaticLessonLayout';
const messages = defineMessages({
  start: {
    id: `${i18nKey}.start`,
    defaultMessage: 'Start quiz',
    description: 'Start button',
  },
});

export const LoyaltyStaticLessonLayout = memo<LoyaltyStaticLessonLayoutProps>(
  ({
    earnCampaignType,
    totalLessonCount,
    assetSlug,
    index,
    entryPoint,
    campaignSlug,
    isLessonCompleted,
    staticLessonRef,
  }) => {
    const { push, goBack } = useStackNavigation();

    const [currentScreenIndex, setCurrentScreenIndex] = useState(0);
    const isRedesignEnabled = useLearningRewardsRedesign();
    const { formatMessage } = useIntl();
    const { top, bottom } = useSafeAreaInsets();

    const data = useFragment(
      graphql`
        fragment LoyaltyStaticLessonLayoutFragment on EarnStaticLesson {
          screens {
            title
            body
            imageUrl
          }
        }
      `,
      staticLessonRef,
    );

    const screens = useMemo(() => {
      return data.screens || [];
    }, [data.screens]);

    const handleGoBack = useCallback(() => {
      goBack();
    }, [goBack]);

    const handleNextScreen = useCallback(() => {
      if (currentScreenIndex === screens.length - 1 && !isLessonCompleted) {
        push('LoyaltyQuiz', {
          earnCampaignType,
          totalLessonCount,
          assetSlug,
          index,
          entryPoint,
          campaignSlug,
          source: 'static_lesson',
        });
      } else {
        setCurrentScreenIndex((screenIndex) => screenIndex + 1);
      }
    }, [
      assetSlug,
      campaignSlug,
      currentScreenIndex,
      earnCampaignType,
      entryPoint,
      index,
      isLessonCompleted,
      push,
      screens.length,
      totalLessonCount,
    ]);

    const handlePreviousScreen = useCallback(() => {
      setCurrentScreenIndex((screenIndex) => screenIndex - 1);
    }, []);

    const currentScreen = screens?.[currentScreenIndex];

    const renderLessonImage = useCallback(() => {
      if (!currentScreen) {
        return null;
      }
      if (currentScreen.imageUrl?.includes('http')) {
        return (
          <RemoteImage
            testID="LoyaltyStaticLessonLayout-RemoteImage"
            height={240}
            aspectRatio={[240, 240] as [number, number]}
            source={{
              uri: currentScreen.imageUrl || undefined,
            }}
          />
        );
      }

      return (
        <HeroSquare
          testID="LoyaltyStaticLessonLayout-HeroSquare"
          name={currentScreen.imageUrl as HeroSquareName}
          fallback={
            <SpotSquare
              testID="LoyaltyStaticLessonLayout-SpotSquare"
              scaleMultiplier={2}
              name={currentScreen.imageUrl as SpotSquareName}
            />
          }
        />
      );
    }, [currentScreen]);

    const showNextScreenButton =
      currentScreenIndex !== screens.length - 1 ? true : !isLessonCompleted;

    const renderNextButton = useCallback(() => {
      if (currentScreenIndex === screens.length - 1 && isLessonCompleted) {
        return null;
      }
      if (currentScreenIndex === screens.length - 1 && !isLessonCompleted) {
        return (
          <Button
            testID="LoyaltyStaticLessonLayout-Button-start"
            compact
            spacingBottom={0}
            onPress={handleNextScreen}
          >
            {formatMessage(messages.start)}
          </Button>
        );
      }
      return (
        <IconButton
          testID="LoyaltyStaticLessonLayout-IconButton-forwardArrow"
          name="forwardArrow"
          onPress={handleNextScreen}
        />
      );
    }, [
      currentScreenIndex,
      formatMessage,
      handleNextScreen,
      isLessonCompleted,
      screens.length,
    ]);

    const headerStyle = useMemo(() => ({ paddingTop: top }), [top]);
    const footerStyle = useMemo(() => ({ paddingBottom: bottom }), [bottom]);

    const renderRedesign = useCallback(() => {
      return (
        <VStack justifyContent="space-between">
          <VStack
            background="secondary"
            spacing={layoutSpacing}
            gap={5}
            height="50%"
          >
            <HStack
              style={headerStyle}
              justifyContent="space-between"
              alignItems="center"
            >
              <Box>
                <IconButton
                  testID="LoyaltyStaticLessonLayout-IconButton-close"
                  name="close"
                  onPress={handleGoBack}
                />
              </Box>
              <HStack width={200} gap={1}>
                {screens?.map((screen, i) => (
                  <ProgressBar
                    key={screen?.body}
                    progress={Number(i <= currentScreenIndex)}
                    color="primary"
                  />
                ))}
              </HStack>
              <Spacer horizontal={5} />
            </HStack>
            {!!currentScreen && (
              <HStack
                width="100%"
                justifyContent="center"
                alignItems="center"
                flexGrow={1}
              >
                {renderLessonImage()}
              </HStack>
            )}
          </VStack>

          <VStack
            spacing={layoutSpacing}
            height="50%"
            justifyContent="space-between"
          >
            {!!currentScreen && (
              <ScrollView bounces={false}>
                <VStack gap={2}>
                  <TextTitle1>{currentScreen.title}</TextTitle1>
                  <TextBody color="foregroundMuted">
                    {currentScreen.body}
                  </TextBody>
                </VStack>
              </ScrollView>
            )}

            <HStack
              spacingTop={2}
              alignItems="center"
              justifyContent={
                currentScreenIndex !== 0 ? 'space-between' : 'flex-end'
              }
              style={footerStyle}
            >
              {currentScreenIndex !== 0 && (
                <IconButton
                  testID="LoyaltyStaticLessonLayout-IconButton-backArrow"
                  name="backArrow"
                  onPress={handlePreviousScreen}
                />
              )}
              {renderNextButton()}
            </HStack>
          </VStack>
        </VStack>
      );
    }, [
      currentScreen,
      currentScreenIndex,
      footerStyle,
      handleGoBack,
      handlePreviousScreen,
      headerStyle,
      renderLessonImage,
      renderNextButton,
      screens,
    ]);

    return isRedesignEnabled ? (
      renderRedesign()
    ) : (
      /* SafeAreaView keeps UI within the bounds of the screen for iOS. So if it is an iPhone with a notch the content starts after the notch to avoid overlapping the status bar. For android, we'll add extra padding to the top the size of the status bar */
      <SafeAreaView style={safeAreaViewStyle}>
        <VStack justifyContent="space-between">
          <VStack
            background="backgroundAlternate"
            spacing={layoutSpacing}
            gap={5}
            height="50%"
          >
            <HStack
              justifyContent="center"
              alignItems="center"
              spacing={2} // Avoid overlay that would prevent "X" icon from being pressable
            >
              <Box
                position="absolute"
                top={0}
                left={0}
                zIndex={zIndex.navigation}
              >
                <IconButton
                  testID="LoyaltyStaticLessonLayout-IconButton-close"
                  name="close"
                  onPress={handleGoBack}
                />
              </Box>
              <VStack alignItems="center">
                <HStack width={80} gap={0.5}>
                  {screens?.map((screen, i) => (
                    <ProgressBar
                      key={screen?.body}
                      progress={Number(i === currentScreenIndex)}
                      color="foreground"
                    />
                  ))}
                </HStack>
              </VStack>
            </HStack>
            {!!currentScreen && (
              <HStack
                width="100%"
                justifyContent="center"
                alignItems="center"
                flexGrow={1}
              >
                {renderLessonImage()}
              </HStack>
            )}
          </VStack>

          <VStack
            spacing={layoutSpacing}
            height="50%"
            justifyContent="space-between"
          >
            {!!currentScreen && (
              <ScrollView bounces={false}>
                <VStack gap={2}>
                  <TextTitle3>{currentScreen.title}</TextTitle3>
                  <TextBody>{currentScreen.body}</TextBody>
                </VStack>
              </ScrollView>
            )}

            <HStack
              spacingTop={2}
              justifyContent={
                currentScreenIndex !== 0 ? 'space-between' : 'flex-end'
              }
            >
              {currentScreenIndex !== 0 && (
                <IconButton
                  testID="LoyaltyStaticLessonLayout-IconButton-backArrow"
                  name="backArrow"
                  onPress={handlePreviousScreen}
                />
              )}
              {showNextScreenButton && (
                <IconButton
                  testID="LoyaltyStaticLessonLayout-IconButton-forwardArrow"
                  name="forwardArrow"
                  onPress={handleNextScreen}
                />
              )}
            </HStack>
          </VStack>
        </VStack>
      </SafeAreaView>
    );
  },
);

import { memo, useCallback, useMemo } from 'react';
import { LoyaltyCardStyle } from '@core/__generated__/enums';
import { useIsTreatment } from '@experiments/hooks/useIsTreatment';
import { gutter } from '@cbhq/cds-common/tokens/sizing';
import { useToggler } from '@cbhq/cds-mobile';
import { Box, Divider, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { TextTitle3 } from '@cbhq/cds-mobile/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';
import {
  FragmentRefs,
  graphql,
  useLazyLoadQuery,
  useRefreshQuery,
  useSubscribeToInvalidationState,
} from '@cbhq/data-layer';
import { useIntl } from '@cbhq/i18n';

import { IconButton } from '@components/interactables/IconButton';
import { AnimatedFlatList } from '@components/UI/FlatList';
import { ViewportTracker } from '@components/ViewportTracker/ViewportTracker';
import { host } from '@config/api';
import { removeFalsyValues } from '@utils/array/arrayUtils';
import { useKillSwitch } from '@utils/clientKillSwitch/useKillSwitch';
import {
  getStoreDataSynchronous,
  setStoreDataSynchronous,
} from '@utils/DataStorage';
import { VisibilityTracker } from '@app/components/Analytics/VisibilityTracker';
import { ErrorBoundary } from '@app/components/ErrorBoundary';
import { RefreshControl } from '@app/components/RefreshControl';
import { Screen } from '@app/components/Screen';
import { ScreenBoundary } from '@app/components/ScreenBoundary/ScreenBoundary';
import { ShareIcon } from '@app/components/ShareIcon';
import { ShareTray } from '@app/components/ShareTray/ShareTray';
import { SocialShareIconEventType } from '@app/components/ShareTray/utils/ShareTrayAnalytics';
import { useTrackViewEffectNotValid } from '@app/hooks/analytics/useTrackViewEffectNotValid';
import { useStackNavigation } from '@app/hooks/navigation/useStackNavigation';
import { useIsInBoostedRewardsExperiment } from '@app/hooks/useIsInBoostedRewardsExperiment';
import { useNavHeaderScrolling } from '@app/hooks/useNavHeaderScrolling';
import { EarnShareCard } from '@app/screens/Loyalty/components/EarnShareCard';
import { InProgressCard } from '@app/screens/Loyalty/components/InProgressCard';
import { MixedCampaignCard } from '@app/screens/Loyalty/components/MixedCampaignCard';
import { loyaltyStoreName } from '@app/screens/Loyalty/utils/constants';
import { PolicyRestrictionName } from '@app/screens/TransactionHistory/hooks/__generated__/usePolicyRestrictionsQuery.graphql';
import { usePolicyRestrictions } from '@app/screens/TransactionHistory/hooks/usePolicyRestrictions';
import { isIdvRestriction } from '@onboarding/utils/PolicyRestrictionUtils';

import { LoyaltySurfaceScreenQuery } from './__generated__/LoyaltySurfaceScreenQuery.graphql';
import { BoostedRewardEntryPoint } from './components/BoostedRewards/BoostedRewardEntryPoint';
import { EarnShareSecondaryCard } from './components/EarnShareSecondaryCard';
import { EarnTcFooter } from './components/EarnTcFooter';
import { useEarnShareCurrencyFormatter } from './components/hooks/useEarnShareCurrencyFormatter';
import { LearningRewardsTermsTray } from './components/LearningRewardsTermsTray';
import { PastTasksFooter } from './components/PastTasksFooter';
import { QuestIntakeCard } from './components/QuestIntakeCard';
import { WalletQuestUpsellCard } from './components/WalletQuestUpsellCard';
import useLearningRewardsInProgress from './hooks/useLearningRewardsInProgress';
import useLearningRewardsRedesign from './hooks/useLearningRewardsRedesign';
import { messages } from './utils/messages';
import LearningRewardsEmptyView from './LearningRewardsEmptyView';
import { LoyaltySurfaceScreenFallback } from './LoyaltySurfaceScreenFallback';
import { LoyaltySurfaceScreenHeader } from './LoyaltySurfaceScreenHeader';

const trackViewEventData = {
  action: ActionType.view,
  componentType: ComponentType.page,
};

const loyaltySurfaceScreenQuery = graphql`
  query LoyaltySurfaceScreenQuery(
    $location: LoyaltyCardLocation
    $inAppIdv: Boolean
    $fullWidthSummary: Boolean
    $isShareEnabled: Boolean!
  ) {
    ...LoyaltySurfaceScreenHeaderFragment
    viewer @required(action: THROW) {
      id
      earnUserProgress {
        eligibilityStatus
        earnings {
          allTimeEarned {
            value
            currency
          }
        }
      }
      ...EarnShareCardFragment @arguments(include: $isShareEnabled)
      ...EarnShareSecondaryCardFragment @arguments(include: $isShareEnabled)
      loyaltyCards(
        location: $location
        inAppIdv: $inAppIdv
        fullWidthSummary: $fullWidthSummary
      ) {
        edges {
          node {
            ...MixedCampaignCardFragment
            ...InProgressCardFragment
            cardName
            reward
            tasks {
              isComplete
            }
          }
        }
        featured {
          isBoosted
          totalRewardAmount
          boostAmount
        }
      }
    }
  }
`;

const LoyaltySurfaceScreen = memo(function LoyaltySurfaceScreen() {
  const [showPastTasks, { toggle: toggleHistory }] = useToggler(false);
  const { formatMessage } = useIntl();
  const { popStack, navigate } = useStackNavigation();
  const { restrictions } = usePolicyRestrictions('receives');
  const { scrollRef, onScroll } = useNavHeaderScrolling();
  useTrackViewEffectNotValid('loyalty_page_viewed', trackViewEventData);
  const showQuestIntake = useIsTreatment('dec_2023_retail_quest_intake');
  const isRedesignEnabled = useLearningRewardsRedesign();
  const isInProgressEnabled = useLearningRewardsInProgress();
  const isInBoostedRewardsExperiment = useIsInBoostedRewardsExperiment();

  const query = useLazyLoadQuery<LoyaltySurfaceScreenQuery>(
    loyaltySurfaceScreenQuery,
    {
      location: 'LOYALTY_SURFACE',
      inAppIdv: true,
      fullWidthSummary: true,
      isShareEnabled: true,
    },
  );

  const { viewer } = query;

  const { refresh } = useRefreshQuery<LoyaltySurfaceScreenQuery>(
    loyaltySurfaceScreenQuery,
    {
      location: 'LOYALTY_SURFACE',
      inAppIdv: true,
      fullWidthSummary: true,
      isShareEnabled: true,
    },
  );

  useSubscribeToInvalidationState([viewer.id], refresh);

  const isWalletQuestUpsellEnabled = useKillSwitch(
    'enable_wallet_quest_upsell_rn',
  );
  const hasIdvRestrictions = useMemo(
    () =>
      restrictions?.some((restriction) =>
        isIdvRestriction(restriction.restrictionName as PolicyRestrictionName),
      ),
    [restrictions],
  );
  const isEarningCardEligible =
    !hasIdvRestrictions &&
    viewer.earnUserProgress?.eligibilityStatus === 'FULLY_ELIGIBLE';

  type Card = {
    readonly cardName: string;
    readonly reward: string | null;
    readonly tasks: readonly { readonly isComplete: boolean | null }[] | null;
    readonly ' $fragmentSpreads': FragmentRefs<
      'InProgressCardFragment' | 'MixedCampaignCardFragment'
    >;
  };

  const upsellFeatured = useMemo(() => {
    return {
      isBoosted: viewer?.loyaltyCards?.featured?.isBoosted ?? false,
      boostAmount: viewer?.loyaltyCards?.featured?.boostAmount ?? null,
      totalRewardAmount:
        viewer?.loyaltyCards?.featured?.totalRewardAmount ?? null,
    };
  }, [viewer?.loyaltyCards]);

  const shouldShowBoostedRewardEntryPoint =
    upsellFeatured?.isBoosted && isInBoostedRewardsExperiment;

  const [nonCompletedCards, inProgressCards, notStartedCards, completedCards] =
    useMemo(() => {
      const walletUpsellEdge = {
        node: {
          cardName: 'walletQuestUpsell',
          subtitle: '',
          title: '',
          reward: '',
          tasks: [
            {
              isComplete: false,
              description: '',
              url: '',
            },
          ],
          style: 'MIXED' as LoyaltyCardStyle,
          ' $fragmentSpreads': null as unknown as FragmentRefs<
            'InProgressCardFragment' | 'MixedCampaignCardFragment'
          >,
        },
      };

      const tempInProgressCards = [] as Card[];
      const tempNotStartedCards = [] as Card[];
      const tempCompletedCards = [] as Card[];

      let loyaltyCardEdges = viewer.loyaltyCards?.edges || [];

      if (isWalletQuestUpsellEnabled && isEarningCardEligible) {
        loyaltyCardEdges = [...loyaltyCardEdges, walletUpsellEdge];
      }

      const nonFalsyCards = removeFalsyValues(
        loyaltyCardEdges.map((edge) => edge.node) || [],
      );

      nonFalsyCards.forEach((card) => {
        const allTasksComplete = card.tasks?.every((task) => task.isComplete);

        if (allTasksComplete) {
          tempCompletedCards.push(card);
        } else if (card.tasks?.some((task) => task.isComplete)) {
          tempInProgressCards.push(card);
        } else {
          tempNotStartedCards.push(card);
        }
      });

      // get numeric reward value from string reward
      const getRewardValue = (reward: string | null) => {
        if (reward) {
          return parseFloat(reward.replace(/[^0-9.-]+/g, ''));
        }
        return 0;
      };

      // sort by reward value
      const tempNonCompletedCards = [
        ...tempInProgressCards,
        ...tempNotStartedCards,
      ].sort((a, b) => {
        return getRewardValue(b.reward) - getRewardValue(a.reward);
      });

      // sort by ratio of completed tasks
      tempInProgressCards.sort((a, b) => {
        const aTasks = a.tasks || [];
        const bTasks = b.tasks || [];

        const aCompletedTasks = aTasks.filter((task) => task.isComplete);
        const bCompletedTasks = bTasks.filter((task) => task.isComplete);

        return (
          bCompletedTasks.length / bTasks.length -
          aCompletedTasks.length / aTasks.length
        );
      });

      return [
        tempNonCompletedCards,
        tempInProgressCards,
        tempNotStartedCards,
        tempCompletedCards,
      ];
    }, [isEarningCardEligible, isWalletQuestUpsellEnabled, viewer]);

  const refreshControl = useMemo(() => {
    return <RefreshControl onRefresh={refresh} />;
  }, [refresh]);

  const allTimeEarned = viewer.earnUserProgress?.earnings.allTimeEarned.value;
  const allTimeEarnedCurrency =
    viewer.earnUserProgress?.earnings.allTimeEarned.currency;

  const formattedAmount = useEarnShareCurrencyFormatter(
    allTimeEarned ?? '0',
    allTimeEarnedCurrency ?? 'USD',
  );

  const showEarnShare = useMemo(() => {
    if (!viewer.earnUserProgress) {
      return false;
    }

    const isEarnShareEligibile =
      viewer.earnUserProgress?.eligibilityStatus === 'FULLY_ELIGIBLE';
    const hasEarned = Number(allTimeEarned) > 0;
    return isEarnShareEligibile && hasEarned;
  }, [allTimeEarned, viewer.earnUserProgress]);

  const [
    shareTrayVisible,
    { toggleOff: hideShareTray, toggleOn: showShareTray },
  ] = useToggler(false);

  const hasLearningRewards = useMemo(
    () => nonCompletedCards.length + completedCards.length > 0,
    [nonCompletedCards.length, completedCards.length],
  );

  const shareTrayMessages = useMemo(
    () => ({
      title: formatMessage(messages.shareTitle, {}),
      message: (isTwitterShare = false) =>
        formatMessage(messages.shareMessage, {
          amount: formattedAmount,
          coinbase: isTwitterShare ? '@Coinbase' : 'Coinbase',
        }),
    }),
    [formatMessage, formattedAmount],
  );

  const renderCard = useCallback(
    ({
      item: card,
      index,
    }: {
      item: (typeof nonCompletedCards)[0];
      index: number;
    }) => {
      const shouldShowDivider = index > 0;

      return (
        <VisibilityTracker
          key={card.cardName}
          eventName="loyalty_card_viewed"
          eventData={{
            action: ActionType.view,
            componentType: ComponentType.unknown,
            card_location: 'loyalty_surface',
            card_name: card.cardName,
          }}
        >
          <ErrorBoundary context={`${card}LoyaltySurfaceCard`} fallback={null}>
            <Box spacingHorizontal={gutter} spacingBottom={4}>
              {card.cardName === 'walletQuestUpsell' ? (
                <WalletQuestUpsellCard shouldShowDivider={shouldShowDivider} />
              ) : (
                <MixedCampaignCard
                  shouldShowDivider={shouldShowDivider}
                  entryPoint="rewards"
                  loyaltyCardRef={card}
                />
              )}
            </Box>
          </ErrorBoundary>
        </VisibilityTracker>
      );
    },
    [],
  );

  const renderInProgressCard = useCallback(
    ({ item: card }: { item: (typeof inProgressCards)[0] }) => {
      return (
        <VisibilityTracker
          key={card.cardName}
          eventName="loyalty_card_viewed"
          eventData={{
            action: ActionType.view,
            componentType: ComponentType.unknown,
            card_location: 'loyalty_surface',
            card_name: card.cardName,
          }}
        >
          <ErrorBoundary
            context={`${card}LoyaltyInProgressCard`}
            fallback={null}
          >
            <Box spacingHorizontal={gutter} spacingBottom={2}>
              <InProgressCard loyaltyCardRef={card} />
            </Box>
          </ErrorBoundary>
        </VisibilityTracker>
      );
    },
    [],
  );

  const handleNavigationToBoostedRewards = useCallback(() => {
    navigate('BoostedRewards', {});
  }, [navigate]);

  const header = useMemo(() => {
    return (
      <>
        <LoyaltySurfaceScreenHeader
          queryRef={query}
          showPastTasks={showPastTasks}
        />
        {isRedesignEnabled &&
          !showPastTasks &&
          isInProgressEnabled &&
          inProgressCards.length > 0 && (
            <>
              <TextTitle3 spacingVertical={2} spacingHorizontal={6}>
                {formatMessage(messages.inProgressTitle)}
              </TextTitle3>
              {inProgressCards.map((card) =>
                renderInProgressCard({ item: card }),
              )}
            </>
          )}
        {isRedesignEnabled && showPastTasks && (
          <TextTitle3 spacingVertical={2} spacingHorizontal={6}>
            {formatMessage(messages.taskHistory)}
          </TextTitle3>
        )}
        {shouldShowBoostedRewardEntryPoint && (
          <BoostedRewardEntryPoint
            rewardModifier={upsellFeatured?.boostAmount}
            onPress={handleNavigationToBoostedRewards}
          />
        )}
      </>
    );
  }, [
    query,
    isRedesignEnabled,
    showPastTasks,
    isInProgressEnabled,
    inProgressCards,
    formatMessage,
    renderInProgressCard,
    upsellFeatured,
    shouldShowBoostedRewardEntryPoint,
    handleNavigationToBoostedRewards,
  ]);

  const hasAgreedToTerms = useMemo(() => {
    return getStoreDataSynchronous(loyaltyStoreName, 'terms', false);
  }, []);

  const [termsTrayVisible, { toggleOff: toggleTermsTrayOff }] =
    useToggler(!hasAgreedToTerms);

  const setAgreedToTerms = useCallback(() => {
    setStoreDataSynchronous(loyaltyStoreName, 'terms', true);
    toggleTermsTrayOff();
  }, [toggleTermsTrayOff]);

  const footer = useMemo(
    () => (
      <VStack spacingHorizontal={isRedesignEnabled ? 3 : 0}>
        <Divider />
        {completedCards.length > 0 && !showPastTasks && (
          <PastTasksFooter onPress={toggleHistory} />
        )}
        {showQuestIntake && (
          <>
            <Divider />
            <QuestIntakeCard />
            <Divider spacingBottom={2} />
          </>
        )}
        {isRedesignEnabled ? (
          termsTrayVisible && (
            <LearningRewardsTermsTray setAgreedToTerms={setAgreedToTerms} />
          )
        ) : (
          <EarnTcFooter spacingHorizontal={gutter} spacingBottom={6} />
        )}
      </VStack>
    ),
    [
      isRedesignEnabled,
      completedCards.length,
      showPastTasks,
      toggleHistory,
      showQuestIntake,
      termsTrayVisible,
      setAgreedToTerms,
    ],
  );

  const trailingNavButtons = useMemo(() => {
    const eventData: SocialShareIconEventType = {
      currency: null,
      surface: 'earn_journey',
      transaction_type: 'earn',
    };

    return (
      <HStack>
        {showEarnShare && !isRedesignEnabled && (
          <ShareIcon
            eventData={eventData}
            onPress={showShareTray}
            transparent
          />
        )}
        {completedCards.length > 0 && (
          <IconButton
            name="clock"
            aria-label="history"
            transparent
            onPress={toggleHistory}
          />
        )}
      </HStack>
    );
  }, [
    completedCards.length,
    isRedesignEnabled,
    showEarnShare,
    showShareTray,
    toggleHistory,
  ]);

  const handleBackPress = useCallback(() => {
    if (showPastTasks) {
      toggleHistory();
    } else {
      popStack();
    }
  }, [showPastTasks, toggleHistory, popStack]);

  const cardsToDisplay = useMemo(() => {
    if (isRedesignEnabled) {
      if (showPastTasks) {
        return completedCards;
      }
      return isInProgressEnabled ? notStartedCards : nonCompletedCards;
    }
    return showPastTasks ? completedCards : nonCompletedCards;
  }, [
    isRedesignEnabled,
    showPastTasks,
    completedCards,
    nonCompletedCards,
    isInProgressEnabled,
    notStartedCards,
  ]);

  if (!hasLearningRewards) {
    return <LearningRewardsEmptyView />;
  }

  return (
    <Screen
      scrollable={false}
      spacingBottom={0}
      scrollRefOverride={scrollRef}
      staticHeader={!hasLearningRewards}
      refreshControl={refreshControl}
      noSpacing={isRedesignEnabled}
      navHeader={{
        title: showPastTasks
          ? formatMessage(messages.taskHistory)
          : formatMessage(messages.title),
        action: 'back',
        backHandler: handleBackPress,
        trailing: trailingNavButtons,
        animate: false,
      }}
    >
      <ViewportTracker>
        <AnimatedFlatList
          data={cardsToDisplay}
          onScroll={onScroll}
          refreshControl={refreshControl}
          onEndReachedThreshold={0.7}
          renderItem={renderCard}
          ListHeaderComponent={header}
          ListFooterComponent={footer}
        />
      </ViewportTracker>

      <ShareTray
        action="Earn"
        cardType="earnJourney"
        isVisible={shareTrayVisible}
        messages={shareTrayMessages}
        onDismiss={hideShareTray}
        shareableLink={`${host}/learning-rewards`}
      >
        <EarnShareCard cardSize="medium" viewerRef={viewer} />
        <EarnShareSecondaryCard cardSize="medium" viewerRef={viewer} />
      </ShareTray>
    </Screen>
  );
});

const LoyaltySurfaceScreenWithBoundary = memo(() => {
  return (
    <ScreenBoundary
      fallback={<LoyaltySurfaceScreenFallback />}
      instrumentationId="LoyaltySurfaceScreen"
    >
      <LoyaltySurfaceScreen />
    </ScreenBoundary>
  );
});

export { LoyaltySurfaceScreenWithBoundary as LoyaltySurfaceScreen };

