export const QuestInstructionsScreenContent = memo(
  function QuestInstructionsScreenContent() {
    const { campaignSlug, assetSlug, lessonIndex, entryPoint } =
      useParams<'QuestInstructions'>();

    useLogEventOnMount('loyalty_quest_instructions', {
      componentType: ComponentType.page,
      campaignSlug,
    });

    const { formatMessage } = useIntl();
    const navigation = useNavigation();
    const { navigate, goBack, push, replace } = useStackNavigation();
    const currentJumioProfile = useGetJumioProfile();
    const navigateToDeepLink = useDeepLinking();
    const spacing = useSpacingScale();
    const { top: paddingTop, bottom: paddingBottom } = useDimensions();
    const [animatedNavBarStyle, handleScroll] = useAnimatedNavBarStyle();

    const {
      viewer: { assetBySlug },
    } = useLazyLoadQuery<QuestInstructionsScreenQuery>(
      graphql`
        query QuestInstructionsScreenQuery(
          $assetSlug: String!
          $index: Int!
          $campaignSlug: String
        ) {
          viewer @required(action: THROW) {
            assetBySlug(slug: $assetSlug) @required(action: THROW) {
              ...QuestStepsScreenFragment
                @arguments(index: $index, campaignSlug: $campaignSlug)
              asset {
                uuid
                imageUrl
                name
                platformName
                color
              }
              earnLessonByIndex(index: $index, campaignSlug: $campaignSlug)
                @required(action: THROW) {
                isLocked
                isComplete
                isIDVRestricted
                earnLesson {
                  rewardCents
                  displayData {
                    ... on EarnQuestLesson {
                      title
                      description
                      imageUrl
                      duration
                      screens {
                        title
                        description
                        imageUrl
                        isComplete
                      }
                      cta {
                        text
                        url
                      }
                    }
                  }
                }
              }
            }
          }
        }
      `,
      { assetSlug, index: +lessonIndex, campaignSlug },
    );

    const uuid = assetBySlug?.asset?.uuid;
    const isLocked = assetBySlug?.earnLessonByIndex?.isLocked;
    const isIDVRestricted = !!assetBySlug?.earnLessonByIndex?.isIDVRestricted;
    const displayData = assetBySlug?.earnLessonByIndex?.earnLesson?.displayData;
    const screens = useMemo(
      () => (displayData?.screens ?? []) as Screen[],
      [displayData?.screens],
    );

    const isRedesignEnabled = useLearningRewardsRedesign();

    const { currentStep, completionRate } = getQuestProgress({
      campaignSlug,
      lessonIndex,
    });

    const numOfCompletedSteps = useMemo(() => {
      if (assetBySlug?.earnLessonByIndex?.isComplete) {
        return screens.length;
      }
      const numOfBackendCompletedSteps = screens.filter(
        (s) => s.isComplete,
      ).length;

      return Math.max(numOfBackendCompletedSteps, currentStep);
    }, [assetBySlug?.earnLessonByIndex?.isComplete, currentStep, screens]);

    const [activeStep, setActiveStep] = useState(numOfCompletedSteps);

    useEffect(() => {
      setStoreDataSynchronous(loyaltyStoreName, lessonIndex + campaignSlug, {
        currentStep: numOfCompletedSteps,
        completionRate: numOfCompletedSteps / screens.length,
      });
    }, [campaignSlug, lessonIndex, numOfCompletedSteps, screens.length]);

    const isLessonComplete = screens.length === numOfCompletedSteps;

    const asset = assetBySlug?.asset;
    const rewardCents =
      assetBySlug?.earnLessonByIndex?.earnLesson?.rewardCents ?? 0;

    const rewardAmount = useMemo(() => {
      if (rewardCents === 0) {
        return '';
      }
      return formatMessage(messages.rewardAmount, {
        reward: `$${rewardCents / 100}`,
        currency: asset?.platformName || '',
      });
    }, [asset?.platformName, formatMessage, rewardCents]);

    const reward = useMemo(() => {
      if (rewardCents === 0) {
        return null;
      }
      return (
        <TextHeadline color={isLessonComplete ? 'positive' : 'foreground'}>
          {rewardAmount}
        </TextHeadline>
      );
    }, [isLessonComplete, rewardAmount, rewardCents]);

    const rewardLabel = useMemo(() => {
      let copy = messages.reward;
      if (isLessonComplete) {
        copy = messages.earned;
      }
      return (
        <TextCaption
          transform="uppercase"
          color={isLessonComplete ? 'positive' : 'foregroundMuted'}
        >
          {formatMessage(copy)}
        </TextCaption>
      );
    }, [isLessonComplete, formatMessage]);

    const ctaText = displayData?.cta?.text;
    const label = useMemo(() => {
      if (isLocked) {
        return formatMessage(messages.unlockNow);
      }
      if (isLessonComplete) {
        return formatMessage(messages.completed);
      }
      if (completionRate > 0) {
        return formatMessage(messages.continue);
      }
      return ctaText ?? formatMessage(messages.start);
    }, [completionRate, ctaText, isLessonComplete, isLocked, formatMessage]);

    const [isWalletTrayVisible, { toggleOn, toggleOff }] = useToggler(false);
    const showWalletDownloadTray = useCallback(async () => {
      if (uuid === ACS_ASSET_UUID) {
        try {
          const isWalletInstalled = await getWalletInstallationStatus();
          if (!isWalletInstalled) {
            toggleOn();
            return true;
          }
          return false;
        } catch (e) {
          return Promise.reject(e);
        }
      }
      return false;
    }, [toggleOn, uuid]);

    const redirectToWalletDownload = useCallback(
      (closeTray: NoopFn) => {
        return () => {
          openAppstore()
            .catch(() => {
              closeTray();
            })
            .finally(() => {
              toggleOff();
            });
        };
      },
      [toggleOff],
    );

    // TODO: refactor this, lot of legacy conditions here
    const navigateToQuestSteps = useCallback(() => {
      const navigateToQuestStepsHelper = async () => {
        const userMustSubmitIDV =
          currentJumioProfile === null ||
          currentJumioProfile.status === 'FAILED';
        const userHasPendingIDV =
          !userMustSubmitIDV && currentJumioProfile.status !== 'COMPLETED';
        if (isIDVRestricted && userMustSubmitIDV) {
          navigation.navigate('SettingsModalStack', {
            screen: 'VerifyIdentityRedirect',
            params: {
              onSuccessRoute: 'EarnModalStack',
              onSuccessRouteParams: {
                screen: 'QuestInstructions',
                params: {
                  campaignSlug,
                  assetSlug,
                  lessonIndex,
                },
              },
              source: 'loyalty',
            },
          });
        } else if (isIDVRestricted && userHasPendingIDV) {
          navigation.navigate('SettingsModalStack', {
            screen: 'PendingRestriction',
            params: {
              source: 'loyalty',
            },
          });
        } else {
          const url = displayData?.cta?.url;
          if (url) {
            if (url.match(/https:\/\/coinbase.com\/cb-pay/)) {
              const parsedUrl = parseUrl(url);
              const [selectedChainIdStr] = parsedUrl.pathname
                .split('/')
                .slice(2);
              const { successExit } = parsedUrl.params;
              const selectedChainId = Number(selectedChainIdStr);
              navigate('DappCbPay', {
                selectedChainId,
                supportedChainIds: [selectedChainId],
                successExit,
              });
            }
            if (url.match(/https:\/\/(www\.)?coinbase.com/)) {
              navigateToDeepLink({ url, fallbackOnInvalidDeepLink: true });
            } else {
              try {
                const supported = await Linking.canOpenURL(url);
                if (supported) {
                  await Linking.openURL(url);
                } else {
                  navigateToDeepLink({ url, fallbackOnInvalidDeepLink: true });
                }
              } catch {
                navigateToDeepLink({ url, fallbackOnInvalidDeepLink: true });
              }
            }
          } else {
            push('QuestSteps', {
              lessonIndex,
              viewerAssetRef: assetBySlug,
            });
          }
        }
      };
      Analytics.tapTracker('loyalty_quest_cta_tapped', {
        componentType: ComponentType.button,
        campaignSlug,
        lessonIndex,
        isLocked,
      });
      if (isLocked) {
        if (uuid === ACS_ASSET_UUID) {
          navigateToDeepLink({
            url: 'https://coinbase.com/learning-rewards/access/lesson/1?type=story&campaign=access-b58c3750-5a3d-4de0-93e7-24ede2fadf7f&entryPoint=rewards',
            fallbackOnInvalidDeepLink: true,
          });
        } else if (uuid === ETH_ASSET_UUID) {
          navigateToDeepLink({
            url: 'https://coinbase.com/learning-rewards/ethereum/lesson/1?type=story&campaign=ethereum-fbbc45b8-a589-4467-9876-be857947ae7b&entryPoint=rewards',
            fallbackOnInvalidDeepLink: true,
          });
        }
      } else {
        showWalletDownloadTray()
          .then((shown) => {
            if (!shown) {
              navigateToQuestStepsHelper();
            }
          })
          .catch(() => {
            navigateToQuestStepsHelper();
          });
      }
    }, [
      campaignSlug,
      lessonIndex,
      isLocked,
      currentJumioProfile,
      isIDVRestricted,
      navigation,
      assetSlug,
      displayData?.cta?.url,
      navigate,
      navigateToDeepLink,
      push,
      assetBySlug,
      uuid,
      showWalletDownloadTray,
    ]);

    const handleGoBack = useCallback(() => {
      if (entryPoint === 'home') {
        replace('LoyaltySurface', {});
      } else {
        goBack();
      }
    }, [entryPoint, goBack, replace]);

    useFocusEffect(() => {
      const { currentStep: currentStepRefresh } = getQuestProgress({
        campaignSlug,
        lessonIndex,
      });
      // This is needed to ensure that local state activeStep is in sync with localStorage current step  when returning to QuestInstructions from QuestSteps
      if (currentStepRefresh !== activeStep) {
        setActiveStep(currentStepRefresh);
      }
    }, [activeStep]);

    if (
      // ESLint rule disabled because the value of asset by itself needs to be checked

      !asset ||
      !asset.imageUrl ||
      !displayData ||
      !displayData.duration ||
      !screens
    ) {
      goBack();
      return null;
    }
    const { imageUrl, title, description, duration } = displayData;
    const { imageUrl: iconUrl, name: assetName, color: assetColor } = asset;

    return isRedesignEnabled ? (
      <>
        <Animated.View style={animatedNavBarStyle}>
          <NavHeader
            title={formatMessage(loyaltyMessages.title)}
            action="back"
            backHandler={handleGoBack}
            animate={false}
          />
        </Animated.View>
        <VStack height="100%">
          <ScrollableView
            bounces={false}
            onScroll={handleScroll}
            scrollEventThrottle={16}
            scrollIndicatorInsets={{ right: 1 }}
          >
            <VStack spacingBottom={4}>
              <Box offsetHorizontal={gutter}>
                <RemoteImage
                  width="100%"
                  source={{
                    uri: imageUrl ?? '',
                  }}
                  resizeMode="cover"
                  aspectRatio={SHARED_IMAGE_SECTION_RATIO}
                  style={styles.borderRadius}
                />
                <Box
                  position="absolute"
                  top={paddingTop + spacing[1]}
                  left={spacing[1]}
                >
                  <IconButton name="backArrow" onPress={handleGoBack} />
                </Box>
              </Box>
              <VStack gap={2}>
                {isLocked && uuid === ACS_ASSET_UUID && (
                  <Box spacingTop={3} spacingBottom={1}>
                    <Banner
                      variant="warning"
                      bordered
                      showDismiss={false}
                      startIcon="lock"
                      title={formatMessage(messages.completeACSTitle)}
                    >
                      {formatMessage(messages.completeACSBody)}
                    </Banner>
                  </Box>
                )}
                <VStack spacingTop={3} gap={1}>
                  <TextTitle1>{title}</TextTitle1>
                  <TextBody color="foregroundMuted">{description}</TextBody>
                </VStack>
                <VStack gap={4} offsetTop={0.5}>
                  <HStack alignItems="center" gap={1}>
                    <Icon name="nft" size="s" color="foregroundMuted" />
                    <TextLabel1 color="foregroundMuted">
                      {formatMessage(messages.questLabel)}
                    </TextLabel1>
                  </HStack>
                  <QuestInstructionsList
                    activeStep={activeStep}
                    isLessonComplete={isLessonComplete}
                    numOfStepsComplete={numOfCompletedSteps}
                    hideProgressHeaders={!!ctaText}
                    screens={screens}
                    reward={rewardAmount}
                  />
                </VStack>
              </VStack>
            </VStack>
          </ScrollableView>
          <HStack
            alignItems="center"
            background="background"
            borderedTop
            gap={3}
            spacingTop={2}
            bottom={paddingBottom}
            spacingStart={3}
            spacingEnd={2}
          >
            {reward !== null && (
              <HStack alignItems="center" gap={1}>
                <AssetIcon
                  uri={iconUrl}
                  size="s"
                  name={assetName}
                  color={assetColor}
                />
                <VStack alignItems="flex-start">
                  {rewardLabel}
                  {reward}
                </VStack>
              </HStack>
            )}
            <Box flexGrow={1}>
              <Button
                testID="QuestInstructionsScreen-CTA"
                block={!isLocked}
                disabled={isLessonComplete}
                onPress={navigateToQuestSteps}
                spacingBottom={0}
              >
                <HStack alignItems="center" gap={2}>
                  {isLocked && (
                    <Icon size="m" name="unlock" color="primaryForeground" />
                  )}
                  <TextHeadline color="primaryForeground">{label}</TextHeadline>
                </HStack>
              </Button>
            </Box>
          </HStack>
          {isWalletTrayVisible && (
            <Tray onCloseComplete={toggleOff}>
              {({ handleClose }) => (
                <VStack
                  spacing={3}
                  spacingBottom={0}
                  gap={2}
                  alignItems="center"
                >
                  <Pictogram name="walletWarning" dimension="48x48" />
                  <TextTitle3 align="center" spacing={0}>
                    {formatMessage(messages.installWalletTitle)}
                  </TextTitle3>
                  <TextBody align="center">
                    {formatMessage(messages.installWalletBody)}
                  </TextBody>
                  <Button
                    spacingTop={1}
                    spacingBottom={0}
                    onPress={redirectToWalletDownload(handleClose)}
                    block
                  >
                    {formatMessage(messages.installWalletCTA)}
                  </Button>
                </VStack>
              )}
            </Tray>
          )}
        </VStack>
      </>
    ) : (
      <>
        <Animated.View style={animatedNavBarStyle}>
          <NavHeader
            title={formatMessage(loyaltyMessages.title)}
            action="back"
            backHandler={handleGoBack}
            animate={false}
          />
        </Animated.View>
        <VStack height="100%">
          <ScrollableView
            bounces={false}
            onScroll={handleScroll}
            scrollEventThrottle={16}
            scrollIndicatorInsets={{ right: 1 }}
          >
            <VStack spacingBottom={4}>
              <Box offsetHorizontal={gutter}>
                <RemoteImage
                  width="100%"
                  source={{
                    uri: imageUrl ?? '',
                  }}
                  resizeMode="cover"
                  aspectRatio={SHARED_IMAGE_SECTION_RATIO}
                  style={styles.borderRadius}
                />
                <Box
                  position="absolute"
                  top={paddingTop + spacing[1]}
                  left={spacing[1]}
                >
                  <IconButton name="backArrow" onPress={handleGoBack} />
                </Box>
              </Box>
              <VStack gap={2}>
                {isLocked && uuid === ACS_ASSET_UUID && (
                  <Box spacingTop={3} spacingBottom={1}>
                    <Banner
                      variant="warning"
                      bordered
                      showDismiss={false}
                      startIcon="lock"
                      title={formatMessage(messages.completeACSTitle)}
                    >
                      {formatMessage(messages.completeACSBody)}
                    </Banner>
                  </Box>
                )}
                <VStack gap={1}>
                  <HStack gap={1} alignItems="center" spacingTop={3}>
                    <AssetIcon
                      uri={iconUrl}
                      size="m"
                      name={assetName}
                      color={assetColor}
                    />
                    <TextHeadline>{assetName}</TextHeadline>
                  </HStack>

                  <TextTitle1>{title}</TextTitle1>
                  <TextBody>{description}</TextBody>
                </VStack>
                <VStack gap={4} offsetTop={0.5}>
                  <QuestLabels duration={duration} />

                  <Divider />
                  <QuestInstructionsList
                    activeStep={activeStep}
                    isLessonComplete={isLessonComplete}
                    numOfStepsComplete={numOfCompletedSteps}
                    hideProgressHeaders={!!ctaText}
                    screens={screens}
                    reward={rewardAmount}
                  />
                </VStack>
              </VStack>
            </VStack>
          </ScrollableView>
          <HStack
            alignItems="center"
            background="background"
            borderedTop
            gap={3}
            spacingTop={2}
            bottom={paddingBottom}
            spacingStart={3}
            spacingEnd={2}
          >
            {reward !== null && (
              <HStack alignItems="center" gap={1}>
                <AssetIcon
                  uri={iconUrl}
                  size="s"
                  name={assetName}
                  color={assetColor}
                />
                <VStack alignItems="flex-start">
                  {rewardLabel}
                  {reward}
                </VStack>
              </HStack>
            )}
            <Box flexGrow={1}>
              <Button
                testID="QuestInstructionsScreen-CTA"
                block={!isLocked}
                disabled={isLessonComplete}
                onPress={navigateToQuestSteps}
                spacingBottom={0}
              >
                <HStack alignItems="center" gap={2}>
                  {isLocked && (
                    <Icon size="m" name="unlock" color="primaryForeground" />
                  )}
                  <TextHeadline color="primaryForeground">{label}</TextHeadline>
                </HStack>
              </Button>
            </Box>
          </HStack>
          {isWalletTrayVisible && (
            <Tray onCloseComplete={toggleOff}>
              {({ handleClose }) => (
                <VStack
                  spacing={3}
                  spacingBottom={0}
                  gap={2}
                  alignItems="center"
                >
                  <Pictogram name="walletWarning" dimension="48x48" />
                  <TextTitle3 align="center" spacing={0}>
                    {formatMessage(messages.installWalletTitle)}
                  </TextTitle3>
                  <TextBody align="center">
                    {formatMessage(messages.installWalletBody)}
                  </TextBody>
                  <Button
                    spacingTop={1}
                    spacingBottom={0}
                    onPress={redirectToWalletDownload(handleClose)}
                    block
                  >
                    {formatMessage(messages.installWalletCTA)}
                  </Button>
                </VStack>
              )}
            </Tray>
          )}
        </VStack>
      </>
    );
  },
);

