type MixedCampaignCardContentProps = {
  campaign: Omit<
    MixedCampaign,
    'title' | 'style' | 'extendedBody' | 'tasks' | 'upsell'
  > & {
    tasks: readonly {
      type: string | null;
      isComplete: boolean | null;
      isLocked: boolean | null;
      isIDVRestricted: boolean | null;
      url: string;
    }[];
  };
  entryPoint: LoyaltyEarnEntryType;
  onPress?: () => void;
  tag?: string;
  cta?: string;
};

type MixedCampaignCardProps = {
  loyaltyCardRef: MixedCampaignCardFragment$key;
  entryPoint: LoyaltyEarnEntryType;
  shouldShowDivider?: boolean;
};

export const MixedCampaignCardContent = memo(function MixedCampaignCardContent({
  campaign,
  entryPoint,
  onPress,
  tag,
  cta,
}: MixedCampaignCardContentProps) {
  const { formatMessage } = useIntl();
  const navigation = useNavigation();
  const currentJumioProfile = useGetJumioProfile();

  const [completionRate, setCompletionRate] = useState(0);
  const { cardName, imageUrl, iconUrl, header, body, duration, reward, tasks } =
    campaign;
  const noReward = reward === 'None';
  const parsedUrl = parseUrl(tasks[0]?.url);
  const { campaign: campaignSlug = '' } = parsedUrl.params;
  const [lessonIndex] = parsedUrl.pathname.split('/').slice(4);

  const isLocked = useMemo(() => {
    return tasks.reduce((acc, task) => acc && !!task.isLocked, true);
  }, [tasks]);

  const completionRateHelper = useCallback(() => {
    if (tasks.length === 0) {
      setCompletionRate(0);
    }
    const frontendCompletionRate = getQuestProgress({
      campaignSlug,
      lessonIndex,
    }).completionRate;
    const backendCompletionRate =
      tasks.filter((task) => task.isComplete).length / tasks.length;
    setCompletionRate(Math.max(frontendCompletionRate, backendCompletionRate));
  }, [campaignSlug, lessonIndex, tasks]);
  // Check and reflect progress
  useEffect(() => {
    completionRateHelper();
  }, [campaignSlug, completionRateHelper, tasks]);
  useFocusEffect(() => {
    // This is needed to ensure that local var completionRate is in sync with localStorage
    completionRateHelper();
  }, []);

  const stepsIconName = useMemo(() => {
    if (tasks.length === 1) {
      return getTaskIconName(tasks[0].type ?? '');
    }
    return 'newsletter';
  }, [tasks]);

  const isLessonsOnly = useMemo(() => {
    return tasks?.every((task) => task.type === 'LESSON' || !task.type);
  }, [tasks]);

  const stepsIconLabel = useMemo(() => {
    if (tasks.length === 1) {
      return formatMessage(getTaskLabel(tasks[0].type ?? ''));
    }
    return isLessonsOnly
      ? formatMessage(messages.lessonsOnlyLabel, {
          numOfLessons: tasks.length,
        })
      : formatMessage(messages.lessonsLabel, {
          numOfLessons: tasks.length,
        });
  }, [formatMessage, isLessonsOnly, tasks]);

  const earnMessage = useMemo(() => {
    return completionRate === 1 ? messages.earnedLabel : messages.rewardLabel;
  }, [completionRate]);
  const earnModal = useModal('EarnModalStack');

  const { navigateWithUrl } = useEarnCardNavigation({
    entryPoint,
    earnCardRef: null,
  });

  const isUsdcCard = useMemo(() => tasks[0].type === 'USDC_UPSELL', [tasks]);

  const handlePress = useCallback(() => {
    Analytics.tapTracker('loyalty_card_tapped', {
      componentType: ComponentType.card,
      card_name: cardName,
      card_location: 'loyalty_surface',
    });

    if (onPress) {
      onPress();
      return;
    }

    if (tasks.length === 1) {
      const isIDVRestricted = !!tasks[0].isIDVRestricted;
      const userMustSubmitIDV =
        currentJumioProfile === null || currentJumioProfile.status === 'FAILED';
      const userHasPendingIDV =
        !userMustSubmitIDV && currentJumioProfile.status !== 'COMPLETED';
      if (isIDVRestricted && userMustSubmitIDV) {
        navigation.navigate('SettingsModalStack', {
          screen: 'VerifyIdentityRedirect',
          params: {
            onSuccessRoute: 'EarnModalStack',
            onSuccessRouteParams: { screen: 'LoyaltySurface', params: {} },
            source: 'loyalty',
          },
        });
      } else if (isIDVRestricted && userHasPendingIDV) {
        navigation.navigate('SettingsModalStack', {
          screen: 'PendingRestriction',
          params: {
            source: 'loyalty',
          },
        });
      } else if (tasks[0].type === 'QUEST') {
        const questParsedUrl = parseUrl(tasks[0].url);
        const [assetSlug, , questLessonIndex] = questParsedUrl.pathname
          .split('/')
          .slice(2);
        const { campaign: questCampaignSlug } = questParsedUrl.params;

        earnModal.present('QuestInstructions', {
          campaignSlug: questCampaignSlug ?? '',
          assetSlug,
          lessonIndex: questLessonIndex,
        });
      } else {
        navigateWithUrl(tasks[0].url);
      }
    } else if (tasks.length > 1) {
      const [assetSlug] = parsedUrl.pathname.split('/').slice(2);
      earnModal.present('LoyaltyMixedCampaignDetail', {
        assetSlug,
        cardName,
      });
    }
  }, [
    onPress,
    tasks,
    currentJumioProfile,
    navigation,
    cardName,
    earnModal,
    navigateWithUrl,
    parsedUrl.pathname,
  ]);

  const ctaButton = useMemo(() => {
    if (isLocked) {
      return (
        <IconButton
          name="lock"
          onPress={handlePress}
          variant="foregroundMuted"
        />
      );
    }
    return completionRate > 0 ? (
      <Box testID="mixedCampaignCard_continueButton">
        <IconButton
          name="caretRight"
          onPress={handlePress}
          variant="foregroundMuted"
        />
      </Box>
    ) : (
      <Button
        testID="mixedCampaignCard_startButton"
        onPress={handlePress}
        variant="secondary"
        spacingBottom={0}
        flexGrow={1}
        flexBasis="50%"
      >
        {cta ?? formatMessage(messages.startCTA)}
      </Button>
    );
  }, [isLocked, completionRate, handlePress, cta, formatMessage]);

  if (tasks.length === 0) {
    return null;
  }

  const showProgressBar =
    completionRate !== 0 && completionRate < 1 && tasks.length >= 1;

  return (
    <Card
      elevation={0}
      bordered
      borderRadius="rounded"
      spacing={0}
      onPress={handlePress}
    >
      <RemoteImage
        testID="mixedCampaignCard_image"
        source={{ uri: imageUrl }}
        height={REMOTE_IMAGE_HEIGHT}
        width="100%"
        resizeMode="cover"
        opacity={isLocked ? 0.5 : 1}
        style={styles.borderRadius}
      />
      <VStack spacing={LAYOUT_SPACING}>
        <VStack gap={1}>
          {!!tag && (
            <HStack>
              <Tag colorScheme="blue">{tag}</Tag>
            </HStack>
          )}
          <TextTitle3>{header}</TextTitle3>
          <TextBody color="foregroundMuted">{body}</TextBody>
        </VStack>

        <HStack gap={3} spacingTop={!isUsdcCard ? LAYOUT_SPACING : 0}>
          {!!duration && (
            <HStack alignItems="center" gap={1}>
              <Icon
                testID="mixedCampaignCard_durationIcon"
                name="clockOutline"
                size="s"
                color="foregroundMuted"
              />
              <TextLabel2 color="foregroundMuted">{duration}</TextLabel2>
            </HStack>
          )}
          {!isUsdcCard && (
            <HStack alignItems="center" gap={1}>
              <Icon
                testID="mixedCampaignCard_stepsIcon"
                name={stepsIconName}
                size="s"
                color="foregroundMuted"
              />
              <TextLabel2
                testID="mixedCampaignCard_stepLabel"
                color="foregroundMuted"
              >
                {stepsIconLabel}
              </TextLabel2>
            </HStack>
          )}
        </HStack>
      </VStack>
      {showProgressBar ? (
        <Box spacing={LAYOUT_SPACING}>
          <ProgressBar progress={completionRate} />
        </Box>
      ) : (
        <Divider />
      )}
      <HStack
        spacing={LAYOUT_SPACING}
        justifyContent={noReward ? 'flex-end' : 'space-between'}
        alignItems="center"
        gap={2}
      >
        {!noReward && (
          <HStack alignItems="center" gap={1}>
            <RemoteImage source={{ uri: iconUrl }} shape="circle" size="m" />
            <VStack alignItems="flex-start">
              <TextCaption
                transform="uppercase"
                color={completionRate === 1 ? 'positive' : 'foregroundMuted'}
              >
                {formatMessage(earnMessage)}
              </TextCaption>
              <TextHeadline
                color={completionRate === 1 ? 'positive' : 'foreground'}
              >
                {reward}
              </TextHeadline>
            </VStack>
          </HStack>
        )}
        {completionRate === 1 ? (
          <Icon
            testID="mixedCampaignCard_completedCampaignIcon"
            name="checkmark"
            size="s"
            color="positive"
            spacingEnd={1}
          />
        ) : (
          ctaButton
        )}
      </HStack>
    </Card>
  );
});

type MixedCampaignCardContentRedesignProps = {
  campaign: Omit<
    MixedCampaign,
    'title' | 'style' | 'extendedBody' | 'tasks' | 'duration'
  > & {
    tasks: readonly {
      type: string | null;
      isComplete: boolean | null;
      isLocked: boolean | null;
      isIDVRestricted: boolean | null;
      url: string;
    }[];
  };
  onPress?: () => void;
  tag?: string;
  shouldShowDivider?: boolean;
};

export const MixedCampaignCardContentRedesign = memo(
  function MixedCampaignCardContentRedesign({
    campaign,
    onPress,
    tag,
    shouldShowDivider = false,
  }: MixedCampaignCardContentRedesignProps) {
    const isInBoostedRewardsExperiment = useIsInBoostedRewardsExperiment();
    const { formatMessage } = useIntl();

    const spacing = useSpacingScale();
    const { cardName, imageUrl, iconUrl, header, body, reward, tasks, upsell } =
      campaign;
    const noReward = reward === 'None';
    const parsedUrl = parseUrl(tasks[0]?.url);

    const earnModal = useModal('EarnModalStack');

    const isBoosted = upsell?.isBoosted && isInBoostedRewardsExperiment;

    const handlePress = useCallback(() => {
      Analytics.tapTracker('loyalty_card_tapped', {
        componentType: ComponentType.card,
        card_name: cardName,
        card_location: 'loyalty_surface',
      });
      if (onPress) {
        onPress();
        return;
      }

      const [assetSlug] = parsedUrl.pathname.split('/').slice(2);
      earnModal.present('LoyaltyMixedCampaignDetail', {
        assetSlug,
        cardName,
      });
    }, [cardName, onPress, parsedUrl.pathname, earnModal]);

    const completedTaskCount = useMemo(() => {
      return tasks.filter((task) => task.isComplete).length;
    }, [tasks]);

    const allTasksCompleted = useMemo(() => {
      return tasks.length > 0 && tasks.length === completedTaskCount;
    }, [tasks, completedTaskCount]);

    const ctaButton = useMemo(() => {
      if (completedTaskCount === 0) {
        return (
          <Button
            testID="mixedCampaignCard_startButton"
            onPress={handlePress}
            variant="secondary"
            spacingBottom={0}
            compact
          >
            {formatMessage(messages.startCTA)}
          </Button>
        );
      }
      if (completedTaskCount < tasks.length) {
        return (
          <Button
            testID="mixedCampaignCard_continueButton"
            onPress={handlePress}
            variant="secondary"
            spacingBottom={0}
            compact
          >
            {formatMessage(messages.continueCTA)}
          </Button>
        );
      }

      return (
        <IconButton
          accessibilityLabel={formatMessage(messages.startCTA)}
          accessibilityHint={formatMessage(messages.startCTA)}
          testID="mixedCampaignCard_continueButton"
          name="forwardArrow"
          onPress={handlePress}
        />
      );
    }, [completedTaskCount, formatMessage, handlePress, tasks.length]);

    const renderProgressBar = useCallback(() => {
      if (completedTaskCount && !allTasksCompleted)
        return (
          <Box spacingBottom={1}>
            <ProgressBar
              progress={completedTaskCount / tasks.length}
              weight="heavy"
            />
          </Box>
        );
      return null;
    }, [completedTaskCount, allTasksCompleted, tasks.length]);

    return (
      <>
        {shouldShowDivider ? (
          <Divider spacingBottom={3} />
        ) : (
          <Spacer vertical={3} />
        )}
        <PressableOpacity onPress={handlePress}>
          <VStack spacingHorizontal={3}>
            {isBoosted && !allTasksCompleted && (
              <HStack
                testID="mixedCampaignCard_boostedBadge"
                position="absolute"
                alignItems="center"
                background="background"
                borderRadius="roundedXLarge"
                left={spacing[4]}
                top={spacing[1]}
                spacingVertical={1}
                spacingHorizontal={1.5}
                zIndex={1}
                gap={2}
              >
                <Icon name="giftBox" size="s" color="primary" />
                <TextHeadline color="primary">
                  {formatMessage(messages.boostedBadge)}
                </TextHeadline>
              </HStack>
            )}
            <RemoteImage
              testID="mixedCampaignCard_image"
              source={{ uri: imageUrl }}
              height={140}
              width="100%"
              resizeMode="cover"
              style={styles.borderRadiusRedesign}
            />
            {allTasksCompleted && (
              <HStack
                spacingVertical={1}
                spacingHorizontal={2}
                background="background"
                gap={1}
                borderRadius="roundedXLarge"
                position="absolute"
                alignItems="center"
                top={8}
                left={32}
              >
                <Icon name="checkmark" size="s" color="positive" />
                <TextHeadline color="positive">
                  {formatMessage(messages.completedLabel)}
                </TextHeadline>
              </HStack>
            )}
            <VStack gap={1} spacingTop={2}>
              {!!tag && (
                <HStack>
                  <Tag colorScheme="blue">{tag}</Tag>
                </HStack>
              )}
              {renderProgressBar()}
