        cardName
        imageUrl
        iconUrl
        header
        body
        duration
        reward
        title
        tasks {
          isIDVRestricted
          type
          url
          isComplete
          isLocked
          imageUrl
        }
        upsell {
          isBoosted
        }
      }
    `,
    loyaltyCardRef,
  );

  const {
    cardName,
