import { memo, useCallback } from 'react';
import { Pressable } from 'react-native';
import { GestureHandlerRootView } from 'react-native-gesture-handler';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { useResolvedNotificationExperiment } from '@cbhq/comms-platform-core/notifications-framework';
import { graphql, useFragment } from '@cbhq/data-layer';

import { ChartHeader } from '@designSystem/core/chart';
import { ChartProvider } from '@designSystem/core/chart/ChartProvider';

import { useNativeCurrencyFormatter } from '@app/hooks/formatters/useNativeCurrencyFormatter';
import { useAssetsFinancialPromotionsUk } from '@app/hooks/useAssetsFinancialPromotionsUk';
import { useChart } from '@app/hooks/useChart';
import { AssetPriceChart } from '@app/screens/Asset/components/AssetPriceChart';
import { useAssetChartHeaderPropsDeprecated } from '@app/screens/Asset/hooks/useAssetChartHeaderPropsDeprecated';

import { NotificationAssetChartFragment$key } from './__generated__/NotificationAssetChartFragment.graphql';
import { NotificationWatchListStar } from './NotificationWatchListStar';

type NotificationAssetChartProps = {
  queryRef: NotificationAssetChartFragment$key;
  onScrubStart?: () => void;
  onScrubEnd?: () => void;
};

export const NotificationAssetChart = memo(
  ({ queryRef, onScrubStart, onScrubEnd }: NotificationAssetChartProps) => {
    const query = useFragment(
      graphql`
        fragment NotificationAssetChartFragment on Query {
          ...NotificationWatchListStarFragment
            @arguments(
              watchlistItemFilter: $watchlistItemFilter
              skipWatchlistStar: $skipTradeTray
            )
          viewer @skip(if: $skipTradeTray) {
            assetByUuid(uuid: $assetUuid) {
              asset @required(action: THROW) {
                ...AssetPriceChartFragment
                ...useChartFragment
                name
                uuid
                latestPrice(quoteCurrency: $nativeCurrency) {
                  price
                  percentChanges {
                    day
                  }
                }
              }
            }
          }
        }
      `,
      queryRef,
    );

    const asset = query?.viewer?.assetByUuid?.asset;
    const assetUuid = asset?.uuid;

    const chartHeaderProps = useAssetChartHeaderPropsDeprecated(
      asset?.name,
      asset?.latestPrice?.price,
      asset?.latestPrice?.percentChanges?.day,
    );
    const formatAmount = useNativeCurrencyFormatter();

    const {
      isScrubbing,
      chartHeaderRef,
      chartNavBarRef,
      activePeriod,
      onScrubStart: defaultOnScrubStart,
      onScrubEnd: defaultOnScrubEnd,
      ...chartProps
    } = useChart({
      defaultLabel: chartHeaderProps.defaultLabel,
      defaultTitle: chartHeaderProps.defaultTitle,
      assetRef: asset,
      formatAmount,
    });

    const handleScrubStart = useCallback(() => {
      defaultOnScrubStart();
      onScrubStart?.();
    }, [defaultOnScrubStart, onScrubStart]);

    const handleScrubEnd = useCallback(() => {
      defaultOnScrubEnd();
      onScrubEnd?.();
    }, [defaultOnScrubEnd, onScrubEnd]);

    const isUkFinancialPromotionsEnabled = useAssetsFinancialPromotionsUk();

    const addToWatchlistExperiment = useResolvedNotificationExperiment();

    return (
      <ChartProvider compact>
        <HStack spacingBottom={1}>
          <Box maxWidth="92%">
            <ChartHeader
              ref={chartHeaderRef}
              defaultTitle={chartHeaderProps.defaultTitle}
              defaultSubHead={chartHeaderProps.defaultSubHead}
              defaultLabel=""
            />
          </Box>
          <Box>
            {addToWatchlistExperiment && !!assetUuid && (
              <NotificationWatchListStar
                assetId={assetUuid}
                assetName={asset?.name}
                queryRef={query}
                showOnTopOfTray
              />
            )}
          </Box>
        </HStack>
        <Box offsetHorizontal={3}>
          {!!asset && (
            // required for scrub gestures to work on android
            // https://github.com/software-mansion/react-native-gesture-handler/issues/139#issuecomment-790329701
            <GestureHandlerRootView>
              <Pressable accessibilityRole="button" onPress={handleScrubStart}>
                <AssetPriceChart
                  assetRef={asset}
                  {...chartProps}
                  onScrubStart={handleScrubStart}
                  onScrubEnd={handleScrubEnd}
                  chartPeriod={isUkFinancialPromotionsEnabled ? 'all' : 'day'}
                />
              </Pressable>
            </GestureHandlerRootView>
          )}
        </Box>
      </ChartProvider>
    );
  },
);

