type ConfirmNumberProps = {
  phoneNumber: string;
  bordered?: boolean;
  compact?: boolean;
  toggleBancomatPayActivated?: () => void;
  isBancomatPayActivated?: boolean;
  toggleConfirmBody?: () => void;
  isConfirmBody?: boolean;
} & SpacingProps &
  OffsetProps;

export const updateNumberHelpCenter = `https://help.coinbase.com/${locale}/contact-us/support-faq/coinbase/how-to-request-a-phone-number-change`;
export const bancomatUrl = 'https://bancomat.it/it/bancomat/bancomat-pay%C2%AE';

export function ConfirmNumber({
  phoneNumber,
  toggleBancomatPayActivated,
  isBancomatPayActivated,
  toggleConfirmBody,
  isConfirmBody,
  bordered,
  compact,
  ...props
}: ConfirmNumberProps) {
  const { formatMessage } = useIntl();

  const handleChangeForBancomatPayActivated = useCallback(() => {
    toggleBancomatPayActivated?.();
  }, [toggleBancomatPayActivated]);

  const handleChangeForConfirmBody = useCallback(() => {
    toggleConfirmBody?.();
  }, [toggleConfirmBody]);

  const handleUpdateNumber = useCallback(() => {
    logEvent('bancomat_deposit', {
      action: ActionType.click,
      componentType: ComponentType.button,
      state: 'update_number',
    });
    Linking.openURL(updateNumberHelpCenter);
  }, []);

  const handleActivateBancomat = useCallback(() => {
    logEvent('bancomat_deposit', {
      action: ActionType.click,
      componentType: ComponentType.button,
      state: 'activate_bancomat',
    });
    Linking.openURL(bancomatUrl);
  }, []);
  return compact ? (
    <HStack
      {...props}
      gap={compact ? 1 : 2}
      alignItems={compact ? 'flex-start' : 'center'}
      bordered={!!bordered}
      borderRadius="roundedMedium"
    >
      <Box spacingTop={0.5}>
        <BancomatIcon size={compact ? 'm' : 'l'} />
      </Box>
      <TextBody color="foregroundMuted">
        {formatMessage(messages.confirmNumber, {
          phone: (
            <TextHeadline color="foregroundMuted">{phoneNumber}</TextHeadline>
          ),
          link: (
            <Link to={updateNumberHelpCenter} underline>
              {formatMessage(messages.followInstructions)}
            </Link>
          ),
          break: '\n',
        })}
      </TextBody>
    </HStack>
  ) : (
    <VStack {...props}>
      <HStack gap={1} spacingTop={3} spacingEnd={6}>
        {toggleBancomatPayActivated ? (
          <Switch
            onChange={handleChangeForBancomatPayActivated}
            checked={isBancomatPayActivated}
          />
        ) : (
          <>
            <Icon
              spacingTop={0.5}
              name="checkmark"
              size="s"
              color="foreground"
            />
            <TextBody color="foregroundMuted">...</TextBody>
          </>
        )}

        <TextBody color="foreground">
          {formatMessage(messages.bancomatPayActivated, {
            instruction: (
              <Link onPress={handleActivateBancomat} underline>
                {formatMessage(messages.updateLink)}
              </Link>
            ),
          })}
        </TextBody>
      </HStack>
      <HStack gap={1} spacingTop={3} spacingEnd={6}>
        {toggleConfirmBody ? (
          <Switch
            onChange={handleChangeForConfirmBody}
            checked={isConfirmBody}
          />
        ) : (
          <>
            <Icon
              spacingTop={0.5}
              name="checkmark"
              size="s"
              color="foreground"
            />
            <TextBody color="foregroundMuted">...</TextBody>
          </>
        )}
        <TextBody color="foreground">
          {formatMessage(messages.confirmBody, {
            link: (
              <Link onPress={handleUpdateNumber} underline>
                {formatMessage(messages.updateLink)}
              </Link>
            ),
            break: '\n',
            phone: <TextHeadline>{phoneNumber}</TextHeadline>,
          })}
        </TextBody>
      </HStack>
    </VStack>
  );
}

