const emptyObject = {};

type PinLockModalContentProps = {
  pinAttempts: number;
  isLocked: boolean;
  pinValue: string;
  setPinValue: Dispatch<SetStateAction<string>>;
  pinUnlockCallback: MutableRefObject<(() => void) | null>;
  pinCancelLock: () => void;
  handleUpdate: (input: NumpadValue) => void;
  isBiometric: boolean;
  isColdBoot: MutableRefObject<boolean>;
};

type AnimationType = 'none' | 'slide' | 'fade' | undefined;

const i18nKey = 'PinCodeInput';
const messages = defineMessages({
  signOutTrayTitle: {
    id: `${i18nKey}.signOutTrayTitle`,
    defaultMessage: 'Forgot your PIN?',
    description: 'modal title',
  },
  signOutTrayMessage: {
    id: `${i18nKey}.signOutTrayMessage`,
    defaultMessage:
      'You can sign out and sign back in again with your credentials.',
    description: 'modal subtitle',
  },
  signOutTrayPositiveButton: {
    id: `${i18nKey}.signOutTrayPositiveButton`,
    defaultMessage: 'Sign out',
    description: 'modal button',
  },
  signOutTrayNegativeButton: {
    id: `${i18nKey}.signOutTrayNegativeButton`,
    defaultMessage: 'Cancel',
    description: 'modal button',
  },
  pinNoAttempt: {
    id: `${i18nKey}.pinNoAttempt`,
    defaultMessage: 'Unlock with your PIN',
    description: 'Pin input label initial state',
  },
  pinAttempt: {
    id: `${i18nKey}.pinAttempt`,
    defaultMessage:
      '{attempt} {attempt, plural, one {attempt} other {attempts}} remaining',
    description: 'Pin input label after incorrect attempt',
  },
});

function PinLockModal() {
  const { pinAttempts, isLocked, pinValue, setPinValue } = usePinLock();
  const {
    pinUnlockCallback,
    pinCancelLock,
    pinSettings: { isBiometric },
    isColdBoot,
    updatePinAttempts,
    pinUnlock,
  } = useContext(PinContext);
  const { handleUpdate } = usePinPad({ pin: pinValue, setPin: setPinValue });

  const handleBiometricPromptSuccess = useCallback(() => {
    pinUnlock();
    if (pinAttempts > 0) {
      updatePinAttempts(0);
    }
  }, [pinAttempts, pinUnlock, updatePinAttempts]);

  // Renders biometric prompt if biometrics is available and enabled
  const showBiometricPrompt = useBiometricPrompt({
    handleBiometricPromptSuccess,
  });

  useEffect(() => {
    if (isBiometric) {
      void showBiometricPrompt();
    }
  }, [showBiometricPrompt, isBiometric]);

  return (
    <PinLockModalContent
      pinAttempts={pinAttempts}
      isLocked={isLocked}
      pinValue={pinValue}
      setPinValue={setPinValue}
      pinUnlockCallback={pinUnlockCallback}
      pinCancelLock={pinCancelLock}
      handleUpdate={handleUpdate}
      isBiometric={isBiometric}
      isColdBoot={isColdBoot}
    />
  );
}

const PinLockModalContent = memo<PinLockModalContentProps>(
  ({
    pinAttempts,
    isLocked,
    pinValue,
    pinUnlockCallback,
    pinCancelLock,
    handleUpdate,
    isBiometric,
    isColdBoot,
  }) => {
    const spacing = useSpacingScale();
    const updateNavBar = useAndroidNavigationBarUpdater();
    const [signOutTray, setSignOutTray] = useState(false);
    const canDismiss = pinUnlockCallback?.current;

    const { formatMessage } = useIntl();
    const getElapsedTime = useTrackElapsedTime();
    useScreenProtectOnMount();

    useEffect(() => {
      // not using useTrackViewEffectNotValid because
      // this modal lives outside of a navigation context
      // and can't useFocusEffect

      (async function () {
        const state = await hasBiometricHardware();
        Analytics.track(pinAnalyticsEvents.PIN_PROMPT_VIEWED, {
          action: ActionType.process, // unlock
          context: 'Pin',
          biometric_state: state && isBiometric ? 'enabled' : 'disabled',
        });
      })();
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const labelText = useMemo(() => {
      if (pinAttempts === 0) {
        return formatMessage(messages.pinNoAttempt);
      }
      return formatMessage(messages.pinAttempt, {
        attempt: MAX_ATTEMPTS - pinAttempts,
      });
    }, [pinAttempts, formatMessage]);

    const handleDismiss = useCallback(() => {
      Analytics.track(pinAnalyticsEvents.PIN_PROMPT_DISMISSED, {
        context: 'Pin',
        action: ActionType.process, // unlock
        time_to_dismiss: getElapsedTime(),
        state: 'cancel',
      });
      pinCancelLock();
    }, [pinCancelLock, getElapsedTime]);

    useEffect(() => {
      updateNavBar();
    }, [updateNavBar]);

    const handleRequestClose = useCallback(() => {
      if (canDismiss) {
        handleDismiss();
      } else {
        BackHandler.exitApp();
      }
    }, [canDismiss, handleDismiss]);

    // We show Modal if shown anywhere within app such as send flow,
    // or when foregrounding the app, otherwise we use an absolutely positioned view
    // to avoid layout jank caused by "Theme.FullScreenDialog" on Android when
    // launching Modal on cold boot
    const Wrapper = isColdBoot.current ? Fragment : Modal;
    const wrapperProps = useMemo(
      () =>
        isColdBoot.current
          ? emptyObject
          : {
              visible: isLocked,
              animationType: (canDismiss ? 'slide' : 'none') as AnimationType,
              transparent: true,
              hardwareAccelerated: true,
              onRequestClose: handleRequestClose,
            },
      [isColdBoot, canDismiss, isLocked, handleRequestClose],
    );

    // On iOS the modal will be fullscreen, overlapping with the StatusBar
    const safeAreaInsets = useSafeAreaInsets();
    const topNotch = device.isAndroid ? 0 : safeAreaInsets.top - spacing[2]; // safeArea - parent's top spacing

    const signOut = useSignOut();

    return (
      <Wrapper {...wrapperProps}>
        <VStack background spacing={2} style={styles.wrapper}>
          <VStack spacing={2} flexGrow={1} justifyContent="center">
            {!!canDismiss && (
              <Box pin="top" top={topNotch} spacingTop={3}>
                <IconButton transparent name="close" onPress={handleDismiss} />
              </Box>
            )}
            <HStack spacing={0}>
              <PinCodeInput label={labelText} value={pinValue} />
            </HStack>
            <Box offsetTop={1}>
              <TextHeadline
                align="center"
                spacingBottom={3}
                color="primary"
                onPress={() => setSignOutTray(true)}
              >
                {pinAttempts > 0
                  ? formatMessage(messages.signOutTrayTitle)
                  : ''}
              </TextHeadline>
            </Box>
          </VStack>
          <NumPad
            onPress={handleUpdate}
            separator=""
            spacingVertical={2}
            spacingHorizontal={0}
          />
          <SignOutTray
            alertData={{
              title: formatMessage(messages.signOutTrayTitle),
              message: formatMessage(messages.signOutTrayMessage),
              positiveButton: {
                text: formatMessage(messages.signOutTrayPositiveButton),
                onPress: () =>
                  signOut({
                    analyticsMessage: 'Pin lock modal sign out',
                  }),
              },
              negativeButton: {
                text: formatMessage(messages.signOutTrayNegativeButton),
              },
            }}
            isVisible={signOutTray}
            onDismiss={() => setSignOutTray(false)}
          />
        </VStack>
      </Wrapper>
    );
  },
);

const styles = StyleSheet.create({
  wrapper: {
    ...StyleSheet.absoluteFillObject,
    zIndex: elevation.layer2,
  },
});

export { PinLockModal };

