import { NetworkBoundary } from '@app/components/NetworkBoundary';
import { useNativeCurrency } from '@app/hooks/useNativeCurrency';
import { usePortfolioChartData } from '@app/screens/Portfolio/hooks/usePortfolioChartData';
import { ChartPeriod } from '@app/types/Chart';

import { PortfolioChartMinimizedQuery } from './__generated__/PortfolioChartMinimizedQuery.graphql';

type PortfolioChartMinimizedProps = {
  activePeriod: ChartPeriod;
  minimized?: boolean;
  setMinimized?: (minimized: boolean) => () => void;
};

const PortfolioChartMinimizedComponent = memo(
  ({ activePeriod, minimized, setMinimized }: PortfolioChartMinimizedProps) => {
    const palette = usePalette();
    const nativeCurrency = useNativeCurrency();

    const { viewer } = useLazyLoadQuery<PortfolioChartMinimizedQuery>(
      graphql`
        query PortfolioChartMinimizedQuery($nativeCurrency: TickerSymbol!) {
          viewer @required(action: THROW) {
            userBalanceChart(currency: $nativeCurrency) {
              balanceChart {
                ...usePortfolioChartDataFragment
              }
            }
          }
        }
      `,
      {
        nativeCurrency,
      },
    );

    const data = usePortfolioChartData(
      viewer?.userBalanceChart?.balanceChart ?? null,
    );

    const dataForPeriod = useMemo(() => {
      if (!data) {
        return [];
      }

      return data[activePeriod] ?? [];
    }, [data, activePeriod]);

    const sparklinePath = useSparklinePath({
      data: dataForPeriod.map((dataPoint) => dataPoint.value),
      width: 90,
      height: 40,
    });

    const handlePressMiniChart = useCallback(() => {
      setMinimized?.(!minimized);
    }, [minimized, setMinimized]);

    return (
      <Pressable
        accessibilityRole="button"
        background="transparent"
        onPress={handlePressMiniChart}
      >
        <PortfolioChartFadeAnimation minimized={minimized}>
          <Box
            width={100}
            height={55}
            justifyContent="center"
            alignItems="center"
          >
            <Sparkline
              testID="HomeChartHeaderSparkline"
              path={sparklinePath}
              color={palette.primary}
              width={90}
              height={40}
            />
          </Box>
        </PortfolioChartFadeAnimation>
      </Pressable>
    );
  },
);

type PortfolioChartFadeAnimationProps = {
  minimized?: boolean;
  children: JSX.Element;
};

function PortfolioChartFadeAnimation({
  minimized,
  children,
}: PortfolioChartFadeAnimationProps) {
  const fadeAnim = useSharedValue(minimized ? 1 : 0);

  useEffect(() => {
    fadeAnim.value = minimized ? 1 : 0;
  }, [fadeAnim, minimized]);

  const animatedStyle = useAnimatedStyle(() => {
    return {
      opacity: withSpring(fadeAnim.value, {
        damping: 20,
        stiffness: 200,
      }),
    };
  });

  return <Animated.View style={animatedStyle}>{children}</Animated.View>;
}

export const PortfolioChartMinimized = memo<PortfolioChartMinimizedProps>(
  (props) => {
    return (
      <NetworkBoundary
        errorFallback={null}
        suspenseFallback={null}
        instrumentationId="PortfolioChartMinimized"
      >
        <PortfolioChartMinimizedComponent {...props} />
      </NetworkBoundary>
    );
  },
);

