import { memo, useCallback, useEffect, useMemo, useRef } from 'react';
import { Box, VStack } from '@cbhq/cds-mobile/layout';

import { IconButton } from '@components/interactables/IconButton';
import { Screen } from '@app/components/Screen';
import { ScreenBoundary } from '@app/components/ScreenBoundary/ScreenBoundary';
import { Spinner } from '@app/components/Spinner';
import { Push2FAModalStatus } from '@app/contexts/Push2FAContext';
import { useStackNavigation } from '@app/hooks/navigation/useStackNavigation';
import { usePush2FAContext } from '@app/hooks/push2FA/usePush2FAContext';
import { logPushStatusUpdate } from '@app/screens/Push2FA/Analytics';

import { BlockedContent } from './components/BlockedContent';
import { CanceledContent } from './components/CanceledContent';
import { ExpiredContent } from './components/ExpiredContent';
import { StartedContent } from './components/StartedContent';

const Push2FALoader = memo(() => {
  return (
    <Box
      justifyContent="center"
      alignItems="center"
      position="absolute"
      width="100%"
      height="100%"
      top={0}
      left={0}
      zIndex={10}
      background="transparent"
    >
      <Spinner size="large" />
    </Box>
  );
});

const Push2FAScreen = memo(() => {
  const { goBack } = useStackNavigation();
  const modalDismissedRef = useRef(false);
  const { notification, status, isLoading, setStatus, resetNotification } =
    usePush2FAContext();

  const { clientAction = 'unknown' } = notification || {};

  useEffect(() => {
    // don't call goBack if handleModalDismiss has already been called
    if (status === Push2FAModalStatus.idle && !modalDismissedRef.current) {
      goBack();
    }
  }, [goBack, status]);

  const handleModalDismiss = useCallback(() => {
    goBack();
    modalDismissedRef.current = true;
    setStatus(Push2FAModalStatus.idle);
    resetNotification();
  }, [goBack, setStatus, resetNotification]);

  const modalContent = useMemo(() => {
    if (status) {
      logPushStatusUpdate(status, clientAction);
    }
    switch (status) {
      case Push2FAModalStatus.started:
        return <StartedContent handleModalDismiss={handleModalDismiss} />;
      case Push2FAModalStatus.blocked:
        return <BlockedContent handleModalDismiss={handleModalDismiss} />;
      case Push2FAModalStatus.expired:
        return <ExpiredContent />;
      case Push2FAModalStatus.canceled:
        return <CanceledContent handleModalDismiss={handleModalDismiss} />;
      default:
        return null;
    }
  }, [status, clientAction, handleModalDismiss]);

  return (
    <ScreenBoundary instrumentationId="Push2FAScreen">
      {!!modalContent && (
        <Screen
          testID="push2fa-screen-container"
          navHeader={{
            // To avoid rendering leading action button and to avoid `Warning: Functions are not valid as a React child` in testing
            // eslint-disable-next-line react/jsx-no-useless-fragment
            leading: <></>,
            // eslint-disable-next-line react/no-unstable-nested-components
            trailing: () => (
              <IconButton
                name="close"
                transparent
                onPress={handleModalDismiss}
              />
            ),
          }}
        >
          <VStack height="100%" width="100%" position="relative">
            {isLoading && <Push2FALoader />}
            {modalContent}
          </VStack>
        </Screen>
      )}
    </ScreenBoundary>
  );
});

export { Push2FAScreen };

