type LightningAmountEntryScreenContentProps = {
  accountRef: LightningAmountEntryScreenQuery$data['viewer']['defaultAccountForFlow'];
  p2PConfigRef: useComputeMinMaxAmountFragment$key | null;
  accountId?: string;
};

const LIGHTNING_ARN_FALLBACK = 'networks/lightning-mainnet';

const LightningAmountEntryScreenContent = memo(
  function LightningAmountEntryScreenContent({
    accountRef,
    p2PConfigRef,
    accountId,
  }: LightningAmountEntryScreenContentProps) {
    const nativeCurrency = useNativeCurrency();
    const formatCurrency = useCurrencyFormatter();
    const fiatCurrency = useFiatCurrencyStub({
      nativeCurrency,
    });

    const [loading, setLoading] = useState(false);

    const { logGenericSendReceiveFlowEvent } = useSendReceiveLoggers();
    const hasReceiveRedesign = useHasReceiveRedesignSupport();

    useLogEventOnMount('lightning_amount_entry_viewed', {
      componentType: ComponentType.page,
      action: ActionType.render,
    });

    const toast = useToast();
    const { navigate, goBack } = useStackNavigation();
    const { formatMessage } = useIntl();

    const { createP2PInvoice, setInvoice } = useLightningInvoiceContext();

    const [
      isLightningInfoTrayVisible,
      { toggleOn: showLightningInfoTray, toggleOff: dismissLightningInfoTray },
    ] = useToggler(false);

    const { amountFiatField, preferredCurrency, noteField } = useFields(Form);

    useEffect(() => {
      if (preferredCurrency.value.type === 'fiat') {
        preferredCurrency.onChange(fiatCurrency);
      }
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    if (!accountRef) {
      const error = new Error(
        'LightningAmountEntryScreenContent: invalid account',
      );
      errorVitals.logError(error, {
        context: 'lighting_amount_entry_screen_invalid_account',
        severity: 'error',
        isHandled: false,
      });

      throw error;
    }

    const currency = useAssetOrCurrencyGraphQL(accountRef.assetOrFiatCurrency);

    const viewerAsset =
      useFragment<LightningAmountEntryScreenContentFragment$key>(
        graphql`
          fragment LightningAmountEntryScreenContentFragment on ViewerAsset {
            supportedNetworks(action: RECEIVE, applicationContext: CONSUMER) {
              supportedNetworks {
                arn
              }
            }
          }
        `,
        accountRef.assetOrFiatCurrency ?? null,
      );

    const convert = useCurrencyConverter(fiatCurrency.code);
    const cryptoAmount = useMemo(
      () =>
        convert(
          {
            amount: amountFiatField.value || '0',
            currency: fiatCurrency.code,
          },
          currency?.code,
        ).toString(),
      [amountFiatField.value, convert, currency?.code, fiatCurrency.code],
    );

    const {
      primaryAmount,
      secondaryAmount,
      inputCurrency,
      setAmount,
      setInputCurrency,
    } = useAmountEntryState({
      cryptoAmount: cryptoAmount || '0',
      currency,
      defaultInputCurrency: fiatCurrency,
      fiatAmount: amountFiatField.value || '0',
    });

    const formattedSecondaryAmount = formatInputAmount({
      locale: app.locale,
      amount: secondaryAmount,
      currency: inputCurrency.secondary,
      trailingCode: true,
    });

    // clean up input and context when screen mounts
    useEffect(() => {
      setAmount('0');
      amountFiatField.onChange('0');
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const handleNumpadInput = useCallback(
      (amount: string, isValid: boolean) => {
        if (isValid) {
          setAmount(amount);
          amountFiatField.onChange(amount);
        }
      },
      [amountFiatField, setAmount],
    );

    const onCreateP2PInvoiceSuccess = useCallback(
      (response: CreateP2PInvoiceSuccessResponse) => {
        setLoading(false);
        setInvoice(response.p2pInvoice);

        toast.show(formatMessage(messages.invoiceCreated));

        if (hasReceiveRedesign) {
          markJourney('navigate_to_receive_v2');

          if (accountId) {
            navigate('ReceiveRedesign', {
              accountId,
              networkSlug: response.p2pInvoice?.network ?? '',
              isDefaultNetwork: false,
              showNetworkToast: true,
            });
          }

          return;
        }

        markJourney('navigate_to_receive');
        navigate('Receive', {
          accountId,
          canChangeAccount: true,
          // TODO: use the provider for a temporary solution until we have lightning network available
          // network: 'btc-lightning',
        });
      },
      [
        navigate,
        setLoading,
        formatMessage,
        accountId,
        toast,
        setInvoice,
        hasReceiveRedesign,
      ],
    );

    const onCreateP2PInvoiceError = useCallback(
      (error?: CreateP2PInvoiceErrorResponse) => {
        setLoading(false);
        toast.show(
          error?.description ?? formatMessage(messages.invoiceCreationFailed),
        );
      },
      [setLoading, toast, formatMessage],
    );

    const handleCreateInvoice = useCallback(() => {
      setLoading(true);

      const lightningArn =
        viewerAsset?.supportedNetworks?.supportedNetworks?.[1]?.arn;

      const isPrimaryFiat = inputCurrency.primary.type === 'fiat';

      const amountFiat = isPrimaryFiat
        ? {
            currency: fiatCurrency.code,
            value: primaryAmount,
          }
        : undefined;

      const amountCrypto = isPrimaryFiat
        ? undefined
        : {
            currency: currency?.code ?? '',
            value: primaryAmount,
          };

      createP2PInvoice({
        input: {
          accountUuid: accountId ?? '',
          networkArn: lightningArn ?? LIGHTNING_ARN_FALLBACK,
          invoiceInputDetails: {
            lightningInvoiceInputDetails: {
              amountCrypto,
              amountFiat,
              memo: noteField.value || '',
              type: 'LIGHTNING_INVOICE_TYPE_FIXED_AMOUNT',
            },
          },
        },
        onSuccess: onCreateP2PInvoiceSuccess,
        onError: onCreateP2PInvoiceError,
      });

      logGenericSendReceiveFlowEvent('receive_modal_button', {
        componentType: ComponentType.button,
        action: ActionType.click,
        flow: 'invoice_creation',
        step: 'create_lightning_invoice',
        componentName: 'create_invoice',
      });
    }, [
      setLoading,
      createP2PInvoice,
      accountId,
      onCreateP2PInvoiceSuccess,
      onCreateP2PInvoiceError,
      noteField.value,
      fiatCurrency.code,
      currency?.code,
      viewerAsset?.supportedNetworks?.supportedNetworks,
      inputCurrency.primary.type,
      primaryAmount,
      logGenericSendReceiveFlowEvent,
    ]);

    // useCallback blocks the state update since previous state isn't ready yet
    // we want to use previous state to ensure the swap is safe
    // eslint-disable-next-line react-hooks/exhaustive-deps
    const swapInputCurrencies = () => {
      setInputCurrency(({ primary, secondary }) => {
        preferredCurrency.onChange(secondary);
        return {
          primary: secondary,
          secondary: primary,
        };
      });
    };

    const swapInputCurrencyType = useMemo(() => {
      return (
        <HStack alignItems="center" gap={1} spacingBottom={1}>
          <Pressable
            onPress={swapInputCurrencies}
            accessibilityRole="button"
            background="transparent"
            hitSlop={20}
          >
            <HStack alignItems="center" gap={0.5}>
              <Icon color="primary" name="arrowsVertical" size="xs" />
              <LiveTicker
                value={
                  inputCurrency.primary.type === 'crypto'
                    ? `${formattedSecondaryAmount} ${inputCurrency.secondary.code}`
                    : `${formattedSecondaryAmount}`
                }
                variant="label1"
                color="primary"
              />
            </HStack>
          </Pressable>
        </HStack>
      );
    }, [
      formattedSecondaryAmount,
      inputCurrency.primary.type,
      inputCurrency.secondary.code,
      swapInputCurrencies,
    ]);

    const header = useMemo(() => {
      return (
        <VStack alignItems="center">
          <TextHeadline>{formatMessage(messages.title)}</TextHeadline>
          <HStack alignItems="center" gap={0.5}>
            <TextBody color="foregroundMuted">
              {formatMessage(messages.subtitle)}
            </TextBody>
            <PressableOpacity onPress={showLightningInfoTray} hitSlop={8}>
              <Icon name="info" color="foregroundMuted" size="s" />
            </PressableOpacity>
          </HStack>
        </VStack>
      );
    }, [formatMessage, showLightningInfoTray]);

    const { maxAmountLimitNativeCurrency, minAmountLimitNativeCurrency } =
      useComputeMinMaxAmount({
        p2PConfigRef,
      });

    const minMaxWarningMessage = useMemo(() => {
      const isPrimaryFiat = inputCurrency.primary.type === 'fiat';

      const fiatInputAmount = isPrimaryFiat ? primaryAmount : secondaryAmount;

      if (Number(fiatInputAmount) === 0) {
        return undefined;
      }

      if (Number(fiatInputAmount) > maxAmountLimitNativeCurrency) {
        return {
          amount: maxAmountLimitNativeCurrency,
          message: formatMessage(messages.maxAmountWarning, {
            amount: formatCurrency({
              amount: maxAmountLimitNativeCurrency,
              currency: {
                code: fiatCurrency.code,
                type: 'fiat',
              },
              isSensitive: true,
            }),
          }),
        };
      }

      if (Number(fiatInputAmount) < minAmountLimitNativeCurrency) {
        return {
          amount: minAmountLimitNativeCurrency,
          message: formatMessage(messages.minAmountWarning, {
            amount: formatCurrency({
              amount: minAmountLimitNativeCurrency,
              currency: {
                code: fiatCurrency.code,
                type: 'fiat',
              },
              isSensitive: true,
            }),
          }),
        };
      }

      return undefined;
    }, [
      maxAmountLimitNativeCurrency,
      minAmountLimitNativeCurrency,
      formatMessage,
      inputCurrency.primary.type,
      primaryAmount,
      secondaryAmount,
      fiatCurrency.code,
      formatCurrency,
    ]);

    const isSubmittable = useMemo(
      () => Number(primaryAmount) > 0 && !minMaxWarningMessage,
      [primaryAmount, minMaxWarningMessage],
    );

    return (
      <Screen
        testID="LightningAmountEntryScreen"
        navHeader={{
          action: 'back',
          title: header,
          backHandler: goBack,
        }}
      >
        <TransactionInputAmount
          variant="jumbo"
          amount={primaryAmount}
          invalidAt={undefined}
          currency={inputCurrency.primary}
          numericOnly={inputCurrency.primary.type === 'crypto'}
          subtitle={swapInputCurrencyType}
          isSimpleTradeRedesign
          isSendFlow
          minimumDeposit={minMaxWarningMessage}
        />
        <HStack alignItems="center" gap={2}>
          <NotesButton entryPoint="btc-lightning" />
        </HStack>
        <InputAmountNumPad
          allowEmptyInput={false}
          onUpdate={handleNumpadInput}
          value={primaryAmount}
          exponent={inputCurrency.primary.exponent}
          currencyCode={inputCurrency.primary.code}
        />
        <Button
          testID="SubmitButton"
          disabled={!isSubmittable || loading}
          onPress={handleCreateInvoice}
          loading={loading}
        >
          {formatMessage(messages.createInvoice)}
        </Button>
        <LightningInfoTray
          isVisible={isLightningInfoTrayVisible}
          dismissTray={dismissLightningInfoTray}
        />
      </Screen>
    );
  },
);

export const LightningAmountEntryScreen = memo(
  function LightningAmountEntryScreenContainer() {
    const { accountId } = useParams<'LightningAmountEntryScreen'>();

    const { viewer } = useLazyLoadQuery<LightningAmountEntryScreenQuery>(
      graphql`
        query LightningAmountEntryScreenQuery(
          $hasDefaultAccountFeatureFlag: Boolean!
          $accountId: Uuid!
          $hasAccountId: Boolean!
        ) {
          viewer @required(action: THROW) {
            p2pConfig {
              ...useComputeMinMaxAmountFragment
            }
            defaultAccountForFlow(
              flow: RECEIVE
              featureFlagEnabled: $hasDefaultAccountFeatureFlag
            ) @skip(if: $hasAccountId) {
              assetOrFiatCurrency {
                ... on ViewerAsset {
                  ...LightningAmountEntryScreenContentFragment
                }
                ...useAssetOrCurrencyGraphQLFragment
              }
            }
            accountByUuid(uuid: $accountId) @include(if: $hasAccountId) {
              assetOrFiatCurrency {
                ... on ViewerAsset {
                  ...LightningAmountEntryScreenContentFragment
                }
                ...useAssetOrCurrencyGraphQLFragment
              }
            }
          }
        }
      `,
      {
        hasDefaultAccountFeatureFlag: false,
        accountId: accountId ?? '',
        hasAccountId: !!accountId,
      },
    );

    const account =
      viewer.defaultAccountForFlow ?? viewer.accountByUuid ?? null;

    return (
      <ScreenBoundary
        fallback={<AmountEntryScreenFallback />}
        instrumentationId="LightningAmountEntryScreen"
      >
        <LightningAmountEntryScreenContent
          accountRef={account}
          p2PConfigRef={viewer.p2pConfig}
          accountId={accountId}
        />
      </ScreenBoundary>
    );
  },
);

