type ReceiveContentProps = {
  accountId?: string;
  accountRef: ReceiveScreenContentAccountFragment$key | null;
  headerAction?: HeaderAction;
  isVault: boolean;
  cryptoRequestEligibilityRef: useCryptoRequestsEligibilityFragment$key | null;
  queryRef: ReceiveScreenQuery$data;
};

const ReceiveContent = memo<ReceiveContentProps>(
  ({
    accountId,
    accountRef,
    queryRef,
    isVault,
    cryptoRequestEligibilityRef,
  }) => {
    const {
      logReceiveModalRenderEvent,
      logReceiveFlowButtonPress,
      logAddressRegenerationBannerViewEvent,
      logInvoiceRegenerationBanner,
    } = useSendReceiveLoggers();
    const { formatMessage } = useIntl();
    const toast = useToast();
    const { amountFiatField, noteField } = useFields(Form);
    const { invoice, setInvoice } = useLightningInvoiceContext();

    const [fetchingNewAddress, setFetchingNewAddress] = useState(false);

    const hasCryptoRequests = useHasCryptoRequests();
    const isCryptoRequestsEligible = useCryptoRequestsEligibility(
      cryptoRequestEligibilityRef,
    );

    const [account, refetchAddress] = useRefetchableFragment(
      graphql`
        fragment ReceiveScreenContentAccountFragment on Account
        @refetchable(queryName: "ReceiveScreenContentAccountRefetchableQuery")
        @argumentDefinitions(
          network: { type: "String" }
          forceRegeneration: { type: "Boolean" }
        ) {
          ...AddressLabelsWithErrorFallbackFragment
            @arguments(network: $network, forceRegeneration: $forceRegeneration)
          ...QRCodeComponentFragment
            @arguments(network: $network, forceRegeneration: $forceRegeneration)
          ...NetworkSelectionFlowFragment
          assetOrFiatCurrency {
            ... on ViewerAsset {
              asset {
                ...useShareReceiveAddressFragment
                name
                platformName
                uuid
                displaySymbol
              }
              supportedNetworks(action: RECEIVE, applicationContext: CONSUMER) {
                __typename
                ...useSupportedNetworksFragment
                ...NetworkSelectorFragment
              }
            }
          }
          address(network: $network, forceRegeneration: $forceRegeneration) {
            shareAddressInfo {
              line1
              line2
            }
            network
            inlineWarning {
              text
              ...AddressInlineWarningFragment
            }
            launchWarning {
              ...AddressLaunchWarningFragment
              title
            }
            addressInfo {
              address @required(action: THROW)
              destinationTag
            }
          }
        }
      `,
      accountRef,
    );

    const asset = account?.assetOrFiatCurrency?.asset;
    const supportedNetworks = account?.assetOrFiatCurrency?.supportedNetworks;
    const address = account?.address;

    const hasBtcLightingEnabled = useHasBtcLightningSupport();

    const {
      selectedNetwork,
      defaultNetwork,
      setSelectedNetwork,
      supportedNetworks: networks,
    } = useSupportedNetworks(supportedNetworks ?? null, undefined);

    const showBtcLightningInvoice = useMemo(() => {
      return (
        hasBtcLightingEnabled &&
        selectedNetwork?.networkSlug === 'lightning' &&
        invoice !== null
      );
    }, [hasBtcLightingEnabled, selectedNetwork?.networkSlug, invoice]);

    const [
      isNetworkSelectionFlowVisible,
      { toggleOff: hideNetworkTray, toggleOn: showNetworkTray },
    ] = useToggler();

    const refreshQuery = useCallback(
      (network?: SupportedNetwork) => {
        setSelectedNetwork(network?.networkSlug ?? '');
        refetchAddress(
          {
            network: network?.networkSlug ?? '',
            forceRegeneration: false,
          },
          {
            fetchPolicy: 'network-only',
          },
        );
      },
      [refetchAddress, setSelectedNetwork],
    );

    const regenerateWalletAddress = useCallback(
      (selectedNetworkSlug: string) => {
        setFetchingNewAddress(true);
        refetchAddress(
          {
            network: networks.length > 0 ? selectedNetworkSlug : '',
            forceRegeneration: true,
          },
          {
            fetchPolicy: 'network-only',
            onComplete: () => {
              logAddressRegenerationBannerViewEvent({
                flow: 'receive_setup',
              });
              setSelectedNetwork(selectedNetworkSlug);
              toast.show(formatMessage(messages.newAddressToastText));
              setFetchingNewAddress(false);
            },
          },
        );
      },
      [
        formatMessage,
        logAddressRegenerationBannerViewEvent,
        networks.length,
        refetchAddress,
        setSelectedNetwork,
        toast,
      ],
    );

    const addressInformation = useMemo(
      () => ({
        address: address?.addressInfo?.address ?? '',
        destinationTag: address?.addressInfo?.destinationTag ?? '',
      }),
      [address?.addressInfo?.address, address?.addressInfo?.destinationTag],
    );

    const shareAddressCopy = useMemo(
      () => ({
        line1: address?.shareAddressInfo?.line1 ?? '',
        line2: address?.shareAddressInfo?.line2 ?? '',
      }),
      [address?.shareAddressInfo?.line1, address?.shareAddressInfo?.line2],
    );

    const share = useShareReceiveAddress();

    const { navigate, push } = useStackNavigation();
    const { present } = useModal('LightningUpsellModalStack');

    const [startLoadAssets] = usePerfMark(
      'p2p',
      'navigate_to_receive_asset_selector',
    );

    const handleNetworkCellPress = useCallback(() => {
      logReceiveFlowButtonPress({
        componentName: 'network_selector',
        flow: 'receive_setup',
      });
      showNetworkTray();
    }, [logReceiveFlowButtonPress, showNetworkTray]);

    useMaxBrightness();

    useFocusEffectAfterInteractions(
      useCallback(() => {
        if (hasBtcLightingEnabled) {
          // Reset fields since BTC lightning invoices and requests feature share the same context
          amountFiatField.onChange('0');
          noteField.onChange('');
        }
        /* eslint-disable-next-line react-hooks/exhaustive-deps  */
      }, []),
    );

    const { setCurrency, entryPoint } = useContext(SendReceiveAnalyticsContext);

    useFocusEffectAfterInteractions(
      useCallback(() => {
        setCurrency(asset?.displaySymbol);
      }, [asset?.displaySymbol, setCurrency]),
    );

    const onAccountListCellPress = useCallback(() => {
      logReceiveFlowButtonPress({
        componentName: 'change_asset',
      });
      startLoadAssets();
      markJourney('navigate_to_receive_account_selector');
      push('ReceiveAccountSelector', {
        headerAction: 'back',
        accountId,
      });
    }, [accountId, logReceiveFlowButtonPress, push, startLoadAssets]);

    const onShareButtonPress = useCallback(() => {
      logReceiveFlowButtonPress({
        componentName: 'share_address',
      });
      share(asset ?? null, addressInformation, shareAddressCopy);
    }, [
      addressInformation,
      asset,
      logReceiveFlowButtonPress,
      share,
      shareAddressCopy,
    ]);

    // Clean up invoice context when changing asset, network or navigating away
    // This is to ensure that the invoice context is not persisted across flows
    useEffect(() => {
      if (!showBtcLightningInvoice) {
        setInvoice(null);
      }
    }, [setInvoice, showBtcLightningInvoice]);

    // Always set address based on network sent from backend, except when there's a recently created lightning invoice
    useEffect(() => {
      if (invoice !== null) {
        setSelectedNetwork('lightning');
        return;
      }

      setSelectedNetwork(address?.network ?? '');
    }, [invoice, address?.network, setSelectedNetwork]);

    const [hidePill, setHidePill] = useState(false);
    const [hasSeenRequestNuxModal, setHasSeenRequestNuxModal] = useState(false);
    const [isRequestModalVisible, setShowRequestNuxModal] = useState(false);
    const [showSystemAlert, setShowSystemAlert] = useState(false);

    useFocusEffectAfterInteractions(
      useCallback(() => {
        logReceiveModalRenderEvent({
          flow: 'receive_setup',
          isDefaultNetwork: selectedNetwork?.isDefault ? 'yes' : 'no',
          selectedNetwork: selectedNetwork?.networkName ?? '',
        });
      }, [
        logReceiveModalRenderEvent,
        selectedNetwork?.isDefault,
        selectedNetwork?.networkName,
      ]),
    );

    useOnMount(() => {
      void (async () => {
        const hasSeenNetworkPill = await getStoreData(
          NETWORK_SELECTION_STORE,
          SEEN_RECEIVE_NETWORK_PILL,
          false,
        );
        setHidePill(hasSeenNetworkPill);
      })();
    });

    useOnMount(() => {
      void (async () => {
        const shouldShowRequestNuxModal = await getStoreData(
          RECEIVE_SCREEN_STORE,
          SEEN_REQUEST_NUX_MODAL,
          false,
        );
        setHasSeenRequestNuxModal(shouldShowRequestNuxModal);
        setShowRequestNuxModal(shouldShowRequestNuxModal);
      })();
    });

    const handleNetworkChange = useCallback(
      (network?: SupportedNetwork) => {
        const networkDidNotChange =
          selectedNetwork?.networkSlug === network?.networkSlug;
        if (networkDidNotChange || !network) {
          return;
        }
        if (!network.isDefault) {
          if (!hidePill) {
            void setStoreData(
              NETWORK_SELECTION_STORE,
              SEEN_RECEIVE_NETWORK_PILL,
              true,
            );
            setHidePill(true);
          }
        }

        if (hasBtcLightingEnabled && network.networkSlug === 'lightning') {
          const hasSeenLightningNUX = getStoreDataSynchronous(
            P2P_BTC_LIGHTNING_STORE_NAME,
            P2P_BTC_LIGHTNING_HAS_SEEN_RECEIVE_UPSELL,
            false,
          );

          if (!hasSeenLightningNUX) {
            present('LightningNUXIntro', { entryPoint: 'receive', accountId });
            return;
          }

          navigate('LightningAmountEntryScreen', { accountId });
          return;
        }

        refreshQuery(network);
      },
      [
        hidePill,
        refreshQuery,
        selectedNetwork,
        hasBtcLightingEnabled,
        navigate,
        accountId,
        present,
      ],
    );

    const hasL2Experience = useHasL2Experience();
    const shouldShowL2Warning =
      !!address?.launchWarning?.title && !!hasL2Experience;

    const selectedNetworkLabel = useMemo(() => {
      if (!defaultNetwork) {
        return '';
      }

      return selectedNetwork?.networkName ?? defaultNetwork?.networkName;
    }, [defaultNetwork, selectedNetwork]);

    const keyForWarningTimestamp = useMemo(
      () =>
        `${
          isVault ? `${asset?.platformName}-vault` : asset?.platformName
        }-warning-dismissed-timestamp`,
      [asset?.platformName, isVault],
    );

    const { shouldSkipWarning, checkShouldSkipWarning } = useShouldSkipWarning(
      RECEIVE_WARNING_STORE,
      keyForWarningTimestamp,
      'short',
    );

    const shouldSkipWarningOnMount =
      networks?.length === 0 || shouldSkipWarning;

    const [, endLoadAddCryptoPerfMark] = usePerfMark(
      'advanced_trade',
      'load_add_crypto',
    );

    // Reset System Alerts when accountId changes
    useEffect(() => {
      setShowSystemAlert(false);
    }, [accountId]);

    useEffect(() => {
      if (account) {
        endLoadAddCryptoPerfMark({
          logMetric: true,
        });
      }
    }, [account, endLoadAddCryptoPerfMark, entryPoint]);

    useEffect(() => {
      markJourney('loaded_receive');
    }, []);

    const statusAlert = useMemo(() => {
      // Show system alert when there is no launchWarning
      // Show system alert after launch warning if both exist
      if (
        !address?.launchWarning?.title ||
        (!!address?.launchWarning?.title && showSystemAlert)
      ) {
        return (
          <SystemAlertSection
            view="RECEIVE"
            currencies={[asset?.platformName ?? '']}
            network={selectedNetwork?.networkName}
          />
        );
      }
      return null;
    }, [
      address?.launchWarning?.title,
      showSystemAlert,
      asset?.platformName,
      selectedNetwork,
    ]);

    const handleLaunchWarningDismiss = useCallback(() => {
      setShowSystemAlert(true);
    }, []);

    const handleGenerateAddressClick = useCallback(async () => {
      if (
        hasBtcLightingEnabled &&
        selectedNetwork?.networkSlug === 'lightning'
      ) {
        logInvoiceRegenerationBanner({
          flow: 'receive_setup',
          step: 'invoice_regeneration',
        });
        navigate('GenerateInvoiceScreen', { accountId });
        return;
      }

      logReceiveFlowButtonPress({
        componentName: 'address_regeneration',
        flow: 'receive_setup',
      });

      const seenAddressGenerationScreen = await getStoreData(
        RECEIVE_SCREEN_STORE,
        SEEN_ADDRESS_GENERATION_SCREEN,
        false,
      );

      if (!seenAddressGenerationScreen) {
        push('GenerateAddress', {
          regenerateWalletAddress,
          selectedNetworkSlug: selectedNetwork?.networkSlug ?? '',
        });
      } else {
        const selectedNetworkSlug =
          selectedNetwork?.networkSlug ?? defaultNetwork?.networkSlug ?? '';

        regenerateWalletAddress(selectedNetworkSlug);
      }
    }, [
      defaultNetwork?.networkSlug,
      logReceiveFlowButtonPress,
      push,
      regenerateWalletAddress,
      selectedNetwork,
      hasBtcLightingEnabled,
      accountId,
      navigate,
      logInvoiceRegenerationBanner,
    ]);

    const navigateToRequestAmountEntryScreen = useCallback(() => {
      navigate('RequestAmountEntryScreen', {});
      void setStoreData(RECEIVE_SCREEN_STORE, SEEN_REQUEST_NUX_MODAL, true);
    }, [navigate]);

    const hideRequestModal = useCallback(() => {
      setHasSeenRequestNuxModal(true);
      setShowRequestNuxModal(false);
      navigateToRequestAmountEntryScreen();
    }, [navigateToRequestAmountEntryScreen]);

    const handleTitleBoxPillClick = useCallback(
      (index?: number) => {
        if (hasSeenRequestNuxModal && index !== 0 && hasCryptoRequests) {
          navigate('RequestAmountEntryScreen', {});
        } else if (
          !hasSeenRequestNuxModal &&
          index !== 0 &&
          hasCryptoRequests
        ) {
          setShowRequestNuxModal(true);
        }
      },
      [hasCryptoRequests, hasSeenRequestNuxModal, navigate],
    );

    const headerTitleBox = (
      <HeaderTitleBox
        setSelectedIndex={handleTitleBoxPillClick}
        selectedIndex={0}
        hasCryptoRequests={hasCryptoRequests}
        isCryptoRequestsEligible={isCryptoRequestsEligible}
      />
    );

    const trailing = useMemo(() => {
      return (
        <IconButton
          hitSlop={12}
          name="share"
          transparent
          onPress={onShareButtonPress}
          testID="ShareWalletIcon"
        />
      );
    }, [onShareButtonPress]);

    const networkSelector = useMemo(() => {
      if (asset?.platformName === 'BTC' && !hasBtcLightingEnabled) {
        return null;
      }

      if (!!selectedNetworkLabel && hasL2Experience) {
        return (
          <NetworkSelector
            hidePill={
              asset?.platformName === 'BTC' && hasBtcLightingEnabled
                ? false
                : hidePill
            }
            selectedNetwork={selectedNetworkLabel}
            onPress={handleNetworkCellPress}
            networkSelectorRef={supportedNetworks ?? null}
          />
        );
      }

      return null;
    }, [
      asset?.platformName,
      hasBtcLightingEnabled,
      selectedNetworkLabel,
      hasL2Experience,
      supportedNetworks,
      hidePill,
      handleNetworkCellPress,
    ]);

    return (
      <Screen
        testID="ReceiveScreen"
        scrollable
        navHeader={{
          action: 'back',
          title: headerTitleBox,

          trailing,
        }}
      >
        <VStack spacingTop={2} flexGrow={1}>
          {statusAlert}
          <VStack spacingBottom={3}>
            <AccountSelector
              title={asset?.name ?? ''}
              subtitle={formatMessage(
                isVault ? messages.vault : messages.wallet,
                { asset: asset?.displaySymbol },
              )}
              onPress={onAccountListCellPress}
            />
          </VStack>
          <VStack gap={3}>
            <>
              <Box offsetStart={3} offsetEnd={4}>
                {networkSelector}
              </Box>
              <QRCodeComponentWithErrorBoundary
                accountRef={account ?? null}
                showBtcLightningInvoice={showBtcLightningInvoice}
              />
              <AddressLabelsWithErrorBoundary
                accountRef={account ?? null}
                handleGenerateAddressClick={handleGenerateAddressClick}
                fetchingNewAddress={fetchingNewAddress}
                showBtcLightningInvoice={showBtcLightningInvoice}
                selectedNetworkLabel={selectedNetworkLabel}
              />
            </>
            {address?.inlineWarning?.text || showBtcLightningInvoice ? (
              <Box zIndex={Number.MAX_SAFE_INTEGER}>
                <AddressInlineWarning
                  inlineWarningRef={address?.inlineWarning ?? null}
                  showLearnMore={
                    Boolean(supportedNetworks) && !showBtcLightningInvoice
                  }
                  showBtcLightningInvoice={showBtcLightningInvoice}
                />
              </Box>
            ) : null}
          </VStack>
          {shouldShowL2Warning && (
            <AddressLaunchWarning
              handleDismiss={handleLaunchWarningDismiss}
              keyForWarningTimestamp={keyForWarningTimestamp}
              shouldSkipWarningOnMount={shouldSkipWarningOnMount}
              warningRef={address.launchWarning}
              assetSymbol={asset?.platformName}
              checkShouldSkipWarning={checkShouldSkipWarning}
            />
          )}
          <MultiPortfolioDisclaimer
            type="deposit"
            queryRef={queryRef}
            spacingTop={2}
            variant="receive"
          />
          <Spacer />
        </VStack>
        <NetworkSelectionFlow
          defaultNetwork={defaultNetwork}
          asset={asset?.platformName ?? null}
          assetTicker={asset?.displaySymbol ?? null}
          isVisible={isNetworkSelectionFlowVisible}
          flow="receive"
          dismissHandler={handleNetworkChange}
          selectedNetwork={selectedNetwork}
          assetId={asset?.uuid ?? ''}
          onTrayClose={hideNetworkTray}
          accountRef={account || null}
        />
        {hasCryptoRequests &&
          !hasSeenRequestNuxModal &&
          isRequestModalVisible && (
            <RequestNuxModal onDismiss={hideRequestModal} />
          )}
      </Screen>
    );
  },
);

const ReceiveScreenContent = memo(() => {
  const { accountId, headerAction, network = '' } = useParams<'Receive'>();
  const query = useLazyLoadQuery<ReceiveScreenQuery>(
    graphql`
      query ReceiveScreenQuery(
        $accountId: Uuid!
        $shouldIncludeAccount: Boolean!
        $useDefaultAccountForFlow: Boolean!
        $network: String
        $forceRegeneration: Boolean!
        $multichainAction: SendReceiveSupportedNetworksAction!
        $multchainContext: SendReceiveSupportedNetworksApplicationContext!
        $toAddress: String
      ) {
        viewer @required(action: THROW) {
          ...useCryptoRequestsEligibilityFragment
          accountByUuid(uuid: $accountId)
            @include(if: $shouldIncludeAccount)
            @required(action: THROW) {
            ...ReceiveScreenContentAccountFragment
              @arguments(
                network: $network
                forceRegeneration: $forceRegeneration
              )
            uuid
            type
          }
          defaultAccountForFlow(flow: RECEIVE)
            @include(if: $useDefaultAccountForFlow)
            @required(action: THROW) {
            ...ReceiveScreenContentAccountFragment
              @arguments(
                network: $network
                forceRegeneration: $forceRegeneration
              )
            uuid
            type
          }
        }
        ...MultiPortfolioDisclaimerFragment
      }
    `,
    {
      accountId: accountId ?? '',
      useDefaultAccountForFlow: !accountId,
      shouldIncludeAccount: !!accountId,
      // Initial request will have empty string since client doesn't have access to networks yet.
      // Since network param is optional on the
      network,
      forceRegeneration: false,
      multichainAction: 'RECEIVE',
      multchainContext: 'CONSUMER',
      toAddress: '',
    },
    { fetchPolicy: 'network-only' },
  );

  const account =
    query.viewer?.accountByUuid ?? query.viewer?.defaultAccountForFlow ?? null;

  const isVault = account?.type === 'VAULT';

  return (
    <ReceiveContent
      accountId={account?.uuid}
      accountRef={account}
      queryRef={query}
      headerAction={headerAction}
      isVault={isVault}
      cryptoRequestEligibilityRef={query.viewer}
    />
  );
});

const ReceiveScreenIntermediaryContent = memo(() => {
  const { accountId, fromDeeplink, isMultichain } = useParams<'Receive'>();
  const { replace } = useStackNavigation();
  const hasReceiveRedesign = useHasReceiveRedesignSupport();

  useOnMount(() => {
    if (fromDeeplink && hasReceiveRedesign) {
      if (accountId && isMultichain) {
        markJourney('navigate_to_receive_network_selector');
        replace('ReceiveNetworkSelector', { accountId });
        return;
      }

      if (accountId && !isMultichain) {
        markJourney('navigate_to_receive_v2');
        replace('ReceiveRedesign', { accountId });
        return;
      }

      markJourney('navigate_to_receive_account_selector');
      replace('ReceiveAccountSelector', { accountId });
    }
  });

  if (fromDeeplink && hasReceiveRedesign) {
    return <FullScreenLoader loading instrumentationId="ReceiveScreen" />;
  }

  return <ReceiveScreenContent />;
});

export const ReceiveScreen = memo(() => {
  return (
    <ReceiveErrorBoundary>
      <PolicyRestrictionEnforcer action="receives" nonBlocking>
        <ReceiveScreenIntermediaryContent />
      </PolicyRestrictionEnforcer>
    </ReceiveErrorBoundary>
  );
});

