type RecipientDetails = NonNullable<
  NonNullable<
    NonNullable<
      RequesteeFulfillmentScreenContentQuery$data['viewer']
    >['p2pRequests']
  >['requestById']
>['requesterDetails'];

type P2PPreviewTrayProps = {
  accountRef: P2PPreviewTrayAccountFragment$key | null;
  isVisible: boolean;
  onDismiss: () => void;
  onCommitError: () => void;
  recipient: RecipientDetails;
  note: string;
  createSendInput?: PreviewSendAmountMutationResponse;
  p2pRequestId?: string;
  assetImageUrl?: string;
  cryptoExponent?: number;
};

const FIXED_CELL_HEIGHT = 80;

export function P2PPreviewTray({
  isVisible,
  onDismiss,
  onCommitError,
  recipient,
  note,
  createSendInput,
  accountRef,
  p2pRequestId,
  assetImageUrl,
  cryptoExponent,
}: P2PPreviewTrayProps) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const nativeCurrency = useNativeCurrency();
  const isUnifiedTwoFactor = useIsUnifiedTwoFactor();
  const [is2faVisible, { toggleOn: showTwoFactor, toggleOff: hideModal }] =
    useToggler(false);

  const { logRequestFlow } = useSendReceiveLoggers();

  const account = useFragment(
    graphql`
      fragment P2PPreviewTrayAccountFragment on Account {
        uuid
      }
    `,
    accountRef,
  );

  const [createSendResponse, setCreateSendResponse] =
    useState<CreateSendResponse>();

  const [createSend, isLoadingCreate] =
    useMutation<P2PPreviewTrayCreateMutation>(graphql`
      mutation P2PPreviewTrayCreateMutation($input: SendsCreateSendInput!) {
        createSend(input: $input) {
          ... on SendsCreateSendSuccess {
            success
            send {
              uuid
              amountFiat {
                value
              }
              amountCrypto {
                value
                currency
              }
            }
          }
        }
      }
    `);

  const [commitSend, isLoadingCommit] =
    useMutation<P2PPreviewTrayCommitMutation>(graphql`
      mutation P2PPreviewTrayCommitMutation($input: SendsCommitSendInput!) {
        commitSend(input: $input) {
          ... on SendsCommitSendSuccess {
            __typename
            send {
              amountFiat {
                value
                currency
              }
            }
          }
          ... on SendsCommitSendError {
            __typename
            error {
              message
              code
            }
          }
        }
      }
    `);

  useEffect(() => {
    if (isVisible && !isLoadingCreate) {
      createSend({
        variables: {
          input: {
            amountCrypto: createSendInput?.amountCrypto as AmountInput,
            amountFiat: createSendInput?.amountFiat,
            exchangeRateCacheKey: createSendInput?.exchangeRateCacheKey,
            fromAccountUuid: account?.uuid ?? '',
            note,
            recipient: recipient?.email ?? '',
            sendType: 'OFF_CHAIN',
          },
        },
        onCompleted: ({ response }) => {
          if (response.createSend?.success) {
            setCreateSendResponse(response.createSend);
          }
        },
        onError: ({ alreadyReportedError }) => {
          errorVitals.logError(alreadyReportedError, {
            severity: 'error',
            context: 'requests',
            isHandled: true,
          });
        },
      });
    }
    /**
     * only fire this on visibility change
     * since it mounts before, visiblity is our idea of "mount" here
     */
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isVisible]);

  const submit = useCallback(
    (token?: string) => {
      logRequestFlow({
        flow: 'request_receiver',
        step: 'request_receiver_fulfillment_preview',
        componentName: 'request_fulfillment_preview_submit',
      });

      commitSend({
        variables: {
          input: {
            uuid: createSendResponse?.send?.uuid as string,
            p2pRequestId,
            shareEmailWithRecipient: true,
            twoFactorProofToken: token,
            isUnifiedTwoFactor,
          },
        },
        onCompleted: ({ response }) => {
          matchUnion(response.commitSend)
            .when('SendsCommitSendError', ({ error }) => {
              if (error.code === 'two_factor_required') {
                showTwoFactor();
              } else {
                errorVitals.logError(
                  new Error(`Failed to commit send request: ${error.message}`),
                  {
                    severity: 'error',
                    context: 'requests',
                    isHandled: false,
                  },
                );

                onCommitError();
              }
            })
            .when('SendsCommitSendSuccess', ({ send }) => {
              onDismiss();

              navigate('ReceiverSendConfirmationScreen', {
                requestId: p2pRequestId,
                fiatValue: send.amountFiat?.value ?? '',
                currency: send.amountFiat?.currency ?? '',
                requesterName: (recipient?.name || recipient?.email) ?? '',
              });
            })
            .otherwise(() => {
              errorVitals.logError(
                new Error(
                  `Mutation commitSend returned unknown response or null.`,
                ),
                {
                  context: 'requests',
                  severity: 'error',
                  isHandled: false,
                },
              );

              onCommitError();
            });
        },
        onError: ({ alreadyReportedError }) => {
          errorVitals.logError(alreadyReportedError, {
            context: 'requests',
            severity: 'error',
            isHandled: false,
          });

          onCommitError();
        },
      });
    },
    [
      commitSend,
      createSendResponse?.send?.uuid,
      p2pRequestId,
      showTwoFactor,
      onCommitError,
      navigate,
      onDismiss,
