  const formattedAccountBalanceCrypto = formatCurrency({
    isSensitive: false,
    compactNotation: true,
    maximumFractionDigits: 4,
    amount: createSendResponse?.send?.amountCrypto?.value ?? '',
    currency: {
      type: 'crypto',
      code: createSendResponse?.send?.amountCrypto?.currency,
      exponent: cryptoExponent,
