                  }
                  detail={
                    <TextBody numberOfLines={1} color="foreground">
                      -{formattedAccountBalanceFiat}
                    </TextBody>
                  }
                  subdetail={
                    <TextBody color="foregroundMuted">
                      -{formattedAccountBalanceCrypto}
                    </TextBody>
                  }
                  media={
                    <CellMedia type="asset" source={assetImageUrl ?? ''} />
                  }
                />
              </Box>
              <Spacer vertical={0.5} />
              <Box
                spacingStart={2}
                offsetVertical={2}
                spacingVertical={0.5}
                offsetHorizontal={1}
                zIndex={1}
                maxWidth={24}
              >
                <Icon name="verticalLine" size="s" color="foregroundMuted" />
              </Box>
              <Box height={FIXED_CELL_HEIGHT}>
                <ListCell
                  outerSpacing={{ spacingHorizontal: 0 }}
                  title={
                    <TextHeadline adjustsFontSizeToFit>
                      {formatMessage(messages.sendTo)}
                    </TextHeadline>
                  }
                  description={
                    <TextBody color="foregroundMuted">
                      {recipient?.email ?? ''}
                    </TextBody>
                  }
                  media={requesterMedia}
                />
              </Box>

              <ListCell
                outerSpacing={{ spacingHorizontal: 0 }}
                title={
                  <TextHeadline>{formatMessage(messages.total)}</TextHeadline>
                }
                detail={
                  <TextHeadline>{formattedAccountBalanceFiat}</TextHeadline>
                }
              />

              <TextLegal color="foregroundMuted" spacingBottom={4}>
                {formatMessage(messages.legal)}
              </TextLegal>

              <Button
                onPress={() => submit()}
                loading={isLoadingCommit}
                disabled={isLoadingCommit}
              >
                {formatMessage(messages.sendNow)}
              </Button>
            </VStack>
          )}
        </Tray>
      ) : null}
      {is2faVisible && (
        <UnifiedTwoFactorV2
          onSuccess={(token: string) => {
            hideModal();
            submit(token);
          }}
          onCancel={hideModal}
        />
      )}
    </>
  );
}

