type AddressLabelsProps = {
  accountRef: AddressLabelsFragment$key | null;
  handleGenerateAddressClick: () => void;
  fetchingNewAddress: boolean;
  showBtcLightningInvoice?: boolean;
  selectedNetworkLabel?: string | null;
};

export function AddressLabels({
  accountRef,
  handleGenerateAddressClick,
  fetchingNewAddress,
  showBtcLightningInvoice,
  selectedNetworkLabel,
}: AddressLabelsProps) {
  const { formatMessage } = useIntl();
  const toast = useToast();
  const { logReceiveFlowButtonPress } = useSendReceiveLoggers();
  const { invoice } = useLightningInvoiceContext();

  const [addressCopied, setAddressCopied] = useState(false);
  const [tagCopied, setTagCopied] = useState(false);

  const account = useFragment(
    graphql`
      fragment AddressLabelsFragment on Account
      @argumentDefinitions(
        network: { type: "String" }
        forceRegeneration: { type: "Boolean" }
      ) {
        uuid
        address(network: $network, forceRegeneration: $forceRegeneration)
          @required(action: THROW) {
          isRegenerable
          addressLabel
          addressInfo {
            address
            destinationTag
          }
        }
        assetOrFiatCurrency {
          ... on ViewerAsset {
            asset {
              displaySymbol
              destinationTag {
                name
              }
            }
          }
        }
      }
    `,
    accountRef,
  );

  const address = useMemo(() => {
    if (showBtcLightningInvoice) {
      return {
        addressLabel: invoice?.addressLabel,
        addressInfo: {
          address: invoice?.addressInfo?.address,
          destinationTag: invoice?.addressInfo?.destinationTag,
        },
        isRegenerable: invoice?.isRegenerable,
      };
    }

    return account?.address ?? null;
  }, [
    showBtcLightningInvoice,
    account?.address,
    invoice?.addressInfo,
    invoice?.isRegenerable,
    invoice?.addressLabel,
  ]);

  const addressTitle = address?.addressLabel ?? '';
  const rawAddress = address?.addressInfo.address ?? '';
  const addressSubtitle = useMemo(() => {
    if (rawAddress.length > ADDRESS_LENGTH_FOR_TRUNCATION) {
      return getEllipsizedString(rawAddress, 8) ?? '';
    }

    return rawAddress;
  }, [rawAddress]);
  const destinationTag = address?.addressInfo.destinationTag ?? '';
  const isRegenerable = address?.isRegenerable ?? false;

  useEffect(() => {
    setAddressCopied(false);
    setTagCopied(false);
  }, [address]);

  if (!address) {
    errorVitals.logError(new Error('Receive address is null'), {
      context: 'receive_address_missing',
      severity: 'error',
      isHandled: false,
      ...(account?.uuid ? { uuid: account.uuid } : {}),
    });
  }

  if (!rawAddress) {
    errorVitals.logError(new Error('Receive address is missing'), {
      context: 'receive_address_content_missing',
      severity: 'error',
      isHandled: false,
      ...(account?.uuid ? { uuid: account.uuid } : {}),
    });
  }

  const dTagTitle =
    getUSDCxMemo(
      account?.assetOrFiatCurrency?.asset?.displaySymbol ?? '',
      account?.address?.addressInfo?.address ?? '',
    )?.name ?? account?.assetOrFiatCurrency?.asset?.destinationTag?.name;

  const onAddressCopy = useCallback(() => {
    if (rawAddress) {
      setStringAsync(rawAddress);
      setAddressCopied(true);
      setTagCopied(false);

      toast.show(formatMessage(messages.copied), {
        bottomOffset: 40,
        duration: TOAST_DURATION,
      });
      setTimeout(() => setAddressCopied(false), COPY_TIMEOUT);

      logReceiveFlowButtonPress({
        componentName: 'copy_address',
        selectedNetwork: selectedNetworkLabel ?? undefined,
      });
    }
  }, [
    rawAddress,
    formatMessage,
    toast,
    logReceiveFlowButtonPress,
    selectedNetworkLabel,
  ]);

  const onDestinationTagCopy = useCallback(() => {
    if (destinationTag) {
      setStringAsync(destinationTag).then(() => {
        setTagCopied(true);
        setAddressCopied(false);

        toast.show(formatMessage(messages.copied), {
          duration: TOAST_DURATION,
        });
        setTimeout(() => setTagCopied(false), COPY_TIMEOUT);
      });
    }
  }, [destinationTag, formatMessage, toast]);

  return (
    <>
      <AddressLabel
        title={addressTitle}
        subtitle={addressSubtitle}
        copied={addressCopied}
        onCopied={onAddressCopy}
        handleGenerateAddressClick={
          isRegenerable ? handleGenerateAddressClick : undefined
        }
        fetchingNewAddress={fetchingNewAddress}
        testID="address"
      />
      {!!address?.addressInfo.destinationTag && (
        <AddressLabel
          title={`${dTagTitle} (${formatMessage(messages.required)})`}
          subtitle={destinationTag}
          copied={tagCopied}
          onCopied={onDestinationTagCopy}
          testID="destinationTag"
        />
      )}
    </>
  );
}

