import { defineMessages, useIntl } from '@cbhq/i18n';

import { TransactionCellFallback } from '@app/components/TransactionCell';
import { useCurrencyFormatter } from '@app/hooks/formatters/useCurrencyFormatter';
import { useAccountRewardApy } from '@app/hooks/useAccountRewardApy';
import { useTxHistoryStylingExperiment } from '@app/screens/AssetsTab/hooks/useTxHistoryStylingExperiment';
import { useRecurringPurchaseTextDeprecated } from '@app/screens/Recurring/hooks/useRecurringPurchaseText';
import { useSimpleTradeRecurringBuyAndStakeExperiment } from '@app/screens/SimpleTrade/hooks/useRecurringBuyAndStakeExperiment/useSimpleTradeRecurringBuyAndStakeExperiment';
import { useRavTransactScreenExperiment } from '@app/screens/TradeTab/hooks/useRavTransactScreenExperiment';
import { CurrencyStub } from '@app/types/Currency';
import { RecurringPeriod } from '@app/types/RecurringPeriod';

import { RecurringTransactionCellFragment$key } from './__generated__/RecurringTransactionCellFragment.graphql';

const messages = defineMessages({
  recurringBuyTitle: {
    id: 'RecurringTransactionCell.recurringBuyTitle',
    defaultMessage: 'Recurring {name} buy',
    description: `#Component:title
    #CharLimit:50
    #Context:Title for recurring buy cell`,
  },
});

type RecurringTransactionCellProps = {
  recurringTransactionRef: RecurringTransactionCellFragment$key;
  onPress: () => void;
};
const RecurringTransactionCell = memo<RecurringTransactionCellProps>(
  ({ recurringTransactionRef, onPress }) => {
    const {
      amount: { value, currency },
      recurringPeriod,
      createdAt,
      account,
      shouldStake,
    } = useFragment(
      graphql`
        fragment RecurringTransactionCellFragment on RecurringTransaction {
          amount {
            value
            currency
          }
          recurringPeriod
          createdAt

          account {
            assetOrFiatCurrency {
              ...useAccountRewardApyFragment
              ... on ViewerAsset {
                asset {
                  name
                  imageUrl
                  displaySymbol
                  exponent
                }
              }
              ... on TiersCurrency {
                type
              }
            }
          }
          shouldStake
        }
      `,
      recurringTransactionRef,
    );

    const period = toLower(recurringPeriod) as RecurringPeriod;
    const formatCurrency = useCurrencyFormatter();
    const { formatMessage } = useIntl();
    const txHistoryRefreshEnabled = useTxHistoryStylingExperiment();
    const isRavExperiment = useRavTransactScreenExperiment();
    const hasRecurringBuyAndStakeExperiment =
      useSimpleTradeRecurringBuyAndStakeExperiment();

    const { recurringPeriodDescription } = useRecurringPurchaseTextDeprecated(
      period,
      createdAt,
    );

    const accountRewardApy = useAccountRewardApy(
      account?.assetOrFiatCurrency ?? null,
    );

    const showRewardApy = useMemo(
      () =>
        hasRecurringBuyAndStakeExperiment &&
        shouldStake &&
        accountRewardApy?.label,
      [accountRewardApy?.label, hasRecurringBuyAndStakeExperiment, shouldStake],
    );

    const currencyStub: CurrencyStub = useMemo(
      () => ({
        type: account?.assetOrFiatCurrency?.type === 'fiat' ? 'fiat' : 'crypto',
        code: currency,
        // Derive exponent from asset, then hardcoded fiat exponent

        exponent: account?.assetOrFiatCurrency?.asset?.exponent || 2,
      }),
      [account?.assetOrFiatCurrency, currency],
    );

    const title = useMemo(() => {
      if (!account?.assetOrFiatCurrency?.asset) {
        return '';
      }

      return txHistoryRefreshEnabled && !isRavExperiment
        ? formatMessage(messages.recurringBuyTitle, {
            name: account?.assetOrFiatCurrency?.asset.name,
          })
        : account?.assetOrFiatCurrency?.asset.name;
    }, [
      account?.assetOrFiatCurrency?.asset,
      formatMessage,
      isRavExperiment,
      txHistoryRefreshEnabled,
    ]);

    const fiatAmount = formatCurrency({
      amount: value,
      currency: currencyStub,
      isSensitive: false,
    });

    const showSubdetail =
      hasRecurringBuyAndStakeExperiment || !txHistoryRefreshEnabled;

    const description = useMemo(() => {
      if (hasRecurringBuyAndStakeExperiment) {
        if (showRewardApy) {
          return (
            <TextLabel2 color="positive">{accountRewardApy?.label}</TextLabel2>
          );
        }
        return undefined;
      }
      if (txHistoryRefreshEnabled) {
        return recurringPeriodDescription;
      }
      return undefined;
    }, [
      accountRewardApy?.label,
      hasRecurringBuyAndStakeExperiment,
      recurringPeriodDescription,
      txHistoryRefreshEnabled,
      showRewardApy,
    ]);

    if (!account?.assetOrFiatCurrency?.asset) {
      return null;
    }

    return (
      <ListCell
        title={title}
        priority="end"
        media={
          <CellMedia
            type="asset"
            source={account?.assetOrFiatCurrency?.asset.imageUrl}
            accessibilityLabel={
              account?.assetOrFiatCurrency?.asset.displaySymbol ||
              account?.assetOrFiatCurrency?.asset.name
            }
          />
        }
        detail={fiatAmount}
        subdetail={showSubdetail ? recurringPeriodDescription : undefined}
        onPress={onPress}
        description={description}
      />
    );
  },
);

export const RecurringTransactionCellFallback = TransactionCellFallback;

export { RecurringTransactionCell };

