async function handlePressSmsShareCard(
  smsBody: string,
  flow: ReferralHubFlowTypes,
) {
  try {
    const separator = Platform.OS === 'ios' ? '&' : '?';
    await Linking.openURL(`sms:${separator}body=${smsBody}`);

    logReferralHubInviteEvent(
      referralHubInviteActionTypes.SMS,
      ComponentType.card,
      flow,
    );
  } catch (err) {
    errorVitals.logError(getErrorInstance(err), {
      context: 'more_ways_to-share',
      severity: 'error',
      isHandled: false,
    });
  }
}

async function handlePressInstalledApp(
  smsTitle: string,
  smsBody: string,
  installedApp: AppData,
  flow: ReferralHubFlowTypes,
) {
  try {
    if (isIncompatibleWithSharePackage(installedApp)) {
      await Linking.openURL(
        `${installedApp.urlScheme}://${installedApp.urlParams}?text=${smsBody}`,
      );
    } else {
      await Share.shareSingle({
        title: smsTitle,
        social: installedApp.type,
        message: smsBody,
      });
    }

    logReferralHubInviteEvent(installedApp.type, ComponentType.card, flow);
  } catch (err) {
    errorVitals.logError(getErrorInstance(err), {
      context: 'more_ways_to_share',
      severity: 'error',
      isHandled: false,
    });
  }
}

function isIncompatibleWithSharePackage(installedApp: AppData) {
  return Platform.OS === 'ios' && installedApp.type === Social.Whatsapp;
