import { memo, PropsWithChildren, useCallback, useMemo } from 'react';
import { View } from 'react-native';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Box, BoxProps } from '@cbhq/cds-mobile/layout/Box';

import { IconButton } from '@components/interactables/IconButton';

import { totalContentScreens } from '../data/screens';
import { useScamQuizNavigation } from '../providers/ScamQuizNavigation';
import {
  logBackPress,
  logQuizExited,
  useMeasureTimeSpentOnScreen,
} from '../utils/scamQuizAnalytics';

import { ScamQuizProgress } from './ScamQuizProgress';

type ScamQuizBaseScreenProps = PropsWithChildren<{
  headerBackground?: BoxProps['background'];
}>;

export const ScamQuizBaseScreen = memo<ScamQuizBaseScreenProps>(
  ({ headerBackground, children }) => {
    const { currentScreenKind, screenIndex } = useScamQuizNavigation();
    const { top, bottom } = useSafeAreaInsets();
    const safeViewTopStyle = useMemo(() => ({ paddingTop: top }), [top]);
    const safeViewBottomStyle = useMemo(
      () => ({ paddingBottom: bottom }),
      [bottom],
    );
    const showProgress =
      currentScreenKind === 'learning' || currentScreenKind === 'question';

    // measure totat time spent on screen
    useMeasureTimeSpentOnScreen(screenIndex);

    return (
      <View
        aria-label="scam-quiz-screen"
        data-screen-index={screenIndex + 1}
        data-current-screen={currentScreenKind}
      >
        <VStack height="100%">
          <Box style={safeViewTopStyle} background={headerBackground} />
          <VStack background={headerBackground} gap={1.5}>
            <HStack
              spacingHorizontal={1}
              spacingTop={1}
              justifyContent="space-between"
            >
              <BackButton />
              <CloseButton />
            </HStack>
            {showProgress && (
              <ScamQuizProgress
                currentScreenIndex={screenIndex}
                totalScreens={totalContentScreens}
              />
            )}
          </VStack>
          {children}
          <Box style={safeViewBottomStyle} />
        </VStack>
      </View>
    );
  },
);

const BackButton = memo(() => {
  const { currentScreenKind, screenIndex, navPrev } = useScamQuizNavigation();
  const handleBackPress = useCallback(() => {
    navPrev();
    logBackPress(screenIndex);
  }, [navPrev, screenIndex]);

  // dont show back button for submission screen
  if (currentScreenKind === 'submission') return <Box />;

  return (
    <IconButton
      compact
      transparent
      aria-label="back button"
      name="backArrow"
      onPress={handleBackPress}
    />
  );
});

const CloseButton = memo(() => {
  const { exit } = useScamQuizNavigation();
  const handleClosePress = useCallback(() => {
    exit();
    logQuizExited();
  }, [exit]);

  return (
    <IconButton
      compact
      transparent
      aria-label="close button"
      name="close"
      onPress={handleClosePress}
    />
  );
});

