type AmountEntryScreenContentProps = {
  queryRef: AmountEntryScreenContentFragment$key;
  network?: string;
};

const i18nKey = 'SendAmountEntryScreen';
const TRUNCATION_LENGTH_ON_CHAIN = 6;
const TRUNCATION_LENGTH_OFF_CHAIN = 12;
const messages = defineMessages({
  preview: {
    id: `${i18nKey}.preview`,
    defaultMessage: 'Preview',
    description:
      'Copy on a button that, when pressed, procedes to the next step of the Send flow.',
  },
  addNote: {
    id: `${i18nKey}.addNote`,
    defaultMessage: 'Add a note',
    description: 'Text shown on button to add a note',
  },
  editNote: {
    id: `${i18nKey}.editNote`,
    defaultMessage: 'Edit note',
    description: 'Text shown on button to edit a note',
  },
  max: {
    id: `${i18nKey}.max`,
    defaultMessage: 'Max',
    description:
      'Label for a button that sends the maximum amount available in the account',
  },
});

const AmountEntryScreenContent = memo(function AmountEntryScreenContent({
  queryRef,
  network,
}: AmountEntryScreenContentProps) {
  const { destinationTag } = useParams<'AmountEntryScreen'>();
  const nativeCurrency = useNativeCurrency();
  const fiatCurrency = useFiatCurrencyStub({
    nativeCurrency,
  });
  const { navigate, goBack } = useStackNavigation();

  const { formatMessage } = useIntl();
  const { setCurrency } = useContext(SendReceiveAnalyticsContext);
  const { logSendFlowButtonPress, logSendModalRenderEvent } =
    useSendReceiveLoggers();
  const [isSendOnly, setSendOnly] = useState(false);
  const [
    isRecipientTrayVisible,
    { toggleOn: toggleRecipientTrayOn, toggleOff: toggleRecipientTrayOff },
  ] = useToggler(false);

  const [
    isAccountSelectorVisible,
    { toggleOn: showAccountSelectorModal, toggleOff: hideAccountSelectorModal },
  ] = useToggler(false);

  const {
    accountIdField,
    amountCurrencyField,
    amountFiatField,
    amountValueField,
    destinationTagField,
    exchangeRateCacheKey,
    noteField,
    preferredCurrency,
    recipientField,
    recipientLookupName,
  } = useFields(Form);

  const query = useFragment(
    graphql`
      fragment AmountEntryScreenContentFragment on Query
      @argumentDefinitions(
        accountId: { type: "Uuid!" }
        multichainAction: { type: "SendReceiveSupportedNetworksAction!" }
        multchainContext: {
          type: "SendReceiveSupportedNetworksApplicationContext!"
        }
        toAddress: { type: "String!" }
      ) {
        ...TopUpTrayAccountFragment
        viewer {
          remediationAlert {
            source
          }
          accountByUuidV3(uuid: $accountId)
            @include(if: $shouldIncludeAccount) {
            account {
              ...SelectNetworkButtonFragment
              ...SendSourceTargetSelectorFragment
              ...RecipientTrayAccountFragment
              assetOrFiatCurrency {
                ...useAssetOrCurrencyGraphQLFragment
                ...useAssetCefiAvailableToSendFragment
                ... on ViewerAsset {
                  asset {
                    name
                  }
                  supportedNetworks(
                    action: $multichainAction
                    applicationContext: $multchainContext
                    address: $toAddress
                  ) {
                    isGeofenced
                    supportedNetworks {
                      __typename
                    }
                  }
                }
              }
            }
          }
        }
        ...MultiPortfolioDisclaimerFragment
      }
    `,
    queryRef,
  );

  const { viewer } = query;

  if (viewer?.remediationAlert?.source === 'c2c_remediation' && !isSendOnly) {
    setSendOnly(true);
  }

  const account = viewer?.accountByUuidV3?.account;

  if (!account) {
    const error = new Error('SendInputScreenContent: invalid account');
    errorVitals.logError(error, {
      context: 'amount_entry_screen',
      severity: 'error',
      isHandled: false,
    });
    throw error;
  }

  const [startLoadPreviewScreen] = usePerfMark(
    'p2p',
    'navigate_to_preview_screen',
  );

  const { trackSardineTextChange } = useSardineIntegrationEvents();

  useSyncParams([destinationTagField, destinationTag]);

  const { balanceInFiat } = useAssetCefiAvailableToSend({
    fragmentRef: account.assetOrFiatCurrency,
    isFiat: false,
  });
  const availableBalance = balanceInFiat ?? 0;

  const currency = useAssetOrCurrencyGraphQL(
    account?.assetOrFiatCurrency ?? null,
  );

  const convert = useCurrencyConverter(fiatCurrency.code);

  const cryptoAmount = useMemo(
    () =>
      convert(
        {
          amount:
            amountFiatField.value === 'max'
              ? availableBalance.toString()
              : amountFiatField.value || '0',
          currency: fiatCurrency.code,
        },
        currency?.code,
      ).toString(),
    [
      amountFiatField.value,
      availableBalance,
      convert,
      currency?.code,
      fiatCurrency.code,
    ],
  );

  const {
    cryptoCurrency,
    amountCrypto,
    fiatAmount,
    primaryAmount,
    secondaryAmount,
    inputCurrency,
    setAmount,
    isMaxed,
    setIsMaxed,
    setInputCurrency,
    resetCurrencies,
  } = useAmountEntryState({
    cryptoAmount: cryptoAmount || '0',
    currency,
    defaultInputCurrency: fiatCurrency,
    fiatAmount:
      amountFiatField.value === 'max'
        ? availableBalance.toString()
        : amountFiatField.value || '0',
  });

  const handleToggleRecipientTrayOn = useCallback(() => {
    logSendFlowButtonPress({
      componentName: 'recipient_tray',
      flow: 'send_setup_v2',
      step: 'amount',
    });

    toggleRecipientTrayOn();
  }, [toggleRecipientTrayOn, logSendFlowButtonPress]);

  // useCallback blocks the state update since previous state isn't ready yet
  // we want to use previous state to ensure the swap is safe
  // eslint-disable-next-line react-hooks/exhaustive-deps
  const swapInputCurrencies = () => {
    setInputCurrency(({ primary, secondary }) => {
      preferredCurrency.onChange(secondary.type);
      return {
        primary: secondary,
        secondary: primary,
      };
    });
    logSendFlowButtonPress({
      componentName: 'switch_asset_type',
      flow: 'send_setup_v2',
      step: 'amount',
    });
  };

  useFocusEffect(
    useCallback(() => {
      setCurrency(cryptoCurrency.code);
    }, [cryptoCurrency.code, setCurrency]),
  );

  useFocusEffect(
    useCallback(() => {
      if (amountValueField.value === 'max' && amountFiatField.value === 'max') {
        setIsMaxed(true);
      }
      setCurrency(cryptoCurrency.code);
    }, [
      amountFiatField.value,
      amountValueField.value,
      cryptoCurrency.code,
      setCurrency,
      setIsMaxed,
    ]),
  );

  useFocusEffectAfterInteractions(
    useCallback(
      () =>
        logSendModalRenderEvent({
          flow: 'send_setup_v2',
          step: 'amount',
        }),
      [logSendModalRenderEvent],
    ),
  );

  useEffect(() => {
    markJourney('loaded_send_amount_entry');
  }, []);

  // only run on account change
  useEffect(() => {
    if (currency) {
      resetCurrencies(fiatCurrency, currency);
    }
    exchangeRateCacheKey.onChange('');
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [accountIdField.value]);

  const formattedSecondaryAmount = formatInputAmount({
    locale: app.locale,
    amount: secondaryAmount,
    currency: inputCurrency.secondary,
    trailingCode: true,
  });

  const { submit: createSend, isSubmittable } = useFormSubmitter(Form, {});

  const cryptoBalance = convert(
    {
      amount: availableBalance.toString(),
      currency: fiatCurrency.code,
    },
    currency?.code,
  ).toString();

  const getAmountCryptoValue = useCallback(() => {
    if (isMaxed) {
      return 'max';
    }
    return amountCrypto.value;
  }, [amountCrypto.value, isMaxed]);

  const submit = useCallback(() => {
    markJourney('navigate_to_send_preview');
    logSendFlowButtonPress({
      componentName: 'preview',
      flow: 'send_setup_v2',
      step: 'amount',
    });

    amountCurrencyField.onChange(cryptoCurrency.code ?? '');
    amountValueField.onChange(getAmountCryptoValue());

    if (inputCurrency.primary.type === 'fiat' && !isMaxed) {
      amountFiatField.onChange(fiatAmount);
    } else if (inputCurrency.primary.type === 'crypto') {
      amountFiatField.onChange('0');
    }

    createSend();
    startLoadPreviewScreen();
  }, [
    amountCurrencyField,
    amountFiatField,
    amountValueField,
    createSend,
    cryptoCurrency.code,
    fiatAmount,
    getAmountCryptoValue,
    inputCurrency.primary.type,
    isMaxed,
    logSendFlowButtonPress,
    startLoadPreviewScreen,
  ]);

  const setMaxSend = useCallback(() => {
    logSendFlowButtonPress({
      componentName: 'send_all',
      flow: 'send_setup_v2',
      step: 'amount',
    });

    amountValueField.onChange('max');
    amountFiatField.onChange('max');
    setAmount(
      inputCurrency.primary.type === 'crypto'
        ? cryptoBalance
        : availableBalance.toString(),
    );
    setIsMaxed(true);

    createSend();
  }, [
    amountFiatField,
    amountValueField,
    availableBalance,
    createSend,
    cryptoBalance,
    inputCurrency.primary.type,
    logSendFlowButtonPress,
    setAmount,
    setIsMaxed,
  ]);

  const handleNumpadInputV2 = useCallback(
    (amount: string, isValid: boolean) => {
      if (isMaxed && isValid) {
        // Set Max as false if input is modified after Max and the modification is valid
        setIsMaxed(false);
      }
      trackSardineTextChange('send_amount_input', amount);
      if (isValid) {
        setAmount(amount);
        amountFiatField.onChange(amount);
      }
    },
    [isMaxed, setIsMaxed, trackSardineTextChange, setAmount, amountFiatField],
  );

  const isSubmittingSend = useIsLoading();

  const accountCurrencyCode = useMemo(
    () => [currency?.code || ''],
    [currency?.code],
  );

  const subtitleV2 = useMemo(() => {
    return (
      <HStack alignItems="center" gap={1}>
        <Pressable
          onPress={swapInputCurrencies}
          accessibilityRole="button"
          background="transparent"
          hitSlop={20}
        >
          <HStack alignItems="center" gap={0.5}>
            <Icon color="primary" name="arrowsVertical" size="xs" />
            <LiveTicker
              value={
                inputCurrency.primary.type === 'crypto'
                  ? `${formattedSecondaryAmount} ${inputCurrency.secondary.code}`
                  : `${formattedSecondaryAmount}`
              }
              variant="label1"
              color="primary"
            />
          </HStack>
        </Pressable>
      </HStack>
    );
  }, [
    formattedSecondaryAmount,
    inputCurrency.primary.type,
    inputCurrency.secondary.code,
    swapInputCurrencies,
  ]);

  const isOnChainSend = isOnChain(recipientField.value);
  const recipientName = recipientLookupName.value;
  const isPhoneNumber = phoneNumber(recipientField.value);
  const isEmail = emailFormat(recipientField.value);

  const iconName = () => {
    if (isPhoneNumber) {
      return 'profile';
    }
    if (isEmail) {
      return 'email';
    }
    return 'wallet';
  };

  const { verifiedWalletsMap } = useVerifiedWallets();
  const isVerifiedWallet = !!verifiedWalletsMap[recipientField.value];

  const recipientIdentifier = useMemo(() => {
    if (recipientName) {
      return recipientName;
    }

    return getEllipsizedString(
      recipientField.value,
      isOnChainSend ? TRUNCATION_LENGTH_ON_CHAIN : TRUNCATION_LENGTH_OFF_CHAIN,
    );
  }, [isOnChainSend, recipientField.value, recipientName]);

  const onNotePress = useCallback(() => {
    navigate('SendEnterNote', {
      source: 'amount_entry',
    });
  }, [navigate]);

  const accessibilityState = useMemo(
    () => ({
      disabled:
        !isSubmittable ||
        isSubmittingSend.isLoading ||
        primaryAmount === '0' ||
        !primaryAmount,
    }),
    [isSubmittable, isSubmittingSend.isLoading, primaryAmount],
  );

  const keyboardPreviewButtonGroup = useMemo(() => {
    return (
      <ButtonGroup block>
        <Button
          testID="AddOrEditNote"
          disabled={!!accessibilityState.disabled}
          accessibilityState={accessibilityState}
          onPress={onNotePress}
          compact
          variant="secondary"
          accessibilityHint="Add or edit a note"
          accessibilityLabel="note_button"
          accessibilityRole="button"
        >
          {!noteField.value
            ? formatMessage(messages.addNote)
            : formatMessage(messages.editNote)}
        </Button>
        <Button
          testID="SubmitButtonTreatment"
          accessibilityState={accessibilityState}
          accessibilityHint="Submit"
          accessibilityLabel="Submit"
          accessibilityRole="button"
          accessible
          disabled={!!accessibilityState.disabled}
          loading={isSubmittingSend.isLoading}
          onPress={submit}
          compact
        >
          {formatMessage(messages.preview)}
        </Button>
      </ButtonGroup>
    );
  }, [
    accessibilityState,
    onNotePress,
    noteField.value,
    formatMessage,
    isSubmittingSend.isLoading,
    submit,
  ]);

  const trailing = useCallback(() => {
    if (
      isOnChainSend &&
      !(account?.assetOrFiatCurrency?.asset?.name === 'Bitcoin') &&
      !account.assetOrFiatCurrency?.supportedNetworks?.isGeofenced &&
      !!account.assetOrFiatCurrency?.supportedNetworks?.supportedNetworks
        ?.length
    ) {
      return (
        <SelectNetworkButton
          accountRef={account}
          disabled={isSubmittingSend.isLoading}
          network={network}
        />
      );
    }

    return null;
  }, [isOnChainSend, account, isSubmittingSend.isLoading, network]);

  const navigateToSendRecipient = useCallback(() => {
    navigate('SendSelectRecipient', {
      accountId: accountIdField.value,
      showWalletUpsell: false,
    });
  }, [accountIdField.value, navigate]);

  const handleAccountChange = useCallback(
    (needsNetworkSelection?: boolean, newAccountId?: string) => {
      if (needsNetworkSelection) {
