        setTimeout(() => {
          navigate('L2AdoptionSelectionModal', {
            accountId: newAccountId ?? '',
            hasAccountChanged: true,
            mode: 'modal',
          });
        }, 250);
        return;
      }
      recipientField.onChange('');
      goBack();
    },
    [goBack, navigate, recipientField],
  );

  return (
    <Screen
      testID="AmountEntryScreen"
      flexBasis="100%"
      flexGrow={1}
      navHeader={{
        trailing,
      }}
    >
      <SystemAlertSection
        view="SEND"
        currencies={accountCurrencyCode}
        network={network}
      />

      <MultiPortfolioDisclaimer
        type="withdraw"
        queryRef={query}
        spacingTop={2}
