      <HStack flexGrow={1} alignItems="center" justifyContent="space-between">
        <Box maxWidth="50%" flexGrow={1}>
          <TransactionInputAmount
            variant="jumbo"
            amount={primaryAmount}
            currency={inputCurrency.primary}
            numericOnly={inputCurrency.primary.type === 'crypto'}
            subtitle={subtitleV2}
            isSimpleTradeRedesign
            isSendFlow
          />
        </Box>
        {primaryAmount === '0' || !primaryAmount ? (
          <Box spacingBottom={3}>
            <SmallButton testID="MaxButton" onPress={setMaxSend}>
              {formatMessage(messages.max)}
            </SmallButton>
          </Box>
        ) : null}
      </HStack>
      <SendSourceTargetSelector
        accountRef={account}
        currencyType={inputCurrency.primary.type}
        recipientIdentifier={recipientIdentifier}
        isVerifiedWallet={isVerifiedWallet}
        recipientType={iconName()}
        handleToggleRecipientTrayOn={handleToggleRecipientTrayOn}
        onAccountSelectorPressProp={showAccountSelectorModal}
      />
      <Box flexBasis="100%">
        <SendInputKeyboard
          onUpdate={handleNumpadInputV2}
          value={primaryAmount}
          exponent={inputCurrency.primary.exponent}
          currencyCode={inputCurrency.primary.code}
          previewButton={keyboardPreviewButtonGroup}
          disabled={!isSubmittable}
        />
      </Box>
      <RecipientTray
        isVisible={isRecipientTrayVisible}
        accountRef={account ?? null}
        onCloseComplete={toggleRecipientTrayOff}
        onEditRecipient={navigateToSendRecipient}
        isVerifiedWallet={isVerifiedWallet}
      />
      <SendAccountSelectorModal
        onAccountChange={handleAccountChange}
        onDismiss={hideAccountSelectorModal}
        visible={isAccountSelectorVisible}
      />
      <TravelRulePrefill />
      <TopUpTray queryRef={query || null} setMaxSend={setMaxSend} />
    </Screen>
  );
});

export function AmountEntryScreen() {
  const { network } = useParams<'AmountEntryScreen'>();
  const dappWalletAddress = useDappWallet()?.walletAddress ?? '';
  const { accountIdField, recipientField } = useFields(Form);
  const isDappWallet = dappWalletAddress === recipientField.value;
  const { isGooglePaySupported, isApplePaySupported } =
    useIsDigitalWalletSupportedContext();
  const paymentMethodsWithMaxAmount = useGetPaymentMethodsWithMaxAmount();

  const query = useLazyLoadQuery<AmountEntryScreenQuery>(
    graphql`
      query AmountEntryScreenQuery(
        $accountId: Uuid!
        $shouldIncludeAccount: Boolean!
        $multichainAction: SendReceiveSupportedNetworksAction!
        $multchainContext: SendReceiveSupportedNetworksApplicationContext!
        $toAddress: String!
        $isGooglePaySupported: Boolean!
        $isApplePaySupported: Boolean!
        $includePaymentMethod: Boolean!
        $paymentMethodId: Uuid!
      ) {
        ...AmountEntryScreenContentFragment
          @arguments(
            accountId: $accountId
            multichainAction: $multichainAction
            multchainContext: $multchainContext
            toAddress: $toAddress
          )
      }
    `,
    {
      shouldIncludeAccount: true,
      accountId: accountIdField.value,
      multichainAction: isDappWallet ? 'RECEIVE' : 'SEND',
      multchainContext: isDappWallet ? 'DEFI' : 'CONSUMER',
      toAddress: recipientField.value ?? '',
      isGooglePaySupported,
      isApplePaySupported,
      includePaymentMethod: paymentMethodsWithMaxAmount.length > 0,
      paymentMethodId: paymentMethodsWithMaxAmount?.[0]?.paymentMethod.id || '',
    },
  );

  return (
    <ScreenBoundary
      fallback={<AmountEntryScreenFallback />}
      instrumentationId="AmountEntryScreen"
    >
      <AmountEntryScreenContent queryRef={query} network={network} />
    </ScreenBoundary>
  );
}

