  },
});

type DestinationTagInputProps = {
  assetRef: DestinationTagInputFragment$key | null;
  onChange?: (text: string) => void;
  initialValue: string;
};
const MEMO_TAG_SUPPORT_URL = `https://help.coinbase.com/${locale}/coinbase/trading-and-funding/sending-or-receiving-cryptocurrency/destination-tag-memo-faq`;
export function DestinationTagInput({
  assetRef,
  onChange,
  initialValue,
}: DestinationTagInputProps) {
  const asset = useFragment(
    graphql`
      fragment DestinationTagInputFragment on Asset {
        destinationTag {
          name
          regex
        }
        displaySymbol
      }
    `,
    assetRef,
  );
  const destinationTag = asset?.destinationTag;
  const assetSymbol = asset?.displaySymbol;
  const { formatMessage } = useIntl();
  const [destinationTagFieldValue, onFieldChange] = useState(
    initialValue || '',
  );
  const [hasError, setHasError] = useState<boolean | undefined>();

  const [isToggled, { toggleOn, toggleOff }] = useToggler(false);
  const [tooltipTrayContent, setTooltipTrayContent] = useState<
    TrayContent | undefined
  >();
  const onTrayInfoPress = useCallback(() => {
    setTooltipTrayContent({
      title: formatMessage(messages.memoTagInfoTrayTitle, {
        assetSymbol: destinationTag?.name ? assetSymbol : null,
      }),
      message: formatMessage(messages.memoTagInfoTrayMessage, {
        assetSymbol: destinationTag?.name ? assetSymbol : null,
      }),
      cta: {
        type: 'link',
        urlOrAction: MEMO_TAG_SUPPORT_URL,
        text: formatMessage(messages.learnMore),
      },
      dismiss: {
        text: formatMessage(messages.memoTagInfoTrayDismiss),
      },
    });
    toggleOn();
  }, [assetSymbol, destinationTag?.name, formatMessage, toggleOn]);

  const handleChange = useCallback(
    (value: string) => {
      // We must imperatively validate this field, because the destination tag regular expression isn't known until runtime.

      onFieldChange(value);
      onChange?.(value);

      if (destinationTag?.regex) {
        const error =
          !regex(new RegExp(destinationTag?.regex))(value) && value !== '';
        setHasError(error);
      }
    },
    [destinationTag, onChange],
  );

  const icon = useMemo(
    () => (
      <Box spacing={2}>
        <TextInputIconButton
          name="info"
          hitSlop={24}
          onPress={onTrayInfoPress}
          size="s"
          color="foregroundMuted"
        />
      </Box>
    ),
    [onTrayInfoPress],
  );

  return (
    <AccessibilityProtection type="write" fieldName="DestinationTag">
      <>
        <TextInput
          accessibilityLabel="Text input field"
          variant={hasError ? 'negative' : undefined}
          value={destinationTagFieldValue}
          helperText={
            hasError ? formatMessage(messages.formatError) : undefined
          }
          end={icon}
          label={
            destinationTag?.name || formatMessage(messages.destinationTagTitle)
          }
          autoCapitalize="none"
          placeholder={destinationTag?.name}
          onChangeText={handleChange}
          testID="DestinationTag"
        />
        <TooltipTray
          hideTray={toggleOff}
          isVisible={isToggled}
          content={tooltipTrayContent}
        />
      </>
    </AccessibilityProtection>
  );
}

