const SendPreviewScreenContent = memo(() => {
  const { recipientLookupName, noteField, recipientField } = useFields(Form);
  const [isToggled, { toggleOn, toggleOff }] = useToggler(false);
  const [tooltipTrayContent, setTooltipTrayContent] = useState<
    TrayContent | undefined
  >();
  const { formatMessage, locale, formatNumber } = useIntl();
  const formatCurrency = useCurrencyFormatter();

  const nativeCurrency = useNativeCurrency();
  const fiatCurrency = useFiatCurrencyStub({
    nativeCurrency,
  });

  const isScamWarningExperimentEnabledForSend =
    useScamWarningOnSendExperiment();

  const HELP_LINK = `https://help.coinbase.com/${locale}/coinbase/privacy-and-security/avoiding-phishing-and-scams/avoiding-cryptocurrency-scams`;

  // Gasless USDC sends experiment values
  // How many free USDC sends per day are authorized
  const FREE_USDC_SENDS_PER_DAY = 5;
  // Maximum amount in dollars per month allocated to gas for free sends
  const MAX_DOLLARS_PER_MONTH_USDC_GAS = '$200';

  const [scrollable, setIsScrollable] = useState(false);
  const [layoutHeight, setLayoutHeight] = useState(0);
  const [isLightiningInvoiceTruncated, setIsLightiningInvoiceTruncated] =
    useState(true);

  const getLayoutHeight = useCallback(
    (e: LayoutChangeEvent) => {
      setLayoutHeight(e.nativeEvent.layout.height);
    },
    [setLayoutHeight],
  );

  const calculateScrollability = useCallback(
    (_contentWidth: number, contentHeight: number) => {
      setIsScrollable(contentHeight > layoutHeight);
    },
    [setIsScrollable, layoutHeight],
  );

  const {
    send: {
      uuid,
      fromAccountUuid,
      sendType,
      network,
      timeEstimation,
      recipientDetails,
      amountFiat,
      amountTotal,
      amountCrypto,
      feeDetailsList,
      blueprintToken,
    },
  } = useParams<'SendPreviewScreen'>();

  const { submit, isSubmitting } = useSendSubmitter({
    uuid,
    fromAccountUuid,
    sendType,
    networkName: network?.name ?? undefined,
    blueprintToken,
  });
  const { viewer } = useLazyLoadQuery<SendPreviewScreenQuery>(
    graphql`
      query SendPreviewScreenQuery(
        $accountUuid: Uuid!
        $address: String!
        $action: SendReceiveSupportedNetworksAction!
        $applicationContext: SendReceiveSupportedNetworksApplicationContext!
      ) {
        viewer @required(action: THROW) {
          accountByUuidV3(uuid: $accountUuid) {
            account {
              assetOrFiatCurrency {
                ... on ViewerAsset {
                  asset {
                    ...useDestinationTagDescriptionAssetFragment
                      @arguments(address: $address)
                    imageUrl
                    exponent
                    platformName
                  }
                  supportedNetworks(
                    action: $action
                    applicationContext: $applicationContext
                  ) {
                    supportedNetworks {
                      networkName
                      isFreeGasEnabled
                      isDefault
                    }
                  }
                }
              }
            }
          }
        }
      }
    `,
    {
      accountUuid: fromAccountUuid,
      address: recipientField.value,
      action: 'SEND',
      applicationContext: 'CONSUMER',
    },
  );

  const accountByUuid = viewer.accountByUuidV3?.account;

  const {
    logSendFlowButtonPress,
    logSendModalRenderEvent,
    logGenericSendReceiveFlowEvent,
  } = useSendReceiveLoggers();

  useFocusEffectAfterInteractions(
    useCallback(() => {
      logSendModalRenderEvent({
        flow: 'send_preview_v2',
        step: 'preview',
        selectedNetwork: network?.name ?? undefined,
      });
      if (isScamWarningExperimentEnabledForSend) {
        logGenericSendReceiveFlowEvent('scam_warning_on_preview_screen', {
          flow: 'send_preview_v2',
          componentType: ComponentType.text,
          action: ActionType.view,
        });
      }
    }, [
      logGenericSendReceiveFlowEvent,
      logSendModalRenderEvent,
      isScamWarningExperimentEnabledForSend,
      network?.name,
    ]),
  );

  const asset = accountByUuid?.assetOrFiatCurrency?.asset;

  const supportedNetworks =
    accountByUuid?.assetOrFiatCurrency?.supportedNetworks?.supportedNetworks ??
    [];
  const assetNetwork = supportedNetworks?.find(
    (supportedNetwork) => supportedNetwork?.networkName === network?.name,
  );

  const hasSeenL2Education = getStoreDataSynchronous(
    P2P_CONTENTFUL_STORE,
    L2_EDUCATION_SEEN_KEY,
    false,
  );

  useOnMount(() => {
    markJourney('loaded_send_preview');
  });

  const isBtcLightningNetwork = useIsBtcLightningNetwork(
    asset?.platformName,
    recipientField.value,
  );

  const handleLightningInvoicePress = useCallback(() => {
    setIsLightiningInvoiceTruncated((prev) => !prev);
  }, []);

  const handlePress = useCallback(() => {
    logSendFlowButtonPress({
      componentName: 'confirm',
      flow: 'send_preview_v2',
      isAssetMultichain: (supportedNetworks.length > 1).toString(),
      isDefaultNetwork: (!!assetNetwork?.isDefault).toString(),
      hasSeenL2Education: hasSeenL2Education.toString(),
      selectedNetwork: network?.name ?? undefined,
    });
    void submit();
  }, [
    logSendFlowButtonPress,
    supportedNetworks.length,
    assetNetwork?.isDefault,
    hasSeenL2Education,
    network?.name,
    submit,
  ]);

  const lightningFee = useContentfulLightningFee();

  const onTrayInfoPress = useCallback(
    (fee: (typeof networkFees)[number]) => {
      logSendFlowButtonPress({
        componentName: 'info',
        flow: 'send_preview_v2',
        selectedNetwork: network?.name ?? undefined,
      });
      switch (fee.type) {
        case 'COINBASE':
          setTooltipTrayContent({
            title: formatMessage(messages.feeTrayTitle),
            message: formatMessage(messages.feeTrayContent, {
              learnMore: (
                <Link testID="TrayLink" variant="body" to={fee.helpUrl}>
                  {formatMessage(messages.learnMore)}
                </Link>
              ),
            }),
            dismiss: {
              text: formatMessage(messages.ok),
            },
          });
          toggleOn();
          break;
        case 'NETWORK':
          if (isBtcLightningNetwork) {
            setTooltipTrayContent({
              title: lightningFee
                ? lightningFee.title
                : formatMessage(messages.processingFee),
              message: lightningFee ? (
                <RichText
                  color="foregroundMuted"
                  contents={lightningFee.content}
                />
              ) : (
                formatMessage(messages.processingFeeContent)
              ),
              dismiss: {
                text: formatMessage(messages.gotIt),
              },
            });
          } else {
            setTooltipTrayContent({
              title: formatMessage(messages.networkFeeTitle),
              message: formatMessage(messages.networkFeeDisclaimer, {
                learnMore: (
                  <Link testID="TrayLink" variant="body" to={fee.helpUrl}>
                    {formatMessage(messages.learnMore)}
                  </Link>
                ),
              }),
              dismiss: {
                text: formatMessage(messages.ok),
              },
            });
          }
          toggleOn();
          break;
        default:
          break;
      }
    },
    [
      formatMessage,
      logSendFlowButtonPress,
      toggleOn,
      isBtcLightningNetwork,
      lightningFee,
      network?.name,
    ],
  );
  const networkFees = useMemo(() => {
    return feeDetailsList.filter((fee) => fee.type !== 'COINBASE');
  }, [feeDetailsList]);

  const destinationTagDescription = useDestinationTagDescription(asset ?? null);

  const formattedFiatAmount = formatCurrency({
    amount: amountTotal?.value,
    currency: {
      code: fiatCurrency.code,
      type: 'fiat',
    },
    isSensitive: false,
  });

  const formattedCryptoSubtitle = formatCurrency({
    amount: amountCrypto.value,
    currency: {
      code: amountCrypto.currency,
      type: 'crypto',
      exponent: asset?.exponent,
    },
    isSensitive: false,
  });

  const gaslessUsdcSendsAreKilled = useGaslessUsdcSendsAreKilled();

  const hasSubsidy = !!networkFees.filter((fee) => !!fee.amountBeforeSubsidy)
    .length;

  const isFreeGasEnabled = useMemo(() => {
    return assetNetwork?.isFreeGasEnabled;
  }, [assetNetwork?.isFreeGasEnabled]);

  const truncatedRecipient = useMemo(() => {
    if (recipientDetails.displayValue) {
      return getEllipsizedString(recipientDetails.displayValue, 6);
    }

    return '';
  }, [recipientDetails.displayValue]);

  const bottomSpaceForSendNowWrapper = useMemo(() => {
    if (isScamWarningExperimentEnabledForSend && !isBtcLightningNetwork) {
      return 0;
    }
    if (scrollable) {
      return 2;
    }
    return 3;
  }, [
    isScamWarningExperimentEnabledForSend,
    scrollable,
    isBtcLightningNetwork,
  ]);

  const { verifiedWalletsMap } = useVerifiedWallets();
  const isVerifiedWallet = !!verifiedWalletsMap[recipientField.value];

  return (
    <Screen
      scrollable={false}
      testID="SendPreviewScreen"
      noSpacing
      spacingHorizontal={0}
    >
      <VStack justifyContent="center" alignItems="center">
        <RemoteImage source={asset?.imageUrl} shape="circle" size="xxl" />
        <HStack gap={0.5} spacingTop={1}>
          <TextTitle2>
            {formatMessage(messages.send, {
              amountFiat: formatNumber(Number(amountFiat?.value)),
            })}
          </TextTitle2>
          <TextTitle2 color="foregroundMuted">{fiatCurrency.code}</TextTitle2>
        </HStack>
        <TextBody color="foregroundMuted">{formattedCryptoSubtitle}</TextBody>
      </VStack>
      <Divider spacingVertical={3} />
      <ScrollView
        scrollEnabled={scrollable}
        onLayout={getLayoutHeight}
        onContentSizeChange={calculateScrollability}
      >
        <VStack
          gap={3}
          justifyContent="flex-start"
          spacingHorizontal={3}
          spacingVertical={2}
        >
          {isBtcLightningNetwork ? (
            <Box>
              <HStack justifyContent="space-between">
                <TextBody>{formatMessage(messages.sendTo)}</TextBody>
                <Pressable
                  accessibilityRole="button"
                  background="transparent"
                  onPress={handleLightningInvoicePress}
                  hitSlop={16}
                >
                  <Icon
                    testID="lightiningInvoiceCaretIcon"
                    size="s"
                    name={
                      isLightiningInvoiceTruncated ? 'caretDown' : 'caretUp'
                    }
                    color="foreground"
                  />
                </Pressable>
              </HStack>
              {isLightiningInvoiceTruncated ? (
                <TextBody
                  color="foregroundMuted"
                  testID="lightningInvoiceTruncated"
                >
                  {truncatedRecipient}
                </TextBody>
              ) : (
                <TextBody color="foregroundMuted" testID="lightningInvoice">
                  {recipientDetails.displayValue}
                </TextBody>
              )}
            </Box>
          ) : (
            <Box>
              <TextBody>{formatMessage(messages.sendTo)}</TextBody>
              {(!!recipientLookupName.value || isVerifiedWallet) && (
                <HStack gap={0.5} alignItems="center" spacingVertical={0.5}>
                  <TextLabel2 color="foreground">
                    {recipientLookupName.value ||
                      formatMessage(messages.verifiedWallet)}
                  </TextLabel2>
                  {isVerifiedWallet && (
                    <Icon name="circleCheckmark" size="xs" color="primary" />
                  )}
                </HStack>
              )}
              <TextBody color="foregroundMuted">
                {recipientDetails.displayValue}
              </TextBody>
              {sendType === 'OFF_CHAIN' && amountFiat !== null && (
                <>
                  <Spacer vertical={2} />
                  <SendDisclaimer
                    spacingBottom={0}
                    fiatValue={amountFiat.value}
                    justifyContent="flex-start"
                  />
                </>
              )}
            </Box>
          )}
          {recipientDetails.destinationTag ? (
            <Box flexDirection="column">
              <TextBody color="foregroundMuted">
                {destinationTagDescription?.name}
              </TextBody>
              <Box flexDirection="row" justifyContent="space-between">
                <TextHeadline>{destinationTagDescription?.name}</TextHeadline>
                <TextBody color="foregroundMuted">
                  {recipientDetails.destinationTag}
                </TextBody>
              </Box>
            </Box>
          ) : null}
          {noteField.value ? (
            <HStack justifyContent="space-between">
              <Box flexDirection="column" spacingEnd={10}>
                <TextBody>{formatMessage(messages.note)}</TextBody>
                <Box flexWrap="wrap" flexDirection="row">
                  <TextBody
                    color="foregroundMuted"
                    ellipsizeMode="tail"
                    numberOfLines={1}
                  >
                    {noteField.value.replace(/\n/g, '').trim()}
                  </TextBody>
                </Box>
              </Box>
            </HStack>
          ) : null}
          {!!network?.name && (
            <Box flexDirection="row" justifyContent="space-between">
              <TextBody>{formatMessage(messages.networkLabel)}</TextBody>
              <TextBody color="foregroundMuted">{network.name}</TextBody>
            </Box>
          )}
          {networkFees.map((fee, i) => (
            <HStack
              // eslint-disable-next-line react/no-array-index-key
              key={i}
              justifyContent="space-between"
              alignItems="baseline"
            >
              <Box
                flexDirection="row"
                justifyContent="center"
                alignItems="center"
              >
                <FeeName
                  isBtcLightningNetwork={isBtcLightningNetwork}
                  feeName={fee.name}
                />
                <TextInputIconButton
                  testID="networkTrayToggle"
                  onPress={() => onTrayInfoPress(fee)}
                  size="s"
                  name="info"
                  color="foregroundMuted"
                />
              </Box>
              <VStack
                flexWrap="wrap"
                justifyContent="flex-end"
                alignItems="flex-end"
              >
                <FeeMessaging
                  gaslessUsdcSendsAreKilled={gaslessUsdcSendsAreKilled}
                  sendType={sendType}
                  feeAmountCurrency={fee.amount.currency}
                  feeAmountValue={fee.amount.value}
                  amountBeforeSubsidy={fee.amountBeforeSubsidy}
                />
              </VStack>
            </HStack>
          ))}
          {!!timeEstimation && (
            <Box flexDirection="row" justifyContent="space-between">
              <TextBody>{formatMessage(messages.estimatedSendTime)}</TextBody>
              <Box maxWidth="55%">
                <TextBody color="foregroundMuted">{timeEstimation}</TextBody>
              </Box>
            </Box>
          )}
          <Box flexDirection="row" justifyContent="space-between">
            <TextHeadline>{formatMessage(messages.total)}</TextHeadline>
            <TextHeadline>{formattedFiatAmount}</TextHeadline>
          </Box>

          {amountCrypto.currency === 'USDC' &&
          !gaslessUsdcSendsAreKilled &&
          !hasSubsidy &&
          isFreeGasEnabled &&
          sendType === 'ON_CHAIN' ? (
            <HStack spacingTop={3} spacingEnd={3}>
              <Box spacingEnd={1} spacingTop={1}>
                <Icon name="info" size="s" color="foreground" />
              </Box>
              <TextLabel2>
                {formatMessage(messages.maxUsdcSends, {
                  freeSendsPerDay: FREE_USDC_SENDS_PER_DAY,
                  dollarGasPerMonth: MAX_DOLLARS_PER_MONTH_USDC_GAS,
                })}
              </TextLabel2>
            </HStack>
          ) : null}
        </VStack>
      </ScrollView>
      <TooltipTray
        hideTray={toggleOff}
        isVisible={isToggled}
        content={tooltipTrayContent}
      />
      <Spacer vertical={0.5} />
      {scrollable ? <Divider spacingBottom={2} /> : null}
      <Box
        testID="SendPreviewSendButtonWrapper"
        spacingHorizontal={2}
        spacingBottom={bottomSpaceForSendNowWrapper}
      >
        <Button
          onPress={handlePress}
          loading={isSubmitting}
          disabled={isSubmitting}
        >
          {formatMessage(messages.sendNow)}
        </Button>
      </Box>
      {isScamWarningExperimentEnabledForSend && !isBtcLightningNetwork && (
        <Box
          alignItems="center"
          spacingHorizontal={2}
          spacingBottom={scrollable ? 5 : 6}
        >
          <TextLegal color="foregroundMuted">
            {formatMessage(messages.scamWarning, {
              learnMore: (
                <Link testID="SendPreviewScamWarningLearnMore" to={HELP_LINK}>
                  {formatMessage(messages.learnMore)}
                </Link>
              ),
            })}
          </TextLegal>
        </Box>
      )}
    </Screen>
  );
});

