import { useIsCoinbaseWallet } from '@app/hooks/menu/useConnectedCBWallets';
import { Form } from '@app/screens/Send/components/SendForm/SendFormProvider';
import { getEllipsizedString } from '@app/screens/Send/utils/contactUtils';

import { useVerifiedWallets } from '../hooks/useVerifiedWallets';

import { SendPreviewScreenRecipientDetailsViewerAssetFragment$key } from './__generated__/SendPreviewScreenRecipientDetailsViewerAssetFragment.graphql';

const i18nKey = 'SendPreviewScreenRecipientDetails';

const messages = defineMessages({
  sendTo: {
    id: `${i18nKey}.sendTo`,
    defaultMessage: 'To',
    description: 'label for the recipient of the transaction',
  },
  verifiedWallet: {
    id: `${i18nKey}.verifiedWallet`,
    defaultMessage: 'Verified wallet',
    description: 'Verified wallet label',
  },
});

type SendPreviewScreenRecipientDetailsProps = {
  viewerAssetRef: SendPreviewScreenRecipientDetailsViewerAssetFragment$key | null;
  recipientDisplayValue: string;
  network: string;
  isCoinbaseWallet?: boolean;
};

function SendPreviewScreenRecipientDetails({
  recipientDisplayValue,
  network,
  viewerAssetRef,
}: SendPreviewScreenRecipientDetailsProps) {
  const viewerAsset = useFragment(
    graphql`
      fragment SendPreviewScreenRecipientDetailsViewerAssetFragment on ViewerAsset {
        ...useConnectedCBWalletsFragment
      }
    `,
    viewerAssetRef,
  );
  const { formatMessage } = useIntl();
  const { recipientLookupName, recipientField } = useFields(Form);
  const { verifiedWalletsMap } = useVerifiedWallets();
  const [isLightiningInvoiceTruncated, setIsLightiningInvoiceTruncated] =
    useState(true);
  const isBtcLightningNetwork = network === 'Lightning';

  const isVerifiedWallet = !!verifiedWalletsMap[recipientField.value];

  const truncatedRecipient = useMemo(() => {
    if (recipientDisplayValue) {
      return getEllipsizedString(recipientDisplayValue);
    }

    return '';
  }, [recipientDisplayValue]);

  const cbWallet = useIsCoinbaseWallet(
    viewerAsset ?? null,
    recipientDisplayValue,
  );

  const shouldShowKnownName =
    !!recipientLookupName.value || isVerifiedWallet || cbWallet?.walletAddress;

  const handleLightningInvoicePress = useCallback(() => {
    setIsLightiningInvoiceTruncated((prev) => !prev);
  }, []);

  if (isBtcLightningNetwork) {
    return (
      <HStack spacingBottom={2} width="100%" justifyContent="space-between">
        <TextBody>{formatMessage(messages.sendTo)}</TextBody>
        <HStack
          width="85%"
          gap={0.5}
          justifyContent="flex-end"
          alignItems={isLightiningInvoiceTruncated ? 'center' : 'flex-start'}
        >
          {isLightiningInvoiceTruncated ? (
            <TextBody color="foreground" testID="lightningInvoiceTruncated">
              {truncatedRecipient}
            </TextBody>
          ) : (
            <TextBody
              align="end"
              color="foregroundMuted"
              testID="lightningInvoice"
            >
              {recipientDisplayValue}
            </TextBody>
          )}
          <Pressable
            accessibilityRole="button"
            background="transparent"
            onPress={handleLightningInvoicePress}
            hitSlop={16}
            testID="lightiningInvoiceCaretIconButton"
          >
            <Icon
              accessibilityHint="lightining Invoice Caret Icon"
              accessibilityLabel="lightining Invoice Caret Icon"
              testID="lightiningInvoiceCaretIcon"
              size="s"
              name={isLightiningInvoiceTruncated ? 'caretDown' : 'caretUp'}
              color="foreground"
            />
          </Pressable>
        </HStack>
      </HStack>
    );
  }

  return (
    <HStack
      spacingBottom={2}
      justifyContent="space-between"
      alignItems="flex-start"
    >
      <TextBody>{formatMessage(messages.sendTo)}</TextBody>
      <VStack width={shouldShowKnownName ? '75%' : '85%'}>
        {shouldShowKnownName && (
          <HStack
            gap={0.5}
            justifyContent="flex-end"
            alignItems="center"
            testID="RecipientDetailsKnownVerifiedContainer"
          >
            <TextBody color="foreground">
              {recipientLookupName.value ||
                cbWallet?.appInfo.name ||
                formatMessage(messages.verifiedWallet)}
            </TextBody>
            {isVerifiedWallet && (
              <Icon
                accessibilityHint="Verified Wallet Icon"
                accessibilityLabel="Verified Wallet Icon"
                name="circleCheckmark"
                size="xs"
                color="primary"
                testID="VerifiedWalletIcon"
              />
            )}
          </HStack>
        )}
        <TextBody
          align="end"
          color={shouldShowKnownName ? 'foregroundMuted' : 'foreground'}
        >
          {shouldShowKnownName
            ? getEllipsizedString(recipientDisplayValue)
            : recipientDisplayValue}
        </TextBody>
      </VStack>
    </HStack>
  );
}

