import { forwardRef, useCallback, useImperativeHandle, useState } from 'react';
import { Keyboard, NativeModules, Platform } from 'react-native';
import { ScrollView } from 'react-native-gesture-handler';
import { FieldProps } from '@cb/forms';
import { gutter } from '@cbhq/cds-common/tokens/sizing';
import { useToggler } from '@cbhq/cds-mobile';
import { Box, Divider, VStack } from '@cbhq/cds-mobile/layout';
import { TextLabel1 } from '@cbhq/cds-mobile/typography';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { InputVariant } from '@designSystem/types';

import { SettingCell } from '@components/cells/SettingCell';
import { Button } from '@components/interactables/Button';
import { TextInput } from '@components/interactables/TextInput';
