import { CountryOfResidenceField } from '@app/components/TravelRules/CountryOfResidenceField';
import {
  defaultGoogleMapsConfig,
  GoogleMapsApiClient,
  IGoogleMapsAutocompletePrediction,
  LanguageISOCode,
  normalizeAddressComponents,
} from '@app/screens/Send/utils/GoogleMapsApiClient';

const i18nKey = 'AddressInputField';
const messages = defineMessages({
  addAddressManually: {
    id: `${i18nKey}.addAddressManually`,
    defaultMessage: 'Add address manually',
    description: 'add address manually link',
  },
  suggestions: {
    id: `${i18nKey}.suggestions`,
    defaultMessage: 'Suggestions',
    description: 'Suggestions list title',
  },
  continue: {
    id: `${i18nKey}.continue`,
    defaultMessage: 'Continue',
    description: 'Continue Button',
  },
});

export type AddressInputFieldProps = {
  label: string;
  modalTitle: string;
  fields: {
    address1: FieldProps<string>;
    address2: FieldProps<string>;
    address3: FieldProps<string>;
    city: FieldProps<string>;
    state: FieldProps<string>;
    country: FieldProps<string>;
    postcode: FieldProps<string>;
  };
  labels: {
    address1: string;
    address2: string;
    address3: string;
    city: string;
    state: string;
    country: string;
    postcode: string;
  };
  deviceLocale: string;
  variant?: InputVariant;
};

export type AddressRef = {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  setAddressSummary: (value: any) => void;
};

export const AddressField = forwardRef<AddressRef, AddressInputFieldProps>(
  ({ label, modalTitle, fields, labels, deviceLocale, variant }, ref) => {
    const { formatMessage } = useIntl();
    const { tapped } = useAnalytics();
    const [addressLookup, setAddressLookup] = useState('');
    const [isModalVisible, { toggleOn, toggleOff }] = useToggler(false);
    const [suggestions, setSuggestions] = useState<
      IGoogleMapsAutocompletePrediction[]
    >([]);
    const [googleMapsApiClient] = useState(
      () =>
        new GoogleMapsApiClient({
          ...defaultGoogleMapsConfig,
        }),
    );

    useImperativeHandle(ref, () => ({
      setAddressSummary: (value) => setAddressLookup(value),
    }));

    const lookupSuggestions = useCallback(
      async (text: string) => {
        const googleSuggestions = await googleMapsApiClient.autocomplete({
          input: text,
          country: deviceLocale || 'US',
          language: getDeviceLanguage(),
        });

        if (googleSuggestions.type === 'failure') {
          fields.address1.onChange(text);
          setSuggestions([]); // todo: maybe log this failure
        } else {
          setSuggestions(googleSuggestions.data.predictions);
        }
      },
      [deviceLocale, fields, googleMapsApiClient],
    );

    const lookupSuggestionsDebounced = useDebouncedCallback(lookupSuggestions);

    const handleAddressChange = useCallback(
      (text: string) => {
        fields.address1.onChange(text);
        setAddressLookup(text);
        void lookupSuggestionsDebounced(text);
      },
      [setAddressLookup, lookupSuggestionsDebounced, fields.address1],
    );

    const handleItemSelect = useCallback(
      async (item: IGoogleMapsAutocompletePrediction) => {
        tapped('address_search_result');
        const detailsResponse = await googleMapsApiClient.details({
          placeId: item.placeId,

          language: getDeviceLanguage(),
        });

        if (detailsResponse.type === 'failure') {
          fields.address1.onChange(addressLookup);

          return;
        }

        const addressComponents = normalizeAddressComponents(
          detailsResponse.data.result.addressComponents,
        );

        fields.address1.onChange(
          addressComponents.address1 || fields.address1.value || '',
        );

        fields.address2.onChange(addressComponents.address2 || '');

        fields.address3.onChange(addressComponents.address3 || '');
        fields.city.onChange(addressComponents.city || '');

        fields.state.onChange(addressComponents.state || '');

        fields.country.onChange(addressComponents.countryCode || '');

        fields.postcode.onChange(addressComponents.zip || '');

        setAddressLookup(item.structuredFormatting.mainText);
        setSuggestions([]);

        Keyboard.dismiss();
      },
      [fields, addressLookup, googleMapsApiClient, tapped],
    );

    const getDeviceLanguage = () => {
      return (
        Platform.OS === 'ios'
          ? NativeModules.SettingsManager.settings.AppleLocale ||
            NativeModules.SettingsManager.settings.AppleLanguages[0] // iOS 13
          : NativeModules.I18nManager.localeIdentifier
      ).slice(0, 2) as LanguageISOCode;
    };

    const clearSearch = () => {
      setAddressLookup('');
      fields.address1.onChange('');
      fields.address2.onChange('');
      fields.address3.onChange('');
      fields.city.onChange('');
      fields.state.onChange('');
      fields.country.onChange('');
      fields.postcode.onChange('');
      setSuggestions([]);
    };

    const fillAddressOnClose = () => {
      setAddressLookup(
        `${fields.address1.value}${
          fields.address2.value ? `, ${fields.address2.value}` : ''
        }${fields.address3.value ? `, ${fields.address3.value}` : ''}`,
      );
      toggleOff();
    };

    const handleAddressSelectDebounced = useDebouncedCallback(handleItemSelect);
    const handleCountrySelect = fields.country.onChange;

    return (
      <>
        <VStack>
          <TextInput
            accessibilityLabel="Text input field"
            autoFocus
            name="address"
            label={label}
            value={addressLookup}
            onChange={handleAddressChange}
            isDirty
            onErrors={() => {}}
            errors={[]}
            returnKeyType="done"
            variant={variant}
            endContent={
              <TextInputIconButton
                color="foregroundMuted"
                name="close"
                onPress={clearSearch}
              />
            }
          />
          <VStack spacing={0} flexGrow={1}>
            {!!suggestions.length && (
              <>
                <TextLabel1 spacingBottom={0.5}>
                  {formatMessage(messages.suggestions)}
                </TextLabel1>
                <VStack offsetHorizontal={gutter}>
                  <Divider />
                </VStack>
              </>
            )}
            <VStack spacing={0} flexGrow={1}>
              <FlatList
                data={[...suggestions]}
                keyboardDismissMode="on-drag"
                renderItem={({ item }) => {
                  const { structuredFormatting } = item;

                  return (
                    <>
                      <SettingCell
                        spacingVertical={0}
                        spacingHorizontal={gutter}
                        caret
                        onPress={async () => handleAddressSelectDebounced(item)}
                        title={structuredFormatting.mainText}
                        subtitle={
                          structuredFormatting
                            ? structuredFormatting.secondaryText
                            : null
                        }
                      />
                      <Divider spacingBottom={1} />
                    </>
                  );
                }}
              />
            </VStack>
          </VStack>
          <Box alignSelf="flex-end" spacingBottom={2}>
            <Link variant="label1" onPress={toggleOn}>
              {formatMessage(messages.addAddressManually)}
            </Link>
          </Box>
        </VStack>
        <Modal
          visible={isModalVisible}
          title={modalTitle}
          onRequestClose={() => {
            fillAddressOnClose();
          }}
        >
          <ScrollView>
            <KeyboardAvoidingView>
              <VStack justifyContent="space-between" height="100%">
                <VStack gap={2}>
                  <TextInput {...fields.address1} label={labels.address1} />
                  <TextInput {...fields.address2} label={labels.address2} />
                  <TextInput {...fields.address3} label={labels.address3} />
                  <TextInput {...fields.city} label={labels.city} />
                  <TextInput {...fields.state} label={labels.state} />
                  <TextInput {...fields.postcode} label={labels.postcode} />
                  <CountryOfResidenceField
                    label={labels.country}
                    onCountrySelect={handleCountrySelect}
                    selectedCountryCode={fields.country.value}
                  />
                </VStack>
                <Button
                  spacingTop={2}
                  testID="ModalContinueButton"
                  variant="primary"
                  onPress={fillAddressOnClose}
                >
                  {formatMessage(messages.continue)}
                </Button>
              </VStack>
            </KeyboardAvoidingView>
          </ScrollView>
        </Modal>
      </>
    );
  },
);

