    contact,
    type,
    isRecents,
    size: iconSize = 'xs',
    image,
    ensAvatarUrl,
  } = props;
  const size = useScaleConditional(image ? imageSize : mediaSize);

  const iconColor = 'secondaryForeground';

  const getContactIcon = (): React.ReactNode => {
    if (type === 'saveContact') {
      return (
        <Icon
          testID="saveContactIcon"
          size={iconSize}
          name="add"
          color={iconColor}
        />
      );
    }
    if (type === 'favorite') {
      return (
        <Icon
          testID="favoriteIcon"
          size={iconSize}
          name="starActive"
          color={iconColor}
        />
      );
    }

    if (ensAvatarUrl) {
      return <CellMedia type="avatar" source={ensAvatarUrl} />;
    }

    if (isRecents && (type === 'email' || type === 'crypto')) {
      return type === 'email' ? (
        <Icon
          testID="emailIcon"
          size={iconSize}
          name="email"
          color={iconColor}
        />
      ) : (
        <Icon
          testID="cryptoIcon"
          size={iconSize}
          name="wallet"
          color={iconColor}
        />
      );
    }

    return initial ? (
      <TextLabel2 align="center" color={iconColor} testID="contactInitial">
        {initial}
      </TextLabel2>
    ) : (
      <Icon
        testID="defaultIcon"
        size={iconSize}
        name="profile"
        color={iconColor}
      />
    );
  };

  if (contact?.hasThumbnail) {
    return (
      <CellMedia
        type="avatar"
        source={contact.thumbnailPath}
        accessibilityLabel=""
      />
    );
  }

  const initial = contact && getInitials(contact);
  return (
    <ThemeProvider name="send-contacts-icon" palette={sendContactsIconPalette}>
      <Box
        testID="contactPlaceholder"
        justifyContent="center"
        alignItems="center"
        borderRadius="roundedFull"
        background="backgroundAlternate"
        height={size}
        width={size}
      >
        {getContactIcon()}
      </Box>
    </ThemeProvider>
  );
});

