export type AuthDappDetails = {
  dappName?: string;
  dappUrl?: string;
  dappIconUrl?: string;
  web3Params: {
    call: Web3Call;
    onResponse: OnWeb3CallResponse;
    wallet: Wallet;
  };
};

type AutoConnectAuthTrayContentProps = {
  dismiss: (
    dismissedFromApprove?: boolean,
    shouldHandleNetworkError?: boolean,
    dialogDetails?: { call: Web3Call; onResponse: OnWeb3CallResponse },
  ) => void;
  dappDetails: AuthDappDetails;
};

const dappIconSize = 50;

function AutoConnectAuthTrayContent({
  dismiss,
  dappDetails,
}: AutoConnectAuthTrayContentProps) {
  const { formatMessage } = useIntl();

  const {
    dappName = formatMessage(messages.unknownDappName),
    dappUrl = formatMessage(messages.unknownDappUrl),
    dappIconUrl,
    web3Params,
  } = dappDetails;

  const safeParsedHostname = useMemo(
    () => safeParseUrl(dappUrl).hostname,
    [dappUrl],
  );

  const [autoConnectStatus, setAutoConnectStatus] = useState<boolean>(false);

  const {
    clearManualAuthorizedDapps,
    setAutoConnectSetting,
    setManualAuthorizationsStore,
  } = useBrowserSettingsManager();

  const clearAuthorizations = useCallback(() => {
    // clear list of authorized dapps if the user switched auto-connect from on to off
    if (autoConnectStatus) {
      clearManualAuthorizedDapps();
    }
  }, [autoConnectStatus, clearManualAuthorizedDapps]);

  const handleSwitch = useCallback(() => {
    trackDefiClick({
      flow: 'browser_settings_change',
      step: '1a_toggle_auto_connect',
      otherParams: { auto_connect_mode: autoConnectStatus ? 'off' : 'on' },
    });

    setAutoConnectSetting(!autoConnectStatus);
    clearAuthorizations();
    setAutoConnectStatus((prevState) => !prevState);
  }, [autoConnectStatus, setAutoConnectSetting, clearAuthorizations]);

  const authorizeDapp = useCallback(() => {
    void requestEthereumAccounts(web3Params);
    setManualAuthorizationsStore(dappName);

    // dismiss and allow the user to connect regardless of success of setting
    // user's manual auth store, as this will ensure they're still able to connect
    // if they want to
    dismiss(true);
    trackDefiClick({
      flow: 'browser_settings_change',
      step: '3_auto_connect_dapp_connection_authorized',
      otherParams: {
        requestingDappUrl: safeParsedHostname,
      },
    });
  }, [
    web3Params,
    setManualAuthorizationsStore,
    dappName,
    dismiss,
    safeParsedHostname,
  ]);

  const rejectDapp = useCallback(() => {
    setAutoConnectSetting(false);
    dismiss(false, true, {
      call: web3Params.call,
      onResponse: web3Params.onResponse,
    });
  }, [dismiss, setAutoConnectSetting, web3Params.call, web3Params.onResponse]);

  useEffect(() => {
    trackDefiTrayView({
      flow: 'browser_settings_change',
      step: '2_auto_connect_auth_tray_opened',
      otherParams: {
        requestingDappUrl: safeParsedHostname,
      },
    });
  }, [safeParsedHostname]);

  return (
    <VStack gap={4} testID="autoConnectAuthTray">
      <HStack gap={3}>
        <DAppIcon
          iconImageUrl={dappIconUrl ?? getUrlFavicon(dappUrl)}
          size={dappIconSize}
        />
        <VStack justifyContent="center" flexShrink={1} flexGrow={1}>
          <TextTitle3>
            {formatMessage(messages.connectToDapp, {
              dappName,
            })}
          </TextTitle3>
          <TextLabel2 color="foregroundMuted">{safeParsedHostname}</TextLabel2>
        </VStack>
      </HStack>
      <VStack gap={3}>
        <TextLabel1>{formatMessage(messages.allowDappTxt)}</TextLabel1>
        <HStack alignItems="center" gap={2} spacingEnd={2}>
          <Icon name="checkmark" size="s" color="positive" />
          <TextLabel2>
            {formatMessage(messages.dappConnectionPermissionText)}
          </TextLabel2>
        </HStack>
        <HStack alignItems="center" gap={2} spacingEnd={2}>
          <Icon name="checkmark" size="s" color="positive" />
          <TextLabel2>
            {formatMessage(messages.sendTxReqPermissionText)}
          </TextLabel2>
        </HStack>
        <HStack alignItems="center" gap={2} spacingEnd={2}>
          <Icon name="close" size="s" color="negative" />
          <TextLabel2>{formatMessage(messages.moveCryptoNFTsReq)}</TextLabel2>
        </HStack>
        <HStack>
          <CheckBox value={autoConnectStatus} onPress={handleSwitch} />
          <TextLabel2 spacingStart={1}>
            {formatMessage(messages.autoConnect)}
          </TextLabel2>
        </HStack>
      </VStack>
      <VStack>
        <ButtonGroup accessibilityLabel="Group" block>
          <Button
            onPress={rejectDapp}
            variant="secondary"
            testID="autoConnectAuthTrayRejectButton"
          >
            {formatMessage(messages.denyButton)}
          </Button>
          <Button
            onPress={authorizeDapp}
            testID="autoConnectAuthTrayAuthorizeButton"
          >
            {formatMessage(messages.connectButton)}
          </Button>
        </ButtonGroup>
      </VStack>
    </VStack>
  );
}

export type AuthTrayParams = Web3Call & {
  call: Web3Call;
  onResponse: OnWeb3CallResponse;
  wallet: Wallet;
  onDismiss: (
    dismissedFromApprove?: boolean,
    shouldHandleNetworkError?: boolean,
    dialogDetails?: { call: Web3Call; onResponse: OnWeb3CallResponse },
  ) => void;
  dappHostName: string;
  dappName: string;
  dappIconUrl: string;
  metadata?: {
    dappUrl: string;
    dappSlug: string;
  };
};

export const AutoConnectAuthTray = memo(
  (authTrayParams: ConfirmationDialogProps<AuthTrayParams>) => {
    const {
      data: {
        call,
        onResponse,
        wallet,
        onDismiss,
        dappName,
        dappHostName,
        dappIconUrl,
      },
    } = authTrayParams;

    const dappDetails = {
      dappName: dappName || authTrayParams.dappName,
      dappUrl: dappHostName || authTrayParams.dappHostName,
      dappIconUrl,
      web3Params: { call, onResponse, wallet },
    };

    const CustomAutoConnectAuthFallback = useCallback(
      () => (
        <AutoConnectAuthFallback
          web3Params={dappDetails.web3Params}
          onDismiss={onDismiss}
        />
      ),
      [dappDetails.web3Params, onDismiss],
    );

    return (
      <NetworkBoundary
        suspenseFallback={
          <AutoConnectAuthFallback
            web3Params={dappDetails.web3Params}
            onDismiss={onDismiss}
          />
        }
        errorFallback={CustomAutoConnectAuthFallback}
        willErrorBlockUser
      >
        <AutoConnectAuthTrayContent
          dismiss={onDismiss}
          dappDetails={dappDetails}
        />
      </NetworkBoundary>
    );
  },
);

