function CashSettings() {
  const { nativeCurrency, includeDefiBalances } = useAssetsScreenQueryParams();
  const countryCode = useCachedCountryCode();
  const hasAssetCurrentBalanceV2Migration =
    useAssetCurrentBalanceV2MigrationExperiment();

  const query = useLazyLoadQuery<CashSettingsQuery>(
    graphql`
      query CashSettingsQuery(
        $assetId: Uuid!
        $nativeCurrency: TickerSymbol!
        $includeDefiBalances: Boolean!
        $includeTestNetworks: Boolean!
        $includeUnsupportedNetworks: Boolean!
        $country: CountryCode!
        $skipAssetCurrentBalanceV2: Boolean!
      ) {
        ...useFiatAssetsWithUsdcFragment
          @arguments(usdcAssetId: $assetId, country: $country)
        viewer @required(action: THROW) {
          assetByUuid(uuid: $assetId) @required(action: THROW) {
            rewardApy {
              formattedValue
              statsLabel
            }
          }
        }
      }
    `,
    {
      assetId: USDC_ASSET_ID,
      nativeCurrency,
      includeDefiBalances,
      includeTestNetworks: false,
      includeUnsupportedNetworks: false,
      country: countryCode,
      skipAssetCurrentBalanceV2: !hasAssetCurrentBalanceV2Migration,
    },
  );

  const { viewer } = query;
  const { formatMessage } = useIntl();
  const toast = useToast();
  const [isSingleBalance] = useState(false); // TODO: get this initial setting value from backend https://jira.coinbase-corp.com/browse/CSTBL-287

  const stableAssets = useFiatAssetsWithUsdc(query);
  const usdcAsset = stableAssets.find(
    (asset) => asset.currency.code === 'USDC',
  );
  const fiatAsset = stableAssets.find((asset) => asset.currency.code === 'USD');

  const handleSwitchChange = useCallback(() => {
    // TODO: Integrate BE mutation https://jira.coinbase-corp.com/browse/CSTBL-287
    toast.show(formatMessage(messages.setAsCash), {
      duration: 3000,
    });
  }, [formatMessage, toast]);

  const rewardsLabel = useMemo(() => {
    if (!viewer.assetByUuid.rewardApy) return null;

    return (
      <TextLabel2 color="positive">
        {`${viewer.assetByUuid.rewardApy.formattedValue} ${viewer.assetByUuid.rewardApy.statsLabel}`}
      </TextLabel2>
    );
  }, [viewer.assetByUuid.rewardApy]);

  const hasFiatToConvert = Number(fiatAsset?.convertedBalance.amount) > 0;

  const navigation = useNavigation();
  const isInAdvancedMode = useIsInAdvancedMode();
  const handleContinueOptIn = useCallback(() => {
    navigateToDestination(
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      navigation as StackNavigationProp<ParamList, any>,
      usdcSingleCashBalanceDestination({}),
      { isInAdvancedMode },
    );
  }, [isInAdvancedMode, navigation]);

  if (hasFiatToConvert && !isSingleBalance) {
    return (
      <VStack gap={1}>
        <TextHeadline>{formatMessage(messages.subheading)}</TextHeadline>

        <TextLabel2 color="foregroundMuted">
          {formatMessage(messages.toUseUsdc)}
        </TextLabel2>

        <Button onPress={handleContinueOptIn} spacingTop={2}>
          {formatMessage(messages.continueToConvert)}
        </Button>
      </VStack>
    );
  }

  return (
    <VStack gap={1}>
      <TextHeadline>{formatMessage(messages.subheading)}</TextHeadline>

      <TextLabel2 color="foregroundMuted">
        {formatMessage(messages.usdcReplacesUsd)}
      </TextLabel2>

      <ListCell
        title={usdcAsset?.currency.name}
