type IsPush2FAFlowParams = {
  preferenceType: NotificationPreferenceType;
  isPush2FAFlow?: boolean;
};

function checkIfPush2FAFlow({
  isPush2FAFlow,
  preferenceType,
}: IsPush2FAFlowParams) {
  return isPush2FAFlow && preferenceType === 'SECURITY_ALERTS_TYPE';
}

function ChannelPreferences() {
  const { formatMessage } = useIntl();
  const { preferenceType, isPush2FAFlow: isPush2FAFlowParam } =
    useParams<'ChannelPreferences'>();
  const isPush2FAFlow = checkIfPush2FAFlow({
    preferenceType,
    isPush2FAFlow: isPush2FAFlowParam,
  });

  const [warningDismissed, { toggleOn: toggleWarningDimiss }] =
    useToggler(false);

  const isSettingExperiment = useNotificationSettingsExperiment();
  const hasAdvancedNotifications = useAdvancedNotifications();

  const isSecurityAlerts = preferenceType === 'SECURITY_ALERTS_TYPE';
  const isAdvancedTransactionNotif =
    preferenceType === 'ADVANCED_TRANSACTION_TYPE';

  const countryCode = useCachedCountryCode();

  const isSmsSecurityChangesExperimentEnabled =
    useNotificationExperiment(
      Experiments.mar_2024_notifications_setting_sms_security_changes,
      countryCode !== 'US',
    ) === 'treatment' &&
    isSecurityAlerts &&
    countryCode === 'US';

  const query = useLazyLoadQuery<ChannelPreferencesScreenQuery>(
    graphql`
      query ChannelPreferencesScreenQuery {
        ...useNotificationPreferencesFragment
        ...CustomPriceAlertsSettingsListFragment
        ...CPATrayToTrayFlowQuery
      }
    `,
    {},
  );

  const { preferences } = useNotificationPreferences(query);
  if (preferences === undefined) {
    throw new GraphQLMissingDataError();
  }

  const preference = useMemo(() => {
    return preferences.find((p) => p.type === preferenceType);
  }, [preferenceType, preferences]);

  const getPreferenceSettingsTitle = useCallback(
    (name: string, type: string) => {
      switch (type) {
        case 'SECURITY_ALERTS_TYPE':
          return formatMessage(messages.securityAlertsSettings);
        case 'ACCOUNT_ACTIVITY_TYPE':
          return formatMessage(messages.accountActivitySettings);
        case 'PRICE_ALERTS_TYPE':
          return formatMessage(messages.priceAlertsSettings);
        case 'NEWS_TYPE':
          return formatMessage(messages.newsSettings);
        case 'PRODUCT_ANNOUNCEMENTS_TYPE':
          return formatMessage(messages.productAnnouncementsSettings);
        case 'TRADING_INSIGHTS_TYPE':
          return formatMessage(messages.tradingInsightsSettings);
        case 'ADVANCED_TRANSACTION_TYPE':
          return formatMessage(messages.advancedTransactions);
        case 'CFTC_FUTURES_TYPE':
          return formatMessage(messages.futuresLiquidationsSettings);
        case 'USER_CUSTOMIZABLE_ALERTS':
          return formatMessage(messages.userCustomizeAbleAlertsSettings);
        default:
          return formatMessage(messages.categorySettings, {
            categoryName: name,
          });
      }
    },
    [formatMessage],
  );

  if (preference === undefined) {
    throw new GraphQLMissingDataError();
  }

  const {
    preference: preferenceProps,
    recommendedChannel,
    inactiveMessage,
  } = useNotificationSettingsProps(
    {
      ...preference,
      subPreferences: preference.subPreferences.map((subPreference) => ({
        ...subPreference,
        type: subPreference.type || '', // Ensure type is always a string
      })),
    },
    countryCode ?? undefined,
  );

  const navHeader = {
    title: getPreferenceSettingsTitle(
      preferenceProps.name,
      preferenceProps.type,
    ),
    bordered: false,
    action: 'back' as const,
    ...(isPush2FAFlow ? { leading: null } : {}),
  };

  const warningBanner = useMemo(() => {
    if (!recommendedChannel || !inactiveMessage) {
      return null;
    }

    const foundChannel = preferenceProps.channelPreferences.find(
      (p) => p.channel === recommendedChannel,
    );
    if (foundChannel && !foundChannel.enabled) {
      return (
        <WarningBanner
          title={`${formatMessage(messages.recommendTitle, {
            channelLabel: foundChannel.name,
          })}`}
          description={inactiveMessage.replace('・', '')}
          onDismissBanner={toggleWarningDimiss}
        />
      );
    }

    return null;
  }, [
    formatMessage,
    inactiveMessage,
    preferenceProps.channelPreferences,
    recommendedChannel,
    toggleWarningDimiss,
  ]);

  const previewNotification = preference.notificationPreview;

  const disclaimerLink1 = useCallback(
    (text: string[]) => (
      <Link to="https://www.coinbase.com/legal/user_agreement" underline>
        {text}
      </Link>
    ),
    [],
  );

  const disclaimerLink2 = useCallback(
    (text: string[]) => (
      <Link to="https://www.coinbase.com/legal/privacy" underline>
        {text}
      </Link>
    ),
    [],
  );

  // skipping tracking since the backend is already firing an expsoure if the user is in treatment and will
  // return the category in the response
  const isCpaEnabled = useCustomPriceAlertsExperiment(true);

  if (isSettingExperiment) {
    return (
      <Screen navHeader={navHeader} height="100%" scrollable={false} noSpacing>
        <ScrollableView>
          {!warningDismissed && warningBanner}
          <Box>
            <TextTitle3 spacingTop={2} spacingBottom={1}>
              {formatMessage(messages.preferences)}
            </TextTitle3>
            <TextBody color="foregroundMuted" spacingBottom={2}>
              {preference.description}
            </TextBody>
            <TextBody color="foregroundMuted" spacingBottom={2}>
              {formatMessage(messages.tellUsHow)}
            </TextBody>

            <ChannelToggleList
              preference={preferenceProps}
              recommendedChannel={recommendedChannel}
            />
            {hasAdvancedNotifications && (
              <SubPreferenceToggleList
                preferenceName={preferenceProps.type}
                subPreferences={preference.subPreferences}
              />
            )}
          </Box>
          {isSmsSecurityChangesExperimentEnabled && (
            <Box spacingTop={1}>
              <TextLegal color="foregroundMuted" spacingBottom={2}>
                {formatMessage(messages.smsSecurityAlertsTextDisclaimer, {
                  Link1: disclaimerLink1,
                  Link2: disclaimerLink2,
                })}
              </TextLegal>
            </Box>
          )}
          {preferenceProps.type === 'USER_CUSTOMIZABLE_ALERTS' &&
            isCpaEnabled && (
              <Box spacingTop={2}>
                <TextTitle3 spacingBottom={1}>
                  {formatMessage(customPriceAlertMessages.cpaTitle)}
                </TextTitle3>
                <TextBody color="foregroundMuted" spacingBottom={2}>
                  {formatMessage(customPriceAlertMessages.manageYourAlerts)}
                </TextBody>

                <CustomPriceAlertsSettingsList queryRef={query} />
                <Box spacingTop={2}>
                  <CPATrayToTrayFlow
                    queryRef={query}
                    compact
                    variant="secondary"
                  />
                </Box>
              </Box>
            )}
          {previewNotification && !isAdvancedTransactionNotif && (
            <Box
              spacingTop={isSmsSecurityChangesExperimentEnabled ? 2 : 8}
              testID="channel-preferences-notification-preview"
            >
              <TextTitle3 spacingBottom={1}>
                {formatMessage(messages.preview)}
              </TextTitle3>
              <NotificationPreview
                previewNotification={previewNotification}
                platform="retail-mobile"
              />
            </Box>
          )}
        </ScrollableView>
        {Boolean(isPush2FAFlow) && (
          <VStack spacingVertical={1} spacingHorizontal={3} background>
            <SecurityAlertsDoneButton />
          </VStack>
        )}
      </Screen>
    );
  }

  return (
    <Screen navHeader={navHeader} height="100%" scrollable={false} noSpacing>
      <ScrollableView>
        {!isAdvancedTransactionNotif && (
          <Box spacingTop={1} testID="channel-preferences-notification-preview">
            <NotificationPreviewCard preview={preference.notificationPreview} />
          </Box>
        )}
        <TextBody color="foregroundMuted" spacingBottom={4} spacingTop={2}>
          {preference.description}
        </TextBody>
        <TextTitle3 spacingBottom={0}>
          {formatMessage(messages.preferences)}
        </TextTitle3>
        <TextBody color="foregroundMuted" spacingBottom={2}>
          {formatMessage(messages.tellUsHow)}
        </TextBody>
        <ChannelToggleList
          preference={preferenceProps}
          recommendedChannel={recommendedChannel}
        />
        {preferenceProps.type === 'USER_CUSTOMIZABLE_ALERTS' &&
          isCpaEnabled && (
            <Box spacingTop={2}>
              <TextTitle3 spacingBottom={1}>
                {formatMessage(customPriceAlertMessages.cpaTitle)}
              </TextTitle3>
              <TextBody color="foregroundMuted" spacingBottom={2}>
                {formatMessage(customPriceAlertMessages.manageYourAlerts)}
              </TextBody>

              <CustomPriceAlertsSettingsList queryRef={query} />
              <CPATrayToTrayFlow queryRef={query} compact variant="secondary" />
            </Box>
          )}
        {hasAdvancedNotifications && (
          <SubPreferenceToggleList
            preferenceName={preferenceProps.type}
            subPreferences={preference.subPreferences}
          />
        )}
      </ScrollableView>

      {Boolean(isPush2FAFlow) && (
        <VStack spacingVertical={1} spacingHorizontal={3} background>
          <SecurityAlertsDoneButton />
        </VStack>
      )}
    </Screen>
  );
}

