import { memo, useCallback, useState } from 'react';
import { useFormatPrice } from '@advancedTrade/hooks/useFormatPrice';
import { Switch } from '@cbhq/cds-mobile/controls';
import { NavigationIcon } from '@cbhq/cds-mobile/icons';
import { HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody, TextHeadline } from '@cbhq/cds-mobile/typography';
import { graphql, useFragment } from '@cbhq/data-layer';
import { useIntl } from '@cbhq/i18n';

import { useDebouncedCallback } from '@hooks/useDebouncedCallback';
import { errorVitals } from '@app/utils/errors/errorVitals';
import {
  logCpaMoreMenuClick,
  logCustomPriceAlertToggleClick,
} from '@app/utils/notifications/NotificationAnalytics';

import { CustomPriceAlertListItemFragment$key } from './__generated__/CustomPriceAlertListItemFragment.graphql';
import { CpaSwipeableRow } from './components/CpaSwipeableRow';
import { customPriceAlertMessages } from './CustomPriceAlerts.messages';

type CustomPriceAlertListItemProps = {
  priceAlertRef: CustomPriceAlertListItemFragment$key;
  handleLastSwipedRowId?: (assetId: string) => void;
  lastSwipedRowId: string | null;
  handleRefetch?: () => void;
  connectionId?: string;
  deletePriceAlert: (
    priceAlertUuid: string,
    priceAlertId: string,
    connectionIds: string[],
  ) => void;
  togglePriceAlert: (uuid: string, isActive: boolean) => void;
  toggleOnMoreMenu?: (priceAlertId: string) => void;
};

const CustomPriceAlertListItem = memo(
  ({
    priceAlertRef,
    handleLastSwipedRowId,
    lastSwipedRowId,
    togglePriceAlert,
    toggleOnMoreMenu,
  }: CustomPriceAlertListItemProps) => {
    const { formatMessage } = useIntl();
    const priceFormatter = useFormatPrice();
    const priceAlert = useFragment(
      graphql`
        fragment CustomPriceAlertListItemFragment on PriceAlert {
          id @required(action: THROW)
          uuid @required(action: THROW)
          targetPrice
          direction
          isActive
          nativeCurrency
        }
      `,
      priceAlertRef,
    );

    const { id: priceAlertId, isActive } = priceAlert;
    const [isPriceAlertActive, setIsPriceAlertActive] = useState(
      Boolean(isActive),
    );

    const handleOnEditClick = useCallback(() => {
      logCpaMoreMenuClick(priceAlert.uuid);
      toggleOnMoreMenu?.(priceAlert.id);
    }, [toggleOnMoreMenu, priceAlert.id, priceAlert.uuid]);

    const handleTogglePriceAlert = useCallback(() => {
      logCustomPriceAlertToggleClick(priceAlert.uuid, isActive ?? false);
      setIsPriceAlertActive(!isPriceAlertActive);
      togglePriceAlert(priceAlert.uuid ?? '', isActive ?? false);
    }, [togglePriceAlert, priceAlert.uuid, isActive, isPriceAlertActive]);

    const debouncedHandleTogglePriceAlert = useDebouncedCallback(
      handleTogglePriceAlert,
    );

    const setLastSwipedRowId = useCallback(() => {
      handleLastSwipedRowId?.(priceAlertId ?? '');
    }, [priceAlertId, handleLastSwipedRowId]);

    const countDecimalPlaces = useCallback(
      (num: string): number | undefined => {
        const numStr = num.toString();
        if (numStr.includes('.')) {
          return numStr.split('.')[1].length;
        }
        return undefined;
      },
      [],
    );

    if (!priceAlert) {
      errorVitals.logError(new Error('missing custom priceAlert record'), {
        context: 'custom_price_alerts',
        severity: 'error',
        isHandled: false,
      });
      return null;
    }

    if (priceAlert.targetPrice === null || priceAlert.direction === null) {
      errorVitals.logError(new Error('missing price alert data'), {
        context: 'custom_price_alerts',
        severity: 'error',
        isHandled: false,
        priceAlert: priceAlert.id,
      });
      return null;
    }

    const cpaCurrency = priceAlert.nativeCurrency ?? 'USD';

    return (
      <CpaSwipeableRow
        isLastSwipedRow={lastSwipedRowId === priceAlertId}
        setLastSwipedRowId={setLastSwipedRowId}
        offsetSpacing={2}
        priceAlertUuid={priceAlert.uuid}
      >
        <HStack
          spacingVertical={2}
          flexGrow={1}
          justifyContent="space-between"
          alignItems="center"
          testID="cpa-list-item"
        >
          <HStack gap={3} alignItems="center">
            <VStack>
              <TextHeadline testID="direction">
                {priceAlert.direction === 'ABOVE'
                  ? formatMessage(customPriceAlertMessages.priceMovesAbove)
                  : formatMessage(customPriceAlertMessages.priceMovesBelow)}
              </TextHeadline>
              <TextBody color="foregroundMuted" testID="targetPrice">
                {priceFormatter({
                  value: priceAlert.targetPrice?.toString() || '',
                  currency: cpaCurrency,
                  precision: countDecimalPlaces(
                    priceAlert.targetPrice.toString(),
                  ),
                })}
              </TextBody>
            </VStack>
          </HStack>
          <HStack gap={1} alignItems="center" justifyContent="flex-end">
            <Switch
              testID="cpa-list-item-toggle"
              checked={isPriceAlertActive}
              onChange={debouncedHandleTogglePriceAlert}
            />

            <Pressable
              background="transparent"
              onPress={handleOnEditClick}
              testID="cpa-list-item-edit"
              accessibilityLabel={formatMessage(
                customPriceAlertMessages.manageYourAlerts,
              )}
              accessibilityHint={formatMessage(
                customPriceAlertMessages.manageYourAlerts,
              )}
            >
              <NavigationIcon size="m" name="moreVertical" />
            </Pressable>
          </HStack>
        </HStack>
      </CpaSwipeableRow>
    );
  },
);

export default CustomPriceAlertListItem;

