export function BrowseAssetsButton() {
  const nativeCurrency = useNativeCurrency();

  const [pricesAssetListQueryRef, loadQuery] =
    useQueryLoader<PricesAssetListQuery>(mainQuery);

  useEffect(() => {
    loadQuery({
      first: InitialNumberToRender,
      nativeCurrency,
      country: getCountryLoggedOut(),
    });
  }, [loadQuery, nativeCurrency]);

  const { formatMessage } = useIntl();
  // use replace to not let users navigate backwards.
  const { replace } = useStackNavigation();

  const handlePress = useCallback(() => {
    if (!pricesAssetListQueryRef) {
      return;
    }
    markSignedOutPricesLoad();
    logEvent(SignedOutLogEventNames.CarouselCTA, {
      componentType: ComponentType.button,
      action: ActionType.click,
      name: 'footer_browse_assets',
    });
    replace('BrowseExperienceStack', { pricesAssetListQueryRef });
  }, [replace, pricesAssetListQueryRef]);

  const label = formatMessage(messages.browseAssets);

  return (
    <Button transparent accessibilityLabel={label} onPress={handlePress}>
      {label}
    </Button>
  );
}

