export const mainQuery = graphql`
  query PricesAssetListQuery(
    $first: Int!
    $nativeCurrency: TickerSymbol!
    $country: String!
  ) {
    ...PricesAssetListFragment @arguments(first: $first, country: $country)
    ...PricesAssetListListedAssetsFragment
      @arguments(first: $first, country: $country)
  }
`;

/*
 * Note we declare "edges { __typename } below despite having the fragment spread
 * edges for us because Relay compiler doesn't yet allow you to spread
 * the Connection with the @connection directive
 * See https://github.com/facebook/relay/issues/1983
 *
 * */
const allAssetsFragment = graphql`
  fragment PricesAssetListFragment on Query
  @argumentDefinitions(
    first: { type: "Int!" }
    after: { type: "String" }
    country: { type: "String!" }
  )
  @refetchable(queryName: "AllAssetsQuery") {
    ALL: searchAssetsV2(query: "", filter: ALL, first: $first, after: $after)
      @connection(key: "PricesAssetList_ALL") {
      edges {
        __typename
      }
      ...AssetListConnectionFragment @arguments(country: $country)
    }
  }
`;

const listedAssetsFragment = graphql`
  fragment PricesAssetListListedAssetsFragment on Query
  @argumentDefinitions(
    first: { type: "Int!" }
    after: { type: "String" }
    country: { type: "String!" }
  )
  @refetchable(queryName: "ListedAssetQuery") {
    LISTED: searchAssetsV2(
      query: ""
      filter: LISTED
      first: $first
      after: $after
    ) @connection(key: "PricesAssetList_LISTED") {
      edges {
        __typename
      }
      ...AssetListConnectionFragment @arguments(country: $country)
    }
  }
`;

export const InitialNumberToRender = 24;
const QueriesByKey = {
  ALL: allAssetsFragment,
  LISTED: listedAssetsFragment,
};

function AssetListQuery({
  query,
  viewerRef,
  routeKey,
  showTurnOnLoggedOutNotificationCTA = false,
  ...flatListFallThroughProps
}: {
  query: ReturnType<typeof graphql>;
  viewerRef: PricesAssetListQuery$data;
  routeKey: 'ALL' | 'LISTED';
  showTurnOnLoggedOutNotificationCTA?: boolean;
} & Partial<AssetListAdditionalFlatListProps>) {
  const { data, loadNext, hasNext, isLoadingNext } = usePaginationFragment<
    AllAssetsQuery | ListedAssetQuery,
    PricesAssetListListedAssetsFragment$key | PricesAssetListFragment$key
  >(query, viewerRef);

  // This if ALL OR IF LISTED is required to make  TypeScript happy
  let assets = null;
  if (routeKey === 'ALL' && routeKey in data) {
    assets = data[routeKey];
  } else if (routeKey === 'LISTED' && routeKey in data) {
    assets = data[routeKey];
  }

  const nativeCurrency = useNativeCurrency();
  const country = getCountryLoggedOut();

  const { refresh } = useRefreshQuery<PricesAssetListQuery>(mainQuery, {
    first: InitialNumberToRender,
    nativeCurrency,
    country,
  });

  return (
    <AssetList
      key={routeKey}
      hasNext={hasNext}
      loadNext={loadNext}
      isLoadingNext={isLoadingNext}
      assetConnectionRef={assets}
      refresh={refresh}
      numberToRender={InitialNumberToRender}
      showTurnOnLoggedOutNotificationCTA={showTurnOnLoggedOutNotificationCTA}
      tradable={routeKey === 'LISTED'}
      windowSize={2}
      {...flatListFallThroughProps}
    />
  );
}

function useQuery() {
  const { pricesAssetListQueryRef } = useParams<'SignedOutPrices'>();
  const nativeCurrency = useNativeCurrency();
  let queryRef;
  // this is temporary to support an experiment with preloading and without
  if (pricesAssetListQueryRef) {
    /* eslint-disable-next-line */
    queryRef = usePreloadedQuery<PricesAssetListQuery>(
      mainQuery,
      pricesAssetListQueryRef,
    );
  } else {
    /* eslint-disable-next-line */
    queryRef = useLazyLoadQuery<PricesAssetListQuery>(mainQuery, {
      first: InitialNumberToRender,
      nativeCurrency,
      country: getCountryLoggedOut(),
    });
  }
  return queryRef;
}

type PricesAssetListProps = {
  showTurnOnLoggedOutNotificationCTA?: boolean;
};

export function PricesAssetList({
  showTurnOnLoggedOutNotificationCTA = false,
}: PricesAssetListProps) {
  const spacing = useSpacingScale();
  const { bottom, top } = useSafeAreaInsets();
  const [index, setIndex] = useState(0);
  const { screenWidth } = useDimensions();

  const { displayBanner } = usePageLevelErrorState();

  const { formatMessage } = useIntl();
  const routes = useMemo(
    () => [
      { key: 'LISTED', title: formatMessage(messages.tradable) },
      { key: 'ALL', title: formatMessage(messages.all) },
    ],
    [formatMessage],
  );

  const queryRef = useQuery();
  const { LoggedOutPricesHeaderHeight } = useLoggedOutPricesHeaderHeight();

  useEffect(() => {
    markSignedOutPricesLoadEnd();
  }, []);

  const tabIndexRef = useRef(0);
  const handleSetIndex = useCallback(
    (_index: number) => {
      tabIndexRef.current = _index;
      setIndex(_index);
    },
    [setIndex],
  );

  const {
    syncScrollOffset,
    tabBarVerticalOffset,
    tabBarBottomBorder,
    headerVerticalOffset,
    listPanResponder,
    headerPanResponder,
    getListRef,
    onListScroll,
  } = useCollapsableHeaderScrollAnimation({
    tabRoutes: routes,
    currentTabIndexRef: tabIndexRef,
  });

  const assetListContentContainerStyle = useMemo(
    () => ({
      paddingTop: LoggedOutPricesHeaderHeight,
      paddingBottom: bottom + 65,
    }),
    [LoggedOutPricesHeaderHeight, bottom],
  );

  const renderScene = useCallback<
    React.ComponentProps<typeof TabView>['renderScene']
  >(
    ({ route }) => {
      const key = route.key as 'ALL' | 'LISTED';
      const isFocused = routes[tabIndexRef.current].key === key;
      return (
        <AssetListQuery
          getRef={getListRef(route.key)}
          showsVerticalScrollIndicator={false}
          onMomentumScrollBegin={syncScrollOffset}
          onMomentumScrollEnd={syncScrollOffset}
          onScrollEndDrag={syncScrollOffset}
          onScroll={isFocused ? onListScroll : undefined}
          {...listPanResponder.panHandlers}
          contentContainerStyle={assetListContentContainerStyle}
          viewerRef={queryRef}
          routeKey={key}
          key={key}
          query={QueriesByKey[key]}
          showTurnOnLoggedOutNotificationCTA={
            showTurnOnLoggedOutNotificationCTA && key === 'LISTED'
          }
        />
      );
    },
    [
      routes,
      getListRef,
      syncScrollOffset,
      onListScroll,
      listPanResponder.panHandlers,
      assetListContentContainerStyle,
      queryRef,
      showTurnOnLoggedOutNotificationCTA,
    ],
  );

  const handleNavigationToLoggedOutSearch = useSignedOutPricesSearchNavigate();

  const renderTabBar = useCallback<RenderTabBar>(
    (p) => (
      <Animated.View
        style={[
          styles.tabBar,
          {
            transform: [
              {
                translateY: tabBarVerticalOffset,
              },
            ],
          },
        ]}
      >
        <Box
          spacingTop={2}
          justifyContent="center"
          background="background"
          width="100%"
        >
          <TabBar startInset={spacing[gutter]} {...p} />
          <Box
            pin="right"
            spacingTop={1}
            spacingEnd={2}
            justifyContent="space-between"
            flexDirection="row"
          >
            <LoggedOutDebugButton />
            <IconButton
              name="search"
              onPress={handleNavigationToLoggedOutSearch}
            />
          </Box>
        </Box>
        <Animated.View style={{ transform: [{ scaleY: tabBarBottomBorder }] }}>
          <Divider />
        </Animated.View>
      </Animated.View>
    ),
    [
      handleNavigationToLoggedOutSearch,
      spacing,
      tabBarVerticalOffset,
      tabBarBottomBorder,
    ],
  );

  const renderHeader = useCallback(() => {
    const transform = {
      transform: [
        {
          translateY: headerVerticalOffset,
        },
      ],
    };

    return (
      <Animated.View
        {...headerPanResponder.panHandlers}
        style={[styles.header, transform]}
      >
        <PricesHeaderPromo />
      </Animated.View>
    );
  }, [headerVerticalOffset, headerPanResponder.panHandlers]);

  return (
    <>
      {displayBanner && (
        <VStack position="absolute" width="100%" zIndex={zIndex.max}>
          <Box height={top} background="background" />
          <SharedGlobalErrorBanner omitFundsMessaging />
        </VStack>
      )}
      <TabView
        index={index}
        onIndexChange={handleSetIndex}
        width={screenWidth}
        routes={routes}
        renderScene={renderScene}
        renderTabBar={renderTabBar}
      />
      {renderHeader()}
    </>
  );
}

const styles = StyleSheet.create({
  header: {
    position: 'absolute',
    width: '100%',
  },
  tabBar: {
    zIndex: 1,
  },
});

