type MinimumPriceTargetErrorProps = ErrorData & {
  setTargetPrice: SetAmountState;
  setAmount: SetAmountState;
  queryRef: MinimumPriceTargetErrorFragment$key;
  targetPrice: string;
  setInputValue?: Dispatch<SetStateAction<string>>;
  setLimitPrice?: (value: string) => void;
  displayedInputCurrency?: CurrencyStub;
  setDisplayedInputCurrency?: Dispatch<SetStateAction<CurrencyStub>>;
  cryptoCurrency?: CurrencyStub;
};

const i18nKey = 'LimitOrderMinimumPriceTargetError';

export const MIN_LIMIT_ORDER_BUY_AMOUNT_LEGACY = 5.5;
export const MIN_LIMIT_ORDER_BUY_AMOUNT_FIAT_EXP = 5.0;

const messages = defineMessages({
  [`${ErrorSuggestionAction.needCryptoToSell}Title`]: {
    id: `${i18nKey}.needCryptoToSellTitle`,
    defaultMessage: 'Add more {platformName} to complete this order.',
    description: 'Balance available to sell',
  },
  [`${ErrorSuggestionAction.needCryptoToSell}Action`]: {
    id: `${i18nKey}.needCryptoToSellAction`,
    defaultMessage: 'Buy {platformName}',
    description: 'Buy',
  },

  [`${ErrorSuggestionAction.maxSellValue}Title`]: {
    id: `${i18nKey}.maxSellValueTitle`,
    defaultMessage: 'You can sell up to {cryptoBalance}',
    description: 'Balance available to sell',
  },
  [`${ErrorSuggestionAction.maxSellValue}Action`]: {
    id: `${i18nKey}.maxSellValueAction`,
    defaultMessage: 'Sell max',
    description: 'Sell max',
  },
  [`${ErrorSuggestionAction.maxTradeValueApiLimit}Title`]: {
    id: `${i18nKey}.maxTradeValueApiLimitTitle`,
    defaultMessage:
      'The maximum {platformName} you can trade is {baseMaxSize} {platformName}',
    description: 'The maximum amount you can buy or sell',
  },
  [`${ErrorSuggestionAction.minTradeValueApiLimit}Title`]: {
    id: `${i18nKey}.minTradeValueApiLimitTitle`,
    defaultMessage:
      'The minimum {platformName} you can trade is {baseMinSize} {platformName}',
    description: 'The minimum amount you can buy or sell',
  },

  [`${ErrorSuggestionAction.minimumBuyPercentage}Title`]: {
    id: `${i18nKey}.minBuyPercentageTitle`,
    defaultMessage:
      'Set a price at least {percentageThreshold} below {platformName}’s current price. ',
    description: 'Minimum buy price',
  },
  [`${ErrorSuggestionAction.minimumBuyPercentage}Action`]: {
    id: `${i18nKey}.minBuyPercentageAction`,
    defaultMessage: '↘ {percentageThreshold}',
    description: 'Buy at minimum percentage',
  },

  [`${ErrorSuggestionAction.minimumSellPercentage}Title`]: {
    id: `${i18nKey}.minSellPercentageTitle`,
    defaultMessage:
      'Set a price at least {percentageThreshold} above {platformName}’s current price. ',
    description: 'Minimum sell price',
  },
  [`${ErrorSuggestionAction.minimumSellPercentage}Action`]: {
    id: `${i18nKey}.minSellPercentageAction`,
    defaultMessage: '↗ {percentageThreshold}',
    description: 'Sell at minimum percentage',
  },

  [`${ErrorSuggestionAction.minAmountValue}Title`]: {
    id: `${i18nKey}.minAmountValueTitle`,
    defaultMessage: 'Minimum amount is {minBuy} dollars',
    description: 'Minimum amount to buy or sell',
  },
  [`${ErrorSuggestionAction.minAmountValue}Action`]: {
    id: `${i18nKey}.minAmountValueAction`,
    defaultMessage: 'Set minimum',
    description: 'Set minimum',
  },
});

const MinimumPriceTarget = memo<MinimumPriceTargetErrorProps>(
  function MinimumPriceTargetError({
    action,
    queryRef,
    setAmount,
    setTargetPrice,
    setInputValue,
    setLimitPrice,
    displayedInputCurrency,
    setDisplayedInputCurrency,
    cryptoCurrency,
    targetPrice,
  }) {
    const { viewer } = useFragment(
      graphql`
        fragment MinimumPriceTargetErrorFragment on Query
        @argumentDefinitions(
          isLimitAPI: { type: "Boolean!", defaultValue: true }
        ) {
          viewer @include(if: $isLimitAPI) {
            assetByUuid(uuid: $assetId) {
              asset {
                brokerageProduct(filter: { quoteTicker: $nativeCurrency }) {
                  baseMaxSize
                  baseMinSize
                }
                platformName
                latestPrice(quoteCurrency: $nativeCurrency) {
                  price
                }
              }
              accounts {
                primary
                availableBalance {
                  value
                }
              }
            }
            assetBySlug(slug: $assetSymbolOrSlug) {
              asset {
                brokerageProduct(filter: { quoteTicker: $nativeCurrency }) {
                  baseMaxSize
                  baseMinSize
                }
                platformName
                latestPrice(quoteCurrency: $nativeCurrency) {
                  price
                }
              }
              accounts {
                primary
                availableBalance {
                  value
                }
              }
            }
            assetBySymbol(symbol: $assetSymbolOrSlug) {
              asset {
                brokerageProduct(filter: { quoteTicker: $nativeCurrency }) {
                  baseMaxSize
                  baseMinSize
                }
                platformName
                latestPrice(quoteCurrency: $nativeCurrency) {
                  price
                }
              }
              accounts {
                primary
                availableBalance {
                  value
                }
              }
            }
          }
        }
      `,
      queryRef,
    );

    const { assetBySymbol, assetBySlug, assetByUuid } = viewer ?? {};

    const assetObj = assetBySlug ?? assetBySymbol ?? assetByUuid;
    const primaryCryptoAccount = assetObj?.accounts?.find(
      (acc) => acc?.primary,
    );
    const availableCrypto =
      primaryCryptoAccount?.availableBalance?.value ?? '0';

    const isFiatExp = useIsLimitOrderFiatQuoteExperiment();
    const MIN_LIMIT_ORDER_BUY_AMOUNT = isFiatExp
      ? MIN_LIMIT_ORDER_BUY_AMOUNT_FIAT_EXP
      : MIN_LIMIT_ORDER_BUY_AMOUNT_LEGACY;

    const platformName = assetObj?.asset?.platformName ?? '';
    const currentCryptoPrice = assetObj?.asset?.latestPrice?.price ?? '0';

    const { navigate } = useStackNavigation();
    const screenParams = useParams() as UnsafeSimpleTradeInputParams;

    useLogBuySellTargetPriceError(targetPrice, action);
    const { logSimpleTradeClickEvent } = useSimpleTradeAnalytics();

    const handleApplySuggestion = useCallback(() => {
      switch (action) {
        case ErrorSuggestionAction.minAmountValue: {
          /*
           * In limit orders we always use the target price as reference to
           * converting from and to Fiat since that's our target, unless when it
           * has not yet been set.
           * */
          const basePrice = Number(targetPrice) || Number(currentCryptoPrice);
          setAmount((currentAmount) => {
            const value =
              currentAmount.unit === 'FIAT'
                ? String(MIN_LIMIT_ORDER_BUY_AMOUNT)
                : String(MIN_LIMIT_ORDER_BUY_AMOUNT / basePrice);
            return {
              ...currentAmount,
              value,
            };
          });
          if (setInputValue) {
            setInputValue(
              displayedInputCurrency?.type === 'fiat'
                ? String(MIN_LIMIT_ORDER_BUY_AMOUNT)
                : String(MIN_LIMIT_ORDER_BUY_AMOUNT / basePrice),
            );
          }
          break;
        }
        case ErrorSuggestionAction.maxSellValue:
          setAmount(() => {
            return {
              value: availableCrypto,
              unit: 'CRYPTO',
            };
          });
          if (setInputValue && setDisplayedInputCurrency && cryptoCurrency) {
            setInputValue(availableCrypto);
            setDisplayedInputCurrency(cryptoCurrency);
          }
          break;
        case ErrorSuggestionAction.needCryptoToSell:
          navigate(
            'SimpleTradeInput',
            {
              ...screenParams,
              tradeType: 'buy',
              orderType: undefined,
              assetSymbolOrSlug: platformName,
            },
            true,
          );
          break;
        case ErrorSuggestionAction.minimumBuyPercentage:
          {
            const percentage = MinimumPercentThreshold.minus;
            const value = String(Number(currentCryptoPrice) * percentage);
            setTargetPrice((currentTargetPrice) => {
              logSimpleTradeClickEvent('buy_tapped_limit_price_error', {
                amount: currentTargetPrice.value,
              });
              return {
                ...currentTargetPrice,
                value,
              };
            });
            if (setLimitPrice) {
              setLimitPrice(value);
            }
          }

          break;
        case ErrorSuggestionAction.minimumSellPercentage:
          setTargetPrice((currentTargetPrice) => {
            logSimpleTradeClickEvent('sell_tapped_limit_price_error', {
              amount: currentTargetPrice.value,
            });
            const percentage = MinimumPercentThreshold.plus;
            const value = String(Number(currentCryptoPrice) * percentage);
            return {
              ...currentTargetPrice,
              value,
            };
          });
          break;
        // These 2 cases do not have associated actions, so we do nothing
        case ErrorSuggestionAction.maxTradeValueApiLimit:
        case ErrorSuggestionAction.minTradeValueApiLimit:
          break;
        default:
          break;
      }
    }, [
      action,
      setAmount,
      setInputValue,
      setDisplayedInputCurrency,
      cryptoCurrency,
      navigate,
      screenParams,
      platformName,
      setTargetPrice,
      targetPrice,
      currentCryptoPrice,
      MIN_LIMIT_ORDER_BUY_AMOUNT,
      displayedInputCurrency?.type,
      availableCrypto,
      setLimitPrice,
      logSimpleTradeClickEvent,
    ]);

    const { formatMessage, formatNumber } = useIntl();

    const formatCurrency = useCurrencyFormatter();
    const cryptoBalance = useMemo(() => {
      if (action === ErrorSuggestionAction.maxSellValue) {
        return `${formatCurrency({
          amount: availableCrypto,
          currency: {
            code: platformName,
            type: 'crypto',
          },
          isSensitive: false,
        })}`;
      }

      return '--';
    }, [action, formatCurrency, platformName, availableCrypto]);

    const title = useMemo(
      () =>
        formatMessage(messages[`${action}Title`], {
          percentageThreshold: MinimumPercentThreshold.percent,
          cryptoBalance,
          platformName,
          baseMaxSize: formatNumber(
            Number(assetObj?.asset?.brokerageProduct?.baseMaxSize),
          ),
          baseMinSize: formatNumber(
            Number(assetObj?.asset?.brokerageProduct?.baseMinSize),
            {
              maximumFractionDigits:
                assetObj?.asset?.brokerageProduct?.baseMinSize?.length ?? 0,
            },
          ),
          minBuy: formatNumber(MIN_LIMIT_ORDER_BUY_AMOUNT, {
            style: 'currency',
            currency: 'USD',
          }),
        }),
      [
        formatMessage,
        action,
        cryptoBalance,
        platformName,
        formatNumber,
        assetObj?.asset?.brokerageProduct?.baseMaxSize,
        assetObj?.asset?.brokerageProduct?.baseMinSize,
        MIN_LIMIT_ORDER_BUY_AMOUNT,
      ],
    );

    // These cases do not have actions associated with them
    const hasAction =
      action !== ErrorSuggestionAction.maxTradeValueApiLimit &&
      action !== ErrorSuggestionAction.minTradeValueApiLimit;

    const actionTitle = useMemo(() => {
      return hasAction
        ? formatMessage(messages[`${action}Action`], {
            percentageThreshold: MinimumPercentThreshold.percent,
            platformName,
          })
        : '';
    }, [action, formatMessage, hasAction, platformName]);

    const { ctaVerticalSpacing } = useInputSpacing();

    return (
      <HStack
        offsetHorizontal={3}
        offsetTop={ctaVerticalSpacing}
        gap={2}
        flexGrow={1}
        background="secondary"
        justifyContent="space-between"
        alignItems="center"
        spacing={2}
        spacingVertical={0}
      >
        <Box flexShrink={1}>
          <TextLabel2>{title}</TextLabel2>
        </Box>
        <Pressable
          onPress={handleApplySuggestion}
          background="transparent"
          accessibilityRole="button"
          accessibilityHint={actionTitle}
        >
          <TextLabel1 color="primary">{actionTitle}</TextLabel1>
        </Pressable>
      </HStack>
    );
  },
);

function MinimumPriceTargetFallback() {
