import { memo, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { LayoutChangeEvent } from 'react-native/types';
import { Icon } from '@cbhq/cds-mobile/icons';
import { HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody } from '@cbhq/cds-mobile/typography';
import { useIntl } from '@cbhq/i18n';

import { useDimensions } from '@designSystem/hooks/useDimensions';

import {
  LayoutMap,
  LiveTicker,
  stripValues,
} from '@app/components/LiveTicker/LiveTicker';
import { useCurrencyFormatter } from '@app/hooks/formatters/useCurrencyFormatter';
import { messages } from '@app/screens/SimpleTrade/components/TradePreviewContentV2/messages';
import { SimpleTradeType } from '@app/screens/SimpleTrade/types';

import { useLivePriceTray } from './useLivePriceTray';

export type LivePriceProps = {
  spreadPercentage: string | null;
  inputCurrency: {
    type?: string;
    displayCode: string;
  };
  outputAmount?: {
    value: string;
    currency: string;
  };
  scale?: number;
  text?: string;
  tradeType?: SimpleTradeType;
  onTrayOpen?: () => void;
};

function generateAlphaNumericArray() {
  let array = [];
  for (let charCode = 65; charCode <= 90; charCode += 1) {
    const alphabet = String.fromCharCode(charCode);
    array.push(alphabet);
  }

  const symbols = ['=', '/', ' '];
  array = array.concat(symbols);
  array = array.concat(stripValues);

  return array;
}

export const LivePrice = memo(function LivePrice(props: LivePriceProps) {
  const {
    inputCurrency,
    outputAmount,
    scale,
    text,
    tradeType,
    onTrayOpen,
    spreadPercentage = null,
  } = props;
  const { formatMessage } = useIntl();
  const [isMeasured, setIsMeasured] = useState(false);
  const { screenWidth } = useDimensions();
  const layoutMap = useRef<LayoutMap>({});
  const totalWidth = useRef(0);
  const alphaNumericArray = generateAlphaNumericArray();
  const formatCurrency = useCurrencyFormatter();

  const { livePriceTray, toggleLivePriceTrayOn } = useLivePriceTray({
    inputCurrency,
    spreadPercentage,
    tradeType,
  });
  const livePrice = useMemo(() => {
    if (tradeType === 'swap') return outputAmount?.value ?? '';

    return formatCurrency({
      amount: outputAmount?.value,
      currency: { code: outputAmount?.currency, type: 'fiat' },
      minimumFractionDigits: scale,
      isSensitive: false,
    });
  }, [
    formatCurrency,
    outputAmount?.currency,
    outputAmount?.value,
    scale,
    tradeType,
  ]);

  useEffect(() => {
    totalWidth.current = 0;
  }, [screenWidth]);

  const handleTrayOpen = useCallback(() => {
    onTrayOpen?.();
    toggleLivePriceTrayOn();
  }, [onTrayOpen, toggleLivePriceTrayOn]);

  const textWithLivePrice = useMemo(() => {
    const textValue =
      text ??
      formatMessage(messages.currencyPrice, {
        currency: inputCurrency.displayCode,
      });
    return `${textValue} ${livePrice}`;
  }, [formatMessage, inputCurrency.displayCode, livePrice, text]);

  const textChars = useMemo(
    () => textWithLivePrice.split(''),
    [textWithLivePrice],
  );

  const onTextLayout = useCallback(
    (c: string) => (event: LayoutChangeEvent) => {
      if (!layoutMap.current) {
        return;
      }

      layoutMap.current[c] = event.nativeEvent.layout;
      if (Object.keys(layoutMap.current).length === alphaNumericArray.length) {
        setIsMeasured(true);
      }
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  );

  const shouldBreakLine = useMemo(() => {
    if (isMeasured) {
      textChars.map((c) => {
        totalWidth.current += layoutMap?.current[c]?.width
          ? layoutMap.current[c].width
          : 0;
        return null;
      });
      return totalWidth.current > screenWidth - 48;
    }
    return false;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isMeasured, screenWidth]);

  const chars = useMemo(() => {
    return alphaNumericArray.map((c) => {
      return (
        <TextBody
          onLayout={onTextLayout(c)}
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            opacity: 0,
          }}
          tabularNumbers
          key={c}
        >
          {c}
        </TextBody>
      );
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [onTextLayout]);

  const Container = useMemo(
    () => (tradeType === 'swap' && shouldBreakLine ? VStack : HStack),
    [tradeType, shouldBreakLine],
  );

  if (!outputAmount?.value) return null;

  return (
    <>
      {tradeType === 'swap' && chars}
      <Container alignItems="center" gap={0.5} justifyContent="center">
        <TextBody color="foregroundMuted">
          {text ??
            formatMessage(messages.currencyPrice, {
              currency: inputCurrency.displayCode,
            })}
        </TextBody>
        <HStack alignItems="center" gap={0.5}>
          <LiveTicker
            value={livePrice}
            variant="body"
            color="foregroundMuted"
          />
          <Pressable
            accessibilityRole="button"
            background="background"
            onPress={handleTrayOpen}
            hitSlop={16}
          >
            <Icon
              name="info"
              size="xs"
              color="foregroundMuted"
              testID="live-price-info-icon"
            />
          </Pressable>
        </HStack>
      </Container>

      {livePriceTray}
    </>
  );
});

import { useCallback, useMemo, useState } from 'react';
import { V3Amount } from '@cbhq/advanced-trading-shared/hooks/useCurrencyFormatter';
import { useToggler } from '@cbhq/cds-mobile';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons/ButtonGroup';
import { Box } from '@cbhq/cds-mobile/layout/Box';
import { Tray } from '@cbhq/cds-mobile/overlays/Tray/Tray';
import { TextBody } from '@cbhq/cds-mobile/typography/TextBody';
import { TextTitle3 } from '@cbhq/cds-mobile/typography/TextTitle3';
import { useTradeBenefitData } from '@cbhq/coinbase-one-shared';
import { markJourney } from '@cbhq/core-vitals-mobile';
import { graphql, useFragment } from '@cbhq/data-layer';
import { useIntl } from '@cbhq/i18n';

import { Button } from '@components/interactables/Button';
import { getFeeLink } from '@utils/getFeeLink';
import { getTaxLink } from '@utils/getTaxLink';
import { SubscriptionChangePlanFlowTray } from '@app/components/subscription/SubscriptionChangePlanFlowTray/SubscriptionChangePlanFlowTray';
import { SubscriptionSignupFlowTray } from '@app/components/subscription/SubscriptionSignupFlowTray/SubscriptionSignupFlowTray';
import { TooltipTray, TrayContent } from '@app/components/Trays/TooltipTray';
import { useStackNavigation } from '@app/hooks/navigation/useStackNavigation';
import { locale } from '@app/localization/localization';
import { SubscriptionTradingBanner } from '@app/product/cb1/components/SubscriptionTradingBanner';
import { useSimpleTradeAnalytics } from '@app/screens/SimpleTrade/analytics/useSimpleTradeAnalytics';
import { useHas2023FeeDisclosureEnabled } from '@app/screens/SimpleTrade/hooks/useHas2023FeeDisclosureEnabled/useHas2023FeeDisclosureEnabled';
import { USDBalanceTray } from '@app/screens/SimpleTrade/LimitOrder/USDBalanceTray';
import { Currency, CurrencyStub } from '@app/types/Currency';
import { CB1_SMALL_TRADE_TRADE_SIGNUP_UPSELL_DISCOUNT_CODE } from '@app/utils/subscription/subscription.constants';

import { useTradePreviewTrayFragment$key } from './__generated__/useTradePreviewTrayFragment.graphql';
import { messages } from './messages';

export type InfoTrayType = {
  title: string;
  description: string;
  link: {
    text: string;
    url: string;
  } | null;
  cta: string;
} | null;

type UseTradePreviewTrayProps = {
  transferType: 'buy' | 'sell';
  currency: Currency;
  inputCurrency: CurrencyStub;
  onShouldBuyAndStakeChange?: (checked: boolean) => void;
  onSubscriptionSignupSuccess?: () => void;
  onSubscriptionUpgradeSuccess?: () => void;
  queryRef: useTradePreviewTrayFragment$key;
  showSubscriptionBanner?: boolean;
  isRecurring?: boolean;
  isUSDCTrade?: boolean;
  isLimitOrder?: boolean;
  offerSubscriptionDiscount?: boolean;
  offerPremiumTier?: boolean;
  tradeTotal?: V3Amount;
};
export function useTradePreviewTray({
  transferType,
  currency,
  inputCurrency,
  onSubscriptionSignupSuccess,
  onSubscriptionUpgradeSuccess,
  queryRef,
  showSubscriptionBanner,
  isRecurring,
  isUSDCTrade,
  isLimitOrder,
  offerSubscriptionDiscount,
  offerPremiumTier,
  tradeTotal,
}: UseTradePreviewTrayProps) {
  const query = useFragment(
    graphql`
      fragment useTradePreviewTrayFragment on Query {
        # eslint-disable-next-line relay/must-colocate-fragment-spreads
        ...useTradeBenefitDataFragment @arguments(skip: false)
        viewer {
          # eslint-disable-next-line relay/must-colocate-fragment-spreads: "warn"
          ...USDBalanceTrayFragment
        }
      }
    `,
    queryRef,
  );
  const { viewer } = query;

  const tradeBenefitData = useTradeBenefitData(query);
  const { formatMessage } = useIntl();
  const { pop } = useStackNavigation();
  const displaySymbol = currency?.displayCode;

  const [
    subscriptionSignupFlowTrayVisible,
    {
      toggleOn: toggleSubscriptionSignupOn,
      toggleOff: toggleSubscriptionSignupFlowTrayOff,
    },
  ] = useToggler(false);
  const toggleSubscriptionSignupFlowTrayOn = useCallback(() => {
    markJourney('press_cb1_trade_preview_upsell');
    toggleSubscriptionSignupOn();
  }, [toggleSubscriptionSignupOn]);

  const [
    subscriptionUpgradeFlowTrayVisible,
    {
      toggleOn: toggleSubscriptionUpgradeFlowTrayOn,
      toggleOff: toggleSubscriptionUpgradeFlowTrayOff,
    },
  ] = useToggler(false);

  const [
    isShowingPriceChangeTray,
    { toggleOn: showPriceChangeTray, toggleOff: hidePriceChangeTray },
  ] = useToggler(false);

  const [isToggled, { toggleOn, toggleOff }] = useToggler(false);
  const [
    isUSDBalanceTrayVisible,
    { toggleOn: showUSDBalanceTray, toggleOff: hideUSDBalanceTray },
  ] = useToggler(false);
  const [tooltipTrayContent, setTooltipTrayContent] = useState<
    TrayContent | undefined
  >();

  const significantPriceChangeTray = useMemo(
    () =>
      isShowingPriceChangeTray ? (
        <Tray onCloseComplete={hidePriceChangeTray}>
          <Box spacingHorizontal={3} spacingTop={2}>
            <TextTitle3 spacingBottom={1}>
              {formatMessage(messages.priceHasChangedTitle, {
                asset: displaySymbol,
              })}
            </TextTitle3>
            <TextBody spacingBottom={3}>
              {formatMessage(messages.priceHasChangedDesc, {
                asset: displaySymbol,
                displayInputCurrency: inputCurrency.code,
              })}
            </TextBody>
            <ButtonGroup
              block
              accessibilityLabel={formatMessage(messages.buttonGroup)}
            >
              <Button variant="secondary" onPress={() => pop()}>
                {formatMessage(messages.goBack)}
              </Button>
              <Button variant="primary" onPress={hidePriceChangeTray}>
                {formatMessage(messages.placeOrder)}
              </Button>
            </ButtonGroup>
          </Box>
        </Tray>
      ) : null,
    [
      displaySymbol,
      formatMessage,
      hidePriceChangeTray,
      inputCurrency.code,
      isShowingPriceChangeTray,
      pop,
    ],
  );

  const subscriptionSignupFlowTray = useMemo(() => {
    return subscriptionSignupFlowTrayVisible ? (
      <SubscriptionSignupFlowTray
        onClose={toggleSubscriptionSignupFlowTrayOff}
        onSignupSuccess={() => {
          onSubscriptionSignupSuccess?.();
        }}
        variant={offerPremiumTier ? 'premium' : 'trade'}
        promoCode={
          offerSubscriptionDiscount
            ? CB1_SMALL_TRADE_TRADE_SIGNUP_UPSELL_DISCOUNT_CODE
            : undefined
        }
        tradeVolume={tradeTotal}
      />
    ) : null;
  }, [
    subscriptionSignupFlowTrayVisible,
    toggleSubscriptionSignupFlowTrayOff,
    offerPremiumTier,
    offerSubscriptionDiscount,
    tradeTotal,
    onSubscriptionSignupSuccess,
  ]);

  const subscriptionUpgradeFlowTray = useMemo(() => {
    return subscriptionUpgradeFlowTrayVisible ? (
      <SubscriptionChangePlanFlowTray
        onClose={toggleSubscriptionUpgradeFlowTrayOff}
        onChangePlanSuccess={() => {
          onSubscriptionUpgradeSuccess?.();
        }}
      />
    ) : null;
  }, [
    subscriptionUpgradeFlowTrayVisible,
    toggleSubscriptionUpgradeFlowTrayOff,
    onSubscriptionUpgradeSuccess,
  ]);

  const usdBalanceTray = useMemo(() => {
    return isUSDBalanceTrayVisible && viewer ? (
      <USDBalanceTray onCloseComplete={hideUSDBalanceTray} viewerRef={viewer} />
    ) : null;
  }, [hideUSDBalanceTray, isUSDBalanceTrayVisible, viewer]);

  const { logSimpleTradeClickEvent } = useSimpleTradeAnalytics(transferType);
  const feeTappedEventString =
    transferType === 'buy'
      ? 'tapped_buy_fee_explanation_button'
      : 'tapped_sell_fee_explanation_button';
  const supportUrl = getFeeLink(locale) as string;
  const tooltipTitle = useMemo(() => {
    if (isRecurring) {
      return formatMessage(messages.feeTrayTitleRecurring);
    }

    if (isLimitOrder) {
      return formatMessage(messages.feeTrayLimitOrderTitle);
    }

    return transferType === 'buy'
      ? formatMessage(messages.feeTrayTitleBuy)
      : formatMessage(messages.feeTrayTitleSell);
  }, [isRecurring, isLimitOrder, transferType, formatMessage]);

  const isFeeDisclosureEnabled = useHas2023FeeDisclosureEnabled();
  const tooltipContent = useMemo(() => {
    let formattedMessage;

    if (isRecurring) {
      if (isUSDCTrade) {
        formattedMessage = formatMessage(
          messages.feeTrayContentRecurringUSDCNoCommissionV3,
        );
      } else {
        formattedMessage = formatMessage(messages.feeTrayContentRecurringV2);
      }
    } else if (isUSDCTrade) {
      formattedMessage = formatMessage(
        messages.feeTrayContentUSDCNoCommissionV3,
      );
    } else if (isLimitOrder) {
      formattedMessage = formatMessage(messages.feeTrayContentLimitOrder);
    } else {
      formattedMessage = formatMessage(
        isFeeDisclosureEnabled
          ? messages.feeTrayContentUpdatedWithFeeDisclosureV2
          : messages.feeTrayContentUpdated,
      );
    }
    return formattedMessage;
  }, [
    isFeeDisclosureEnabled,
    formatMessage,
    isLimitOrder,
    isRecurring,
    isUSDCTrade,
  ]);

  const handleFeeInfoPress = useCallback(() => {
    logSimpleTradeClickEvent(feeTappedEventString, {
      content: 'coinbase_fees',
      orderType: isLimitOrder ? 'limit' : '',
    });
    setTooltipTrayContent({
      title: tooltipTitle,
      message: tooltipContent,
      cta: {
        type: 'link',
        urlOrAction: supportUrl,
        text: isLimitOrder
          ? formatMessage(messages.learnMore)
          : formatMessage(messages.here),
      },
      postMessageContent: showSubscriptionBanner && tradeBenefitData && (
        <SubscriptionTradingBanner tradeBenefitData={tradeBenefitData} />
      ),
      dismiss: {
        text: formatMessage(messages.ok),
      },
    });
    toggleOn();
  }, [
    logSimpleTradeClickEvent,
    feeTappedEventString,
    isLimitOrder,
    tooltipTitle,
    tooltipContent,
    supportUrl,
    formatMessage,
    showSubscriptionBanner,
    tradeBenefitData,
    toggleOn,
  ]);

  const taxInfo = useCallback(
    (taxType: string) => {
      switch (taxType) {
        case 'INDIA_WITHHOLDING':
          return {
            title: formatMessage(messages.tdsTrayTitle),
            content: formatMessage(messages.tdsTrayContent),
          };
        case 'AUSTRALIA_GST':
          return {
            title: formatMessage(messages.gstTrayTitle),
            content: formatMessage(messages.auGstTrayContent),
          };
        case 'SINGAPORE_GST':
          return {
            title: formatMessage(messages.gstTrayTitle),
            content: formatMessage(messages.sgGstTrayContent),
          };
        default:
          return null;
      }
    },
    [formatMessage],
  );

  const handleTaxInfoPress = useCallback(
    (taxType: string) => {
      const taxTrayInfo = taxInfo(taxType);
      if (taxTrayInfo?.title && taxTrayInfo?.content) {
        setTooltipTrayContent({
          title: taxTrayInfo.title,
          message: taxTrayInfo.content,
          cta: {
            type: 'link',

            urlOrAction: getTaxLink(taxType),

            text: formatMessage(messages.learnMore),
          },
          dismiss: {
            text: formatMessage(messages.done),
          },
        });
        toggleOn();
      }
    },
    [formatMessage, taxInfo, toggleOn],
  );

  const handleOneTimeBonusInfoPress = useCallback(() => {
    setTooltipTrayContent({
      title: formatMessage(messages.oneTimeBonusTrayTitle),
      message: formatMessage(messages.oneTimeBonusTrayDetail, {
        asset: displaySymbol,
      }),
      cta: {
        type: 'link',
        urlOrAction:
          'https://help.coinbase.com/en/coinbase/getting-started/getting-started-with-coinbase/first-yield-incentive',
        text: formatMessage(messages.termsApply),
      },
      dismiss: {
        text: formatMessage(messages.gotIt),
      },
    });
    toggleOn();
  }, [displaySymbol, formatMessage, toggleOn]);

  const handleShowInfoTray = useCallback(
    (info: InfoTrayType) => {
      if (info) {
        setTooltipTrayContent({
          title: info.title,
          message: info.description,
          cta: info.link
            ? {
                type: 'link',
                urlOrAction: info.link.url,
                text: info.link.text,
              }
            : undefined,
          dismiss: {
            text: info.cta,
          },
        });
        toggleOn();
      }
    },
    [toggleOn],
  );

  const tooltipTray = useMemo(() => {
    return (
      <TooltipTray
        hideTray={toggleOff}
        isVisible={isToggled}
        content={tooltipTrayContent}
      />
    );
  }, [isToggled, toggleOff, tooltipTrayContent]);

  const updateTooltipTray = useCallback(
    (
      title: TrayContent['title'],
      message: TrayContent['message'],
      link?: { url: string | null; text: string | null },
    ) => {
      setTooltipTrayContent({
        title,
        message,
        cta:
          link?.url && link?.text
            ? {
                type: 'link',
                urlOrAction: link.url,
                text: link.text,
              }
            : undefined,
        dismiss: {
          text: formatMessage(messages.done),
        },
      });
    },
    [formatMessage],
  );

  const openTooltipTray = useCallback(() => {
    toggleOn();
  }, [toggleOn]);

  return useMemo(
    () => ({
      tooltipTray,
      significantPriceChangeTray,
      subscriptionSignupFlowTray,
      subscriptionUpgradeFlowTray,
      usdBalanceTray,
      subscriptionSignupFlowTrayVisible,
      toggleSubscriptionSignupFlowTrayOn,
      toggleSubscriptionSignupFlowTrayOff,
      toggleSubscriptionUpgradeFlowTrayOn,
      toggleSubscriptionUpgradeFlowTrayOff,
      handleOneTimeBonusInfoPress,
      handleShowInfoTray,
      handleFeeInfoPress,
      showPriceChangeTray,
      showUSDBalanceTray,
      handleTaxInfoPress,
      updateTooltipTray,
      openTooltipTray,
    }),
    [
      tooltipTray,
      significantPriceChangeTray,
      subscriptionSignupFlowTray,
      subscriptionUpgradeFlowTray,
      usdBalanceTray,
      subscriptionSignupFlowTrayVisible,
      toggleSubscriptionSignupFlowTrayOn,
      toggleSubscriptionSignupFlowTrayOff,
      toggleSubscriptionUpgradeFlowTrayOn,
      toggleSubscriptionUpgradeFlowTrayOff,
      handleOneTimeBonusInfoPress,
      handleShowInfoTray,
      handleFeeInfoPress,
      showPriceChangeTray,
      showUSDBalanceTray,
      handleTaxInfoPress,
