import { CashOperation } from '@app/components/navigation/stacks/SimpleTradeCashStack';
import { NetworkBoundary } from '@app/components/NetworkBoundary';
import { ErrorTray } from '@app/components/Trays/ErrorTray';
import { useNativeCurrencyFormatter } from '@app/hooks/formatters/useNativeCurrencyFormatter';
import { useFiatAssetsWithUsdc } from '@app/hooks/useFiatAssetsWithUsdc';
import { MyCashInformationTray } from '@app/screens/AssetsTab/components/MyCashBalanceHeader/MyCashInformationTray';
import { isAssetOfType, USDC_TICKER } from '@app/screens/Stablecoin/constants';
import { messages } from '@app/screens/Stablecoin/messages';

import { CashSelectorTrayFragment$key } from './__generated__/CashSelectorTrayFragment.graphql';

type CashSelectorContentProps = Pick<
  CashSelectorTrayProps,
  'cashOperation' | 'selected' | 'queryRef'
> & {
  onSelect: (selectedCurrency: string) => void;
};

function CashSelectorContent({
  cashOperation,
  onSelect,
  selected,
  queryRef,
}: CashSelectorContentProps) {
  const { formatMessage } = useIntl();
  const formatAmount = useNativeCurrencyFormatter();
  const [
    isInformationTrayVisible,
    { toggleOn: toggleInformationTrayOn, toggleOff: toggleInformationTrayOff },
  ] = useToggler();

  const query = useFragment<CashSelectorTrayFragment$key>(
    graphql`
      fragment CashSelectorTrayFragment on Query {
        ...useFiatAssetsWithUsdcFragment
          @arguments(usdcAssetId: $usdcAssetId, country: $country)
        viewer {
          assetBySlug(slug: $slug) {
            asset {
              uuid
            }
            rewardApy {
              formattedValue
              statsLabel
            }
          }
          # A temporary workaround until a better available balance for cash out is supported
          accountByUuid(uuid: $usdcSlugId) {
            assetOrFiatCurrency {
              ... on ViewerAsset {
                assetBalanceBreakdown {
                  availableToCashOutBalanceFiat: availableToSendBalanceFiat {
                    value
                  }
                }
              }
            }
          }
        }
      }
    `,
    queryRef,
  );
  const { viewer } = query;
  const reward = viewer?.assetBySlug?.rewardApy;
  const stableAssets = useFiatAssetsWithUsdc(query);

  const subdetail = useMemo(() => {
    if (cashOperation === 'cash_in') {
      return formatMessage(messages.cashTrayBalanceLabel);
    }
    return formatMessage(messages.cashoutBalanceLabel);
  }, [cashOperation, formatMessage]);

  const assetCells = useMemo(
    () =>
      stableAssets
        .filter(
          (asset) =>
            asset.currency.code === 'USD' ||
            asset.currency.code === USDC_TICKER,
        )
        .map((asset) => {
          const isStablecoin = isAssetOfType(
            asset.currency.code,
            viewer?.assetBySlug?.asset?.uuid,
          );

          const isCashIn = cashOperation === 'cash_in';
          const isCashOut = cashOperation === 'cash_out';

          // Deposits - show the total balance for stable asset regardless if it's available to use or not
          // Withdraws - show only the available balance the user can withdraw
          let amount = asset?.availableToTradeBalanceFiat?.amount;
          if (isStablecoin) {
            if (isCashIn) {
              amount = asset?.balance?.amount;
            } else if (isCashOut) {
              amount =
                viewer?.accountByUuid?.assetOrFiatCurrency
                  ?.assetBalanceBreakdown?.availableToCashOutBalanceFiat?.value;
            }
          }

          return (
            <ListCell
              key={asset.currency.code}
              detail={formatAmount({
                amount: amount || '',
                isSensitive: true,
              })}
              description={
                isStablecoin ? (
                  <TextLabel2 color="positive">
                    {reward?.formattedValue} {reward?.statsLabel}
                  </TextLabel2>
                ) : undefined
              }
              media={
                isStablecoin ? (
                  <CellMedia
                    type="asset"
                    source={asset.currency.image.url}
                    accessibilityLabel={asset.currency.code}
                  />
                ) : (
                  <Icon
                    size="l"
                    bordered
                    name={`cash${asset.currency.code}` as IconName}
                  />
                )
              }
              onPress={() => onSelect(asset.currency.code)}
              outerSpacing={{ spacingHorizontal: 0 }}
              subdetail={subdetail}
              title={asset.currency.name}
              selected={selected === asset.currency.code}
            />
          );
        }),
    [
      formatAmount,
      onSelect,
      reward?.formattedValue,
      reward?.statsLabel,
      selected,
      stableAssets,
      subdetail,
      cashOperation,
      viewer?.assetBySlug?.asset?.uuid,
      viewer?.accountByUuid?.assetOrFiatCurrency?.assetBalanceBreakdown
        ?.availableToCashOutBalanceFiat?.value,
    ],
  );

  const trayTitle = useMemo(() => {
    if (cashOperation === 'cash_out') {
      return formatMessage(messages.withdrawTrayTitle);
    }

    return formatMessage(messages.DepositTrayTitle);
  }, [cashOperation, formatMessage]);

  return (
    <VStack spacingHorizontal={3} spacingVertical={0.5}>
      <HStack alignItems="center" justifyContent="center" gap={1}>
        <TextHeadline>{trayTitle}</TextHeadline>
        <PressableOpacity
          accessibilityRole="button"
          onPress={toggleInformationTrayOn}
          testID="information-btn"
        >
          <Icon name="info" size="xs" color="foregroundMuted" />
        </PressableOpacity>
      </HStack>
      {assetCells}
      <MyCashInformationTray
        isVisible={isInformationTrayVisible}
        onDismiss={toggleInformationTrayOff}
      />
    </VStack>
  );
}

type CashSelectorTrayProps = {
  cashOperation: CashOperation;
  isTrayVisible: boolean;
  queryRef: CashSelectorTrayFragment$key;
  selected: string;
  toggleTrayOff: (selectedCurrency: string, isBlurred: boolean) => void;
};

export const CashSelectorTray = memo(function CashSelectorTray({
  cashOperation,
  isTrayVisible,
  toggleTrayOff,
  selected,
  queryRef,
}: CashSelectorTrayProps) {
  const trayRef = useRef<DrawerRefBaseProps | null>(null);
  // use ref instead of state because state is reset when onCloseComplete fires
  const isBlurred = useRef<boolean>(false);
  const selectedCurrency = useRef<string>(selected);

  const handleOnBlur = useCallback(() => {
    isBlurred.current = true;
  }, []);

  const handleOnPickerPress = useCallback((currency: string) => {
    isBlurred.current = false;
    selectedCurrency.current = currency;
    trayRef.current?.handleClose();
  }, []);

  const handleOnCloseComplete = useCallback(() => {
    toggleTrayOff(selectedCurrency.current, isBlurred.current);
  }, [toggleTrayOff]);

  const errorFallback = useCallback(() => {
    return (
      <ErrorTray isVisible={isTrayVisible} onDismiss={handleOnCloseComplete} />
    );
  }, [isTrayVisible, handleOnCloseComplete]);

  if (!isTrayVisible) {
    return null;
  }

  return (
    <NetworkBoundary
      suspenseFallback={null}
      errorFallback={errorFallback}
      willErrorBlockUser={false}
    >
      <Tray
        onBlur={handleOnBlur}
        onCloseComplete={handleOnCloseComplete}
        ref={trayRef}
        testID="cash-selector-tray"
      >
        <CashSelectorContent
          cashOperation={cashOperation}
          onSelect={handleOnPickerPress}
          selected={selected}
          queryRef={queryRef}
        />
      </Tray>
    </NetworkBoundary>
  );
});

