type SimpleRewardsOverviewProps = {
  queryRef: SimpleRewardsOverviewFragment$key;
  currency: string;
};

function SimpleRewardsOverviewContent({
  queryRef,
  currency,
}: SimpleRewardsOverviewProps) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const formatStablecoinAmount = useStablecoinFormatter();

  const navigateToRewardsInformation = useCallback(() => {
    navigate('RewardsInformation', {
      currency,
    });
  }, [navigate, currency]);

  const query = useFragment(
    graphql`
      fragment SimpleRewardsOverviewFragment on Query {
        ...useHasTieredRewardsExperimentFragment
        retailAccruedRewardsSummary {
          accruedThisMonth {
            amount {
              value
              currency
            }
          }
        }
        stablecoinRateCard {
          rateCard {
            # eslint-disable-next-line relay/unused-fields
            upperBalanceLimit
            # eslint-disable-next-line relay/unused-fields
            lowerBalanceLimit
            rewardRate
          }
          currency
        }
        viewer {
          assetBySymbol(symbol: $assetSymbolOrSlug) {
            accounts {
              primary
              type
              totalBalance {
                value
              }
            }
            earnPayout {
              totalFiat {
                value
                currency
              }
            }
            asset {
              uuid
            }
            earnProgram {
              isEnrolled
            }
          }
        }
      }
    `,
    queryRef,
  );

  const hasTieredRewardsExperiment = useHasTieredRewardsExperiment({
    queryRef: query,
  });

  const accounts = query?.viewer?.assetBySymbol?.accounts;

  const totalStablecoinBalance = accounts?.find(
    (account) => account?.primary && account?.type === 'WALLET',
  )?.totalBalance?.value;

  const earnProgram = query.viewer?.assetBySymbol
    ?.earnProgram as EarnProgramType;
  const isEligible = !!earnProgram;
  const isEnrolled = earnProgram?.isEnrolled;
  const rateCard = query.stablecoinRateCard?.rateCard;
  const asset = query.viewer?.assetBySymbol?.asset;

  const currentRateLevel = useMemo(() => {
    return getCurrentRewardsLevel(
      totalStablecoinBalance,
      rateCard as RateCard[],
    );
  }, [rateCard, totalStablecoinBalance]);

  const nextRateLevel = useMemo(() => {
    return getNextRewardsLevel(totalStablecoinBalance, rateCard as RateCard[]);
  }, [rateCard, totalStablecoinBalance]);

  const amountUntilNextLevel = useMemo(() => {
    return getAmountUntilNextRewardLevel(
      totalStablecoinBalance,
      rateCard as RateCard[],
    );
  }, [rateCard, totalStablecoinBalance]);

  const formattedAmountUntilNextLevel = useMemo(() => {
    return formatStablecoinAmount({
      amount: amountUntilNextLevel,
      currency,
      forceCrypto: true,
    });
  }, [amountUntilNextLevel, currency, formatStablecoinAmount]);

  const decimalUntilNextRewardLevel = useMemo(() => {
    return getDecimalUntilNextRewardLevel(
      totalStablecoinBalance,
      rateCard as RateCard[],
    );
  }, [rateCard, totalStablecoinBalance]);

  const accruedThisMonth =
    query.retailAccruedRewardsSummary?.accruedThisMonth?.amount;

  const lifetimeEarnings = query.viewer?.assetBySymbol?.earnPayout?.totalFiat;

  const formattedAccruedThisMonth = useMemo(() => {
    return formatStablecoinAmount({
      amount: accruedThisMonth?.value,
      currency: accruedThisMonth?.currency,
    });
  }, [accruedThisMonth, formatStablecoinAmount]);

  const formattedLifetimeEarnings = useMemo(() => {
    return formatStablecoinAmount({
      amount: lifetimeEarnings?.value,
      currency: lifetimeEarnings?.currency,
    });
  }, [formatStablecoinAmount, lifetimeEarnings]);

  const navigateToPayouts = useCallback(() => {
    navigate('TransactionHistoryV2', {
      transactionTypeFilter: {
        messageId: 'usdcRewards',
        categories: ['INTEREST'],
      },
    });
  }, [navigate]);

  if (
    !hasTieredRewardsExperiment ||
    !nextRateLevel ||
    !isEligible ||
    !isEnrolled
  ) {
    return null;
  }

  return (
    <>
      <Divider offsetHorizontal={3} spacingBottom={3} />
      <Box>
        <Pressable
          background="transparent"
          accessibilityRole="button"
          onPress={navigateToRewardsInformation}
          noScaleOnPress
        >
          <TextTitle3>
            {formatMessage(messages.title, {
              currency,
            })}
          </TextTitle3>

          <TextBody color="foregroundMuted">
            {formatMessage(messages.subtitle, {
              currency,
            })}
          </TextBody>

          {amountUntilNextLevel && amountUntilNextLevel > 0 ? (
            <>
              <Box spacingTop={2} spacingBottom={1}>
                <ProgressBar progress={decimalUntilNextRewardLevel} />
              </Box>

              <HStack alignItems="center" gap={1}>
                <TextBody>
                  {formatMessage(messages.nextLevel, {
                    amount: formattedAmountUntilNextLevel,
                    rewardsApy: formatRewardsRate(nextRateLevel?.rewardRate),
                  })}
                </TextBody>

                <Icon name="infoInactive" size="s" color="foregroundMuted" />
              </HStack>
            </>
          ) : null}
        </Pressable>

        <VStack gap={3} spacingTop={3}>
          <HStack justifyContent="space-between">
            <TextHeadline>
              {formatMessage(messages.currentRateText)}
            </TextHeadline>
            <TextBody color="positive">
              {formatMessage(messages.apyDisplay, {
                rewardsApy: formatRewardsRate(currentRateLevel?.rewardRate),
              })}
            </TextBody>
          </HStack>

          <HStack justifyContent="space-between">
            <TextHeadline>{formatMessage(messages.accrualsText)}</TextHeadline>
            <TextBody>{formattedAccruedThisMonth}</TextBody>
          </HStack>

          <HStack justifyContent="space-between">
            <TextHeadline>
              {formatMessage(messages.lifetimeEarningsText)}
            </TextHeadline>
            <TextBody>{formattedLifetimeEarnings}</TextBody>
          </HStack>

          <Box spacingBottom={1}>
            <ButtonGroup block accessibilityLabel="Group">
              <Button variant="secondary" compact onPress={navigateToPayouts}>
                {formatMessage(messages.seePayouts)}
              </Button>
              <ManageButton assetId={asset?.uuid} spacingTop={0} />
            </ButtonGroup>
          </Box>
        </VStack>
      </Box>
    </>
  );
}

