function TieredRewardsUpsellTrayContent({
  upsell,
  onDismiss,
  currency,
  visible,
}: TieredRewardsUpsellTrayProps) {
  const { formatMessage } = useIntl();
  const navigateToAddCashScreen = useNavigateToBuyInput();
  const { navigate } = useStackNavigation();
  const formatStablecoinAmount = useStablecoinFormatter();

  const { onPrimaryClick, onSecondaryClick } = useUpsellFrameworkInteract(
    upsell,
    ComponentType.modal,
    true,
  );

  const handleAddCurrency = useCallback(() => {
    onPrimaryClick();
    onDismiss();

    navigateToAddCashScreen({
      cashOperation: 'cash_in',
      assetSymbolOrSlug: 'USDC',
      transferSource: 'dashboard',
    });
  }, [navigateToAddCashScreen, onDismiss, onPrimaryClick]);

  const handleLearnMore = useCallback(() => {
    onSecondaryClick();
    onDismiss();

    navigate('RewardsInformation', {
      currency,
    });
  }, [currency, navigate, onSecondaryClick, onDismiss]);

  const query = useLazyLoadQuery<TieredRewardsUpsellTrayQuery>(
    graphql`
      query TieredRewardsUpsellTrayQuery($currency: String!) {
        stablecoinRateCard {
          rateCard {
            # eslint-disable-next-line relay/unused-fields
            upperBalanceLimit
            # eslint-disable-next-line relay/unused-fields
            lowerBalanceLimit
            rewardRate
          }
          currency
        }
        viewer {
          assetBySymbol(symbol: $currency) {
            accounts {
              primary
              type
              totalBalance {
                value
              }
            }
            earnProgram {
              isEnrolled
            }
          }
        }
      }
    `,
    {
      currency: currency as never,
    },
  );

  const accounts = query?.viewer?.assetBySymbol?.accounts;

  const totalStablecoinBalance = accounts?.find(
    (account) => account?.primary && account?.type === 'WALLET',
  )?.totalBalance?.value;

  const earnProgram = query.viewer?.assetBySymbol
    ?.earnProgram as EarnProgramType;
  const isEligible = !!earnProgram;
  const isEnrolled = earnProgram?.isEnrolled;
  const rateCard = query.stablecoinRateCard?.rateCard;
  const maxRewardsRate = rateCard ? rateCard[rateCard.length - 1] : null;

  const currentRateLevel = useMemo(() => {
    return getCurrentRewardsLevel(
      totalStablecoinBalance,
      rateCard as RateCard[],
    );
  }, [rateCard, totalStablecoinBalance]);

  const nextRateLevel = useMemo(() => {
    return getNextRewardsLevel(totalStablecoinBalance, rateCard as RateCard[]);
  }, [rateCard, totalStablecoinBalance]);

  const amountUntilNextLevel = useMemo(() => {
    return getAmountUntilNextRewardLevel(
      totalStablecoinBalance,
      rateCard as RateCard[],
    );
  }, [rateCard, totalStablecoinBalance]);

  const formattedAmountUntilNextLevel = useMemo(() => {
    return formatStablecoinAmount({
      amount: amountUntilNextLevel,
      currency,
      forceCrypto: true,
    });
  }, [amountUntilNextLevel, currency, formatStablecoinAmount]);

  const decimalUntilNextRewardLevel = useMemo(() => {
    return getDecimalUntilNextRewardLevel(
      totalStablecoinBalance,
      rateCard as RateCard[],
    );
  }, [rateCard, totalStablecoinBalance]);

  if (
    !visible ||
    !currentRateLevel ||
    !nextRateLevel ||
    !maxRewardsRate ||
    !isEligible ||
    !isEnrolled ||
    amountUntilNextLevel === 0
  ) {
    return null;
  }

  return (
    <Tray onCloseComplete={onDismiss} testID="TieredRewardsUpsellTray">
      <VStack gap={2} spacingHorizontal={3}>
        <Box alignItems="center">
          <Pictogram name="earnNavigation" dimension="48x48" />
