          background="secondary"
          borderRadius="roundedLarge"
          spacingVertical={2}
          spacingHorizontal={3}
          gap={2}
        >
          <HStack justifyContent="space-between" alignItems="center">
            <Box>
              <TextBody>{formatMessage(messages.currentLevel)}</TextBody>
              <TextTitle3>
