            <Box>
              <TextBody>{formatMessage(messages.nextLevel)}</TextBody>
              <TextTitle3 color="positive">
                {formatMessage(messages.apyDisplay, {
                  apy: formatRewardsRate(nextRateLevel?.rewardRate),
                })}
