          <TextBody color="foregroundMuted">
            {formatMessage(messages.amountUntilNext, {
              amount: formattedAmountUntilNextLevel,
            })}
          </TextBody>
        </VStack>

        <VStack gap={3} spacingVertical={2}>
          <HStack gap={2} width="90%">
            <Icon name="checkmark" size="m" />
            <TextBody color="foregroundMuted">
              {formatMessage(messages.pointOne, {
                currency,
                maxRate: formatRewardsRate(maxRewardsRate?.rewardRate),
              })}
            </TextBody>
          </HStack>
          <HStack gap={2} width="90%">
            <Icon name="checkmark" size="m" />
            <TextBody color="foregroundMuted">
              {formatMessage(messages.pointTwo)}
            </TextBody>
          </HStack>
        </VStack>

        <ButtonGroup block accessibilityLabel="Group">
