import { memo, useMemo } from 'react';
import { ListCell, ListCellFallback } from '@cbhq/cds-mobile/cells';
import { HStack } from '@cbhq/cds-mobile/layout/HStack';
import { TextBody, TextHeadline } from '@cbhq/cds-mobile/typography';
import { graphql, useFragment } from '@cbhq/data-layer';
import { useIntl } from '@cbhq/i18n';

import { IconButton } from '@components/interactables/IconButton';
import { formatPercentage } from '@utils/number/percentageUtils';
import { InstrumentedSuspense } from '@app/components/InstrumentedSuspense';
import { app } from '@app/config/app';
import { useCurrencyFormatter } from '@app/hooks/formatters/useCurrencyFormatter';
import { AssetAllocationIcon } from '@app/screens/AssetsTab/components/AssetAllocationIcon/AssetAllocationIcon';
import { messages as YieldCenterMessages } from '@app/screens/YieldCenter/messages';

import { useMissedEarningsAmounts } from '../MissedEarningsProvider';

import { MissedEarningAssetsCellFragment$key } from './__generated__/MissedEarningAssetsCellFragment.graphql';

export type MissedEarningAsset = {
  assetUuid: string;
  cryptoAmount: number;
};

const MissedEarningAssetsCellContent = memo(
  ({
    nativeCurrency,
    earnProgramRef,
    onPress,
  }: MissedEarningAssetsCellProps) => {
    const { formatMessage } = useIntl();
    const formatCurrency = useCurrencyFormatter();

    const earnProgram = useFragment(
      graphql`
        fragment MissedEarningAssetsCellFragment on EarnProgram {
          currentRate {
            formatted
            unitSymbol
          }
          asset {
            asset {
              uuid
              name
              imageUrl
              color
            }
          }
        }
      `,
      earnProgramRef,
    );

    const rewardApy = earnProgram?.currentRate;
    const viewerAsset = earnProgram?.asset;
    const asset = viewerAsset?.asset;

    const { getStakeAmounts } = useMissedEarningsAmounts();
    const stakeAmounts = getStakeAmounts(asset?.uuid ?? '');

    const title = useMemo(() => {
      const assetName = rewardApy ? `${asset?.name} · ` : asset?.name;

      return (
        <HStack>
          <TextHeadline>
            {assetName}
            {rewardApy ? (
              <TextHeadline color="positive" inherit>
                {formatMessage(YieldCenterMessages.amountApy, {
                  amount: rewardApy.formatted,
                  apy: rewardApy.unitSymbol,
                })}
              </TextHeadline>
            ) : null}
          </TextHeadline>
        </HStack>
      );
    }, [asset?.name, formatMessage, rewardApy]);

    const rawPercent =
      (stakeAmounts?.amountToStakeInCrypto ?? 0) /
      (stakeAmounts?.totalStakingBalanceInCrypto ?? 0);

    if (!asset || !stakeAmounts?.totalStakingBalanceInCrypto) {
      return null;
    }

    const stakeTotal = formatCurrency({
      currency: { code: nativeCurrency, type: 'fiat' },
      amount: stakeAmounts.amountToStakeInFiat.toString(),
      isSensitive: true,
    });

    const stakePercent = formatPercentage({
      value: rawPercent,
      locale: app.locale,
      signDisplay: 'never',
      scale: 2,
    });

    return (
      <ListCell
        testID={`missed-earnings-cell-${asset?.uuid}`}
        media={
          <AssetAllocationIcon
            imageUrl={asset?.imageUrl ?? ''}
            color={asset?.color ?? '#fff'}
            progress={rawPercent}
          />
        }
        title={title}
        description={
          <TextBody color="foregroundMuted">
            {`${stakeTotal} (${stakePercent})`}
          </TextBody>
        }
        action={
          <IconButton
            testID={`missed-earnings-cell-edit-${asset?.uuid}`}
            name="pencil"
            variant="secondary"
            onPress={() =>
              onPress({
                assetUuid: asset?.uuid ?? '',
                cryptoAmount: stakeAmounts?.amountToStakeInCrypto ?? 0,
              })
            }
          />
        }
      />
    );
  },
);

