import { memo, useCallback, useEffect, useMemo, useState } from 'react';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { markJourney } from '@cbhq/core-vitals-mobile';
import { graphql, useFragmentWithError } from '@cbhq/data-layer';
import { useIntl } from '@cbhq/i18n';

import { Button } from '@components/interactables/Button';
import { useModal } from '@app/hooks/navigation/useModal';
import { useStackNavigation } from '@app/hooks/navigation/useStackNavigation';
import { useBuyAndStakeEligible } from '@app/screens/SimpleTrade/Buy/hooks/useBuyAndStakeEligible/useBuyAndStakeEligible';
import { useStakingActionEligibility } from '@app/screens/StakingV2/hooks/useStakingActionEligibility';
import { messages } from '@app/screens/StakingV2/messages';
import { useNavigateToBuyInput } from '@app/screens/Trade/Buy/BuyInput/hooks/useNavigateToBuyInput/useNavigateToBuyInput';
import { useDegradedBanner } from '@app/screens/YieldCenter/DegradedBannerProvider';
import { useAccountsByType } from '@app/screens/YieldCenter/hooks/useAccountsByType/useAccountsByType';

import {
  logBuyMoreButtonClick,
  logBuyMoreButtonView,
  logStakeMoreButtonClick,
  logStakeToEarnButtonClick,
  logStakingButtonView,
  logUnstakeButtonClick,
  StakingSource,
} from '../StakingV2Analytics';

import { StakingV2AccountActionsFragment$key } from './__generated__/StakingV2AccountActionsFragment.graphql';
import { EthUnstakingInterstitialTray } from './EthUnstakingInterstitialTray';
import { UnstakeButton } from './UnstakeButton';

type StakingV2AccountActionsProps = {
  accountRef: StakingV2AccountActionsFragment$key | null;
  compact?: boolean;
  source: StakingSource;
};

export const StakingV2AccountActions = memo(
  ({ accountRef, compact, source }: StakingV2AccountActionsProps) => {
    const { formatMessage } = useIntl();
    const { popStack } = useStackNavigation();
    const stakingV2Stack = useModal('StakingV2Stack');
    const navigateToBuyInput = useNavigateToBuyInput();
    const { setIsDegradedState } = useDegradedBanner();

    const [account, getErrors] = useFragmentWithError(
      graphql`
        fragment StakingV2AccountActionsFragment on Account {
          ...EthUnstakingInterstitialTrayAccountFragment
          type
          assetOrFiatCurrency {
            ... on ViewerAsset {
              ...UnstakeButtonFragment
              ...useStakingActionEligibilityFragment
              ...useBuyAndStakeEligibleFragment
              asset {
                platformName
              }
              staking {
                pendingRequests {
                  stakingAvailableBalance {
                    value
                  }
                  unstakingAvailableBalance {
                    value
                  }
                }
              }
              accounts {
                uuid
                ...useAccountsByTypeFragment
                availableBalance {
                  value
                }
              }
            }
          }
        }
      `,
      accountRef,
    );

    const viewerAsset = account?.assetOrFiatCurrency ?? null;
    const stakingActionEligibility = useStakingActionEligibility(viewerAsset);
    const isBuyAndStakeEligible = useBuyAndStakeEligible({
      viewerAssetRef: viewerAsset,
    });

    const isAccountsDegraded =
      viewerAsset?.accounts === null &&
      getErrors('viewerAsset.accounts') !== null;
    const isYieldServiceDegraded = stakingActionEligibility === null;

    useEffect(() => {
      setIsDegradedState({
        isAccountsDegraded,
        isYieldServiceDegraded,
      });
    }, [setIsDegradedState, isAccountsDegraded, isYieldServiceDegraded]);

    const platformName = account?.assetOrFiatCurrency?.asset?.platformName;
    const accounts = useAccountsByType(viewerAsset?.accounts);
    const primaryAccount = accounts.WALLET;
    const stakedAccount = accounts.STAKED_FUNDS;
    const unstakingAvailableBalance = Number(
      viewerAsset?.staking?.pendingRequests?.unstakingAvailableBalance?.value ??
        0,
    );
    const stakingAvailableBalance = Number(
      viewerAsset?.staking?.pendingRequests?.stakingAvailableBalance?.value ??
        0,
    );

    const hasZeroPrimaryBalance = useMemo(() => {
      return stakingAvailableBalance === 0;
    }, [stakingAvailableBalance]);

    const hasZeroStakedBalance = useMemo(
      () =>
        !stakedAccount ||
        Number(stakedAccount?.availableBalance?.value ?? 0) === 0,
      [stakedAccount],
    );

    const onStakePress = useCallback(() => {
      if (!platformName) {
        return;
      }
      markJourney('navigate_to_staking_nux_screen_from_account_screen_button');
      stakingV2Stack.present('StakingNux', {
        assetSymbol: platformName,
        transferSource: source,
      });
    }, [stakingV2Stack, platformName, source]);

    const handleStakeToEarnPress = useCallback(() => {
      logStakeToEarnButtonClick({
        asset: platformName ?? '',
        context: source,
      });
      onStakePress();
    }, [onStakePress, source, platformName]);

    const handleStakeMorePress = useCallback(() => {
      logStakeMoreButtonClick({
        asset: platformName ?? '',
        context: source,
      });
      onStakePress();
    }, [onStakePress, source, platformName]);

    const handleBuyMorePress = useCallback(() => {
      if (!platformName) {
        return;
      }

      // pop the earn stack so after a buy the user is taken to the Earn tab
      if (source === 'EarningDetails') {
        popStack();
      }

      logBuyMoreButtonClick({ asset: platformName, context: source });

      navigateToBuyInput({
        accountId: primaryAccount?.uuid,
        assetSymbolOrSlug: platformName,
        isBuyAndStakePreselected: isBuyAndStakeEligible,
        transferSource: source,
      });
    }, [
      source,
      popStack,
      platformName,
      navigateToBuyInput,
      primaryAccount?.uuid,
      isBuyAndStakeEligible,
    ]);

    const [unstakeInterstitialRendering, setUnstakeInterstitialRendering] =
      useState<{ hasRendered: boolean; shouldShow: boolean }>({
        hasRendered: false,
        shouldShow: false,
      });
    const toggleOn = useCallback(() => {
      setUnstakeInterstitialRendering({
        hasRendered: true,
        shouldShow: true,
      });
    }, [setUnstakeInterstitialRendering]);

    const toggleOff = useCallback(() => {
      setUnstakeInterstitialRendering({
        hasRendered: true,
        shouldShow: false,
      });
    }, [setUnstakeInterstitialRendering]);

    const presentUnstaking = useCallback(() => {
      if (platformName) {
        markJourney('navigate_to_unstaking_from_account_screen_button');
        stakingV2Stack.present('UnstakingInput', {
          assetSymbol: platformName,
          transferSource: source,
        });
      }
    }, [platformName, stakingV2Stack, source]);

    const onUnstakePress = useCallback(() => {
      if (!platformName) {
        return;
      }

      logUnstakeButtonClick({
        asset: platformName ?? '',
        context: source,
      });
      if (platformName.toLowerCase() === 'eth') {
        toggleOn();
      } else {
        presentUnstaking();
      }
    }, [source, platformName, presentUnstaking, toggleOn]);

    const handleInterstitialContinue = useCallback(() => {
      toggleOff();
      presentUnstaking();
    }, [toggleOff, presentUnstaking]);

    const unstakingOverlays = useMemo(() => {
      if (
        !platformName ||
        account?.type !== 'STAKED_FUNDS' ||
        !primaryAccount
      ) {
        return null;
      }

      if (!unstakeInterstitialRendering.hasRendered) {
        // do not render the interstitial tray until user has clicked unstake once
        return null;
      }

      return (
        <EthUnstakingInterstitialTray
          isVisible={unstakeInterstitialRendering.shouldShow}
          onDismiss={toggleOff}
          onContinue={handleInterstitialContinue}
          transferSource={source}
          accountRef={account}
        />
      );
    }, [
      platformName,
      account,
      primaryAccount,
      unstakeInterstitialRendering.hasRendered,
      unstakeInterstitialRendering.shouldShow,
      toggleOff,
      handleInterstitialContinue,
      source,
    ]);

    const buyButton = useMemo(() => {
      if (!platformName) {
        return null;
      }

      if (!hasZeroPrimaryBalance) {
        return null;
      }

      if (
        stakingActionEligibility?.BUY_AND_STAKE?.isHidden ||
        stakingActionEligibility?.STAKE?.isHidden
      ) {
        return null;
      }

      logBuyMoreButtonView({ asset: platformName ?? '', context: source });

      return (
        <Button compact={compact} onPress={handleBuyMorePress}>
          {formatMessage(messages.buyAndStake)}
        </Button>
      );
    }, [
      source,
      compact,
      platformName,
      formatMessage,
      handleBuyMorePress,
      hasZeroPrimaryBalance,
      stakingActionEligibility?.BUY_AND_STAKE?.isHidden,
      stakingActionEligibility?.STAKE?.isHidden,
    ]);

    const stakeButton = useMemo(() => {
      if (hasZeroPrimaryBalance) {
        return null;
      }

      if (stakingActionEligibility?.STAKE?.isHidden) {
        return null;
      }

      logStakingButtonView({
        asset: platformName ?? '',
        disabled: !stakingActionEligibility?.STAKE?.isEnabled,
        hasZeroStakedBalance,
        context: source,
      });

      if (hasZeroStakedBalance) {
        return (
          <Button
            compact={compact}
            onPress={handleStakeToEarnPress}
            disabled={!stakingActionEligibility?.STAKE?.isEnabled}
          >
            {formatMessage(messages.startEarning)}
          </Button>
        );
      }

      return (
        <Button
          compact={compact}
          onPress={handleStakeMorePress}
          disabled={!stakingActionEligibility?.STAKE?.isEnabled}
        >
          {formatMessage(messages.stakeMore)}
        </Button>
      );
    }, [
      source,
      compact,
      platformName,
      formatMessage,
      handleStakeMorePress,
      handleStakeToEarnPress,
      hasZeroPrimaryBalance,
      hasZeroStakedBalance,
      stakingActionEligibility?.STAKE?.isEnabled,
      stakingActionEligibility?.STAKE?.isHidden,
    ]);

    const unstakeButton = useMemo(() => {
      // staked account balance could exist during unstaking
      // so we also need to check for unstaking available balance
      if (
        hasZeroStakedBalance ||
        !stakedAccount ||
        !unstakingAvailableBalance
      ) {
        return null;
      }

      if (stakingActionEligibility?.UNSTAKE?.isHidden) {
        return null;
      }

      return (
        <UnstakeButton
          compact={compact}
          onPress={onUnstakePress}
          viewerAssetRef={viewerAsset}
          context={source}
          loading={unstakeInterstitialRendering.shouldShow}
        />
      );
    }, [
      hasZeroStakedBalance,
      stakedAccount,
      unstakingAvailableBalance,
      stakingActionEligibility?.UNSTAKE?.isHidden,
      compact,
      onUnstakePress,
      viewerAsset,
      source,
      unstakeInterstitialRendering.shouldShow,
    ]);

    // do not display if we can not get staking eligibility or account information
    if (
      !platformName ||
      !primaryAccount ||
      isYieldServiceDegraded ||
      isAccountsDegraded
    ) {
      return null;
    }

    return (
      <>
        <ButtonGroup
          block
          accessibilityLabel={formatMessage(messages.accountActionsA11yLabel)}
        >
          {unstakeButton}
          {hasZeroPrimaryBalance ? buyButton : stakeButton}
        </ButtonGroup>
        {unstakingOverlays}
      </>
    );
  },
);

