      componentName: 'installed_app_share',
      action: ActionType.click,
      flow: 'referrals',
      componentType: ComponentType.button,
      appName: installedApp.label,
    });
    if (isIncompatibleWithSharePackage(installedApp)) {
      await Linking.openURL(
        `${installedApp.urlScheme}://${installedApp.urlParams}?text=${smsBody}`,
      );
    } else {
      await Share.shareSingle({
        title: smsTitle,
        social: installedApp.type,
        message: smsBody,
      });
    }
  } catch (err) {
    logSubscriptionError({
      error: getErrorInstance(err),
      isHandled: true,
      componentName: 'ShareButtons',
    });
  }
}

export async function handlePressTrayShareCard(
  smsTitle: string,
  smsBody: string,
) {
  try {
    logEvent('subscription_management', {
      componentName: 'generic_share',
      action: ActionType.click,
      flow: 'referrals',
      componentType: ComponentType.button,
    });

    await Share.open({
      title: smsTitle,
      message: smsBody,
    });
  } catch (err) {
    logSubscriptionError({
      error: getErrorInstance(err),
      isHandled: true,
      componentName: 'ShareButtons',
    });
  }
}

export function isIncompatibleWithSharePackage(installedApp: AppData) {
  // workaround for the Social enums being compiled to undefined at runtime. If type is undefined, we try to read it as a string
  const installedAppTypeString =
    !installedApp.type || (installedApp.type as string);

  return (
    Platform.OS === 'ios' &&
    (installedApp.type === Social.Whatsapp ||
      installedAppTypeString === 'whatsapp')
  );
}

type ShareButtonsProps = {
  queryRef: ShareButtonsFragment$key;
};

export const ShareButtons = memo(({ queryRef }: ShareButtonsProps) => {
  const { formatMessage } = useIntl();
  const query = useFragment(
    graphql`
      fragment ShareButtonsFragment on Query {
        ...useIsReferralRewardZeroFragment
        ...useSubscriptionReferralsFragment
      }
    `,
    queryRef,
  );

  const { referralCode, rewardAmount } = useSubscriptionReferrals({
    queryRef: query,
  });
  const isRewardZero = useIsReferralRewardZero({ queryRef: query });

  const formattedSmsTitle = useMemo(
    () => formatMessage(messages.smsTitle),
    [formatMessage],
  );
  const spectrum = useSpectrum();

  const createSmsBody = useCallback(() => {
    const url = ReferralURL(referralCode);
    return formatMessage(
      isRewardZero ? messages.smsBodyZeroReward : messages.smsBody,
      {
        link: url,
        amount: rewardAmount,
      },
    );
  }, [formatMessage, rewardAmount, referralCode, isRewardZero]);

  return (
    <HStack flexGrow={1} justifyContent="center" gap={3} flexWrap="wrap">
      <HStack gap={3}>
        <ShareCard
          label={formatMessage(messages.messagesSocialTitle)}
          icon={
            <ShareButton
              dimensionOverride={40}
              spectrum={spectrum}
              source="messages"
            />
          }
          onPress={() => void handlePressSmsShareCard(createSmsBody())}
        />
        <ShareInstalledAppCard
          supportedApps={supportedApps}
          onPress={(installedApp) =>
            void handlePressInstalledApp(
              formattedSmsTitle,
              createSmsBody(),
              installedApp,
            )
          }
        />
      </HStack>
      <ShareCard
        label={formatMessage(messages.shareSocialTitle)}
        icon={
          <IconButton
            name="more"
            onPress={() =>
              void handlePressTrayShareCard(formattedSmsTitle, createSmsBody())
            }
          />
        }
        onPress={() =>
          void handlePressTrayShareCard(formattedSmsTitle, createSmsBody())
        }
      />
    </HStack>
  );
});

import { memo, useCallback, useEffect, useState } from 'react';
