import { SecurityReviewButton } from './components/SecurityReviewButton';
import { UnbanReviewForm } from './UnbanReviewForm';

const i18nKey = 'SupportUnbanInputScreen';
const messages = defineMessages({
  headerTitle: {
    id: `${i18nKey}.header`,
    defaultMessage: 'Please help us with some details',
    description: '',
  },
  headerSubtitle: {
    id: `${i18nKey}.headerSubtitle`,
    defaultMessage:
      'Providing false or insufficiently detailed answers could lead to rejection. Please provide as much information as possible to help us promptly review your account.',
    description: '',
  },
});

export const SupportUnbanInputScreen = memo(function SupportUnbanInputScreen() {
  const { inputs } = useParams<'SupportUnbanInputScreen'>();
  const { formatMessage } = useIntl();

  const { getReviewButtonLabel } = useSupportUnbanICHelpers();
  const buttonLabel = getReviewButtonLabel();

  const { userInputs } = useFields(UnbanReviewForm);
  const [showSubmitButton, setShowSubmitButton] = useState(false);

  useEffect(() => {
    const emptyTexts = inputs.filter(
      (item) => userInputs.value && !userInputs.value[item.id],
    );
    if (emptyTexts.length === 0) {
      setShowSubmitButton(true);
    } else {
      setShowSubmitButton(false);
    }
  }, [inputs, userInputs]);

  const handleInputChange = useCallback(
    (value: string, itemId: string) => {
      userInputs.onChange({ ...userInputs.value, [itemId]: value });
    },
    [userInputs],
  );

  return (
    <ScreenBoundary instrumentationId="SupportUnbanInputScreen">
      <Screen
        header={
          <Box flexDirection="column" spacingTop={2}>
            <TextTitle1 spacingVertical={1}>
              {formatMessage(messages.headerTitle)}
            </TextTitle1>
            <TextBody>{formatMessage(messages.headerSubtitle)}</TextBody>
          </Box>
        }
      >
        <VStack flexGrow={1} spacingTop={3}>
          {inputs.map((item) => {
            const currentValue = userInputs.value
              ? userInputs.value[item.id]
              : '';
            return (
              <TextInput
                accessibilityLabel="Text input field"
                key={item.id}
                label={item.question}
                placeholder="Type your response here"
                value={currentValue}
                onChangeText={(value) => handleInputChange(value, item.id)}
              />
            );
          })}
        </VStack>
        <SecurityReviewButton
          buttonLabel={buttonLabel}
          disabled={!showSubmitButton}
        />
      </Screen>
    </ScreenBoundary>
  );
});

