import { PixTransactionDetails } from './PixTransactionDetails';
// transactions of the following catgories will have their fee row
// say "Network fee" as opposed to "Coinbase fee" for the rest
const networkFeeCategories: AccountHistoryEntryCategory[] = [
  'CRYPTO_SEND',
  'EMAIL_SEND',
  'PHONE_SEND',
  'USER_RECEIVE',
  'CRYPTO_RECEIVE',
];

type TransactionCellsProps = {
  assetRef: TransactionCellsAssetFragment$key | null;
  viewerRef: TransactionCellsViewerFragment$key | null;
  transactionRef: TransactionCellsFragment$key | null;
};

const caretIconMarginTop = { marginTop: 4 };

export const TransactionCells = memo<TransactionCellsProps>(
  ({ transactionRef, assetRef, viewerRef }) => {
    const { formatMessage, formatDate, formatTime } = useIntl();
    const formatCurrency = useCurrencyFormatter();
    const toast = useToast();

    const assetOrCurrency = useFragment(
      graphql`
        fragment TransactionCellsAssetFragment on AssetOrCurrency {
          ... on TiersCurrency {
            exponent
          }
          ... on ViewerAsset {
            asset {
              exponent
            }
          }
        }
      `,
      assetRef,
    );

    const transaction = useFragment(
      graphql`
        fragment TransactionCellsFragment on AccountHistoryEntry
        @argumentDefinitions(
          shouldIncludeMgx: { type: "Boolean", defaultValue: false }
        ) {
          createdAt
          title
          category
          amount {
            value
            currency
          }
          nativeAmountV2 {
            value
            currency
          }
          ...TransactionStatusFragment
          ...PixTransactionDetailsFragment
          details {
            ...useDetailsUtilsIsSendOrReceive
            ...useDetailsUtilsIsFiatTransfer
            ... on BuyDetails {
              referenceCode
              nonNullablePricePerCoin: pricePerCoin {
                value
                currency
              }
              paymentMethod
              total {
                value
                currency
              }
              subtotal {
                value
                currency
              }
              fee {
                value
                currency
              }
              taxDetails {
                name
                amount {
                  value
                  currency
                }
              }
            }
            ... on SellDetails {
              referenceCode
              nonNullablePricePerCoin: pricePerCoin {
                value
                currency
              }
              paymentMethod
              total {
                value
                currency
              }
              subtotal {
                value
                currency
              }
              fee {
                value
                currency
              }
              taxDetails {
                name
                amount {
                  value
                  currency
                }
              }
            }
            ... on ConvertDetails {
              referenceCode
              paymentMethod
              pricePerCoin {
                value
                currency
              }
              taxDetails {
                name
                amount {
                  value
                  currency
                }
              }
            }
            ... on RetailMGXBuyDetails @include(if: $shouldIncludeMgx) {
              transactionReferenceCode: referenceCode
              nullablePaymentMethod: paymentMethod
              pricePerCoin {
                value
                currency
              }
              networkFee {
                value
                currency
              }
              coinbaseFee {
                value
                currency
              }
              subTotal {
                value
                currency
              }
              nullableTotal: total {
                value
                currency
              }
              nullableTo: to {
                address
              }
              networkInfo {
                networkName
                networkIconUrl
              }
            }
            ... on RetailMGXTradeDetails @include(if: $shouldIncludeMgx) {
              transactionReferenceCode: referenceCode
              nullablePaymentMethod: paymentMethod
              coinbaseFee {
                value
                currency
              }
              networkFee {
                value
                currency
              }
              pricePerCoin {
                value
                currency
              }
              networkInfo {
                networkName
                networkIconUrl
              }
            }
            ... on CryptoSendDetails {
              note
              transactionHash
              pricePerCoin {
                value
                currency
              }
              sendConfirmations: confirmations
              networkInfo {
                networkName
                networkIconUrl
              }
              fee {
                value
                currency
              }
              sendRecipient: recipient {
                address
                destinationTag
              }
            }
            ... on CryptoReceiveDetails {
              cryptoReceiveTo: to
              transactionHash
              receiveConfirmations: confirmations
              pricePerCoin {
                value
                currency
              }
              networkInfo {
                networkName
                networkIconUrl
              }
            }
            ... on UserSendDetails {
              note
              pricePerCoin {
                value
                currency
              }
              recipient
            }
            ... on UserReceiveDetails {
              note
              pricePerCoin {
                value
                currency
              }
              from
            }
            ... on FiatWithdrawalDetails {
              transactionReferenceCode: referenceCode
              to
              pixDetails {
                pixTransactionId
              }
            }
            ... on FiatDepositDetails {
              transactionReferenceCode: referenceCode
              from
              pixDetails {
                pixTransactionId
              }
            }
            ... on OrderDetails {
              to
              name
              description
              code
            }
            ... on SubscriptionRebateDetails {
              rebateNote: note
              orderId
            }
            ... on StakingTransferDetails {
              warmUpCompletionDate
            }
            ... on UnstakingTransferDetails {
              coolDownCompletionDate
              unstakeCompletionDate
            }
          }
        }
      `,
      transactionRef,
    );

    const [isLightiningInvoiceTruncated, setIsLightiningInvoiceTruncated] =
      useState(true);

    const { lookupEnsName, ensInfo } = useReverseResolveEnsLookup();
    const viewer = useFragment(
      graphql`
        # eslint-disable-next-line @cbhq/cdl-graphql-no-fragments-on-viewer
        fragment TransactionCellsViewerFragment on Viewer {
          ...PixTransactionDetailsViewerFragment
        }
      `,
      viewerRef,
    );

    const transactionDetails = transaction?.details;

    useEffect(() => {
      if (
        transaction?.category === 'CRYPTO_RECEIVE' &&
        transaction?.details?.from
      ) {
        lookupEnsName(transaction?.details?.from);
      }

      if (
        transaction?.category === 'CRYPTO_SEND' &&
        transactionDetails?.sendRecipient?.address
      ) {
        lookupEnsName(transactionDetails?.sendRecipient?.address);
      }
    }, [
      lookupEnsName,
      transaction?.category,
      transaction?.details?.from,
      transactionDetails?.sendRecipient?.address,
    ]);

    const [isToggled, { toggleOn, toggleOff }] = useToggler(false);
    const [tooltipTrayContent, setTooltipTrayContent] = useState<
      TrayContent | undefined
    >();
    const taxInfo = useCallback(
      (taxType: string) => {
        switch (taxType) {
          case 'INDIA_WITHHOLDING':
            return {
              title: formatMessage(messages.tdsTrayTitle),
              content: formatMessage(messages.tdsTrayContent),
            };
          case 'AUSTRALIA_GST':
            return {
              title: formatMessage(messages.gstTrayTitle),
              content: formatMessage(messages.auGstTrayContent),
            };
          case 'SINGAPORE_GST':
            return {
              title: formatMessage(messages.gstTrayTitle),
              content: formatMessage(messages.sgGstTrayContent),
            };
          default:
            return null;
        }
      },
      [formatMessage],
    );

    const exponent =
      assetOrCurrency?.asset?.exponent ?? assetOrCurrency?.exponent ?? 6;
    const handleTaxInfoPress = useCallback(
      (taxType: string) => {
        const taxTrayInfo = taxInfo(taxType);
        if (taxTrayInfo?.title && taxTrayInfo?.content) {
          setTooltipTrayContent({
            title: taxTrayInfo.title,
            message: taxTrayInfo.content,
            cta: {
              type: 'link',
              urlOrAction: getTaxLink(taxType),
              text: formatMessage(messages.learnMore),
            },
            dismiss: {
              text: formatMessage(messages.done),
            },
          });
          toggleOn();
        }
      },
      [formatMessage, taxInfo, toggleOn],
    );

    const handlePriceInfoPress = useCallback(() => {
      setTooltipTrayContent({
        title: '',
        message: formatMessage(messages.priceExecutedV2, {
          link: TradingFeesLink,
        }),
        dismiss: {
          text: formatMessage(messages.gotIt),
        },
      });
      toggleOn();
    }, [formatMessage, toggleOn]);

    const handleInvoiceCaretPress = useCallback(() => {
      setIsLightiningInvoiceTruncated((prev) => !prev);
    }, []);

    const isSendReceive = useIsSendOrReceive(transactionDetails ?? null);
    const isFiatTransfer = useIsFiatTransfer(transactionDetails ?? null);
    const hideTxStatus = isSendReceive;
    const taxTitleMessage: Record<string, string> = useMemo(
      () => ({
        INDIA_WITHHOLDING: formatMessage(messages.tds),
        AUSTRALIA_GST: formatMessage(messages.gst),
        SINGAPORE_GST: formatMessage(messages.gst),
      }),

      [formatMessage],
    );

    const transactionTime = formatTime(transaction?.createdAt);
    const transactionDate = formatDate(transaction?.createdAt, {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });

    const isSubscriptionRebate: boolean =
      transaction?.category === 'SUBSCRIPTION_REBATE';
    const isMgxBuyCategory = transaction?.category === 'RETAIL_MGX_DEX_BUY';
    const isMgxDexTradeCategory =
      transaction?.category === 'RETAIL_MGX_DEX_TRADE';
    const isMgxCategory = isMgxBuyCategory || isMgxDexTradeCategory;
    const taxes = transaction?.details?.taxDetails;
    const isNetworkFeeRow =
      transaction?.category &&
      networkFeeCategories.includes(transaction?.category);
    const isStaking =
      transaction?.category === 'STAKING' ||
      transaction?.category === 'UNSTAKING';
    const isWrapping =
      transaction?.category === 'WRAPPING' ||
      transaction?.category === 'UNWRAPPING';
    const isStakingReward = transaction?.category === 'STAKING_REWARD';
    const isDustTransaction = transaction?.category === 'RETAIL_SIMPLE_DUST';

    const generateCellPress = (address: string) => {
      return function onAddressPress() {
        toast.clearQueue();
        Haptics.lightImpact()
          .then(() => {
            setStringAsync(address).then(() =>
              toast.show(formatMessage(messages.copied)),
            );
          })
          .catch((error) =>
            errorVitals.logError(getErrorInstance(error), {
              context: 'transaction_cells_clipboard',
              severity: 'error',
              isHandled: false,
            }),
          );
      };
    };

    const referenceCode =
      transactionDetails?.referenceCode ??
      transactionDetails?.transactionReferenceCode;
    const paymentMethod =
      transactionDetails?.paymentMethod ??
      transactionDetails?.nullablePaymentMethod;

    const subtotal =
      transactionDetails?.subtotal ?? transactionDetails?.subTotal;
    const total =
      transactionDetails?.total ?? transactionDetails?.nullableTotal;

    // For crypto transactions
    const pricePerCoin = useMemo(() => {
      return isFiatTransfer || isDustTransaction
        ? undefined
        : transactionDetails?.nonNullablePricePerCoin ??
            transactionDetails?.pricePerCoin ?? {
              value: (
                Number(transaction?.nativeAmountV2?.value) /
                Number(transaction?.amount.value)
              ).toString(),
              currency: transaction?.nativeAmountV2?.currency,
            };
    }, [
      isFiatTransfer,
      isDustTransaction,
      transactionDetails?.nonNullablePricePerCoin,
      transactionDetails?.pricePerCoin,
      transaction?.nativeAmountV2?.value,
      transaction?.nativeAmountV2?.currency,
      transaction?.amount.value,
    ]);

    // For fiat transactions where fiat wallet currency != transaction currency (ex: Canadian users with a USD fiat wallet)
    const exchangeRate = useMemo(() => {
      return isFiatTransfer &&
        transaction?.nativeAmountV2?.currency &&
        transaction?.amount?.currency &&
        transaction?.nativeAmountV2.currency !== transaction?.amount.currency
        ? {
            value: (
              Number(transaction?.nativeAmountV2.value) /
              Number(transaction?.amount.value)
            ).toString(),
            baseCurrency: transaction?.amount.currency,
            quoteCurrency: transaction?.nativeAmountV2.currency,
          }
        : undefined;
    }, [
      isFiatTransfer,
      transaction?.nativeAmountV2?.currency,
      transaction?.amount?.currency,
      transaction?.amount.value,
      transaction?.nativeAmountV2?.value,
    ]);

    const recipient =
      transactionDetails?.sendRecipient?.address ??
      transactionDetails?.to ??
      transactionDetails?.cryptoReceiveTo ??
      transactionDetails?.nullableTo?.address ??
      transactionDetails?.recipient;
    const { verifiedWalletsMap } = useVerifiedWallets();
    const isVerifiedWallet = recipient && !!verifiedWalletsMap[recipient];

    const truncatedRecipient = useMemo(() => {
      if (recipient) {
        return getEllipsizedString(recipient, 6);
      }

      return '';
    }, [recipient]);

    const isPixTransaction =
      transaction?.amount?.currency === 'BRL' &&
      !!transaction?.details?.pixDetails?.pixTransactionId;

    const feeLabel = useMemo(() => {
      if (transactionDetails?.networkInfo?.networkName === 'Lightning') {
        return formatMessage(messages.processingFee);
      }

      if (isNetworkFeeRow) {
        return formatMessage(messages.networkFee);
      }

      return formatMessage(messages.fee);
    }, [formatMessage, isNetworkFeeRow, transactionDetails?.networkInfo]);

    if (isPixTransaction) {
      return (
        <PixTransactionDetails
          transactionRef={transaction}
          viewerRef={viewer}
        />
      );
    }

    const formattedTransactionAmount = formatCurrency({
      amount: pricePerCoin?.value,
      currency: {
        code: pricePerCoin?.currency,
        type: 'fiat',
      },
      isSensitive: false,
      minimumFractionDigits: getPriceScale(pricePerCoin?.value),
    });

    const isFromCoinbaseOne =
      transaction?.category === 'CB_ONE_BOOSTED_INTEREST' ||
      transaction?.category === 'SUBSCRIPTION_REBATE';

    return (
      <>
        {isFromCoinbaseOne && (
          <TransactionDetailCell
            title={formatMessage(messages.from)}
            detail={
              <HStack alignItems="center">
                <Box spacingEnd={1}>
                  <Icon name="coinbaseOne" size="s" color="primary" />
                </Box>
                <TextBody color="foregroundMuted">{PRODUCT_NAME}</TextBody>
              </HStack>
            }
          />
        )}
        {!!referenceCode && (
          <TransactionDetailCell
            title={formatMessage(messages.referenceCode)}
            detail={referenceCode}
          />
        )}
        {!!transactionDetails?.from && (
          <TransactionDetailCell
            title={formatMessage(messages.from)}
            onPress={
              transaction?.category === 'CRYPTO_RECEIVE'
                ? generateCellPress(transactionDetails?.from)
                : undefined
            }
            detail={
              <TextBody
                align="end"
                color="foregroundMuted"
                mono={transaction?.category === 'CRYPTO_RECEIVE'}
              >
                {transactionDetails?.from}
              </TextBody>
            }
          />
        )}
        {(!!transactionDetails?.sendRecipient?.address ||
          !!transactionDetails?.to ||
          !!transactionDetails?.cryptoReceiveTo ||
          !!transactionDetails?.nullableTo?.address ||
          !!transactionDetails?.recipient ||
          isVerifiedWallet) && (
          <TransactionDetailCell
            outerSpacing={
              ensInfo?.address
                ? {
                    spacingHorizontal: 0,
                    spacingVertical: 0,
                    offsetBottom: 1,
                  }
                : undefined
            }
            title={formatMessage(messages.to)}
            onPress={
              transaction?.category === 'CRYPTO_SEND'
                ? generateCellPress(
                    transactionDetails?.sendRecipient?.address as string,
                  )
                : undefined
            }
            detail={
              transactionDetails?.networkInfo?.networkName === 'Lightning' ? (
                <HStack alignItems="flex-start" gap={1}>
                  {isLightiningInvoiceTruncated ? (
                    <TextBody
                      color="foregroundMuted"
                      testID="lightningInvoiceTruncated"
                    >
                      {truncatedRecipient}
                    </TextBody>
                  ) : (
                    <TextBody color="foregroundMuted" testID="lightningInvoice">
                      {recipient}
                    </TextBody>
                  )}
                  <Pressable
                    accessibilityRole="button"
                    background="transparent"
                    onPress={handleInvoiceCaretPress}
                    hitSlop={16}
                    style={caretIconMarginTop}
                  >
                    <Icon
                      testID="lightiningInvoiceCaretIcon"
                      size="s"
                      name={
                        isLightiningInvoiceTruncated ? 'caretDown' : 'caretUp'
                      }
                      color="foreground"
                    />
                  </Pressable>
                </HStack>
              ) : (
                <VStack alignItems="flex-end">
                  <HStack gap={0.5} alignItems="center">
                    {(!!ensInfo?.address || isVerifiedWallet) && (
                      <TextBody>
                        {ensInfo?.ensName ||
                          formatMessage(messages.verifiedWallet)}
                      </TextBody>
                    )}
                    {isVerifiedWallet && (
                      <Icon name="circleCheckmark" size="xs" color="primary" />
                    )}
                  </HStack>
                  <TextBody
                    color="foregroundMuted"
                    mono={transaction?.category === 'CRYPTO_SEND'}
                    align="end"
                  >
                    {recipient}
                  </TextBody>
                </VStack>
              )
            }
            dontWrapDetail
          />
        )}
        {!!transactionDetails?.sendRecipient?.destinationTag && (
          <TransactionDetailCell
            title={formatMessage(messages.destinationTag)}
            detail={
              <TextBody
                color="foregroundMuted"
                mono={transaction?.category === 'CRYPTO_SEND'}
              >
                {transactionDetails?.sendRecipient?.destinationTag}
              </TextBody>
            }
            overflow="ellipsize-middle"
          />
        )}
        {!!pricePerCoin &&
          !isFiatTransfer &&
          !isSubscriptionRebate &&
          !isStaking &&
          !isWrapping && (
            <TransactionDetailCell
              title={formatMessage(messages.price)}
              onInfoPress={isSendReceive ? undefined : handlePriceInfoPress}
              info={isSendReceive || isStakingReward ? undefined : 'info'}
              detail={formattedTransactionAmount}
            />
          )}
        {isWrapping && (
          <TransactionDetailCell
            title={formatMessage(messages.conversionRate)}
            detail={formattedTransactionAmount}
          />
        )}
        {!!exchangeRate && isFiatTransfer && (
          <TransactionDetailCell
            title={formatMessage(messages.exchangeRate, {
              base: exchangeRate.baseCurrency,
              quote: exchangeRate.quoteCurrency,
            })}
            detail={formatCurrency({
              amount: exchangeRate.value,
              currency: {
                code: exchangeRate.quoteCurrency,
                type: 'fiat',
              },
              isSensitive: false,
              minimumFractionDigits: getPriceScale(exchangeRate.value),
            })}
          />
        )}
        {!!transactionDetails?.networkInfo && (
          <TransactionDetailCell
            title={formatMessage(messages.network)}
            detail={
              <NetworkInfo
                networkName={transactionDetails?.networkInfo?.networkName ?? ''}
                networkIconUrl={
                  transactionDetails?.networkInfo?.networkIconUrl ?? ''
                }
              />
            }
          />
        )}
        {!!transactionDetails?.fee && !isDustTransaction && (
          <TransactionDetailCell
            testID="TransactionDetailFeeCell"
            title={feeLabel}
            detail={formatCurrency({
              amount: transactionDetails.fee.value,
              currency: {
                type: 'crypto',
                code: transactionDetails.fee.currency,
                exponent,
              },
              isSensitive: false,
            })}
          />
        )}
        {isMgxCategory && !!transactionDetails?.networkFee && (
          <TransactionDetailCell
            testID="MgxTransactionNetworkFeeCell"
            title={formatMessage(messages.networkFee)}
            detail={formatCurrency({
              amount: transactionDetails.networkFee.value,
              currency: {
                type: 'crypto',
                code: transactionDetails.networkFee.currency,
                exponent,
              },
              isSensitive: false,
            })}
          />
        )}
        {isMgxCategory && !!transactionDetails?.coinbaseFee && (
          <TransactionDetailCell
            testID="MgxTransactionCoinbaseFeeCell"
            title={formatMessage(messages.fee)}
            detail={formatCurrency({
              amount: transactionDetails.coinbaseFee.value,
              currency: {
                type: 'crypto',
                code: transactionDetails.coinbaseFee.currency,
                exponent,
              },
              isSensitive: false,
            })}
          />
        )}
        {taxes?.map(({ name, amount }) =>
          Number(amount.value) ? (
            <TransactionDetailCell
              key={name}
              title={taxTitleMessage[name]}
              minWidth={44}
              onInfoPress={() => handleTaxInfoPress(name)}
              info="info"
              detail={formatCurrency({
                amount: amount.value,
                currency: {
                  type: 'fiat',
                  code: amount.currency,
                },
                isSensitive: false,
              })}
            />
          ) : null,
        )}
        {(!!transactionDetails?.sendConfirmations ||
          !!transactionDetails?.receiveConfirmations) && (
          <TransactionDetailCell
            title={formatMessage(messages.confirmations)}
            detail={
              transactionDetails?.sendConfirmations?.toString() ??
              transactionDetails?.receiveConfirmations?.toString()
            }
          />
        )}
        {!!paymentMethod && (
          <ConfirmationCell
            key={formatMessage(messages.paymentMethod)}
            title={formatMessage(messages.paymentMethod)}
            detail={paymentMethod}
          />
        )}
        {!!subtotal && !isDustTransaction && (
          <TransactionDetailCell
            title={formatMessage(messages.subtotal)}
            detail={formatCurrency({
              amount: subtotal.value,
              currency: {
                code: subtotal.currency,
                type: 'fiat',
              },
              isSensitive: false,
            })}
          />
        )}
        {!isMgxDexTradeCategory && !!total && (
          <TransactionDetailCell
            title={formatMessage(messages.total)}
            detail={formatCurrency({
              amount: total.value,
              currency: {
                code: total.currency,
                type: 'fiat',
              },
              isSensitive: false,
            })}
          />
        )}
        {!!transactionDetails?.name && (
          <TransactionDetailCell
            title={formatMessage(messages.name)}
            detail={transactionDetails.name}
          />
        )}
        {!!transactionDetails?.description && (
          <TransactionDetailCell
            title={formatMessage(messages.description)}
            detail={transactionDetails.description}
          />
        )}
        {!!transactionDetails?.code && (
          <TransactionDetailCell
            title={formatMessage(messages.code)}
            detail={transactionDetails.code}
          />
        )}
        {transactionDetails?.transactionHash ? (
          <TransactionDetailCell
            onPress={generateCellPress(transactionDetails?.transactionHash)}
            title={formatMessage(messages.transactionHash)}
            detail={getEllipsizedString(transactionDetails?.transactionHash, 6)}
          />
        ) : null}
        <TransactionDetailCell
          title={formatMessage(messages.date)}
          detail={`${transactionTime} – ${transactionDate}`}
        />
        {!!transactionDetails?.note && (
          <TransactionDetailCell
            title={formatMessage(messages.note)}
            detail={transactionDetails?.note}
          />
        )}
        {isSubscriptionRebate && !!transactionDetails?.rebateNote && (
          <TransactionDetailCell
            title={formatMessage(messages.note)}
            detail={transactionDetails?.rebateNote}
          />
        )}
        {!!transactionDetails?.orderId && (
          <TransactionDetailCell
            title={formatMessage(messages.orderId)}
            detail={transactionDetails?.orderId}
          />
        )}
        {!!transactionDetails?.warmUpCompletionDate && (
          <TransactionDetailCell
            title={formatMessage(messages.warmUpCompletionDate)}
            detail={formatDate(transactionDetails?.warmUpCompletionDate, {
              year: 'numeric',
              month: 'short',
              day: 'numeric',
            })}
          />
        )}
        {!!transactionDetails?.unstakeCompletionDate && (
          <TransactionDetailCell
            title={formatMessage(messages.unstakeCompletionDate)}
            detail={formatDate(transactionDetails?.unstakeCompletionDate, {
              year: 'numeric',
              month: 'short',
              day: 'numeric',
            })}
          />
        )}
        {!hideTxStatus ? (
          <TransactionDetailCell
            title={formatMessage(messages.status)}
            detail={
              transaction ? (
                <TransactionStatus
                  // Use React.Fragment instead of default Box to utilize
                  // TransactionDetailCell's wrapping and right-alignment.
                  container={Fragment}
                  transactionRef={transaction}
                />
              ) : null
            }
          />
        ) : null}
        {!!transactionDetails?.coolDownCompletionDate && (
          <TransactionDetailCell
            title={formatMessage(messages.unstakingEarningStatus)}
            detail={formatMessage(
              new Date(transactionDetails?.coolDownCompletionDate) > new Date()
                ? messages.isEarningRewards
                : messages.notEarningRewards,
            )}
          />
        )}
        <TooltipTray
          hideTray={toggleOff}
          isVisible={isToggled}
          content={tooltipTrayContent}
        />
      </>
    );
  },
);

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Platform, View } from 'react-native';
import Animated, { FadeIn } from 'react-native-reanimated';
import { AccountHistoryEntryStatus } from '@core/__generated__/enums';
import { DrawerRefBaseProps, useToggler } from '@cbhq/cds-common';
import { gutter } from '@cbhq/cds-common/tokens/sizing';
import { usePalette } from '@cbhq/cds-mobile/hooks/usePalette';
import { useSpacingScale } from '@cbhq/cds-mobile/hooks/useSpacingScale';
import { Icon } from '@cbhq/cds-mobile/icons';
import { Box, HStack, Spacer, VStack } from '@cbhq/cds-mobile/layout';
import { RemoteImage } from '@cbhq/cds-mobile/media/RemoteImage';
import { Tray } from '@cbhq/cds-mobile/overlays';
import { Pressable } from '@cbhq/cds-mobile/system/Pressable';
import { TextBody, TextTitle3 } from '@cbhq/cds-mobile/typography';
import { graphql } from '@cbhq/data-layer';
import { useIntl } from '@cbhq/i18n';

import { Button } from '@components/interactables/Button';
import { useWebBrowserOpener } from '@hooks/useWebBrowserOpener';
import { Spinner } from '@app/components/Spinner';
import { TransactionOnHoldTray } from '@app/components/TravelRules/TransactionOnHoldTray';
import { useParams } from '@app/hooks/navigation/useParams';
import { usePollGqlQuery } from '@app/hooks/usePollGqlQuery';
import { useFuzzyDurationFormatter } from '@app/screens/Send/components/ContactsList/hooks/useFuzzyDurationFormatter';
import useHasP2PLiveSendTimesExperiment from '@app/screens/Send/hooks/useHasP2PLiveSendTimesExperiment';
import {
  ESTIMATE_BUFFER_SECONDS,
  NETWORK_LATENCY_THRESHOLD_MAP_SECONDS,
} from '@app/screens/Send/SendPreviewScreen/SendPreviewScreenDetails';
import {
  DELAYED_TRANSACTION_SUPPORT_ARTICLE_URL,
  PENDING_TRANSACTIONS_SUPPORT_ARTICLE_URL,
} from '@app/screens/TransactionHistory/constants';

import { useStatusMessage } from '../hooks/useStatusMessage';
import { useTransactionCategory } from '../hooks/useTransactionCategory';
import { messages } from '../messages';

import { TransactionStatusTrackerPollingQuery } from './__generated__/TransactionStatusTrackerPollingQuery.graphql';
import StatusSpinner from './StatusSpinner';
import { TimeEstimate } from './TimeEstimate';

const STATUS_SPINNER_STYLE = { left: 15 };
const PRESSABLE_HIT_SLOP = { bottom: 30, left: 100, right: 30, top: 30 };

const FINISHED_STATUSES: Record<string, object> = {
  COMPLETED: messages.completed,
  FAILED: messages.failed,
  EXPIRED: messages.expired,
  CANCELED: messages.canceled,
  RETURNED: messages.returned,
};

type TransactionStatusTrackerProps = {
  transactionStatus: AccountHistoryEntryStatus | null;
};

const AnimatedView = Animated.createAnimatedComponent(View);
export function TransactionStatusTracker({
  transactionStatus,
}: TransactionStatusTrackerProps) {
  const openURL = useWebBrowserOpener();
  const { accountId, transactionId } = useParams<'TransactionDetails'>();
  const { formatMessage, formatDate, formatTime } = useIntl();
  const palette = usePalette();
  const hasP2PLiveSendTimesExperiment = useHasP2PLiveSendTimesExperiment();
  const formatSendDuration = useFuzzyDurationFormatter();
  const latencyInfoTrayRef = useRef<DrawerRefBaseProps>(null);
  const [
    isLatencyTrayVisible,
    { toggleOn: toggleLatencyTrayOn, toggleOff: toggleLatencyTrayOff },
  ] = useToggler(false);

  const [liveSendTime, setLiveSendTime] = useState<string | undefined>();

  const { response } = usePollGqlQuery<TransactionStatusTrackerPollingQuery>(
    graphql`
      query TransactionStatusTrackerPollingQuery(
        $transactionId: Uuid!
        $accountId: Uuid!
      ) {
        viewer {
          accountByUuidV3(uuid: $accountId) {
            account {
              assetOrFiatCurrency {
                ... on ViewerAsset {
                  asset {
                    platformName
                    networks {
                      displayName
                      confirmationEstimate
                    }
                  }
                }
              }
              accountHistoryEntryByUuid(uuid: $transactionId) {
                status
                createdAt
                details {
                  __typename
                  ... on CryptoReceiveDetails {
                    transactionUrl
                    networkName
                    networkInfo {
                      networkIconUrl
                      networkName
                    }
                  }
                  ... on UserSendDetails {
                    __typename
                    delayedSendDate
                  }
                  ... on CryptoSendDetails {
                    transactionUrl
                    delayedSendDate
                    networkName
                    networkInfo {
                      networkIconUrl
                      networkName
                    }
                  }
                }
                ...TimeEstimateFragment
                ...useTransactionCategoryFragment
                ...useStatusMessageFragment
              }
            }
          }
        }
      }
    `,
    {
      transactionId,
      accountId: accountId as string,
    },
    600,
    10000,
  );

  const account = response?.viewer?.accountByUuidV3?.account;
  const transaction = account?.accountHistoryEntryByUuid;
  const assetNetworks = account?.assetOrFiatCurrency?.asset?.networks;
  const isOnChain =
    transaction?.details?.__typename === 'CryptoSendDetails' ||
    transaction?.details?.__typename === 'CryptoReceiveDetails';
  const txNetworkName = isOnChain ? transaction?.details?.networkName : '';
  const shouldShowTimeHeader =
    !hasP2PLiveSendTimesExperiment || liveSendTime !== undefined;

  const { message, color, name } = useStatusMessage(transaction ?? null);
  const { i18nCategory } = useTransactionCategory(transaction ?? null);
  const iconSpacingScale = -useSpacingScale()['0.5'];
  const isOnChainSendReceive =
    transaction?.details?.__typename === 'CryptoSendDetails' ||
    transaction?.details?.__typename === 'CryptoReceiveDetails';

  const isPending = useMemo(() => {
    if (transaction?.status) {
      return transaction?.status === 'PENDING';
    }

    return transactionStatus === 'PENDING';
  }, [transaction?.status, transactionStatus]);

  const blockchainExplorerUrl = isOnChainSendReceive
    ? transaction?.details?.transactionUrl
    : '';
  const handleOpenBlockExplorer = useCallback(() => {
    if (blockchainExplorerUrl) {
      void openURL(blockchainExplorerUrl);
    }
  }, [openURL, blockchainExplorerUrl]);

  const [isOnHoldTrayVisible, setIsOnHoldTrayVisible] = useState(false);
  const showOnHoldTray = useCallback(() => {
    setIsOnHoldTrayVisible(true);
  }, [setIsOnHoldTrayVisible]);
  const hideOnHoldTray = useCallback(() => {
    setIsOnHoldTrayVisible(false);
  }, [setIsOnHoldTrayVisible]);

  const delayedSendDate =
    (transaction?.details?.__typename !== 'CryptoReceiveDetails' &&
      transaction?.details?.__typename !== '%other' &&
      transaction?.details?.delayedSendDate) ??
    false;

  const isDelayed =
    transaction?.status === 'WAITING_FOR_CLEARING' ||
    (transaction?.status === 'WAITING_FOR_SIGNATURE' &&
      Boolean(delayedSendDate));

  const isLightningNetwork =
    (transaction?.details?.__typename === 'CryptoSendDetails' ||
      transaction?.details?.__typename === 'CryptoReceiveDetails') &&
    transaction?.details?.networkInfo?.networkName === 'Lightning';

  const isOnHold = transaction?.status === 'WAITING_FOR_INFORMATION';

  const hasIcon =
    isOnChainSendReceive && !!transaction?.details?.networkInfo?.networkIconUrl;

  const transactionStatusMessage = useMemo(() => {
    if (
      transactionStatus &&
      Object.keys(FINISHED_STATUSES).includes(transactionStatus)
    ) {
      return (
        <TextBody align="end" testID="TransactionStatusMessage">
          {formatMessage(FINISHED_STATUSES[transactionStatus])}
        </TextBody>
      );
    }

    return message === 'Unknown' ? (
      <Box spacingEnd={3}>
        <Spinner />
      </Box>
    ) : (
      <TextBody align="end" testID="TransactionStatusMessage">
        {message}
      </TextBody>
    );
  }, [formatMessage, message, transactionStatus]);

  const timeHeader = useMemo(() => {
    if (
      isPending &&
      isLightningNetwork &&
      transaction?.details?.__typename === 'CryptoReceiveDetails'
    ) {
      return formatMessage(messages.expiresIn);
    }

    if (hasP2PLiveSendTimesExperiment && isPending) {
      return formatMessage(messages.timeRemaining);
    }

    return formatMessage(messages.timeElapsed);
  }, [
    formatMessage,
    hasP2PLiveSendTimesExperiment,
    isLightningNetwork,
    isPending,
    transaction?.details?.__typename,
  ]);

  const confirmationEstimate = useMemo(() => {
    if (!assetNetworks || !isOnChain) {
      return null;
    }

    const txNetwork = assetNetworks.find(
      (assetNetwork) => assetNetwork?.displayName === txNetworkName,
    );

    if (!txNetwork || !txNetwork.confirmationEstimate) {
      return null;
    }

    return txNetwork.confirmationEstimate + ESTIMATE_BUFFER_SECONDS;
  }, [assetNetworks, isOnChain, txNetworkName]);

  const showToolTip = isPending || isDelayed;

  const statusHeader = useMemo(() => {
    if (isPending && shouldShowTimeHeader) {
      return (
        <>
          <Spacer horizontal={2} />
          <TextBody color="foregroundMuted" testID="TimeHeader">
            {timeHeader}
          </TextBody>
        </>
      );
    }

    return undefined;
  }, [isPending, shouldShowTimeHeader, timeHeader]);

  const updateLiveSendTime = useCallback(() => {
    if (!transaction?.createdAt || !confirmationEstimate) {
      return;
    }

    const createdAtDate = new Date(transaction?.createdAt).getTime();
    const currentDate = new Date().getTime();
    const confirmationEstimateMs = confirmationEstimate * 1000;

    const txCompletedDate = createdAtDate + confirmationEstimateMs;
    const txSeconds = Math.floor((txCompletedDate - currentDate) / 1000);
    const time = formatSendDuration(txSeconds, true);

    if (time !== liveSendTime) {
      setLiveSendTime(time);
    }
  }, [
    confirmationEstimate,
    formatSendDuration,
    liveSendTime,
    transaction?.createdAt,
  ]);

  useEffect(() => {
    if (liveSendTime === undefined) {
      updateLiveSendTime();
    }
    const interval = setInterval(() => {
      updateLiveSendTime();
    }, 1000);

    return () => clearInterval(interval);
  }, [liveSendTime, updateLiveSendTime]);

  const openHelpLink = useCallback(
    () =>
      void openURL(
        isDelayed
          ? DELAYED_TRANSACTION_SUPPORT_ARTICLE_URL
          : PENDING_TRANSACTIONS_SUPPORT_ARTICLE_URL,
        {
          readerMode: true,
        },
      ),
    [isDelayed, openURL],
  );

  const handlePressInfoButton = useCallback(() => {
    if (!hasP2PLiveSendTimesExperiment) {
      openHelpLink();
      return;
    }

    if (isDelayed) {
      openHelpLink();
      return;
    }

    const networkLower = txNetworkName?.toLowerCase();
    const isNetworkSlow =
      confirmationEstimate !== null &&
      (networkLower && networkLower in NETWORK_LATENCY_THRESHOLD_MAP_SECONDS
        ? confirmationEstimate >
          NETWORK_LATENCY_THRESHOLD_MAP_SECONDS[networkLower]
        : confirmationEstimate > NETWORK_LATENCY_THRESHOLD_MAP_SECONDS.default);

    if (isPending && !isNetworkSlow) {
      openHelpLink();
      return;
    }

    toggleLatencyTrayOn();
  }, [
    confirmationEstimate,
    hasP2PLiveSendTimesExperiment,
    isDelayed,
    isPending,
    openHelpLink,
    toggleLatencyTrayOn,
    txNetworkName,
  ]);

  const handleLatencyTrayDismiss = useCallback(() => {
    latencyInfoTrayRef.current?.handleClose();
    toggleLatencyTrayOff();
  }, [toggleLatencyTrayOff]);

  const handleCloseTray = useCallback(() => {
    latencyInfoTrayRef.current?.handleClose();
  }, []);

  if (!transaction) {
    return null;
  }

  return (
    <AnimatedView entering={FadeIn}>
      <HStack
        spacingVertical={2}
        spacingHorizontal={gutter}
        alignItems="center"
        justifyContent="space-between"
        minHeight={80}
      >
        <HStack
          gap={2}
          alignItems="center"
          justifyContent="space-between"
          position="relative"
        >
          <>
            <Icon
              name={name}
              size="xs"
              dangerouslySetColor={color ?? 'foregroundMuted'}
              style={STATUS_SPINNER_STYLE}
              testID="StatusSpinnerIcon"
            />
            <Box
              position="absolute"
              style={{
                height: 128,
                width: 128,
              }}
              testID="StatusSpinnerContainer"
            >
              <StatusSpinner
                isComplete={transaction?.status !== 'PENDING'}
                color={color}
                isStatic={transaction?.status !== 'PENDING'}
                style={{
                  right: 43,
                  height: 128,
                  width: 128,
                }}
              />
            </Box>
            {hasIcon ? (
              <>
                <Box
                  height={20}
                  width={20}
                  top={13}
                  left={10}
                  bordered
                  style={{
                    borderColor: palette.background,
                    borderRadius: 18,
                    borderWidth: 2,
                  }}
                />
                <RemoteImage
                  accessibilityHint={
                    transaction?.details?.networkInfo?.networkName ?? ''
                  }
                  style={{
                    right: 9,
                    top: 13,
                  }}
                  source={transaction?.details?.networkInfo?.networkIconUrl}
                  width={18}
                  height={18}
                />
              </>
            ) : null}
            <VStack
              alignSelf="flex-start"
              spacingStart={hasIcon ? 0.5 : 5}
              testID="StatusHeader"
            >
              <TextBody>{i18nCategory}</TextBody>
              {statusHeader}
            </VStack>
          </>
        </HStack>
        <HStack alignItems="center" gap={0.5}>
          <VStack>
            {transactionStatusMessage}
            {isPending ? (
              <TimeEstimate
                accountHistoryEntryRef={transaction ?? null}
                isLightningNetwork={isLightningNetwork}
                liveSendTime={liveSendTime ?? ''}
              />
            ) : undefined}
            {isDelayed && !!delayedSendDate ? (
              <TextBody color="foregroundMuted" testID="DelayedSendText">
                {formatMessage(messages.dateTime, {
                  date: formatDate(delayedSendDate as string, {
                    day: 'numeric',
                    month: 'short',
                  }),
                  time: formatTime(delayedSendDate as string),
                })}
              </TextBody>
            ) : null}
          </VStack>
          {showToolTip && (
            <Pressable
              hitSlop={PRESSABLE_HIT_SLOP}
              background="transparent"
              accessibilityRole="button"
              testID="infoIconPressable"
              onPress={handlePressInfoButton}
            >
              <VStack
                bottom={Platform.OS === 'ios' ? undefined : iconSpacingScale}
                right={Platform.OS === 'ios' ? iconSpacingScale : undefined}
                justifyContent="center"
                alignItems="center"
              >
                <Icon
                  testID="infoIcon"
                  name="info"
                  size="s"
                  color="foregroundMuted"
                />
              </VStack>
            </Pressable>
          )}
        </HStack>
      </HStack>
      {isOnHold && (
        <>
          <Button
            flexGrow={1}
            onPress={showOnHoldTray}
            variant="primary"
            spacingHorizontal={gutter}
          >
            {formatMessage(messages.provideInfoButtonCopy)}
          </Button>
          <TransactionOnHoldTray
            isVisible={isOnHoldTrayVisible}
            hideSelf={hideOnHoldTray}
            transactionId={transactionId}
          />
        </>
      )}
      {!isOnHold && isOnChainSendReceive && !isLightningNetwork && (
        <Button
          flexGrow={1}
          onPress={handleOpenBlockExplorer}
          variant="secondary"
          disabled={!blockchainExplorerUrl}
          spacingHorizontal={gutter}
        >
          {formatMessage(messages.blockExplorerButtonCopy)}
        </Button>
      )}
      {isLatencyTrayVisible && (
        <Tray
          onCloseComplete={handleLatencyTrayDismiss}
          ref={latencyInfoTrayRef}
        >
          <VStack spacingHorizontal={3} testID="TxLatencyTray">
            <TextTitle3 spacingTop={3} spacingBottom={1}>
              {formatMessage(messages.broadcastLatencyTrayHeader)}
            </TextTitle3>
            <TextBody color="foregroundMuted" spacingBottom={3}>
              {formatMessage(messages.broadcastLatencyTrayBody, {
                asset: account?.assetOrFiatCurrency?.asset?.platformName ?? '',
                network: txNetworkName ?? '',
              })}
            </TextBody>
            <Button onPress={handleCloseTray} block variant="secondary">
              {formatMessage(messages.gotIt)}
            </Button>
          </VStack>
        </Tray>
      )}
    </AnimatedView>
  );
}

import { memo } from 'react';
import { CellMedia } from '@cbhq/cds-mobile/cells/CellMedia';
import { Box } from '@cbhq/cds-mobile/layout/Box';
import { HStack } from '@cbhq/cds-mobile/layout/HStack';
import { Pressable } from '@cbhq/cds-mobile/system/Pressable';
import { TextHeadline } from '@cbhq/cds-mobile/typography/TextHeadline';

type RecentlyTappedPillProps = {
  title?: string;
  onTap: () => void;
  imageUrl?: string | null;
};

const MAX_TITLE_LENGTH = 180;

export const RecentlyTappedPill = memo(function RecentlyTappedPill({
  title,
  onTap,
  imageUrl,
}: RecentlyTappedPillProps) {
  return (
    <Box spacingEnd={1}>
      <Pressable
        accessibilityLabel={title}
        accessibilityHint={title}
        onPress={onTap}
        background="transparent"
        borderRadius="roundedFull"
        borderColor="line"
        borderWidth="button"
      >
        <HStack
          spacing={1}
          spacingVertical={1}
          alignItems="center"
          justifyContent="space-between"
        >
          {!!imageUrl && (
            <Box spacingEnd={title ? 1 : 0}>
              <CellMedia
                type="asset"
                source={imageUrl}
                cache="force-cache"
                accessibilityLabel={title}
              />
            </Box>
          )}
          {!!title && (
            <Box
              spacingEnd={0.5}
              spacingStart={imageUrl ? 0 : 0.5}
