export type WatchlistRecommendationsAssetCellProps = {
  assetRef: WatchlistRecommendationsAssetCellFragment$key;
  isWatched: boolean;
  onToggleWatched: (isWatched: boolean) => void;
  onPress: () => void;
};

export const WatchlistRecommendationsAssetCell = memo(
  ({
    assetRef,
    isWatched,
    onToggleWatched,
    onPress,
  }: WatchlistRecommendationsAssetCellProps) => {
    const { asset, rewardApy } = useFragment(
      graphql`
        fragment WatchlistRecommendationsAssetCellFragment on ViewerAsset {
          asset {
            uuid
            imageUrl
            name
            platformName
            displaySymbol
            latestPrice(quoteCurrency: $nativeCurrency) {
              price
              percentChanges {
                day
              }
            }
          }
          rewardApy {
            formattedValue
            statsLabel
          }
        }
      `,
      assetRef,
    );

    const { percent, sign, variant } = usePercentChange(
      asset?.platformName,
      asset?.latestPrice?.percentChanges?.day,
    );
    const latestPriceFormatter = useNativeCurrencyFormatter({
      minimumFractionDigits: getPriceScale(asset?.latestPrice?.price),
    });

    const { formatMessage } = useIntl();

    const descriptionAPY =
      rewardApy?.statsLabel === 'APY'
        ? `${formatMessage(messages.apyFormat, {
            percent: rewardApy?.formattedValue,
            apy: rewardApy?.statsLabel,
          })} • `
        : '';

    // eslint-disable-next-line no-unsafe-optional-chaining
    const description = descriptionAPY + asset?.displaySymbol || '';

    const detail = useMemo(
      () =>
        latestPriceFormatter({
          amount: asset?.latestPrice?.price,
          isSensitive: false,
        }),
      [asset?.latestPrice?.price, latestPriceFormatter],
    );
    const subdetail = `${sign}${percent}`;

    const cellMedia = useMemo(() => {
      if (asset === null) {
        return undefined;
      }

      return (
        <CellMedia
          type="asset"
          source={asset.imageUrl}
          accessibilityLabel={asset.displaySymbol || asset.name || ''}
          cache="force-cache"
        />
      );
    }, [asset]);

    return (
      <ListCell
        onPress={onPress}
        title={asset?.name ?? ''}
        description={description}
        variant={variant}
        action={
          <HStack gap={1} offsetHorizontal={2}>
            <VStack alignContent="flex-end" justifyContent="center">
              <TextBody align="end" numberOfLines={1} adjustsFontSizeToFit>
                {detail}
              </TextBody>

              <TextBody
                align="end"
                numberOfLines={1}
                color={variant}
                adjustsFontSizeToFit
              >
                {subdetail}
              </TextBody>
            </VStack>
            <WatchlistRecommendationsStar
              isWatched={isWatched}
              onToggleWatched={onToggleWatched}
              testID={`watchlist-star-${asset?.uuid}`}
            />
          </HStack>
        }
        media={cellMedia}
      />
    );
  },
);

