const i18nKey = 'MiniDappBrowser';
const messages = defineMessages({
  title: {
    id: `${i18nKey}.title`,
    // TODO: Once we expand beyond just SWC Donate experience, remove these hardcoded strings and get the data from backend
    defaultMessage: 'Donate',
    description: `
    #Component:Title
    #Context:Title for the mini dapp browser screen
  `,
  },
  error: {
    id: `${i18nKey}.error`,
    defaultMessage: 'There was an issue. Please refresh and try again.',
    description: `
      #Component:Label
      #Context:Error message when there is an issue with the dapp
    `,
  },
});

const MiniDappBrowser = memo(function MiniDappBrowser() {
  const { formatMessage } = useIntl();
  const { pop, navigate } = useStackNavigation();
  const showErrorTray = useShowErrorTray();
  const { uri, entryPoint } = useParams<'MiniDappBrowserScreen'>();
  const webViewRef = useRef<WebView>(null);
  const [dappInitialized, setDappInitialized] = useState(false);
  const [webViewLoaded, setWebViewLoaded] = useState(false);
  const [activeSession, setActiveSession] = useState<WebViewNavigation | null>(
    null,
  );

  useTrackMiniDappScreenViewed({ step: '1_browser', entryPoint, dappUrl: uri });

  const query = useLazyLoadQuery<MiniDappBrowserScreenQuery>(
    graphql`
      query MiniDappBrowserScreenQuery(
        $url: Url!
        $includeTestNetworks: Boolean!
        $includeUnsupportedNetworks: Boolean!
      ) {
        ...Web3WebViewFragment
        ...MiniDappBannerFragment
        viewer {
          userProperties {
            name
            email
          }
        }
      }
    `,
    {
      url: uri,
      includeTestNetworks: getIsTestnetsEnabled(),
      includeUnsupportedNetworks: getIsUnsupportedNetworksEnabled(),
    },
  );

  const user = query.viewer?.userProperties;

  const initializeDapp = useCallback(() => {
    // TODO: Once we expand beyond just SWC Donate experience, remove the hardcoded id and data, and get it from DefiDapp on the backend
    const data: MiniDappPostMessage = {
      id: '1',
      type: 'initialize',
      source: 'cb-mini-dapp',
      data: { name: user?.name, email: user?.email },
    };

    const dataString = JSON.stringify(data);
    const formatted = formatInjectedJavascript(
      `window.postMessage(${dataString});`,
    );

    webViewRef.current?.injectJavaScript(formatted);
  }, [user, webViewRef]);

  useEffect(() => {
    if (!dappInitialized && user && webViewRef.current && webViewLoaded) {
      initializeDapp();
      setDappInitialized(true);
    }
  }, [
    webViewRef,
    dappInitialized,
    setDappInitialized,
    initializeDapp,
    webViewLoaded,
    user,
  ]);

  const handleClose = useCallback(() => {
    trackMiniDappClick({
      step: '1_browser',
      eventAction: 'close_browser',
    });
    pop();
  }, [pop]);

  const closeButton = useCallback(
    () => <IconButton name="close" transparent onPress={handleClose} />,
    [handleClose],
  );

  const navigateBack = useCallback(() => {
    webViewRef?.current?.goBack();
  }, [webViewRef]);

  const backButton = useMemo(() => {
    if (activeSession?.canGoBack && webViewRef?.current) {
      return <IconButton name="backArrow" transparent onPress={navigateBack} />;
    }
    return <Box />;
  }, [webViewRef, activeSession, navigateBack]);

  const navHeaderConfig = useMemo(
    () => ({
      bordered: true,
      title: formatMessage(messages.title),
      trailing: closeButton,
      leading: backButton,
    }),
    [formatMessage, closeButton, backButton],
  );

  const handleOnLoad = useCallback(() => {
    setDappInitialized(false);
    setWebViewLoaded(true);
  }, []);

  const handleMagitKitResponse = useCallback(
    ({ txInput, error }: MagicKitCallResponse) => {
      if (txInput) {
        navigate('DeFiStack', {
          screen: 'MgxSendPrepareTxLoader',
          params: { txInput, dappUrl: uri },
        });
      } else {
        showErrorTray({
          error: new Error(error ?? 'MagicKit call failed'),
          displayMessage: formatMessage(messages.error),
        });
      }
    },
    [navigate, uri, showErrorTray, formatMessage],
  );

  const handleMagicKitCalls = useCallback(
    (data: MagicKitCall) => {
      trackMiniDappClick({
        step: '1_browser',
        eventAction: 'dapp_initiated_mgx',
      });

      const magicKitCall = magicKitMethods[data.request.method];

      const metadata = {
        dappUrl: uri,
        dappHost: safeParseUrl(uri)?.hostname,
      };

      magicKitCall({
        call: data,
        onResponse: handleMagitKitResponse,
        metadata,
      });
    },
    [handleMagitKitResponse, uri],
  );

  return (
    <Screen navHeader={navHeaderConfig} noSpacing>
      <MiniDappBanner queryRef={query} />
      <Web3WebView
        uri={uri}
        webViewRef={webViewRef}
        setActiveSession={setActiveSession}
        queryRef={query}
        onLoadProp={handleOnLoad}
        handleMagictKitCalls={handleMagicKitCalls}
        browserType="mini-dapp-browser"
      />
    </Screen>
  );
});

