// only log event once every 3 days
function shouldLogEvent() {
  const lastViewedDate = getStoreDataSynchronous(
    DAPP_BROWSER_STORE_KEY,
    WEB3_TABS_SCREEN_LAST_VIEWED_KEY,
    null,
  );

  return !lastViewedDate || Number(lastViewedDate) < Date.now() - ONE_DAY;
}

