};

const Web3TabsMoreActionsTray = memo(
  ({ onDismiss, isVisible }: Web3TabsMoreActionsTrayProps) => {
    const { formatMessage } = useIntl();
    const { dispatch } = useWeb3BrowserTabs();

    const handleRemoveAllTabs = useCallback(() => {
      trackWeb3BrowserTabs({
        flow: 'web3_multi_tab',
