      dispatch({ type: 'removeAllTabs' });
      onDismiss();
    }, [onDismiss, dispatch]);

    return (
      <Tray onDismiss={onDismiss} isVisible={isVisible} spacing={0}>
        <ListCell
          outerSpacing={outerSpacing}
          title={formatMessage(messages.closeAllTabs)}
          onPress={handleRemoveAllTabs}
          media={<CellMedia type="icon" name="trashCan" color="foreground" />}
          accessibilityLabel="More actions"
          accessibilityHint="Shows more actions tray"
        />
      </Tray>
    );
  },
);

const Web3BrowserTabs = memo(() => {
  const platform = Platform.OS;
  const { top, bottom } = useDimensions();
  const { formatMessage } = useIntl();
  const { popStack, pop } = useStackNavigation();
  const { navigate } = useNavigation();

  const { web3BrowserState } = useWeb3BrowserTabs();
  const [removedTabId, setRemovedTabId] = useState('');
  const { walletAddress: web3WalletAddress } = useDappWallet();
  const [defiEligible] = useIsWeb3WalletEligible();
  const { present } = useModal('Web3BrowserModalStack');
  const hasWeb3Wallet = useMemo(() => !!web3WalletAddress, [web3WalletAddress]);

  const query = useLazyLoadQuery<Web3BrowserTabsScreenQuery>(
    graphql`
      query Web3BrowserTabsScreenQuery {
        ...useDappWalletChecksFragment
      }
    `,
    {},
  );

  const returnTo: NavigateArgs = useMemo(
    () => ['Web3BrowserTabsScreen', {}],
    [],
  );

  const [checkRequirements, refreshRequirements] = useDappWalletChecks(query, {
    returnTo,
  });

  const gatedNonBlockingCall = useDappWalletNonBlockingCallEffect({
    checkRequirements,
    refreshRequirements,
  });

  const openWeb3WalletOnboarding = useCallback(() => {
    void gatedNonBlockingCall({
      entryPoint: 'web3Tabs',
      forcePromptFunding: true,
    });
  }, [gatedNonBlockingCall]);

  const headerStyle = useMemo(
    () => ({ paddingTop: platform === 'ios' ? top : top + 10 }),
    [top, platform],
  );
  const footerStyle = useMemo(() => ({ paddingBottom: bottom }), [bottom]);

  const [
    isWeb3MoreActionsTrayVisible,
    { toggleOn: showWeb3MoreActionsTray, toggleOff: hideWeb3MoreActionsTray },
  ] = useToggler(false);

  useOnMount(() => {
    if (shouldLogEvent() && defiEligible && hasWeb3Wallet) {
      trackWeb3BrowserTabs({
        flow: 'web3_multi_tab',
        step: 'web3_opened_tabs_count',
        otherParams: {
          web3_tabs_number: web3BrowserState.tabs.length,
        },
      });

      setStoreDataSynchronous(
        DAPP_BROWSER_STORE_KEY,
        WEB3_TABS_SCREEN_LAST_VIEWED_KEY,
        String(Date.now()),
      );
    }
  });

  const onCloseTab = useCallback(
    (tabId: string) => {
      setRemovedTabId(tabId);
    },
    [setRemovedTabId],
  );

  const handleNavigateToBookmarks = useCallback(() => {
    present('DappBookmarks', { entryPoint: 'web3Tabs' });
  }, [present]);

  const handleClose = useCallback(() => {
    if (
      removedTabId === web3BrowserState.latestTab?.id ||
      web3BrowserState.tabs?.length === 0
    ) {
      popStack();
    } else {
      pop();
    }
  }, [pop, popStack, removedTabId, web3BrowserState]);

  const handleAddTab = useCallback(() => {
    if (hasWeb3Wallet) {
      trackWeb3BrowserTabs({
        flow: 'web3_multi_tab',
        step: '2_web3_add_tab',
      });
      navigate('Web3BrowserSearchScreen', {});
    } else {
      openWeb3WalletOnboarding();
    }
  }, [navigate, openWeb3WalletOnboarding, hasWeb3Wallet]);

  const navHeader: CustomNavHeader = useCallback(
    () => (
      <HStack
        style={headerStyle}
        spacingHorizontal={3}
        position="relative"
        justifyContent="space-between"
        alignItems="center"
      >
        <Pressable
          accessibilityRole="button"
          hitSlop={8}
          transparentWhileInactive
          borderColor="transparent"
          borderRadius="rounded"
          borderWidth="button"
          feedback="light"
          background="transparent"
          onPress={handleClose}
          testID="Web3BrowserTabsCaretDown"
        >
          <Icon name="backArrow" size="s" color="foreground" />
        </Pressable>

        {!!(defiEligible && hasWeb3Wallet) && (
          <TextHeadline spacingStart={2}>
            {web3BrowserState.tabs.length === 1
              ? formatMessage(messages.tab)
              : formatMessage(messages.tabs, {
                  total: web3BrowserState.tabs.length,
                })}
          </TextHeadline>
        )}

        <Box width={40} height={40} />
      </HStack>
    ),
    [
      headerStyle,
      handleClose,
      web3BrowserState.tabs.length,
      formatMessage,
      defiEligible,
      hasWeb3Wallet,
    ],
  );

  const footer = useMemo(
    () => (
      <HStack
        style={footerStyle}
        alignItems="center"
        justifyContent="space-around"
        borderedTop
        spacingHorizontal={2}
        spacingTop={2}
      >
        <IconButton
          name="bookmarkActive"
          variant="secondary"
          onPress={handleNavigateToBookmarks}
          compact
          transparent
          disabled={!defiEligible || !hasWeb3Wallet}
        />

        <IconButton
          name="add"
          accessibilityLabel={formatMessage(messages.addTab)}
          accessibilityHint={formatMessage(messages.addTab)}
          variant="secondary"
          onPress={handleAddTab}
          compact
          disabled={!defiEligible || web3BrowserState.tabs?.length >= MAX_TABS}
        />

        <IconButton
          name="more"
          variant="secondary"
          onPress={showWeb3MoreActionsTray}
          compact
          transparent
          disabled={
            !defiEligible ||
            !hasWeb3Wallet ||
            web3BrowserState.tabs?.length === 0
          }
        />
      </HStack>
    ),
    [
      footerStyle,
      handleNavigateToBookmarks,
      handleAddTab,
      showWeb3MoreActionsTray,
      formatMessage,
      hasWeb3Wallet,
      defiEligible,
      web3BrowserState.tabs,
    ],
  );

  const screenContent = useMemo(() => {
    if (!defiEligible) {
      return (
        <VStack height="100%" flexGrow={1} spacing={gutter}>
          <Web3IneligibleErrorContent />
        </VStack>
      );
    }

    if (!hasWeb3Wallet || web3BrowserState.tabs?.length === 0) {
      return (
        <Web3BrowserTabsNux
          openWeb3WalletOnboarding={openWeb3WalletOnboarding}
        />
      );
    }

    return (
      <Box spacing={2} flexGrow={1} flexDirection="row" flexWrap="wrap">
        {web3BrowserState.tabs.map((tab) => (
          <Web3BrowserTabItem key={tab.id} tab={tab} onCloseTab={onCloseTab} />
        ))}
      </Box>
    );
  }, [
    defiEligible,
    onCloseTab,
    web3BrowserState,
    hasWeb3Wallet,
    openWeb3WalletOnboarding,
  ]);

  return (
    <Screen navHeader={navHeader} floatingFooter={footer} noSpacing>
      {screenContent}

      <Web3TabsMoreActionsTray
        onDismiss={hideWeb3MoreActionsTray}
        isVisible={isWeb3MoreActionsTrayVisible}
      />
    </Screen>
  );
});

export const Web3BrowserTabsScreen = memo(function Web3BrowserTabsScreen() {
  return (
    <ScreenBoundary
      instrumentationId="Web3BrowserTabsScreen"
      tabBarVisible={false}
    >
      <Web3BrowserTabs />
    </ScreenBoundary>
  );
});

