import { memo, MutableRefObject, useCallback, useEffect, useMemo } from 'react';
import {
  Animated,
  Platform,
  StyleProp,
  StyleSheet,
  ViewStyle,
} from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { usePalette } from '@cbhq/cds-mobile/hooks/usePalette';
import { Icon } from '@cbhq/cds-mobile/icons';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { Pressable, PressableOpacity } from '@cbhq/cds-mobile/system';
import { TextLabel1, TextLabel2 } from '@cbhq/cds-mobile/typography';

import { useDimensions } from '@designSystem/hooks/useDimensions';

import { useWeb3BrowserTabs } from '@app/contexts/Defi/Web3BrowserTabsProvider';
import {
  trackWeb3BrowserScreen,
  trackWeb3BrowserTabs,
} from '@app/screens/Defi/analytics/events';
import { safeParseUrl } from '@app/screens/Defi/DAppBrowser/utils/urlUtils';
import { getUrlFavicon } from '@app/screens/Defi/utils';
import { removeUTMParams } from '@app/screens/Defi/utils/dappUtms/dappUtms';
import { RoutesAfterScreenShot } from '@app/screens/Web3/Web3BrowserScreen';

const BLURRED_SEARCH_BAR_SCALE = 0.75;
const MAX_HEADER_RANGE = 50;
const ICON_NOT_VISIBLE_VALUE = 16;

const styles = StyleSheet.create({
  searchInteractable: {
    width: `${BLURRED_SEARCH_BAR_SCALE * 100}%`,
    flexShrink: 1,
  },
  animatedSearchbar: {
    borderRadius: 28,
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
  },
});

type Web3BrowserNavHeaderProps = {
  uri: string;
  tabId: string;
  handleCaptureScreenshot: (goTo?: RoutesAfterScreenShot) => void;
  scrollYRef: MutableRefObject<Animated.Value>;
};

// Nav header from the Webview.
export const Web3BrowserNavHeader = memo(function Web3BrowserNavHeader({
  uri: uriFromProps,
  tabId,
  handleCaptureScreenshot,
  scrollYRef,
}: Web3BrowserNavHeaderProps) {
  const platform = Platform.OS;
  const { backgroundAlternate, transparent, foreground } = usePalette();
  const { top } = useDimensions();
  const { navigate } = useNavigation();
  const { dispatch, web3BrowserState } = useWeb3BrowserTabs();

  const numberOfTabs = web3BrowserState.tabs.length;
  const uri = web3BrowserState.activeSession?.url ?? uriFromProps;
  const hostname =
    web3BrowserState.activeSession?.hostname ??
    safeParseUrl(uriFromProps).hostname;

  useEffect(() => {
    dispatch({ type: 'updateActiveTabId', payload: { tabId } });
  }, [dispatch, tabId]);

  const boxStyle: StyleProp<ViewStyle> = useMemo(
    () => ({
      borderColor: foreground,
      borderWidth: 2,
    }),
    [foreground],
  );

  const diffClamp = Animated.diffClamp(
    scrollYRef?.current,
    0,
    MAX_HEADER_RANGE,
  );

  // When user scrolls a certain range, we change the opacity of the icons to 0.
  const opacity = diffClamp.interpolate({
    inputRange: [0, MAX_HEADER_RANGE / 3],
    outputRange: [1, 0],
  });

  const opacityAnimationStyles = useMemo(() => {
    return {
      opacity,
    };
  }, [opacity]);

  // When the user isn't scrolling, it applies the default top padding.
  // Whenever a user scrolls a certain range, we decrease the top padding of the nav header.
  const paddingTop = diffClamp.interpolate({
    inputRange: [
      0,
      platform === 'ios' ? MAX_HEADER_RANGE / 3 : MAX_HEADER_RANGE * 2,
    ],
    outputRange: [platform === 'ios' ? top : top + 10, top - 10],
    extrapolateRight: 'clamp',
  });

  // When the user isn't scrolling, it applies a bottom padding of 10.
  // Whenever a user scrolls a certain range, we remove the bottom padding completely.
  const paddingBottom = diffClamp.interpolate({
    inputRange: [
      0,
      platform === 'ios' ? MAX_HEADER_RANGE / 3 : MAX_HEADER_RANGE * 2,
    ],
    outputRange: [10, 0],
    extrapolateRight: 'clamp',
  });

  const headerAnimationStyles = useMemo(() => {
    return {
      paddingTop,
      paddingBottom,
    };
  }, [paddingTop, paddingBottom]);

  // When the user starts scrolling a certain range, we change the background color from light gray to white.
  const backgroundColor = diffClamp.interpolate({
    inputRange: [0, MAX_HEADER_RANGE / 3],
    outputRange: [backgroundAlternate, transparent],
    extrapolateRight: 'clamp',
  });

  // Removing the searchbar vertical padding when the user starts scrolling a certain range.
  // Default value of 10 matches the design spec.
  const searchbarPaddingY = diffClamp.interpolate({
    inputRange: [
      0,
      platform === 'ios' ? MAX_HEADER_RANGE : MAX_HEADER_RANGE * 2,
    ],
    outputRange: [10, 0],
    extrapolateLeft: 'clamp',
  });

  const searchbarAnimationStyles = useMemo(() => {
    return {
      backgroundColor,
      paddingTop: searchbarPaddingY,
      paddingBottom: searchbarPaddingY,
    };
  }, [backgroundColor, searchbarPaddingY]);

  const handlePressSearchBar = useCallback(() => {
    if (JSON.stringify(diffClamp) !== '0') {
      scrollYRef.current.setValue(0);
    } else {
      navigate('Web3BrowserSearchScreen', { uri });
    }
  }, [diffClamp, scrollYRef, uri, navigate]);

  const handleCloseBrowser = useCallback(() => {
    // extend header if tapped and down caret is not visible
    const iconNotVisible =
      Number(JSON.stringify(diffClamp)) > ICON_NOT_VISIBLE_VALUE;
    if (iconNotVisible) {
      scrollYRef.current.setValue(0);
      return;
    }

    const iconUrl =
      web3BrowserState.tabs.find((tab) => tab.id === tabId)?.iconUrl ??
      getUrlFavicon(uri);

    const cleanUri = removeUTMParams(uri);

    trackWeb3BrowserScreen({
      flow: 'web3_browser_webview',
      step: '2_web3_close_tab',
      otherParams: {
        dapp_url: cleanUri,
      },
    });

    dispatch({
      type: 'closeTab',
      payload: {
        id: tabId,
        url: cleanUri,
        iconUrl,
      },
    });
    // Calling this method will trigger the onCapture callback at Web3BrowserScreen.tsx and navigate the user away from the webview.
    // This is counterintuitive but currently there's no way to await for a screenshot to be taken before navigating away from the screen, as @cbhq/react-native-viewshot works with callbacks and not promises.
    handleCaptureScreenshot();
  }, [
    diffClamp,
    web3BrowserState.tabs,
    uri,
    dispatch,
    tabId,
    scrollYRef,
    handleCaptureScreenshot,
  ]);

  const navigateToBrowserTabs = useCallback(() => {
    // extend header if tapped and tabs icon/reload button is not visible
    const iconNotVisible =
      Number(JSON.stringify(diffClamp)) > ICON_NOT_VISIBLE_VALUE;
    if (iconNotVisible) {
      scrollYRef.current.setValue(0);
      return;
    }
    trackWeb3BrowserTabs({
      flow: 'web3_multi_tab',
      step: '0_web3_tabs_entry',
      otherParams: {
        entry_point: 'web3Browser',
      },
    });

    handleCaptureScreenshot('tabs');
  }, [diffClamp, handleCaptureScreenshot, scrollYRef]);

  return (
    <Animated.View style={headerAnimationStyles}>
      <HStack
        justifyContent="space-evenly"
        alignItems="center"
        gap={2}
        spacingHorizontal={2}
      >
        <Pressable
          accessibilityRole="button"
          transparentWhileInactive
          borderColor="transparent"
          borderRadius="rounded"
          borderWidth="button"
          feedback="light"
          background="transparent"
          onPress={handleCloseBrowser}
          testID="Web3BrowserNavHeaderCaretDown"
        >
          <Animated.View style={opacityAnimationStyles}>
            <Icon name="caretDown" size="m" color="foreground" />
          </Animated.View>
        </Pressable>

        <PressableOpacity
          testID="Web3BrowserNavHeaderSearchBar"
          noScaleOnPress
          onPress={handlePressSearchBar}
          style={styles.searchInteractable}
        >
          <Animated.View
            style={[styles.animatedSearchbar, searchbarAnimationStyles]}
          >
            <Icon
              size="xs"
              name="lock"
              color="foregroundMuted"
              spacingEnd={1}
            />
            <TextLabel2 color="foregroundMuted" numberOfLines={1}>
              {hostname}
            </TextLabel2>
          </Animated.View>
        </PressableOpacity>

        <Pressable
          accessibilityRole="button"
          transparentWhileInactive
          borderColor="transparent"
          borderRadius="rounded"
          borderWidth="button"
          feedback="light"
          background="transparent"
          onPress={navigateToBrowserTabs}
          testID="Web3BrowserNavHeaderTabsButton"
        >
          <Animated.View style={opacityAnimationStyles}>
            <Box
              style={boxStyle}
              borderRadius="rounded"
              minHeight={24}
              minWidth={24}
              justifyContent="center"
              alignItems="center"
            >
              <TextLabel1 color="foreground" adjustsFontSizeToFit>
                {numberOfTabs}
              </TextLabel1>
            </Box>
          </Animated.View>
        </Pressable>
      </HStack>
    </Animated.View>
  );
});

import { memo, useCallback } from 'react';
