type WrapOrUnwrapCardProps = {
  viewerAssetRef: WrapOrUnwrapCardFragment$key | null;
  context: StakingSource;
} & SpacingProps;

const WrapOrUnwrapCardContent = memo(function WrapOrUnwrapCardContent({
  viewerAssetRef,
  context,
  ...spacingProps
}: WrapOrUnwrapCardProps) {
  const viewerAsset = useFragment(
    graphql`
      fragment WrapOrUnwrapCardFragment on ViewerAsset {
        ...WrappedAssetEntryPointTrayFragment
        wrappedAsset {
          wrapUnwrapEntryPoint {
            text
            title
          }
        }
      }
    `,
    viewerAssetRef,
  );

  const wrappedAsset = viewerAsset?.wrappedAsset;
  const v2EntryPoint = wrappedAsset?.wrapUnwrapEntryPoint;

  const [isTrayVisible, { toggleOn: showWrapTray, toggleOff: hideWrapTray }] =
    useToggler(false);

  const handleShowWrapTray = useCallback(() => {
    logEvent(WRAP_FLOW, {
      ...SEE_OPTIONS_CLICK,
      context,
    });
    showWrapTray();
  }, [context, showWrapTray]);

  if (!v2EntryPoint) {
    return null;
  }

  const wrapTitle = v2EntryPoint?.title;
  const wrapText = v2EntryPoint?.text;

  return (
    <>
      <Box {...spacingProps}>
        <Pressable
          accessibilityRole="button"
          background="transparent"
          onPress={handleShowWrapTray}
        >
          <NudgeCard
            title={<TextHeadline>{wrapTitle}</TextHeadline>}
            description={wrapText}
            pictogram="earnNavigation"
            width="100%"
          />
        </Pressable>
      </Box>
      {isTrayVisible && !!viewerAsset && (
        <WrappedAssetEntryPointTray
          viewerAssetRef={viewerAsset}
          onCloseTray={hideWrapTray}
          context={context}
        />
      )}
    </>
  );
});

