  hideDisclaimer?: boolean;
  wrapCta?: string;
  unwrapCta?: string;
  onCtaPress?: () => void;
  source: StakingSource;
};

export function WrappedActions({
  viewerAssetRef,
  direction = 'vertical',
  hideDisclaimer,
  compact,
  wrapCta,
  unwrapCta,
  onCtaPress,
  source,
}: WrappedActionsProps) {
  const { formatMessage } = useIntl();
  const navigateToDeepLink = useDeepLinking();
  const navigateToBuyInput = useNavigateToBuyInput();
  const hasCbEthStateRegulatoryExperiment = useCbethStateRegulatoryExperiment();
  const { setIsDegradedState } = useDegradedBanner();

  const [viewerAsset, getErrors] = useFragmentWithError(
    graphql`
      fragment WrappedActionsFragment on ViewerAsset {
        asset {
          name
          platformName
        }
        accounts {
          ...useAccountsByTypeFragment
          availableBalance {
            value
          }
        }
        wrappedAsset {
          guide {
            underlyingAsset {
              accounts {
                ...useAccountsByTypeFragment
                availableBalance {
                  value
                }
              }
            }
          }
          wrapUnwrapEntryPoint {
            model {
              unstakeText
              unstakeCta {
                text
                url
              }
              wrapCta {
                isEnabled
                cta {
                  url
                  text
                }
              }
              unwrapCta {
                isEnabled
                cta {
                  text
                  url
                }
              }
            }
          }
        }
      }
    `,
    viewerAssetRef,
  );

  const assetName = viewerAsset?.asset?.name ?? '';
  const platformName = viewerAsset?.asset?.platformName ?? '';
  const model = viewerAsset?.wrappedAsset?.wrapUnwrapEntryPoint?.model;
  const underlyingAssetAccounts = useAccountsByType(
    viewerAsset?.wrappedAsset?.guide?.underlyingAsset?.accounts,
  );
  const underlyingAssetBalance = Number(
    underlyingAssetAccounts.STAKED_FUNDS?.availableBalance?.value ?? 0,
  );
  const wrappedAssetAccounts = useAccountsByType(viewerAsset?.accounts);
  const wrappedAssetBalance = Number(
    wrappedAssetAccounts.WALLET?.availableBalance?.value ?? 0,
  );

  const isAccountsDegraded = viewerAsset?.accounts === null;
  const isWrappedAssetsDegraded =
    viewerAsset?.wrappedAsset?.guide === null &&
    getErrors('wrappedAsset.guide') !== null;

  useEffect(() => {
    setIsDegradedState({
      isAccountsDegraded,
      isWrappedAssetsDegraded,
    });
  }, [setIsDegradedState, isAccountsDegraded, isWrappedAssetsDegraded]);

  const [wrapInterstitialRendering, setWrapInterstitialRendering] = useState<{
    hasRendered: boolean;
    shouldShow: boolean;
  }>({
    hasRendered: false,
    shouldShow: false,
  });
  const toggleOn = useCallback(() => {
    setWrapInterstitialRendering({
      hasRendered: true,
      shouldShow: true,
    });
  }, [setWrapInterstitialRendering]);

  const toggleOff = useCallback(() => {
    setWrapInterstitialRendering({
      hasRendered: true,
      shouldShow: false,
    });
  }, [setWrapInterstitialRendering]);

  const isInRebateExperiment = useHasEthRebateExperiment();

  const navigateToWrap = useCallback(() => {
    navigateToDeepLink({
      url: appendQuery(model?.wrapCta?.cta?.url ?? '', {
        transferSource: source,
      }),
      fallbackOnInvalidDeepLink: true,
    });
  }, [model?.wrapCta?.cta?.url, navigateToDeepLink, source]);

  const handleWrapPress = useCallback(() => {
    logWrapClick({ asset: platformName, context: source });

    if (isInRebateExperiment) {
      toggleOn();
      return;
    }

    navigateToWrap();
    onCtaPress?.();
  }, [
    platformName,
    source,
    isInRebateExperiment,
    navigateToWrap,
    onCtaPress,
    toggleOn,
  ]);

  const handleUnwrapPress = useCallback(() => {
    logUnwrapClick({ asset: platformName, context: source });

    navigateToDeepLink({
      url: appendQuery(model?.unwrapCta?.cta?.url ?? '', {
        transferSource: source,
      }),
      fallbackOnInvalidDeepLink: true,
    });
    onCtaPress?.();
  }, [
    source,
    onCtaPress,
    platformName,
    model?.unwrapCta?.cta?.url,
    navigateToDeepLink,
  ]);

  const handleBuyPress = useCallback(() => {
    logWrapBuyClick({ asset: platformName, context: source });

    navigateToBuyInput({
      assetSymbolOrSlug: platformName,
      transferSource: source,
      assetName,
    });
    onCtaPress?.();
  }, [assetName, source, onCtaPress, platformName, navigateToBuyInput]);

  const buttonTypes = useMemo(() => {
    // only show Wrap when there is a staked asset available to wrap
    const showWrap = Boolean(
      model?.wrapCta?.isEnabled && underlyingAssetBalance > 0,
    );

    // only show unwrap when the user has a wrapped asset available to unwrap
    const showUnwrap = Boolean(
      model?.unwrapCta?.isEnabled && wrappedAssetBalance > 0,
    );

    return {
      WRAP: showWrap,
      UNWRAP: showUnwrap,
      BUY: !showWrap,
    };
  }, [
    model?.wrapCta,
    model?.unwrapCta,
    wrappedAssetBalance,
    underlyingAssetBalance,
  ]);

  useLogWrappedActionsView({
    asset: platformName,
    context: source,
    buttonTypes,
  });

  const buttons = useMemo(() => {
    const buttonsArr = [];
    if (buttonTypes.WRAP) {
      buttonsArr.push(
        <Button
          key="wrap"
          variant="primary"
          compact={compact}
          onPress={handleWrapPress}
          loading={wrapInterstitialRendering.shouldShow}
        >
          {wrapCta ?? model?.wrapCta?.cta?.text ?? ''}
        </Button>,
      );
    } else {
      buttonsArr.push(
        <Button
          key="buy"
          variant="primary"
          compact={compact}
          onPress={handleBuyPress}
        >
          {formatMessage(messages.buyMore)}
        </Button>,
      );
    }

    if (buttonTypes.UNWRAP) {
      buttonsArr.push(
        <Button
          key="unwrap"
          variant="secondary"
          compact={compact}
          onPress={handleUnwrapPress}
        >
          {unwrapCta ?? model?.unwrapCta?.cta?.text ?? ''}
        </Button>,
      );
    }

    return direction === 'vertical' ? buttonsArr : buttonsArr.reverse();
  }, [
    buttonTypes.WRAP,
    buttonTypes.UNWRAP,
    direction,
    compact,
    handleWrapPress,
    wrapInterstitialRendering.shouldShow,
    wrapCta,
    model?.wrapCta?.cta?.text,
    model?.unwrapCta?.cta?.text,
    handleBuyPress,
    formatMessage,
    handleUnwrapPress,
    unwrapCta,
  ]);

  const handleInterstitialContinue = useCallback(() => {
    toggleOff();
    onCtaPress?.();
    navigateToWrap();
  }, [navigateToWrap, onCtaPress, toggleOff]);

  const interstitialTray = useMemo(() => {
    if (!wrapInterstitialRendering.shouldShow) {
      return null;
    }

    return (
      <EthRebateWrapInterstitialTray
        isVisible={wrapInterstitialRendering.shouldShow}
        onDismiss={toggleOff}
        onContinue={handleInterstitialContinue}
        transferSource={source}
      />
    );
  }, [
    handleInterstitialContinue,
    source,
    toggleOff,
    wrapInterstitialRendering.shouldShow,
  ]);

  if (isAccountsDegraded || isWrappedAssetsDegraded) {
    return null;
  }

  return (
    <>
      {!hideDisclaimer &&
        hasCbEthStateRegulatoryExperiment &&
        !!model?.unstakeText && (
          <TextBody color="foregroundMuted" spacingBottom={3}>
            {model.unstakeText}{' '}
            {!!model?.unstakeCta?.text && !!model?.unstakeCta?.url && (
              <Link to={model.unstakeCta.url} underline>
                {model.unstakeCta.text}
              </Link>
            )}
          </TextBody>
        )}
      <ButtonGroup
        block
        direction={direction}
        accessibilityLabel={formatMessage(messages.wrappedActionsA11yLabel)}
      >
        {buttons}
      </ButtonGroup>
      {interstitialTray}
    </>
  );
}

