type AssetNotOwnedCardProps = {
  viewerAssetRef: AssetNotOwnedCardFragment$key;
  compact?: boolean;
  context: StakingSource;
};

export const AssetNotOwnedCard = memo(function AssetNotOwnedCard({
  viewerAssetRef,
  compact,
  context,
}: AssetNotOwnedCardProps) {
  const { formatMessage } = useIntl();
  const navigateToBuyInput = useNavigateToBuyInput();

  const viewerAsset = useFragment(
    graphql`
      fragment AssetNotOwnedCardFragment on ViewerAsset {
        ...useBuyAndStakeEligibleFragment
        asset {
          name
          displaySymbol
          platformName
        }
        earnProgram {
          currentRate {
            formatted
            unitSymbol
          }
        }
      }
