import { useCallback, useEffect } from 'react';
import { PictogramName } from '@cbhq/cds-common';
import { NudgeCard } from '@cbhq/cds-mobile/cards/NudgeCard';
import { Box } from '@cbhq/cds-mobile/layout/Box';
import { Pressable } from '@cbhq/cds-mobile/system';
import { graphql, useFragment } from '@cbhq/data-layer';

import { NetworkBoundary } from '@app/components/NetworkBoundary';
import { useDeepLinking } from '@app/hooks/navigation/useDeepLinking';

import { trackEarnNudgeCardClick, trackEarnNudgeCardView } from '../eventing';

import { EarnNudgeCardFragment$key } from './__generated__/EarnNudgeCardFragment.graphql';

type EarnNudgeCardContentProps = {
  viewerAssetRef: EarnNudgeCardFragment$key;
};

function EarnNudgeCardContent({ viewerAssetRef }: EarnNudgeCardContentProps) {
  const viewerAsset = useFragment(
    graphql`
      fragment EarnNudgeCardFragment on ViewerAsset
      @argumentDefinitions(entryPoint: { type: "EarnEntryPoint!" }) {
        earnAsset {
          promotion(entryPoint: $entryPoint) {
            title @required(action: NONE)
            description @required(action: NONE)
            cta {
              url
            }
            image {
              name
            }
          }
        }
      }
    `,
    viewerAssetRef,
  );

  const promotion = viewerAsset.earnAsset?.promotion;

  const openDeepLink = useDeepLinking();
  const navigateToDeepLink = useCallback(() => {
    if (!promotion?.cta?.url) {
      return;
    }

    trackEarnNudgeCardClick();
    openDeepLink({ url: promotion?.cta.url });
  }, [openDeepLink, promotion]);

  const renderPromotion = !!promotion;

  useEffect(() => {
    if (renderPromotion) {
      trackEarnNudgeCardView();
    }
  }, [renderPromotion]);

  if (!renderPromotion) {
    return null;
  }

  return (
    <Box spacingBottom={2}>
      <Pressable
        accessibilityRole="button"
        background="transparent"
        onPress={navigateToDeepLink}
      >
        <NudgeCard
          title={promotion.title}
          description={promotion.description}
          pictogram={promotion.image?.name as PictogramName}
          testID="EarnNudgeCard"
        />
      </Pressable>
    </Box>
  );
}

type EarnNudgeCardProps = {
  viewerAssetRef: EarnNudgeCardFragment$key | null | undefined;
};

export function EarnNudgeCard({ viewerAssetRef }: EarnNudgeCardProps) {
  if (!viewerAssetRef) {
    return null;
  }
  return (
    <NetworkBoundary suspenseFallback={null} errorFallback={null}>
      <EarnNudgeCardContent viewerAssetRef={viewerAssetRef} />
    </NetworkBoundary>
  );
}

import { useCallback, useMemo } from 'react';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { Fallback } from '@cbhq/cds-mobile/layout';
import { markJourney } from '@cbhq/core-vitals-mobile';
import { graphql, useFragment, useLazyLoadQuery } from '@cbhq/data-layer';
import { defineMessages, useIntl } from '@cbhq/i18n';

import { Button } from '@components/interactables/Button';
import { ErrorBoundary } from '@app/components/ErrorBoundary';
import { InstrumentedSuspense } from '@app/components/InstrumentedSuspense';
import { useModal } from '@app/hooks/navigation/useModal';
import { StakingSource } from '@app/screens/StakingV2/StakingV2Analytics';
import { useNavigateToBuyInput } from '@app/screens/Trade/Buy/BuyInput/hooks/useNavigateToBuyInput/useNavigateToBuyInput';
import { trackManageClick } from '@app/screens/YieldCenter/eventing';
import { useAccountsByType } from '@app/screens/YieldCenter/hooks/useAccountsByType/useAccountsByType';

import { EarningActionsFragment$key } from './__generated__/EarningActionsFragment.graphql';
import { EarningActionsQuery } from './__generated__/EarningActionsQuery.graphql';

const i18nKey = 'EarningActions';
const messages = defineMessages({
  manage: {
    id: `${i18nKey}.manage`,
    defaultMessage: 'Manage',
    description: 'Manage button text',
  },
  startEarning: {
    id: `${i18nKey}.startEarning`,
    defaultMessage: 'Start earning',
    description: 'Start earning button text',
  },
  buyMore: {
    id: `${i18nKey}.buyMore`,
    defaultMessage: 'Buy more',
    description: 'Buy more button text',
  },
  buyAsset: {
    id: `${i18nKey}.buyAsset`,
    defaultMessage: 'Buy {asset}',
    description: 'Buy USDC button text',
  },
  a11yLabel: {
    id: `${i18nKey}.a11yLabel`,
    defaultMessage: 'Available actions for your asset',
    description: 'Accessibility label for buttons',
  },
});

type ManageButtonProps = {
  assetUuid: string;
  isEnrolled: boolean;
  compact?: boolean;
  onManagePress: () => void;
};

function ManageButtonContent({
  assetUuid,
  isEnrolled,
  compact,
  onManagePress,
}: ManageButtonProps) {
  const { formatMessage } = useIntl();

  const preferenceData = useLazyLoadQuery<EarningActionsQuery>(
    graphql`
      query EarningActionsQuery($uuid: Uuid!) {
        viewer @required(action: THROW) {
          assetByUuid(uuid: $uuid) {
            rewardsPreferenceOptions {
              __typename
            }
          }
        }
      }
    `,
    { uuid: assetUuid },
  );

  const cta = useMemo(() => {
    if (isEnrolled) {
      return formatMessage(messages.manage);
    }

    return formatMessage(messages.startEarning);
  }, [isEnrolled, formatMessage]);

  const variant = useMemo(() => {
    if (isEnrolled) {
      return 'secondary';
    }

    return 'primary';
  }, [isEnrolled]);

  if (!preferenceData?.viewer?.assetByUuid?.rewardsPreferenceOptions?.length) {
    return null;
  }

  return (
    <Button
      key="manageButtons"
      variant={variant}
      block
      compact={compact}
      onPress={onManagePress}
      testID="ManageActionButtons-Manage"
    >
      {cta}
    </Button>
  );
}

function ManageButton({ assetUuid, ...props }: ManageButtonProps) {
  if (!assetUuid) {
    return null;
  }

  return (
    <ErrorBoundary fallback={null}>
      <InstrumentedSuspense
        instrumentationId="ManageActionButtons"
        fallback={<FallbackManageButton />}
      >
        <ManageButtonContent assetUuid={assetUuid} {...props} />
      </InstrumentedSuspense>
    </ErrorBoundary>
  );
}

function FallbackManageButton() {
  return <Fallback height={58} width="100%" shape="circle" spacingBottom={2} />;
}

type EarningActionsProps = {
  viewerAssetRef: EarningActionsFragment$key | null;
  compact?: boolean;
  context: StakingSource;
};

export function EarningActions({
  viewerAssetRef,
  compact,
  context,
}: EarningActionsProps) {
  const { formatMessage } = useIntl();
  const yieldCenterStack = useModal('YieldCenterStack');
  const navigateToBuyInput = useNavigateToBuyInput();

  const viewerAsset = useFragment(
    graphql`
      fragment EarningActionsFragment on ViewerAsset {
        asset {
          uuid
          name
          platformName
        }
        earnProgram {
          isEnrolled
          currentRate {
            __typename
          }
        }
        accounts {
          ...useAccountsByTypeFragment
          availableBalance {
            value
          }
        }
      }
    `,
    viewerAssetRef,
  );

  const asset = viewerAsset?.asset;
  const hasCurrentRate = Boolean(viewerAsset?.earnProgram?.currentRate);
  const isEnrolled = Boolean(viewerAsset?.earnProgram?.isEnrolled);
  const accounts = useAccountsByType(viewerAsset?.accounts);
  const balance = Number(accounts.WALLET?.availableBalance?.value ?? 0);

  const handleBuyPress = useCallback(() => {
    navigateToBuyInput({
      assetSymbolOrSlug: asset?.platformName ?? '',
      transferSource: 'yieldCenter',
      assetName: asset?.name ?? '',
    });
  }, [asset, navigateToBuyInput]);

  const handleManagePress = useCallback(() => {
    markJourney('navigate_to_staking_rewards_rate_modal');
    trackManageClick(asset?.platformName ?? '', context);
    yieldCenterStack.present('ManageInterest', {
      assetId: asset?.uuid ?? '',
    });
  }, [yieldCenterStack, asset, context]);

  // if no primary balance, show BUY {asset} button
  if (balance === 0) {
    return (
      <Button
        key="buyMoreButton"
        testID="EarningActionsBuyButton"
        block
        compact={compact}
        onPress={handleBuyPress}
      >
        {formatMessage(messages.buyAsset, { asset: asset?.platformName ?? '' })}
      </Button>
    );
  }

  return (
    <ButtonGroup block accessibilityLabel={formatMessage(messages.a11yLabel)}>
      {!!asset?.uuid && (
        <ManageButton
          assetUuid={asset?.uuid}
          isEnrolled={isEnrolled}
          onManagePress={handleManagePress}
        />
      )}
      {hasCurrentRate && isEnrolled && (
        <Button
          key="buyMoreButton"
          testID="EarningActionsBuyMoreButton"
          block
          compact={compact}
          onPress={handleBuyPress}
        >
          {formatMessage(messages.buyMore)}
        </Button>
      )}
    </ButtonGroup>
  );
}

