}: EarningRateTrayProps) {
  const useDynamicApyTray = useEarnApyDataSource();

  const viewerAsset = useFragment(
    graphql`
      fragment EarningRateTrayFragment on ViewerAsset {
        asset {
          platformName
        }
        earnAsset {
          copy {
            supportLink {
              url
              text
            }
          }
        }
        rewardApy {
          description
        }
        earnProgram {
          currentRate {
            formatted
            unitSymbol
            details {
              text
              ...EarningRateTrayDetailsFragment
            }
            explainer {
              description @required(action: NONE)
              cta @required(action: NONE)
              details @required(action: NONE) {
                title @required(action: NONE)
                description {
                  text
                  ...EarningRateTrayDetailsFragment
                }
              }
            }
          }
        }
      }
    `,
    viewerAssetRef,
  );

  const earnProgram = viewerAsset?.earnProgram;
  const currentRate = earnProgram?.currentRate;
  const rewardApy = viewerAsset?.rewardApy;
  const link = viewerAsset?.earnAsset?.copy?.supportLink;

  useTrackEarningTrayView({
    asset: viewerAsset?.asset?.platformName ?? '',
    type: 'earning_rate',
    context,
  });

  const { formatMessage } = useIntl();

  const [displayApyExplainer, { toggle, toggleOff }] = useToggler(false);

  const handleShowApyExplainer = useCallback(() => {
    trackApyExplainerButtonClick({
      asset: viewerAsset?.asset?.platformName ?? '',
      context,
    });
    toggle();
  }, [toggle, context, viewerAsset?.asset?.platformName]);

  const handleHideApyExplainer = useCallback(() => {
    trackApyExplainerDismiss({
      asset: viewerAsset?.asset?.platformName ?? '',
      context,
    });
    toggleOff();
  }, [toggleOff, context, viewerAsset?.asset?.platformName]);

  const explainersContent = useMemo(() => {
    return (
      <>
        <HStack
          justifyContent="space-between"
          spacingHorizontal={1}
          spacingBottom={2}
        >
          <HStack alignItems="center" gap={1}>
            <IconButton
              name="backArrow"
              onPress={handleHideApyExplainer}
              transparent
            />
            <TextTitle3>{currentRate?.explainer?.details.title}</TextTitle3>
          </HStack>
        </HStack>
        <VStack spacingHorizontal={gutter} gap={2}>
          {currentRate?.explainer?.details?.description?.map((detail) => {
            if (!detail) {
              return null;
            }
            return (
              <EarningRateTrayDetails
                earnRateDetailRef={detail}
                key={detail?.text}
                inline
              />
            );
          })}
        </VStack>
      </>
    );
  }, [
    currentRate?.explainer?.details?.description,
    currentRate?.explainer?.details.title,
    handleHideApyExplainer,
  ]);

  const staticDetails = useMemo(() => {
    return (
      <TextBody color="foregroundMuted" spacingBottom={3}>
        {rewardApy?.description}{' '}
        {!!link?.url && !!link?.text && (
          <Link to={link?.url} underline>
            {link?.text}
          </Link>
        )}
      </TextBody>
    );
  }, [rewardApy, link]);

  const dynamicDetails = useMemo(() => {
    // If more than 1 detail or explainer is present, show inline.
    const detailsInline =
      (currentRate?.details?.length ?? 0) > 1 || !!currentRate?.explainer;

    return (
      <VStack gap={2}>
        {currentRate?.details?.map((detail) => {
          if (!detail) {
            return null;
          }
          return (
            <EarningRateTrayDetails
              earnRateDetailRef={detail}
              key={detail?.text}
              inline={detailsInline}
            />
          );
        })}
        {currentRate?.explainer?.cta && (
          <TextBody spacingBottom={1} color="foregroundMuted">
            {currentRate?.explainer?.description}{' '}
            {!hideExplainerLink && (
              <TextBody
                color="primary"
                onPress={handleShowApyExplainer}
                accessibilityRole="button"
              >
                {currentRate.explainer.cta}
              </TextBody>
            )}
          </TextBody>
        )}
      </VStack>
    );
  }, [currentRate, hideExplainerLink, handleShowApyExplainer]);

  const detailsContent = useMemo(() => {
    return (
      <VStack spacingHorizontal={gutter}>
        <TextTitle2 color="positive" spacingBottom={2}>
          {currentRate?.formatted} {currentRate?.unitSymbol}
        </TextTitle2>
        {useDynamicApyTray ? dynamicDetails : staticDetails}
      </VStack>
    );
  }, [useDynamicApyTray, currentRate, dynamicDetails, staticDetails]);

  const handleCloseComplete = useCallback(() => {
    handleHideApyExplainer();
    onCloseComplete();
  }, [handleHideApyExplainer, onCloseComplete]);

  if (!isVisible || !currentRate) {
    return null;
  }

  return (
    <Tray
      title={
        displayApyExplainer ? undefined : (
          <TextHeadline spacingTop={gutter} spacingHorizontal={gutter}>
            {formatMessage(messages.earningRate)}
          </TextHeadline>
        )
      }
      onCloseComplete={handleCloseComplete}
    >
      {({ handleClose }) => (
        <>
          {displayApyExplainer ? explainersContent : detailsContent}
          <Button
            variant="secondary"
            onPress={handleClose}
            spacingHorizontal={gutter}
            spacingTop={3}
            spacingBottom={0}
          >
            {formatMessage(messages.gotIt)}
          </Button>
        </>
      )}
    </Tray>
  );
}

