  forwardRef,
  memo,
  SetStateAction,
  useCallback,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from 'react';
import { StyleProp, TextStyle } from 'react-native';
import { fontScaleProps } from '@cbhq/cds-mobile/hooks/useDeviceScaleToCdsScale';
import { usePalette } from '@cbhq/cds-mobile/hooks/usePalette';
