import {
  FabricTextInput,
  FabricTextInputRef,
} from '@designSystem/core/chart/ChartHeaderAndNavBar/FabricTextInput';

import { device } from '@config/device';
import { useNativeCurrency } from '@app/hooks/useNativeCurrency';
