import { EarningsLabel } from '../EarningsLabel/EarningsLabel';

import { YieldEarnedChartHeaderFragment$key } from './__generated__/YieldEarnedChartHeaderFragment.graphql';

type InputProps = {
  inputRef: React.RefObject<FabricTextInputRef>;
  defaultValue?: string;
  inputStyles: StyleProp<TextStyle>;
};

// TextInput elements allow for by ref access of a 'value' field
const YieldCenterInput = memo(
  ({ inputRef, defaultValue, inputStyles }: InputProps) => (
    <FabricTextInput
      ref={inputRef}
      defaultValue={defaultValue}
      style={inputStyles}
      {...fontScaleProps}
    />
  ),
);

type YieldEarnedChartHeaderValues = {
  interestValue: number;
};

export type YieldEarnedChartHeaderRef = {
  update: (params: YieldEarnedChartHeaderValues) => void;
};

export type YieldEarnedChartHeaderProps = {
  viewerRef: YieldEarnedChartHeaderFragment$key;
  isScrubbing: boolean;
  activePeriod: ChartPeriod;
  totalEarnedThisPeriod: number;
  averageRate: string;
  onViewInterestEarnedDisclaimerTray: Dispatch<SetStateAction<boolean>>;
  onViewInterestRateDisclaimerTray: Dispatch<SetStateAction<boolean>>;
};

// YieldEarnedChart uses it's ref of this component to update on scrub state change.
export const YieldEarnedChartHeader = memo(
  forwardRef<YieldEarnedChartHeaderRef, YieldEarnedChartHeaderProps>(
    (
      {
        viewerRef,
        isScrubbing,
        activePeriod,
        totalEarnedThisPeriod,
        averageRate,
        onViewInterestEarnedDisclaimerTray,
        onViewInterestRateDisclaimerTray,
      },
      forwardedRef,
    ) => {
      const viewer = useFragment<YieldEarnedChartHeaderFragment$key>(
        graphql`
          # eslint-disable-next-line @cbhq/cdl-graphql-no-fragments-on-viewer
          fragment YieldEarnedChartHeaderFragment on Viewer {
            earn {
              payouts {
                totalFiat {
                  currency
                }
              }
            }
          }
        `,
        viewerRef,
      );

      const { formatMessage } = useIntl();
      const nativeCurrency = useNativeCurrency();
      const currency = viewer?.earn?.payouts?.totalFiat?.currency;

      const [interest, setInterest] = useState<number>(0);

      const interestLabelRef = useRef<FabricTextInputRef>(null);
      const averageRateInputRef = useRef<FabricTextInputRef>(null);

      const nonScrubbingEarningLabel = usePeriodEarningsLabel(activePeriod);

      useEffect(() => {
        if (!isScrubbing) {
          // set interest to the total when not scrubbing
          setInterest(totalEarnedThisPeriod);
          const defaultInterestLabel = nonScrubbingEarningLabel;
          interestLabelRef.current?.update(defaultInterestLabel);
        }
      }, [
        isScrubbing,
        formatMessage,
        totalEarnedThisPeriod,
        nonScrubbingEarningLabel,
      ]);

      // Define & attach 'update()' method to the forwardedRef with useImperativeHandle
      const update = useCallback(
        ({ interestValue }: YieldEarnedChartHeaderValues) => {
          setInterest(interestValue);
          const interestEarnedText = formatMessage(messages.amountEarned);
          if (interestLabelRef.current?.value !== interestEarnedText) {
            interestLabelRef.current?.update(interestEarnedText);
          }
        },
        [formatMessage],
      );

      useImperativeHandle(
        forwardedRef,
        () => {
          return {
            update,
          };
        },
        [update],
      );

      // Match TextInput styling to CDS Labels using CDS hooks.
      const palette = usePalette();
      const labelStyles = useTypographyStyles('label1');
      const textAlignVertical = 'top';
      const SPACING_BOTTOM = 1;

      const spacing = useSpacingStyles({
        spacingBottom: device.isAndroid ? 0 : SPACING_BOTTOM,
        spacingTop: 0,
      });

      const inputStyles: StyleProp<TextStyle> = {
        ...spacing,
        ...labelStyles,
        textAlignVertical,
        color: palette.foregroundMuted,
      };

      const onViewInterestEarnedDisclaimerTrayPress = useCallback(() => {
        onViewInterestEarnedDisclaimerTray(true);
        Analytics.logEvent('view-interest-earned-disclaimer-tray', {
          action: ActionType.click,
          componentType: ComponentType.button,
        });
      }, [onViewInterestEarnedDisclaimerTray]);

      const onViewInterestRateDisclaimerTrayPress = useCallback(() => {
        onViewInterestRateDisclaimerTray(true);
        Analytics.logEvent('view-interest-rate-disclaimer-tray', {
          action: ActionType.click,
          componentType: ComponentType.button,
        });
      }, [onViewInterestRateDisclaimerTray]);

      return (
        <HStack testID="YieldEarnedChartHeader" justifyContent="space-between">
          <Pressable
            accessibilityRole="button"
            background="transparent"
            feedback="normal"
            testID="ViewInterestEarnedDisclaimer"
            onPress={onViewInterestEarnedDisclaimerTrayPress}
          >
            <HStack alignItems="center" gap={1}>
              <YieldCenterInput
                inputRef={interestLabelRef}
                inputStyles={inputStyles}
              />
              <Icon name="info" size="xs" color="foregroundMuted" />
            </HStack>
            <TextTitle3>
              <EarningsLabel
                inFiat
                showPlusSignPrefix
                exponent={2}
                value={interest}
                currency={currency ?? nativeCurrency}
              />
            </TextTitle3>
          </Pressable>
          {!isScrubbing && !!averageRate && (
            <Pressable
              accessibilityRole="button"
              background="transparent"
              feedback="normal"
              testID="ViewInterestRateDisclaimer"
              onPress={onViewInterestRateDisclaimerTrayPress}
            >
              <HStack alignItems="center" gap={1}>
                <YieldCenterInput
                  inputRef={averageRateInputRef}
                  defaultValue={formatMessage(messages.averageRate)}
                  inputStyles={inputStyles}
                />
                <Icon name="info" size="xs" color="foregroundMuted" />
              </HStack>
              <TextTitle3 align="end">{averageRate}</TextTitle3>
            </Pressable>
          )}
        </HStack>
      );
    },
  ),
);

