import { fireEvent, render } from '@testing-library/react-native';
import { location as analyticsLocation } from '@cbhq/client-analytics';

import { RootScreenParamList } from '@app/components/navigation/stacks/SignedInStack';
import { PAGE_KEYS } from '@app/utils/analytics/pagekeys';

import { PageKeyMetadata, useGetPageKey } from './useGetPageKey';

const TEST_ROUTE_ONE = 'TestRouteOne' as keyof RootScreenParamList;
const TEST_PAGE_KEY_ONE = 'TestPageKeyOne';
const TEST_ROUTE_TWO = 'TestRouteTwo' as keyof RootScreenParamList;
const TEST_PAGE_KEY_TWO = 'TestPageKeyTwo';

const Stack = createStackNavigator();

describe('useGetPageKey', () => {
  let reportedMetadata: PageKeyMetadata;
  function ReportThisPageKey({ name = '' }: { name?: string }) {
    const getPageKey = useGetPageKey();
    const handleReport = useCallback(() => {
      reportedMetadata = getPageKey();
    }, [getPageKey]);
    handleReport();
    return <Button title={`Report PageKey${name}`} onPress={handleReport} />;
  }

  function LinksToTwo() {
    return (
      <>
        <ReportThisPageKey name="One" />
        <Link to={`/${TEST_ROUTE_TWO}`}>Go to Two</Link>
      </>
    );
  }

  function EmptyComponent() {
    return null;
  }

  beforeAll(() => {
    // Fake a new page key
    Object.assign(PAGE_KEYS, {
      [TEST_ROUTE_ONE]: TEST_PAGE_KEY_ONE,
      [TEST_ROUTE_TWO]: TEST_PAGE_KEY_TWO,
    });
  });

  beforeEach(() => {
    // Reset the analytics location
    analyticsLocation.pageKey = 'GLOBAL_TEST_PAGE_KEY';
    analyticsLocation.pagePath = 'GLOBAL_TEST_PAGE_PATH';
    analyticsLocation.prevPageKey = 'GLOBAL_TEST_PREV_PAGE_KEY';
    analyticsLocation.prevPagePath = 'GLOBAL_TEST_PREV_PAGE_PATH';
  });

  it('returns analytics location data when not inside a navigator', () => {
    render(<ReportThisPageKey />);

    expect(reportedMetadata).toEqual({
      pageKey: 'GLOBAL_TEST_PAGE_KEY',
      pagePath: 'GLOBAL_TEST_PAGE_PATH',
      prevPageKey: 'GLOBAL_TEST_PREV_PAGE_KEY',
      prevPagePath: 'GLOBAL_TEST_PREV_PAGE_PATH',
      pageKeyCorrected: false,
      pagePathCorrected: false,
      isPageKeyInBackground: undefined, // Not reported because we do not know
    });
  });

  it('assigns the prevPageKey and prevPagePath from the analytics location object', () => {
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={ReportThisPageKey} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      prevPageKey: 'GLOBAL_TEST_PREV_PAGE_KEY',
      prevPagePath: 'GLOBAL_TEST_PREV_PAGE_PATH',
    });
  });

  it('assigns a page key and path for the routed component', () => {
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={ReportThisPageKey} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKey: TEST_PAGE_KEY_ONE,
      pagePath: TEST_ROUTE_ONE,
    });
  });

  it('indicates when the page is in focus', () => {
    const { getByText } = render(
      <NavigationContainer>
        <Stack.Navigator initialRouteName={TEST_ROUTE_ONE}>
          <Stack.Screen name={TEST_ROUTE_ONE} component={LinksToTwo} />
          <Stack.Screen name={TEST_ROUTE_TWO} component={EmptyComponent} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKey: TEST_PAGE_KEY_ONE,
      isPageKeyInBackground: false,
    });

    const reportPageKeyOne = getByText('Report PageKeyOne');
    // Navigate to route two
    fireEvent.press(getByText('Go to Two'));
    // Reports *PAGE ONE*'s page key info again
    fireEvent.press(reportPageKeyOne);

    expect(reportedMetadata).toMatchObject({
      pageKey: TEST_PAGE_KEY_ONE,
      isPageKeyInBackground: true,
    });
  });

  it('assigns a page key for nested routes', () => {
    function NestedStack() {
      return (
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_TWO} component={ReportThisPageKey} />
        </Stack.Navigator>
      );
    }
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={NestedStack} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKey: TEST_PAGE_KEY_TWO,
      pagePath: TEST_ROUTE_TWO,
    });
  });

  it('reports parent page key when rendered in multiple levels of nesting while navigating to a new route for the first time', () => {
    // This test is a verification of the scenario when we are navigating to a deeply-nested
    // path for the first time which means the root navigator state will not yet include
    // the newly-navigated state.

    function NestedStackOneA() {
      return (
        <Stack.Navigator>
          <Stack.Screen name="unmapped-one-A-bottom" component={LinksToTwo} />
        </Stack.Navigator>
      );
    }
    function NestedStackOneB() {
      return (
        <Stack.Navigator>
          <Stack.Screen
            name="unmapped-one-B-bottom"
            component={EmptyComponent}
          />
        </Stack.Navigator>
      );
    }
    function NestedStackOne() {
      return (
        <Stack.Navigator initialRouteName="unmapped-one-A">
          <Stack.Screen name="unmapped-one-A" component={NestedStackOneA} />
          <Stack.Screen name="unmapped-one-B" component={NestedStackOneB} />
        </Stack.Navigator>
      );
    }
    function NestedStackTwo() {
      return (
        <Stack.Navigator>
          <Stack.Screen name="unmapped-two" component={ReportThisPageKey} />
        </Stack.Navigator>
      );
    }
    const { getByText } = render(
      <NavigationContainer>
        <Stack.Navigator initialRouteName={TEST_ROUTE_ONE}>
          <Stack.Screen name={TEST_ROUTE_ONE} component={NestedStackOne} />
          <Stack.Screen name={TEST_ROUTE_TWO} component={NestedStackTwo} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    fireEvent.press(getByText('Go to Two'));

    expect(reportedMetadata).toMatchObject({
      pageKey: TEST_PAGE_KEY_TWO,
      pagePath: 'unmapped-two',
      isPageKeyInBackground: false,
    });
  });

  it('reports parent page key when rendered in multiple levels of nesting on the initial render', () => {
    // This test is a verification of the scenario when we are rendering a deeply-nested
    // path on the very first render which means the root navigator state will not be
    // available and we take a different approach when computing the page key
    function NestedStackOneA() {
      return (
        <Stack.Navigator>
          <Stack.Screen
            name="unmapped-one-A-bottom"
            component={EmptyComponent}
          />
        </Stack.Navigator>
      );
    }
    function NestedStackOneB() {
      return (
        <Stack.Navigator>
          <Stack.Screen
            name="unmapped-one-B-bottom"
            component={ReportThisPageKey}
          />
        </Stack.Navigator>
      );
    }

    function NestedStackOne() {
      return (
        <Stack.Navigator initialRouteName="unmapped-one-B">
          <Stack.Screen name="unmapped-one-A" component={NestedStackOneA} />
          <Stack.Screen name="unmapped-one-B" component={NestedStackOneB} />
        </Stack.Navigator>
      );
    }
    function NestedStackTwo() {
      return (
        <Stack.Navigator>
          <Stack.Screen name="unmapped-two" component={ReportThisPageKey} />
        </Stack.Navigator>
      );
    }
    render(
      <NavigationContainer>
        <Stack.Navigator initialRouteName={TEST_ROUTE_ONE}>
          <Stack.Screen name={TEST_ROUTE_ONE} component={NestedStackOne} />
          <Stack.Screen name={TEST_ROUTE_TWO} component={NestedStackTwo} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKey: TEST_PAGE_KEY_ONE,
      pagePath: 'unmapped-one-B-bottom',
      isPageKeyInBackground: false,
    });
  });

  it('reports unfocused nested routes', () => {
    function NestedStackOne() {
      return (
        <Stack.Navigator>
          <Stack.Screen name="unmapped-one" component={LinksToTwo} />
        </Stack.Navigator>
      );
    }
    function NestedStackTwo() {
      return (
        <Stack.Navigator>
          <Stack.Screen name="unmapped-two" component={ReportThisPageKey} />
        </Stack.Navigator>
      );
    }
    const { getByText } = render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={NestedStackOne} />
          <Stack.Screen name={TEST_ROUTE_TWO} component={NestedStackTwo} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    const reportPageKeyOne = getByText('Report PageKeyOne');
    // Navigate away from route one
    fireEvent.press(getByText('Go to Two'));
    // Report the unfocused page key one again
    fireEvent.press(reportPageKeyOne);

    expect(reportedMetadata).toMatchObject({
      pageKey: TEST_PAGE_KEY_ONE,
      pagePath: 'unmapped-one',
      isPageKeyInBackground: true,
    });
  });

  it('assigns a page key of the parent of unmapped nested routes but the path of the reporting route', () => {
    function NestedStack() {
      return (
        <Stack.Navigator>
          <Stack.Screen name="unmapped" component={ReportThisPageKey} />
        </Stack.Navigator>
      );
    }
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={NestedStack} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKey: TEST_PAGE_KEY_ONE,
      pagePath: 'unmapped', // path of the reporting route is assigned
    });
  });

  it('includes whitelisted parameters in the page path', () => {
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen
            name={TEST_ROUTE_ONE}
            initialParams={{ name: 'Test' }}
            component={ReportThisPageKey}
          />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pagePath: `${TEST_ROUTE_ONE}&${TEST_ROUTE_ONE}_name=Test`,
    });
  });

  it('updates the page path when parameters change', () => {
    function UpdatesParams() {
      const nav = useNavigation();
      const updateParams = useCallback(() => {
        nav.setParams({ name: 'New Name' });
      }, [nav]);
      return (
        <>
          <Button onPress={updateParams} title="Update Params" />
          <ReportThisPageKey />
        </>
      );
    }

    const { getByText } = render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen
            name={TEST_ROUTE_ONE}
            initialParams={{ name: 'Test' }}
            component={UpdatesParams}
          />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    fireEvent.press(getByText('Update Params'));

    expect(reportedMetadata).toMatchObject({
      pagePath: `${TEST_ROUTE_ONE}&${TEST_ROUTE_ONE}_name=New Name`,
    });
  });

  it('assigns an unknown page key when no page key is found', () => {
    analyticsLocation.pageKey = '';
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name="unmapped" component={ReportThisPageKey} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKey: '',
    });
  });

  it('reports when global page key was corrected', () => {
    analyticsLocation.pageKey = 'wrong-key';
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={ReportThisPageKey} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKeyCorrected: true,
      correctedPageKey: 'wrong-key',
    });
  });

  it('reports the corrected page key as empty string when global page key was empty', () => {
    analyticsLocation.pageKey = '';
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={ReportThisPageKey} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKeyCorrected: true,
      correctedPageKey: '',
    });
  });

  it('reports when global page key was not corrected', () => {
    analyticsLocation.pageKey = TEST_PAGE_KEY_ONE;
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={ReportThisPageKey} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pageKeyCorrected: false,
      correctedPageKey: undefined,
    });
  });

  it('reports when global page path was corrected', () => {
    analyticsLocation.pagePath = 'wrong-path';
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={ReportThisPageKey} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pagePathCorrected: true,
      correctedPagePath: 'wrong-path',
    });
  });

  it('reports when global page path was not corrected', () => {
    analyticsLocation.pagePath = TEST_ROUTE_ONE;
    render(
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name={TEST_ROUTE_ONE} component={ReportThisPageKey} />
        </Stack.Navigator>
      </NavigationContainer>,
    );

    expect(reportedMetadata).toMatchObject({
      pagePathCorrected: false,
      correctedPagePath: undefined,
    });
  });
});

import { useCallback } from 'react';
import { Button } from 'react-native';
import {
  fireEvent,
  render,
  renderHook,
  screen,
} from '@testing-library/react-native';
import {
  identity,
  location as analyticsLocation,
} from '@cbhq/client-analytics';
import { NetworkError } from '@cbhq/data-layer';

import {
  BUGSNAG_IGNORE_ERRORS,
  ErrorMetadata,
  errorVitals,
  filterBugsnagErrors,
  useErrorVitals,
} from '@app/utils/errors/errorVitals';

jest.mock('@cbhq/error-vitals-mobile', () => ({
  init: () => ({
    logError: () => {},
  }),
}));

jest.unmock('@app/utils/errors/errorVitals');

const defaultNotifyOpts: ErrorMetadata = {
  context: 'test',
  severity: 'error',
  isHandled: false,
};

function NotifyButton() {
  const errorLogger = useErrorVitals();
  const handlePress = useCallback(() => {
    errorLogger.logError(new Error('Test Error'), defaultNotifyOpts);
  }, [errorLogger]);
  return <Button onPress={handlePress} title="Notify Logger" />;
}

describe('useErrorVitals', () => {
  beforeEach(() => {
    jest.spyOn(errorVitals, 'logError');
  });

  it('passes through error metadata', () => {
    const {
      result: { current: errorLogger },
    } = renderHook(() => useErrorVitals());

    errorLogger.logError(new Error('Test'), {
      ...defaultNotifyOpts,
      foo: 'FOO',
      bar: 'BAR',
    });

    expect(errorVitals.logError).toHaveBeenCalledWith(
      new Error('Test'),
      expect.objectContaining({
        foo: 'FOO',
        bar: 'BAR',
      }),
    );
  });

  it('assigns page key and path', () => {
    analyticsLocation.pageKey = 'analyticsPageKey';
    analyticsLocation.pagePath = 'analyticsPagePath';
    render(<NotifyButton />);

    fireEvent.press(screen.getByText('Notify Logger'));

    expect(errorVitals.logError).toHaveBeenCalledWith(
      new Error('Test Error'),
      expect.objectContaining({
        pageKey: 'analyticsPageKey',
        pagePath: 'analyticsPagePath',
      }),
    );
  });

  describe('filterBugsnagErrors', () => {
    const ORIGINAL_BUGSNAG_IGNORE_ERRORS = [...BUGSNAG_IGNORE_ERRORS];
    const ORIGINAL_IDENTITY_OPT_OUT = identity.isOptOut;

    afterEach(() => {
      BUGSNAG_IGNORE_ERRORS.length = 0;
      BUGSNAG_IGNORE_ERRORS.concat(...ORIGINAL_BUGSNAG_IGNORE_ERRORS);
      identity.isOptOut = ORIGINAL_IDENTITY_OPT_OUT;
    });

    it('returns false for errors where the message contains a value from the BUGSNAG_IGNORE_LIST', () => {
      BUGSNAG_IGNORE_ERRORS.length = 0;
      BUGSNAG_IGNORE_ERRORS[0] = 'Ignore this error';
      BUGSNAG_IGNORE_ERRORS[1] = 'Ignore me too';

      BUGSNAG_IGNORE_ERRORS.forEach((message) => {
        expect(filterBugsnagErrors(new Error(message))).toBe(false);
      });

      expect(
        filterBugsnagErrors(new Error('This is not in the ignore list')),
      ).toBe(true);
    });

    it('returns false for network or connection errors', () => {
      const testNetworkError = new NetworkError({
        message: 'Test Network Error',
      });

      expect(filterBugsnagErrors(testNetworkError)).toBe(false);
      expect(
        filterBugsnagErrors(
          new Error('Test Regular Error With Network Cause', {
            cause: testNetworkError,
          }),
        ),
      ).toBe(false);
    });
  });

  it('filters all errors when the user is opted out of analytics', () => {
    const testError = new Error('Test Error');
    expect(filterBugsnagErrors(testError)).toBe(true);

    identity.isOptOut = true;
    expect(filterBugsnagErrors(testError)).toBe(false);
  });
});

