import { memo, useCallback, useMemo, useState } from 'react';
import { FlatList, StyleProp, ViewStyle } from 'react-native';
import { useToggler } from '@cbhq/cds-common';
import { Checkbox } from '@cbhq/cds-mobile/controls/Checkbox';
import { Box, Divider, HStack, Spacer, VStack } from '@cbhq/cds-mobile/layout';
import { Tooltip } from '@cbhq/cds-mobile/overlays';
import { TextLabel1, TextLabel2 } from '@cbhq/cds-mobile/typography';
import { AnalyticsRequest } from '@cbhq/coinbase-dev-extension-utils';

import { IconButton } from '@components/interactables/IconButton';

import { TextButton } from './TextButton';

type ClientAnalyticsTabProps = {
  analyticsRequests: AnalyticsRequest[];
  analyticsTabStyles: StyleProp<ViewStyle>;
  onClearPress: () => void;
};

function keyExtractor(item: AnalyticsRequest, index: number) {
  return `${index}-${item.request_url}`;
}

const EVENT_NAME_LONG_TEXT_THRESHOLD = 25;

export function filteredRequests(
  analyticsRequests: AnalyticsRequest[],
  tabEntryType: string,
  hideDataLayer: boolean,
) {
  const requests = analyticsRequests
    .filter((req) => {
      if (tabEntryType === 'all') {
        return true;
      }

      if (tabEntryType === 'metric' && req.request_type === 'metric') {
        return true;
      }

      if (tabEntryType === 'event' && req.request_type === 'event') {
        return true;
      }

      return false;
    })
    .sort((a, b) => (b.request_timestamp < a.request_timestamp ? -1 : 1));

  if (hideDataLayer) {
    const dataLayerMetricPrefix = 'cb.react.data_layer';
    const dataLayerEventPrefix = 'cb_react_data_layer';

    return requests.filter((req) => {
      const isDataLayerRequest =
        (req.request_type === 'metric' &&
          (req?.request_body?.metric_name as string)?.startsWith(
            dataLayerMetricPrefix,
          )) ||
        (req.request_type === 'event' &&
          (req?.request_body?.event_type as string)?.startsWith(
            dataLayerEventPrefix,
          ));

      return !isDataLayerRequest;
    });
  }

  return requests;
}

type AnalyticsRequestEntryProps = {
  item: AnalyticsRequest;
};

function AnalyticsRequestEntry({ item }: AnalyticsRequestEntryProps) {
  let label = '';

  if (item.request_body?.metric_name) {
    label = item.request_body?.metric_name as string;
  }
  if (item.request_body?.event_type) {
    label = item.request_body?.event_type as string;
  }

  // some metric names are quite long.
  // these are some potential prefixes to
  // help make the labels more readable
  const potentialPrefix = [
    'cb.react.data_layer.request',
    'cb.react.data_layer',
    'user_journey_step',
    'cb.react',
  ];

  const prefix = potentialPrefix.find((p) => label.startsWith(p));
  if (prefix) {
    const parts = label.split(prefix);
    const [, withoutPrefix] = parts;
    label = withoutPrefix;
    if (label.startsWith('.')) {
      label = label.substring(1);
    }
  }

  const labelMarkup =
    label && label.length > EVENT_NAME_LONG_TEXT_THRESHOLD ? (
      <Tooltip placement="bottom" content={label}>
        <TextLabel1 ellipsizeMode="tail" ellipsize="tail">
          {label.substring(0, EVENT_NAME_LONG_TEXT_THRESHOLD)}...
        </TextLabel1>
      </Tooltip>
    ) : (
      <TextLabel1 ellipsizeMode="tail" ellipsize="tail">
        {label}
      </TextLabel1>
    );

  // convert iso timestamp to local time
  // in the format HH:MM:SS
  const timestamp = new Date(item.request_timestamp);
  const pad = (num: number) => num.toString().padStart(2, '0');
  const hours = pad(timestamp.getHours());
  const minutes = pad(timestamp.getMinutes());
  const seconds = pad(timestamp.getSeconds());
  const time = `${hours}:${minutes}:${seconds}`;

  return (
    <Box>
      <HStack spacingVertical={1} alignItems="center" gap={1}>
        <VStack alignItems="center">
          <TextLabel2>{time}</TextLabel2>
          <TextLabel2>{item.request_type}</TextLabel2>
        </VStack>
        <Box flexGrow={1}>
          {labelMarkup}
          <HStack>
            <TextLabel2 ellipsizeMode="tail" ellipsize="tail">
              {prefix}
            </TextLabel2>
            <Spacer />
          </HStack>
        </Box>
      </HStack>
      <Divider />
    </Box>
  );
}

export const ClientAnalyticsTab = memo(
  ({
    analyticsRequests,
    analyticsTabStyles,
    onClearPress,
  }: ClientAnalyticsTabProps) => {
    const [tabEntryType, setTabEntryType] = useState('all');
    const [hideDataLayer, { toggle }] = useToggler(true);

    const renderTabButtons = useMemo(() => {
      const tabButtons: Record<string, string>[] = [
        {
          label: 'all',
          displayName: 'All',
        },
        {
          label: 'metric',
          displayName: 'Metric',
        },
        {
          label: 'event',
          displayName: 'Event',
        },
      ];

      return tabButtons.map((button) => {
        return (
          <TextButton
            key={button.label}
            label={button.label}
            displayName={button.displayName}
            active={tabEntryType === button.label}
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onPress={() => setTabEntryType(button.label)}
          />
        );
      });
    }, [tabEntryType]);

    const renderFilterToggles = useMemo(() => {
      return (
        <HStack
          spacingBottom={1}
          alignItems="center"
          justifyContent="space-around"
        >
          <Box flexGrow={3}>
            <Checkbox onChange={toggle} checked={hideDataLayer}>
              <TextLabel2>Hide Data Layer</TextLabel2>
            </Checkbox>
          </Box>
          <Box flexGrow={1}>
            <IconButton name="trashCan" compact onPress={onClearPress} />
          </Box>
        </HStack>
      );
    }, [hideDataLayer, onClearPress, toggle]);

    const filteredEntries: AnalyticsRequest[] = useMemo(() => {
      return filteredRequests(analyticsRequests, tabEntryType, hideDataLayer);
    }, [analyticsRequests, tabEntryType, hideDataLayer]);

    const renderClientAnalyticsReq = useCallback(
      ({ item, index }: { item: AnalyticsRequest; index: number }) => {
        return <AnalyticsRequestEntry key={index} item={item} />;
      },
      [],
    );

    return (
      <>
        <Box>
          <HStack spacingBottom={1} alignItems="center">
            <HStack>{renderTabButtons}</HStack>
            <Spacer />
            <VStack alignItems="center" spacingBottom={2} />
          </HStack>
          <HStack spacingBottom={1} spacingTop={1} alignItems="center">
            <HStack>{renderFilterToggles}</HStack>
            <Spacer />
            <VStack alignItems="center" spacingBottom={2} />
          </HStack>
        </Box>
        <FlatList
          data={filteredEntries}
          renderItem={renderClientAnalyticsReq}
          keyExtractor={keyExtractor}
          style={analyticsTabStyles}
        />
      </>
    );
  },
);

