import { DebugBanner, useSetDebugBannerVisibility } from './DebugBanner';

jest.mock('@utils/DataStorage', () => ({
  ...jest.requireActual('@utils/DataStorage'),
  getStoreDataSynchronous: jest.fn(),
  setStoreData: jest.fn(async () => Promise.resolve()),
}));

jest.mock('@config/environment', () => ({
  ...jest.requireActual('@config/environment'),
  isAlpha: false,
  isProduction: false,
}));

const mockGetStoreData = getStoreDataSynchronous as jest.Mock;
const mockSetStoreData = setStoreData as jest.Mock;

function DebugBannerToggler() {
  const { setDebugBannerVisibility, isDebugBannerVisible } =
    useSetDebugBannerVisibility();
  return (
    <Button
      title="Toggle Debug Banner"
      onPress={() => setDebugBannerVisibility(!isDebugBannerVisible)}
    />
  );
}

describe('DebugBanner', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  function renderDebugBanner() {
    return render(
      <MockProviders>
        <DebugBanner>
          <Text>Child</Text>
          <DebugBannerToggler />
        </DebugBanner>
      </MockProviders>,
    );
  }

  it('should not render debug banner in production environment', () => {
    (config.isProduction as boolean) = true;

    const { queryByText, getByText } = renderDebugBanner();
    expect(queryByText('DEV')).toBeNull();
    expect(queryByText('ALPHA')).toBeNull();
    expect(getByText('Child')).toBeTruthy();
  });

  it('should not render debug banner in alpha environment by default', () => {
    (config.isAlpha as boolean) = true;

    const { queryByText, getByText } = renderDebugBanner();
    expect(queryByText('DEV')).toBeNull();
    expect(queryByText('ALPHA')).toBeNull();
    expect(getByText('Child')).toBeTruthy();
  });

  it('should render debug banner in dev environment by default', () => {
    (config.isAlpha as boolean) = false;
    (config.isProduction as boolean) = false;
    mockGetStoreData.mockReturnValueOnce(true);

    const { getByText } = renderDebugBanner();
    expect(getByText('DEV')).toBeTruthy();
    expect(getByText('Child')).toBeTruthy();
  });

  it('should toggle modal visibility on banner press', () => {
    (config.isAlpha as boolean) = false;
    (config.isProduction as boolean) = false;
    mockGetStoreData.mockReturnValueOnce(true);

    const { getByText } = renderDebugBanner();
    const bannerButton = getByText('DEV');
    fireEvent.press(bannerButton);
    expect(getByText('Profile')).toBeTruthy();
  });

  it('should update local storage when visibility is toggled', async () => {
    (config.isAlpha as boolean) = false;
    (config.isProduction as boolean) = false;
    mockGetStoreData.mockReturnValueOnce(true);

    const { getByText } = renderDebugBanner();
    const bannerButton = getByText('Toggle Debug Banner');
    fireEvent.press(bannerButton);
    expect(mockSetStoreData).toHaveBeenCalledWith(
      'debugBannerStore',
      'isVisible',
      false,
    );
  });

  it('should initialize visibility from local storage in non-production environments', () => {
    (config.isAlpha as boolean) = false;
    (config.isProduction as boolean) = false;
    mockGetStoreData.mockReturnValueOnce(false);

    const { queryByText } = renderDebugBanner();
    expect(queryByText('DEV')).toBeNull();
  });
});

import { memo, useCallback, useMemo, useState } from 'react';
import { Button, StyleProp, View, ViewStyle } from 'react-native';

import { Root } from '@app/components/Root';

export const UnmountableApp = memo(function UnmountableApp() {
  const [isMounted, setMounted] = useState(false);
  const rootStyle = useMemo(
    () => ({
      flex: 1,
    }),
    [],
  );

  const buttonContainerStyle: StyleProp<ViewStyle> = useMemo(
    () => ({
      backgroundColor: 'yellow',
      position: 'absolute',
      top: 50,
      right: 20,
    }),
    [],
  );

  const handlePress = useCallback(() => {
    setMounted(!isMounted);
  }, [isMounted]);

  return (
    <View style={rootStyle}>
      {isMounted ? <Root /> : null}
      <View style={buttonContainerStyle}>
        <Button title={isMounted ? 'Unmount' : 'Mount'} onPress={handlePress} />
      </View>
    </View>
  );
});
